  `enabled` tinyint(1) NOT NULL DEFAULT '1',
  `window` int unsigned NOT NULL DEFAULT '0',
  `fetchmore` smallint DEFAULT '0',
  `weekday` int unsigned NOT NULL DEFAULT '127',
  `delayedstudy` float DEFAULT '0',
  `delayedseries` float DEFAULT '0',
  `destfolder` varchar(255) CHARACTER SET latin1 COLLATE latin1_swedish_ci DEFAULT NULL,
  `sendingaet` varchar(16) CHARACTER SET latin1 COLLATE latin1_swedish_ci DEFAULT NULL,
  `retryinterval` tinyint unsigned DEFAULT '0',
