/*Table structure for table `drfirst_drug` */

CREATE TABLE `drfirst_drug` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `NDCID` text,
  `RxnormID` bigint DEFAULT NULL,
  `RxnormIDType` varchar(50) DEFAULT NULL,
  `Schedule` varchar(50) DEFAULT NULL,
  `FirstDataBank_MedID` varchar(30) DEFAULT NULL,
  `BrandName` varchar(200) DEFAULT NULL,
  `GenericName` varchar(200) DEFAULT NULL,
  `BrandType` varchar(100) DEFAULT NULL,
  `fdb_route_code` varchar(50) DEFAULT NULL COMMENT 'FDB Route code',
  `drug_form` varchar(30) DEFAULT NULL COMMENT '{drug form, e.g ''tablet''',
  `drug_strength` varchar(30) DEFAULT NULL COMMENT 'drug strength, e.g "25 mg"',
  `Action_type` varchar(100) DEFAULT NULL COMMENT '''Take'', ''Apply'', etc',
  `Dose` varchar(50) DEFAULT NULL COMMENT 'Number of units to take at one time, e.g. 2',
  `Dose_Unit` varchar(50) DEFAULT NULL,
  `Route` varchar(50) DEFAULT NULL COMMENT 'route of administration, e.g. ''by mouth''',
  `Dose_Timing` varchar(50) DEFAULT NULL,
  `Dose_Other` varchar(50) DEFAULT NULL,
  `Duration` int DEFAULT NULL,
  `Quantity` decimal(10,0) DEFAULT NULL,
  `Quantity_Unit` varchar(20) DEFAULT NULL,
  `Refills` varchar(10) DEFAULT NULL,
  `Substitution_Permitted` char(1) DEFAULT NULL,
  `Other_Notes` text,
  `Patient_Notes` text,
  `Comments` text,
  `source` varchar(50) DEFAULT NULL,
  `department_id` tinyint DEFAULT NULL,
  `external_id` bigint DEFAULT NULL,
  `patient_id` varchar(200) DEFAULT NULL,
  `CreatedDate` datetime DEFAULT NULL,
  `CompletedDate` datetime DEFAULT NULL,
  `SignedDate` datetime DEFAULT NULL,
  `StopDate` datetime DEFAULT NULL,
  `drug_status` varchar(100) DEFAULT NULL,
  `synchronized` tinyint(1) DEFAULT NULL,
  `rcopiaid` varchar(50) DEFAULT NULL COMMENT 'external id of all medication prescription',
  `deleted` char(1) DEFAULT NULL,
  `voided` char(1) DEFAULT NULL,
  `denied` char(1) DEFAULT NULL,
  `needsReview` char(1) DEFAULT NULL,
  `height` varchar(15) DEFAULT NULL,
  `weight` varchar(15) DEFAULT NULL,
  `drugDescription` varchar(50) DEFAULT NULL,
  `legendStatus` varchar(10) DEFAULT NULL,
  `created_date` datetime DEFAULT NULL,
  `modified_date` datetime DEFAULT NULL,
  `created_by` varchar(255) DEFAULT NULL,
  `modified_by` varchar(255) DEFAULT NULL,
  `SendMethod` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `RxNormID_index` (`RxnormID`),
  KEY `id_index` (`id`),
  KEY `brandname` (`BrandName`),
  KEY `genericname` (`GenericName`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

