/*Table structure for table `icd_codes` */

CREATE TABLE `icd_codes` (
  `nr` bigint NOT NULL AUTO_INCREMENT,
  `diagnosis_code` varchar(12) NOT NULL,
  `description` varchar(255) NOT NULL,
  `IS_CURRENT_ICD` int NOT NULL,
  `is_fav` tinyint(1) DEFAULT NULL COMMENT '1=favorate',
  `IP_USAGE` varchar(255) NOT NULL,
  `OP_USAGE` varchar(255) NOT NULL,
  `AVG_USAGE` varchar(255) NOT NULL,
  `IS_NEC` int NOT NULL,
  `SNOMED_CID` varchar(255) NOT NULL,
  `SNOMED_FSN` varchar(255) NOT NULL,
  `SNOMED_VALUESET` varchar(255) DEFAULT NULL,
  `IS_1-1MAP` int NOT NULL,
  `CORE_USAGE` varchar(255) NOT NULL,
  `IN_CORE` int NOT NULL,
  `class_sub` varchar(5) DEFAULT NULL,
  `type` varchar(1) DEFAULT 'D' COMMENT 'D=ICD9, X=ICD10',
  `is_cc` tinyint(1) DEFAULT NULL,
  `body_indicator` tinyint DEFAULT NULL,
  `notes` text,
  `std_code` char(1) DEFAULT NULL,
  `sub_level` tinyint NOT NULL DEFAULT '0',
  `remarks` text,
  `extra_codes` text,
  `extra_subclass` text,
  `default_select` tinyint DEFAULT '0',
  `sort` tinyint DEFAULT NULL,
  `is_active` tinyint NOT NULL DEFAULT '1',
  `m_sync_app_status_id` tinyint DEFAULT '0',
  PRIMARY KEY (`nr`),
  KEY `icd_code_is_active` (`is_active`),
  KEY `default_select_index` (`default_select`),
  KEY `dianosis_code` (`diagnosis_code`),
  KEY `diagnosis` (`description`),
  KEY `SNOMED_CID` (`SNOMED_CID`),
  KEY `SNOMED_FSN` (`SNOMED_FSN`),
  KEY `is_fav` (`is_fav`),
  KEY `type` (`type`)
) ENGINE=InnoDB AUTO_INCREMENT=462892 DEFAULT CHARSET=latin1;

/*Table structure for table `icd_codes_nlm` */

CREATE TABLE `icd_codes_nlm` (
  `nr` int NOT NULL AUTO_INCREMENT,
  `diagnosis_code` varchar(12) NOT NULL,
  `description` varchar(255) NOT NULL,
  `SNOMED_CID` varchar(255) NOT NULL,
  `SNOMED_FSN` varchar(255) NOT NULL,
  `SNOMED_VALUESET` varchar(255) DEFAULT NULL,
  `type` varchar(1) DEFAULT 'D' COMMENT 'D=ICD9, X=ICD10',
  `sort` tinyint DEFAULT NULL,
  `is_active` tinyint NOT NULL DEFAULT '1',
  PRIMARY KEY (`nr`),
  KEY `icd_code_is_active` (`is_active`),
  KEY `dianosis_code` (`diagnosis_code`),
  KEY `diagnosis` (`description`)
) ENGINE=InnoDB AUTO_INCREMENT=179789 DEFAULT CHARSET=latin1;

/*Table structure for table `icd_codes_old` */

CREATE TABLE `icd_codes_old` (
  `nr` int NOT NULL AUTO_INCREMENT,
