  `order_index` int NOT NULL DEFAULT '0',
  `status` enum('QUEUED','IN_PROGRESS','COMPLETED','FAILED','FAILED_DISPATCH','PENDING','WAITING') DEFAULT NULL,
  `start_time` datetime DEFAULT NULL,
  `end_time` datetime DEFAULT NULL,
  `estimated_runtime` int DEFAULT NULL,
  `actual_runtime` int DEFAULT NULL,
  `total_records` int DEFAULT NULL,
  `remarks` text,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `error_message` varchar(255) DEFAULT NULL,
  `records` int DEFAULT NULL,
  `population` int DEFAULT NULL,
  `runtime_seconds` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `batch_id` (`batch_id`,`measure_id`),
  UNIQUE KEY `uniq_batch_measure` (`batch_id`,`measure_id`),
  KEY `idx_job_status_batch` (`batch_id`,`measure_id`,`status`)
) ENGINE=InnoDB AUTO_INCREMENT=350 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

