  `origid` varchar(64) DEFAULT NULL,
  `type` enum('HCC','Lab','ED/Inpatient','Alerts','MD Review','Hedis/Quality','Rx Adverse','Rx Refill') NOT NULL,
  `ref_id` bigint DEFAULT NULL COMMENT 'id of diagnosis, lab result, medication, quality measure',
  `ref` int DEFAULT NULL,
  `ref_detail` varchar(50) DEFAULT NULL,
  `ref_description` text,
  `original_status` int DEFAULT NULL COMMENT '0-Start, 1-Red, 2-Yellow, 3-Orange, 4-Green',
  `current_status` int DEFAULT '0' COMMENT '0-Start, 1-Red, 2-Yellow, 3-Orange, 4-Green',
  `ref_date` datetime NOT NULL,
  `ack_date` datetime DEFAULT NULL,
  `ack_by` varchar(180) DEFAULT NULL,
  `ack_notes` text,
  `resolved_date` datetime DEFAULT NULL,
  `resolved_by` varchar(180) DEFAULT NULL,
  `md_review_status` int DEFAULT '0' COMMENT '0-Not Send, 1-Sent, 2-Reviewed',
  `md_reviewed_date` datetime DEFAULT NULL,
  `md_reviewed_by` varchar(180) DEFAULT NULL,
  `added_date` datetime DEFAULT NULL,
  `source` varchar(70) DEFAULT NULL,
  PRIMARY KEY (`nr`,`ref_date`),
  KEY `Index_origid` (`origid`),
  KEY `Index_ref_date` (`ref_date`),
  KEY `Index_status` (`current_status`),
  KEY `index_type` (`type`),
  KEY `index_ref` (`ref`)
) ENGINE=InnoDB AUTO_INCREMENT=5319453 DEFAULT CHARSET=utf8mb3
/*!50100 PARTITION BY RANGE (year(`ref_date`))
(PARTITION p2022 VALUES LESS THAN (2023) ENGINE = InnoDB,
 PARTITION p2023 VALUES LESS THAN (2024) ENGINE = InnoDB,
 PARTITION p2024 VALUES LESS THAN (2025) ENGINE = InnoDB,
 PARTITION pMax VALUES LESS THAN MAXVALUE ENGINE = InnoDB) */;

