/*Table structure for table `mra_uamcc_details` */

CREATE TABLE `mra_uamcc_details` (
  `nr` int NOT NULL AUTO_INCREMENT,
  `origid` varchar(50) DEFAULT NULL COMMENT 'Patient ID',
  `condition_category` varchar(255) DEFAULT NULL COMMENT 'Chronic condition category',
  `diagnosis_code` varchar(50) DEFAULT NULL COMMENT 'Diagnosis code (ICD-10 formatted with dots)',
  `diagnosis_desc` text COMMENT 'Diagnosis description from icd_codes',
  `service_date` date DEFAULT NULL COMMENT 'Date of service',
  `prov_npi_nr` varchar(50) DEFAULT NULL COMMENT 'Provider NPI number',
  `prov_name` varchar(255) DEFAULT NULL COMMENT 'Provider name from personell table',
  `partg_phys` tinyint(1) DEFAULT '0' COMMENT '1=participating physician, 0=not participating',
  `prov_taxonomy` varchar(255) DEFAULT NULL COMMENT 'Provider taxonomy/speciality',
  `facility_npi` varchar(50) DEFAULT NULL COMMENT 'Facility NPI number',
  `facility_name` varchar(255) DEFAULT NULL COMMENT 'Facility name',
  `billing_tin_name` varchar(255) DEFAULT NULL COMMENT 'Billing TIN name',
  `claim_source` varchar(100) DEFAULT NULL COMMENT 'Claim source',
  `claim_type` varchar(100) DEFAULT NULL COMMENT 'Claim type',
  `pcp_diagnosis_code` varchar(50) DEFAULT NULL COMMENT 'PCP diagnosis code',
  `pcp_service_date` date DEFAULT NULL COMMENT 'PCP service date',
  `pcp_provider_name` varchar(255) DEFAULT NULL COMMENT 'PCP provider name',
  `pcp_billing_status` varchar(100) DEFAULT NULL COMMENT 'PCP billing status',
  `version` char(8) DEFAULT NULL COMMENT 'Version in YYYYMMDD format',
  `is_most_recent_per_category` tinyint(1) DEFAULT '0',
  `error_notes` text,
  PRIMARY KEY (`nr`),
  KEY `origid` (`origid`),
  KEY `version` (`version`),
  KEY `condition_category` (`condition_category`),
  KEY `prov_npi_nr` (`prov_npi_nr`)
) ENGINE=InnoDB AUTO_INCREMENT=255897 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

/*Table structure for table `mra_uamcc_flatfile` */

CREATE TABLE `mra_uamcc_flatfile` (
  `nr` int NOT NULL AUTO_INCREMENT,
  `origid` varchar(50) DEFAULT NULL COMMENT 'Patient ID',
  `condition_category` varchar(255) DEFAULT NULL COMMENT 'Chronic condition category',
  `diagnosis_code` varchar(50) DEFAULT NULL COMMENT 'Diagnosis code (raw format)',
  `service_date` date DEFAULT NULL COMMENT 'Date of service',
  `prov_npi_nr` varchar(50) DEFAULT NULL COMMENT 'Provider NPI number',
  `provider_name` varchar(255) DEFAULT '',
  `facility_npi` varchar(50) DEFAULT NULL COMMENT 'Facility NPI number',
  `facility_name` varchar(255) DEFAULT NULL COMMENT 'Facility name',
  `billing_tin_name` varchar(255) DEFAULT NULL COMMENT 'Billing TIN name',
  `claim_source` varchar(100) DEFAULT NULL COMMENT 'Claim source',
  `claim_type` varchar(100) DEFAULT NULL COMMENT 'Claim type',
  `pcp_diagnosis_code` varchar(50) DEFAULT NULL COMMENT 'PCP diagnosis code',
  `pcp_service_date` date DEFAULT NULL COMMENT 'PCP service date',
  `pcp_provider_name` varchar(255) DEFAULT NULL COMMENT 'PCP provider name',
  `pcp_billing_status` varchar(100) DEFAULT NULL COMMENT 'PCP billing status',
  `version` char(8) DEFAULT NULL COMMENT 'Version in YYYYMMDD format',
  `file_name` varchar(255) DEFAULT NULL COMMENT 'Source filename',
  `error_notes` text COMMENT 'Error messages if processing failed',
  `processed` tinyint(1) DEFAULT '0' COMMENT '0=not processed, 1=processed into details',
  `is_participant_provider` tinyint(1) DEFAULT '0',
  `provider_taxonomy` varchar(255) DEFAULT NULL,
  `is_most_recent_per_category` tinyint(1) DEFAULT '0',
  PRIMARY KEY (`nr`),
  KEY `processed` (`processed`),
  KEY `origid` (`origid`),
  KEY `version` (`version`)
) ENGINE=InnoDB AUTO_INCREMENT=255897 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

