/*Table structure for table `patient_access_history` */

CREATE TABLE `patient_access_history` (
  `nr` bigint unsigned NOT NULL AUTO_INCREMENT,
  `origid` varchar(64) DEFAULT NULL,
  `service_date` date NOT NULL,
  `procedure_type` varchar(50) DEFAULT NULL,
  `location` varchar(150) DEFAULT NULL,
  `type_of_access` varchar(50) DEFAULT NULL,
  `placed_by` varchar(50) DEFAULT NULL,
  `placed_doctor_name` varchar(200) DEFAULT NULL,
  `referrer_dr` varchar(200) DEFAULT NULL,
  `placed_other_name` varchar(200) DEFAULT NULL,
  `surgeon` varchar(255) DEFAULT NULL,
  `interventionalist` varchar(255) DEFAULT NULL,
  `primary_doctor` varchar(255) DEFAULT NULL,
  `performing_doctor` varchar(255) DEFAULT NULL,
  `hospital` varchar(250) DEFAULT NULL,
  `dialysis_center` varchar(250) DEFAULT NULL,
  `access_notes` text,
  `created_by` varchar(200) DEFAULT NULL,
  `created_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `encounter_nr` bigint unsigned DEFAULT '0',
  `start_using_date` date DEFAULT NULL,
  `abandoned_date` date DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT '1',
  `is_inuse` tinyint(1) DEFAULT '1',
  `is_abandoned` tinyint(1) DEFAULT '1',
  `procedure_name` varchar(125) DEFAULT NULL,
  `is_success` tinyint DEFAULT '0',
  `functional_at_next_dialysis` tinyint DEFAULT '0',
  `indication` varchar(60) DEFAULT NULL,
  `assessment_of_access` text,
  `angioplasty_site` text,
  `stent_type` text,
  `balloon` text,
  `date_first_used` date DEFAULT NULL,
  PRIMARY KEY (`nr`),
  KEY `patient_access_history_origid_idx` (`origid`),
  KEY `encounter_nr` (`encounter_nr`),
  KEY `procedure_type` (`procedure_type`,`type_of_access`),
  KEY `service_date` (`service_date`)
) ENGINE=InnoDB AUTO_INCREMENT=284 DEFAULT CHARSET=latin1;

/*Table structure for table `patient_access_history_verification` */

CREATE TABLE `patient_access_history_verification` (
  `nr` bigint NOT NULL AUTO_INCREMENT,
  `origid` varchar(64) NOT NULL,
  `requested_by` varchar(200) NOT NULL,
  `requested_date` datetime NOT NULL,
