  KEY `origid` (`origid`,`status`),
  KEY `assigned_doctor` (`assigned_doctor`)
) ENGINE=InnoDB AUTO_INCREMENT=143 DEFAULT CHARSET=latin1;

/*Table structure for table `patient_alert_notification` */

CREATE TABLE `patient_alert_notification` (
  `nr` bigint NOT NULL AUTO_INCREMENT,
  `hl7_message_queue_nr` bigint DEFAULT NULL,
  `alert_type` enum('adt','cm') DEFAULT NULL,
  `origid` varchar(64) DEFAULT NULL,
  `message_type` enum('Email','Fax','sms','direct','Both') DEFAULT NULL,
  `to` varchar(80) DEFAULT NULL,
  `to_name` varchar(80) DEFAULT NULL,
  `encounter_nr` bigint unsigned NOT NULL,
  `content` text,
  `status` tinyint(1) DEFAULT '0' COMMENT 'if sms or email is sent status=1',
  `event_type` varchar(100) DEFAULT NULL,
  `notification_status` tinyint(1) DEFAULT '0' COMMENT 'if alert notification link is clicked notification_status=1 mean alert is read',
  `first_notification` datetime DEFAULT NULL,
  `second_notification` datetime DEFAULT NULL,
  `3rd_notification` datetime DEFAULT NULL,
  `created_date` datetime DEFAULT NULL,
  `failed_reason` text,
  `no_retries` tinyint(1) DEFAULT '0',
  `ack_by` varchar(100) DEFAULT NULL,
  `ack_datetime` datetime DEFAULT NULL,
  `modify_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`nr`),
  KEY `enc_nr` (`encounter_nr`),
  KEY `origid` (`origid`),
  KEY `m7key` (`modify_time`)
) ENGINE=InnoDB AUTO_INCREMENT=631300 DEFAULT CHARSET=latin1;

