/*Table structure for table `qpi_batch_actions` */

CREATE TABLE `qpi_batch_actions` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `batch_id` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `measure_id` int DEFAULT NULL,
  `action` enum('RETRY','RETRY_TRIGGERED','CREATE','DELETE','PAUSE','RESUME') COLLATE utf8mb4_unicode_ci NOT NULL,
  `message` text COLLATE utf8mb4_unicode_ci,
  `created_by` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_batch_id` (`batch_id`),
  KEY `idx_measure_action` (`measure_id`,`action`),
  KEY `idx_created_at` (`created_at` DESC)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

/*Table structure for table `qpi_batch_status` */

CREATE TABLE `qpi_batch_status` (
  `id` int NOT NULL AUTO_INCREMENT,
  `batch_id` varchar(50) NOT NULL,
  `step_name` varchar(100) NOT NULL,
  `worker_index` int NOT NULL,
  `status` enum('COMPLETED','FAILED') DEFAULT 'COMPLETED',
  `failure_reason` varchar(1000) DEFAULT NULL,
  `duration_secs` int DEFAULT '0',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `measure_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_worker_status` (`batch_id`,`step_name`,`worker_index`,`measure_id`),
  KEY `idx_qbs_batch_process` (`batch_id`,`step_name`,`worker_index`)
) ENGINE=InnoDB AUTO_INCREMENT=766 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

/*Table structure for table `qpi_facility_summary` */

CREATE TABLE `qpi_facility_summary` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `batch_id` varchar(50) NOT NULL,
  `measure_id` varchar(10) NOT NULL,
  `facility_nr` varchar(20) NOT NULL,
  `total_denominator` int DEFAULT '0',
  `total_numerator` int DEFAULT '0',
  `duration_secs` int DEFAULT '0',
  `months_processed` varchar(20) NOT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_batch_facility_month` (`batch_id`,`measure_id`,`facility_nr`,`months_processed`)
) ENGINE=InnoDB AUTO_INCREMENT=1092 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

/*Table structure for table `qpi_failed_records` */

CREATE TABLE `qpi_failed_records` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'Surrogate key',
  `origid` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'TFU origid / encounter id',
  `batch_id` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Batch that was processing',
  `reason` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Truncated failure reason',
  `status` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'FAILED' COMMENT 'FAILED / RETRIED / RESOLVED',
  `measure_id` int DEFAULT NULL COMMENT 'Measure identifier (e.g. 1023 for TFU)',
  `month` tinyint unsigned DEFAULT NULL COMMENT 'Processing month (1-12)',
  `year` smallint unsigned DEFAULT NULL COMMENT 'Processing year',
  `provider_npi` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Associated provider NPI',
  `facility_nr` varchar(25) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Facility number',
  `retry_count` smallint unsigned NOT NULL DEFAULT '0' COMMENT 'Times we retried this record',
  `logged_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Initial failure timestamp',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Last update timestamp',
  PRIMARY KEY (`id`),
  KEY `idx_origid_batch` (`origid`,`batch_id`),
  KEY `idx_batch_status` (`batch_id`,`status`),
  KEY `idx_measure_year` (`measure_id`,`year`,`month`),
  KEY `idx_facility` (`facility_nr`,`logged_at`)
) ENGINE=InnoDB AUTO_INCREMENT=87749 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Captures TFU/QPI records that failed to process so they can be analyzed or retried';

/*Table structure for table `qpi_origid_tracker` */

CREATE TABLE `qpi_origid_tracker` (
  `batch_id` varchar(50) NOT NULL,
  `process_name` varchar(100) NOT NULL,
  `facility_nr` varchar(20) DEFAULT NULL,
  `type` enum('denom','num') NOT NULL,
  `last_processed_origid` varchar(50) DEFAULT NULL,
  `last_processed_ref_id` varchar(50) DEFAULT NULL,
  `measure_id` int DEFAULT NULL,
  PRIMARY KEY (`batch_id`,`process_name`,`type`),
  UNIQUE KEY `idx_origid_tracker_key` (`batch_id`,`process_name`,`type`),
  UNIQUE KEY `idx_origid_process_key` (`batch_id`,`process_name`,`type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

/*Table structure for table `qpi_process_tracker` */

CREATE TABLE `qpi_process_tracker` (
  `id` int NOT NULL AUTO_INCREMENT,
  `process_name` varchar(100) NOT NULL,
  `last_processed_facility_nr` varchar(20) DEFAULT NULL,
  `facility_nr` varchar(20) DEFAULT NULL,
  `batch_id` varchar(50) NOT NULL,
  `status` enum('IN_PROGRESS','COMPLETED','FAILED') DEFAULT 'IN_PROGRESS',
  `failure_reason` varchar(1000) DEFAULT NULL,
  `last_processed_origid` varchar(100) DEFAULT NULL,
  `start_time` datetime DEFAULT NULL,
  `end_time` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `measure_id` int DEFAULT NULL,
  `last_processed_stage` varchar(50) DEFAULT NULL,
  `last_processed_group` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_process_batch` (`process_name`,`batch_id`),
  UNIQUE KEY `uniq_process_batch` (`process_name`,`batch_id`),
  KEY `idx_qpt_batch_measure_process` (`batch_id`,`measure_id`,`process_name`),
  KEY `ix_qpi_tracker_batch_measure_time` (`batch_id`,`measure_id`,`updated_at` DESC),
  KEY `ix_qpi_tracker_batch_status` (`batch_id`,`status`)
) ENGINE=InnoDB AUTO_INCREMENT=807801 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

/*Table structure for table `qpi_provider_summary` */

CREATE TABLE `qpi_provider_summary` (
