  `studyuid` varchar(64) NOT NULL,
  `description` varchar(64) DEFAULT NULL,
  `seriesdate` date DEFAULT NULL,
  `seriestime` time DEFAULT NULL,
  `department` varchar(64) DEFAULT NULL,
  `stationname` varchar(16) DEFAULT NULL,
  `modality` varchar(16) DEFAULT NULL,
  `bodypart` varchar(16) DEFAULT NULL,
  `seriesnumber` int DEFAULT NULL,
  `instances` int DEFAULT NULL,
  `protocolname` varchar(64) DEFAULT NULL,
  `operatorname` varchar(64) DEFAULT NULL,
  `institution` varchar(64) DEFAULT NULL,
  PRIMARY KEY (`uuid`),
  KEY `studyuid` (`studyuid`),
  KEY `seriesnumber` (`seriesnumber`),
  KEY `uuid_index` (`uuid`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

/*Table structure for table `sessions` */

CREATE TABLE `sessions` (
