  KEY `username` (`username`),
  FULLTEXT KEY `notes` (`notes`)
) ENGINE=InnoDB AUTO_INCREMENT=5066 DEFAULT CHARSET=latin1;

/*Table structure for table `studynotes_billing_status` */

CREATE TABLE `studynotes_billing_status` (
  `nr` int unsigned NOT NULL AUTO_INCREMENT,
  `patient_id` varchar(64) NOT NULL,
  `encounter_nr` bigint unsigned NOT NULL,
  `notes_id` int NOT NULL,
  `notes_date_time` datetime NOT NULL,
  `notes_received_from` varchar(64) NOT NULL,
  `billing_status` tinyint DEFAULT NULL,
  `billing_processed_date` datetime DEFAULT NULL,
  `hl7_message` text,
  PRIMARY KEY (`nr`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

/*Table structure for table `studynotes_billing_status_resend` */

CREATE TABLE `studynotes_billing_status_resend` (
  `nr` int unsigned NOT NULL AUTO_INCREMENT,
  `patient_id` varchar(64) NOT NULL,
  `encounter_nr` bigint unsigned NOT NULL,
  `notes_id` int NOT NULL,
  `notes_date_time` datetime NOT NULL,
  `notes_received_from` varchar(64) NOT NULL,
  `billing_status` tinyint DEFAULT NULL,
  `billing_processed_date` datetime DEFAULT NULL,
  `hl7_message` text,
  PRIMARY KEY (`nr`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

/*Table structure for table `studynotes_pending` */

CREATE TABLE `studynotes_pending` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `origid` varchar(64) NOT NULL DEFAULT '',
  `lastname` varchar(64) DEFAULT NULL,
  `firstname` varchar(64) DEFAULT NULL,
  `middlename` varchar(64) DEFAULT NULL,
  `birthdate` date DEFAULT NULL,
  `sex` varchar(16) DEFAULT NULL,
  `addr_zip` varchar(15) DEFAULT NULL,
  `procedure_date` datetime NOT NULL,
  `referringphysician` varchar(125) DEFAULT NULL,
  `readingphysician` varchar(125) DEFAULT NULL,
  `procedure_description` varchar(125) DEFAULT NULL,
  `notes` text,
  `encounter_nr` varchar(100) DEFAULT NULL,
  `created_date` datetime NOT NULL,
  `hl7_message` text,
  `status` tinyint DEFAULT NULL COMMENT '0 - unprocessed, 1 - processed',
  `study_notes_id` int unsigned DEFAULT NULL,
  `updated_by` varchar(150) DEFAULT NULL,
  `updated_date` datetime DEFAULT NULL,
  `hl7_location` varchar(150) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `encounter_nr` (`encounter_nr`),
  KEY `origid` (`origid`),
  KEY `procedure_date` (`procedure_date`),
  KEY `status` (`status`),
  KEY `study_notes_id` (`study_notes_id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

/*Table structure for table `studynotes_settings` */

CREATE TABLE `studynotes_settings` (
  `nr` bigint NOT NULL AUTO_INCREMENT,
  `name` text,
  `block_nr` bigint DEFAULT NULL,
  `type` text,
  `status` tinyint DEFAULT NULL,
  `user_status` tinyint DEFAULT NULL,
  `default_selected` tinyint DEFAULT NULL,
  `display_order` int DEFAULT NULL,
  `created_by` varchar(250) DEFAULT NULL,
  `created_date` datetime DEFAULT NULL,
  PRIMARY KEY (`nr`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

/*Table structure for table `studynotes_temp` */

CREATE TABLE `studynotes_temp` (
  `studynotes_id` int DEFAULT NULL,
  `id` int NOT NULL AUTO_INCREMENT,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

/*Table structure for table `studynotes_us_diagram_tags` */

CREATE TABLE `studynotes_us_diagram_tags` (
