/* Trigger structure for table `study` */

DELIMITER $$

/*!50003 CREATE */ /*!50003 TRIGGER `trg_update_encounter_info` AFTER INSERT ON `study` FOR EACH ROW BEGIN
DECLARE m_encounter_number BIGINT DEFAULT 0;
DECLARE m_old_uuid VARCHAR(64) DEFAULT NULL;
IF EXISTS (SELECT 'X' FROM encounter WHERE encounter_nr = NEW.accessionnum) THEN
	SELECT encounter_nr INTO m_encounter_number FROM encounter WHERE encounter_nr = NEW.accessionnum;
ELSEIF EXISTS ( SELECT 'X' FROM encounter WHERE encounter_nr = NEW.id ) THEN
	SELECT encounter_nr INTO m_encounter_number FROM encounter WHERE encounter_nr = NEW.id;
END IF;
IF (m_encounter_number>0) THEN
BEGIN
	BEGIN
		SELECT UUID INTO m_old_uuid FROM encounter_study_assocs WHERE (encounter_nr = NEW.accessionnum OR encounter_nr = NEW.id ) AND UUID = NEW.UUID  LIMIT 1;
	END;
	IF(ISNULL(m_old_uuid)) THEN
		INSERT INTO encounter_study_assocs (encounter_nr, UUID) VALUES ( m_encounter_number, NEW.UUID);
	END IF;
END;
ELSEIF NOT EXISTS (SELECT 'X' FROM encounter_study_assocs WHERE UUID = NEW.UUID) THEN
 UPDATE sequence_table_data SET sequence_id = sequence_id +1 WHERE sequence_name='encounter';
 SELECT CONCAT(DATE_FORMAT(CURRENT_DATE,'%Y%m%d'),sequence_id) INTO  m_encounter_number
 FROM sequence_table_data WHERE sequence_name='encounter';
 INSERT INTO encounter_study_assocs (encounter_nr, UUID) VALUES ( m_encounter_number, NEW.UUID);
 INSERT IGNORE INTO encounter (encounter_nr, origid, encounter_date,encounter_status, encounter_class_nr, referrer_dr,consulting_dr,
  is_discharged, discharge_date, discharge_time, STATUS, history, create_id, create_time, hospital_nr, bed_time_procedure,modify_id )
 VALUES (m_encounter_number, NEW.patientid, NEW.studydate,'cancelled',3 ,NEW.referringphysician, NEW.readingphysician,
  1,NEW.studydate, NEW.studytime,'closed','Study created from images', 'pacs', CURRENT_DATE(), 1, 0,'pacs');
 INSERT IGNORE INTO appointment (encounter_nr,origid,DATE,TIME,hospital_nr,to_dept_nr,to_personell_nr,to_personell_name,
  purpose,encounter_class_nr,is_pre_schedule,filler_app_id,admitting_department,room_number)
 VALUES (m_encounter_number,NEW.patientid,NOW(),NOW(),1,14,0,'','Created from Study images',2,0,'','','');
 INSERT IGNORE INTO encounter_procedure SET admitting_nurse='',admitting_physician='', encounter_nr=m_encounter_number, procedure_date=NOW(), interventionalist='', procedure_type='unknown';
 INSERT IGNORE INTO cpoe_orders  SET order_id = CONCAT('OE-AP-',DATE_FORMAT(NOW(),'%Y%m%d'),'-0'),
  master_order_id = CONCAT('OE-MO-',DATE_FORMAT(NOW(),'%Y%m%d'),'-',DATE_FORMAT(NOW(),'%h%i%s'),'-1-84'),
  order_date=NOW(), created_date=NOW(), created_by='pacs study', order_type='appointment', 
  order_status='pending', patient_id=NEW.patientid, encounter_nr=m_encounter_number, 
  doctor=0, category=1, sub_category=84, item=5001, order_properties='Outpatient';
 INSERT IGNORE INTO encounter_page_options_status (page_header_nr, page_option_nr, o_status, encounter_nr, o_is_header)
 SELECT a_header_nr, o.o_nr, 0, m_encounter_number AS encounter_nr, o.o_is_header FROM page_options_list AS o
 INNER JOIN page_options_assocs AS a ON a.a_option_nr = o_nr
 LEFT JOIN encounter_page_options_status AS r ON (r.page_option_nr = o.o_nr AND page_header_nr = a_header_nr AND encounter_nr = m_encounter_number)
 WHERE o_show_status = 1 AND r.page_option_nr IS NULL;
 INSERT IGNORE INTO encounter_page_options_status (page_header_nr, page_option_nr, o_status, encounter_nr, o_is_header)
 SELECT o.o_nr AS a_header_nr, o.o_nr, 0, m_encounter_number AS encounter_nr, o.o_is_header FROM page_options_list AS o
 LEFT JOIN encounter_page_options_status AS r ON (r.page_option_nr = o.o_nr AND page_header_nr = o.o_nr AND encounter_nr = m_encounter_number)
 WHERE o_show_status = 1 AND o.o_is_header = 1 AND r.page_option_nr IS NULL AND o.o_nr IN(SELECT DISTINCT a_header_nr FROM page_options_assocs);
END IF;
UPDATE patient SET date_reg = (CAST(NOW() AS DATETIME)) WHERE origid = NEW.patientid AND date_reg IS NULL;
UPDATE patient SET modify_id = 'pacs' WHERE origid = NEW.patientid AND modify_id IS NULL;
UPDATE worklist SET STATUS = 900 WHERE accessionnum = m_encounter_number AND STATUS <> 200;
END */$$


DELIMITER ;

