/* Function  structure for function  `emar_get_time` */

DELIMITER $$

/*!50003 CREATE FUNCTION `emar_get_time`(orid VARCHAR(255),enc_nr INT,med VARCHAR(255),cur_date DATE) RETURNS varchar(250) CHARSET utf8mb3
BEGIN
	DECLARE med_time VARCHAR(250);
	DECLARE ret_time VARCHAR(250);
	DECLARE front TEXT DEFAULT NULL;
	DECLARE frontlen INT DEFAULT NULL;
	DECLARE TempValue TEXT DEFAULT NULL;
	SET med_time = '';
	SET ret_time = '';
	SELECT medication_time INTO med_time FROM encounter_patient_medication WHERE patientid=orid AND (stop_date > CAST(CURRENT_TIMESTAMP AS DATE) OR stop_date = '0000-00-00 00:00:00' OR stop_date IS NULL) AND TYPE='ORDER' AND medications=med AND start_date <= cur_date AND stop_date > cur_date LIMIT 1;
   iterator:
   LOOP  
   IF LENGTH(TRIM(med_time)) = 0 OR med_time IS NULL THEN
	LEAVE iterator;
   END IF;
   
   SET front = SUBSTRING_INDEX(med_time,',',1);
   SET frontlen = LENGTH(front);
   SET TempValue = TRIM(front);
   SET med_time = INSERT(med_time,1,frontlen + 1,'');
   IF( DATE_FORMAT(NOW(),'%h:00:00') > STR_TO_DATE(TempValue,'%h:%i %p') ) THEN
	SET ret_time := CONCAT(ret_time,',',TempValue);
   END IF;
   END LOOP;
	RETURN ret_time;
    END */$$
DELIMITER ;

/* Function  structure for function  `ExtractDate` */

DELIMITER $$

/*!50003 CREATE FUNCTION `ExtractDate`(text_input TEXT) RETURNS text CHARSET latin1
    DETERMINISTIC
BEGIN
    DECLARE extracted_date TEXT;
    
    -- Use REGEXP to find date patterns
   IF text_input REGEXP '[0-9]{2}/[0-9]{2}/[0-9]{4}' THEN
        SET extracted_date = SUBSTRING(text_input, LOCATE('/', text_input) - 2, 10);
   ELSEIF text_input REGEXP '[0-9]{1}/[0-9]{2}/[0-9]{4}' THEN
        SET extracted_date = CONCAT('0',SUBSTRING(text_input, LOCATE('/', text_input) - 1, 9));   
   ELSEIF text_input REGEXP '[0-9]{2}/[0-9]{1}/[0-9]{4}' THEN
        SET extracted_date = CONCAT(LEFT(CONCAT('',SUBSTRING(text_input, LOCATE('/', text_input) - 2, 9)),3),CONCAT('0',SUBSTRING(SUBSTRING(text_input, LOCATE('/', text_input) - 2, 9),4,8))) ;
   ELSEIF text_input REGEXP '[0-9]{1}/[0-9]{1}/[0-9]{4}' THEN
        SET extracted_date = CONCAT(LEFT(CONCAT('0',SUBSTRING(text_input, LOCATE('/', text_input) - 1, 8)),3),CONCAT('0',SUBSTRING(SUBSTRING(text_input, LOCATE('/', text_input) - 1, 8),3,8))) ; 
        
        
ELSEIF text_input REGEXP '[0-9]{2}/[0-9]{2}/[0-9]{2}' THEN
        SET extracted_date = CONCAT(LEFT(SUBSTRING(text_input, LOCATE('/', text_input) - 2, 8),6),'20',RIGHT(SUBSTRING(text_input, LOCATE('/', text_input) - 2, 8),2)) ;
   ELSEIF text_input REGEXP '[0-9]{1}/[0-9]{2}/[0-9]{2}' THEN
        SET extracted_date = CONCAT(LEFT(CONCAT('0',SUBSTRING(text_input, LOCATE('/', text_input) - 1, 7)),6),'20',RIGHT(CONCAT('0',SUBSTRING(text_input, LOCATE('/', text_input) - 1, 7)),2));   

   ELSEIF text_input REGEXP '[0-9]{2}/[0-9]{1}/[0-9]{2}' THEN
        SET extracted_date = CONCAT(LEFT(CONCAT(LEFT(CONCAT('',SUBSTRING(text_input, LOCATE('/', text_input) - 2, 7)),3),CONCAT('0',SUBSTRING(SUBSTRING(text_input, LOCATE('/', text_input) - 2, 7),4,7))),6),'20',RIGHT(CONCAT(LEFT(CONCAT('',SUBSTRING(text_input, LOCATE('/', text_input) - 2, 7)),3),CONCAT('0',SUBSTRING(SUBSTRING(text_input, LOCATE('/', text_input) - 2, 7),4,7))),2)) ;
   
   
   ELSEIF text_input REGEXP '[0-9]{1}/[0-9]{1}/[0-9]{2}' THEN
        SET extracted_date = CONCAT(LEFT(CONCAT(LEFT(CONCAT('0',SUBSTRING(text_input, LOCATE('/', text_input) - 1, 5)),3),CONCAT('0',SUBSTRING(SUBSTRING(text_input, LOCATE('/', text_input) - 1, 5),3,6))),6),'20',RIGHT(CONCAT(LEFT(CONCAT('0',SUBSTRING(text_input, LOCATE('/', text_input) - 1, 6)),3),CONCAT('0',SUBSTRING(SUBSTRING(text_input, LOCATE('/', text_input) - 1, 6),3,6))),2)) ; 
        
       
        
        
        
    

    
    ELSE
        SET extracted_date = NULL;  -- No valid date found
    END IF;
    
    RETURN extracted_date;
END */$$
DELIMITER ;

/* Function  structure for function  `fetch_room_info` */

DELIMITER $$

/*!50003 CREATE FUNCTION `fetch_room_info`(appointment_id BIGINT) RETURNS varchar(50) CHARSET latin1
    READS SQL DATA
BEGIN
	DECLARE room_name VARCHAR(50);
	SET room_name = '';
	SELECT hr.name INTO room_name FROM hospital_rooms hr INNER JOIN `procedure_room` pr ON hr.nr=pr.room_nr INNER JOIN appointment a ON a.encounter_nr=pr.encounter_nr WHERE a.nr=appointment_id AND pr.room_type='OR-Room';
	RETURN room_name;
END */$$
DELIMITER ;

/* Function  structure for function  `getReadmitCount` */

DELIMITER $$

/*!50003 CREATE FUNCTION `getReadmitCount`(orig_id VARCHAR(64),enc_date DATETIME) RETURNS int
BEGIN
    DECLARE mcnt INT;
    SELECT IF(COUNT(encounter_nr )>1,1,0) INTO mcnt  FROM mra1_encounter WHERE  enc_disch_date BETWEEN DATE_ADD(enc_date, INTERVAL -30 DAY) AND enc_date AND enc_class_nr IN (1,9) AND enc_pos IN (60,61) AND patient_id=orig_id;
    RETURN mcnt;
    END */$$
DELIMITER ;

/* Function  structure for function  `get_2nd_laboratary_result_data` */

DELIMITER $$

/*!50003 CREATE FUNCTION `get_2nd_laboratary_result_data`(patient_id BIGINT,Loinc_Number TEXT,start_date DATETIME,end_date DATETIME) RETURNS text CHARSET latin1
    READS SQL DATA
BEGIN
          DECLARE en_date   VARCHAR(50) DEFAULT '';
	  DECLARE l_code   VARCHAR(50) DEFAULT '';
	  DECLARE no_more_dates INT;	
	  DECLARE e_start INT DEFAULT 0;
	  DECLARE e_limit INT DEFAULT 1;
	  DECLARE order_status VARCHAR(4) DEFAULT 'ORDER BY e.encounter_date ASC';
	DECLARE date_csr CURSOR FOR
        SELECT DATE_FORMAT(mcr.result_date,'%Y-%m-%d') AS result_date FROM mucert_cpoe_result mcr 
	INNER JOIN mucert_cpoe_result_values mcrv ON mcrv.result_id = mcr.result_id  
	INNER JOIN mucert_encounter e ON e.patient_id=mcr.patient_id
	WHERE mcr.patient_id=patient_id AND FIND_IN_SET(mcrv.loinc_num,Loinc_Number)
	ORDER BY mcr.result_date DESC LIMIT 1,1
	;	
	DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_dates=1;
    
         SET no_more_dates=0;
          OPEN date_csr;
          REPEAT
               FETCH date_csr INTO l_code;  
		IF NOT no_more_dates THEN 
               SET en_date = CONCAT(en_date , l_code,', '); 
		END IF;      
          UNTIL no_more_dates
          END REPEAT;
          CLOSE date_csr;
          SET no_more_dates=0;
	  RETURN TRIM(BOTH ', ' FROM en_date);
          
    END */$$
DELIMITER ;

/* Function  structure for function  `get_allergies_date` */

DELIMITER $$

/*!50003 CREATE FUNCTION `get_allergies_date`(patient_id BIGINT, allergy VARCHAR(50)) RETURNS varchar(10) CHARSET latin1
    READS SQL DATA
BEGIN
	DECLARE al_desc   TEXT DEFAULT '';
	  DECLARE al_code   VARCHAR(100) DEFAULT '';
	  DECLARE no_more_allergy INT;
    
          DECLARE allergy_scr CURSOR FOR
		SELECT COUNT(id) AS cnt
		FROM mucert_encounter_allergy_codes meac 
		WHERE meac.patient_id = patient_id AND meac.`status`='Active' AND meac.allergy_desc=allergy
		LIMIT 0,1
		;
    
          DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_allergy=1;
    
         SET no_more_allergy=0;
          OPEN allergy_scr;
          REPEAT
               FETCH allergy_scr INTO al_code;    
              IF NOT no_more_allergy THEN 
               SET al_desc = al_code;    
		END IF;    
          UNTIL no_more_allergy
          END REPEAT;
          CLOSE allergy_scr;
          SET no_more_allergy=0;
	  RETURN TRIM(BOTH ', ' FROM al_desc);
END */$$
DELIMITER ;

/* Function  structure for function  `get_config_global` */

DELIMITER $$

/*!50003 CREATE FUNCTION `get_config_global`(property varchar(60)) RETURNS varchar(60) CHARSET utf8mb3
BEGIN
	declare present VARCHAR(60);
	DECLARE config_cur CURSOR FOR SELECT `value` FROM config_global WHERE `type`=property;
	set present=0;
	open config_cur;
	SELECT FOUND_ROWS() INTO present;
	if present=0 then
		return present;
	end if;
	fetch config_cur into present;
	return present;
    END */$$
DELIMITER ;

