/* Function  structure for function  `get_cpt_codes_encounter_date` */

DELIMITER $$

/*!50003 CREATE FUNCTION `get_cpt_codes_encounter_date`(in_encounter_nr BIGINT, modifier_val VARCHAR(255), start_date DATETIME, end_date DATETIME, cpt_codes TEXT) RETURNS varchar(500) CHARSET latin1
    READS SQL DATA
BEGIN
	DECLARE l_desc   VARCHAR(500) DEFAULT '';
	  DECLARE l_code   VARCHAR(50) DEFAULT '';
	  DECLARE no_more_cpt_ocdes INT;
    
          DECLARE cpt_csr CURSOR FOR
               SELECT e.encounter_date
				FROM mucert_encounter e
				INNER JOIN mucert_study_report_billing srb ON srb.encounter_nr = e.id
				INNER JOIN mucert_study_report_billing_codes srbc ON srb.Billing_ID = srbc.Billing_ID
				WHERE FIND_IN_SET(srbc.Billing_Code, cpt_codes)	AND srb.encounter_nr = in_encounter_nr AND e.encounter_date BETWEEN start_date AND end_date;
    
    
          DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_cpt_ocdes=1;
    
         SET no_more_cpt_ocdes=0;
          OPEN cpt_csr;
          REPEAT
               FETCH cpt_csr INTO l_code;    
		IF NOT no_more_cpt_ocdes THEN 
               SET l_desc = CONCAT(l_desc , l_code,', ');    
		END IF;   
          UNTIL no_more_cpt_ocdes
          END REPEAT;
          CLOSE cpt_csr;
          SET no_more_cpt_ocdes=0;
	  RETURN TRIM(BOTH ', ' FROM l_desc);
    END */$$
