          DECLARE icd_csr CURSOR FOR
SELECT CONCAT(cpt_name,'(',Billing_Code,')')
FROM study_report_billing_codes INNER JOIN study_report_billing ON study_report_billing.Billing_ID = study_report_billing_codes.Billing_ID INNER JOIN cpt_codes ON cpt_codes.cpt_code=study_report_billing_codes.Billing_Code
