/* Function  structure for function  `get_encounter_orders_status` */

DELIMITER $$

/*!50003 CREATE FUNCTION `get_encounter_orders_status`(inc_number BIGINT, in_order_type VARCHAR(50)) RETURNS varchar(500) CHARSET latin1
    READS SQL DATA
BEGIN
	DECLARE l_desc   VARCHAR(500) DEFAULT '';
	  DECLARE l_cat   VARCHAR(150) DEFAULT '';
	  DECLARE l_status   VARCHAR(50) DEFAULT '';
	  DECLARE no_more_orders INT;  
			
          DECLARE order_csr CURSOR FOR 
              SELECT UPPER(SUBSTRING(category,1,2)) AS category, order_status 
               FROM cpoe_orders WHERE order_type = in_order_type 
               AND encounter_nr = inc_number AND order_status != 'cancelled';
    
          DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_orders=1;       
          
           IF ( inc_number IS NULL OR inc_number = 0  ) THEN
		RETURN l_desc;
	  END IF;
    
         SET no_more_orders=0;
          OPEN order_csr;
         orders_loop:WHILE(no_more_orders=0) DO
               FETCH order_csr INTO l_cat, l_status;  
               IF no_more_orders=1 THEN
                    LEAVE orders_loop;
               END IF;  
               SET l_desc = CONCAT(l_desc , l_cat, ',', l_status,'~');    
          END WHILE orders_loop;
          CLOSE order_csr;
          SET no_more_orders=0;
	  RETURN TRIM(BOTH '~' FROM l_desc);
END */$$
DELIMITER ;

/* Function  structure for function  `get_enc_proc_count` */

DELIMITER $$

/*!50003 CREATE FUNCTION `get_enc_proc_count`(patient_id BIGINT, enc_number TINYINT, item_id TEXT,start_date DATETIME,end_date DATETIME) RETURNS tinyint
    READS SQL DATA
BEGIN
	DECLARE l_desc   TINYINT (2) DEFAULT 0;
	  DECLARE l_code  TINYINT (2)  DEFAULT 0;
	  DECLARE no_more_icd_ocdes INT;
          DECLARE icd_csr CURSOR FOR
		SELECT COUNT(mco.nr) AS 'count' 
		FROM mucert_cpoe_orders mco
		INNER JOIN mucert_encounter e ON e.id = mco.enc_id 
		WHERE e.appt_date BETWEEN start_date AND end_date AND mco.patient_id=patient_id AND FIND_IN_SET(mco.item,item_id);
          DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_icd_ocdes=1;
    
         SET no_more_icd_ocdes=0;
          OPEN icd_csr;
          REPEAT
               FETCH icd_csr INTO l_code;  
		IF NOT no_more_icd_ocdes THEN 
               SET l_desc = l_code; 
		END IF;      
          UNTIL no_more_icd_ocdes
          END REPEAT;
          CLOSE icd_csr;
          SET no_more_icd_ocdes=0;
	  RETURN TRIM(BOTH ', ' FROM l_desc);
END */$$
DELIMITER ;

/* Function  structure for function  `get_enc_study_attachments` */

DELIMITER $$

/*!50003 CREATE FUNCTION `get_enc_study_attachments`(in_encounter_nr BIGINT) RETURNS varchar(500) CHARSET latin1
    READS SQL DATA
BEGIN
	DECLARE l_desc   VARCHAR(500) DEFAULT '';
	  DECLARE l_name   VARCHAR(150) DEFAULT '';
	  DECLARE no_more_attach INT;
	  DECLARE l_id   INT(10) DEFAULT 0;  
	  
		
          DECLARE attach_csr CURSOR FOR 
          SELECT nr, file_name FROM patient_attachments WHERE page_header_nr=45 AND page_option_nr= 94 AND encounter_nr = in_encounter_nr;
    
          DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_attach=1;       
          
           IF ( in_encounter_nr IS NULL OR in_encounter_nr = 0  ) THEN
		RETURN l_desc;
	  END IF;
    
         SET no_more_attach=0;
          OPEN attach_csr;
         orders_loop:WHILE(no_more_attach=0) DO
               FETCH attach_csr INTO l_id, l_name;  
               IF no_more_attach=1 THEN
                    LEAVE orders_loop;
               END IF;  
               SET l_desc = CONCAT(l_desc , l_id, '!', l_name, '~');    
          END WHILE orders_loop;
          CLOSE attach_csr;
          SET no_more_attach=0;
	  RETURN TRIM(BOTH '~' FROM l_desc);
END */$$
