/*!50003 CREATE FUNCTION `get_first_physical_date`(patient_id BIGINT,history_nr BIGINT,start_date DATETIME,end_date DATETIME) RETURNS varchar(255) CHARSET latin1
    READS SQL DATA
BEGIN
 	DECLARE l_desc   VARCHAR(50) DEFAULT '';
	  DECLARE l_code   VARCHAR(50) DEFAULT '';
	  DECLARE no_more_med INT;
          DECLARE icd_csr CURSOR FOR
		SELECT DATE_FORMAT(e.encounter_date,'%Y-%m-%d') AS enc_date  FROM mucert_procedure_history_data mphd
		INNER JOIN mucert_encounter e ON e.id=mphd.enc_id
		WHERE e.patient_id=patient_id AND mphd.history_nr=history_nr
		AND e.encounter_date IS NOT NULL
		ORDER BY e.encounter_date ASC LIMIT 0,1;
          DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_med=1;
    
         SET no_more_med=0;
          OPEN icd_csr;
          REPEAT
               FETCH icd_csr INTO l_code;  
		IF NOT no_more_med THEN 
