/* Function  structure for function  `get_mostrecent_encounter_date` */

DELIMITER $$

/*!50003 CREATE FUNCTION `get_mostrecent_encounter_date`(patient_id BIGINT,item_id TEXT,start_date DATETIME,end_date DATETIME) RETURNS varchar(50) CHARSET latin1
    READS SQL DATA
BEGIN
          DECLARE en_date   VARCHAR(50) DEFAULT '0000-00-00';
	  DECLARE l_code   VARCHAR(50) DEFAULT '';
	  DECLARE no_more_dates INT;	
	  DECLARE e_start INT DEFAULT 0;
	  DECLARE e_limit INT DEFAULT 1;
	  DECLARE order_status VARCHAR(4) DEFAULT 'ORDER BY e.encounter_date DESC';
	DECLARE date_csr CURSOR FOR
        SELECT DATE_FORMAT(e.encounter_date,'%Y-%m-%d') AS enc_date
	FROM mucert_cpoe_orders mco  
	INNER JOIN mucert_encounter e ON e.id = mco.enc_id 
	WHERE e.appt_date BETWEEN start_date AND end_date AND mco.patient_id=patient_id AND FIND_IN_SET(mco.item,item_id)
	AND e.encounter_date IS NOT NULL
	ORDER BY e.encounter_date DESC LIMIT 0,1;	
	
	DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_dates=1;
    
         SET no_more_dates=0;
          OPEN date_csr;
          REPEAT
               FETCH date_csr INTO l_code;  
		IF NOT no_more_dates THEN 
               SET en_date = l_code; 
		END IF;      
          UNTIL no_more_dates
          END REPEAT;
          CLOSE date_csr;
          SET no_more_dates=0;
	  RETURN TRIM(BOTH ', ' FROM en_date);
          
    END */$$
DELIMITER ;

