    READS SQL DATA
BEGIN
	DECLARE al_desc   TEXT DEFAULT '';
	  DECLARE al_code   VARCHAR(100) DEFAULT '';
	  DECLARE no_more_allergy INT;
    
          DECLARE allergy_scr CURSOR FOR
 SELECT CONCAT(allergy,'~',IF(severity IN('Severe','Moderate to Severe'),1,0)) AS allergy FROM patient_allergies WHERE allergy IS NOT NULL AND patient_id =oigid AND `allergy_status`='Active' AND RxnormID !='-99' ORDER BY allergy ASC;
            
    
          DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_allergy=1;
    
         SET no_more_allergy=0;
          OPEN allergy_scr;
          REPEAT
