 	DECLARE l_desc   VARCHAR(50) DEFAULT '';
	  DECLARE l_code   VARCHAR(50) DEFAULT '';
	  DECLARE no_more_med INT;
          DECLARE icd_csr CURSOR FOR
		SELECT COUNT(mphd.proc_history_nr) AS val FROM  mucert_cpoe_orders co 
		INNER JOIN mucert_procedure_history_data mphd ON mphd.enc_id=co.enc_id
		WHERE co.patient_id = patientid AND mphd.history_nr=history_nr AND FIND_IN_SET(co.item,itemids)
		;
          DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_med=1;
    
         SET no_more_med=0;
          OPEN icd_csr;
          REPEAT
               FETCH icd_csr INTO l_code;  
		IF NOT no_more_med THEN 
               SET l_desc = l_code; 
		END IF;      
          UNTIL no_more_med
          END REPEAT;
          CLOSE icd_csr;
          SET no_more_med=0;
	  RETURN TRIM(BOTH ', ' FROM l_desc);
    END */$$
DELIMITER ;

