/* Function  structure for function  `get_pid_enc_proc_count` */

DELIMITER $$

/*!50003 CREATE FUNCTION `get_pid_enc_proc_count`(patient_id BIGINT, item_id TEXT,start_date DATETIME,end_date DATETIME) RETURNS varchar(50) CHARSET latin1
    READS SQL DATA
BEGIN
	DECLARE l_desc   VARCHAR(20) DEFAULT 0;
