		SELECT COUNT(mco.patient_id) AS 'count' 
		FROM mucert_cpoe_orders mco
		WHERE mco.patient_id=patient_id AND FIND_IN_SET(mco.item,item_id) AND mco.order_date BETWEEN start_date AND end_date GROUP BY mco.patient_id;
          DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_icd_ocdes=1;
    
         SET no_more_icd_ocdes=0;
          OPEN icd_csr;
          REPEAT
               FETCH icd_csr INTO l_code;  
		IF NOT no_more_icd_ocdes THEN 
               SET l_desc = l_code; 
		END IF;      
          UNTIL no_more_icd_ocdes
          END REPEAT;
          CLOSE icd_csr;
          SET no_more_icd_ocdes=0;
	  RETURN TRIM(BOTH ', ' FROM l_desc);
END */$$
