/* Function  structure for function  `get_procedure_count` */

DELIMITER $$

/*!50003 CREATE FUNCTION `get_procedure_count`(patient_id BIGINT,item TEXT,frmDate DATETIME,toDate DATETIME) RETURNS tinyint
    READS SQL DATA
BEGIN
 	  DECLARE l_desc   TINYINT DEFAULT 0;
	  DECLARE l_code   TINYINT DEFAULT 0;
	  DECLARE no_more_med INT;
          DECLARE icd_csr CURSOR FOR
		SELECT COUNT(co.patient_id) AS cal_value FROM mucert_cpoe_orders co 
		INNER JOIN mucert_encounter e
		ON co.enc_id = e.id WHERE co.item=item AND co.patient_id=patient_id AND e.appt_date BETWEEN frmDate AND toDate
		;
          DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_med=1;
          SET no_more_med=0;
          OPEN icd_csr;
          REPEAT
               FETCH icd_csr INTO l_code;  
		IF NOT no_more_med THEN 
               SET l_desc = CONCAT(l_desc , l_code,', '); 
		END IF;      
          UNTIL no_more_med
          END REPEAT;
          CLOSE icd_csr;
          SET no_more_med=0;
	  RETURN TRIM(BOTH ', ' FROM l_desc);
    END */$$
DELIMITER ;

/* Function  structure for function  `get_procedure_count_for_report` */

DELIMITER $$

/*!50003 CREATE FUNCTION `get_procedure_count_for_report`(orid VARCHAR(255)) RETURNS text CHARSET utf8mb3
BEGIN
	DECLARE all_data TEXT;
	SET all_data = '';
	
	SELECT (SELECT GROUP_CONCAT(cnt)
    FROM
(SELECT CONCAT(procedure_type,'(',COUNT(procedure_type),')<br>') AS cnt
 FROM encounter_procedure ep INNER JOIN encounter e ON ep.encounter_nr = e.encounter_nr 
WHERE e.origid = orid AND encounter_status != 'cancelled'
GROUP BY procedure_type) AS q) INTO all_data;
	
	RETURN all_data;
    END */$$
DELIMITER ;

/* Function  structure for function  `get_procedure_date` */

DELIMITER $$

/*!50003 CREATE FUNCTION `get_procedure_date`(patient_id BIGINT,item_id TEXT) RETURNS varchar(50) CHARSET latin1
    READS SQL DATA
BEGIN
          DECLARE en_date   VARCHAR(50) DEFAULT '0000-00-00';
	  DECLARE l_code   VARCHAR(50) DEFAULT '0000-00-00';
	  DECLARE no_more_dates INT;	
	
	DECLARE date_csr CURSOR FOR
        SELECT DATE_FORMAT(e.encounter_date,'%Y-%m-%d') AS enc_date
	FROM mucert_encounter e    
	INNER JOIN mucert_cpoe_orders mco ON e.id = mco.enc_id 
	AND mco.patient_id=patient_id AND FIND_IN_SET(mco.item,item_id)
	AND e.encounter_date IS NOT NULL
	ORDER BY e.encounter_date ASC LIMIT 0,1;	
	
	DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_dates=1;
    
         SET no_more_dates=0;
          OPEN date_csr;
          REPEAT
               FETCH date_csr INTO l_code;  
		IF NOT no_more_dates THEN 
               SET en_date = l_code; 
		END IF;      
          UNTIL no_more_dates
          END REPEAT;
          CLOSE date_csr;
          SET no_more_dates=0;
	  RETURN TRIM(BOTH ', ' FROM en_date);
          
    END */$$
DELIMITER ;

