/* Function  structure for function  `get_procedure_in_item` */

DELIMITER $$

/*!50003 CREATE FUNCTION `get_procedure_in_item`(patient_nr BIGINT,item TEXT,proc_nr TEXT,start_date DATETIME,end_date DATETIME) RETURNS varchar(255) CHARSET latin1
    READS SQL DATA
BEGIN
 	DECLARE l_desc   VARCHAR(50) DEFAULT '';
	  DECLARE l_code   VARCHAR(50) DEFAULT '';
	  DECLARE no_more_date INT;
          DECLARE date_csr CURSOR FOR
		
	SELECT e.appt_date FROM mucert_encounter e INNER JOIN mucert_cpoe_orders co ON e.patient_id = co.patient_id WHERE FIND_IN_SET(co.item,item) AND co.parent_encounter_nr=(SELECT encounter_nr FROM mucert_encounter e1 
INNER JOIN mucert_cpoe_orders co1 ON e1.patient_id = co1.patient_id
WHERE e1.patient_id=patient_nr AND co1.item=proc_nr AND e.appt_date BETWEEN @fromDate AND @toDate ORDER BY e1.appt_date ASC LIMIT 0,1 )
AND e.patient_id=patient_nr AND e.appt_date BETWEEN @fromDate AND @toDate ORDER BY e.appt_date ASC LIMIT 0,1;
          DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_date=1;
    
         SET no_more_date=0;
          OPEN date_csr;
          REPEAT
               FETCH date_csr INTO l_code;  
		IF NOT no_more_date THEN 
               SET l_desc = l_code; 
		END IF;      
          UNTIL no_more_date
          END REPEAT;
          CLOSE date_csr;
          SET no_more_date=0;
	  RETURN TRIM(BOTH ', ' FROM l_desc);
    END */$$
