	  DECLARE l_code   VARCHAR(50) DEFAULT '';
	  DECLARE no_more_dates INT;	
	  DECLARE e_start INT DEFAULT 0;
	  DECLARE e_limit INT DEFAULT 1;
	  DECLARE order_status VARCHAR(4) DEFAULT 'ORDER BY e.encounter_date ASC';
	DECLARE date_csr CURSOR FOR
        SELECT  DATE_FORMAT(e.discharge_date,'%Y-%m-%d') AS discharge_date FROM mucert_cpoe_orders mco
	INNER JOIN mucert_encounter e ON e.id = mco.enc_id 
	WHERE mco.patient_id=patient_id AND FIND_IN_SET(mco.item,item_id)
	AND e.discharge_date IS NOT NULL
	ORDER BY e.encounter_date ASC LIMIT 1,1
	;	
	DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_dates=1;
    
         SET no_more_dates=0;
          OPEN date_csr;
          REPEAT
               FETCH date_csr INTO l_code;  
		IF NOT no_more_dates THEN 
               SET en_date = l_code; 
		END IF;      
          UNTIL no_more_dates
          END REPEAT;
          CLOSE date_csr;
          SET no_more_dates=0;
	  RETURN TRIM(BOTH ', ' FROM en_date);
          
    END */$$
DELIMITER ;

