/* Function  structure for function  `MRA_A01_GetEncounterNrNew` */

DELIMITER $$

/*!50003 CREATE FUNCTION `MRA_A01_GetEncounterNrNew`(mpp1 VARCHAR(8),mpp2 VARCHAR(2)) RETURNS varchar(100) CHARSET latin1
BEGIN

 DECLARE vtmp VARCHAR(100);DECLARE vm_enc_nr VARCHAR(100);

 UPDATE sequence_table_data SET sequence_id=sequence_id+1 WHERE sequence_name='adt_encounter';
 SET vtmp = (SELECT sequence_id FROM sequence_table_data WHERE sequence_name='adt_encounter');  
 SET vm_enc_nr= CONCAT(mpp1,mpp2,vtmp);
 RETURN vm_enc_nr;

END */$$
DELIMITER ;

/* Function  structure for function  `MRA_A20_GetHospitalTaxnomy` */

DELIMITER $$

/*!50003 CREATE FUNCTION `MRA_A20_GetHospitalTaxnomy`(mpp1 VARCHAR(1000)) RETURNS varchar(100) CHARSET latin1
BEGIN

 DECLARE vtmp VARCHAR(100);DECLARE vm_taxno_nr VARCHAR(100) DEFAULT '';
 SET mpp1=LOWER(mpp1);

 IF (LOCATE("rehabilitation",mpp1)>0 OR LOCATE("rehab",mpp1)>0) THEN
  SET vm_taxno_nr='283X00000X';# Rehabilitation Hospital
 ELSEIF (LOCATE("skilled",mpp1)>0 OR LOCATE("nursing",mpp1)>0 OR LOCATE("snf",mpp1)>0) THEN
  SET vm_taxno_nr='314000000X';# Skilled Nursing Facility
 ELSEIF (LOCATE("respite",mpp1)>0 OR LOCATE("hospice",mpp1)>0) THEN
  SET vm_taxno_nr='251G00000X';# Hospice Care, Community Based
 ELSEIF (LOCATE("hha ",mpp1)>0 OR LOCATE(" hha ",mpp1)>0 OR LOCATE(" hha",mpp1)>0 OR LOCATE("hh ",mpp1)>0 OR LOCATE(" hh ",mpp1)>0 OR LOCATE(" hh",mpp1)>0 OR LOCATE("home health",mpp1)>0) THEN
  SET vm_taxno_nr='251E00000X';# Home Health
 ELSEIF (LOCATE("acute ",mpp1)>0 OR LOCATE("regional medical",mpp1)>0 OR LOCATE("hospital",mpp1)>0) THEN
  SET vm_taxno_nr='282N00000X';# General Acute Care Hospital
 END IF;

 RETURN vm_taxno_nr;

END */$$
DELIMITER ;

/* Function  structure for function  `MRA_A31_Get72HrFlowUpDays_m1` */

DELIMITER $$

/*!50003 CREATE FUNCTION `MRA_A31_Get72HrFlowUpDays_m1`(mpp1 VARCHAR(10),mpp2 VARCHAR(10)) RETURNS tinyint
    READS SQL DATA
BEGIN

 DECLARE mv01 VARCHAR(10);
 DECLARE mmi INT; DECLARE mDaysNums INT; DECLARE mCntLoop INT;

 SET mmi=1; SET mDaysNums=0;
 SET mCntLoop=DATEDIFF(mpp1,mpp2); IF mCntLoop <0 THEN SET mCntLoop=0; END IF;
 SET mv01= mpp2 + INTERVAL+1 DAY; 

 LOOP_M01: LOOP
  IF mmi > mCntLoop THEN LEAVE LOOP_M01; END IF;

  IF WEEKDAY(mv01) NOT IN (5,6) THEN
   SET mDaysNums = mDaysNums + 1;
  END IF;

  SET mv01= mv01 + INTERVAL+1 DAY;  
  SET mmi = mmi + 1; ITERATE LOOP_M01;

 END LOOP;
 
 RETURN mDaysNums;

END */$$
DELIMITER ;

/* Function  structure for function  `MRA_C11_GetEncounterNrNew` */

DELIMITER $$

/*!50003 CREATE FUNCTION `MRA_C11_GetEncounterNrNew`(mpp1 VARCHAR(8),mpp2 VARCHAR(2)) RETURNS bigint
    READS SQL DATA
BEGIN

 DECLARE vtmp VARCHAR(100);DECLARE vm_enc_nr BIGINT(20);

 UPDATE sequence_table_data SET sequence_id=sequence_id+1 WHERE sequence_name='cclf_encounter';
 SET vtmp = (SELECT sequence_id FROM sequence_table_data WHERE sequence_name='cclf_encounter');  
 SET vm_enc_nr= CONCAT(mpp1,LPAD(vtmp,11,0));
 RETURN vm_enc_nr;

END */$$
DELIMITER ;

/* Function  structure for function  `mra_fetch_patient_visits` */

DELIMITER $$

/*!50003 CREATE FUNCTION `mra_fetch_patient_visits`(orig_id VARCHAR(64)) RETURNS text CHARSET utf8mb3
BEGIN
    DECLARE visits TEXT;
    SELECT GROUP_CONCAT(tb.val SEPARATOR '<br/>')  INTO visits FROM (SELECT (CONCAT(ec.name,' : ',COUNT(ec.name))) AS val,origid FROM encounter en INNER JOIN class_encounter ec ON en.encounter_class_nr=ec.class_nr WHERE en.origid=orig_id GROUP BY encounter_class_nr ) AS tb WHERE tb.origid=orig_id;
    RETURN visits;
    END */$$
DELIMITER ;

/* Function  structure for function  `mra_fetch_patient_visit_details` */

DELIMITER $$

/*!50003 CREATE FUNCTION `mra_fetch_patient_visit_details`(orig_id VARCHAR(64)) RETURNS text CHARSET utf8mb3
BEGIN
    DECLARE visits TEXT;
    SELECT GROUP_CONCAT(tb.details SEPARATOR '<br/>') INTO visits FROM (SELECT CONCAT(a.to_personell_name,'-',hc.name,'-',DATE_FORMAT(a.date,'%m/%d/%Y')) AS details FROM appointment a INNER JOIN encounter e ON e.encounter_nr=a.encounter_nr INNER JOIN hospital_centers hc ON hc.nr=a.hospital_nr WHERE a.origid=orig_id GROUP BY a.encounter_nr) AS tb;
    RETURN visits;
    END */$$
DELIMITER ;

/* Function  structure for function  `MRA_FN01_DcMememberCount` */

DELIMITER $$

/*!50003 CREATE FUNCTION `MRA_FN01_DcMememberCount`(mpp1 INT,mpp2 BIGINT,mpp3 VARCHAR(12),mpp4 VARCHAR(10)) RETURNS int
BEGIN

 DECLARE m1MemberCnt INT; 
 SET m1MemberCnt= (SELECT COUNT(DISTINCT(BENE_MBI_ID)) FROM dc_bene_alignment_rostr_m01 WHERE cc_version=mpp1 AND dce_group_nr=mpp2 AND prov_npi_nr=mpp3 AND ALIGN_STATUS_CODE IN ('AL','D1Y') AND mm_date=mpp4);
 RETURN m1MemberCnt;

END */$$
