/* Function  structure for function  `MRA_FN01_DcMememberCount_bk01` */

DELIMITER $$

/*!50003 CREATE FUNCTION `MRA_FN01_DcMememberCount_bk01`(mpp1 INT,mpp2 BIGINT,mpp3 VARCHAR(12),mpp4 VARCHAR(10)) RETURNS int
BEGIN

 DECLARE m1MemberCnt INT DEFAULT 0; DECLARE m1MonthNum INT DEFAULT 0;
 SET m1MonthNum=(SELECT MONTH(mpp4));
 
 IF m1MonthNum = 1 THEN
  SET m1MemberCnt= (SELECT COUNT(DISTINCT(BENE_MBI_ID)) FROM dc_bene_alignment_roster WHERE cc_version=mpp1 AND dce_group_nr=mpp2 AND prov_npi_nr=mpp3 AND Jan IN ('AL','D1Y'));
 ELSEIF m1MonthNum = 2 THEN
  SET m1MemberCnt= (SELECT COUNT(DISTINCT(BENE_MBI_ID)) FROM dc_bene_alignment_roster WHERE cc_version=mpp1 AND dce_group_nr=mpp2 AND prov_npi_nr=mpp3 AND Feb IN ('AL','D1Y'));
 ELSEIF m1MonthNum = 3 THEN
  SET m1MemberCnt= (SELECT COUNT(DISTINCT(BENE_MBI_ID)) FROM dc_bene_alignment_roster WHERE cc_version=mpp1 AND dce_group_nr=mpp2 AND prov_npi_nr=mpp3 AND Mar IN ('AL','D1Y'));
 ELSEIF m1MonthNum = 4 THEN
  SET m1MemberCnt= (SELECT COUNT(DISTINCT(BENE_MBI_ID)) FROM dc_bene_alignment_roster WHERE cc_version=mpp1 AND dce_group_nr=mpp2 AND prov_npi_nr=mpp3 AND Apr IN ('AL','D1Y'));
 ELSEIF m1MonthNum = 5 THEN
  SET m1MemberCnt= (SELECT COUNT(DISTINCT(BENE_MBI_ID)) FROM dc_bene_alignment_roster WHERE cc_version=mpp1 AND dce_group_nr=mpp2 AND prov_npi_nr=mpp3 AND May IN ('AL','D1Y'));
 ELSEIF m1MonthNum = 6 THEN
  SET m1MemberCnt= (SELECT COUNT(DISTINCT(BENE_MBI_ID)) FROM dc_bene_alignment_roster WHERE cc_version=mpp1 AND dce_group_nr=mpp2 AND prov_npi_nr=mpp3 AND Jun IN ('AL','D1Y'));
 ELSEIF m1MonthNum = 7 THEN
  SET m1MemberCnt= (SELECT COUNT(DISTINCT(BENE_MBI_ID)) FROM dc_bene_alignment_roster WHERE cc_version=mpp1 AND dce_group_nr=mpp2 AND prov_npi_nr=mpp3 AND Jul IN ('AL','D1Y'));
 ELSEIF m1MonthNum = 8 THEN
  SET m1MemberCnt= (SELECT COUNT(DISTINCT(BENE_MBI_ID)) FROM dc_bene_alignment_roster WHERE cc_version=mpp1 AND dce_group_nr=mpp2 AND prov_npi_nr=mpp3 AND Aug IN ('AL','D1Y'));
 ELSEIF m1MonthNum = 9 THEN
  SET m1MemberCnt= (SELECT COUNT(DISTINCT(BENE_MBI_ID)) FROM dc_bene_alignment_roster WHERE cc_version=mpp1 AND dce_group_nr=mpp2 AND prov_npi_nr=mpp3 AND Sep IN ('AL','D1Y'));
 ELSEIF m1MonthNum = 10 THEN
  SET m1MemberCnt= (SELECT COUNT(DISTINCT(BENE_MBI_ID)) FROM dc_bene_alignment_roster WHERE cc_version=mpp1 AND dce_group_nr=mpp2 AND prov_npi_nr=mpp3 AND `Oct` IN ('AL','D1Y'));
 ELSEIF m1MonthNum = 11 THEN
  SET m1MemberCnt= (SELECT COUNT(DISTINCT(BENE_MBI_ID)) FROM dc_bene_alignment_roster WHERE cc_version=mpp1 AND dce_group_nr=mpp2 AND prov_npi_nr=mpp3 AND Nov IN ('AL','D1Y'));
 ELSEIF m1MonthNum = 12 THEN
  SET m1MemberCnt= (SELECT COUNT(DISTINCT(BENE_MBI_ID)) FROM dc_bene_alignment_roster WHERE cc_version=mpp1 AND dce_group_nr=mpp2 AND prov_npi_nr=mpp3 AND `Dec` IN ('AL','D1Y')); 
 END IF; 

 RETURN m1MemberCnt;

END */$$
DELIMITER ;

/* Function  structure for function  `MRA_FN01_GetPatientAlignStatus` */

DELIMITER $$

/*!50003 CREATE FUNCTION `MRA_FN01_GetPatientAlignStatus`(mpp1 VARCHAR(100), mpp2 VARCHAR(20)) RETURNS varchar(100) CHARSET latin1
    READS SQL DATA
BEGIN
    DECLARE vtmp VARCHAR(100);
    DECLARE mc1val INT; 
    DECLARE mc2val VARCHAR(100) DEFAULT 'UNK';
    DECLARE mc11val INT;
    SET mc11val = YEAR(NOW());
    IF mpp2 != '' THEN 
        SET mc11val = YEAR(mpp2); 
    END IF;
    SET mc1val = (
        SELECT MAX(cc_version) 
        FROM dc_bene_alignment_rostr_m01 
        WHERE mm_year = mc11val AND mm_curr_mbi_id = mpp1
    );
    SET vtmp = (
        SELECT ALIGN_STATUS_CODE 
        FROM dc_bene_alignment_rostr_m01 
        WHERE cc_version = mc1val AND mm_curr_mbi_id = mpp1 
        ORDER BY mm_date DESC 
        LIMIT 1
    );
    IF vtmp IS NOT NULL THEN
        IF vtmp = 'AL' THEN
            SET mc2val = 'AL';
        ELSE
            SET mc2val = 'UAL';
        END IF;
    END IF;
    RETURN mc2val;
END */$$
DELIMITER ;

/* Function  structure for function  `MRA_FN01_GetPatientIDLastCCLF` */

DELIMITER $$

/*!50003 CREATE FUNCTION `MRA_FN01_GetPatientIDLastCCLF`(mpp1 VARCHAR(100)) RETURNS varchar(100) CHARSET latin1
    READS SQL DATA
BEGIN
 DECLARE vtmp VARCHAR(100);
 DECLARE m1MemberID VARCHAR(100) CHARACTER SET latin1 DEFAULT mpp1;

 SET vtmp=(SELECT mm_curr_mbi_id FROM mra_file_static.mra_cclf9 WHERE PRVS_NUM=mpp1 COLLATE latin1_swedish_ci OR CRNT_NUM=mpp1 COLLATE latin1_swedish_ci ORDER BY create_date DESC LIMIT 1);

 IF vtmp IS NOT NULL THEN
  SET m1MemberID=vtmp;
 END IF;

 RETURN m1MemberID;

END */$$
