/* Function  structure for function  `MRA_SV01_SetEncounterVals` */

DELIMITER $$

/*!50003 CREATE FUNCTION `MRA_SV01_SetEncounterVals`(mpp1 VARCHAR(100), mpp2 BIGINT, mpp3 VARCHAR(20)) RETURNS tinyint
    READS SQL DATA
BEGIN
 DECLARE vtmp TEXT; DECLARE v2tmp INT; DECLARE v3tmp TEXT;
 DECLARE mc1val INT; DECLARE mhPatClass VARCHAR(100);DECLARE mvLockChk VARCHAR(2);DECLARE mHl7Status INT;
 DECLARE mAdmitDate VARCHAR(30); DECLARE mDischargeDate VARCHAR(30);DECLARE mCreateTime VARCHAR(30);DECLARE mDceGroupNr BIGINT;
 DECLARE mTaxonomy VARCHAR(30); DECLARE mv07 VARCHAR(50);DECLARE mv08 TINYINT; DECLARE mPosCurr SMALLINT;
 DECLARE isM1Check TINYINT DEFAULT 1; DECLARE isAcoGroupChk TINYINT DEFAULT 0; DECLARE isDischargeDateChk TINYINT DEFAULT 0; DECLARE mif_check TINYINT DEFAULT 0;
 INSERT INTO adt_encounter_logger SET encounter_nr=mpp2,log_info='Encounter Call : Start',created_date=NOW();
 SET vtmp = (
    SELECT CONCAT(
        IF(is_edit_lock IS NULL,0,is_edit_lock),'!@#',
        IF(hl7_rec_status IS NULL,0,hl7_rec_status),'!@#',
        IF(discharge_date IS NULL,'0000-00-00',discharge_date),'!@#',
        IF(create_time IS NULL,'0000-00-00 00:00:00',create_time),'!@#',
        IF(dce_group_nr IS NULL,0,dce_group_nr),'!@#',
        IF(taxonomy IS NULL,'1234',taxonomy),'!@#',
        IF(mra_clm_refer_m02 IS NULL,'1234',mra_clm_refer_m02),'!@#',
        mflag_census,'!@#',
        encounter_date,'!@#',
        pos_curr,'!@#',
        IF(mos IS NULL,'',mos),'!@#',
        IF(mh_patient_class IS NULL,0,mh_patient_class),'!@#',
        mif_exclusion
    )
    FROM adt_encounter
    WHERE encounter_nr = mpp2
    LIMIT 1
);
SET @mvMOS = '';
IF vtmp IS NOT NULL THEN
    SET mvLockChk = SUBSTRING_INDEX(vtmp,'!@#',1);
    SET v3tmp    = SUBSTRING_INDEX(vtmp,'!@#',2);  SET mHl7Status     = SUBSTRING_INDEX(v3tmp,'!@#',-1);
    SET v3tmp    = SUBSTRING_INDEX(vtmp,'!@#',3);  SET mDischargeDate= SUBSTRING_INDEX(v3tmp,'!@#',-1);
    SET v3tmp    = SUBSTRING_INDEX(vtmp,'!@#',4);  SET mCreateTime   = SUBSTRING_INDEX(v3tmp,'!@#',-1);
    SET v3tmp    = SUBSTRING_INDEX(vtmp,'!@#',5);  SET mDceGroupNr   = SUBSTRING_INDEX(v3tmp,'!@#',-1);
    SET v3tmp    = SUBSTRING_INDEX(vtmp,'!@#',6);  SET mTaxonomy     = SUBSTRING_INDEX(v3tmp,'!@#',-1);
    SET v3tmp    = SUBSTRING_INDEX(vtmp,'!@#',7);  SET mv07          = SUBSTRING_INDEX(v3tmp,'!@#',-1);
    SET v3tmp    = SUBSTRING_INDEX(vtmp,'!@#',8);  SET mv08          = SUBSTRING_INDEX(v3tmp,'!@#',-1);
    SET v3tmp    = SUBSTRING_INDEX(vtmp,'!@#',9);  SET mAdmitDate    = SUBSTRING_INDEX(v3tmp,'!@#',-1);
