END IF; 
 INSERT INTO adt_encounter_logger SET encounter_nr=mpp2,log_info=CONCAT('c1DATA: mDischargeDate= ',mDischargeDate,' mhPatClass= ',mhPatClass,' mTaxonomy= ',mTaxonomy,' mv08= ',mv08),created_date=NOW();
 SET @m1DateVdiff=0; SET @m2DateVdiff=0;
