  ELSEIF mPosCurr=21 AND mc1val<>59 THEN
   INSERT INTO adt_encounter_logger SET encounter_nr=mpp2,log_info='Encounter Current POS Not updated : InPatient Lock',created_date=NOW(); 
  ELSE
