 INSERT INTO adt_encounter_logger SET encounter_nr=mpp2,log_info=CONCAT('mval - m1DateVdiff: ',@m1DateVdiff,' - m2DateVdiff: ',@m2DateVdiff,' - is_CMActive_z: ',@is_CMActive_z,' '),created_date=NOW();
 SET @isCK5_Census_z=0; 
 IF mv08=0 AND isM1Check=1 THEN SET @isCK5_Census_z=1; END IF;
 IF @isCK5_Census_z=1 AND mc1val=21 THEN SET @isCK5_Census_z=2; END IF; #AND isDischargeDateChk=0 
