 IF @isCK5_MOS_z=1 AND mTaxonomy IN ('314000000X','261QR0400X','283X00000X','261QR0401X','273Y00000X','2081P2900X','208100000X','283XC2000X','261QR0404X','111NR0400X','225400000X') THEN SET @isCK5_MOS_z=2; END IF;
 IF @mvMOS<>'' AND @mvMOS<>'Not Assigned' THEN
