 END IF; 
 
    
 INSERT INTO adt_encounter_logger SET encounter_nr=mpp2,log_info=CONCAT('mdv_mos:: - isCK5_MOS_z: ',@isCK5_MOS_z,' - is_TFU_z: ',@is_TFU_z,' - is_CMActive_z: ',@is_CMActive_z,' - mTaxonomy: ',mTaxonomy,' - isDischargeDateChk: ',isDischargeDateChk,' - isM1Check: ',isM1Check,' - mc1val: ',mc1val,' - mvMOS: ',@mvMOS,' '),created_date=NOW();
 IF mvLockChk='1' THEN 
