 UPDATE adt_encounter e INNER JOIN patient p ON e.origid=p.origid SET e.m_cal_bed_days=DATEDIFF(DATE_ADD(e.discharge_date, INTERVAL 1 DAY),e.encounter_date),e.hl7_rec_status=1,e.hl7_rec_stats_up_dt=NOW(), e.lastname=p.lastname, e.firstname=p.firstname ,e.middlename=p.middlename,e.sex=p.sex,e.pt_dob=p.birthdate WHERE e.encounter_nr=mpp2;
 INSERT INTO adt_encounter_logger SET encounter_nr=mpp2,log_info='Encounter patient update',created_date=NOW();
 # UPDATE adt_encounter t1 INNER JOIN adt_hosp_mhie t2 ON t2.nr=t1.mhos_mhie_nr SET t1.hospital_name=t2.`mname`,t1.hospital_npi=t2.`npi_id` WHERE t1.mhos_mhie_nr>1 AND t1.hospital_name='UNK'; 
 UPDATE adt_encounter t1 INNER JOIN adt_hosp_mhie t2 ON t2.nr=t1.mhos_mhie_nr SET t1.hospital_name=t2.`mname`,t1.hospital_npi=t2.`npi_id` WHERE t1.encounter_nr=mpp2; 
 IF mHl7Status=0 OR mDceGroupNr=0 THEN
