/* Function  structure for function  `MRA_SV05_GetPosVal_mc` */

DELIMITER $$

/*!50003 CREATE FUNCTION `MRA_SV05_GetPosVal_mc`(m1pp VARCHAR(100),m2pp VARCHAR(100)) RETURNS int
    NO SQL
BEGIN

 DECLARE rt_val INT DEFAULT 22;

 IF m1pp="Emergency (E)" OR m1pp="E" OR m1pp="Emergency" THEN
  SET rt_val=23;
 ELSEIF (m2pp="m01_ny" OR m2pp="bamboo") AND m1pp="V" THEN
  SET rt_val=24;
 ELSEIF m1pp="Inpatient (I)" OR m1pp="I" OR m1pp="Inpatient" OR m1pp="B" OR m1pp="V" THEN
  SET rt_val=21;
 ELSEIF m1pp="OBS" OR m1pp="Observation" THEN
  SET rt_val=24;
 ELSEIF m1pp="Unkown (U)" OR m1pp="U" THEN
  SET rt_val=25;
 ELSEIF m1pp="IP-PREADMIT" THEN
  SET rt_val= -99;
 END IF;

 RETURN rt_val;

END */$$
DELIMITER ;

/* Function  structure for function  `PQRS_Chk_Insurance` */

DELIMITER $$

/*!50003 CREATE FUNCTION `PQRS_Chk_Insurance`(p_id BIGINT,ins_code TEXT) RETURNS varchar(500) CHARSET latin1
    READS SQL DATA
BEGIN
 DECLARE l_desc   VARCHAR(500) DEFAULT '';
   DECLARE l_name   VARCHAR(150) DEFAULT '';
   DECLARE no_more_ins INT;
   DECLARE l_id   INT(10) DEFAULT 0;  
   
  
          DECLARE ins_csr CURSOR FOR 
          
SELECT 1 FROM mucert_patient_insurance 
  WHERE patient_id=p_id  AND FIND_IN_SET(insurance_firm_id,ins_code);
    
        DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_ins=1;
    
         SET no_more_ins=0;
          OPEN ins_csr;
          REPEAT
               FETCH ins_csr INTO l_name;  
  IF NOT no_more_ins THEN 
               SET l_desc = l_name; 
  END IF;      
          UNTIL no_more_ins
          END REPEAT;
          CLOSE ins_csr;
          SET no_more_ins=0;
   RETURN TRIM(BOTH ', ' FROM l_desc);
END */$$
DELIMITER ;

/* Function  structure for function  `QRD_AgeBTDates` */

DELIMITER $$

/*!50003 CREATE FUNCTION `QRD_AgeBTDates`(C1Date DATE, C2Date DATE) RETURNS bigint
    NO SQL
BEGIN
 DECLARE retVal BIGINT DEFAULT 0;
 
 SET retVal = (DATE_FORMAT(C1Date, '%Y') - DATE_FORMAT(C2Date, '%Y') - (DATE_FORMAT(C1Date, '00-%m-%d') < DATE_FORMAT(C2Date, '00-%m-%d')));
 IF retVal >200 THEN 
	SET retVal = 0; 
 END IF; 
 
 
 RETURN retVal;
END */$$
DELIMITER ;

/* Function  structure for function  `QRD_CK_HistoryVals` */

DELIMITER $$

/*!50003 CREATE FUNCTION `QRD_CK_HistoryVals`(enc_id BIGINT,history_nr TEXT) RETURNS varchar(3) CHARSET latin1
    READS SQL DATA
BEGIN
	DECLARE l_desc VARCHAR(3) DEFAULT '0';
	DECLARE l_code VARCHAR(3) DEFAULT '0';
	DECLARE no_more_med INT;
	DECLARE icd_csr CURSOR FOR
		SELECT '1' FROM mucert_procedure_history_data mphd WHERE mphd.enc_id=enc_id AND mphd.history_nr IN (history_nr) LIMIT 0,1;
	DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_med=1;
	SET no_more_med=0;
	OPEN icd_csr;
	REPEAT
		FETCH icd_csr INTO l_code;  
			IF NOT no_more_med THEN 
				SET l_desc = l_code; 
			END IF;      
		UNTIL no_more_med
	END REPEAT;
	CLOSE icd_csr;
	SET no_more_med=0;
	RETURN l_desc;
END */$$
DELIMITER ;

/* Function  structure for function  `QRD_enrL_variable` */

DELIMITER $$

/*!50003 CREATE FUNCTION `QRD_enrL_variable`() RETURNS int
BEGIN
	RETURN 10;
END */$$
DELIMITER ;

/* Function  structure for function  `QRD_FirstEnrDate` */

DELIMITER $$

/*!50003 CREATE FUNCTION `QRD_FirstEnrDate`(patient_id BIGINT,item_id TEXT,start_date DATETIME,end_date DATETIME) RETURNS varchar(50) CHARSET latin1
    READS SQL DATA
BEGIN
          DECLARE en_date   VARCHAR(50);
	  DECLARE l_code   VARCHAR(50);
	  DECLARE no_more_dates INT;	
	DECLARE date_csr CURSOR FOR
        SELECT DATE_FORMAT(e.encounter_date,'%Y-%m-%d') AS encounter_date FROM mucert_cpoe_orders mco  
	INNER JOIN mucert_encounter e ON e.id = mco.enc_id 
	WHERE e.appt_date BETWEEN start_date AND end_date AND mco.patient_id=patient_id AND FIND_IN_SET(mco.item,item_id)
	AND mco.order_status!='cancelled'
	ORDER BY e.encounter_date ASC LIMIT 0,1;	
	
	DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_dates=1;
    
         SET no_more_dates=0;
          OPEN date_csr;
          REPEAT
               FETCH date_csr INTO l_code;  
		IF NOT no_more_dates THEN 
               SET en_date = l_code; 
		END IF;      
          UNTIL no_more_dates
          END REPEAT;
          CLOSE date_csr;
          SET no_more_dates=0;
	  RETURN en_date;
          
    END */$$
DELIMITER ;

/* Function  structure for function  `QRD_Mra1ProcCount` */

DELIMITER $$

/*!50003 CREATE FUNCTION `QRD_Mra1ProcCount`(patientid BIGINT, item_id TEXT,start_date DATETIME,end_date DATETIME) RETURNS tinyint
    READS SQL DATA
BEGIN
	DECLARE l_desc TINYINT (2) DEFAULT 0;
	DECLARE l_code TINYINT (2) DEFAULT 0;
	DECLARE no_more_icd_ocdes INT;
	DECLARE icd_csr CURSOR FOR
SELECT COUNT(distinct mra_enc_nr) FROM mra1_encounter_bill_cpts 
		WHERE 
		patient_id=patientid AND bb_code IN(item_id ) AND mcreate_datetime BETWEEN start_date AND end_date;
	DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_icd_ocdes=1;
    
	SET no_more_icd_ocdes=0;
          OPEN icd_csr;
          REPEAT
               FETCH icd_csr INTO l_code;  
	IF NOT no_more_icd_ocdes THEN 
               SET l_desc = l_code; 
	END IF;      
          UNTIL no_more_icd_ocdes
          END REPEAT;
          CLOSE icd_csr;
          SET no_more_icd_ocdes=0;
	RETURN TRIM(BOTH ', ' FROM l_desc);
END */$$
DELIMITER ;

/* Function  structure for function  `QRD_NO_enrollments` */

DELIMITER $$

/*!50003 CREATE FUNCTION `QRD_NO_enrollments`(oigid VARCHAR(64)) RETURNS text CHARSET latin1
    READS SQL DATA
BEGIN
	DECLARE al_desc   TEXT DEFAULT '';
	  DECLARE al_code   VARCHAR(100) DEFAULT '';
	  DECLARE no_more_allergy INT;
    
          DECLARE allergy_scr CURSOR FOR
	SELECT 
(LOCATE('AL',IFNULL(Jan,'CO'))+LOCATE('AL',IFNULL(Feb,'CO'))+ LOCATE('AL',IFNULL(Mar,'CO'))+LOCATE('AL',IFNULL(Apr,'CO'))+LOCATE('AL',IFNULL(May,'CO'))+LOCATE('AL',IFNULL(Jun,'CO'))+LOCATE('AL',IFNULL(Jul,'CO'))+LOCATE('AL',IFNULL(Aug,'CO'))+LOCATE('AL',IFNULL(Sep,'CO'))+LOCATE('AL',IFNULL(`Oct`,'CO'))+LOCATE('AL',IFNULL(Nov,'CO'))+LOCATE('AL',IFNULL(`Dec`,'CO'))) AS total
FROM dc_bene_alignment_roster
WHERE BENE_MBI_ID=oigid AND `cc_version`=25
ORDER BY total DESC LIMIT 1;
          DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_allergy=1;
    
         SET no_more_allergy=0;
          OPEN allergy_scr;
          REPEAT
               FETCH allergy_scr INTO al_code; 
		IF NOT no_more_allergy THEN 
               SET al_desc = CONCAT(al_desc , al_code,', ');    
		END IF;
          UNTIL no_more_allergy
          END REPEAT;
          CLOSE allergy_scr;
          SET no_more_allergy=0;
	  RETURN TRIM(BOTH ', ' FROM al_desc);
END */$$
DELIMITER ;

/* Function  structure for function  `QRD_PatProcCount` */

DELIMITER $$

/*!50003 CREATE FUNCTION `QRD_PatProcCount`(patient_id BIGINT, item_id TEXT,start_date DATETIME,end_date DATETIME) RETURNS tinyint
    READS SQL DATA
BEGIN
	DECLARE l_desc TINYINT (2) DEFAULT 0;
	DECLARE l_code TINYINT (2) DEFAULT 0;
	DECLARE no_more_icd_ocdes INT;
	DECLARE icd_csr CURSOR FOR
		SELECT COUNT(mco.nr) AS 'count' FROM mucert_cpoe_orders mco	INNER JOIN mucert_encounter e ON e.id = mco.enc_id WHERE e.appt_date BETWEEN start_date AND end_date AND mco.patient_id=patient_id AND FIND_IN_SET(mco.item,item_id);
	DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_icd_ocdes=1;
    
	SET no_more_icd_ocdes=0;
          OPEN icd_csr;
          REPEAT
               FETCH icd_csr INTO l_code;  
	IF NOT no_more_icd_ocdes THEN 
               SET l_desc = l_code; 
	END IF;      
          UNTIL no_more_icd_ocdes
          END REPEAT;
          CLOSE icd_csr;
          SET no_more_icd_ocdes=0;
	RETURN TRIM(BOTH ', ' FROM l_desc);
END */$$
DELIMITER ;

/* Function  structure for function  `QRD_prev_enrollments` */

DELIMITER $$

/*!50003 CREATE FUNCTION `QRD_prev_enrollments`(oigid VARCHAR(64)) RETURNS int
    READS SQL DATA
BEGIN
	DECLARE al_desc   TEXT DEFAULT '';
	  DECLARE al_code   VARCHAR(100) DEFAULT '';
	  DECLARE no_more_allergy INT;
    
          DECLARE allergy_scr CURSOR FOR
	SELECT 
(LOCATE('AL',IFNULL(Jan,'CO'))+LOCATE('AL',IFNULL(Feb,'CO'))+ LOCATE('AL',IFNULL(Mar,'CO'))+LOCATE('AL',IFNULL(Apr,'CO'))+LOCATE('AL',IFNULL(May,'CO'))+LOCATE('AL',IFNULL(Jun,'CO'))+LOCATE('AL',IFNULL(Jul,'CO'))+LOCATE('AL',IFNULL(Aug,'CO'))+LOCATE('AL',IFNULL(Sep,'CO'))+LOCATE('AL',IFNULL(`Oct`,'CO'))+LOCATE('AL',IFNULL(Nov,'CO'))+LOCATE('AL',IFNULL(`Dec`,'CO'))) AS total
FROM dc_bene_alignment_rpt_overview
WHERE BENE_MBI_ID=oigid AND `year`=2021
ORDER BY total DESC LIMIT 1;
          DECLARE CONTINUE HANDLER FOR NOT FOUND SET no_more_allergy=1;
    
         SET no_more_allergy=0;
          OPEN allergy_scr;
          REPEAT
               FETCH allergy_scr INTO al_code; 
		IF NOT no_more_allergy THEN 
               SET al_desc = CONCAT(al_desc , al_code,', ');    
		END IF;
          UNTIL no_more_allergy
          END REPEAT;
          CLOSE allergy_scr;
          SET no_more_allergy=0;
	  RETURN TRIM(BOTH ', ' FROM al_desc);
END */$$
DELIMITER ;

/* Function  structure for function  `QRD_TmplCData` */

DELIMITER $$

/*!50003 CREATE FUNCTION `QRD_TmplCData`(template_id INT, tag_name VARCHAR(100)) RETURNS text CHARSET latin1
    READS SQL DATA
BEGIN
  DECLARE retVal TEXT DEFAULT '';
	DECLARE dd_csr CURSOR FOR
	 SELECT tag_value FROM qrda_template_data_config AS q1 WHERE q1.template_id=template_id AND q1.tag_name=tag_name LIMIT 0,1;
	OPEN dd_csr;
		FETCH dd_csr INTO retVal;    
	CLOSE dd_csr;
	RETURN retVal;
END */$$
DELIMITER ;

/* Function  structure for function  `removeNull` */

DELIMITER $$

/*!50003 CREATE FUNCTION `removeNull`(char_in VARCHAR(400)) RETURNS varchar(400) CHARSET utf8mb3
BEGIN
	DECLARE char_out VARCHAR(400);
	IF char_in='NULL' OR char_in IS NULL THEN SET char_out='';
	ELSE SET char_out = char_in;
	END IF;
	RETURN (char_out);
    END */$$
DELIMITER ;

/* Function  structure for function  `removeNullDate` */

DELIMITER $$

/*!50003 CREATE FUNCTION `removeNullDate`(char_in VARCHAR(20)) RETURNS varchar(20) CHARSET utf8mb3
BEGIN
   DECLARE char_out VARCHAR(20);
   IF char_in='NULL' OR char_in IS NULL OR SUBSTRING(char_in,1,10)='12/31/1969' OR SUBSTRING(char_in,1,10)='00/00/0000' OR SUBSTRING(char_in,1,10)='1969-12-31' OR SUBSTRING(char_in,1,10)='0000-00-00' THEN SET char_out='';
   ELSE SET char_out = char_in;
   END IF;
   RETURN (char_out);
    END */$$
DELIMITER ;

/* Procedure structure for procedure `CALL_SyncLogger` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `CALL_SyncLogger`(pp1ValueNr BIGINT,pp2TableName VARCHAR(30), pp3TableColID VARCHAR(30),pp4NEW_SyncId TINYINT, pp5OLD_SyncId TINYINT)
BEGIN
IF (pp4NEW_SyncId != 3 || (pp4NEW_SyncId <=> pp5OLD_SyncId) = 1 ) THEN
INSERT INTO db_sync_logger SET message_type='SYCN', message_sub_type='db001SyncSetTrigger',other_id=pp1ValueNr,send_to=pp2TableName,send_from=pp3TableColID,message_created_by='db11Trigger',message_status='0',origid='0',encounter_nr='0';
END IF;
END */$$
DELIMITER ;

/* Procedure structure for procedure `cclf_exports` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `cclf_exports`()
BEGIN
    -- Declare variables to store selected values
    DECLARE MV01 INT;
    DECLARE MV02 INT;
    
   

    -- Fetch values from a SELECT statement and store them in variables
    SET @MV01 = (SELECT MAX(mm_imp_job_nr) AS mm_imp_job_nr FROM mra_file_static.mra_cclf8);
    SET @MV02 = (SELECT MAX(cc_version) FROM dc_bene_alignment_roster);
    
    -- Perform the first UPDATE operation
    UPDATE mra_file_static.mra_cclf1 t1 INNER JOIN mradb_prod.dc_bene_alignment_roster t2 ON t2.BENE_MBI_ID=t1.BENE_MBI_ID SET t1.dce_group_nr=t2.dce_group_nr 
	WHERE t1.mm_imp_job_nr=@MV01 AND t2.cc_version=@MV02;
	UPDATE mra_file_static.mra_cclf2 t1 INNER JOIN mradb_prod.dc_bene_alignment_roster t2 ON t2.BENE_MBI_ID=t1.BENE_MBI_ID SET t1.dce_group_nr=t2.dce_group_nr 
	WHERE t1.mm_imp_job_nr=@MV01 AND t2.cc_version=@MV02;
	UPDATE mra_file_static.mra_cclf3 t1 INNER JOIN mradb_prod.dc_bene_alignment_roster t2 ON t2.BENE_MBI_ID=t1.BENE_MBI_ID SET t1.dce_group_nr=t2.dce_group_nr 
	WHERE t1.mm_imp_job_nr=@MV01 AND t2.cc_version=@MV02;
	UPDATE mra_file_static.mra_cclf4 t1 INNER JOIN mradb_prod.dc_bene_alignment_roster t2 ON t2.BENE_MBI_ID=t1.BENE_MBI_ID SET t1.dce_group_nr=t2.dce_group_nr 
	WHERE t1.mm_imp_job_nr=@MV01 AND t2.cc_version=@MV02;
	UPDATE mra_file_static.mra_cclf5 t1 INNER JOIN mradb_prod.dc_bene_alignment_roster t2 ON t2.BENE_MBI_ID=t1.BENE_MBI_ID SET t1.dce_group_nr=t2.dce_group_nr 
	WHERE t1.mm_imp_job_nr=@MV01 AND t2.cc_version=@MV02;
	UPDATE mra_file_static.mra_cclf6 t1 INNER JOIN mradb_prod.dc_bene_alignment_roster t2 ON t2.BENE_MBI_ID=t1.BENE_MBI_ID SET t1.dce_group_nr=t2.dce_group_nr 
	WHERE t1.mm_imp_job_nr=@MV01 AND t2.cc_version=@MV02;
	UPDATE mra_file_static.mra_cclf7 t1 INNER JOIN mradb_prod.dc_bene_alignment_roster t2 ON t2.BENE_MBI_ID=t1.BENE_MBI_ID SET t1.dce_group_nr=t2.dce_group_nr 
	WHERE t1.mm_imp_job_nr=@MV01 AND t2.cc_version=@MV02;
	UPDATE mra_file_static.mra_cclf8 t1 INNER JOIN mradb_prod.dc_bene_alignment_roster t2 ON t2.BENE_MBI_ID=t1.BENE_MBI_ID SET t1.dce_group_nr=t2.dce_group_nr 
	WHERE t1.mm_imp_job_nr=@MV01 AND t2.cc_version=@MV02;
	UPDATE mra_file_static.mra_cclf9 t1 INNER JOIN mradb_prod.`dc_bene_alignment_roster` t2 ON t2.BENE_MBI_ID=t1.`mm_curr_mbi_id` SET t1.dce_group_nr=t2.dce_group_nr 
	WHERE t1.mm_imp_job_nr=@MV01 AND t2.cc_version=(SELECT MAX(cc_version) FROM  mradb_prod.`dc_bene_alignment_roster`);

    
    -- Optionally, you can add more logic or handle errors

    END */$$
DELIMITER ;

/* Procedure structure for procedure `ccm_active` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `ccm_active`(enc_nr BIGINT, pat_id VARCHAR(64))
BEGIN

 DECLARE cm_name VARCHAR(125); DECLARE mc_version INT;
 
 SET cm_name=(SELECT encounter_nr FROM ccm_active WHERE encounter_nr=enc_nr AND TYPE='RNCC' AND assigned_cm IS NOT NULL AND assigned_cm<>'' LIMIT 1);
 IF cm_name IS NULL THEN 
  SET mc_version=(SELECT MAX(cc_version) FROM dc_bene_alignment_roster);
  SET cm_name=(SELECT pr1.name AS 'CM' FROM personell pr INNER JOIN dc_bene_alignment_roster p ON pr.name=p.dce_provider_name INNER JOIN mra_dce_cm_mapping mc ON pr.npr_id=mc.provider_npi INNER JOIN personell pr1 ON mc.cm_nr=pr1.nr WHERE p.BENE_MBI_ID=pat_id AND mc.cm_nr=pr1.nr AND mc.type='CCM_MNGT' AND p.cc_version=mc_version LIMIT 1);

  IF cm_name IS NULL OR cm_name='' THEN 
   INSERT INTO adt_encounter_logger SET encounter_nr=enc_nr,log_info='Encounter ccm_active : cm_name empty',created_date=NOW(); 
   SET cm_name='Not Assigned';
  END IF;

  INSERT INTO adt_encounter_logger SET encounter_nr=enc_nr,log_info='Encounter ccm_active : before',created_date=NOW();
  INSERT IGNORE INTO ccm_active SET origid=pat_id,encounter_nr=enc_nr,TYPE='RNCC',STATUS='pending',onset_date=NOW(),expiration_date=DATE_ADD(CURRENT_DATE(), INTERVAL 30 DAY),active_period='30',SOURCE='ADT',created_by='auto_script',assigned_cm=cm_name;
  UPDATE ccm_active SET assigned_cm=cm_name WHERE encounter_nr=enc_nr AND `TYPE`='RNCC';
  INSERT INTO adt_encounter_logger SET encounter_nr=enc_nr,log_info=CONCAT('Encounter ccm_active : added - ',cm_name),created_date=NOW();

 ELSE  
  INSERT INTO adt_encounter_logger SET encounter_nr=enc_nr,log_info='Encounter ccm_active : skipped',created_date=NOW();   
 END IF;

END */$$
DELIMITER ;

/* Procedure structure for procedure `ccm_active_census` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `ccm_active_census`(enc_nr BIGINT, pat_id VARCHAR(64))
BEGIN
 DECLARE census_name VARCHAR(125);
 DECLARE census_name1 VARCHAR(125);  
 DECLARE mc_version INT;
 DECLARE mm_dates VARCHAR(125);
 SET census_name=(SELECT encounter_nr FROM ccm_active WHERE encounter_nr=enc_nr AND TYPE='Census_Notes' AND assigned_cm IS NOT NULL AND assigned_cm<>'' LIMIT 1);
 IF census_name IS NULL THEN 
  SET mc_version=(SELECT MAX(cc_version) FROM dc_bene_alignment_rostr_m01);
  SET mm_dates=(SELECT MAX(mm_date)FROM `dc_bene_alignment_rostr_m01` HAVING MAX(cc_version) );
  SET census_name=(SELECT pr1.name AS 'Census' FROM personell pr INNER JOIN dc_bene_alignment_rostr_m01 p ON pr.name=p.dce_provider_name INNER JOIN mra_dce_cm_mapping mc ON pr.npr_id=mc.provider_npi INNER JOIN personell pr1 ON mc.cm_nr=pr1.nr WHERE p.`mm_curr_mbi_id`=pat_id AND mc.cm_nr=pr1.nr AND mc.type='census_notes' AND p.cc_version=(SELECT MAX(cc_version) FROM dc_bene_alignment_rostr_m01 )  AND mm_date=mm_dates LIMIT 1);
  
  UPDATE adt_encounter SET closed='Open' WHERE encounter_nr=enc_nr; 
SET census_name1=(SELECT pr1.NAME AS 'Census' FROM personell pr1
INNER JOIN mra_dce_cm_mapping mc ON pr1.nr=mc.cm_nr 
INNER JOIN adt_encounter adt ON mc.hospital_id=adt.mhos_mhie_nr
WHERE  adt.encounter_nr=enc_nr AND  mc.TYPE IN ('HCC_NOTES', 'Census_Notes', 'HCC')  LIMIT 1);
IF census_name1 IS NOT NULL THEN
   
   INSERT INTO ccm_active 
    (origid, encounter_nr, TYPE, STATUS, onset_date, expiration_date, active_period, SOURCE, created_by)
VALUES 
    (pat_id, enc_nr, 'Census_Notes', 'active', NOW(), DATE_ADD(CURRENT_DATE(), INTERVAL 30 DAY), '30', 'ADT', 'auto_script')
ON DUPLICATE KEY UPDATE
    STATUS = 'pending',
	assigned_cm='',
    created_by = 'auto_script';
	
	UPDATE adt_encounter SET mflag_census=1 WHERE encounter_nr=enc_nr;
       INSERT INTO adt_encounter_logger 
       SET encounter_nr = enc_nr, 
           log_info = CONCAT('Encounter ccm_active_hospital : updated - ', census_name1), 
           created_date = NOW(); 
  
      UPDATE adt_encounter SET hcc_owner=census_name1 WHERE encounter_nr=enc_nr ;
      INSERT INTO ccm_active 
    (origid, encounter_nr, TYPE, STATUS, onset_date, expiration_date, active_period, SOURCE, created_by, assigned_cm)
VALUES 
    (pat_id, enc_nr, 'Census_Notes', 'active', NOW(), DATE_ADD(CURRENT_DATE(), INTERVAL 30 DAY), '30', 'ADT', 'auto_script', census_name1)
ON DUPLICATE KEY UPDATE
    STATUS = 'active',
     assigned_cm = census_name;
ELSE 
    INSERT INTO adt_encounter_logger SET encounter_nr=enc_nr,log_info='Encounter ccm_active_census : census_name1 empty',created_date=NOW(); 
 END IF; 
  IF census_name IS NULL OR census_name='' THEN 
   INSERT INTO adt_encounter_logger SET encounter_nr=enc_nr,log_info='Encounter ccm_active_census : census_name empty',created_date=NOW(); 
  ELSE 
   INSERT INTO adt_encounter_logger SET encounter_nr=enc_nr,log_info='Encounter ccm_active_census : before',created_date=NOW();
UPDATE adt_encounter set mflag_census=1 WHERE encounter_nr=enc_nr;
   INSERT INTO ccm_active 
    (origid, encounter_nr, TYPE, STATUS, onset_date, expiration_date, active_period, SOURCE, created_by, assigned_cm)
VALUES 
    (pat_id, enc_nr, 'Census_Notes', 'active', NOW(), DATE_ADD(CURRENT_DATE(), INTERVAL 30 DAY), '30', 'ADT', 'auto_script', census_name)
ON DUPLICATE KEY UPDATE
    STATUS = 'active',
     assigned_cm = census_name;
  # UPDATE ccm_active SET assigned_cm=census_name WHERE encounter_nr=enc_nr AND `TYPE`='Census_Notes';
  INSERT INTO adt_encounter_logger SET encounter_nr=enc_nr,log_info=CONCAT('Encounter ccm_active_census : added - ',census_name),created_date=NOW();
  END IF;
 ELSE  
  INSERT INTO adt_encounter_logger SET encounter_nr=enc_nr,log_info='Encounter ccm_active_census : skipped',created_date=NOW();   
 END IF;
END */$$
DELIMITER ;

