/* Procedure structure for procedure `ccm_active_mos` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `ccm_active_mos`(encounterId BIGINT, origId VARCHAR(64))
BEGIN
 DECLARE messageTxt VARCHAR(250);
 DECLARE mosLock TINYINT;
 DECLARE mosName VARCHAR(250);
 DECLARE posCurr TINYINT;
 DECLARE mifExclusion TINYINT;
 DECLARE taxonomyVal VARCHAR(10);
 DECLARE tfuEnabled TINYINT;
 DECLARE dischargeDate DATE;
 DECLARE encounterType VARCHAR(100);
  
 
 SET mosName=(SELECT pr1.NAME AS 'MOS' FROM personell pr INNER JOIN `dc_bene_alignment_rostr_m01` p ON pr.NAME=p.dce_provider_name INNER JOIN mra_dce_cm_mapping mc ON pr.npr_id=mc.provider_npi INNER JOIN personell pr1 ON mc.cm_nr=pr1.nr WHERE p.BENE_MBI_ID=origId AND mc.cm_nr=pr1.nr AND mc.TYPE='Outreach' AND p.cc_version=(SELECT MAX(cc_version) FROM dc_bene_alignment_rostr_m01 ) AND p.mm_date=(SELECT MAX(mm_date) FROM dc_bene_alignment_rostr_m01 ) LIMIT 1);
 IF mosName IS NULL OR mosName='' THEN 
   SET mosName='Not assigned'; 
 END IF;
 
 SELECT mos_lock, pos_curr, mif_exclusion, taxonomy, tfu_enabled, discharge_date, encounter_type 
 INTO mosLock, posCurr, mifExclusion, taxonomyVal, tfuEnabled, dischargeDate, encounterType 
 FROM adt_encounter WHERE encounter_nr=encounterId LIMIT 1;
 
 IF dischargeDate IS NULL THEN
    SET dischargeDate = '0000-00-00';
 END IF;	
  SET messageTxt = CONCAT('(mos_lock = ',mosLock,' AND (pos_curr=',posCurr,' && mif_exclusion=',mifExclusion, ' && taxonomy=', taxonomyVal, ' && tfu_enabled=', tfuEnabled, ' && discharge_date=', dischargeDate, ' && encounter_type=', encounterType, '))');
   
 IF encounterType='Deceased' OR encounterType='IP-DECEASED' THEN 
    INSERT INTO adt_encounter_logger SET encounter_nr=encounterId,log_info=CONCAT('MOS is not updated, ', messageTxt),created_date=NOW(); 
 ELSEIF mosLock=0 AND posCurr=21 AND mifExclusion=0 AND 
   (taxonomyVal='282N00000X' OR taxonomyVal='282NC0060X' OR taxonomyVal='282NR1301X' OR taxonomyVal='282NC2000X' OR taxonomyVal='284300000X' OR taxonomyVal='286500000X') AND 
   (dischargeDate<>'0000-00-00' AND dischargeDate<>'1969-12-31' AND dischargeDate IS NOT NULL) THEN
     UPDATE adt_encounter SET mos=mosName, followup_days='7' WHERE encounter_nr=encounterId;
    INSERT INTO adt_encounter_logger 
SET encounter_nr = encounterId,
    log_info = CONCAT(
        'MOS is updated for MIF/Inpatient. Executed: UPDATE adt_encounter SET mos = \'', 
        mosName, '\', followup_days = \'7\' WHERE encounter_nr = ', encounterId, 
        '. Conditions: ', messageTxt
    ),
    created_date = NOW();
 ELSEIF mosLock=0 AND posCurr=21 AND tfuEnabled=0 AND mifExclusion=1 THEN 
   INSERT INTO adt_encounter_logger SET encounter_nr=encounterId,log_info=CONCAT('MOS is not updated, ', messageTxt),created_date=NOW();    
 ELSEIF mosLock=0 AND posCurr=21 AND tfuEnabled=0 AND 
   (dischargeDate='0000-00-00' OR dischargeDate='1969-12-31' OR dischargeDate IS NULL) THEN 
   INSERT INTO adt_encounter_logger SET encounter_nr=encounterId,log_info=CONCAT('MOS is not updated, ', messageTxt),created_date=NOW();    
 ELSEIF mosLock=0 AND ((posCurr!=-99 AND posCurr!=22) OR tfuEnabled=1) AND mifExclusion=0 THEN
   UPDATE adt_encounter SET mos=mosName WHERE encounter_nr=encounterId;
   INSERT INTO adt_encounter_logger SET encounter_nr=encounterId,log_info=CONCAT('MOS is updated, ', messageTxt),created_date=NOW();		
 ELSE
   INSERT INTO adt_encounter_logger SET encounter_nr=encounterId,log_info=CONCAT('MOS is not updated, ', messageTxt),created_date=NOW();    
 END IF;
  
END */$$
DELIMITER ;

/* Procedure structure for procedure `ccm_active_uha` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `ccm_active_uha`(IN pat_id VARCHAR(64))
BEGIN
    DECLARE cm_name VARCHAR(125);
    DECLARE duplicate_count INT;

    -- Retrieve the Care Manager (CM) name
    SELECT pr1.name AS CM
    INTO cm_name
    FROM personell pr
    INNER JOIN dc_bene_alignment_roster p ON pr.name = p.dce_provider_name
    INNER JOIN mra_dce_cm_mapping mc ON pr.npr_id = mc.provider_npi
    INNER JOIN personell pr1 ON mc.cm_nr = pr1.nr
    WHERE p.BENE_MBI_ID = pat_id
      AND mc.cm_nr = pr1.nr
      AND mc.type = 'CCM_MNGT'
      AND p.cc_version = (SELECT MAX(cc_version) FROM dc_bene_alignment_roster)
    LIMIT 1;

    -- Check for duplicates in the ccm_active table
    SELECT COUNT(*)
    INTO duplicate_count
    FROM ccm_active
    WHERE origid = pat_id 
      AND TYPE = 'RNCC' 
      AND `source`='UHA'
      AND (
           expiration_date IS NOT NULL     -- Include NULL expiration_date
          AND expiration_date >= CURRENT_DATE -- Include cases where expiration_date is less than or equal to the current date
      ) AND `status`='pending';

    -- If no duplicates are found, proceed with insert/update
    IF duplicate_count = 0 THEN
        INSERT INTO ccm_active 
        SET origid = pat_id,
            TYPE = 'RNCC',
            STATUS = 'pending',
            created_date = NOW(),
            onset_date = NOW(),
            expiration_date = DATE_ADD(CURRENT_DATE(), INTERVAL 90 DAY),
            active_period = '30',
            SOURCE = 'UHA',
            created_by = 'auto_script',
            assigned_cm = cm_name
        ON DUPLICATE KEY UPDATE 
            TYPE = 'RNCC',
            STATUS = 'pending',
            onset_date = NOW(),
            expiration_date = DATE_ADD(CURRENT_DATE(), INTERVAL 90 DAY),
            active_period = '90',
            SOURCE = 'UHA',
            created_by = 'auto_script',
            assigned_cm = cm_name;
    ELSE
        -- Handle the duplicate case
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Duplicate entry found in ccm_active for the given origid.';
    END IF;
END */$$
DELIMITER ;

/* Procedure structure for procedure `ccm_Remove_Assigned_MOS_CM` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `ccm_Remove_Assigned_MOS_CM`(
IN enc_nr BIGINT,
IN orgid VARCHAR(64),
IN enc_date DATE,
OUT response VARCHAR(64)
)
BEGIN
	IF (enc_nr < 1 OR enc_nr = '') THEN
		SET response = 'Invalid encounter_nr';
	ELSEIF (orgid = '') THEN
		SET response = 'Invalid origid';
	ELSE
		INSERT INTO adt_encounter_logger SET encounter_nr=enc_nr,log_info='Encounter ccm_Remove_Assigned_MOS_CM called',created_date=NOW();
	   		DELETE FROM ccm_active WHERE encounter_nr=enc_nr AND origid=orgid AND TYPE='RNCC';
	   		DELETE FROM ccm_history WHERE encounter_nr=enc_nr AND origid=orgid AND TYPE='RNCC';
			UPDATE adt_encounter SET mos = '' WHERE encounter_nr=enc_nr AND origid=orgid;
			#UPDATE adt_encounter set closed='Open' WHERE encounter_nr=enc_nr AND origid=orgid;
			
			#CALL ccm_active_census(enc_nr, orgid);
			#CALL ccm_active_cm_mos(enc_nr, orgid);
			SELECT MRA_SV01_SetEncounterVals(orgid,enc_nr,enc_date) AS mpid;
			INSERT INTO adt_encounter_logger SET encounter_nr=enc_nr,log_info='Encounter ccm_Remove_Assigned_MOS_CM ended',created_date=NOW();
		
	END IF;
END */$$
DELIMITER ;

