/* Procedure structure for procedure `ExportIncrementalToCSV` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `ExportIncrementalToCSV`(
    IN last_export_time DATETIME,
    IN output_file_path VARCHAR(255)
)
BEGIN
    -- Create a temporary table to store the results
    CREATE TEMPORARY TABLE temp_export AS
    SELECT * 
    FROM ccm_Active
    WHERE created_date > last_export_time;

    -- Check if there are records to export
    IF (SELECT COUNT(*) FROM temp_export) > 0 THEN
        -- Export the data to a CSV file
        SET @query = CONCAT(
            'SELECT * INTO OUTFILE \'', output_file_path, 
            '\' FIELDS TERMINATED BY \',\' ENCLOSED BY \'\"\' LINES TERMINATED BY \'\n\' FROM temp_export'
        );
        PREPARE stmt FROM @query;
        EXECUTE stmt;
        DEALLOCATE PREPARE stmt;
    ELSE
        SELECT 'No new or updated records found' AS message;
    END IF;

    -- Drop the temporary table
    DROP TEMPORARY TABLE temp_export;
END */$$
DELIMITER ;

/* Procedure structure for procedure `kill_other_processes` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `kill_other_processes`()
BEGIN
  DECLARE finished INT DEFAULT 0;
  DECLARE proc_id INT;
  DECLARE proc_id_cursor CURSOR FOR SELECT id FROM information_schema.processlist WHERE db='mradb_prod';
  DECLARE CONTINUE HANDLER FOR NOT FOUND SET finished = 1;

  OPEN proc_id_cursor;
  proc_id_cursor_loop: LOOP
    FETCH proc_id_cursor INTO proc_id;

    IF finished = 1 THEN 
      LEAVE proc_id_cursor_loop;
    END IF;

INSERT INTO mra_00_tmp SET mdd_1=proc_id,mdd_2='END',mdd_3=1;

    IF proc_id <> CONNECTION_ID() THEN
      KILL proc_id;
      
    END IF;

  END LOOP proc_id_cursor_loop;
  CLOSE proc_id_cursor;
END */$$
DELIMITER ;

/* Procedure structure for procedure `Load_HEI_Records` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `Load_HEI_Records`()
BEGIN


SELECT * FROM
(
SELECT DISTINCT p.origid,m.market_name AS market ,dba.dce_group_name AS 'DCE_Group',dba.dce_group_nr,dba.dce_provider_name AS 'DCE_Provider',
    MONTH(e.encounter_date) AS months,YEAR(e.encounter_date) AS YEAR,dba.dce_sub_group_name AS dce_sub_group,DATE_FORMAT(p.birthdate,'%m/%d/%Y') AS dob,

          
     Case 
     When r.modified_by IS NULL OR r.modified_by = '' Then r.created_by
     else r.modified_by
     END As userid
    
    
    
    ,history_value,hm.market_id AS market_id,dba.ALIGN_STATUS_CODE AS ALIGN_STATUS_CODE,e.encounter_class_nr,r.history_nr ,e.origid as enc_mbi,
    
    (SELECT DATE_FORMAT(history_value,'%m/%d/%Y') FROM mra_member_history_data WHERE encounter_nr=r.encounter_nr AND history_nr=150661 LIMIT 1) AS history_date,
    
    
     (SELECT DATE_FORMAT(history_value,'%m/%d/%Y') FROM mra_member_history_data WHERE encounter_nr=r.encounter_nr AND history_nr=150661 LIMIT 1) AS history_dt,
     
      (SELECT history_value FROM mra_member_history_data WHERE encounter_nr=r.encounter_nr AND history_nr=150665 LIMIT 1) AS state,
     
    /*, 
    GROUP_CONCAT(DISTINCT(r.encounter_nr)) as 'concat_encounter'*/
    r.encounter_nr AS 'concat_encounter', CONCAT(p.lastname,' ',p.firstname) AS 'Patient_name', IF(office_check.enc IS NULL, 'No', 'Yes') AS is_completed_by_office , r.source,dba.cc_version
    
     FROM mra_member_history_data r 
 INNER JOIN encounter e ON r.encounter_nr=e.encounter_nr 
 INNER JOIN patient p ON e.origid=p.origid 
 INNER JOIN `dc_bene_alignment_rostr_m01` dba ON dba.mm_curr_mbi_id=p.origid
 INNER JOIN hospital_market_assocs hm ON dba.dce_group_nr=hm.hosp_id
 INNER JOIN `hospital_market` m ON m.market_id=hm.market_id
 LEFT JOIN (SELECT DISTINCT(encounter_nr) enc FROM mra_member_history_data WHERE   history_nr IN (150686) AND  history_value= 'Y') AS office_check ON r.encounter_nr=office_check.enc
 
    
    WHERE (SELECT DATE_FORMAT(history_value,'%Y-%m-%d') FROM mra_member_history_data WHERE encounter_nr=r.encounter_nr AND history_nr=150661 LIMIT 1)  BETWEEN '2023-01-01' AND '2025-12-31'
    
    /*AND YEAR(e.encounter_date)>=2023*/
    /*AND r.created_by NOT IN  ('user, Administrator') */

    /*AND p.origid='5RJ7N93FD47' */
    
    
    AND r.history_nr IN (150665,150661)
    AND r.history_value IS NOT NULL 
    /*AND r.history_value IN ('Completed')*/
    AND history_value NOT IN(';../../','')

/*    AND r.created_by !='-1'*/

     
   
     AND ((dba.cc_version=(SELECT MAX(cc_version) FROM `dc_bene_alignment_rostr_m01` dba) 
     AND dba.mm_date= (SELECT MAX(mm_date) FROM `dc_bene_alignment_rostr_m01` dba1 WHERE 
cc_version IN (SELECT MAX(cc_version) FROM `dc_bene_alignment_rostr_m01` dba)))

or (dba.cc_version=20241204 and Month(mm_date)=12) or (dba.cc_version=20231204 AND MONTH(mm_date)=12)

) /*'2024-11-01'*/
      
    /*and  p.origid IN ('2KN5HG0VQ51','3Y33PM9MM71')*/
     
     /*GROUP BY r.encounter_nr,p.origid,userid,dba.dce_provider_name,dba.dce_group_nr,r.history_value,dba.ALIGN_STATUS_CODE*/
     ) AS main
     
     LEFT JOIN 




( 

SELECT M.nr, MAX(rep_name) AS rep_name, MAX(full_name) AS full_name,  MIN(M.type) Department  FROM 
   (
     
     SELECT DISTINCT  p.nr,t.type,p.name AS rep_name, CONCAT(p.last_name,', ',p.First_name) AS full_name  ,`is_default_role` , pr.Active_date FROM personell p INNER JOIN personell_roles pr ON p.nr=pr.`personell_nr` INNER JOIN type_personel t ON pr.`job_type_nr`=t.nr WHERE
      p.is_dce=1 AND p.dce_type='DCE' AND pr.job_type_nr IN (116,117,121,122,123,124,125) AND `is_default_role`=1
      
      UNION 
      
       SELECT DISTINCT  p.nr,t.type,p.name AS rep_name,CONCAT(p.last_name,', ',p.First_name) AS full_name  ,`is_default_role` , pr.Active_date FROM personell p INNER JOIN personell_roles pr ON p.nr=pr.`personell_nr` INNER JOIN type_personel t ON pr.`job_type_nr`=t.nr
       
INNER JOIN ( SELECT  personell_nr, MAX(Active_date) max_active FROM personell_roles 
     GROUP  BY personell_nr) AS max_tab ON     max_tab.max_active >= pr.Active_date AND max_tab.personell_nr=  p.nr
       
        WHERE
      p.is_dce=1 AND p.dce_type='DCE' AND pr.job_type_nr IN (116,117,121,122,123,124,125)  
      
      AND p.nr NOT IN 
      
      ( 
      
	SELECT DISTINCT  p.nr FROM personell p INNER JOIN personell_roles pr ON p.nr=pr.`personell_nr` INNER JOIN type_personel t ON pr.`job_type_nr`=t.nr WHERE
      p.is_dce=1 AND p.dce_type='DCE' AND pr.job_type_nr IN (116,117,121,122,123,124,125) AND `is_default_role`=1      
      
      )
      
      
    ) AS M
    GROUP BY M.nr

) AS deps ON (deps.rep_name=main.userid OR deps.full_name=main.userid  )

LEFT JOIN 

(

SELECT M.nr AS duplicated_nr  FROM 
   (
     
     SELECT DISTINCT  p.nr,t.type,CONCAT(p.last_name,', ',p.First_name) AS rep_name ,`is_default_role` , pr.Active_date FROM personell p INNER JOIN personell_roles pr ON p.nr=pr.`personell_nr` INNER JOIN type_personel t ON pr.`job_type_nr`=t.nr WHERE
      p.is_dce=1 AND p.dce_type='DCE' AND pr.job_type_nr IN (116,117,121,122,123,124,125) 
   
      
      
      
    ) AS M
   
    GROUP BY M.nr
    HAVING COUNT(M.type) > 1
     




) dupli

ON deps.nr=dupli.duplicated_nr;



END */$$
DELIMITER ;

/* Procedure structure for procedure `Load_Sva_Records` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `Load_Sva_Records`()
BEGIN

SELECT 20240701 AS cc_version, 2024 AS mm_year,7 AS mm_mon, mra_sva_records.origid,benef_first_name AS benef_first_name,benef_last_name AS benef_last_name,benef_street_addr AS benef_street_addr, mra_sva_records.city AS City, mra_sva_records.state AS State, mra_sva_records.Zip_code AS Zip_code,mra_sva_records.dce_group AS Group_name,group_nr,mra_sva_records.signature_date AS sva_sig_date, 
NULL Response_Code_List,
mra_sva_records.Source,mra_sva_records.npr_id AS npr_id,todays_date,is_delete,
pr.name AS provider_name,spi.Market,

(SELECT hc.name FROM personell_hosp_assocs phc INNER JOIN hospital_centers hc ON phc.hospital_nr=hc.nr 
                
                WHERE user_npi = mra_sva_records.npr_id AND YEAR(phc.end_date) >=  YEAR(mra_sva_records.todays_date)  AND is_sub_group=1 LIMIT 1 ) AS sub_group_name

FROM mra_sva_records AS mra_sva_records 

LEFT JOIN personell pr ON pr.npr_id=mra_sva_records.npr_id

LEFT JOIN Sva_Provider_info AS spi ON spi.npr_id=mra_sva_records.npr_id
    
    WHERE  pr.is_sva_enable=1 AND mra_sva_records.is_delete=0 AND mra_sva_records.npr_id IN (SELECT p.npr_id FROM personell p INNER JOIN personell_hosp_assocs pha ON p.npr_id=pha.user_npi INNER JOIN `hospital_centers` hc ON pha.hospital_nr=hc.nr WHERE p.npr_id IS NOT NULL AND p.npr_id != '' AND (p.npr_id NOT LIKE '%xx%' OR p.name LIKE '%UNK%') AND YEAR(pha.start_date) <= '2024' AND YEAR(pha.end_date) >= '2024' AND p.is_dce=1 AND p.dce_type = 'DCE' GROUP BY p.npr_id ORDER BY p.name )  
    AND  mra_sva_records.group_nr  IN (SELECT hc.nr AS id FROM hospital_centers hc  WHERE hc.is_dce = 1 AND (hc.main_hospital_nr IS NULL OR hc.main_hospital_nr=0) AND hc.dce_type='DCE'  AND YEAR(hc.start_date) <= '2024' AND YEAR(hc.end_date) >= '2024' ORDER BY hc.name ASC
);

END */$$
DELIMITER ;

/* Procedure structure for procedure `make_appointment_from` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `make_appointment_from`(p_enc_nr BIGINT,p_new_enc BIGINT,p_date DATE,p_time TIME,new_order_id VARCHAR(32))
BEGIN
	DROP TABLE IF EXISTS temporary_table;CREATE TABLE temporary_table AS SELECT * FROM `appointment` WHERE encounter_nr=p_enc_nr;UPDATE temporary_table SET `encounter_nr`=p_new_enc,`date`=p_date,`time`=p_time,`appt_status`='pending',`status`='pending',modify_id=NULL,modify_time=NULL,cancel_date=NULL,cancel_reason=NULL,cancel_notes=NULL;ALTER TABLE `temporary_table` CHANGE `nr` `nr` BIGINT(20) UNSIGNED NULL;UPDATE temporary_table SET nr=NULL;INSERT INTO appointment SELECT * FROM temporary_table;
	
	DROP TABLE IF EXISTS temporary_table;CREATE TABLE temporary_table AS SELECT * FROM `procedure_room` WHERE encounter_nr=p_enc_nr;ALTER TABLE `temporary_table` CHANGE `nr` `nr` BIGINT(20) UNSIGNED NULL;UPDATE temporary_table SET nr=NULL,`encounter_nr`=p_new_enc;INSERT INTO procedure_room SELECT * FROM temporary_table;
	DROP TABLE IF EXISTS temporary_table;CREATE TABLE temporary_table AS SELECT * FROM `block_out_dates` WHERE appointment_id=(SELECT nr FROM appointment WHERE encounter_nr=p_enc_nr);UPDATE temporary_table SET nr=NULL,start_date=p_date,start_time=p_time,end_date=p_date,end_time=(SELECT DATE_FORMAT(DATE_ADD(CONCAT(start_date,' ',start_time), INTERVAL procedure_time MINUTE),'%H:%i:%s')  FROM appointment WHERE encounter_nr=p_enc_nr),appointment_id=(SELECT nr FROM appointment WHERE encounter_nr=p_new_enc);INSERT INTO block_out_dates SELECT * FROM temporary_table;
	
	DROP TABLE IF EXISTS temporary_table;CREATE TABLE temporary_table AS SELECT * FROM `encounter_procedure` WHERE encounter_nr=p_enc_nr;UPDATE temporary_table SET procedure_nr=NULL,`encounter_nr`=p_new_enc,procedure_date=CONCAT(p_date,' ',p_time),initial_sign=NULL, sign_full_name=NULL, sign_date=NULL;INSERT INTO encounter_procedure SELECT * FROM temporary_table;
	
	DROP TABLE IF EXISTS temporary_table;CREATE TABLE temporary_table AS SELECT * FROM `encounter_allergy_codes` WHERE encounter_nr=p_enc_nr;UPDATE temporary_table SET id=NULL,`encounter_nr`=p_new_enc;INSERT INTO encounter_allergy_codes SELECT * FROM temporary_table;
	
	DROP TABLE IF EXISTS temporary_table;CREATE TABLE temporary_table AS SELECT * FROM `encounter_icd_codes` WHERE encounter_nr=p_enc_nr;ALTER TABLE `temporary_table` CHANGE `id` `id` BIGINT(20) UNSIGNED NULL;UPDATE temporary_table SET id=NULL,`encounter_nr`=p_new_enc;INSERT INTO encounter_icd_codes SELECT * FROM temporary_table;
	
	DROP TABLE IF EXISTS temporary_table;CREATE TABLE temporary_table AS SELECT * FROM `encounter_patient_medication` WHERE encounter_nr=p_enc_nr;ALTER TABLE `temporary_table` CHANGE `id` `id` BIGINT(20) UNSIGNED NULL;UPDATE temporary_table SET id=NULL,`encounter_nr`=p_new_enc;INSERT INTO encounter_patient_medication SELECT * FROM temporary_table;
	
	DROP TABLE IF EXISTS temporary_table;CREATE TABLE temporary_table AS SELECT * FROM `cpoe_orders` WHERE encounter_nr=p_enc_nr;ALTER TABLE `temporary_table` CHANGE `nr` `nr` BIGINT(20) UNSIGNED NULL;UPDATE temporary_table SET nr=NULL,`encounter_nr`=p_new_enc,order_id=new_order_id;INSERT INTO cpoe_orders SELECT * FROM temporary_table;
	END */$$
DELIMITER ;

/* Procedure structure for procedure `message_mov1_main_to_temp` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `message_mov1_main_to_temp`(IN msys_id INT,IN mres_id INT)
BEGIN
	INSERT IGNORE INTO msg_tmp_system SELECT * FROM message_system WHERE id=msys_id;
	INSERT IGNORE INTO msg_tmp_recepient SELECT * FROM message_recepient WHERE message_id=msys_id AND id=mres_id;
	UPDATE msg_tmp_recepient SET modified_date=NOW() WHERE message_id=msys_id AND id=mres_id;
	INSERT IGNORE INTO msg_tmp_attachments SELECT * FROM `message_attachments` WHERE message_id=msys_id;
	/* DELETE FROM `message_attachments` WHERE message_id=msys_id; */
	DELETE FROM message_recepient WHERE message_id=msys_id AND id=mres_id;
	/* DELETE FROM message_system WHERE id=msys_id; */
    END */$$
DELIMITER ;

/* Procedure structure for procedure `message_mov2_temp_to_main` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `message_mov2_temp_to_main`(IN msys_id INT,IN mres_id INT)
BEGIN
	/* INSERT IGNORE INTO message_system SELECT * FROM msg_tmp_system WHERE id=msys_id; */
	INSERT IGNORE INTO message_recepient SELECT * FROM msg_tmp_recepient WHERE message_id=msys_id AND id=mres_id;
	UPDATE message_recepient SET modified_date=NOW() WHERE message_id=msys_id AND id=mres_id;
	/* INSERT IGNORE INTO message_attachments SELECT * FROM msg_tmp_attachments WHERE message_id=msys_id; */
	DELETE FROM `msg_tmp_attachments` WHERE message_id=msys_id;
	DELETE FROM msg_tmp_recepient WHERE message_id=msys_id AND id=mres_id;
	DELETE FROM msg_tmp_system WHERE id=msys_id;
    END */$$
DELIMITER ;

/* Procedure structure for procedure `MHC_11_init_group_performance_07` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MHC_11_init_group_performance_07`(m1pp int)
BEGIN

DECLARE vtmp VARCHAR(999); DECLARE mmi INT; DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(999);DECLARE qArg02 VARCHAR(999);
DECLARE mrw CURSOR FOR SELECT distinct Provider_NPI FROM bt_static.mra_config_a1_perf_prov_01 where YEAR(MOS)=m1pp; /* AND dce_group_nr=0 */
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;
SET mmi=1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01;
 IF bmc = 0 THEN
  SET vtmp = (SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',market_id) AS mccc FROM dc_bene_alignment_rostr_m01 WHERE prov_npi_nr=qArg01 AND year(mm_date)=m1pp and dce_group_nr>0 ORDER BY cc_version DESC LIMIT 1);
  IF vtmp IS not NULL THEN
   SET @v1tmp=SUBSTRING_INDEX(vtmp,'!@#',1); SET @v99tmp=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET @v2tmp=SUBSTRING_INDEX(vtmp,'!@#',2); SET @v2tmp=SUBSTRING_INDEX(@v2tmp,'!@#',-1);
   UPDATE `bt_static`.`mra_config_a1_perf_prov_01` set dce_group_nr=@v1tmp,dce_group_sub_nr=@v2tmp,market_nr=@v99tmp WHERE YEAR(MOS)=m1pp and Provider_NPI=qArg01;
  END IF;
  SET mmi = mmi + 1;
  INSERT INTO mra_00_tmp SET mdd_1="MHC11_init_group_perfor_07",mdd_2=vtmp,mdd_3=qArg01,mdd_4=mmi;
 END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MHC_11_init_group_performance_08` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MHC_11_init_group_performance_08`()
BEGIN

 DECLARE vtmp VARCHAR(999); DECLARE mmi INT;
 DECLARE bmc INT DEFAULT 0;
 DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(999);DECLARE qArg02 VARCHAR(999);

 DECLARE mrw CURSOR FOR SELECT nr,Provider_NPI,MOS FROM bt_static.mra_config_a1_perf_prov_01 ORDER BY MOS;

 DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

 TRUNCATE mra_00_tmp;

SET @mc1val=(SELECT MAX(cc_version) FROM dc_bene_alignment_rostr_m01);

CALL MHC_11_init_group_performance_11();
CALL MHC_11_init_group_performance_11_02();
CALL MHC_11_init_group_performance_12(@mc1val);

SET mmi = 1;

UPDATE `bt_static`.`mra_config_a1_perf_prov_01` SET dce_group_sub_nr=0,group_sub_name='';

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02;

 IF bmc = 0 THEN
  SET vtmp = (SELECT dce_sub_group_nr FROM dc_bene_alignment_rostr_m01 WHERE prov_npi_nr=qArg01 AND mm_date=qArg02 AND (cc_version IN (26,20231202) OR cc_version=@mc1val) LIMIT 1);
  IF vtmp IS NOT NULL THEN
   UPDATE `bt_static`.`mra_config_a1_perf_prov_01` SET dce_group_sub_nr=vtmp WHERE nr=qArg00;
  END IF;
  SET mmi = mmi + 1;
  INSERT INTO mra_00_tmp SET mdd_1="MHC_11_init_group_perf_08",mdd_2=vtmp,mdd_3=qArg01,mdd_4=qArg02;

 END IF;
END LOOP;
CLOSE mrw;
 

 UPDATE `bt_static`.`mra_config_a1_perf_prov_01` t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.dce_group_sub_nr SET t1.group_sub_name=t2.`name`;
 ########################################################################
 UPDATE bt_static.mra_config_a1_perf_prov_01 SET Group_Name="Julia Bornmann",dce_group_nr=10223497 WHERE Provider_NPI='1275957466' AND MOS>='2023-01-01';
 UPDATE bt_static.mra_config_a1_perf_prov_01 t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.dce_group_nr SET t1.Group_Name=t2.`name`;
 ########################################################################
 UPDATE `bt_static`.`mra_config_a1_perf_prov_01` t1 SET t1.market_nr = (SELECT t2.market_id FROM hospital_market_assocs t2 WHERE t2.hosp_id=t1.dce_group_nr);
 UPDATE `bt_static`.`mra_config_a1_perf_prov_01` t1 INNER JOIN hospital_market t2 ON t2.market_id=t1.market_nr SET t1.market_name=t2.`market_name`;
 UPDATE `bt_static`.`mra_config_a1_perf_prov_01` t1 SET t1.provider_name=(SELECT `name` FROM personell t2 WHERE t2.npr_id=t1.Provider_NPI AND is_dce=1 LIMIT 1);

/*
SET @mc1val=(SELECT MAX(YEAR(MOS)) FROM bt_static.mra_config_a1_perf_prov_01);
SET @mc2val=(SELECT MAX(MONTH(MOS)) FROM bt_static.mra_config_a1_perf_prov_01 WHERE YEAR(MOS)=@mc1val);
DELETE FROM bt_static.mra_config_a1_perf_prov_01 WHERE YEAR(MOS)=@mc1val AND MONTH(MOS)>@mc2val;
*/
DELETE FROM bt_static.mra_config_a1_perf_prov_01 WHERE YEAR(MOS)>2023;

END */$$
DELIMITER ;

/* Procedure structure for procedure `Migrate_Med_PatToEnc` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `Migrate_Med_PatToEnc`(IN or_id VARCHAR(64),IN enc_nr BIGINT(20))
start_migrate:BEGIN
DECLARE epm_id INTEGER;
DECLARE pat_id_d VARCHAR (64);
DECLARE med_d TEXT;
DECLARE act_d VARCHAR (200);
DECLARE dose_d VARCHAR (100);
DECLARE dos_st_d VARCHAR (255);
DECLARE gen_n_d VARCHAR (255);
DECLARE dos_un_d VARCHAR (200);
DECLARE quan_d VARCHAR (200);
DECLARE quan_un_d VARCHAR (200);
DECLARE dur_d VARCHAR (200);
DECLARE rout_d VARCHAR (200);
DECLARE dos_tim_d VARCHAR (200);
DECLARE dose_oth_d VARCHAR (255);
DECLARE refl_d VARCHAR (50);
DECLARE subs_d VARCHAR (200);
DECLARE NDC_d TEXT;
DECLARE Rxid_d VARCHAR (30);
DECLARE med_ext_d VARCHAR (200);
DECLARE sch_d VARCHAR (80);
DECLARE oth_name_d VARCHAR (80);
DECLARE off_only_d TEXT;
DECLARE st_reas_d TEXT;
DECLARE fl_date_d DATETIME;
DECLARE str_date_d DATETIME;
DECLARE stp_date_d DATETIME;
DECLARE cr_by_d VARCHAR (200);
DECLARE cr_date_d DATETIME;
DECLARE src_d VARCHAR (20);
DECLARE enc_date DATETIME;
DECLARE v_finished INTEGER DEFAULT 0;
declare config_val varchar(60);
DECLARE epm_cur CURSOR FOR SELECT id FROM encounter_patient_medication WHERE patientid=or_id AND encounter_nr=enc_nr;
/*DECLARE dpm_cur cursor;
DECLARE enc_dt_cur CURSOR;*/
set config_val = get_config_global('patient_migrate_medications_encounter');
if config_val != 1 then
	leave start_migrate;
end if;
SET epm_id=0;
	OPEN epm_cur;
		SELECT FOUND_ROWS() INTO epm_id;
			IF epm_id = 0 THEN
				BEGIN
					DECLARE dpm_cur CURSOR FOR SELECT patientid,medications,`action`,dose,dose_strength,generic_name,dose_unit,quantity,quantity_unit,duration,rout,dose_timming,dose_others,refills,substitution_permitted,NDCID,RxnormID,medication_external_id,SCHEDULE,other_notes,office_useonly,stopreason,fill_date,start_date,stop_date,created_by,created_date,source FROM drfirst_patient_medications WHERE patientid=or_id AND delete_status='n' AND RxnormID!='-99' AND source NOT IN ('order','ORDER');
					DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_finished = 1;
					OPEN dpm_cur;
						med_loop: LOOP
							FETCH dpm_cur INTO pat_id_d,med_d,act_d,dose_d,dos_st_d,gen_n_d,dos_un_d,quan_d,quan_un_d,dur_d,rout_d,dos_tim_d,dose_oth_d,refl_d,subs_d,NDC_d,Rxid_d,med_ext_d,sch_d,oth_name_d,off_only_d,st_reas_d,fl_date_d,str_date_d,stp_date_d,cr_by_d,cr_date_d,src_d;
							IF pat_id_d IS NOT NULL THEN
								block_cursor:BEGIN
									DECLARE enc_dt_cur CURSOR FOR SELECT encounter_date FROM encounter WHERE encounter_nr=enc_nr;
									OPEN enc_dt_cur;
									FETCH enc_dt_cur INTO enc_date;
									INSERT INTO encounter_patient_medication SET
									patientid = pat_id_d,
									encounter_nr = enc_nr,
									medications= med_d,
									delete_status='n',
									ACTION=act_d,
									dose=dose_d,
									dose_strength=dos_st_d,
									generic_name=gen_n_d,
									dose_unit=dos_un_d,
									quantity=quan_d,
									quantity_unit=quan_un_d,
									duration=dur_d,
									rout=rout_d,
									dose_timming=dos_tim_d,
									dose_others=dose_oth_d,
									refills=refl_d,
									substitution_permitted=subs_d,
									NDCID=NDC_d,
									RxnormID=Rxid_d,
									medication_external_id=med_ext_d,
									SCHEDULE=sch_d,
									other_notes=oth_name_d,
									commentes_office_only=off_only_d,
									stopreason=st_reas_d,
									fill_date=fl_date_d,
									start_date=str_date_d,
									`type`='Past Medication',
									reviewed_date=enc_date,
									stop_date=stp_date_d,
									created_by=cr_by_d,
									created_date=cr_date_d,
									source=src_d;
									CLOSE enc_dt_cur;
								END block_cursor;
							END IF;
							IF v_finished = 1 THEN LEAVE med_loop; END IF;
						END LOOP med_loop;
					CLOSE dpm_cur;
				END;
			END IF;
	CLOSE epm_cur;
END */$$
DELIMITER ;

