/* Procedure structure for procedure `MRA_01_Cal_EncHccScore_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_01_Cal_EncHccScore_01`()
BEGIN

DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;
DECLARE mrw CURSOR FOR SELECT t1.encounter_nr FROM cclf_encounter t1 WHERE t1.mra_proc_type_nr in (1,2) and t1.encounter_date>='2021-01-01' AND (t1.hcc_score IS NULL or t1.hcc_score=0) ORDER BY t1.entry_nr DESC;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00;
 IF bmc = 0 THEN
  call MRA_01_Cal_EncHccScore_11(qArg00);
 END IF;
END LOOP;
CLOSE mrw;

UPDATE mra1_encounter_icd_codes t1 INNER JOIN cclf_encounter_icd_codes t2 ON 
 t1.mm_imp_ref_num=t2.id and t1.encounter_nr=t2.encounter_nr AND t1.diagnosis_code=t2.diagnosis_code
SET t1.hcc_score=t2.hcc_score,t1.hcc_level=t2.hcc_level,t1.hcc_inc=t2.hcc_inc;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_01_Cal_EncHccScore_11` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_01_Cal_EncHccScore_11`(mpp1 BIGINT)
BEGIN

DECLARE bmc INT DEFAULT 0; DECLARE vtmp TEXT; DECLARE v2tmp TEXT; 
DECLARE mv1tmp VARCHAR(50);DECLARE mv2tmp VARCHAR(50);

DECLARE mHccLevel INT; DECLARE mHccScore DOUBLE(20,4);
DECLARE mCommNonDualAged DOUBLE(20,4); DECLARE mCommNonDualDis DOUBLE(20,4);
DECLARE mCommFbDualAged DOUBLE(20,4); DECLARE mCommFbDualDis DOUBLE(20,4);
DECLARE mCommPbDualAged DOUBLE(20,4); DECLARE mCommPbDualDis DOUBLE(20,4);

DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);
DECLARE mrw CURSOR FOR SELECT id,patient_id,diagnosis_code FROM cclf_encounter_icd_codes WHERE encounter_nr=mpp1 GROUP BY diagnosis_code;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

UPDATE cclf_encounter_icd_codes SET hcc_score=0,hcc_level=0,hcc_inc=0 WHERE encounter_nr=mpp1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02;

 IF bmc = 0 THEN

 SET mHccScore=0; SET mHccLevel=0; SET mCommFbDualDis=0;SET mCommPbDualAged=0;
 SET mCommPbDualDis=0;SET mCommNonDualAged=0;SET mCommNonDualDis=0;SET mCommFbDualAged=0;

 SET vtmp = (SELECT CONCAT(BENE_MDCR_STUS_CD,'!@#',BENE_DUAL_STUS_CD) FROM mra_file_static.mra_cclf8 WHERE BENE_MBI_ID = qArg01 ORDER BY nr DESC LIMIT 1);
 IF vtmp IS NOT NULL THEN
  SET mv1tmp=SUBSTRING_INDEX(vtmp,'!@#',1); SET mv2tmp=SUBSTRING_INDEX(vtmp,'!@#',-1);
 END IF;
 
 SET vtmp = (SELECT CONCAT(hcc_nr,'!@#',community_nondual_aged,'!@#',community_nondual_disabled,'!@#',community_fbdual_aged,'!@#',community_fbdual_disabled,'!@#',community_pbdual_aged,'!@#',community_pbdual_disabled) FROM bt_static.mra_hcc_coefficients WHERE diagnosis_code=qArg02 ORDER BY nr DESC LIMIT 1);
 IF vtmp IS NOT NULL THEN
  SET mHccLevel=SUBSTRING_INDEX(vtmp,'!@#',1); SET mCommPbDualDis=SUBSTRING_INDEX(vtmp,'!@#',-1);
  SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',2); SET mCommNonDualAged=SUBSTRING_INDEX(v2tmp,'!@#',-1);
  SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',3); SET mCommNonDualDis=SUBSTRING_INDEX(v2tmp,'!@#',-1);
  SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',4); SET mCommFbDualAged=SUBSTRING_INDEX(v2tmp,'!@#',-1);
  SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',5); SET mCommFbDualDis=SUBSTRING_INDEX(v2tmp,'!@#',-1);
  SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',6); SET mCommPbDualAged=SUBSTRING_INDEX(v2tmp,'!@#',-1);
 END IF;

 SET mHccScore=mCommNonDualAged;
 IF (mv1tmp="20" OR mv1tmp="21") THEN
  SET mHccScore=mCommNonDualDis;
  IF (mv2tmp="02" OR mv2tmp="04" OR mv2tmp="08") THEN
   SET mHccScore=mCommFbDualDis;
  ELSEIF (mv2tmp="01" OR mv2tmp="03" OR mv2tmp="05" OR mv2tmp="06") THEN
   SET mHccScore=mCommPbDualDis;
  END IF;
 ELSE
  IF (mv2tmp="02" OR mv2tmp="04" OR mv2tmp="08") THEN
   SET mHccScore=mCommFbDualAged;
  ELSEIF (mv2tmp="01" OR mv2tmp="03" OR mv2tmp="05" OR mv2tmp="06") THEN
   SET mHccScore=mCommPbDualAged;
  END IF;
 END IF;

 UPDATE cclf_encounter_icd_codes SET hcc_score=mHccScore,hcc_level=mHccLevel,hcc_inc=1 WHERE id=qArg00;

 END IF;
END LOOP;
CLOSE mrw;


 mBLOCK_01: BEGIN
DECLARE bmc INT DEFAULT 0;DECLARE qArg01 VARCHAR(200); DECLARE vtmp VARCHAR(100);
DECLARE mrw CURSOR FOR SELECT hcc_level FROM cclf_encounter_icd_codes WHERE encounter_nr=mpp1 AND hcc_inc=1 ORDER BY hcc_level;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01;
 IF bmc = 0 THEN

 SET vtmp = (SELECT m2_hcc_nr FROM bt_static.mra_config_d01_diagdropoff WHERE m1_hcc_nr = qArg01 ORDER BY nr DESC LIMIT 1);
 IF vtmp IS NOT NULL THEN
  UPDATE cclf_encounter_icd_codes SET hcc_inc=0 WHERE encounter_nr=mpp1 AND hcc_level IN (SELECT m2_hcc_nr FROM bt_static.mra_config_d01_diagdropoff WHERE m1_hcc_nr = qArg01);
 END IF;

 END IF;
END LOOP;
CLOSE mrw; 
 END mBLOCK_01;

 mBLOCK_02: BEGIN
  DECLARE bmc INT DEFAULT 0; DECLARE qArg01 DOUBLE(20,4);
  DECLARE mrw CURSOR FOR SELECT hcc_score FROM cclf_encounter_icd_codes WHERE encounter_nr = mpp1 AND hcc_score>0 AND hcc_inc=1 GROUP BY hcc_level;
  DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
  SET mHccScore =0;
  OPEN mrw;
  read_loop: LOOP
  IF bmc = 1 THEN LEAVE read_loop; END IF;
  FETCH mrw INTO qArg01;
   IF bmc = 0 THEN
    SET mHccScore= mHccScore + qArg01;
   END IF;
  END LOOP;
  CLOSE mrw;
  UPDATE cclf_encounter SET hcc_score=mHccScore WHERE encounter_nr=mpp1; 
 END mBLOCK_02;
 INSERT INTO mra_00_tmp SET mdd_1='MRA_Cal_EncHccScore_11',mdd_2=mpp1,mdd_3=1;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_ADT_E01_EncMapping_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_ADT_E01_EncMapping_01`(mpp1 VARCHAR(30))
BEGIN

DECLARE vtmp TEXT;DECLARE v2tmp TEXT; DECLARE mvTaxnmy VARCHAR(100);
DECLARE mv01 VARCHAR(30);DECLARE mv02 VARCHAR(20);DECLARE mv03 VARCHAR(10);DECLARE mv04 tinyint;

INSERT INTO adt_encounter_logger SET encounter_nr=mpp1,log_info='Encounter ADT_E01_EncMapping_01 : START',created_date=NOW(); 

SET vtmp=(SELECT CONCAT(IF(encounter_status IS NULL,'',encounter_status),'!@#',IF(align_status_code IS NULL,'',align_status_code),'!@#',IF(pos_curr IS NULL,'',pos_curr),'!@#',IF(encounter_class_nr IS NULL,'',encounter_class_nr),'!@#',IF(taxonomy IS NULL,'',taxonomy)) FROM adt_encounter WHERE encounter_nr=mpp1 LIMIT 1);

IF vtmp IS NOT NULL THEN
 SET mv01=SUBSTRING_INDEX(vtmp,'!@#',1); SET mvTaxnmy=SUBSTRING_INDEX(vtmp,'!@#',-1);
 SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',2); SET mv02=SUBSTRING_INDEX(v2tmp,'!@#',-1);
 SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',3); SET mv03=SUBSTRING_INDEX(v2tmp,'!@#',-1);
 SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',4); SET mv04=SUBSTRING_INDEX(v2tmp,'!@#',-1);
END IF; 

IF mv01 NOT IN ('cancelled','duplicate','delete', 'inactive') AND mv02 IN ('AL') and mv04=4 THEN

 IF mv03 IN (21,60,61) AND mvTaxnmy IN ('282N00000X','282NC0060X','282NR1301X','282NC2000X','284300000X') THEN
  UPDATE adt_encounter SET enc_proc_type='Acute Hospital' WHERE encounter_nr=mpp1;
 ELSEIF mv03 IN (21,60,61) AND mvTaxnmy IN ('261QR0400X','283X00000X','261QR0401X','273Y00000X','2081P2900X','208100000X','283XC2000X','261QR0404X','111NR0400X','225400000X') THEN
  UPDATE adt_encounter SET enc_proc_type='Rehabilitation' WHERE encounter_nr=mpp1;
 ELSEIF mv03 IN (21,60,61) AND mvTaxnmy IN ('251E00000X','253Z00000X','374U00000X','251F00000X') THEN
  UPDATE adt_encounter SET enc_proc_type='HHA' WHERE encounter_nr=mpp1;
 ELSEIF mv03 IN (21,60,61) AND mvTaxnmy IN ('251G00000X') THEN
  UPDATE adt_encounter SET enc_proc_type='Hospice' WHERE encounter_nr=mpp1;
 ELSEIF mv03 IN (21,60,61) AND mvTaxnmy IN ('314000000X') THEN
  UPDATE adt_encounter SET enc_proc_type='SNF' WHERE encounter_nr=mpp1;
 ELSEIF mv03 IN (23) THEN
  UPDATE adt_encounter SET enc_proc_type='Emergency' WHERE encounter_nr=mpp1;
 ELSEIF mv03 IN (22) THEN
  UPDATE adt_encounter SET enc_proc_type='OutPatient' WHERE encounter_nr=mpp1;
 ELSEIF mv03 IN (24) THEN
  UPDATE adt_encounter SET enc_proc_type='Observation' WHERE encounter_nr=mpp1;
 ELSEIF mv03="-99" THEN
  UPDATE adt_encounter SET enc_proc_type='IP-PREADMIT' WHERE encounter_nr=mpp1; 
 END IF;

 UPDATE adt_encounter t1 INNER JOIN adt_appointment t2 ON t2.encounter_nr=t1.encounter_nr INNER JOIN personell_hosp_assocs t3 ON t3.hospital_nr=t1.dce_group_nr AND t3.user_nr=t2.to_personell_nr 
	SET t1.is_visit_pcp=1
 WHERE t1.encounter_nr=mpp1 AND t1.is_visit_pcp IS NULL;

END IF;

INSERT INTO adt_encounter_logger SET encounter_nr=mpp1,log_info='Encounter ADT_E01_EncMapping_01 : END',created_date=NOW(); 

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_ADT_E02_EncMapping_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_ADT_E02_EncMapping_01`(mpp1 VARCHAR(30))
BEGIN

UPDATE adt_encounter SET market_id='14' WHERE market_id=0 OR market_id IS NULL;
UPDATE adt_encounter SET market_name='Unassigned Market' WHERE market_id=14 OR market_name IS NULL OR market_name='';

UPDATE adt_encounter SET dce_group_name='UNK' WHERE dce_group_nr=0 OR dce_group_nr IS NULL OR dce_group_name IS NULL OR dce_group_name='';
UPDATE adt_encounter SET dce_group_sub_name='No Sub Group' WHERE dce_group_sub_nr=0 OR dce_group_sub_nr IS NULL OR dce_group_sub_name IS NULL OR dce_group_sub_name='';
UPDATE adt_encounter SET dce_provider_name='UNK' WHERE dce_prov_npi_nr=0 OR dce_prov_npi_nr IS NULL OR dce_provider_name IS NULL OR dce_provider_name='';

UPDATE adt_encounter SET dce_prov_npi_nr='XXXX' WHERE dce_prov_npi_nr=0 OR dce_prov_npi_nr IS NULL;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_ADT_GroupMapping_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_ADT_GroupMapping_01`(mpp1 INT)
BEGIN

DECLARE vtmp VARCHAR(1000); DECLARE m_year INT; DECLARE m_month INT; DECLARE m2year INT;
DECLARE m1MarketNr INT; DECLARE ptFacilityNr VARCHAR(100); DECLARE ptFacilitySubNr VARCHAR(100); DECLARE ptProviderNum VARCHAR(100); DECLARE ptProviderName VARCHAR(100); DECLARE m1GroupName VARCHAR(300); DECLARE m1GroupSubName VARCHAR(300); DECLARE m1MarketName VARCHAR(100);

/*

DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg1 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);
DECLARE mrw CURSOR FOR SELECT entry_nr,origid,encounter_date,discharge_date FROM adt_encounter WHERE year(discharge_date)>=mpp1;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP

 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg1,qArg2,qArg3;
 IF bmc = 0 THEN
  
  SET ptFacilityNr='0';SET ptFacilitySubNr='0';SET ptProviderNum='';SET ptProviderName='';
  set m_year=YEAR(qArg2); SET m_month=month(qArg2); SET m2year=YEAR(qArg3);

  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_bene_alignment_roster WHERE mm_curr_mbi_id=qArg1 AND mm_year=m_year AND mm_month=m_month ORDER BY cc_version DESC LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET ptFacilitySubNr=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(ptFacilitySubNr,'!@#',-1);
  END IF;

IF ptFacilityNr='' OR ptFacilityNr='0' THEN   
  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_bene_alignment_roster WHERE mm_curr_mbi_id=qArg1 AND mm_year=m_year AND mm_month<=m_month ORDER BY cc_version DESC LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET ptFacilitySubNr=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(ptFacilitySubNr,'!@#',-1);
  END IF;
END IF;
 
IF ptFacilityNr='' OR ptFacilityNr='0' THEN 
  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_bene_alignment_roster WHERE mm_curr_mbi_id=qArg1 AND mm_year<=m2year order by cc_version desc LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET ptFacilitySubNr=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(ptFacilitySubNr,'!@#',-1);
  END IF;
END IF;

IF ptFacilityNr='' OR ptFacilityNr='0' THEN 
  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_bene_alignment_roster WHERE mm_curr_mbi_id=qArg1 ORDER BY cc_version DESC LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET ptFacilitySubNr=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(ptFacilitySubNr,'!@#',-1);
  END IF;
END IF;
IF ptFacilityNr='' OR ptFacilityNr='0' THEN
  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_quater_alignment WHERE mm_curr_mbi_id=qArg1 AND qArg2 BETWEEN m_start_date AND m_end_date LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET ptFacilitySubNr=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(ptFacilitySubNr,'!@#',-1);
  END IF;
END IF;
IF ptFacilityNr='' OR ptFacilityNr='0' THEN 
  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_quater_alignment WHERE mm_curr_mbi_id=qArg1 ORDER BY cc_version DESC LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET ptFacilitySubNr=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(ptFacilitySubNr,'!@#',-1);
  END IF;
END IF;

 SET vtmp=(SELECT `name` FROM personell WHERE is_dce=1 and npr_id=ptProviderNum LIMIT 1);
 IF vtmp IS NOT NULL THEN SET ptProviderName=vtmp; END IF;
 SET m1GroupName = (SELECT `name` FROM hospital_centers WHERE nr=ptFacilityNr LIMIT 1);
 SET m1GroupSubName = (SELECT `name` FROM hospital_centers WHERE nr=ptFacilitySubNr LIMIT 1);
 SET m1MarketNr = (SELECT market_id FROM hospital_market_assocs WHERE hosp_id=ptFacilityNr LIMIT 1);
 SET m1MarketName = (SELECT `market_name` FROM hospital_market WHERE market_id=m1MarketNr LIMIT 1);

 update adt_encounter SET market_id=m1MarketNr,dce_group_name=m1GroupName,dce_group_nr=ptFacilityNr,dce_group_sub_nr=ptFacilitySubNr,dce_prov_npi_nr=ptProviderNum,dce_provider_name=ptProviderName,market_name=m1MarketName,dce_group_sub_name=m1GroupSubName where entry_nr=qArg00;

 INSERT INTO mra_00_tmp SET mdd_1=mpp1,mdd_2=qArg00,mdd_3=qArg1;

END IF;
END LOOP;
CLOSE mrw;
*/

END */$$
