/* Procedure structure for procedure `MRA_ADT_V41_TempData_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_ADT_V41_TempData_01`()
BEGIN

/*
 UPDATE adt_encounter AS a
JOIN (
    SELECT
        encounter_nr,
        CASE
            WHEN ExtractDate(comments) IS NOT NULL THEN STR_TO_DATE(ExtractDate(comments),'%m/%d/%Y')
            WHEN CONCAT(
                LEFT(encounter_nr, 4), '-', 
                LPAD(MONTH(
                    COALESCE(
                        STR_TO_DATE(SUBSTRING_INDEX(comments, '@', 1), '%m/%d/%y'),
                        STR_TO_DATE(SUBSTRING_INDEX(SUBSTRING_INDEX(comments, '@', 1), ' ', -1), '%m/%d/%Y'),
                        STR_TO_DATE(SUBSTRING_INDEX(SUBSTRING_INDEX(comments, '-', 1), ' ', -1), '%m/%d/%Y'),
                        STR_TO_DATE(SUBSTRING_INDEX(SUBSTRING_INDEX(comments, 'at', 1), ' ', -1), '%m/%d/%Y'),
                        STR_TO_DATE(SUBSTRING_INDEX(SUBSTRING_INDEX(comments, '@', 1), ' ', -1), '%c/%e/%y')
                    )
                ), 2, '0'), '-', 
                LPAD(DAY(
                    COALESCE(
                        STR_TO_DATE(SUBSTRING_INDEX(SUBSTRING_INDEX(comments, '@', 1), ' ', -1), '%m/%d/%Y'),
                        STR_TO_DATE(SUBSTRING_INDEX(SUBSTRING_INDEX(comments, '-', 1), ' ', -1), '%m/%d/%Y'),
                        STR_TO_DATE(SUBSTRING_INDEX(SUBSTRING_INDEX(comments, 'at', 1), ' ', -1), '%m/%d/%Y'),
                        STR_TO_DATE(SUBSTRING_INDEX(SUBSTRING_INDEX(comments, '@', 1), ' ', -1), '%c/%e/%y')
                    )
                ), 2, '0')
            ) IS NOT NULL
            THEN CONCAT(
                LEFT(encounter_nr, 4), '-', 
                LPAD(MONTH(
                    COALESCE(
                        STR_TO_DATE(SUBSTRING_INDEX(comments, '@', 1), '%m/%d/%y'),
                        STR_TO_DATE(SUBSTRING_INDEX(SUBSTRING_INDEX(comments, '@', 1), ' ', -1), '%m/%d/%Y'),
                        STR_TO_DATE(SUBSTRING_INDEX(SUBSTRING_INDEX(comments, '-', 1), ' ', -1), '%m/%d/%Y')
                    )
                ), 2, '0'), '-', 
                LPAD(DAY(
                    COALESCE(
                        STR_TO_DATE(SUBSTRING_INDEX(SUBSTRING_INDEX(comments, '@', 1), ' ', -1), '%m/%d/%Y')
                    )
                ), 2, '0')
            )
            ELSE NULL
        END AS followup_date
    FROM procedure_history_data
    WHERE history_nr = 111555
    AND history_value = 'Yes'
) AS p ON a.encounter_nr = p.encounter_nr
SET a.followup_date = p.followup_date
WHERE p.followup_date IS NOT NULL;
 */
 
 UPDATE adt_encounter SET followup_date='0000-00-00' WHERE  followup_date IS NOT NULL
    AND (
        followup_date < '1900-01-01' 
        OR followup_date > '2024-12-31'
        OR followup_date LIKE '____-00-__'  -- Year is valid, but month is zero
        OR followup_date LIKE '____-__-00'  -- Year and month are valid, but day is zero
        OR followup_date LIKE '%-%-%-%'      -- Handles cases like '0202-04-08' or '0221-08-02'
    );

UPDATE adt_encounter SET followup_date=NULL WHERE followup_date='0000-00-00';
END */$$
