/* Procedure structure for procedure `MRA_IMP14_C21ENC01_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP14_C21ENC01_m3`(mpp1 SMALLINT,mpp2 BIGINT,mpp3 VARCHAR(100),mpp4 SMALLINT)
BEGIN

DECLARE _rollback BOOL DEFAULT 0; DECLARE m1i INT DEFAULT 0;

DECLARE vtmp VARCHAR(1000); DECLARE m_enc_nr BIGINT;
DECLARE m_year INT; DECLARE m_month INT;

DECLARE msgVR01 VARCHAR(100);DECLARE msgVR02 VARCHAR(200);

DECLARE m1vv VARCHAR(300);DECLARE m2vv VARCHAR(300);
DECLARE mMBI_IDNEW VARCHAR(100);

DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 SMALLINT;DECLARE qArg02 SMALLINT;DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(100);DECLARE qArg06 VARCHAR(100);DECLARE qArg07 VARCHAR(100);DECLARE qArg08 VARCHAR(100);DECLARE qArg09 VARCHAR(100);DECLARE qArg10 VARCHAR(100);DECLARE qArg11 VARCHAR(100);DECLARE qArg12 VARCHAR(100);DECLARE qArg13 VARCHAR(100);DECLARE qArg14 VARCHAR(100);DECLARE qArg15 VARCHAR(30);DECLARE qArg16 VARCHAR(8);DECLARE qArg17 VARCHAR(200);DECLARE qArg18 VARCHAR(20);DECLARE qArg19 VARCHAR(20);DECLARE att_PRVDR_NPI_NUM VARCHAR(20);DECLARE qArg21 VARCHAR(20);DECLARE qArg22 VARCHAR(20);DECLARE qArg23 VARCHAR(20);DECLARE qArg24 VARCHAR(20);DECLARE qArg25 VARCHAR(20);DECLARE qArg26 VARCHAR(20);DECLARE qArg27 VARCHAR(20);DECLARE qArg28 VARCHAR(30);DECLARE qArg29 VARCHAR(200);DECLARE clmIPadmsn_type_cd VARCHAR(30);DECLARE qArg31 VARCHAR(200);DECLARE qArg32 VARCHAR(30);DECLARE qArg33 VARCHAR(30);DECLARE qArg34 VARCHAR(30);DECLARE qArg35 VARCHAR(30);DECLARE qArg36 VARCHAR(200);DECLARE qArg37 VARCHAR(30);DECLARE qArg38 VARCHAR(200);DECLARE qArg39 VARCHAR(30);DECLARE fiClm_actn_nm VARCHAR(200);DECLARE qArg41 VARCHAR(30);DECLARE qArg42 VARCHAR(30);

DECLARE mrw CURSOR FOR SELECT t1.nr,t1.clm_type_nr,t1.proc_type_nr,t1.BENE_MBI_ID,t1.CLM_FROM_DT,t1.CLM_THRU_DT,t1.FAC_PRVDR_NPI_NUM,t1.rendering_PRVDR_NPI_NUM,t1.CUR_CLM_UNIQ_ID,t1.CLM_CNTL_NUM,t1.CLM_PMT_AMT,t1.CLM_POS_CD,t1.rendering_PRVDR_SPLTY_CD,t1.CLM_ADJSMT_TYPE_CD,t1.mm_imp_job_nr,t1.PRVDR_OSCAR_NUM,t1.CLM_TYPE_CD,t1.FAC_PRVDR_Name,t1.primary_PRVDR_NPI_NUM,t1.primary_PRVDR_SPLTY_CD,t1.attending_PRVDR_NPI_NUM,t1.attending_PRVDR_SPLTY_CD,t1.referring_PRVDR_NPI_NUM,t1.referring_PRVDR_SPLTY_CD,t1.operating_PRVDR_NPI_NUM,t1.operating_PRVDR_SPLTY_CD,t1.otheroperating_PRVDR_NPI_NUM,t1.otheroperating_PRVDR_SPLTY_CD,t1.pat_status_ind_code,t1.pat_status_ind_nm,t1.clm_ip_admsn_type_cd,t1.clm_ip_admsn_type_nm,t1.clm_src_ip_admsn_cd,t1.clm_drg_cd,t1.clm_freq_cd,t1.discharge_status_cd,t1.discharge_status_nm,t1.nch_line_ident_cd,t1.nch_line_ident_nm,t1.fi_clm_actn_cd,t1.fi_clm_actn_nm,t1.clm_srvc_clsfctn_type_cd,t1.fi_num,t2.mdd_3 FROM mra_file_static.mra_bcda3_enc_1m t1 INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=t1.BENE_MBI_ID WHERE t2.mdd_2=mpp1 AND t1.map_data_status=5 AND t1.map_process_status=1 AND t1.CLM_FROM_DT>='2025-01-01' ORDER BY t1.clm_type_nr,t1.BENE_MBI_ID,t1.mm_imp_job_nr;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
BEGIN
 SET _rollback = 1;
 GET DIAGNOSTICS CONDITION 1
 msgVR01 = RETURNED_SQLSTATE, msgVR02 = MESSAGE_TEXT;
END;

INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='m01Call',mdd_3=CONCAT('c2-',mpp1);

CREATE TEMPORARY  TABLE `mra4_enc2keys` (
  `encounter_nr` BIGINT UNSIGNED NOT NULL,  `patient_id` VARCHAR(64) NOT NULL,
  `enc_admit_date` DATE NULL,  `clm_type_nr` SMALLINT DEFAULT '0',
  `proc_type_nr` SMALLINT NOT NULL DEFAULT '0',  `m_provider_npi` VARCHAR(20) DEFAULT NULL,
  `CLM_TYPE_CD` VARCHAR(10) DEFAULT NULL,  `PRVDR_OSCAR_NUM` VARCHAR(20) DEFAULT NULL,
  KEY `mkey01` (`proc_type_nr`),  KEY `mkey02` (`CLM_TYPE_CD`),  KEY `mkey03` (`clm_type_nr`),
  KEY `mkey04` (`m_provider_npi`),  KEY `mkey05` (`patient_id`),  KEY `mkey06` (`enc_admit_date`)
) ENGINE=INNODB DEFAULT CHARSET=latin1;

INSERT INTO mra4_enc2keys (encounter_nr,patient_id,enc_admit_date,clm_type_nr,proc_type_nr,m_provider_npi,CLM_TYPE_CD,PRVDR_OSCAR_NUM)
SELECT t1.encounter_nr,t1.patient_id,t1.enc_admit_date,t1.clm_type_nr,t1.proc_type_nr,t1.m_provider_npi,t1.CLM_TYPE_CD,t1.PRVDR_OSCAR_NUM FROM mra4_encounter t1 INNER JOIN mra1_311_m1 t2 ON t2.mdd_3=t1.patient_id WHERE t2.mdd_2=mpp1;


SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
START TRANSACTION;

SET @mg1vv=0; SET @mg2vv=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05,qArg06,qArg07,qArg08,qArg09,qArg10,qArg11,qArg12,qArg13,qArg14,qArg15,qArg16,qArg17,qArg18,qArg19,att_PRVDR_NPI_NUM,qArg21,qArg22,qArg23,qArg24,qArg25,qArg26,qArg27,qArg28,qArg29,clmIPadmsn_type_cd,qArg31,qArg32,qArg33,qArg34,qArg35,qArg36,qArg37,qArg38,qArg39,fiClm_actn_nm,qArg41,qArg42,mMBI_IDNEW;
 
 IF bmc = 0 THEN

 IF mMBI_IDNEW IS NULL THEN SET mMBI_IDNEW=qArg03; END IF;

 IF qArg02=1 THEN
  SET m_enc_nr=(SELECT encounter_nr FROM mra4_enc2keys WHERE clm_type_nr=qArg01 AND proc_type_nr=qArg02 AND patient_id=mMBI_IDNEW AND enc_admit_date=qArg04 AND PRVDR_OSCAR_NUM=qArg15 AND CLM_TYPE_CD=qArg16 LIMIT 1);
 ELSEIF qArg01=1 THEN
   SET m_enc_nr=(SELECT encounter_nr FROM mra4_enc2keys WHERE clm_type_nr=qArg01 AND proc_type_nr=qArg02 AND patient_id=mMBI_IDNEW AND enc_admit_date=qArg04 AND m_provider_npi=qArg07 AND CLM_TYPE_CD=qArg16 LIMIT 1);
 ELSE
   SET m_enc_nr=(SELECT encounter_nr FROM mra4_enc2keys WHERE clm_type_nr=qArg01 AND proc_type_nr=qArg02 AND patient_id=mMBI_IDNEW AND enc_admit_date=qArg04 AND CLM_TYPE_CD=qArg16 LIMIT 1);  
 END IF;

 IF m_enc_nr=0 OR m_enc_nr IS NULL THEN

  SET m1vv=qArg10;SET m2vv=0;
  IF qArg01=2 THEN SET m1vv=0;SET m2vv=qArg10; END IF;

