  CALL MRA_IMP14_C21ENC11_CPT_m3(1,qArg00,mMBI_IDNEW); CALL MRA_IMP14_C21ENC12_ICD_m3(1,qArg00,mMBI_IDNEW);
  
 END IF;

  INSERT INTO mra4_encounter_logs SET mcreate_id='system',map_data_src=1,encounter_nr=qArg00,patient_id=mMBI_IDNEW,proc_type_nr=qArg02,m_notes=qArg01,mSrcInserted_Type='mra_bcda3_enc_1m',mSrcInserted_ID=qArg00,mm_imp_job_nr=qArg14;

  UPDATE mra_file_static.mra_bcda3_enc_1m SET map_data_status=1 where nr=qArg00;

