INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='END',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00;
