/*!50003 CREATE PROCEDURE `MRA_IMP14_C21ENC11_CPT_m3`(mpp1 smallINT,mpp2 bigint,mpp3 VARCHAR(100))
BEGIN

DECLARE _rollback BOOL DEFAULT 0;
DECLARE vtmp VARCHAR(100); DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 VARCHAR(100);DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(100);DECLARE qArg06 VARCHAR(20);DECLARE qArg07 VARCHAR(300);DECLARE qArg08 VARCHAR(50);DECLARE qArg09 VARCHAR(50);DECLARE qArg10 VARCHAR(300);DECLARE qArg11 VARCHAR(50);DECLARE qArg12 VARCHAR(50);DECLARE qArg13 VARCHAR(30);

DECLARE mrw CURSOR FOR SELECT nr,CLM_LINE_HCPCS_CD,HCPCS_1_MDFR_CD,CLM_LINE_CVRD_PD_AMT,CLM_LINE_NUM,CLM_LINE_SRVC_UNIT_QTY,CLM_LINE_PROD_REV_CTR_CD,CLM_LINE_PROD_REV_NM,CLM_LINE_Charge_AMT,CLM_POS_CD,CLM_POS_NM,line_cms_type_srvc_cd,carr_line_clia_lab_num,mm_imp_job_nr FROM mra_file_static.mra_bcda3_enc_cpt WHERE m_nr=mpp2;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION SET _rollback = 1;

START TRANSACTION;

if mpp1=1 then DELETE FROM mra4_encounter_bill_cpts WHERE encounter_nr=mpp2; end if;

OPEN mrw;
read_loop: LOOP

 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05,qArg06,qArg07,qArg08,qArg09,qArg10,qArg11,qArg12,qArg13;
 IF bmc = 0 THEN
  INSERT INTO mra4_encounter_bill_cpts SET mm_imp_ref_num=qArg00,mcreate_datetime=NOW(),mra_enc_nr=mpp1,encounter_nr=mpp2,patient_id=mpp3,bb_Code=qArg01,bb_Type=1,bb_modifier=qArg02,bb_count=qArg05,bb_order_num=qArg04,CLM_LINE_PROD_REV_CTR_CD=qArg06,cal_amount=qArg03,cal2amount=0,cal3amount=qArg08,CLM_LINE_PROD_REV_NM=qArg07,CLM_POS_CD=qArg09,CLM_POS_NM=qArg10,line_cms_type_srvc_cd=qArg11,carr_line_clia_lab_num=qArg12,mm_imp_job_nr=qArg13;
 END IF;
 
END LOOP;
CLOSE mrw;

COMMIT;

IF `_rollback` THEN
 INSERT INTO mra4_01_tmp SET mdd_1='MRAIMP4_M1ENC_03',mdd_2='Error-Cpt',mdd_3=concat(mpp1,'-',mpp2),mdd_4=RETURNED_SQLSTATE,mdd_5=MESSAGE_TEXT;
END IF;

END */$$
