DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP14_C30_START_m3`(m1pp tinyINT)
BEGIN

 DECLARE mCnt INT;

 if m1pp=1 then 
  INSERT INTO mra4_01_tmp SET mdd_1='MRAIMP14_C31_k3',mdd_2='START';
  CALL MRA_IMP14_C31ENC01_k3(20); INSERT INTO mra4_01_tmp SET mdd_1='MRAIMP14_C31_m3',mdd_2='m-4031';
  CALL MRA_IMP1_M03ENC31_m31_m3(4031); CALL MRA_IMP1_M03ENC31_m12_ToCheck_m3();
  INSERT INTO mra4_01_tmp SET mdd_1='MRAIMP14_C31_m3',mdd_2='END';
 elseif m1pp=2 then 
  SET mCnt=(SELECT COUNT(entry_nr) AS mcc FROM mra4_encounter WHERE m4_map_status=0 AND enc_admit_date>='2025-01-01');
  IF mCnt>0 THEN
   INSERT INTO mra4_01_tmp SET mdd_1='MRAIMP14_C32_k3',mdd_2='START',mdd_3=mCnt;
   CALL MRA_IMP14_C32ENC01_k3(20); INSERT INTO mra4_01_tmp SET mdd_1='MRAIMP14_C32_m3',mdd_2='m-4032';
   CALL MRA_IMP1_M03ENC31_m31_m3(4032); CALL MRA_IMP1_M03ENC31_m12_ToCheck_m3();
   INSERT INTO mra4_01_tmp SET mdd_1='MRAIMP14_C32_m3',mdd_2='END';
  ELSE 
   INSERT INTO mra4_01_tmp SET mdd_1='IMP14_C32_START_m3',mdd_2='SKIP',mdd_3=mCnt;
  END IF;
 end if;

END */$$
