/* Procedure structure for procedure `MRA_IMP14_C31ENC01_k3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP14_C31ENC01_k3`(m1pp tinyINT)
BEGIN

DECLARE mmi INT; DECLARE m2mi INT; DECLARE m3mi INT;
DECLARE vtmp VARCHAR(100); 

TRUNCATE mra1_311_m1;
INSERT INTO mra1_311_m1 (mdd_1,mdd_2,mdd_3)
SELECT DISTINCT patient_id,1,'mra14_c31enc' FROM mra4_encounter WHERE enc_admit_date>='2025-01-01';

SET m3mi=(SELECT COUNT(mdd_1) FROM mra1_311_m1); SET m3mi=CEIL(m3mi/m1pp);
SET mmi=1;

LOOP_M01: LOOP
 SET m2mi= ((mmi-1)*m3mi ) +1;
 UPDATE mra1_311_m1 SET mdd_2=mmi WHERE nr BETWEEN m2mi AND (m2mi+(m3mi-1));
 IF mmi > m1pp THEN LEAVE  LOOP_M01; END IF;
 SET mmi = mmi + 1;
 ITERATE LOOP_M01;
END LOOP;

UPDATE mra1_311_m1 SET mdd_1='a123z' WHERE mdd_1='' OR mdd_1 IS NULL;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP14_C31ENC01_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP14_C31ENC01_m3`(mpp1 SMALLINT,mpp2 BIGINT,mpp3 VARCHAR(100),mpp4 SMALLINT)
BEGIN

DECLARE bmc INT DEFAULT 0;DECLARE _rollback TINYINT DEFAULT 0;DECLARE m1i INT DEFAULT 0;

DECLARE qArg00 BIGINT;DECLARE qArg01 BIGINT;

DECLARE mEncProcType VARCHAR(50);DECLARE msgVR01 VARCHAR(100);DECLARE msgVR02 VARCHAR(200);

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t1.encounter_nr FROM mra4_encounter t1 INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=t1.patient_id WHERE t1.enc_admit_date>='2025-01-01' AND t2.mdd_2=mpp1;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
BEGIN
 SET _rollback = 1;
 GET DIAGNOSTICS CONDITION 1
 msgVR01 = RETURNED_SQLSTATE, msgVR02 = MESSAGE_TEXT;
END;

INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='m01Call',mdd_3=CONCAT('c2-',mpp1);

SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
START TRANSACTION;

SET @mg1vv=0; SET @mg2vv=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01;
 IF bmc = 0 THEN

  /* ,is_72_hr_flwup=0,is_flwup_7_days=0,is_flwup_14_days=0,is_gflwup_14_days=0,m72hr_flwup_date=NULL, is_er_readmit=0,is_c2_readmit=0,pre_hospital_nr=0,pre_discharge_date=NULL,is_snf_rec=0,is_snf_admitdate_ref=NULL, pre_emr_hospital_name=NULL,pre_emr_discharge_date=NULL */ 

  UPDATE mra4_encounter SET modify_datetime=NOW(),is_enc_transfer=1,is_enc_ref_admitdate=enc_admit_date WHERE entry_nr=qArg00; 

  SET @mg2vv=qArg00; if m1i=0 then SET @mg1vv=qArg00; end if;
  INSERT INTO mra1_331_m1 SET mdd_1=mpp3,mdd_2='m02Call',mdd_5=mpp1,mdd_6=qArg00,mdd_7=m1i;
  SET m1i=m1i+1;

 END IF;
END LOOP;
CLOSE mrw;

COMMIT;

INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='END',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00;
IF `_rollback` THEN
 INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='ERROR',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00,mdd_4=msgVR01,mdd_5=msgVR02;
END IF;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP14_C32ENC01_k3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP14_C32ENC01_k3`(m1pp tinyINT)
BEGIN

DECLARE mmi INT; DECLARE m2mi INT; DECLARE m3mi INT;
DECLARE vtmp VARCHAR(100); 

TRUNCATE mra1_311_m1;
INSERT INTO mra1_311_m1 (mdd_1,mdd_2,mdd_3)
SELECT DISTINCT t1.patient_id,1,'mra14_enc' FROM mra4_encounter t1 WHERE t1.m4_map_status=0 AND t1.enc_admit_date>='2025-01-01';

SET m3mi=(SELECT COUNT(mdd_1) FROM mra1_311_m1); SET m3mi=CEIL(m3mi/m1pp);
SET mmi=1;

LOOP_M01: LOOP
 SET m2mi= ((mmi-1)*m3mi ) +1;
 UPDATE mra1_311_m1 SET mdd_2=mmi WHERE nr BETWEEN m2mi AND (m2mi+(m3mi-1));
 IF mmi > m1pp THEN LEAVE  LOOP_M01; END IF;
 SET mmi = mmi + 1;
 ITERATE LOOP_M01;
END LOOP;

UPDATE mra1_311_m1 SET mdd_1='a123z' WHERE mdd_1='' OR mdd_1 IS NULL;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP14_C32ENC01_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP14_C32ENC01_m3`(mpp1 SMALLINT,mpp2 BIGINT,mpp3 VARCHAR(100),mpp4 SMALLINT)
BEGIN

DECLARE bmc INT DEFAULT 0;DECLARE _rollback TINYINT DEFAULT 0;DECLARE m1i INT DEFAULT 0;

DECLARE qArg00 BIGINT;DECLARE qArg01 BIGINT; DECLARE qArg02 BIGINT; DECLARE qPatientID VARCHAR(100);DECLARE qProcTypeNr SMALLINT; DECLARE qEncPos VARCHAR(20); DECLARE qHosTaxonomy01 VARCHAR(50); DECLARE qAlignedStatus TINYINT;DECLARE qAligned2Status TINYINT; DECLARE qEncDischDate DATE;DECLARE qEncRefAdmitDate DATE; DECLARE qMproviderMr INT;
DECLARE qIsSnfRec tinyINT;

DECLARE mEncProcType VARCHAR(50);DECLARE msgVR01 VARCHAR(100);DECLARE msgVR02 VARCHAR(200);

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t1.encounter_nr,t1.pt_facility_nr,t1.patient_id,t1.proc_type_nr,t1.CLM_TYPE_CD,t1.pt_aligned_status,t1.pt_aligned2status,t1.enc_disch_date,t1.is_enc_ref_admitdate,t1.m_provider_nr,t1.is_snf_rec FROM mra4_encounter t1 INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=t1.patient_id WHERE t1.m4_map_status=0 AND t1.enc_admit_date>='2025-01-01' AND t2.mdd_2=mpp1;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
BEGIN
 SET _rollback = 1;
 GET DIAGNOSTICS CONDITION 1
 msgVR01 = RETURNED_SQLSTATE, msgVR02 = MESSAGE_TEXT;
END;

INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='m01Call',mdd_3=CONCAT('c2-',mpp1);

SET @mRosterVersion=(SELECT MAX(cc_version) as mcc FROM mra1_dcbeneroster);

CREATE TEMPORARY TABLE `dc_tm_align_rostr_m01`(`cc_version` INT,`mm_curr_mbi_id` VARCHAR(100),`mm_date` DATE,`ALIGN_STATUS_CODE` VARCHAR(10),  
KEY `mkey01` (`cc_version`),KEY `mkey02` (`mm_curr_mbi_id`),KEY `mkey03` (`mm_date`),KEY `mkey04` (`ALIGN_STATUS_CODE`))
ENGINE=INNODB DEFAULT CHARSET=latin1;

INSERT INTO dc_tm_align_rostr_m01 (cc_version,mm_curr_mbi_id,mm_date,ALIGN_STATUS_CODE)
SELECT t1.cc_version,t1.mm_curr_mbi_id,t1.mm_date,t1.ALIGN_STATUS_CODE FROM dc_bene_alignment_rostr_m01 AS t1
INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=t1.mm_curr_mbi_id
WHERE t1.cc_version =@mRosterVersion AND t2.mdd_2=mpp1;


SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
START TRANSACTION;

SET @mg1vv=0; SET @mg2vv=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qPatientID,qProcTypeNr,qEncPos,qAlignedStatus,qAligned2Status,qEncDischDate,qEncRefAdmitDate,qMproviderMr,qIsSnfRec;
 IF bmc = 0 THEN

  SET mEncProcType='UNK'; SET @mIsErVisit=0; SET @mIsVisitPcp=0; SET qIsSnfRec=0;
  
  UPDATE mra4_encounter t1 INNER JOIN adt_hosp_centers t2 ON t2.npi_id=t1.hc_npi_nr SET t1.hos_taxonomy01=t2.`mtaxonomy`,t1.hospital_nr=t2.`nr` WHERE t1.entry_nr=qArg00;  
  SET qHosTaxonomy01 = (SELECT t2.`mtaxonomy` FROM mra4_encounter t1 INNER JOIN adt_hosp_centers t2 ON t2.npi_id=t1.hc_npi_nr WHERE t1.entry_nr=qArg00 LIMIT 1);

  IF qProcTypeNr=1 AND qEncPos IN ('60','61') AND qHosTaxonomy01 IN ('282N00000X','282NC0060X','282NR1301X','282NC2000X','284300000X') THEN SET mEncProcType='Acute Hospital';
  ELSEIF qProcTypeNr=1 AND qEncPos IN ('60','61') AND qHosTaxonomy01 IN ('282E00000X') THEN SET mEncProcType='Long Term Care Hospital';
  ELSEIF qProcTypeNr=1 AND qEncPos IN ('60','61') AND qHosTaxonomy01 IN ('261QR0400X','283X00000X','261QR0401X','273Y00000X','2081P2900X','208100000X','283XC2000X','261QR0404X','111NR0400X','225400000X') THEN SET mEncProcType='Rehabilitation';
  ELSEIF qProcTypeNr=1 AND qEncPos IN ('60','61') AND qHosTaxonomy01 IN ('251E00000X','253Z00000X','374U00000X','251F00000X') THEN SET mEncProcType='HHA';
  ELSEIF qProcTypeNr=1 AND qEncPos IN ('60','61') AND qHosTaxonomy01 IN ('273R00000X','283Q00000X') THEN SET mEncProcType='Psychiatric';
  ELSEIF qProcTypeNr=1 AND qEncPos IN ('50') THEN SET mEncProcType='Hospice';
  ELSEIF qProcTypeNr=1 AND qEncPos IN ('20','30') THEN SET mEncProcType='SNF'; SET qIsSnfRec=1;
  ELSEIF qProcTypeNr=2 THEN SET mEncProcType='Part B';
  ELSEIF qProcTypeNr=3 THEN SET mEncProcType='Part DME';
  ELSEIF qProcTypeNr=4 THEN SET mEncProcType='Part D';
  END IF;  


  SET @mv2Val="update mra4_encounter SET m4_map_status=1";

mBLOCK_01: BEGIN
 DECLARE b2mc INT DEFAULT 0; DECLARE m2i INT;
 DECLARE q2Arg01 VARCHAR(100);DECLARE q2Arg02 VARCHAR(100);
 DECLARE m2rw CURSOR FOR SELECT bb_Code,cal_amount FROM mra4_encounter_bill_cpts WHERE encounter_nr=qArg01 ORDER BY cal_amount DESC LIMIT 10;
 DECLARE CONTINUE HANDLER FOR NOT FOUND SET b2mc = 1;
 SET m2i=0;
 OPEN m2rw; 
 read2loop: LOOP
  IF b2mc = 1 THEN LEAVE read2loop; END IF;
  FETCH FROM m2rw INTO q2Arg01,q2Arg02;
  IF b2mc = 0 THEN
   SET m2i=m2i+1;
   SET @mv2Val=CONCAT(@mv2Val,",m4_cpt",m2i,"_bb_code='",q2Arg01,"',m4_cpt",m2i,"_cal_amount='",q2Arg02,"'");
  END IF;
 END LOOP read2loop;
 mLOOP_01: LOOP
