  ELSEIF qProcTypeNr=1 AND qEncPos IN ('60','61') AND qHosTaxonomy01 IN ('273R00000X','283Q00000X') THEN SET mEncProcType='Psychiatric';
  ELSEIF qProcTypeNr=1 AND qEncPos IN ('50') THEN SET mEncProcType='Hospice';
