 END LOOP;
END mBLOCK_01;

mBLOCK_02: BEGIN
 DECLARE b2mc INT DEFAULT 0; DECLARE m2i INT; DECLARE m3i INT;
 DECLARE q2Arg01 VARCHAR(100); DECLARE q2Arg02 VARCHAR(50);
