    SET m2i=m2i+1; SET @mv2Val=CONCAT(@mv2Val,",m4_icd",m2i,"_code='",q2Arg01,"'");
   END IF;
  END IF;
 END LOOP read2loop;

 SET @mv2Val=CONCAT(@mv2Val,",m4_icd_admit='",@mv41Val,"'");
 SET @mv2Val=CONCAT(@mv2Val,",m4_icd_princ='",@mv42Val,"'");

 mLOOP_01: LOOP
  IF  m2i >= 10 THEN LEAVE mLOOP_01; END IF;
  SET m2i = m2i + 1;
  SET @mv2Val=CONCAT(@mv2Val,",m4_icd",m2i,"_code=''");
  ITERATE  mLOOP_01;
 END LOOP;
