  UPDATE mra4_encounter t1 INNER JOIN personell_hosp_assocs t2 ON t2.hospital_nr=t1.pt_facility_nr AND t2.user_nr=t1.m_provider_nr SET t1.is_visit_pcp=1 WHERE t1.entry_nr=qArg00;

  UPDATE mra4_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.pt_facility_nr SET t1.pt_fac_name=t2.`name` WHERE t1.entry_nr=qArg00;
  UPDATE mra4_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.pt_facility_sub_nr SET t1.pt_fac_sub_name=t2.`name` WHERE t1.entry_nr=qArg00;
  UPDATE mra4_encounter t1 INNER JOIN personell t2 ON t2.npr_id=t1.pt_provider_num AND t2.is_dce=1 SET t1.pt_sp_dr_1=t2.`name` WHERE t1.entry_nr=qArg00;
