   SET @mRefAdtDate=CONCAT(YEAR(qEncRefAdmitDate),'-',MONTH(qEncRefAdmitDate),'-01');
   SET @vtmp = (SELECT 1 FROM dc_tm_align_rostr_m01 WHERE mm_curr_mbi_id=qPatientID AND mm_date=@mDisDate AND ALIGN_STATUS_CODE='AL' AND cc_version=@ccVersion LIMIT 1);
   IF @vtmp IS NOT NULL THEN SET qAlignedStatus=1; END IF;
   IF @mDisDate=@mRefAdtDate THEN SET qAligned2Status=qAlignedStatus;
   ELSE SET qAligned2Status=0;
    SET @vtmp = (SELECT 1 FROM dc_tm_align_rostr_m01 WHERE mm_curr_mbi_id=qPatientID AND mm_date=@mRefAdtDate AND ALIGN_STATUS_CODE='AL' AND cc_version=@cc2Version LIMIT 1);
    IF @vtmp IS NOT NULL THEN SET qAligned2Status=1; END IF;
   END IF;
  END IF;
  
  IF qProcTypeNr=1 THEN
    SET @vtmp = (SELECT 1 FROM mra4_encounter e INNER JOIN mra4_encounter_bill_cpts t2 ON t2.encounter_nr=e.encounter_nr WHERE e.proc_type_nr=1 AND ( (t2.CLM_LINE_PROD_REV_CTR_CD IN ('0450','0451','0452','0453','0454','0455','0456','0457','0458','0459','0981') OR t2.bb_Code IN ('99281','99282','99283','99284','99285') ) AND DATEDIFF(e.enc_disch_date,e.enc_admit_date) <= 2) AND e.entry_nr=qArg00 LIMIT 1);
    IF @vtmp IS NOT NULL THEN
     SET @mIsErVisit=1; SET mEncProcType='Emergency';
    END IF;
  END IF;

  SET @mIsVisitPcp= (SELECT 1 FROM personell_hosp_assocs WHERE hospital_nr=qArg02 AND user_nr=qMproviderMr LIMIT 1);
  IF @mIsVisitPcp IS NULL THEN SET @mIsVisitPcp=0; END IF;  
  
  IF qProcTypeNr IN (1,2) THEN
   IF @mIsVisitPcp=1 THEN
    UPDATE mra4_encounter t1 INNER JOIN mra4_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr INNER JOIN personell t4 ON t1.m_provider_nr=t4.nr SET t1.is_offvisit_rec=1 WHERE ( (t2.bb_Code IN ('98000','98001','98002','98003','98004','98005','98006','98007','98008','98009','98010','98011','98012','98013','98014','98015','98016','90957','90958','90959','90960','90961','90962','90965','90966','90969','90970','92002','92004','92012','92014','93750','93797','93798','94004','94625','94626','94664','96160','96164','96165','96167','96168','97129','97130','97151','97152','97161','97162','97163','97164','97530','97535','97750','97755','97761','97763','97802','97803','97804','98960','98961','98962','98966','98967','98968','98970','98971','98972','99091','99201','99202','99203','99204','99205','99211','99212','99213','99214','99215','99241','99242','99243','99244','99245','99341','99342','99343','99344','99345','99347','99348','99349','99350','99381','99382','99383','99384','99385','99386','99387','99391','99392','99393','99394','99395','99396','99397','99401','99402','99403','99404','99411','99412','99421','99422','99423','99429','99441','99442','99443','99453','99454','99455','99456','99457','99458','99473','99474','99487','99489','99490','99491','99495','99496','99497','99498','0591T','0592T','0593T','G0071','G0108','G0109','G0270','G0296','G0402','G0406','G0407','G0408','G0420','G0421','G0422','G0423','G0425','G0426','G0427','G0438','G0439','G0446','G0459','G0463','G0506','G0508','G0509','G0511','G0512','G0513','G0514','G2010','G2012','G2025','G2061','G2062','G2063','G2211','G2212','G2250','G2251','G2252','G3002','G3003','G9481','G9482','G9483','G9484','G9485','G9486','G9487','G9488','G9489','T1015','G2001','G2002','G2003','G2004','G2005','G2006','G2007','G2008','G2009','G2013','G2014','G2015') AND (t1.proc_type_nr=2 OR (t1.proc_type_nr=1 AND t1.CLM_TYPE_CD="40")) ) OR (t1.proc_type_nr=2 AND t1.CLM_TYPE_CD IN ('02','10')) ) AND t4.is_dce=1 AND t4.dce_type='DCE' AND t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
   END IF;
   UPDATE mra4_encounter t1 INNER JOIN mra4_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr SET t1.is_offvisit2rec=1 WHERE ( (t2.bb_Code IN ('98000','98001','98002','98003','98004','98005','98006','98007','98008','98009','98010','98011','98012','98013','98014','98015','98016','90957','90958','90959','90960','90961','90962','90965','90966','90969','90970','92002','92004','92012','92014','93750','93797','93798','94004','94625','94626','94664','96160','96164','96165','96167','96168','97129','97130','97151','97152','97161','97162','97163','97164','97530','97535','97750','97755','97761','97763','97802','97803','97804','98960','98961','98962','98966','98967','98968','98970','98971','98972','99091','99201','99202','99203','99204','99205','99211','99212','99213','99214','99215','99241','99242','99243','99244','99245','99341','99342','99343','99344','99345','99347','99348','99349','99350','99381','99382','99383','99384','99385','99386','99387','99391','99392','99393','99394','99395','99396','99397','99401','99402','99403','99404','99411','99412','99421','99422','99423','99429','99441','99442','99443','99453','99454','99455','99456','99457','99458','99473','99474','99487','99489','99490','99491','99495','99496','99497','99498','0591T','0592T','0593T','G0071','G0108','G0109','G0270','G0296','G0402','G0406','G0407','G0408','G0420','G0421','G0422','G0423','G0425','G0426','G0427','G0438','G0439','G0446','G0459','G0463','G0506','G0508','G0509','G0511','G0512','G0513','G0514','G2010','G2012','G2025','G2061','G2062','G2063','G2211','G2212','G2250','G2251','G2252','G3002','G3003','G9481','G9482','G9483','G9484','G9485','G9486','G9487','G9488','G9489','T1015','G2001','G2002','G2003','G2004','G2005','G2006','G2007','G2008','G2009','G2013','G2014','G2015') AND (t1.proc_type_nr=2 OR (t1.proc_type_nr=1 AND t1.CLM_TYPE_CD="40")) ) OR (t1.proc_type_nr=2 AND t1.CLM_TYPE_CD IN ('02','10')) ) AND t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
  END IF;
  
  SET @mFlwupFlag=0; SET @mIs72HrFp=0;SET @mIs7DyHrFp=0;SET @mIs14DyHrFp=0;SET @mIsG14DyHrFp=0;SET @m72HrFpDate=NULL;

  IF (@mIsErVisit=1 OR (qEncPos IN ('60','61') AND qHosTaxonomy01 IN ('282N00000X','282NC0060X','282NR1301X','282NC2000X','284300000X'))) THEN
    SET @mFlwupFlag=1;
  END IF;

  IF @mFlwupFlag=1 THEN
   SET @m72HrFpDate = (SELECT e.enc_admit_date FROM mra4_encounter e WHERE e.proc_type_nr IN (1,2) AND e.is_offvisit_rec=1 AND e.patient_id=qPatientID AND e.enc_admit_date>=qEncDischDate ORDER BY e.enc_admit_date LIMIT 1);
   IF @m72HrFpDate IS NOT NULL THEN
    SET @mIs72HrFp=0;SET @mIs7DyHrFp=0;SET @mIs14DyHrFp=0;SET @mIsG14DyHrFp=0;
    SET @m1vc=MRA_A31_Get72HrFlowUpDays_m1(@m72HrFpDate,qEncDischDate);

    IF @m1vc BETWEEN 0 AND 3 THEN  SET @mIs72HrFp=1; SET @mIs7DyHrFp=1; SET @mIs14DyHrFp=1; 
    ELSEIF @m1vc BETWEEN 4 AND 7 THEN  SET @mIs7DyHrFp=1; SET @mIs14DyHrFp=1;
    ELSEIF @m1vc BETWEEN 8 AND 14 THEN  SET @mIs14DyHrFp=1; END IF;
    IF @m1vc >= 0 THEN SET @mIsG14DyHrFp=1; END IF;
   END IF;
  END IF;

  UPDATE mra4_encounter SET enc_proc_type=mEncProcType,is_snf_rec=qIsSnfRec,is_er_visit=@mIsErVisit, m_cal_bed_days=DATEDIFF(enc_disch_date,enc_admit_date), pt_aligned_status=qAlignedStatus,pt_aligned2status=qAligned2Status,m_flwup_flag=@mFlwupFlag,is_72_hr_flwup=@mIs72HrFp,is_flwup_7_days=@mIs7DyHrFp,is_flwup_14_days=@mIs14DyHrFp,is_gflwup_14_days=@mIsG14DyHrFp,m72hr_flwup_date=@m72HrFpDate WHERE entry_nr=qArg00;

  UPDATE mra4_encounter t1 INNER JOIN dc_bene_alignment_roster t2 ON t2.mm_curr_mbi_id=t1.patient_id
  SET t1.market_nr=t2.market_id,t1.market_name=t2.market_names,t1.pt_fac_name=t2.dce_group_name,t1.pt_facility_nr=t2.dce_group_nr,t1.pt_facility_sub_nr=t2.dce_sub_group_nr,t1.pt_provider_num=t2.prov_npi_nr,t1.pt_sp_dr_1=t2.dce_provider_name,t1.pt_fac_sub_name=t2.dce_sub_group_name WHERE t2.cc_version=@mRosterVersion AND t1.entry_nr=qArg00;



  SET @mg2vv=qArg00; IF m1i=0 THEN SET @mg1vv=qArg00; END IF;
  INSERT INTO mra1_331_m1 SET mdd_1=mpp3,mdd_2='m02Call',mdd_5=mpp1,mdd_6=qArg00,mdd_7=m1i;
  SET m1i=m1i+1;

 END IF;
END LOOP;
CLOSE mrw;

COMMIT;

INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='END',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00;
IF `_rollback` THEN
 INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='ERROR',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00,mdd_4=msgVR01,mdd_5=msgVR02;
END IF;

END */$$
DELIMITER ;

