DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_AF301_CLF_M3`(mpp1 INT)
BEGIN

SET @mTmp=(SELECT mdd_3 FROM mra_06_tmp WHERE mdd_1='Mra6_AF301CLFM3_Check' and mdd_2='m201z' ORDER BY nr DESC LIMIT 1);
