 INSERT INTO mra_01_tmp SET mdd_1='mra_start',mdd_2='MRA_IMP1AF301CLF_M3',mdd_3='START';
 UPDATE mra_file_static.mra_cclf1 SET mm_famount=CONCAT('-',CLM_PMT_AMT) WHERE CLM_ADJSMT_TYPE_CD=1 AND CLM_PMT_AMT>0 AND mm_famount IS NULL;
 UPDATE mra_file_static.mra_cclf1 SET mm_famount=ABS(CLM_PMT_AMT) WHERE CLM_ADJSMT_TYPE_CD=1 AND CLM_PMT_AMT<0 AND mm_famount IS NULL;
 UPDATE mra_file_static.mra_cclf1 SET mm_famount=CLM_PMT_AMT WHERE CLM_ADJSMT_TYPE_CD<>1 AND mm_famount IS NULL;

 UPDATE feed_status SET date_received=DATE_SUB(NOW(), INTERVAL 1 DAY),time_received=NOW(),updated_as_of=NOW(),date_in_uat=NOW(),date_in_prod=NOW() WHERE `type`='CCLF' ORDER BY `year` DESC LIMIT 1;

