 UPDATE feed_status SET date_received=DATE_SUB(NOW(), INTERVAL 1 DAY),time_received=NOW(),updated_as_of=NOW(),date_in_uat=NOW(),date_in_prod=NOW() WHERE `type`='Claims_Reduction' ORDER BY `year` DESC LIMIT 1;
 INSERT INTO mra_01_tmp SET mdd_1='mrai',mdd_2='TIMP2_CR35_PA',mdd_3='START';
 TRUNCATE mra_00_tmp; CALL MRA_IMP2_CR_M35_PA_02_m3();
 INSERT INTO mra_01_tmp SET mdd_1='mrai',mdd_2='TIMP2_CR35_PB',mdd_3='START';
