IF @mTmp='START' THEN SET @mTmp='1'; ELSE
 INSERT INTO mra_01_tmp SET mdd_1='mrai',mdd_2='MRA_IMP3M03ENC_CleanDup_m1',mdd_3='START';
 CALL MRA_IMP3_M03ENC_CleanDup_m1(1);
 INSERT INTO mra_01_tmp SET mdd_1='mrai',mdd_2='MRA_M12CalEncHeader_m1',mdd_3='START';
 CALL MRA_IMP3_M12CalEncounterHeader();
 INSERT INTO mra_01_tmp SET mdd_1='mrai',mdd_2='MRA_M11CalEncHeader_m1',mdd_3='START';
 CALL MRA_IMP3_M11CalEncounterHeader();
