/* Procedure structure for procedure `MRA_IMP1_B210_m3Roster_START_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_B210_m3Roster_START_m3`(m1pp SMALLINT)
BEGIN

 DECLARE mmi INT; DECLARE mjobId INT; DECLARE m2Cnt INT;

 IF m1pp=1 THEN
  CALL MRA_IMP1_M03ENC31_m11_START_m3(3);
 END IF;

 INSERT INTO mra_01_tmp SET mdd_1='mra01tmp',mdd_2='MRAIMP1B210M3Rosterm3',mdd_3='START';

 SET @ccVersion=(SELECT max(cc_version) as mcc FROM mra1_dcbeneroster);
 UPDATE dc_bene_alignment_rostr_m01 SET map_process_status=0 WHERE cc_version=@ccVersion;

 SET @m1Cnt=(SELECT COUNT(DISTINCT torder) AS mcc FROM mra1_61_tmp WHERE mjob_id BETWEEN 2111 AND 2200);

 SET mmi=1;
 LOOP_M01: LOOP
  IF mmi > @m1Cnt THEN LEAVE LOOP_M01; END IF;

  SET @m1tmp=(SELECT CONCAT(mdd_1,'!@#',mjob_id) AS mcc FROM mra1_61_tmp WHERE mjob_id BETWEEN 2111 AND 2200 and torder=mmi LIMIT 1);
  SET @m1dd=SUBSTRING_INDEX(@m1tmp,'!@#',1);SET mjobId=SUBSTRING_INDEX(@m1tmp,'!@#',-1);

  IF m1pp in (1,3) THEN
   IF mjobId=2115 THEN CALL mradb_prod.MRA_IMP1_B211_m5Roster_K15_k3(20); END IF;
  END IF;

  INSERT INTO mra_01_tmp SET mdd_1='mra_01_tmp',mdd_2=@m1dd,mdd_3='START';
  CALL MRA_IMP1_M03ENC31_m31_m3(mjobId); CALL MRA_IMP1_M03ENC31_m12_ToCheck_m3();
  
  SET mmi=mmi+1;
  ITERATE LOOP_M01;
 END LOOP;

 INSERT INTO mra_01_tmp SET mdd_1='mra01tmp',mdd_2='MRAIMP1B210M3Rosterm3',mdd_3='END';

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_B211_m5Roster_K15_k3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_B211_m5Roster_K15_k3`(m1pp tinyINT)
BEGIN

DECLARE mmi INT; DECLARE m2mi INT; DECLARE m3mi INT;
DECLARE vtmp VARCHAR(100); 

TRUNCATE mra1_311_m1;
INSERT INTO mra1_311_m1 (mdd_1,mdd_2,mdd_3)
SELECT DISTINCT t1.mm_curr_mbi_id,1,'k11_roster' FROM dc_bene_alignment_rostr_m01 t1 WHERE t1.map_process_status=0;

SET m3mi=(SELECT COUNT(mdd_1) FROM mra1_311_m1); SET m3mi=CEIL(m3mi/m1pp);
SET mmi=1;

LOOP_M01: LOOP
 SET m2mi= ((mmi-1)*m3mi ) +1;
 UPDATE mra1_311_m1 SET mdd_2=mmi WHERE nr BETWEEN m2mi AND (m2mi+(m3mi-1));
 IF mmi > m1pp THEN LEAVE  LOOP_M01; END IF;
 SET mmi = mmi + 1;
 ITERATE LOOP_M01;
END LOOP;

UPDATE mra1_311_m1 SET mdd_1='a123z' WHERE mdd_1='' OR mdd_1 IS NULL;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_B211_m5Roster_K15_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_B211_m5Roster_K15_m3`(mpp1 SMALLINT,mpp2 BIGINT,mpp3 VARCHAR(100),mpp4 SMALLINT)
BEGIN

DECLARE bmc INT DEFAULT 0;DECLARE _rollback TINYINT DEFAULT 0;DECLARE m1i INT DEFAULT 0;
DECLARE vtmp VARCHAR(999);

DECLARE qArg00 bigINT;DECLARE qArg01 INT;DECLARE qArg02 bigINT;DECLARE qArg03 VARCHAR(100);DECLARE qArg04 smallint;DECLARE qArg05 tinyint;

DECLARE msgVR01 VARCHAR(100);DECLARE msgVR02 VARCHAR(200);

DECLARE mrw CURSOR FOR sELECT t1.nr,t1.cc_version,t1.dce_group_nr,t1.mm_curr_mbi_id,t1.mm_year,t1.mm_month FROM dc_bene_alignment_rostr_m01 t1 INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=t1.mm_curr_mbi_id WHERE t1.map_process_status=0 AND t2.mdd_2=mpp1 group by t1.cc_version,t1.mm_curr_mbi_id;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
BEGIN
 SET _rollback = 1;
 GET DIAGNOSTICS CONDITION 1
 msgVR01 = RETURNED_SQLSTATE, msgVR02 = MESSAGE_TEXT;
END;

CREATE TEMPORARY TABLE `mtm_encounter`(`entry_nr` BIGINT,`patient_id` VARCHAR(100),`enc_disch_date` DATE,`pt_aligned_status` TINYINT,`enc_pos` VARCHAR(10),proc_type_nr TINYINT,pt_aligned2status TINYINT,is_er_visit TINYINT,enc_admit_date DATE,is_offvisit_rec TINYINT,m_provider_nr BIGINT,KEY `mkey01`(`entry_nr`),KEY `mkey02`(`patient_id`),KEY `mkey03`(`enc_disch_date`),KEY `mkey04`(`pt_aligned_status`),KEY `mkey05`(`enc_pos`),KEY mkey06(pt_aligned2status),KEY mkey07(is_er_visit),KEY `mkey08`(`enc_admit_date`),KEY `mkey09`(`is_offvisit_rec`),KEY mkey10(m_provider_nr)) ENGINE=INNODB DEFAULT CHARSET=latin1;

INSERT INTO mtm_encounter(entry_nr,patient_id,enc_disch_date,pt_aligned_status,enc_pos,proc_type_nr,pt_aligned2status,is_er_visit,enc_admit_date,is_offvisit_rec,m_provider_nr)
SELECT e.entry_nr,e.patient_id,e.enc_disch_date,e.pt_aligned_status,e.enc_pos,e.proc_type_nr,e.pt_aligned2status,e.is_er_visit,e.enc_admit_date,e.is_offvisit_rec,e.m_provider_nr FROM mra1_encounter AS e
INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=e.patient_id
WHERE e.proc_type_nr in (1,2) and e.enc_disch_date>='2024-01-01' AND t2.mdd_2=mpp1;

INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='m01Call',mdd_3=CONCAT('c2-',mpp1);

SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
START TRANSACTION;

SET @mg1vv=0; SET @mg2vv=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05;
 IF bmc = 0 THEN

  SET @mCols=''; set @m1Months=1;SET @m2Months=3;

  if qArg05 between 4 and 6 then SET @m1Months=4;SET @m2Months=6;
  elseif qArg05 BETWEEN 7 AND 9 THEN SET @m1Months=7;SET @m2Months=9;
  elseif qArg05 BETWEEN 10 AND 12 THEN SET @m1Months=10;SET @m2Months=12; end if;

  SET @mCntInpatient=(SELECT COUNT(t1.entry_nr) AS mmcc1 FROM mtm_encounter t1 WHERE t1.proc_type_nr=1 AND t1.pt_aligned_status=1 AND t1.patient_id=qArg03 AND t1.enc_pos IN ('60','61') AND year(t1.enc_disch_date) = qArg04);
  if @mCntInpatient is null then set @mCntInpatient=0; end if;
  SET @mCols=CONCAT(@mCols,",mcnt_inpatient=",@mCntInpatient,"");

  SET @mCntErVisit=(SELECT COUNT(DISTINCT e.entry_nr) AS mmcc1 FROM mtm_encounter e WHERE e.proc_type_nr=1 AND e.pt_aligned2status=1 AND e.is_er_visit=1 AND year(e.enc_admit_date)=qArg04 AND e.patient_id=qArg03);
  if @mCntErVisit is null then set @mCntErVisit=0; end if;
  SET @mCols=CONCAT(@mCols,",mcnt_er_visit=",@mCntErVisit,"");
 
  SET @mCntOffVisit=(SELECT COUNT(DISTINCT t1.entry_nr) AS mmcc1 FROM mtm_encounter t1 WHERE t1.patient_id=qArg03 AND t1.is_offvisit_rec=1 AND year(t1.enc_disch_date)=qArg04);
  if @mCntOffVisit is null then set @mCntOffVisit=0; end if;
  SET @mCols=CONCAT(@mCols,",mcnt_off_visit=",@mCntOffVisit,"");

  /* SET @mraAdiScore=(SELECT adi_score FROM mra_adi_score WHERE origid=qArg03 AND m_year=qArg04 ORDER BY `version` DESC LIMIT 1);
  IF @mraAdiScore IS NULL THEN SET @mraAdiScore=0; END IF;
  SET @mCols=CONCAT(@mCols,",mra_adi_score='",@mraAdiScore,"'"); */

  SET @mUHApercentile=(SELECT percentile FROM refactor_ai WHERE report_type_id=1 AND origid=qArg03 AND YEAR(index_date)=qArg04 AND MONTH(index_date) BETWEEN @m1Months and @m2Months ORDER BY mnr DESC LIMIT 1);
  IF @mUHApercentile IS NULL THEN
   SET @mUHApercentile=(SELECT percentile FROM refactor_ai WHERE report_type_id=1 AND origid=qArg03 ORDER BY mnr DESC LIMIT 1);
  END IF;
  IF @mUHApercentile IS NULL THEN SET @mUHApercentile=0; END IF;
  SET @mCols=CONCAT(@mCols,",UHA_percentile='",@mUHApercentile,"'");

  set @mLastPCP_VisitDate='';set @mLastPCP_VisitPc='';set @mLastVisit_Date='';set @mLastVisit_Pc='';
  SET @mtmp=(SELECT CONCAT(t1.enc_admit_date,'!@#',t4.`name`) as mcc FROM mtm_encounter t1 INNER JOIN personell t4 ON t1.m_provider_nr=t4.nr WHERE t1.patient_id=qArg03 AND t1.proc_type_nr IN (1,2) AND t1.is_offvisit_rec=1 ORDER BY t1.enc_admit_date DESC LIMIT 1);
  IF @mtmp IS not NULL THEN
   SET @mLastPCP_VisitDate=SUBSTRING_INDEX(@mtmp,'!@#',1); SET @mLastPCP_VisitPc=SUBSTRING_INDEX(@mtmp,'!@#',-1);
  END IF;
  SET @mCols=CONCAT(@mCols,",Last_PCP_Visit_Date='",@mLastPCP_VisitDate,"',Last_PCP_Visit_Pc='",@mLastPCP_VisitPc,"'");

  SET @mtmp=(SELECT CONCAT(t1.enc_admit_date,'!@#',t4.`name`) AS mcc FROM mtm_encounter t1 INNER JOIN personell t4 ON t1.m_provider_nr=t4.nr WHERE t1.patient_id=qArg03 AND t1.proc_type_nr IN (1,2) AND t1.is_offvisit2rec=1 ORDER BY t1.enc_admit_date DESC LIMIT 1);
  IF @mtmp IS not NULL THEN
   SET @mLastVisit_Date=SUBSTRING_INDEX(@mtmp,'!@#',1); SET @mLastVisit_Pc=SUBSTRING_INDEX(@mtmp,'!@#',-1);
  END IF;
  SET @mCols=CONCAT(@mCols,",Last_Visit_Date='",@mLastVisit_Date,"',Last_Visit_Pc='",@mLastVisit_Pc,"'");

  SET @mmDate=CONCAT(qArg04,'-',qArg05,'-01');

  set @mStratificat_Level='';set @mStratificationReason='';
  SET @mtmp=(SELECT MAX(stratification_date) AS mm_date FROM `patient_stratification_history` WHERE stratification_date <= LAST_DAY(@mmDate));
  IF @mtmp IS not NULL THEN
   SET @mtmp=(SELECT CONCAT(stratification_level,'!@#',stratification_reason) as mcc FROM `patient_stratification_history` WHERE origid=qArg03 AND stratification_date=@mtmp);
   IF @mtmp IS not NULL THEN
    SET @mStratificat_Level=SUBSTRING_INDEX(@mtmp,'!@#',1); SET @mStratificationReason=SUBSTRING_INDEX(@mtmp,'!@#',-1);
   END IF;  
  END IF;

  IF @mStratificat_Level IS NULL or @mStratificat_Level='' THEN
   SET @mStratificat_Level='Level 1';
  END IF; 

  SET @mCols=CONCAT(@mCols,",stratification_level='",@mStratificat_Level,"',stratification_reason='",@mStratificationReason,"'");

  SET @mQry="UPDATE dc_bene_alignment_roster SET map_process_status=1";
  SET @mQry=CONCAT(@mQry,@mCols," WHERE cc_version=",qArg01," AND mm_curr_mbi_id='",qArg03,"'");
  PREPARE stmt FROM @mQry; EXECUTE stmt; DEALLOCATE PREPARE stmt;

  SET @mQry="UPDATE dc_bene_alignment_rostr_m01 SET map_process_status=1";
  SET @mQry=CONCAT(@mQry,@mCols," WHERE cc_version=",qArg01," AND mm_curr_mbi_id='",qArg03,"' AND mm_date='",@mmDate,"'");
  PREPARE stmt FROM @mQry; EXECUTE stmt; DEALLOCATE PREPARE stmt;
  SET @mQry=CONCAT("UPDATE dc_bene_alignment_rostr_m01 SET map_process_status=2 WHERE cc_version=",qArg01," AND mm_curr_mbi_id='",qArg03,"' AND map_process_status=0");
  PREPARE stmt FROM @mQry; EXECUTE stmt; DEALLOCATE PREPARE stmt;

  UPDATE dc_bene_alignment_roster t1 INNER JOIN hospital_market_assocs t2 ON t2.hosp_id=t1.dce_group_nr SET t1.market_id=t2.market_id WHERE cc_version=qArg01 AND mm_curr_mbi_id=qArg03;  
  UPDATE dc_bene_alignment_roster t1 INNER JOIN hospital_market t2 ON t2.market_id=t1.market_id SET t1.market_names=t2.`market_name` WHERE cc_version=qArg01 AND mm_curr_mbi_id=qArg03;

  UPDATE dc_bene_alignment_roster t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.dce_group_nr SET t1.dce_group_name=t2.`name` WHERE cc_version=qArg01 AND mm_curr_mbi_id=qArg03;
  UPDATE dc_bene_alignment_roster t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.dce_sub_group_nr SET t1.dce_sub_group_name=t2.`name` WHERE cc_version=qArg01 AND mm_curr_mbi_id=qArg03;
  UPDATE dc_bene_alignment_roster t1 INNER JOIN personell t2 ON t2.npr_id=t1.prov_npi_nr AND t2.is_dce=1 SET t1.dce_provider_name=t2.`name` WHERE t2.is_dce=1 AND cc_version=qArg01 AND mm_curr_mbi_id=qArg03;

  UPDATE dc_bene_alignment_rostr_m01 t1 INNER JOIN hospital_market_assocs t2 ON t2.hosp_id=t1.dce_group_nr SET t1.market_id=t2.market_id WHERE cc_version=qArg01 AND mm_curr_mbi_id=qArg03;
  UPDATE dc_bene_alignment_rostr_m01 t1 INNER JOIN hospital_market t2 ON t2.market_id=t1.market_id SET t1.market_names=t2.`market_name` WHERE cc_version=qArg01 AND mm_curr_mbi_id=qArg03;

  UPDATE dc_bene_alignment_rostr_m01 t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.dce_group_nr SET t1.dce_group_name=t2.`name` WHERE cc_version=qArg01 AND mm_curr_mbi_id=qArg03;
  UPDATE dc_bene_alignment_rostr_m01 t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.dce_sub_group_nr SET t1.dce_sub_group_name=t2.`name` WHERE cc_version=qArg01 AND mm_curr_mbi_id=qArg03;
  UPDATE dc_bene_alignment_rostr_m01 t1 INNER JOIN personell t2 ON t2.npr_id=t1.prov_npi_nr AND t2.is_dce=1 SET t1.dce_provider_name=t2.`name` WHERE t2.is_dce=1 AND cc_version=qArg01 AND mm_curr_mbi_id=qArg03;

  UPDATE dc_bene_alignment_roster SET market_id='14' WHERE cc_version=qArg01 AND mm_curr_mbi_id=qArg03 AND dce_group_nr=10014313 AND market_id=0;
  UPDATE dc_bene_alignment_roster SET dce_provider_name='UNK',prov_npi_nr='1234' WHERE cc_version=qArg01 AND mm_curr_mbi_id=qArg03 AND (prov_npi_nr='1234' OR prov_npi_nr='' OR prov_npi_nr IS NULL);

  SET @mg2vv=qArg00; if m1i=0 then SET @mg1vv=qArg00; end if;
  INSERT INTO mra1_331_m1 SET mdd_1=mpp3,mdd_2='m02Call',mdd_5=mpp1,mdd_6=qArg00,mdd_7=m1i;
  SET m1i=m1i+1;

 END IF;
END LOOP;
CLOSE mrw;

COMMIT;

INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='END',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00;
IF `_rollback` THEN
 INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='ERROR',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00,mdd_4=msgVR01,mdd_5=msgVR02;
END IF;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_C20_M3CLF_START_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C20_M3CLF_START_m3`(m1pp SMALLINT)
BEGIN

 DECLARE mmi INT; DECLARE mjobId INT; DECLARE m1Nr BIGINT; DECLARE m1sval SMALLINT;DECLARE m2sval SMALLINT;

 INSERT INTO mra_01_tmp SET mdd_1='mra_start',mdd_2='MRAIMP1C20M3_CLFm13',mdd_3='START';

 IF m1pp=1 THEN SET m1sval=2011; SET m2sval=2020;
 ELSEIF m1pp=2 THEN SET m1sval=2021; SET m2sval=2025; 
 ELSEIF m1pp=3 THEN SET m1sval=2026; SET m2sval=2030; END IF;

 SET @m1Cnt=(SELECT COUNT(DISTINCT torder) AS mcc FROM mra1_61_tmp WHERE mjob_id BETWEEN m1sval AND m2sval);

 SET mmi=1;
 LOOP_M01: LOOP
  IF mmi > @m1Cnt THEN LEAVE LOOP_M01; END IF;

  SET @m1tmp=(SELECT CONCAT(mdd_1,'!@#',mjob_id) AS mcc FROM mra1_61_tmp WHERE is_active=1 AND mjob_id BETWEEN m1sval AND m2sval AND torder=mmi LIMIT 1);

  IF @m1tmp IS NULL THEN
   SET mmi=mmi+1; ITERATE LOOP_M01;
  ELSE    
  
   SET @m1dd=SUBSTRING_INDEX(@m1tmp,'!@#',1);SET mjobId=SUBSTRING_INDEX(@m1tmp,'!@#',-1);

   SET m1Nr=NULL;
   IF mjobId=2011 THEN SET m1Nr=(SELECT nr FROM mra_file_static.mra_cclf1 WHERE map_data_status=0 LIMIT 1);
   ELSEIF mjobId=2012 THEN SET m1Nr=(SELECT nr FROM mra_file_static.mra_cclf5 WHERE map_data_status=0 AND CLM_CARR_PMT_DNL_CD != "0" LIMIT 1);
   ELSEIF mjobId=2013 THEN SET m1Nr=(SELECT nr FROM mra_file_static.mra_cclf6 WHERE map_data_status=0 LIMIT 1);
   ELSEIF mjobId=2014 THEN SET m1Nr=(SELECT nr FROM mra_file_static.mra_cclf7 WHERE map_data_status=0 LIMIT 1); 
   ELSEIF mjobId=2021 THEN SET m1Nr=(SELECT entry_nr FROM cclf_encounter WHERE map_data_status=0 AND mra_proc_type_nr BETWEEN 1 AND 4 LIMIT 1);
   ELSEIF mjobId=2026 THEN SET m1Nr=(SELECT entry_nr FROM mra1_encounter WHERE m1_map_status=5 LIMIT 1);
   END IF;

   IF m1Nr IS NULL THEN
    SET mmi=mmi+1;
   ELSE

    IF mjobId=2011 THEN CALL mradb_prod.MRA_IMP1_C21CLF_P1_k3(20);
    ELSEIF mjobId=2012 THEN CALL mradb_prod.MRA_IMP1_C21CLF_P2_k3(20);
    ELSEIF mjobId=2013 THEN CALL mradb_prod.MRA_IMP1_C21CLF_P3_k3(20);
    ELSEIF mjobId=2014 THEN CALL mradb_prod.MRA_IMP1_C21CLF_P4_k3(20);
    ELSEIF mjobId=2021 THEN CALL mradb_prod.MRA_IMP1_C22_m5ENC_C11_k3(20);
    ELSEIF mjobId=2026 THEN CALL mradb_prod.MRA_IMP1_C23_m5ENC_C11_k3(20);
    END IF;

    INSERT INTO mra_01_tmp SET mdd_1='mra_01_tmp',mdd_2=@m1dd,mdd_3='START';
    CALL MRA_IMP1_M03ENC31_m31_m3(mjobId); CALL MRA_IMP1_M03ENC31_m12_ToCheck_m3();
   END IF;

  END IF;
  ITERATE LOOP_M01;
 END LOOP;
 
 INSERT INTO mra_01_tmp SET mdd_1='mra_end',mdd_2='MRAIMP1C20M3_CLFm13',mdd_3='END';

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_C21CLF_P1_k3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P1_k3`(m1pp tinyINT)
BEGIN

DECLARE mmi INT; DECLARE m2mi INT; DECLARE m3mi INT;
DECLARE vtmp VARCHAR(100); 

TRUNCATE mra1_311_m1;
INSERT INTO mra1_311_m1 (mdd_1,mdd_2,mdd_3)
SELECT DISTINCT t1.BENE_MBI_ID,1,mradb_prod.MRA_FN01_GetPatientIDLastCCLF(t1.BENE_MBI_ID) 
FROM mra_file_static.mra_cclf1 t1 WHERE t1.map_data_status=0;

SET m3mi=(SELECT COUNT(mdd_1) FROM mra1_311_m1); SET m3mi=CEIL(m3mi/m1pp);
SET mmi=1;

LOOP_M01: LOOP
 SET m2mi= ((mmi-1)*m3mi ) +1;
 UPDATE mra1_311_m1 SET mdd_2=mmi WHERE nr BETWEEN m2mi AND (m2mi+(m3mi-1));
 IF mmi > m1pp THEN LEAVE  LOOP_M01; END IF;
 SET mmi = mmi + 1;
 ITERATE LOOP_M01;
END LOOP;

UPDATE mra1_311_m1 SET mdd_1='a123z' WHERE mdd_1='' OR mdd_1 IS NULL;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_C21CLF_P1_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P1_m3`(mpp1 SMALLINT,mpp2 BIGINT,mpp3 VARCHAR(100),mpp4 SMALLINT)
BEGIN

DECLARE bmc INT DEFAULT 0;DECLARE _rollback TINYINT DEFAULT 0;DECLARE m1i INT DEFAULT 0;

DECLARE vtmp VARCHAR(999); DECLARE v1tmp INT; DECLARE mMBI_IDNEW VARCHAR(100);
DECLARE mv_proc_type_nr SMALLINT DEFAULT 1; DECLARE ms01vv VARCHAR(20); 
DECLARE procedure_type VARCHAR(50); DECLARE to_personell_name VARCHAR(100); DECLARE mproc_center VARCHAR(100); DECLARE vm_enc_nr BIGINT;
DECLARE mToPersonelNr INT; DECLARE mHospNr INT;

DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);DECLARE qArg7 VARCHAR(100);DECLARE qArg8 VARCHAR(100);DECLARE qArg9 VARCHAR(100);DECLARE qArg10 VARCHAR(100);DECLARE qArg11 VARCHAR(100);DECLARE qArg12 VARCHAR(100);DECLARE qArg13 VARCHAR(100);DECLARE qArg14 VARCHAR(100);DECLARE qArg15 VARCHAR(999);DECLARE qArg16 VARCHAR(10);
DECLARE qArg17 VARCHAR(100);DECLARE qArg18 VARCHAR(100);DECLARE qArg19 VARCHAR(100);DECLARE qArg20 VARCHAR(100);DECLARE qArg21 VARCHAR(100); DECLARE qArg22 VARCHAR(30);DECLARE qArg23 VARCHAR(50);DECLARE qArg24 INT; DECLARE qMapDatSrc INT;DECLARE qArg26 VARCHAR(50);DECLARE qArg27 VARCHAR(100);DECLARE qArg28 VARCHAR(10);

DECLARE msgVR01 VARCHAR(100);DECLARE msgVR02 VARCHAR(200);

DECLARE mrw CURSOR FOR SELECT t1.nr,t1.`CUR_CLM_UNIQ_ID`,t1.`ATNDG_PRVDR_NPI_NUM`,t1.`OPRTG_PRVDR_NPI_NUM`,t1.`CLM_FROM_DT`,CONCAT(SUBSTR(t1.`CLM_FROM_DT`,1,4),SUBSTR(t1.`CLM_FROM_DT`,6,2),SUBSTR(t1.`CLM_FROM_DT`,9,2)) AS encounter_date,t1.`BENE_MBI_ID`,t1.`FAC_PRVDR_NPI_NUM`,t1.`CLM_THRU_DT`,t1.`PRVDR_OSCAR_NUM`,t1.`CLM_BILL_FAC_TYPE_CD`,t1.`CLM_TYPE_CD`,t1.`CLM_OP_SRVC_TYPE_CD`,t1.`CLM_ADMSN_TYPE_CD`,t1.`CLM_ADMSN_SRC_CD`,t1.BENE_PTNT_STUS_CD,t1.CLM_ADJSMT_TYPE_CD,t1.CLM_BLG_PRVDR_OSCAR_NUM,t1.CLM_BLG_PRVDR_NPI_NUM,t1.CLM_OPRTG_PRVDR_NPI_NUM,t1.CLM_ATNDG_PRVDR_NPI_NUM,t1.CLM_OTHR_PRVDR_NPI_NUM,t1.CLM_EFCTV_DT,t1.CLM_PMT_AMT,t1.mm_imp_job_nr,t1.map_data_src,t1.CLM_CNTL_NUM,t1.CLM_BILL_CLSFCTN_CD,t1.CLM_MDCR_NPMT_RSN_CD,t2.mdd_3 FROM mra_file_static.mra_cclf1 t1 INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=t1.BENE_MBI_ID WHERE t1.map_data_status=0 AND t2.mdd_2=mpp1 ORDER BY t1.mm_imp_job_nr,t1.CLM_EFCTV_DT,t1.CUR_CLM_UNIQ_ID,t1.`nr`;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
BEGIN
 SET _rollback = 1;
 GET DIAGNOSTICS CONDITION 1
 msgVR01 = RETURNED_SQLSTATE, msgVR02 = MESSAGE_TEXT;
END;

CREATE TEMPORARY TABLE `mtm_encounter`(`encounter_nr` BIGINT,`origid` VARCHAR(100),`CLM_BLG_PRVDR_OSCAR_NUM` VARCHAR(50),`encounter_date` DATE,`place_of_service` VARCHAR(10),KEY `mkey01`(`encounter_nr`),KEY `mkey02`(`origid`),KEY `mkey03`(`CLM_BLG_PRVDR_OSCAR_NUM`),KEY `mkey04`(`encounter_date`),KEY `mkey05`(`place_of_service`)) ENGINE=INNODB DEFAULT CHARSET=latin1;

INSERT INTO mtm_encounter(encounter_nr,encounter_date,origid,CLM_BLG_PRVDR_OSCAR_NUM,place_of_service)
SELECT e.encounter_nr,DATE_FORMAT(e.encounter_date,'%Y-%m-%d'),e.origid,e.CLM_BLG_PRVDR_OSCAR_NUM,e.place_of_service FROM cclf_encounter AS e
INNER JOIN mra1_311_m1 t2 ON t2.mdd_3=e.origid
WHERE e.mra_proc_type_nr=mv_proc_type_nr AND t2.mdd_2=mpp1;

INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='m01Call',mdd_3=CONCAT('c2-',mpp1);

SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
START TRANSACTION;

SET @mg1vv=0; SET @mg2vv=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8,qArg9,qArg10,qArg11,qArg12,qArg13,qArg14,qArg15,qArg16,qArg17,qArg18,qArg19,qArg20,qArg21,qArg22,qArg23,qArg24,qMapDatSrc,qArg26,qArg27,qArg28,mMBI_IDNEW;
 IF bmc = 0 THEN

  SET ms01vv= "mclf1_a";

  CALL MRA_IMP_FUNC_Hospital(qArg7);
  IF qArg2<>'~' THEN CALL MRA_IMP_FUNC_Personell(qArg2); END IF; 

  SET mHospNr=0; SET mproc_center=qArg7;
  SET vtmp = (SELECT nr FROM adt_hosp_centers WHERE npi_id=mproc_center LIMIT 1);
  IF vtmp IS NOT NULL THEN
   SET mHospNr=vtmp; SET mproc_center = (SELECT `mname` FROM adt_hosp_centers WHERE nr=mHospNr LIMIT 1);
  END IF;

  SET mToPersonelNr=1; SET to_personell_name=''; IF qArg2<>'~' THEN SET to_personell_name=qArg2; END IF;
  SET vtmp = (SELECT nr FROM personell WHERE npr_id=to_personell_name LIMIT 1);
  IF vtmp IS NOT NULL THEN
   SET mToPersonelNr=vtmp; SET to_personell_name = (SELECT `name` FROM personell WHERE nr=mToPersonelNr LIMIT 1);
  END IF;

 SET @mfamount = (SELECT SUM(mm_famount) FROM mra_file_static.mra_cclf1 WHERE BENE_MBI_ID=qArg6 AND CLM_FROM_DT=qArg4 AND CLM_BLG_PRVDR_OSCAR_NUM=qArg17 AND CLM_TYPE_CD=qArg11 AND map_process2status=1);  

 SET vm_enc_nr = (SELECT encounter_nr FROM mtm_encounter WHERE origid=mMBI_IDNEW AND encounter_date=qArg4 AND CLM_BLG_PRVDR_OSCAR_NUM=qArg17 AND place_of_service=qArg11 LIMIT 1); 
 IF vm_enc_nr IS NULL THEN

  SET vm_enc_nr=CONCAT('31',SUBSTRING(qArg5,3,8),LPAD(qArg00,11,'0'));  

  SET procedure_type=qArg11;
  SET vtmp = (SELECT Option_Label FROM option_code_values WHERE Column_Order=1119 AND Option_Value=procedure_type LIMIT 1);
  IF vtmp IS NOT NULL THEN SET procedure_type=vtmp; END IF;
  IF qArg12<>"~" AND qArg12<>"" THEN
   IF qArg12=1 THEN SET procedure_type="Outpatient Emergent"; 
   ELSEIF qArg12=2 THEN SET procedure_type="Outpatient Urgent"; 
   ELSEIF qArg12=3 THEN SET procedure_type="Outpatient Elective"; END IF;
  END IF;

  SET v1tmp=0; IF qArg16="1" THEN SET v1tmp=1; END IF;

  INSERT INTO cclf_encounter SET map_data_status=v1tmp,modify_time=NOW(),create_time=NOW(),mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,create_id='mra_sch_import_claim',encounter_status='admitted',mra_proc_type_nr=mv_proc_type_nr,encounter_class_nr='9',is_discharged='0',report_status='1',mm_curr_mbi_id=qArg6,origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,mhos_cent_nr=mHospNr,current_att_dr_nr=mToPersonelNr,encounter_date=qArg4,discharge_date=qArg8,discharge_time="",encounter_type=procedure_type,place_of_service=qArg11,pos=qArg11,ATNDG_PRVDR_NPI_NUM=qArg2,PRVDR_OSCAR_NUM=qArg9,FAC_PRVDR_NPI_NUM=qArg7,CUR_CLM_UNIQ_ID=qArg01,CLM_EFCTV_DT=qArg22,CLM_CNTL_NUM=qArg26,CLM_ADJSMT_TYPE_CD=qArg16,mm_imp_job_nr=qArg24,CLM_BLG_PRVDR_OSCAR_NUM=qArg17,CLM_BLG_PRVDR_NPI_NUM=qArg18,CLM_BILL_FAC_TYPE_CD=qArg10,CLM_BILL_CLSFCTN_CD=qArg27,CLM_MDCR_NPMT_RSN_CD=qArg28,CLM_ADMSN_TYPE_CD=qArg13,CLM_ADMSN_SRC_CD=qArg14,CLM_AMT_PD=@mfamount;

  SET vtmp = (SELECT Option_Label FROM option_code_values WHERE Column_Order=86 AND Option_Value=qArg15 LIMIT 1);
  IF vtmp IS NULL THEN SET vtmp=qArg15; END IF;
  INSERT IGNORE INTO cclf_procedure_discharge SET encounter_nr=vm_enc_nr,discharge_type=qArg15,discharge_date=qArg8,discharge_to=vtmp,discharge_loc=vtmp,discharge_comments=vtmp,created_by='mra_sch_import_claim',create_date=NOW();
  INSERT INTO cclf_encounter_procedure SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,comments='mra_sch_import_claim',encounter_nr=vm_enc_nr,procedure_type=procedure_type,procedure_date=qArg4,procedure_center=mproc_center,interventionalist=to_personell_name,prcedure_op_type=1;
  
  INSERT INTO cclf_study_report_billing SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,created_date=NOW(),created_by='mra_sch_import_claim',Patient_Id=mMBI_IDNEW,encounter_nr=vm_enc_nr,Procedure_Type=procedure_type,CLM_ADJSMT_TYPE_CD=qArg16,CLM_BILL_FAC_TYPE_CD=qArg10,CLM_TYPE_CD=qArg11,CLM_OP_SRVC_TYPE_CD=qArg12,CLM_ADMSN_TYPE_CD=qArg13,CLM_ADMSN_SRC_CD=qArg14,CLM_AMT_PD=@mfamount;

