DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P1_m3_old`(mpp1 SMALLINT,mpp2 BIGINT,mpp3 VARCHAR(100),mpp4 SMALLINT)
BEGIN

DECLARE bmc INT DEFAULT 0;DECLARE _rollback TINYINT DEFAULT 0;DECLARE m1i INT DEFAULT 0;

DECLARE vtmp VARCHAR(999); DECLARE v1tmp INT; DECLARE mMBI_IDNEW VARCHAR(100);
DECLARE mv_proc_type_nr SMALLINT DEFAULT 1; DECLARE ms01vv VARCHAR(20); 
DECLARE procedure_type VARCHAR(50); DECLARE to_personell_name VARCHAR(100); DECLARE mproc_center VARCHAR(100); DECLARE vm_enc_nr BIGINT;
DECLARE mToPersonelNr INT; DECLARE mHospNr INT;

DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);DECLARE qArg7 VARCHAR(100);DECLARE qArg8 VARCHAR(100);DECLARE qArg9 VARCHAR(100);DECLARE qArg10 VARCHAR(100);DECLARE qArg11 VARCHAR(100);DECLARE qArg12 VARCHAR(100);DECLARE qArg13 VARCHAR(100);DECLARE qArg14 VARCHAR(100);DECLARE qArg15 VARCHAR(999);DECLARE qArg16 VARCHAR(10);
DECLARE qArg17 VARCHAR(100);DECLARE qArg18 VARCHAR(100);DECLARE qArg19 VARCHAR(100);DECLARE qArg20 VARCHAR(100);DECLARE qArg21 VARCHAR(100); DECLARE qArg22 VARCHAR(30);DECLARE qArg23 VARCHAR(50);DECLARE qArg24 INT; DECLARE qMapDatSrc INT;DECLARE qArg26 VARCHAR(50);DECLARE qArg27 VARCHAR(100);DECLARE qArg28 VARCHAR(10);

DECLARE msgVR01 VARCHAR(100);DECLARE msgVR02 VARCHAR(200);

DECLARE mrw CURSOR FOR SELECT t1.nr,t1.`CUR_CLM_UNIQ_ID`,t1.`ATNDG_PRVDR_NPI_NUM`,t1.`OPRTG_PRVDR_NPI_NUM`,t1.`CLM_FROM_DT`,CONCAT(SUBSTR(t1.`CLM_FROM_DT`,1,4),SUBSTR(t1.`CLM_FROM_DT`,6,2),SUBSTR(t1.`CLM_FROM_DT`,9,2)) AS encounter_date,t1.`BENE_MBI_ID`,t1.`FAC_PRVDR_NPI_NUM`,t1.`CLM_THRU_DT`,t1.`PRVDR_OSCAR_NUM`,t1.`CLM_BILL_FAC_TYPE_CD`,t1.`CLM_TYPE_CD`,t1.`CLM_OP_SRVC_TYPE_CD`,t1.`CLM_ADMSN_TYPE_CD`,t1.`CLM_ADMSN_SRC_CD`,t1.BENE_PTNT_STUS_CD,t1.CLM_ADJSMT_TYPE_CD,t1.CLM_BLG_PRVDR_OSCAR_NUM,t1.CLM_BLG_PRVDR_NPI_NUM,t1.CLM_OPRTG_PRVDR_NPI_NUM,t1.CLM_ATNDG_PRVDR_NPI_NUM,t1.CLM_OTHR_PRVDR_NPI_NUM,t1.CLM_EFCTV_DT,t1.CLM_PMT_AMT,t1.mm_imp_job_nr,t1.map_data_src,t1.CLM_CNTL_NUM,t1.CLM_BILL_CLSFCTN_CD,t1.CLM_MDCR_NPMT_RSN_CD,t2.mdd_3 FROM mra_file_static.mra_cclf1 t1 INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=t1.BENE_MBI_ID WHERE t1.map_data_status=0 AND t2.mdd_2=mpp1 ORDER BY t1.mm_imp_job_nr,t1.CLM_EFCTV_DT,t1.CUR_CLM_UNIQ_ID,t1.`nr`;

