read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8,qArg9,qArg10,qArg11,qArg12,qArg13,qArg14,qArg15,qArg16,qArg17,qArg18,qArg19,qArg20,qArg21,qArg22,qArg23,qArg24,qMapDatSrc,qArg26,qArg27,qArg28,mMBI_IDNEW;
 IF bmc = 0 THEN

  SET ms01vv= "mclf1_a";

  CALL MRA_IMP_FUNC_Hospital(qArg7);
  IF qArg2<>'~' THEN CALL MRA_IMP_FUNC_Personell(qArg2); END IF; 

  SET mHospNr=0; SET mproc_center=qArg7;
  SET vtmp = (SELECT nr FROM hospital_centers WHERE nrp_id=mproc_center LIMIT 1);
  IF vtmp IS NOT NULL THEN
   SET mHospNr=vtmp; SET mproc_center = (SELECT `name` FROM hospital_centers WHERE nr=mHospNr LIMIT 1);
  END IF;

  SET mToPersonelNr=1; SET to_personell_name=''; IF qArg2<>'~' THEN SET to_personell_name=qArg2; END IF;
  SET vtmp = (SELECT nr FROM personell WHERE npr_id=to_personell_name LIMIT 1);
  IF vtmp IS NOT NULL THEN
   SET mToPersonelNr=vtmp; SET to_personell_name = (SELECT `name` FROM personell WHERE nr=mToPersonelNr LIMIT 1);
  END IF;

 SET @mfamount = (SELECT SUM(mm_famount) FROM mra_file_static.mra_cclf1 WHERE BENE_MBI_ID=qArg6 AND CLM_FROM_DT=qArg4 AND CLM_BLG_PRVDR_OSCAR_NUM=qArg17 AND CLM_TYPE_CD=qArg11 AND map_process2status=1);  

 SET vm_enc_nr = (SELECT encounter_nr FROM mtm_encounter WHERE origid=mMBI_IDNEW AND encounter_date=qArg4 AND CLM_BLG_PRVDR_OSCAR_NUM=qArg17 AND place_of_service=qArg11 LIMIT 1); 
 IF vm_enc_nr IS NULL THEN

  SET vm_enc_nr=CONCAT('31',SUBSTRING(qArg5,3,8),LPAD(qArg00,11,'0'));  

  SET procedure_type=qArg11;
  SET vtmp = (SELECT Option_Label FROM option_code_values WHERE Column_Order=1119 AND Option_Value=procedure_type LIMIT 1);
  IF vtmp IS NOT NULL THEN SET procedure_type=vtmp; END IF;
  IF qArg12<>"~" AND qArg12<>"" THEN
   IF qArg12=1 THEN SET procedure_type="Outpatient Emergent"; 
   ELSEIF qArg12=2 THEN SET procedure_type="Outpatient Urgent"; 
   ELSEIF qArg12=3 THEN SET procedure_type="Outpatient Elective"; END IF;
  END IF;

  SET v1tmp=0; IF qArg16="1" THEN SET v1tmp=1; END IF;

  INSERT INTO cclf_encounter SET map_data_status=v1tmp,modify_time=NOW(),create_time=NOW(),mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,create_id='mra_sch_import_claim',encounter_status='admitted',mra_proc_type_nr=mv_proc_type_nr,encounter_class_nr='9',is_discharged='0',report_status='1',mm_curr_mbi_id=qArg6,origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,hospital_nr=mHospNr,current_att_dr_nr=mToPersonelNr,encounter_date=qArg4,discharge_date=qArg8,discharge_time="",encounter_type=procedure_type,place_of_service=qArg11,pos=qArg11,ATNDG_PRVDR_NPI_NUM=qArg2,PRVDR_OSCAR_NUM=qArg9,FAC_PRVDR_NPI_NUM=qArg7,CUR_CLM_UNIQ_ID=qArg01,CLM_EFCTV_DT=qArg22,CLM_CNTL_NUM=qArg26,CLM_ADJSMT_TYPE_CD=qArg16,mm_imp_job_nr=qArg24,CLM_BLG_PRVDR_OSCAR_NUM=qArg17,CLM_BLG_PRVDR_NPI_NUM=qArg18,CLM_BILL_FAC_TYPE_CD=qArg10,CLM_BILL_CLSFCTN_CD=qArg27,CLM_MDCR_NPMT_RSN_CD=qArg28,CLM_ADMSN_TYPE_CD=qArg13,CLM_ADMSN_SRC_CD=qArg14,CLM_AMT_PD=@mfamount;

  SET vtmp = (SELECT Option_Label FROM option_code_values WHERE Column_Order=86 AND Option_Value=qArg15 LIMIT 1);
  IF vtmp IS NULL THEN SET vtmp=qArg15; END IF;
  INSERT IGNORE INTO cclf_procedure_discharge SET encounter_nr=vm_enc_nr,discharge_type=qArg15,discharge_date=qArg8,discharge_to=vtmp,discharge_loc=vtmp,discharge_comments=vtmp,created_by='mra_sch_import_claim',create_date=NOW();
  INSERT INTO cclf_encounter_procedure SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,comments='mra_sch_import_claim',encounter_nr=vm_enc_nr,procedure_type=procedure_type,procedure_date=qArg4,procedure_center=mproc_center,interventionalist=to_personell_name,prcedure_op_type=1;
  
  INSERT INTO cclf_study_report_billing SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,created_date=NOW(),created_by='mra_sch_import_claim',Patient_Id=mMBI_IDNEW,encounter_nr=vm_enc_nr,Procedure_Type=procedure_type,CLM_ADJSMT_TYPE_CD=qArg16,CLM_BILL_FAC_TYPE_CD=qArg10,CLM_TYPE_CD=qArg11,CLM_OP_SRVC_TYPE_CD=qArg12,CLM_ADMSN_TYPE_CD=qArg13,CLM_ADMSN_SRC_CD=qArg14,CLM_AMT_PD=@mfamount;

  INSERT INTO mtm_encounter SET encounter_nr=vm_enc_nr,origid=mMBI_IDNEW,encounter_date=qArg4,CLM_BLG_PRVDR_OSCAR_NUM=qArg17,place_of_service=qArg11; 
 ELSE

  CALL MRA_IMP3_M01ENC_99_01(vm_enc_nr);

  SET v1tmp=0; IF qArg16="1" THEN SET v1tmp=1; END IF;
  #set @mmnotes=concat('c1-',v1tmp,'-',now());post_encounter_notes=@mmnotes,
  UPDATE cclf_encounter SET map_data_status=v1tmp,modify_time=NOW(),mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,CUR_CLM_UNIQ_ID=qArg01,PRVDR_OSCAR_NUM=qArg9,FAC_PRVDR_NPI_NUM=qArg7,hospital_nr=mHospNr,current_att_dr_nr=mToPersonelNr,discharge_date=qArg8,place_of_service=qArg11,pos=qArg11,ATNDG_PRVDR_NPI_NUM=qArg2,CLM_EFCTV_DT=qArg22,CLM_ADJSMT_TYPE_CD=qArg16,CLM_CNTL_NUM=qArg26,CLM_BLG_PRVDR_OSCAR_NUM=qArg17,CLM_BLG_PRVDR_NPI_NUM=qArg18,CLM_BILL_FAC_TYPE_CD=qArg10,CLM_BILL_CLSFCTN_CD=qArg27,CLM_MDCR_NPMT_RSN_CD=qArg28,CLM_ADMSN_TYPE_CD=qArg13,CLM_ADMSN_SRC_CD=qArg14,CLM_AMT_PD=@mfamount,mm_imp_job_nr=qArg24 WHERE encounter_nr=vm_enc_nr;

 END IF; 

 IF (qArg11="60" OR qArg11="61" OR qArg11="20" OR qArg11="30") THEN
  SET vtmp = (SELECT t1.nr FROM mra_file_static.mra_cclf2 t1 INNER JOIN mra_file_static.mra_cclf1 t2 ON t2.CUR_CLM_UNIQ_ID=t1.CUR_CLM_UNIQ_ID WHERE t2.map_data_status=0 AND t2.`BENE_MBI_ID`=qArg6 AND t2.`CLM_FROM_DT`=qArg4 AND t2.`CLM_BLG_PRVDR_OSCAR_NUM`=qArg17 AND t2.CUR_CLM_UNIQ_ID=qArg01 LIMIT 1);
  IF vtmp IS NULL THEN
   CALL MRA_IMP1_C21CLF_P1_m41_c2(ms01vv,vm_enc_nr,qArg00);
  ELSE
   CALL MRA_IMP1_C21CLF_P1_m41_c1(ms01vv,vm_enc_nr,qArg6,qArg4,qArg17,qArg01);
  END IF; 
 ELSE 
  CALL MRA_IMP1_C21CLF_P1_m41_c1(ms01vv,vm_enc_nr,qArg6,qArg4,qArg17,qArg01);
 END IF;

 CALL MRA_IMP1_C21CLF_P1_m42_c1(ms01vv,vm_enc_nr,qArg6,qArg4,qArg17,qArg01,mMBI_IDNEW); 

 CALL MRA_01_Cal_EncHccScore_11(vm_enc_nr);

 INSERT INTO mra1_encounter_logs SET mcreate_id='system',map_data_src=qMapDatSrc,encounter_nr=vm_enc_nr,patient_id=qArg6,proc_type_nr=mv_proc_type_nr,m_notes='',mSrcInserted_Type='mra_cclf1',mSrcInserted_ID=qArg00,mm_imp_job_nr=qArg24;

 UPDATE mra_file_static.mra_cclf1 SET map_data_status=2,map_process_status=1 WHERE map_data_status=0 AND BENE_MBI_ID=qArg6 AND CLM_FROM_DT=qArg4 AND CLM_BLG_PRVDR_OSCAR_NUM=qArg17 AND CUR_CLM_UNIQ_ID=qArg01; 

  SET @mg2vv=qArg00; if m1i=0 then SET @mg1vv=qArg00; end if;
