/* Procedure structure for procedure `MRA_IMP1_C21CLF_P1_m41_c1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P1_m41_c1`(ms01vv VARCHAR(20), mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100))
BEGIN

DECLARE mvID BIGINT; DECLARE modifiers VARCHAR(100); DECLARE mm1 INT DEFAULT 1;
DECLARE bmc INT DEFAULT 0;

DECLARE qArg00 VARCHAR(100);DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(100);DECLARE qArg06 VARCHAR(100);DECLARE qArg07 VARCHAR(100);

DECLARE mrw CURSOR FOR SELECT DISTINCT t1.nr,t1.`CUR_CLM_UNIQ_ID`,t1.`CLM_LINE_NUM`,t1.`CLM_LINE_HCPCS_CD`,t1.`CLM_LINE_CVRD_PD_AMT`,CONCAT(t1.`HCPCS_1_MDFR_CD`,',',t1.`HCPCS_2_MDFR_CD`,',',t1.`HCPCS_3_MDFR_CD`,',',t1.`HCPCS_4_MDFR_CD`,',',t1.`HCPCS_5_MDFR_CD`) AS modifiers,t2.CLM_ADJSMT_TYPE_CD,t1.CLM_LINE_PROD_REV_CTR_CD FROM mra_file_static.mra_cclf2 t1 INNER JOIN mra_file_static.mra_cclf1 t2 ON t2.CUR_CLM_UNIQ_ID=t1.CUR_CLM_UNIQ_ID WHERE t2.map_data_status=0 AND t2.`BENE_MBI_ID`=mpp2 AND t2.`CLM_FROM_DT`=mpp3 AND t2.`CLM_BLG_PRVDR_OSCAR_NUM`=mpp4 and t2.CUR_CLM_UNIQ_ID=mpp5;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

START TRANSACTION;

UPDATE cclf_study_report_billing_codes SET cal_amount=0 WHERE encounter_nr=mpp1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05,qArg06,qArg07;
 IF bmc = 0 THEN

 SET modifiers=REPLACE(qArg05,"~",","); SET modifiers=REPLACE(modifiers,",,",","); SET modifiers=REPLACE(modifiers,",,",",");
 SET modifiers=REPLACE(modifiers,",,",","); SET modifiers=REPLACE(modifiers,",,",","); SET modifiers=REPLACE(modifiers,",,",",");

 IF qArg06 <> "1" THEN
  IF qArg06= "0" THEN 
   SET mvID=(SELECT ID FROM cclf_study_report_billing_codes WHERE encounter_nr=mpp1 AND Billing_Code=qArg03 AND CLM_LINE_NUM=qArg02 AND CUR_CLM_UNIQ_ID=qArg01 LIMIT 1);
  else 
   SET mvID=(SELECT ID FROM cclf_study_report_billing_codes WHERE encounter_nr=mpp1 AND Billing_Code=qArg03 AND CLM_LINE_NUM=qArg02 LIMIT 1);
  END IF;

  IF mvID IS not NULL THEN
   update cclf_study_report_billing_codes set mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,modified_date=NOW(),`modifier`=modifiers,cal_amount=qArg04,Billing_Code=qArg03,CLM_ADJSMT_TYPE_CD=qArg06,CLM_LINE_PROD_REV_CTR_CD=qArg07 where ID=mvID;
  else 
   INSERT IGNORE INTO cclf_study_report_billing_codes SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,created_date=now(),modified_date=NOW(),Billing_Id=0,encounter_nr=mpp1,`count`='1',`modifier`=modifiers,Billing_Type='P',cpt_code_order_num=qArg02,cal_amount=qArg04,Billing_Code=qArg03,CLM_ADJSMT_TYPE_CD=qArg06,CLM_LINE_PROD_REV_CTR_CD=qArg07,CUR_CLM_UNIQ_ID=qArg01,CLM_LINE_NUM=qArg02;
  END IF;
 END IF;

 END IF;

END LOOP;
CLOSE mrw;

COMMIT;

END */$$
DELIMITER ;

