DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P1_m41_c2`(ms01vv VARCHAR(20), mpp1 BIGINT, mpp2 BIGINT)
BEGIN

DECLARE mvID BIGINT; DECLARE mm1 INT DEFAULT 1;
DECLARE bmc INT DEFAULT 0;

DECLARE qArg00 VARCHAR(10);DECLARE qArg01 VARCHAR(50);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);
DECLARE mrw CURSOR FOR SELECT nr,`CLM_ADJSMT_TYPE_CD`,`DGNS_DRG_CD`,`CLM_PMT_AMT`,CUR_CLM_UNIQ_ID FROM mra_file_static.mra_cclf1 WHERE nr=mpp2;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

START TRANSACTION;

UPDATE cclf_study_report_billing_codes SET cal_amount=0 WHERE encounter_nr=mpp1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04;
 IF bmc = 0 THEN

 IF qArg01 <> "1" THEN 
  IF qArg01="0" THEN 
   SET mvID= (SELECT ID FROM cclf_study_report_billing_codes WHERE encounter_nr=mpp1 AND Billing_Code=qArg02 AND CUR_CLM_UNIQ_ID=qArg04 LIMIT 1);
  else 
   SET mvID= (SELECT ID FROM cclf_study_report_billing_codes WHERE encounter_nr=mpp1 AND Billing_Code=qArg02 LIMIT 1); 
  END IF;

  IF mvID IS NULL THEN 
   INSERT IGNORE INTO cclf_study_report_billing_codes SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,created_date=now(),modified_date=NOW(),Billing_Id=0, encounter_nr=mpp1,COUNT='1',`modifier`='', Billing_Type='P',cpt_code_order_num=mm1,cal_amount=qArg03,Billing_Code=qArg02, CLM_ADJSMT_TYPE_CD=qArg01,CUR_CLM_UNIQ_ID=qArg04;
   SET mm1=mm1+1;
  ELSE  
   UPDATE cclf_study_report_billing_codes SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,modified_date=NOW(),cal_amount=qArg03,CLM_ADJSMT_TYPE_CD=qArg01, CUR_CLM_UNIQ_ID=qArg04 WHERE ID=mvID;
  END IF;
 END IF;

 END IF;
END LOOP;
CLOSE mrw;

COMMIT;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_C21CLF_P1_m42_c1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P1_m42_c1`(ms01vv VARCHAR(20),mpp1 BIGINT,mpp2 VARCHAR(100),mpp3 VARCHAR(100),mpp4 VARCHAR(100),mpp5 VARCHAR(100),mpp6 VARCHAR(100))
BEGIN

DECLARE vtmp VARCHAR(100); DECLARE bmc INT DEFAULT 0; 
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);

DECLARE mrw CURSOR FOR SELECT `nr`,CUR_CLM_UNIQ_ID,`CLM_ADJSMT_TYPE_CD` FROM mra_file_static.mra_cclf1 WHERE BENE_MBI_ID=mpp2 AND CLM_FROM_DT=mpp3 AND CLM_BLG_PRVDR_OSCAR_NUM=mpp4 AND CUR_CLM_UNIQ_ID=mpp5 AND map_data_status=0;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

START TRANSACTION;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02; 
 IF bmc = 0 THEN
  
  DELETE FROM cclf_encounter_icd_codes WHERE encounter_nr=mpp1;  
  IF qArg02 <> "1" THEN
   CALL MRA_IMP1_C21CLF_P1_m42_e1(ms01vv,mpp1,mpp2,mpp3,mpp4,qArg01,mpp6);
   CALL MRA_IMP1_C21CLF_P1_m42_e2(ms01vv,mpp1,mpp2,mpp3,mpp4,qArg01,mpp6);
   CALL MRA_IMP1_C21CLF_P1_m42_e3(ms01vv,mpp1,mpp2,mpp3,mpp4,qArg01,mpp6);
  END IF;

 END IF;
END LOOP;
CLOSE mrw;

COMMIT;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_C21CLF_P1_m42_e1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P1_m42_e1`(ms01vv VARCHAR(30),mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100), mpp6 VARCHAR(100))
BEGIN

DECLARE mm1 INT DEFAULT 1; DECLARE vm_probdesc VARCHAR(100);DECLARE prob_type VARCHAR (100);
DECLARE bmc INT DEFAULT 0; DECLARE qArg0 BIGINT;DECLARE qArg1 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);
DECLARE mrw CURSOR FOR SELECT nr,`BENE_MBI_ID`,`CLM_FROM_DT`,IF (LENGTH(`PRNCPL_DGNS_CD`)>3,CONCAT(SUBSTR(`PRNCPL_DGNS_CD`,1,3),'.',SUBSTR(`PRNCPL_DGNS_CD`,4)),`PRNCPL_DGNS_CD`) AS `PRNCPL_DGNS_CD`,
IF (LENGTH(`ADMTG_DGNS_CD`)>3,CONCAT(SUBSTR(`ADMTG_DGNS_CD`,1,3),'.',SUBSTR(`ADMTG_DGNS_CD`,4)),`ADMTG_DGNS_CD`) AS `ADMTG_DGNS_CD`,CUR_CLM_UNIQ_ID FROM mra_file_static.mra_cclf1 WHERE `BENE_MBI_ID`=mpp2 AND `CLM_FROM_DT`=mpp3 AND CLM_BLG_PRVDR_OSCAR_NUM=mpp4 and CUR_CLM_UNIQ_ID=mpp5 AND map_data_status=0;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

START TRANSACTION;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg0,qArg1,qArg2,qArg3,qArg4,qArg5; 

 IF bmc = 0 then
 IF qArg3<>"~" AND qArg3<>"" THEN
  SET prob_type="Principal"; SET vm_probdesc = MRA_FN21_GetIcdDescription(qArg3);
  INSERT IGNORE INTO cclf_encounter_icd_codes SET mra_clm_refer_num=qArg0,mra_clm_refer_m01=ms01vv,patient_id=mpp6,`onset_date`=qArg2,diagnosis_type='Diagnosis',encounter_nr=mpp1, diagnosis_code=qArg3,`diagnosis_desc`=vm_probdesc,SNOMED_CID='',SNOMED_FSN='',`status`='Active',problem_type=prob_type,`created_by`='mra_sch_import_claim',`created_date`=NOW();
 END IF;
 
 IF qArg4<>"~" AND qArg4<>"" THEN
  SET prob_type="Admitting"; SET vm_probdesc = MRA_FN21_GetIcdDescription(qArg4);
  INSERT IGNORE INTO cclf_encounter_icd_codes SET mra_clm_refer_num=qArg0,mra_clm_refer_m01=ms01vv,patient_id=mpp6,`onset_date`=qArg2,diagnosis_type='Diagnosis',encounter_nr=mpp1, diagnosis_code=qArg4,`diagnosis_desc`=vm_probdesc,SNOMED_CID='',SNOMED_FSN='',`status`='Active',problem_type=prob_type,`created_by`='mra_sch_import_claim',`created_date`=NOW();
 END IF;

 SET mm1=mm1+1;
 END IF;

END LOOP;
CLOSE mrw;

COMMIT;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_C21CLF_P1_m42_e2` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P1_m42_e2`(ms01vv VARCHAR(30),mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100), mpp6 VARCHAR(100))
BEGIN

DECLARE mm1 INT DEFAULT 1; DECLARE vm_probdesc VARCHAR(100); DECLARE bmc INT DEFAULT 0;
DECLARE qArg0 BIGINT;DECLARE qArg1 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 BIGINT;DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);DECLARE qArg7 VARCHAR(100);DECLARE qArg8 VARCHAR(100);DECLARE qArg9 VARCHAR(100);DECLARE qArg10 VARCHAR(100);
DECLARE mrw CURSOR FOR SELECT nr,`CUR_CLM_UNIQ_ID`,`BENE_MBI_ID`,`CLM_TYPE_CD`,`CLM_VAL_SQNC_NUM`,`CLM_PRCDR_CD`,`CLM_PRCDR_PRFRM_DT`,`CLM_FROM_DT`,`CLM_THRU_DT`,`DGNS_PRCDR_ICD_IND` FROM mra_file_static.mra_cclf3 WHERE `BENE_MBI_ID`=mpp2 AND `CLM_FROM_DT`=mpp3 AND CUR_CLM_UNIQ_ID=mpp5 and map_data_status=0;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

START TRANSACTION;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg0,qArg1,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8,qArg9; 
 IF bmc = 0 AND qArg5<>"~" AND qArg5<>"" THEN

 IF LENGTH(qArg5)>3 AND qArg5 NOT LIKE '%.%' THEN
  SET qArg5=CONCAT(SUBSTR(qArg5,1,3),'.',SUBSTR(qArg5,4));
 END IF;

 SET vm_probdesc = MRA_FN21_GetIcdDescription(qArg5);

 INSERT IGNORE INTO cclf_encounter_icd_codes SET mra_clm_refer_num=qArg0,mra_clm_refer_m01=ms01vv,icd_order=qArg4,patient_id=mpp6,`onset_date`=qArg6,diagnosis_type='Diagnosis',encounter_nr=mpp1, diagnosis_code=qArg5,`diagnosis_desc`=vm_probdesc,SNOMED_CID='',SNOMED_FSN='',`status`='Active',problem_type="",`created_by`='mra_sch_import_claim',`created_date`=NOW();
 
 END IF;
 SET mm1=mm1+1;
 
END LOOP;
CLOSE mrw;

COMMIT;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_C21CLF_P1_m42_e3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P1_m42_e3`(ms01vv VARCHAR(30),mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100), mpp6 VARCHAR(100))
BEGIN

DECLARE mm1 INT DEFAULT 1;
DECLARE vm_probdesc VARCHAR(100);
DECLARE bmc INT DEFAULT 0;
DECLARE qArg0 BIGINT;DECLARE qArg1 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 BIGINT;DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);DECLARE qArg7 VARCHAR(100);DECLARE qArg8 VARCHAR(100);DECLARE qArg9 VARCHAR(100);DECLARE qArg10 VARCHAR(100);DECLARE qArg11 VARCHAR(100);
DECLARE mrw CURSOR FOR SELECT `nr`,`CUR_CLM_UNIQ_ID`,`BENE_MBI_ID`,`CLM_TYPE_CD`,`CLM_PROD_TYPE_CD`,`CLM_VAL_SQNC_NUM`,`CLM_DGNS_CD`,IF (LENGTH(`CLM_DGNS_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_CD`,1,3),'.',SUBSTR(`CLM_DGNS_CD`,4)),`CLM_DGNS_CD`) AS diag_code,`PRVDR_OSCAR_NUM`,`CLM_FROM_DT`,`CLM_THRU_DT`,`DGNS_PRCDR_ICD_IND` FROM mra_file_static.mra_cclf4 WHERE `BENE_MBI_ID`=mpp2 AND `CLM_FROM_DT`=mpp3 AND CUR_CLM_UNIQ_ID=mpp5 and map_data_status=0;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

START TRANSACTION;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg0,qArg1,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8,qArg9,qArg10,qArg11; 
 IF bmc = 0 AND qArg7<>"~" AND qArg7<>"" THEN
 SET vm_probdesc = MRA_FN21_GetIcdDescription(qArg7);

 INSERT IGNORE INTO cclf_encounter_icd_codes SET mra_clm_refer_num=qArg0,mra_clm_refer_m01=ms01vv,icd_order=qArg5,patient_id=mpp6,`onset_date`=qArg9,diagnosis_type='Diagnosis',encounter_nr=mpp1, diagnosis_code=qArg7,`diagnosis_desc`=vm_probdesc,SNOMED_CID='',SNOMED_FSN='',`status`='Active',problem_type=qArg11,`created_by`='mra_sch_import_claim',`created_date`=NOW();
 END IF;

 SET mm1=mm1+1;
 
END LOOP;
CLOSE mrw;

COMMIT;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_C21CLF_P2_k3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P2_k3`(m1pp tinyINT)
BEGIN

DECLARE mmi INT; DECLARE m2mi INT; DECLARE m3mi INT;
DECLARE vtmp VARCHAR(100); 

TRUNCATE mra1_311_m1;
INSERT INTO mra1_311_m1 (mdd_1,mdd_2,mdd_3)
SELECT DISTINCT t1.BENE_MBI_ID,1,mradb_prod.MRA_FN01_GetPatientIDLastCCLF(t1.BENE_MBI_ID) 
FROM mra_file_static.mra_cclf5 t1 WHERE t1.map_data_status=0 AND t1.CLM_CARR_PMT_DNL_CD != "0";

SET m3mi = (SELECT COUNT(mdd_1) FROM mra1_311_m1); SET m3mi = CEIL(m3mi/m1pp);
SET mmi = 1;

LOOP_M01: LOOP
 SET m2mi= ((mmi-1)*m3mi ) +1;
 UPDATE mra1_311_m1 SET mdd_2=mmi WHERE nr BETWEEN m2mi AND (m2mi+(m3mi-1)); 
 IF mmi > m1pp THEN LEAVE  LOOP_M01;  END  IF;
 SET mmi = mmi + 1;
 ITERATE LOOP_M01;
END LOOP;

UPDATE mra1_311_m1 SET mdd_1='a123z' WHERE mdd_1='' OR mdd_1 IS NULL;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_C21CLF_P2_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P2_m3`(mpp1 SMALLINT,mpp2 BIGINT,mpp3 VARCHAR(100),mpp4 SMALLINT)
BEGIN

DECLARE bmc INT DEFAULT 0;DECLARE _rollback TINYINT DEFAULT 0;DECLARE m1i INT DEFAULT 0;

DECLARE vtmp VARCHAR(100); DECLARE v1tmp INT; DECLARE mMBI_IDNEW VARCHAR(100) CHARACTER SET latin1;
DECLARE mv_proc_type_nr SMALLINT DEFAULT 2; DECLARE ms01vv VARCHAR(20); 
DECLARE procedure_type VARCHAR(50); DECLARE m_personell_name VARCHAR(100) CHARACTER SET latin1; DECLARE vm_enc_nr BIGINT;
DECLARE mToPersonelNr INT; DECLARE mHospNr BIGINT;

DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg2 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);DECLARE qArg7 VARCHAR(100);DECLARE qArg8 VARCHAR(100);DECLARE qArg9 VARCHAR(100);DECLARE qArg10 VARCHAR(100);DECLARE qArg11 VARCHAR(100);DECLARE qArg12 VARCHAR(100);DECLARE qArg13 VARCHAR(100);DECLARE qArg14 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg15 VARCHAR(100);DECLARE qArg16 VARCHAR(100); DECLARE qArg17 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg18 VARCHAR(100);DECLARE qArg19 VARCHAR(20);DECLARE qArg20 VARCHAR(100) CHARACTER SET latin1; DECLARE qArg21 INT;

DECLARE msgVR01 VARCHAR(100);DECLARE msgVR02 VARCHAR(200);

DECLARE mrw CURSOR FOR SELECT t1.`nr`,t1.`CUR_CLM_UNIQ_ID`,t1.`BENE_MBI_ID`,t1.CLM_FED_TYPE_SRVC_CD,t1.`CLM_TYPE_CD`,t1.`CLM_FROM_DT`,t1.`CLM_THRU_DT`,CONCAT(SUBSTR(t1.`CLM_FROM_DT`,1,4),SUBSTR(t1.`CLM_FROM_DT`,6,2),SUBSTR(t1.`CLM_FROM_DT`,9,2)) AS encounter_date,t1.`RNDRG_PRVDR_TYPE_CD`,t1.`RNDRG_PRVDR_FIPS_ST_CD`,t1.`CLM_PRVDR_SPCLTY_CD`,t1.`CLM_POS_CD`,t1.`CLM_LINE_PRMRY_PYR_CD`,t1.`CLM_RNDRG_PRVDR_TAX_NUM`,t1.`RNDRG_PRVDR_NPI_NUM`,t1.CLM_ADJSMT_TYPE_CD,t1.CLM_PRVDR_SPCLTY_CD,t1.CLM_RNDRG_PRVDR_NPI_NUM,t1.CLM_RFRG_PRVDR_NPI_NUM,t1.CLM_EFCTV_DT,t1.CLM_CNTL_NUM,t1.mm_imp_job_nr,t2.mdd_3 FROM mra_file_static.mra_cclf5 t1 INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=t1.BENE_MBI_ID COLLATE latin1_swedish_ci WHERE t2.mdd_2=mpp1 and t1.map_data_status=0 AND t1.CLM_CARR_PMT_DNL_CD != "0" GROUP BY t1.CLM_FROM_DT,t1.RNDRG_PRVDR_NPI_NUM,t1.CLM_CNTL_NUM,t1.CUR_CLM_UNIQ_ID ORDER BY t1.mm_imp_job_nr,t1.CLM_EFCTV_DT,t1.CUR_CLM_UNIQ_ID,t1.`nr`;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
BEGIN
 SET _rollback = 1;
 GET DIAGNOSTICS CONDITION 1
 msgVR01 = RETURNED_SQLSTATE, msgVR02 = MESSAGE_TEXT;
END;

CREATE TEMPORARY TABLE `mtm_encounter`(`encounter_nr` BIGINT,`origid` VARCHAR(100),`ATNDG_PRVDR_NPI_NUM` VARCHAR(50),`encounter_date` DATE,`CLM_CNTL_NUM` VARCHAR(100),KEY `mkey01`(`encounter_nr`),KEY `mkey02`(`origid`),KEY `mkey03`(`ATNDG_PRVDR_NPI_NUM`),KEY `mkey04`(`encounter_date`),KEY `mkey05`(`CLM_CNTL_NUM`)) ENGINE=INNODB DEFAULT CHARSET=latin1;

INSERT INTO mtm_encounter(encounter_nr,encounter_date,origid,ATNDG_PRVDR_NPI_NUM,CLM_CNTL_NUM)
SELECT e.encounter_nr,DATE_FORMAT(e.encounter_date,'%Y-%m-%d'),e.origid,e.ATNDG_PRVDR_NPI_NUM,e.CLM_CNTL_NUM 
FROM cclf_encounter AS e INNER JOIN mra1_311_m1 t2 ON t2.mdd_3=e.origid
WHERE e.mra_proc_type_nr=mv_proc_type_nr AND t2.mdd_2=mpp1;

INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='m01Call',mdd_3=CONCAT('c2-',mpp1);

SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
START TRANSACTION;

SET @mg1vv=0; SET @mg2vv=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 
 FETCH mrw INTO qArg00,qArg01,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8,qArg9,qArg10,qArg11,qArg12,qArg13,qArg14,qArg15,qArg16,qArg17,qArg18,qArg19,qArg20,qArg21,mMBI_IDNEW;
 IF bmc = 0 THEN

 SET ms01vv = "mclf5_b";
 IF qArg14<>'~' THEN CALL MRA_IMP_FUNC_Personell(qArg14); END IF;
 IF qArg17<>'~' THEN CALL MRA_IMP_FUNC_Personell(qArg17); END IF;

 SET mHospNr= -3; SET mToPersonelNr=1; SET m_personell_name=qArg14;
 SET vtmp = (SELECT nr FROM personell WHERE npr_id=m_personell_name COLLATE latin1_swedish_ci LIMIT 1);
 IF vtmp IS NOT NULL THEN
  SET mToPersonelNr=vtmp; SET m_personell_name=(SELECT `name` FROM personell WHERE nr=mToPersonelNr LIMIT 1);
 END IF;

 SET vm_enc_nr=(SELECT encounter_nr FROM mtm_encounter WHERE origid=mMBI_IDNEW AND encounter_date=qArg5 AND ATNDG_PRVDR_NPI_NUM=qArg14 AND CLM_CNTL_NUM=qArg20 LIMIT 1); 

 IF vm_enc_nr IS NULL THEN

 SET vm_enc_nr=CONCAT('32',SUBSTRING(qArg7,3,8),LPAD(qArg00,11,'0'));

 SET procedure_type=qArg11;
 SET vtmp = (SELECT Option_Label FROM option_code_values WHERE Column_Order=1120 AND Option_Value=procedure_type LIMIT 1);
 IF vtmp IS NOT NULL THEN SET procedure_type=vtmp; END IF;

 SET v1tmp=0; IF qArg15="1" THEN SET v1tmp=1; END IF; 

 INSERT INTO cclf_encounter SET map_data_status=v1tmp,modify_time=NOW(),create_time=NOW(),mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,create_id='mra_sch_import_claim',encounter_status='admitted',mra_proc_type_nr=mv_proc_type_nr,encounter_class_nr='10',is_discharged='0',report_status='1',mm_curr_mbi_id=qArg2,origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,mhos_cent_nr=mHospNr,current_att_dr_nr=mToPersonelNr,encounter_date=qArg5,discharge_date=qArg6,discharge_time="",encounter_type=procedure_type,place_of_service=qArg11,pos=qArg11,CLM_PRVDR_SPCLTY_CD=qArg16,ATNDG_PRVDR_NPI_NUM=qArg14,CUR_CLM_UNIQ_ID=qArg01,CLM_EFCTV_DT=qArg19,CLM_ADJSMT_TYPE_CD=qArg15,CLM_CNTL_NUM=qArg20,RNDRG_PRVDR_TYPE_CD=qArg8,CLM_RNDRG_PRVDR_TAX_NUM=qArg13,CLM_RNDRG_PRVDR_NPI_NUM=qArg17,mm_imp_job_nr=qArg21;

 INSERT INTO cclf_encounter_procedure SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,comments='mra_sch_import_claim',encounter_nr=vm_enc_nr,procedure_type=procedure_type,procedure_date=qArg5,procedure_center="NA",interventionalist=m_personell_name,prcedure_op_type=1;
 INSERT INTO cclf_study_report_billing SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,created_date=NOW(),created_by='mra_sch_import_claim',Patient_Id=mMBI_IDNEW,encounter_nr=vm_enc_nr,Procedure_Type=procedure_type,CLM_ADJSMT_TYPE_CD=qArg15;
 INSERT INTO mtm_encounter SET encounter_nr=vm_enc_nr,origid=mMBI_IDNEW,encounter_date=qArg5,ATNDG_PRVDR_NPI_NUM=qArg14,CLM_CNTL_NUM=qArg20;
ELSE

  CALL MRA_IMP3_M01ENC_99_01(vm_enc_nr);

  SET v1tmp=0; IF qArg15="1" THEN SET v1tmp=1; END IF;  

  UPDATE cclf_encounter SET map_data_status=v1tmp,modify_time=NOW(),mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,mhos_cent_nr=mHospNr,current_att_dr_nr=mToPersonelNr,discharge_date=qArg6,place_of_service=qArg11,pos=qArg11,CLM_PRVDR_SPCLTY_CD=qArg16,ATNDG_PRVDR_NPI_NUM=qArg14,CUR_CLM_UNIQ_ID=qArg01,CLM_EFCTV_DT=qArg19,CLM_ADJSMT_TYPE_CD=qArg15,CLM_CNTL_NUM=qArg20,RNDRG_PRVDR_TYPE_CD=qArg8,CLM_RNDRG_PRVDR_TAX_NUM=qArg13,CLM_RNDRG_PRVDR_NPI_NUM=qArg17,mm_imp_job_nr=qArg21 WHERE encounter_nr=vm_enc_nr;

END IF; 

 CALL MRA_IMP1_C21CLF_P2_m41_c1(ms01vv,vm_enc_nr,qArg2,qArg5,qArg14,qArg20,qArg01);
 CALL MRA_IMP1_C21CLF_P2_m42_c1(ms01vv,vm_enc_nr,qArg2,qArg5,qArg14,qArg20,qArg01,mMBI_IDNEW);

 CALL MRA_01_Cal_EncHccScore_11(vm_enc_nr);

 INSERT INTO mra1_encounter_logs SET map_data_src=1,encounter_nr=vm_enc_nr,patient_id=qArg01,proc_type_nr=mv_proc_type_nr,m_notes='',mcreate_id='system',mSrcInserted_Type='mra_cclf5',mSrcInserted_ID=qArg00,mm_imp_job_nr=qArg21;

 UPDATE mra_file_static.mra_cclf5 SET map_data_status=2,map_process_status=1 WHERE map_data_status=0 AND BENE_MBI_ID=qArg2 COLLATE latin1_swedish_ci AND CLM_FROM_DT=qArg5 AND RNDRG_PRVDR_NPI_NUM=qArg14 COLLATE latin1_swedish_ci AND `CLM_CNTL_NUM`=qArg20 COLLATE latin1_swedish_ci AND CUR_CLM_UNIQ_ID=qArg01 COLLATE latin1_swedish_ci;

  SET @mg2vv=qArg00; if m1i=0 then SET @mg1vv=qArg00; end if;
