 IF vm_enc_nr IS NULL THEN

 SET vm_enc_nr=CONCAT('32',SUBSTRING(qArg7,3,8),LPAD(qArg00,11,'0'));

 SET procedure_type=qArg11;
 SET vtmp = (SELECT Option_Label FROM option_code_values WHERE Column_Order=1120 AND Option_Value=procedure_type LIMIT 1);
 IF vtmp IS NOT NULL THEN SET procedure_type=vtmp; END IF;

 SET v1tmp=0; IF qArg15="1" THEN SET v1tmp=1; END IF; 

 INSERT INTO cclf_encounter SET map_data_status=v1tmp,modify_time=NOW(),create_time=NOW(),mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,create_id='mra_sch_import_claim',encounter_status='admitted',mra_proc_type_nr=mv_proc_type_nr,encounter_class_nr='10',is_discharged='0',report_status='1',mm_curr_mbi_id=qArg2,origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,hospital_nr=mHospNr,current_att_dr_nr=mToPersonelNr,encounter_date=qArg5,discharge_date=qArg6,discharge_time="",encounter_type=procedure_type,place_of_service=qArg11,pos=qArg11,CLM_PRVDR_SPCLTY_CD=qArg16,ATNDG_PRVDR_NPI_NUM=qArg14,CUR_CLM_UNIQ_ID=qArg01,CLM_EFCTV_DT=qArg19,CLM_ADJSMT_TYPE_CD=qArg15,CLM_CNTL_NUM=qArg20,RNDRG_PRVDR_TYPE_CD=qArg8,CLM_RNDRG_PRVDR_TAX_NUM=qArg13,CLM_RNDRG_PRVDR_NPI_NUM=qArg17,mm_imp_job_nr=qArg21;

 INSERT INTO cclf_encounter_procedure SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,comments='mra_sch_import_claim',encounter_nr=vm_enc_nr,procedure_type=procedure_type,procedure_date=qArg5,procedure_center="NA",interventionalist=m_personell_name,prcedure_op_type=1;
 INSERT INTO cclf_study_report_billing SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,created_date=NOW(),created_by='mra_sch_import_claim',Patient_Id=mMBI_IDNEW,encounter_nr=vm_enc_nr,Procedure_Type=procedure_type,CLM_ADJSMT_TYPE_CD=qArg15;
