/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P2_m41_c1`(ms01vv VARCHAR(30), mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100), mpp6 VARCHAR(100))
BEGIN

DECLARE mvID BIGINT; DECLARE mm1 INT DEFAULT 1; DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg1 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(10);DECLARE qArg6 VARCHAR(100);DECLARE qArg7 VARCHAR(30);DECLARE qArg8 VARCHAR(30);

DECLARE mrw CURSOR FOR SELECT `nr`,`CLM_LINE_HCPCS_CD`,`CLM_FROM_DT`,`CLM_LINE_ALOWD_CHRG_AMT`,sum(`CLM_LINE_CVRD_PD_AMT`),`CLM_ADJSMT_TYPE_CD`,CONCAT(`HCPCS_1_MDFR_CD`,',',`HCPCS_2_MDFR_CD`,',',`HCPCS_3_MDFR_CD`,',',`HCPCS_4_MDFR_CD`,',',`HCPCS_5_MDFR_CD`) AS modifiers,CLM_PRCSG_IND_CD,CLM_CARR_PMT_DNL_CD FROM mra_file_static.mra_cclf5 WHERE `BENE_MBI_ID`=mpp2 COLLATE latin1_swedish_ci AND `CLM_FROM_DT`=mpp3 AND `RNDRG_PRVDR_NPI_NUM`=mpp4 COLLATE latin1_swedish_ci AND `CLM_CNTL_NUM`=mpp5 COLLATE latin1_swedish_ci AND `CUR_CLM_UNIQ_ID`=mpp6 COLLATE latin1_swedish_ci AND map_data_status=0 group by CLM_LINE_HCPCS_CD;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

