UPDATE cclf_study_report_billing_codes SET cal_amount=0 WHERE encounter_nr=mpp1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg1,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8; 
 IF bmc = 0 THEN

  SET qArg6=REPLACE(qArg6,"~",",");SET qArg6=REPLACE(qArg6,",,",",");SET qArg6=REPLACE(qArg6,",,",",");
  SET qArg6=REPLACE(qArg6,",,",",");SET qArg6=REPLACE(qArg6,",,",",");

  SET mvID = (SELECT ID FROM cclf_study_report_billing_codes WHERE encounter_nr=mpp1 AND Billing_Code=qArg1 COLLATE latin1_swedish_ci LIMIT 1);
  IF mvID IS NOT NULL THEN
   UPDATE cclf_study_report_billing_codes SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,modified_date=NOW(),`MODIFIER`=qArg6,cpt_code_order_num=mm1,cal_amount=qArg4,CLM_ADJSMT_TYPE_CD=qArg5,CLM_PRCSG_IND_CD=qArg7,CLM_MDCR_NPMT_RSN_CD=qArg8 WHERE ID=mvID;
  ELSE
   INSERT IGNORE INTO cclf_study_report_billing_codes SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,created_date=now(),modified_date=NOW(),Billing_Id=0,encounter_nr=mpp1,COUNT='1',`MODIFIER`=qArg6,Billing_Type='P',cpt_code_order_num=mm1,cal_amount=qArg4,cal2amount=0,Billing_Code=qArg1,CLM_ADJSMT_TYPE_CD=qArg5,CLM_PRCSG_IND_CD=qArg7,CLM_MDCR_NPMT_RSN_CD=qArg8;
  END IF;

  SET mm1=mm1+1;

 END IF;
