/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P2_m42_c1`(ms01vv VARCHAR(30), mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100), mpp6 VARCHAR(100), mpp7 VARCHAR(100))
