DECLARE mrw CURSOR FOR SELECT nr,IF (LENGTH(`CLM_LINE_DGNS_CD`)>3,CONCAT(SUBSTR(`CLM_LINE_DGNS_CD`,1,3),'.',SUBSTR(`CLM_LINE_DGNS_CD`,4)),`CLM_LINE_DGNS_CD`) AS diag_code,IF (LENGTH(`CLM_DGNS_1_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_1_CD`,1,3),'.',SUBSTR(`CLM_DGNS_1_CD`,4)),`CLM_DGNS_1_CD`) AS diag_code1,IF (LENGTH(`CLM_DGNS_2_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_2_CD`,1,3),'.',SUBSTR(`CLM_DGNS_2_CD`,4)),`CLM_DGNS_2_CD`) AS diag_code2,IF (LENGTH(`CLM_DGNS_3_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_3_CD`,1,3),'.',SUBSTR(`CLM_DGNS_3_CD`,4)),`CLM_DGNS_3_CD`) AS diag_code3,IF (LENGTH(`CLM_DGNS_4_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_4_CD`,1,3),'.',SUBSTR(`CLM_DGNS_4_CD`,4)),`CLM_DGNS_4_CD`) AS diag_code4,IF (LENGTH(`CLM_DGNS_5_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_5_CD`,1,3),'.',SUBSTR(`CLM_DGNS_5_CD`,4)),`CLM_DGNS_5_CD`) AS diag_code5,IF (LENGTH(`CLM_DGNS_6_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_6_CD`,1,3),'.',SUBSTR(`CLM_DGNS_6_CD`,4)),`CLM_DGNS_6_CD`) AS diag_code6,IF (LENGTH(`CLM_DGNS_7_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_7_CD`,1,3),'.',SUBSTR(`CLM_DGNS_7_CD`,4)),`CLM_DGNS_7_CD`) AS diag_code7,IF (LENGTH(`CLM_DGNS_8_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_8_CD`,1,3),'.',SUBSTR(`CLM_DGNS_8_CD`,4)),`CLM_DGNS_8_CD`) AS diag_code8,IF (LENGTH(`CLM_DGNS_9_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_9_CD`,1,3),'.',SUBSTR(`CLM_DGNS_9_CD`,4)),`CLM_DGNS_9_CD`) AS diag_code9,IF (LENGTH(`CLM_DGNS_10_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_10_CD`,1,3),'.',SUBSTR(`CLM_DGNS_10_CD`,4)),`CLM_DGNS_10_CD`) AS diag_code10,IF (LENGTH(`CLM_DGNS_11_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_11_CD`,1,3),'.',SUBSTR(`CLM_DGNS_11_CD`,4)),`CLM_DGNS_11_CD`) AS diag_code11,IF (LENGTH(`CLM_DGNS_12_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_12_CD`,1,3),'.',SUBSTR(`CLM_DGNS_12_CD`,4)),`CLM_DGNS_12_CD`) AS diag_code12 FROM mra_file_static.mra_cclf5 WHERE `BENE_MBI_ID`=mpp2 COLLATE latin1_swedish_ci AND `RNDRG_PRVDR_NPI_NUM`=mpp4 COLLATE latin1_swedish_ci AND `CLM_CNTL_NUM`=mpp5 COLLATE latin1_swedish_ci AND `CUR_CLM_UNIQ_ID`=mpp6 COLLATE latin1_swedish_ci AND `CLM_FROM_DT`=mpp3 AND map_data_status=0 GROUP BY CLM_LINE_HCPCS_CD ORDER BY nr DESC LIMIT 1;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

