read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg0,qArg1,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8,qArg9,qArg10,qArg11,qArg12,qArg13; 
