/* Procedure structure for procedure `MRA_IMP1_C21CLF_P3_k3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P3_k3`(m1pp tinyINT)
BEGIN

DECLARE mmi INT; DECLARE m2mi INT; DECLARE m3mi INT;
DECLARE vtmp VARCHAR(100); 

TRUNCATE mra1_311_m1;
INSERT INTO mra1_311_m1 (mdd_1,mdd_2,mdd_3)
SELECT DISTINCT t1.BENE_MBI_ID,1,mradb_prod.MRA_FN01_GetPatientIDLastCCLF(t1.BENE_MBI_ID) 
FROM mra_file_static.mra_cclf6 t1 WHERE t1.map_data_status=0;

SET m3mi = (SELECT COUNT(mdd_1) FROM mra1_311_m1); SET m3mi = CEIL(m3mi/m1pp);
SET mmi = 1;

LOOP_M01: LOOP
 SET m2mi= ((mmi-1)*m3mi ) +1;
 UPDATE mra1_311_m1 SET mdd_2=mmi WHERE nr BETWEEN m2mi AND (m2mi+(m3mi-1)); 
 IF mmi > m1pp THEN LEAVE  LOOP_M01;  END  IF;
 SET mmi = mmi + 1;
 ITERATE LOOP_M01;
END LOOP;

UPDATE mra1_311_m1 SET mdd_1='a123z' WHERE mdd_1='' OR mdd_1 IS NULL;

END */$$
DELIMITER ;

