  SET vtmp=(SELECT nr FROM personell WHERE npr_id=to_personell_name COLLATE latin1_swedish_ci LIMIT 1);
  IF vtmp IS NOT NULL THEN
   SET mToPersonelNr=vtmp; SET to_personell_name=(SELECT `name` FROM personell WHERE nr=mToPersonelNr LIMIT 1);
  END IF;
  SET procedure_type=qArg8;
  SET vtmp=(SELECT Option_Label FROM option_code_values WHERE Column_Order=1120 AND Option_Value=procedure_type LIMIT 1);
  IF vtmp IS NOT NULL THEN SET procedure_type=vtmp; END IF;

  INSERT INTO cclf_encounter SET mra_clm_refer_num=qArg00,modify_time=NOW(),create_time=NOW(),mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,create_id='mra_sch_import_claim',mra_proc_type_nr=mv_proc_type_nr,encounter_class_nr='12',encounter_status='admitted',is_discharged='0',report_status='1',mm_curr_mbi_id=qArg2,origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,mhos_cent_nr=@mHospNr,current_att_dr_nr=mToPersonelNr,encounter_date=qArg4,discharge_date=qArg5,discharge_time="",encounter_type=procedure_type,pos=qArg8,place_of_service=qArg8,ATNDG_PRVDR_NPI_NUM=qArg11,CLM_EFCTV_DT=qArg15,CLM_ADJSMT_TYPE_CD=qArg12,CLM_CNTL_NUM=qArg16,mm_imp_job_nr=qArg17;
