DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

START TRANSACTION;

UPDATE cclf_study_report_billing_codes SET cal_amount=0 WHERE encounter_nr=mpp1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg1,qArg2,qArg3,qArg4; 
 IF bmc = 0 THEN

  SET mvID = (SELECT ID FROM cclf_study_report_billing_codes WHERE encounter_nr=mpp1 AND Billing_Code=qArg1 COLLATE latin1_swedish_ci LIMIT 1);
  IF mvID IS NOT NULL THEN
   UPDATE cclf_study_report_billing_codes SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,modified_date=NOW(),cpt_code_order_num=mm1,Billing_Code=qArg1,cal_amount=qArg3,CLM_ADJSMT_TYPE_CD=qArg4 WHERE ID=mvID;
  ELSE
   INSERT IGNORE INTO cclf_study_report_billing_codes SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,created_date=now(),modified_date=NOW(),Billing_Id=0,encounter_nr=mpp1,`count`='1',`modifier`='',Billing_Type='P',cpt_code_order_num=mm1,Billing_Code=qArg1,cal_amount=qArg3,cal2amount=0,CLM_ADJSMT_TYPE_CD=qArg4;
  END IF;
  SET mm1=mm1+1;

 END IF;
END LOOP;
CLOSE mrw;

COMMIT;

END */$$
