/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P4_m41`(ms01vv VARCHAR(20), mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100))
BEGIN

DECLARE mvID BIGINT; DECLARE vtmp VARCHAR(100); DECLARE v2tmp TINYINT DEFAULT 0;
DECLARE vm_cptcode VARCHAR(100); DECLARE mm1 INT DEFAULT 1; DECLARE bmc INT DEFAULT 0;

DECLARE qArg00 BIGINT; DECLARE qArg1 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);

DECLARE mrw CURSOR FOR SELECT `nr`,`CLM_LINE_NDC_CD`,`CLM_LINE_BENE_PMT_AMT`,`CLM_ADJSMT_TYPE_CD` FROM mra_file_static.mra_cclf7 WHERE map_data_status=0 AND CLM_LINE_NDC_CD!='~' AND `BENE_MBI_ID`=mpp2 AND `CLM_LINE_FROM_DT`=mpp3 AND CLM_PRSBNG_PRVDR_GNRC_ID_NUM=mpp4 AND `CUR_CLM_UNIQ_ID`=mpp5;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

START TRANSACTION;

update cclf_study_report_billing_codes set cal_amount=0 WHERE encounter_nr=mpp1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg1,qArg2,qArg3; 
 IF bmc = 0 THEN
  SET vm_cptcode = CONCAT(SUBSTRING(qArg1,1,5),'-',SUBSTRING(qArg1,6,4),'-',SUBSTRING(qArg1,10,2));
  SET vtmp = (SELECT cpt_code FROM cpt_codes WHERE cpt_ndc_code=vm_cptcode LIMIT 1); 
  IF vtmp IS NOT NULL THEN SET vm_cptcode=vtmp; END IF;
  IF vm_cptcode IS NULL THEN SET vm_cptcode=qArg1; END IF;

  SET mvID = (SELECT ID FROM cclf_study_report_billing_codes WHERE encounter_nr=mpp1 AND Billing_Code=vm_cptcode COLLATE latin1_swedish_ci LIMIT 1);
  IF mvID IS NOT NULL THEN
   UPDATE cclf_study_report_billing_codes SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,modified_date=NOW(),cpt_code_order_num=mm1,cal_amount=qArg2,Billing_Code=vm_cptcode,CLM_ADJSMT_TYPE_CD=qArg3 WHERE ID=mvID;
  ELSE    
   INSERT IGNORE INTO cclf_study_report_billing_codes SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,created_date=now(),modified_date=NOW(),encounter_nr=mpp1,Billing_Id=0,`count`="1",`modifier`="",Billing_Type='P',cpt_code_order_num=mm1,cal_amount=qArg2,Billing_Code=vm_cptcode,CLM_ADJSMT_TYPE_CD=qArg3;
   SET mm1=mm1+1;
  END IF; 
 END IF;
END LOOP;
CLOSE mrw;

COMMIT;

END */$$
DELIMITER ;

