DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C21CLF_P4_m42`(ms01vv VARCHAR(20), mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100), mpp6 VARCHAR(100))
BEGIN

DECLARE vtmp VARCHAR(100); DECLARE mm1 INT DEFAULT 1; DECLARE bmc INT DEFAULT 0; 
DECLARE vm_s0v BIGINT; DECLARE vm_s1v VARCHAR(80);DECLARE vm_s2v VARCHAR(100); DECLARE vm_presdocname VARCHAR(100) DEFAULT '';
DECLARE qArg0 BIGINT;DECLARE qArg1 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);

DECLARE mrw CURSOR FOR SELECT `nr`,CLM_LINE_NDC_CD,CLM_LINE_FROM_DT,CLM_PRSBNG_PRVDR_GNRC_ID_NUM,CLM_LINE_DAYS_SUPLY_QTY,CLM_LINE_RX_FILL_NUM,CLM_LINE_SRVC_UNIT_QTY FROM mra_file_static.mra_cclf7 WHERE map_data_status=0 AND CLM_LINE_NDC_CD!='~' AND `BENE_MBI_ID`=mpp2 AND `CLM_LINE_FROM_DT`=mpp3 AND CLM_PRSBNG_PRVDR_GNRC_ID_NUM=mpp4 AND `CUR_CLM_UNIQ_ID`=mpp5;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

START TRANSACTION;

DELETE FROM cclf_encounter_patient_medication WHERE encounter_nr=mpp1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg0,qArg1,qArg2,qArg3,qArg4,qArg5,qArg6;
 IF bmc = 0 THEN
 SET vm_s0v=0;SET vm_s1v='';SET vm_s2v='';
 SET vtmp = (SELECT `rxnconso2_id` FROM bt_static.`rxnconso2_ndcid_map` WHERE `NDCID`=qArg1 LIMIT 1); 
 IF vtmp IS NOT NULL THEN SET vm_s0v=vtmp; END IF;
 IF vm_s0v != 0 THEN  
  SET vtmp = (SELECT CONCAT(RXAUI,'!@#',STR) AS vtmp FROM bt_static.rxnconso2 WHERE nr=vm_s0v LIMIT 1); 
  IF vtmp IS NOT NULL THEN  
    SET vm_s1v=SUBSTRING_INDEX(vtmp,'!@#',1);SET vm_s2v=SUBSTRING_INDEX(vtmp,'!@#',-1);
  END IF;  
 END IF;
 SET vm_presdocname="";
 SET vtmp = (SELECT `name` FROM personell WHERE npr_id=qArg3 LIMIT 1); 
 IF vtmp IS NOT NULL THEN SET vm_presdocname=vtmp; END IF; 
 INSERT IGNORE INTO cclf_encounter_patient_medication SET mra_clm_refer_num=qArg0,mra_clm_refer_m01=ms01vv,`created_by`='mra_sch_import_claim',`created_date`=NOW(),`quantity_unit`=qArg6,`fill_date`='',`type`='Order',`source`='MRA',`med_units`=qArg6,`patientid`=mpp6,`encounter_nr`=mpp1,`medications`=vm_s2v,`RxnormID`=vm_s1v,`NDCID`=qArg1,`quantity`=qArg4,`refills`=qArg5,`start_date`=qArg2,`prescribed_doctor`=vm_presdocname;
  
 SET mm1=mm1+1;
 
 END IF;
END LOOP;
CLOSE mrw;

COMMIT;

END */$$
DELIMITER ;

