DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C22_m5ENC_C11_m3_old`(mpp1 SMALLINT,mpp2 BIGINT,mpp3 VARCHAR(100),mpp4 SMALLINT)
BEGIN

DECLARE bmc INT DEFAULT 0;DECLARE _rollback TINYINT DEFAULT 0;DECLARE m1i INT DEFAULT 0;

DECLARE vtmp VARCHAR(1000); DECLARE mra_enc_nr BIGINT DEFAULT 0; DECLARE m_year INT; DECLARE m_month INT;
DECLARE ptFacilityNr INT; DECLARE ptFacilitySubNr INT; DECLARE ptProviderNum VARCHAR(100); 
DECLARE m1MarketNr INT;
DECLARE mc1data VARCHAR(30); DECLARE mc2data VARCHAR(30);

DECLARE qArg00 BIGINT;DECLARE qArg01 BIGINT;DECLARE qArg02 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);DECLARE qArg7 VARCHAR(100);DECLARE qArg8 VARCHAR(100);DECLARE qArg9 VARCHAR(100);DECLARE qArg10 VARCHAR(100);DECLARE qArg12 VARCHAR(100);DECLARE qArg14 int;DECLARE qArg15 VARCHAR(100);DECLARE qArg16 SMALLINT;DECLARE qArg17 VARCHAR(2);DECLARE qArg18 VARCHAR(100);DECLARE qArg19 VARCHAR(50);DECLARE qArg20 VARCHAR(10);DECLARE qHccScore DOUBLE(20,4);DECLARE qArg22 VARCHAR(10);DECLARE qArg23 VARCHAR(10);DECLARE qArg24 VARCHAR(30);DECLARE qArg25 VARCHAR(50);DECLARE qArg26 VARCHAR(30);DECLARE qArg27 VARCHAR(100);DECLARE qArg28 VARCHAR(100);DECLARE qArg29 VARCHAR(100);DECLARE qClmBLG_PRVDR_NPI_NUM VARCHAR(100);DECLARE qArg31 VARCHAR(100);DECLARE qArg32 VARCHAR(100);DECLARE qArg33 VARCHAR(100);DECLARE qArg34 VARCHAR(200);DECLARE m_CLM_ADMSN_SRC_CD VARCHAR(10);DECLARE mClmAmtPD DOUBLE(20,4);DECLARE qpLastName VARCHAR(100);DECLARE qpFirstName VARCHAR(100);DECLARE qpBirthDate VARCHAR(100);

DECLARE msgVR01 VARCHAR(100);DECLARE msgVR02 VARCHAR(200);

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t1.encounter_nr,t1.origid,t1.encounter_class_nr,t1.encounter_status,t1.discharge_date,t1.discharge_time,t1.create_id,t1.place_of_service,t1.encounter_type,t1.`encounter_date`,t1.hospital_nr, t1.current_att_dr_nr,t1.CLM_PRVDR_SPCLTY_CD,t1.mra_proc_type_nr,t1.mra_is_clf_redunct,t1.mm_curr_mbi_id,t1.mra_clm_refer_num,t1.mm_imp_job_nr,t1.hcc_score,t1.CLM_ADMSN_TYPE_CD,t3.discharge_type,t4.npr_id,t5.taxonomy_1,t5.nrp_id,t1.CLM_BILL_FAC_TYPE_CD,t1.CLM_BILL_CLSFCTN_CD,t1.CLM_BLG_PRVDR_OSCAR_NUM,t1.CLM_BLG_PRVDR_NPI_NUM,t1.RNDRG_PRVDR_TYPE_CD,t1.CLM_RNDRG_PRVDR_TAX_NUM,t1.CLM_RNDRG_PRVDR_NPI_NUM,t5.name,t1.CLM_ADMSN_SRC_CD,t1.CLM_AMT_PD,t6.lastname,t6.firstname,t6.birthdate FROM cclf_encounter t1 INNER JOIN mra1_311_m1 f2 ON f2.mdd_1=t1.origid LEFT JOIN cclf_procedure_discharge t3 ON t3.encounter_nr=t1.encounter_nr LEFT JOIN personell t4 ON t4.nr=t1.current_att_dr_nr LEFT JOIN hospital_centers t5 ON t5.nr=t1.hospital_nr LEFT JOIN patient t6 ON t6.origid=t1.origid WHERE t1.map_data_status=0 AND f2.mdd_2=mpp1 AND t1.mra_proc_type_nr BETWEEN 1 AND 4 ORDER BY t1.entry_nr;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
BEGIN
 SET _rollback = 1;
 GET DIAGNOSTICS CONDITION 1
 msgVR01 = RETURNED_SQLSTATE, msgVR02 = MESSAGE_TEXT;
END;

SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
START TRANSACTION;

SET @mg1vv=0; SET @mg2vv=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8,qArg9,qArg10,qArg12,qArg14,qArg15,qArg16,qArg17,qArg18,qArg19,qArg20,qHccScore,qArg22,qArg23,qArg24,qArg25,qArg26,qArg27,qArg28,qArg29,qClmBLG_PRVDR_NPI_NUM,qArg31,qArg32,qArg33,qArg34,m_CLM_ADMSN_SRC_CD,mClmAmtPD,qpLastName,qpFirstName,qpBirthDate;
 IF bmc = 0 THEN

  CALL `MRA_IMP3_M01ENC_99_01`(qArg01);
  SET ptFacilityNr=0;SET ptFacilitySubNr=0;SET ptProviderNum='';

  SET m_year=YEAR(qArg5); SET m_month=MONTH(qArg5);
  SET @mDischargeDate=CONCAT(m_year,'-',m_month,'-01');

  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_bene_alignment_rostr_m01 WHERE mm_curr_mbi_id=qArg02 AND mm_date=@mDischargeDate ORDER BY cc_version DESC LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET @v2tmp=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(@v2tmp,'!@#',-1);
  END IF;  
 
IF ptFacilityNr IS NULL OR ptFacilityNr=0 THEN
  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_bene_alignment_rostr_m01 WHERE mm_curr_mbi_id=qArg02 ORDER BY cc_version DESC LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET @v2tmp=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(@v2tmp,'!@#',-1);
  END IF;
END IF;

IF ptFacilityNr IS NULL OR ptFacilityNr=0 THEN
  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_quater_alignment WHERE mm_curr_mbi_id=qArg02 ORDER BY cc_version DESC LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET @v2tmp=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(@v2tmp,'!@#',-1);
  END IF;
END IF;

 SET mc1data=qArg8; SET mc2data=qArg10;
 IF qArg3="10" THEN SET mc1data=qArg15; END IF;
 IF qArg3="9" THEN SET mc2data=qArg5; END IF;

 SET @mEncChk1Pos=qArg8; IF qArg16=2 THEN SET @mEncChk1Pos=qArg15; END IF;
 SET m1MarketNr = (SELECT market_id FROM hospital_market_assocs WHERE hosp_id=ptFacilityNr LIMIT 1);

 SET @mc1tmp=0;SET @mc2tmp=0;
 SET vtmp=(SELECT CONCAT(SUM(cal_amount),'##',SUM(cal2amount)) AS mcc FROM cclf_study_report_billing_codes WHERE encounter_nr=qArg01);
 IF vtmp IS NOT NULL THEN SET @mc1tmp=SUBSTRING_INDEX(vtmp,'##',1); SET @mc2tmp=SUBSTRING_INDEX(vtmp,'##',-1); END IF;

 IF qArg16>1 THEN SET mClmAmtPD=@mc1tmp; END IF;

 # SET mra_enc_nr = (SELECT entry_nr FROM mra1_encounter WHERE encounter_nr=qArg01 LIMIT 1);
 INSERT IGNORE INTO mra1_encounter SET encounter_nr=qArg01,mcreate_datetime=NOW(),mmodify_datetime=NOW(),market_nr=m1MarketNr,mra_score_val=0,mh1_cal_amount=mClmAmtPD,patient_id=qArg02,enc_class_nr=qArg3,enc_status=qArg4,enc_disch_date=qArg5,enc_disch_time=qArg6,mcreate_id=qArg7,enc_pos=qArg8,proc_type_nr=qArg16,enc_admit_date=qArg10,enc_admit_time='05:00:00',hospital_nr=qArg12,dept_nr=14,m_provider_nr=qArg14,CLM_PRVDR_SPCLTY_CD=qArg15,pt_facility_nr=ptFacilityNr,pt_facility_sub_nr=ptFacilitySubNr,pt_provider_num=ptProviderNum,enc_chk1_pos=@mEncChk1Pos,enc_chk1_date=mc2data,enc_chk1_time='05:00:00',pt_sp_dr_1='',mra_is_clf_redunct=qArg17,mm_curr_mbi_id=qArg18,mra_clm_refer_num=qArg19,mm_imp_job_nr=qArg20,hcc_score=qHccScore,CLM_ADMSN_TYPE_CD=qArg22,e_discharge_type=qArg23,m_provider_npi=qArg24,hospital_name=qArg34,hos_taxonomy01=qArg25,hc_npi_nr=qArg26,CLM_BILL_FAC_TYPE_CD=qArg27,CLM_BILL_CLSFCTN_CD=qArg28,CLM_BLG_PRVDR_OSCAR_NUM=qArg29,CLM_BLG_PRVDR_NPI_NUM=qClmBLG_PRVDR_NPI_NUM,RNDRG_PRVDR_TYPE_CD=qArg31,CLM_RNDRG_PRVDR_TAX_NUM=qArg32,CLM_RNDRG_PRVDR_NPI_NUM=qArg33,CLM_ADMSN_SRC_CD=m_CLM_ADMSN_SRC_CD,pt_lastname=qpLastName,pt_firstname=qpFirstName,pt_birthdate=qpBirthDate,mc1_cal_amount=@mc1tmp,mc1_cal2amount=@mc2tmp,mc1_bb_Code='-123',mc1_diagnosis_code='-123',mc1_CLM_LINE_PROD_REV_CTR_CD='-123',m1_map_status=5;

 CALL MRA_IMP1_C22_m5ENC_C11_F11_m3(mra_enc_nr,qArg01,qArg02);
 CALL MRA_IMP1_C22_m5ENC_C11_F12_m3(mra_enc_nr,qArg01,qArg02);

 UPDATE cclf_encounter SET map_data_status=1 WHERE map_data_status=0 AND entry_nr=qArg00;

  SET @mg2vv=qArg00; IF m1i=0 THEN SET @mg1vv=qArg00; END IF;
  INSERT INTO mra1_331_m1 SET mdd_1=mpp3,mdd_2='m02Call',mdd_5=mpp1,mdd_6=qArg00,mdd_7=m1i;
  SET m1i=m1i+1;

 END IF;
END LOOP;
CLOSE mrw;

COMMIT;

INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='END',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00;
IF `_rollback` THEN
 INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='ERROR',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00,mdd_4=msgVR01,mdd_5=msgVR02;
END IF;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_C23_m5ENC_C11_k3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C23_m5ENC_C11_k3`(m1pp tinyINT)
BEGIN

DECLARE mmi INT; DECLARE m2mi INT; DECLARE m3mi INT;
DECLARE vtmp VARCHAR(100); 

TRUNCATE mra1_311_m1; TRUNCATE mra_00_tmp;
insert into mra_00_tmp set mdd_1='START',mdd_2=0;

INSERT INTO mra1_311_m1 (mdd_1,mdd_2,mdd_3)
SELECT DISTINCT patient_id,1,'C23_m5ENC_C11_k3' FROM mra1_encounter WHERE m1_map_status=5;

SET m3mi = (SELECT COUNT(mdd_1) FROM mra1_311_m1);
SET m3mi = CEIL(m3mi/m1pp);

SET mmi = 1;

LOOP_M01:  LOOP

 SET m2mi= ((mmi-1)*m3mi ) +1;
 UPDATE mra1_311_m1 SET mdd_2=mmi WHERE nr BETWEEN m2mi AND (m2mi+(m3mi-1)); 
 IF  mmi > m1pp THEN LEAVE  LOOP_M01;  END  IF;
 SET  mmi = mmi + 1;
 insert into mra_00_tmp set mdd_1='m1cc',mdd_2=mmi;

 ITERATE  LOOP_M01;
END LOOP;

UPDATE mra1_311_m1 SET mdd_1='a123z' WHERE mdd_1='' OR mdd_1 IS NULL;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_C23_m5ENC_ColMapping_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C23_m5ENC_ColMapping_m3`(mpp1 SMALLINT,mpp2 BIGINT,mpp3 VARCHAR(100),mpp4 SMALLINT)
BEGIN

DECLARE _rollback TINYINT DEFAULT 0;DECLARE m1i INT DEFAULT 0;
DECLARE bmc INT DEFAULT 0;DECLARE qArg00 BIGINT;DECLARE qArg01 BIGINT;DECLARE qArg02 INT;DECLARE qFacilityNr INT;

DECLARE msgVR01 VARCHAR(100);DECLARE msgVR02 VARCHAR(200);

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t1.encounter_nr,t1.proc_type_nr,t1.pt_facility_nr FROM mra1_encounter t1 INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=t1.patient_id WHERE t2.mdd_2=mpp1 and t1.m1_map_status=5;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
BEGIN
 SET _rollback = 1;
 GET DIAGNOSTICS CONDITION 1
 msgVR01 = RETURNED_SQLSTATE, msgVR02 = MESSAGE_TEXT;
END;


SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
START TRANSACTION;

SET @mg1vv=0; SET @mg2vv=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qFacilityNr;
 
 IF bmc = 0 THEN

  SET @mv2Val="update mra1_encounter SET m1_map_status=1,mmodify_datetime=NOW()";
  SET @mEncCptTxt=''; SET @mEncIcdTxt='';SET @mEncIcd1Txt='';SET @mEncIcd2Txt='';SET @mEncIcd3Txt='';
  SET @mIcdAdmit=''; SET @mIcdPrinc='';
  
IF qArg02 = 1 THEN
mBLOCK_11: BEGIN
 DECLARE b2mc INT DEFAULT 0; DECLARE m2i INT;
 DECLARE q2Arg01 VARCHAR(100);DECLARE q2Arg02 VARCHAR(100);DECLARE q2Arg03 VARCHAR(30);
 DECLARE m2rw CURSOR FOR SELECT bb_Code,SUM(cal_amount+cal2amount) AS mtotal,CLM_LINE_PROD_REV_CTR_CD FROM mra1_encounter_bill_cpts WHERE encounter_nr=qArg01 GROUP BY bb_Code ORDER BY mtotal DESC LIMIT 20;
 DECLARE CONTINUE HANDLER FOR NOT FOUND SET b2mc = 1;
 SET m2i=0;
 OPEN m2rw; 
 read2loop: LOOP
  IF b2mc = 1 THEN LEAVE read2loop; END IF;
  FETCH FROM m2rw INTO q2Arg01,q2Arg02,q2Arg03;
  IF b2mc = 0 THEN
   SET m2i=m2i+1;
   IF q2Arg01 IS NULL THEN SET q2Arg01=''; END IF; IF q2Arg02 IS NULL THEN SET q2Arg02='0'; END IF;
   IF q2Arg03 IS NULL THEN SET q2Arg03=''; END IF;
   SET @mv2Val=CONCAT(@mv2Val,",m1_cpt",m2i,"_bb_code='",q2Arg01,"',m1_cpt",m2i,"_cal_amount='",q2Arg02,"',m1_cpt",m2i,"_revenue_code='",q2Arg03,"'");
   SET @mtmp=(SELECT cpt_name FROM cpt_codes WHERE cpt_code=q2Arg01 LIMIT 1);
   IF @mtmp IS NULL THEN SET @mtmp=''; END IF;
   IF q2Arg01 IS NULL THEN SET q2Arg01=''; END IF;
   SET @mEncCptTxt=CONCAT(@mEncCptTxt,' # ',m2i,' ) ',q2Arg01,' : ',@mtmp,', Amount : $ ',FORMAT(q2Arg02,2));
  END IF;
 END LOOP read2loop;
 mLOOP_01: LOOP
  IF  m2i >= 20 THEN LEAVE mLOOP_01; END IF;
  SET m2i = m2i + 1;
  SET @mv2Val=CONCAT(@mv2Val,",m1_cpt",m2i,"_bb_code='',m1_cpt",m2i,"_cal_amount='0',m1_cpt",m2i,"_revenue_code=''");
  ITERATE  mLOOP_01;
 END LOOP;
END mBLOCK_11;
ELSE
mBLOCK_12: BEGIN
 DECLARE b2mc INT DEFAULT 0; DECLARE m2i INT;
 DECLARE q2Arg01 VARCHAR(100);DECLARE q2Arg02 VARCHAR(100);DECLARE q2Arg03 VARCHAR(30);
 DECLARE m2rw CURSOR FOR SELECT bb_Code,SUM(cal_amount+cal2amount) AS mtotal,CLM_LINE_PROD_REV_CTR_CD FROM mra1_encounter_bill_cpts WHERE encounter_nr=qArg01 GROUP BY bb_Code ORDER BY mtotal DESC LIMIT 20;
 DECLARE CONTINUE HANDLER FOR NOT FOUND SET b2mc = 1;
 SET m2i=0;
 OPEN m2rw; 
 read2loop: LOOP
  IF b2mc = 1 THEN LEAVE read2loop; END IF;
  FETCH FROM m2rw INTO q2Arg01,q2Arg02,q2Arg03;
  IF b2mc = 0 THEN
   SET m2i=m2i+1;
   IF q2Arg01 IS NULL THEN SET q2Arg01=''; END IF; IF q2Arg02 IS NULL THEN SET q2Arg02='0'; END IF;
   IF q2Arg03 IS NULL THEN SET q2Arg03=''; END IF;
   SET @mv2Val=CONCAT(@mv2Val,",m1_cpt",m2i,"_bb_code='",q2Arg01,"',m1_cpt",m2i,"_cal_amount='",q2Arg02,"',m1_cpt",m2i,"_revenue_code='",q2Arg03,"'");
   SET @mtmp=(SELECT cpt_name FROM cpt_codes WHERE cpt_code=q2Arg01 LIMIT 1);
   IF @mtmp IS NULL THEN SET @mtmp=''; END IF;
   IF q2Arg01 IS NULL THEN SET q2Arg01=''; END IF;
   SET @mEncCptTxt=CONCAT(@mEncCptTxt,' # ',m2i,' ) ',q2Arg01,' : ',@mtmp,', Amount : $ ',FORMAT(q2Arg02,2));
  END IF;
 END LOOP read2loop;
 mLOOP_01: LOOP
  IF  m2i >= 20 THEN LEAVE mLOOP_01; END IF;
  SET m2i = m2i + 1;
  SET @mv2Val=CONCAT(@mv2Val,",m1_cpt",m2i,"_bb_code='',m1_cpt",m2i,"_cal_amount='0',m1_cpt",m2i,"_revenue_code=''");
  ITERATE  mLOOP_01;
 END LOOP;
END mBLOCK_12;
END IF;

mBLOCK_21: BEGIN
 DECLARE b2mc INT DEFAULT 0; DECLARE m2i INT; DECLARE m3i INT;
 DECLARE q2Arg01 VARCHAR(100); DECLARE q2Arg02 VARCHAR(30); DECLARE q2Arg03 VARCHAR(300);
 DECLARE m2rw CURSOR FOR SELECT diagnosis_code,problem_type,diagnosis_desc FROM cclf_encounter_icd_codes WHERE encounter_nr=qArg01 GROUP BY diagnosis_code,problem_type;
 DECLARE CONTINUE HANDLER FOR NOT FOUND SET b2mc = 1;

 SET m2i=0;
 OPEN m2rw; 
 read2loop: LOOP
  IF b2mc = 1 THEN LEAVE read2loop; END IF;
  FETCH FROM m2rw INTO q2Arg01,q2Arg02,q2Arg03;
  IF b2mc = 0 THEN
   SET m2i=m2i+1;
   IF q2Arg01 IS NULL THEN SET q2Arg01=''; END IF;

   IF q2Arg02='Admitting' THEN SET @mIcdAdmit=q2Arg01;
   ELSEIF q2Arg02='Principal' THEN SET @mIcdPrinc=q2Arg01; END IF;

   IF m2i <= 10 THEN SET @mv2Val=CONCAT(@mv2Val,",m1_icd",m2i,"_code='",q2Arg01,"'"); END IF;

   IF q2Arg02='Admitting' THEN 
    SET @mEncIcd1Txt=CONCAT(@mEncIcd1Txt,'
  # ',q2Arg01,' - ',q2Arg03);
   ELSEIF q2Arg02='Principal' THEN 
    SET @mEncIcd2Txt=CONCAT(@mEncIcd2Txt,'
  # ',q2Arg01,' - ',q2Arg03);
   ELSE 
    SET @mEncIcd3Txt=CONCAT(@mEncIcd3Txt,'
  # ',q2Arg01,' - ',q2Arg03);
   END IF;
  END IF;
 END LOOP read2loop;

 SET @mEncIcdTxt=CONCAT('[Admitting]',@mEncIcd1Txt,'
 
[Principal]',@mEncIcd2Txt,'
 
[Misc.]',@mEncIcd3Txt);


 mLOOP_01: LOOP
  IF  m2i >= 10 THEN LEAVE mLOOP_01; END IF;
  SET m2i = m2i + 1;
  SET @mv2Val=CONCAT(@mv2Val,",m1_icd",m2i,"_code=''");
  ITERATE  mLOOP_01;
 END LOOP;
END mBLOCK_21;

  SET @mEncCptTxt=REPLACE(@mEncCptTxt,"'","\\'"); SET @mEncIcdTxt=REPLACE(@mEncIcdTxt,"'","\\'");

  SET @mv2Val=CONCAT(@mv2Val,",m2_icd_admit='",@mIcdAdmit,"', m2_icd_princ='",@mIcdPrinc,"'"); 
  SET @mv2Val=CONCAT(@mv2Val,",m1_cpt_cpt_text='",@mEncCptTxt,"',m1_icd_code='",@mEncIcdTxt,"' WHERE entry_nr=",qArg00," AND pt_facility_nr=",qFacilityNr);
  PREPARE stmt FROM @mv2Val; EXECUTE stmt; DEALLOCATE PREPARE stmt;

  SET @mg2vv=qArg00; if m1i=0 then SET @mg1vv=qArg00; end if;
  INSERT INTO mra1_331_m1 SET mdd_1=mpp3,mdd_2='m02Call',mdd_5=mpp1,mdd_6=qArg00,mdd_7=m1i;
  SET m1i=m1i+1;

 END IF;
END LOOP;
CLOSE mrw;

COMMIT;


INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='END',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00;
IF `_rollback` THEN
 INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='ERROR',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00,mdd_4=msgVR01,mdd_5=msgVR02;
END IF;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_C31ENC_03` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C31ENC_03`(m1pp VARCHAR(100),m2pp INT,m3pp BIGINT,m4pp BIGINT,m5pp INT,m6pp SMALLINT)
BEGIN

DECLARE bmc INT DEFAULT 0;DECLARE _rollback TINYINT DEFAULT 0;DECLARE m1i INT;DECLARE m2i INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg02 INT;DECLARE qArg03 INT;
DECLARE msgVR01 VARCHAR(100);DECLARE msgVR02 VARCHAR(200);

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t1.pt_facility_nr FROM mra1_encounter t1 WHERE YEAR(t1.enc_disch_date)>=m6pp ORDER BY t1.entry_nr LIMIT m3pp,m4pp;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc=1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
BEGIN
 SET _rollback = 1;
 GET DIAGNOSTICS CONDITION 1
 msgVR01 = RETURNED_SQLSTATE, msgVR02 = MESSAGE_TEXT;
END;

SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
START TRANSACTION;

SET m1i=m5pp; SET @m1vval=0; SET @m2vval=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg02;

 IF bmc = 0 THEN
/* # m1_map3status=0,
UPDATE mra1_encounter t1 SET t1.pt_aligned_status=2 WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02; */
  UPDATE mra1_encounter SET mm_test_val='a03m1z',mmodify_datetime=NOW(),tfu_followup_date=NULL,is_72_hr_flwup=0,is_flwup_7_days=0,is_flwup_14_days=0,is_gflwup_14_days=0,m72hr_flwup_date=NULL,is_er_readmit=0,is_c2_readmit=0,pre_hospital_nr=0,pre_discharge_date=NULL,is_snf_rec=0,is_snf_admitdate_ref=NULL,pre_emr_hospital_name=NULL,pre_emr_discharge_date=NULL,is_enc_transfer=1,is_enc_ref_admitdate=enc_admit_date,mh1_cal_amount = IF(proc_type_nr=1,mh1_cal_amount,mc1_cal_amount) WHERE entry_nr=qArg00 AND pt_facility_nr=qArg02;

  SET @m2vval=qArg00; IF m2i=0 THEN SET @m1vval=qArg00; END IF;
  INSERT INTO mra1_331_m1 SET mdd_1=m1pp,mdd_2='m02Call',mdd_5=m2pp,mdd_6=m1i,mdd_7=qArg00;
  SET m1i=m1i+1; SET m2i=m2i+1;

 END IF;
END LOOP;
CLOSE mrw;

COMMIT;

INSERT INTO mra1_316_m1 SET mdd_1=m1pp,mdd_2='END',mdd_3=m2pp,mdd_6=@m1vval,mdd_7=@m2vval,mdd_8=m2pp,m_rec_lastid=m1i;
IF `_rollback` THEN
