DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C31ENC_04_11`(m1pp VARCHAR(100),m2pp INT,m3pp BIGINT,m4pp BIGINT,m5pp INT,m6pp SMALLINT)
BEGIN

DECLARE bmc INT DEFAULT 0;DECLARE _rollback TINYINT DEFAULT 0;DECLARE m1i INT;DECLARE m2i INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg02 INT;DECLARE qArg03 INT;DECLARE qEncounterNr BIGINT;DECLARE qDischDate DATE;DECLARE qProcTypeNr SMALLINT;DECLARE qIsErVisit TINYINT;DECLARE qEncPos VARCHAR(10);DECLARE qHosTaxonomy01 VARCHAR(50);DECLARE qIsSnfRec TINYINT;DECLARE qMproviderMr INT;DECLARE qPatientID VARCHAR(100);DECLARE qAdmitDate DATE;DECLARE qEdischargeType VARCHAR(5);DECLARE qMproviderNr INT;DECLARE qMraClmReferNum BIGINT;

DECLARE mEncProcType VARCHAR(50);DECLARE msgVR01 VARCHAR(100);DECLARE msgVR02 VARCHAR(200);

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t1.pt_facility_nr,t1.pt_facility_sub_nr,t1.encounter_nr,t1.enc_disch_date,t1.proc_type_nr,t1.is_er_visit,t1.enc_pos,t1.hos_taxonomy01,t1.is_snf_rec,t1.m_provider_nr,t1.patient_id,t1.enc_admit_date,t1.e_discharge_type,t1.m_provider_nr,t1.mra_clm_refer_num FROM mra1_encounter t1 WHERE YEAR(t1.enc_disch_date)>=m6pp AND t1.m1_map3status IN (0,2) ORDER BY t1.entry_nr LIMIT m3pp,m4pp;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc=1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
BEGIN
 SET _rollback = 1;
 GET DIAGNOSTICS CONDITION 1
 msgVR01 = RETURNED_SQLSTATE, msgVR02 = MESSAGE_TEXT;
END;

SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
START TRANSACTION;

SET m1i=m5pp; SET @m1vval=0; SET @m2vval=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg02,qArg03,qEncounterNr,qDischDate,qProcTypeNr,qIsErVisit,qEncPos,qHosTaxonomy01,qIsSnfRec,qMproviderMr,qPatientID,qAdmitDate,qEdischargeType,qMproviderNr,qMraClmReferNum;

 IF bmc = 0 THEN
  SET mEncProcType='UNK'; SET @mIsErVisit=0;SET @mIsVisitPcp=0;SET @mFlwupFlag=0;

