   IF @mHospNr IS NULL THEN SET @mHospNr=0; END IF;
   IF @mHospNr=0 THEN
    UPDATE mra1_encounter t1 SET t1.mhos_cent_nr= -3,t1.hos_taxonomy01='',t1.hospital_name='',t1.hc_npi_nr='' WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
   ELSE
    SET @vtmp = (SELECT CONCAT(IF(`mname` IS NULL,'NA',`mname`),'!@#',IF(npi_id IS NULL,'NA',npi_id),'!@#',IF(mtaxonomy IS NULL,'NA',mtaxonomy)) FROM adt_hosp_centers WHERE nr=@mHospNr LIMIT 1); 
    SET @mHospitalName=SUBSTRING_INDEX(@vtmp,'!@#',1);SET qHosTaxonomy01=SUBSTRING_INDEX(@vtmp,'!@#',-1);
    SET @v3tmp=SUBSTRING_INDEX(@vtmp,'!@#',2); SET @mHcNpiNr=SUBSTRING_INDEX(@v3tmp,'!@#',-1);
    UPDATE mra1_encounter SET mhos_cent_nr=@mHospNr,hos_taxonomy01=qHosTaxonomy01,hospital_name=@mHospitalName,hc_npi_nr=@mHcNpiNr WHERE entry_nr=qArg00 AND pt_facility_nr=qArg02;
   END IF;
   UPDATE cclf_encounter_procedure SET procedure_center=@mHospitalName WHERE encounter_nr=qEncounterNr;
  END IF;
  # */

  IF qProcTypeNr=1 AND qEncPos IN ('60','61') AND qHosTaxonomy01 IN ('282N00000X','282NC0060X','282NR1301X','282NC2000X','284300000X') THEN SET mEncProcType='Acute Hospital';
  ELSEIF qProcTypeNr=1 AND qEncPos IN ('60','61') AND qHosTaxonomy01 IN ('282E00000X') THEN SET mEncProcType='Long Term Care Hospital';
  ELSEIF qProcTypeNr=1 AND qEncPos IN ('60','61') AND qHosTaxonomy01 IN ('261QR0400X','283X00000X','261QR0401X','273Y00000X','2081P2900X','208100000X','283XC2000X','261QR0404X','111NR0400X','225400000X') THEN SET mEncProcType='Rehabilitation';
  ELSEIF qProcTypeNr=1 AND qEncPos IN ('60','61') AND qHosTaxonomy01 IN ('251E00000X','253Z00000X','374U00000X','251F00000X') THEN SET mEncProcType='HHA';
  ELSEIF qProcTypeNr=1 AND qEncPos IN ('60','61') AND qHosTaxonomy01 IN ('273R00000X','283Q00000X') THEN SET mEncProcType='Psychiatric';
  ELSEIF qProcTypeNr=1 AND qEncPos IN ('50') THEN SET mEncProcType='Hospice';
  ELSEIF qProcTypeNr=2 THEN SET mEncProcType='Part B';
  ELSEIF qProcTypeNr=3 THEN SET mEncProcType='Part DME';
  ELSEIF qProcTypeNr=4 THEN SET mEncProcType='Part D';
  END IF;

  SET @mIsVisitPcp= (SELECT 1 FROM personell_hosp_assocs WHERE hospital_nr=qArg02 AND user_nr=qMproviderMr LIMIT 1);
  IF @mIsVisitPcp IS NULL THEN SET @mIsVisitPcp=0; END IF;  

  IF qProcTypeNr=1 THEN 

   IF qEncPos IN ('00','10','40','50') THEN
    SET @vtmp = (SELECT 1 FROM mra1_encounter e INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=e.encounter_nr WHERE e.proc_type_nr=1 AND e.enc_chk1_pos IN ('00','10','40','50') AND ( (t2.CLM_LINE_PROD_REV_CTR_CD IN ('0450','0451','0452','0453','0454','0455','0456','0457','0458','0459','0981') OR t2.bb_Code IN ('99281','99282','99283','99284','99285') ) AND DATEDIFF(e.enc_disch_date,e.enc_admit_date) <= 2) AND e.entry_nr=qArg00 AND e.pt_facility_nr=qArg02 LIMIT 1);
    IF @vtmp IS NOT NULL THEN
     SET @mIsErVisit=1; SET mEncProcType='Emergency';
    END IF;
   END IF;

   IF (@mIsErVisit=1 OR (qEncPos IN ('60','61') AND qHosTaxonomy01 IN ('282N00000X','282NC0060X','282NR1301X','282NC2000X','284300000X'))) AND (qEdischargeType IN ('1','6','7','30','50','81','86') OR qEdischargeType IS NULL ) THEN
    SET @mFlwupFlag=1;
   END IF;

  END IF;


  UPDATE mra1_encounter SET mm_test_val='a_h01_z',m_pos_txt='',m_prov_spclty_txt='',market_name='',pt_facility_sub_name='',pt_sp_dr_1='',pt_facility_name='',e_discharge_text='',pt_lastname='',m_provider_name='',mmodify_datetime=NOW(),enc_proc_type=mEncProcType,is_er_visit=@mIsErVisit,is_visit_pcp=@mIsVisitPcp,is_offvisit_rec=NULL,is_offvisit2rec=NULL,m_flwup_flag=@mFlwupFlag,tfu_pb_er=0,tfu_pb_obs=0 WHERE entry_nr=qArg00 AND pt_facility_nr=qArg02;

