y_nr=qArg00 AND t1.pt_facility_nr=qArg02;
   END IF;
   UPDATE mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr SET t1.is_offvisit2rec=1 WHERE ( (t2.bb_Code IN ('98000','98001','98002','98003','98004','98005','98006','98007','98008','98009','98010','98011','98012','98013','98014','98015','98016','90957','90958','90959','90960','90961','90962','90965','90966','90969','90970','92002','92004','92012','92014','93750','93797','93798','94004','94625','94626','94664','96160','96164','96165','96167','96168','97129','97130','97151','97152','97161','97162','97163','97164','97530','97535','97750','97755','97761','97763','97802','97803','97804','98960','98961','98962','98966','98967','98968','98970','98971','98972','99091','99201','99202','99203','99204','99205','99211','99212','99213','99214','99215','99241','99242','99243','99244','99245','99341','99342','99343','99344','99345','99347','99348','99349','99350','99381','99382','99383','99384','99385','99386','99387','99391','99392','99393','99394','99395','99396','99397','99401','99402','99403','99404','99411','99412','99421','99422','99423','99429','99441','99442','99443','99453','99454','99455','99456','99457','99458','99473','99474','99487','99489','99490','99491','99495','99496','99497','99498','0591T','0592T','0593T','G0071','G0108','G0109','G0270','G0296','G0402','G0406','G0407','G0408','G0420','G0421','G0422','G0423','G0425','G0426','G0427','G0438','G0439','G0446','G0459','G0463','G0506','G0508','G0509','G0511','G0512','G0513','G0514','G2010','G2012','G2025','G2061','G2062','G2063','G2211','G2212','G2250','G2251','G2252','G3002','G3003','G9481','G9482','G9483','G9484','G9485','G9486','G9487','G9488','G9489','T1015','G2001','G2002','G2003','G2004','G2005','G2006','G2007','G2008','G2009','G2013','G2014','G2015') AND (t1.proc_type_nr=2 OR (t1.proc_type_nr=1 AND t1.enc_pos="40")) ) OR (t1.proc_type_nr=2 AND t1.enc_pos IN ('02','10')) ) AND t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
  END IF;

 IF qProcTypeNr=1 THEN
  UPDATE mra1_encounter t1 SET t1.m_pos_txt=(SELECT t2.`option_label` FROM option_code_values t2 WHERE t2.column_order='1119' AND t2.option_value=t1.enc_pos LIMIT 1) WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
  IF qEncPos IN ('60','61') AND mEncProcType<>'Acute Hospital' THEN
   UPDATE mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr SET t1.enc_proc_type='Observation' WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02 AND (t2.CLM_LINE_PROD_REV_CTR_CD IN ('0760','0762') OR t2.bb_Code IN ('99217','99218','99219','99220','99221','99222','99223','99224','99225','99226','99231','99232','99233','99234','99235','99236','99252','99253','99254'));
  END IF;
 ELSEIF qProcTypeNr=2 THEN 
  UPDATE mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr SET t1.tfu_pb_er=1 WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02 AND t2.bb_Code IN ('99281','99282','99283','99284','99285');
  UPDATE mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr SET t1.tfu_pb_obs=1 WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02 AND t2.bb_Code IN ('99217','99218','99219','99220','99221','99222','99223','99224','99225','99226','99232','99233','99234','99235','99236','99252','99253','99254');
