  ELSEIF qProcTypeNr=1 AND qEncPos IN ('50') THEN SET mEncProcType='Hospice';
  ELSEIF qProcTypeNr=2 THEN SET mEncProcType='Part B';
  ELSEIF qProcTypeNr=3 THEN SET mEncProcType='Part DME';
  ELSEIF qProcTypeNr=4 THEN SET mEncProcType='Part D';
  END IF;

  SET @mIsVisitPcp= (SELECT 1 from personell_hosp_assocs where hospital_nr=qArg02 AND user_nr=qMproviderMr LIMIT 1);
  IF @mIsVisitPcp is null THEN SET @mIsVisitPcp=0; END IF;  

  IF qProcTypeNr=1 THEN 

   IF qEncPos IN ('00','10','40','50') THEN
    SET @vtmp = (SELECT 1 FROM mra1_encounter e INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=e.encounter_nr WHERE e.proc_type_nr=1 AND e.enc_chk1_pos IN ('00','10','40','50') AND ( (t2.CLM_LINE_PROD_REV_CTR_CD IN ('0450','0451','0452','0453','0454','0455','0456','0457','0458','0459','0981') OR t2.bb_Code IN ('99281','99282','99283','99284','99285') ) AND DATEDIFF(e.enc_disch_date,e.enc_admit_date) <= 2) AND e.entry_nr=qArg00 AND e.pt_facility_nr=qArg02 LIMIT 1);
    IF @vtmp IS NOT NULL THEN
     SET @mIsErVisit=1; SET mEncProcType='Emergency';
    END IF;
   END IF;

   IF (@mIsErVisit=1 OR (qEncPos IN ('60','61') AND qHosTaxonomy01 IN ('282N00000X','282NC0060X','282NR1301X','282NC2000X','284300000X'))) AND (qEdischargeType IN ('1','6','7','30','50','81','86') OR qEdischargeType IS NULL ) THEN
    SET @mFlwupFlag=1;
   END IF;

  END IF;


  UPDATE mra1_encounter SET mm_test_val='a_h01_z',m_pos_txt='',m_prov_spclty_txt='',market_name='',pt_facility_sub_name='',pt_sp_dr_1='',pt_facility_name='',e_discharge_text='',pt_lastname='',m_provider_name='',mmodify_datetime=NOW(),enc_proc_type=mEncProcType,is_er_visit=@mIsErVisit,is_visit_pcp=@mIsVisitPcp,is_offvisit_rec=NULL,is_offvisit2rec=NULL,m_flwup_flag=@mFlwupFlag,tfu_pb_er=0,tfu_pb_obs=0 WHERE entry_nr=qArg00 AND pt_facility_nr=qArg02;

  IF qProcTypeNr in (1,2) THEN
   IF @mIsVisitPcp=1 THEN
    UPDATE mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr INNER JOIN personell t4 ON t1.m_provider_nr=t4.nr SET t1.is_offvisit_rec=1 WHERE ( (t2.bb_Code IN ('98000','98001','98002','98003','98004','98005','98006','98007','98008','98009','98010','98011','98012','98013','98014','98015','98016','90957','90958','90959','90960','90961','90962','90965','90966','90969','90970','92002','92004','92012','92014','93750','93797','93798','94004','94625','94626','94664','96160','96164','96165','96167','96168','97129','97130','97151','97152','97161','97162','97163','97164','97530','97535','97750','97755','97761','97763','97802','97803','97804','98960','98961','98962','98966','98967','98968','98970','98971','98972','99091','99201','99202','99203','99204','99205','99211','99212','99213','99214','99215','99241','99242','99243','99244','99245','99341','99342','99343','99344','99345','99347','99348','99349','99350','99381','99382','99383','99384','99385','99386','99387','99391','99392','99393','99394','99395','99396','99397','99401','99402','99403','99404','99411','99412','99421','99422','99423','99429','99441','99442','99443','99453','99454','99455','99456','99457','99458','99473','99474','99487','99489','99490','99491','99495','99496','99497','99498','0591T','0592T','0593T','G0071','G0108','G0109','G0270','G0296','G0402','G0406','G0407','G0408','G0420','G0421','G0422','G0423','G0425','G0426','G0427','G0438','G0439','G0446','G0459','G0463','G0506','G0508','G0509','G0511','G0512','G0513','G0514','G2010','G2012','G2025','G2061','G2062','G2063','G2211','G2212','G2250','G2251','G2252','G3002','G3003','G9481','G9482','G9483','G9484','G9485','G9486','G9487','G9488','G9489','T1015','G2001','G2002','G2003','G2004','G2005','G2006','G2007','G2008','G2009','G2013','G2014','G2015') AND (t1.proc_type_nr=2 OR (t1.proc_type_nr=1 AND t1.enc_pos="40")) ) OR (t1.proc_type_nr=2 AND t1.enc_pos IN ('02','10')) ) AND t4.is_dce=1 AND t4.dce_type='DCE' AND t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
   END IF;
   UPDATE mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr SET t1.is_offvisit2rec=1 WHERE ( (t2.bb_Code IN ('98000','98001','98002','98003','98004','98005','98006','98007','98008','98009','98010','98011','98012','98013','98014','98015','98016','90957','90958','90959','90960','90961','90962','90965','90966','90969','90970','92002','92004','92012','92014','93750','93797','93798','94004','94625','94626','94664','96160','96164','96165','96167','96168','97129','97130','97151','97152','97161','97162','97163','97164','97530','97535','97750','97755','97761','97763','97802','97803','97804','98960','98961','98962','98966','98967','98968','98970','98971','98972','99091','99201','99202','99203','99204','99205','99211','99212','99213','99214','99215','99241','99242','99243','99244','99245','99341','99342','99343','99344','99345','99347','99348','99349','99350','99381','99382','99383','99384','99385','99386','99387','99391','99392','99393','99394','99395','99396','99397','99401','99402','99403','99404','99411','99412','99421','99422','99423','99429','99441','99442','99443','99453','99454','99455','99456','99457','99458','99473','99474','99487','99489','99490','99491','99495','99496','99497','99498','0591T','0592T','0593T','G0071','G0108','G0109','G0270','G0296','G0402','G0406','G0407','G0408','G0420','G0421','G0422','G0423','G0425','G0426','G0427','G0438','G0439','G0446','G0459','G0463','G0506','G0508','G0509','G0511','G0512','G0513','G0514','G2010','G2012','G2025','G2061','G2062','G2063','G2211','G2212','G2250','G2251','G2252','G3002','G3003','G9481','G9482','G9483','G9484','G9485','G9486','G9487','G9488','G9489','T1015','G2001','G2002','G2003','G2004','G2005','G2006','G2007','G2008','G2009','G2013','G2014','G2015') AND (t1.proc_type_nr=2 OR (t1.proc_type_nr=1 AND t1.enc_pos="40")) ) OR (t1.proc_type_nr=2 AND t1.enc_pos IN ('02','10')) ) AND t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
  END IF;

 if qProcTypeNr=1 then
  UPDATE mra1_encounter t1 SET t1.m_pos_txt=(SELECT t2.`option_label` FROM option_code_values t2 WHERE t2.column_order='1119' AND t2.option_value=t1.enc_pos LIMIT 1) WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
  IF qEncPos IN ('60','61') AND mEncProcType<>'Acute Hospital' THEN
   UPDATE mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr SET t1.enc_proc_type='Observation' WHERE t1.entry_nr=qArg00 and t1.pt_facility_nr=qArg02 AND (t2.CLM_LINE_PROD_REV_CTR_CD IN ('0760','0762') OR t2.bb_Code IN ('99217','99218','99219','99220','99221','99222','99223','99224','99225','99226','99231','99232','99233','99234','99235','99236','99252','99253','99254'));
  end if;
 elseIF qProcTypeNr=2 THEN 
  UPDATE mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr SET t1.tfu_pb_er=1 WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02 AND t2.bb_Code IN ('99281','99282','99283','99284','99285');
  UPDATE mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr SET t1.tfu_pb_obs=1 WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02 AND t2.bb_Code IN ('99217','99218','99219','99220','99221','99222','99223','99224','99225','99226','99232','99233','99234','99235','99236','99252','99253','99254');
  UPDATE mra1_encounter t1 SET t1.m_prov_spclty_txt=(SELECT t2.`option_label` FROM option_code_values t2 WHERE t2.column_order='1118' AND t2.option_value=t1.CLM_PRVDR_SPCLTY_CD LIMIT 1) WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
 ELSEIF qProcTypeNr=3 THEN  
  UPDATE mra1_encounter t1 SET t1.m_pos_txt=(SELECT t2.`option_label` FROM option_code_values t2 WHERE t2.column_order='1120' AND t2.option_value=t1.enc_pos LIMIT 1) WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
 end if;

  UPDATE mra1_encounter t1 INNER JOIN hospital_market t2 ON t2.market_id=t1.market_nr SET t1.market_name=t2.`market_name` WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
  UPDATE mra1_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.pt_facility_nr SET t1.pt_facility_name=t2.`name` WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
  UPDATE mra1_encounter t1 INNER JOIN personell t2 ON t2.npr_id=t1.pt_provider_num AND t2.is_dce=1 SET t1.pt_sp_dr_1=t2.`name` WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02 and t2.is_dce=1;

  IF qArg03=0 or qArg03 is null THEN UPDATE mra1_encounter t1 SET t1.pt_facility_sub_name='No Sub Group' WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
  else UPDATE mra1_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.pt_facility_sub_nr SET t1.pt_facility_sub_name=t2.`name` WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02; END IF;

  IF qMproviderNr IN (0,1,2) THEN UPDATE mra1_encounter t1 SET t1.m_provider_name='UNK',t1.m_provider_npi='xxxx',t1.m_provider_nr=1 WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02; 
  else UPDATE mra1_encounter t1 INNER JOIN personell t2 ON t2.nr=t1.m_provider_nr SET t1.m_provider_name=t2.`name` WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02; END IF;

  UPDATE mra1_encounter t1 INNER JOIN patient t2 ON t1.patient_id=t2.origid SET t1.pt_lastname=t2.lastname,t1.pt_firstname=t2.firstname,t1.pt_birthdate=t2.birthdate WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
  UPDATE mradb_prod.mra1_encounter t1 INNER JOIN procedure_discharge t2 ON t2.encounter_nr=t1.encounter_nr SET t1.e_discharge_text=t2.discharge_loc where t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;

  UPDATE mra1_encounter t1 SET t1.m1_map3status=2 WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;


  SET @m2vval=qArg00; IF m2i=0 THEN SET @m1vval=qArg00; END IF;
  INSERT INTO mra1_331_m1 SET mdd_1=m1pp,mdd_2='m02Call',mdd_5=m2pp,mdd_6=m1i,mdd_7=qArg00;
  SET m1i=m1i+1; SET m2i=m2i+1;

 END IF;
END LOOP;
CLOSE mrw;

COMMIT;

INSERT INTO mra1_316_m1 SET mdd_1=m1pp,mdd_2='END',mdd_3=m2pp,mdd_6=@m1vval,mdd_7=@m2vval,mdd_8=m2pp,m_rec_lastid=m1i;
IF `_rollback` THEN
 INSERT INTO mra1_316_m1 SET mdd_1=m1pp,mdd_2='ERROR',mdd_3=m2pp,mdd_6=@m1vval,mdd_7=@m2vval,mdd_8=m2pp,m_rec_lastid=m1i,mdd_4=msgVR01,mdd_5=msgVR02;
END IF;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_C31ENC_05_11` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C31ENC_05_11`(mpp1 SMALLINT,mpp2 BIGINT,mpp3 VARCHAR(100),mpp4 SMALLINT)
BEGIN

DECLARE bmc INT DEFAULT 0;DECLARE _rollback TINYINT DEFAULT 0;DECLARE m1i INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qEncProcType VARCHAR(50);DECLARE qArg02 INT;DECLARE qPatientID VARCHAR(100);DECLARE qEncDischDate DATE;DECLARE qEncAdmitDate DATE;DECLARE qProcTypeNr SMALLINT;DECLARE qAlignedStatus TINYINT;DECLARE qAligned2Status TINYINT;DECLARE qIsErVisit TINYINT;DECLARE qEncPos VARCHAR(10);DECLARE qHosTaxonomy01 VARCHAR(50);DECLARE qIsSnfRec TINYINT;DECLARE qEncRefAdmitDate DATE;DECLARE qEncSnfAdmitDate DATE;DECLARE qmFlwupFlag TINYINT;DECLARE qTfuPbEr TINYINT;DECLARE qTfuPbObs TINYINT;

DECLARE msgVR01 VARCHAR(100);DECLARE msgVR02 VARCHAR(200);DECLARE mv1tmp VARCHAR(100);DECLARE mv2tmp BIGINT;

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t1.enc_proc_type,t1.pt_facility_nr,t1.patient_id,t1.enc_disch_date,t1.enc_admit_date,t1.proc_type_nr,t1.pt_aligned_status,t1.pt_aligned2status,t1.is_er_visit,t1.enc_pos,t1.hos_taxonomy01,t1.is_snf_rec,t1.is_enc_ref_admitdate,t1.is_snf_admitdate_ref,t1.m_flwup_flag,t1.tfu_pb_er,t1.tfu_pb_obs FROM mra1_encounter t1 INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=t1.patient_id WHERE YEAR(t1.enc_disch_date)>=mpp4 AND t2.mdd_2=mpp1 AND t1.entry_nr>=mpp2 ORDER BY t1.entry_nr;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
BEGIN
 SET _rollback = 1;
 GET DIAGNOSTICS CONDITION 1
 msgVR01 = RETURNED_SQLSTATE, msgVR02 = MESSAGE_TEXT;
END;

SET @cc2022Version=(SELECT cc_version FROM mra1_dcbeneroster WHERE mm_year=2022);
SET @cc2023Version=(SELECT cc_version FROM mra1_dcbeneroster WHERE mm_year=2023);
SET @cc2024Version=(SELECT cc_version FROM mra1_dcbeneroster WHERE mm_year=2024);
SET @cc2025Version=(SELECT cc_version FROM mra1_dcbeneroster WHERE mm_year=2025);
SET @cc2026Version=(SELECT cc_version FROM mra1_dcbeneroster WHERE mm_year=2026);

CREATE TEMPORARY TABLE `mra1_tm_encounter`( `entry_nr` BIGINT,`patient_id` VARCHAR(100),`enc_proc_type` VARCHAR(40),`enc_pos` VARCHAR(20),`enc_admit_date` DATE,`enc_disch_date` DATE,`proc_type_nr` SMALLINT, `is_offvisit_rec` TINYINT,`is_offvisit2rec` TINYINT,  
KEY `mkey01` (`patient_id`),KEY `mkey02` (`enc_admit_date`),KEY `mky21` (`enc_disch_date`),KEY `mkey03` (`proc_type_nr`),KEY `mkey04` (`is_offvisit_rec`),KEY `mkey05` (`is_offvisit2rec`),KEY `mkey06` (`entry_nr`),KEY `mkey07` (`enc_pos`) )
ENGINE=INNODB DEFAULT CHARSET=latin1;

INSERT INTO mra1_tm_encounter (entry_nr,patient_id,enc_proc_type,enc_admit_date,enc_disch_date,proc_type_nr,is_offvisit_rec,is_offvisit2rec,enc_pos)
SELECT e.entry_nr,e.patient_id,e.enc_proc_type,e.enc_admit_date,e.enc_disch_date,e.proc_type_nr,e.is_offvisit_rec,e.is_offvisit2rec,e.enc_pos FROM mra1_encounter AS e
INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=e.patient_id
WHERE e.proc_type_nr IN (1,2) AND YEAR(e.enc_disch_date)>=mpp4 AND t2.mdd_2=mpp1;

CREATE TEMPORARY TABLE `dc_tm_align_rostr_m01`(`cc_version` INT,`mm_curr_mbi_id` VARCHAR(100),`mm_date` DATE,`ALIGN_STATUS_CODE` VARCHAR(10),  
KEY `mkey01` (`cc_version`),KEY `mkey02` (`mm_curr_mbi_id`),KEY `mkey03` (`mm_date`),KEY `mkey04` (`ALIGN_STATUS_CODE`))
ENGINE=INNODB DEFAULT CHARSET=latin1;

INSERT INTO dc_tm_align_rostr_m01 (cc_version,mm_curr_mbi_id,mm_date,ALIGN_STATUS_CODE)
SELECT t1.cc_version,t1.mm_curr_mbi_id,t1.mm_date,t1.ALIGN_STATUS_CODE FROM dc_bene_alignment_rostr_m01 AS t1
INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=t1.mm_curr_mbi_id
WHERE t1.cc_version IN (@cc2022Version,@cc2023Version,@cc2024Version,@cc2025Version,@cc2026Version) AND t2.mdd_2=mpp1;

INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='m01Call',mdd_3=CONCAT('c2-',mpp1);

SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
START TRANSACTION;

SET @mg1vv=0; SET @mg2vv=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
  FETCH mrw INTO qArg00,qEncProcType,qArg02,qPatientID,qEncDischDate,qEncAdmitDate,qProcTypeNr,qAlignedStatus,qAligned2Status,qIsErVisit,qEncPos,qHosTaxonomy01,qIsSnfRec,qEncRefAdmitDate,qEncSnfAdmitDate,qmFlwupFlag,qTfuPbEr,qTfuPbObs;
 IF bmc = 0 THEN

  SET @mIs72HrFp=0;SET @mIs7DyHrFp=0;SET @mIs14DyHrFp=0;SET @mIsG14DyHrFp=0;SET @m72HrFpDate=NULL;SET @mTfuFollowupDate=NULL;SET @mIsEncTransfer=1;SET qEncRefAdmitDate=qEncAdmitDate;SET @mCalBedDays=DATEDIFF(qEncDischDate,qEncRefAdmitDate);

  IF qProcTypeNr=1 THEN
   IF qEncProcType IN ('Acute Hospital','Hospice','Observation') THEN
SET @tmp=(SELECT 1 FROM mra1_tm_encounter WHERE proc_type_nr=1 AND patient_id=qPatientID AND enc_proc_type=qEncProcType AND enc_admit_date=qEncDischDate AND entry_nr<>qArg00 LIMIT 1);
IF @tmp IS NULL THEN 
  SET mv1tmp=qEncAdmitDate;SET mv2tmp=qArg00; SET @mv3tmp='0;;';
  LOOP_M01: LOOP
   SET @m1val=(SELECT CONCAT(enc_admit_date,';;',entry_nr) FROM mra1_tm_encounter WHERE proc_type_nr=1 AND patient_id=qPatientID AND enc_proc_type=qEncProcType AND entry_nr<>mv2tmp AND enc_disch_date=mv1tmp LIMIT 1);
   IF @m1val IS NULL THEN
    LEAVE LOOP_M01;
   ELSEIF @m1val IS NOT NULL THEN
    SET mv1tmp=SUBSTRING_INDEX(@m1val,';;',1);SET mv2tmp=SUBSTRING_INDEX(@m1val,';;',-1);
    IF LOCATE(CONCAT(';;',mv2tmp,';;'),@mv3tmp)>0 THEN LEAVE LOOP_M01; END IF;
    SET @mv3tmp=CONCAT(@mv3tmp,mv2tmp,';;');
   END IF;
  ITERATE LOOP_M01;
  END LOOP;
  SET @mIsEncTransfer=0;SET qEncRefAdmitDate=mv1tmp; SET @mCalBedDays=DATEDIFF(qEncDischDate,qEncRefAdmitDate);
END IF;
   ELSEIF qEncPos IN ('20','30') THEN
SET @tmp=(SELECT 1 FROM mra1_tm_encounter WHERE proc_type_nr=1 AND patient_id=qPatientID AND enc_pos IN ('20','30') AND DATEDIFF(enc_admit_date,qEncDischDate) IN (0,1) LIMIT 1);
IF @tmp IS NULL THEN
  SET mv1tmp=qEncAdmitDate;SET mv2tmp=qArg00; SET @mv3tmp='0;;';
  LOOP_M01: LOOP
   SET @m1val=(SELECT CONCAT(enc_admit_date,';;',entry_nr) FROM mra1_tm_encounter WHERE proc_type_nr=1 AND patient_id=qPatientID AND enc_pos IN ('20','30') AND entry_nr<>mv2tmp AND DATEDIFF(mv1tmp,enc_disch_date) IN (0,1) LIMIT 1);
   IF @m1val IS NULL THEN
    LEAVE LOOP_M01;
   ELSEIF @m1val IS NOT NULL THEN
    SET mv1tmp=SUBSTRING_INDEX(@m1val,';;',1);SET mv2tmp=SUBSTRING_INDEX(@m1val,';;',-1);
    IF LOCATE(CONCAT(';;',mv2tmp,';;'),@mv3tmp)>0 THEN LEAVE LOOP_M01; END IF;
    SET @mv3tmp=CONCAT(@mv3tmp,mv2tmp,';;');
   END IF;
  ITERATE LOOP_M01;
  END LOOP;
  SET qIsSnfRec=1; SET qEncSnfAdmitDate=mv1tmp; SET qEncProcType='SNF'; SET @mCalBedDays=DATEDIFF(qEncDischDate,qEncSnfAdmitDate);
END IF;    
   END IF;

   IF qmFlwupFlag=1 THEN
    SET @m72HrFpDate = (SELECT e.enc_admit_date FROM mra1_tm_encounter e WHERE e.proc_type_nr IN (1,2) AND e.is_offvisit_rec=1 AND e.patient_id=qPatientID AND e.enc_admit_date>=qEncDischDate ORDER BY e.enc_admit_date LIMIT 1);
    IF @m72HrFpDate IS NOT NULL THEN
     SET @mIs72HrFp=0;SET @mIs7DyHrFp=0;SET @mIs14DyHrFp=0;SET @mIsG14DyHrFp=0;
     SET @m1vc=MRA_A31_Get72HrFlowUpDays_m1(@m72HrFpDate,qEncDischDate);

     IF @m1vc BETWEEN 0 AND 3 THEN  SET @mIs72HrFp=1; SET @mIs7DyHrFp=1; SET @mIs14DyHrFp=1; 
     ELSEIF @m1vc BETWEEN 4 AND 7 THEN  SET @mIs7DyHrFp=1; SET @mIs14DyHrFp=1;
     ELSEIF @m1vc BETWEEN 8 AND 14 THEN  SET @mIs14DyHrFp=1; END IF;
     IF @m1vc >= 0 THEN SET @mIsG14DyHrFp=1; END IF;
    END IF;
   END IF;
  END IF;

  IF qProcTypeNr=1 OR (qProcTypeNr=2 AND (qTfuPbEr=1 OR qTfuPbObs=1)) THEN
   SET @mTfuFollowupDate = (SELECT e.enc_admit_date FROM mra1_tm_encounter e WHERE e.proc_type_nr IN (1,2) AND (e.is_offvisit_rec=1 OR e.is_offvisit2rec=1) AND e.patient_id=qPatientID AND e.enc_admit_date>=qEncDischDate ORDER BY e.enc_admit_date LIMIT 1);   
  END IF;

  IF YEAR(qEncDischDate)>=2025 OR qAlignedStatus>1 THEN
   SET qAlignedStatus=0; SET @ccVersion=@cc2026Version; SET @cc2Version=@cc2026Version;

   IF YEAR(qEncDischDate)=2025 THEN SET @ccVersion=@cc2025Version;
   ELSEIF YEAR(qEncDischDate)=2024 THEN SET @ccVersion=@cc2024Version;
   ELSEIF YEAR(qEncDischDate)=2023 THEN SET @ccVersion=@cc2023Version;
   ELSEIF YEAR(qEncDischDate)=2022 THEN SET @ccVersion=@cc2022Version; END IF;

   IF YEAR(qEncRefAdmitDate)=2025 THEN SET @cc2Version=@cc2025Version;
   ELSEIF YEAR(qEncRefAdmitDate)=2024 THEN SET @cc2Version=@cc2024Version;
   ELSEIF YEAR(qEncRefAdmitDate)=2023 THEN SET @cc2Version=@cc2023Version;
   ELSEIF YEAR(qEncRefAdmitDate)=2022 THEN SET @cc2Version=@cc2022Version; END IF;

   SET @mDisDate=CONCAT(YEAR(qEncDischDate),'-',MONTH(qEncDischDate),'-01');
   SET @mRefAdtDate=CONCAT(YEAR(qEncRefAdmitDate),'-',MONTH(qEncRefAdmitDate),'-01');
   SET @vtmp = (SELECT 1 FROM dc_tm_align_rostr_m01 WHERE mm_curr_mbi_id=qPatientID AND mm_date=@mDisDate AND ALIGN_STATUS_CODE='AL' AND cc_version=@ccVersion LIMIT 1);
   IF @vtmp IS NOT NULL THEN SET qAlignedStatus=1; END IF;
   IF @mDisDate=@mRefAdtDate THEN SET qAligned2Status=qAlignedStatus;
   ELSE SET qAligned2Status=0;
    SET @vtmp = (SELECT 1 FROM dc_tm_align_rostr_m01 WHERE mm_curr_mbi_id=qPatientID AND mm_date=@mRefAdtDate AND ALIGN_STATUS_CODE='AL' AND cc_version=@cc2Version LIMIT 1);
    IF @vtmp IS NOT NULL THEN SET qAligned2Status=1; END IF;
   END IF;
  END IF;

  UPDATE mra1_encounter SET mm_test_val='a0511z',enc_proc_type=qEncProcType,tfu_followup_date=@mTfuFollowupDate,m_cal_bed_days=@mCalBedDays,pt_aligned_status=qAlignedStatus,pt_aligned2status=qAligned2Status,is_72_hr_flwup=@mIs72HrFp,is_flwup_7_days=@mIs7DyHrFp,is_flwup_14_days=@mIs14DyHrFp,is_gflwup_14_days=@mIsG14DyHrFp,m72hr_flwup_date=@m72HrFpDate,is_enc_transfer=@mIsEncTransfer,is_enc_ref_admitdate=qEncRefAdmitDate,is_snf_rec=qIsSnfRec,is_snf_admitdate_ref=qEncSnfAdmitDate WHERE entry_nr=qArg00 AND pt_facility_nr=qArg02;

  SET @mg2vv=qArg00; IF m1i=0 THEN SET @mg1vv=qArg00; END IF;
  INSERT INTO mra1_331_m1 SET mdd_1=mpp3,mdd_2='m02Call',mdd_5=mpp1,mdd_6=qArg00,mdd_7=m1i;
  SET m1i=m1i+1;

 END IF;
END LOOP;
CLOSE mrw;

COMMIT;

INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='END',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00;
IF `_rollback` THEN
 INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='ERROR',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00,mdd_4=msgVR01,mdd_5=msgVR02;
END IF;

END */$$
