/* Procedure structure for procedure `MRA_IMP1_C31ENC_05_21` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_C31ENC_05_21`(mpp1 SMALLINT,mpp2 BIGINT,mpp3 VARCHAR(100),mpp4 SMALLINT)
BEGIN

DECLARE bmc INT DEFAULT 0;DECLARE _rollback TINYINT DEFAULT 0;DECLARE m1i INT DEFAULT 0;
DECLARE qArg00 BIGINT; DECLARE qFacilityNr INT;DECLARE qEncProcType VARCHAR(50);DECLARE qEncNr BIGINT;DECLARE qPatientID VARCHAR(100);DECLARE qEncDischDate DATE;DECLARE qEncAdmitDate DATE;DECLARE qProcTypeNr SMALLINT;DECLARE qHospNr INT;DECLARE qIsErVisit TINYINT;DECLARE qEncPos VARCHAR(10);DECLARE qIsSnfRec TINYINT;DECLARE qEncRefAdmitDate DATE;DECLARE qEncSnfAdmitDate DATE;DECLARE qIsEncTransfer TINYINT;

DECLARE msgVR01 VARCHAR(100);DECLARE msgVR02 VARCHAR(200);DECLARE mv1tmp VARCHAR(100);DECLARE mv2tmp BIGINT;
DECLARE mEntryNr BIGINT;

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t1.pt_facility_nr,t1.enc_proc_type,t1.encounter_nr,t1.patient_id,t1.enc_disch_date,t1.enc_admit_date,t1.proc_type_nr,t1.mhos_cent_nr,t1.is_er_visit,t1.enc_pos,t1.is_snf_rec,t1.is_enc_ref_admitdate,t1.is_snf_admitdate_ref,t1.is_enc_transfer FROM mra1_encounter t1 INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=t1.patient_id WHERE year(t1.enc_disch_date)>=mpp4 AND t2.mdd_2=mpp1 AND t1.entry_nr>=mpp2 ORDER BY t1.entry_nr;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
BEGIN
 SET _rollback = 1;
 GET DIAGNOSTICS CONDITION 1
 msgVR01 = RETURNED_SQLSTATE, msgVR02 = MESSAGE_TEXT;
END;

INSERT INTO mra1_100_tmp SET mdd_1=mpp3,mdd_2='m01Call',mdd_3=CONCAT('c2-',mpp1);

CREATE TEMPORARY TABLE `mra1_tm_encounter`( `entry_nr` BIGINT,`pt_facility_nr` INT,`patient_id` VARCHAR(100),`enc_proc_type` VARCHAR(40),`enc_admit_date` DATE,`enc_disch_date` DATE,`proc_type_nr` SMALLINT,`enc_pos` VARCHAR(20),is_er_visit TINYINT,is_enc_transfer TINYINT, is_enc_ref_admitdate DATE,is_snf_rec TINYINT,is_snf_admitdate_ref DATE,`mhos_cent_nr` INT,`hospital_name` VARCHAR(100),  
KEY `mkey01` (`entry_nr`),KEY `mkey02` (`pt_facility_nr`),KEY `mkey03` (`patient_id`),KEY `mkey04` (`enc_proc_type`),KEY `mkey05` (`enc_admit_date`),KEY `mkey06` (`enc_disch_date`),KEY `mkey07` (`proc_type_nr`),KEY `mkey08` (`enc_pos`),KEY `mkey09` (is_er_visit),KEY `mkey10` (is_enc_transfer),KEY `mkey11` (is_enc_ref_admitdate),KEY `mkey12` (is_snf_rec),KEY `mkey13` (is_snf_admitdate_ref) ) ENGINE=INNODB DEFAULT CHARSET=latin1;


INSERT INTO mra1_tm_encounter (entry_nr,pt_facility_nr,patient_id,enc_proc_type,enc_admit_date,enc_disch_date,proc_type_nr,enc_pos,is_er_visit,is_enc_transfer,is_enc_ref_admitdate,is_snf_rec,is_snf_admitdate_ref,mhos_cent_nr,hospital_name)
SELECT e.entry_nr,e.pt_facility_nr,e.patient_id,e.enc_proc_type,e.enc_admit_date,e.enc_disch_date,e.proc_type_nr,e.enc_pos,e.is_er_visit,e.is_enc_transfer,e.is_enc_ref_admitdate,e.is_snf_rec,e.is_snf_admitdate_ref,e.mhos_cent_nr,e.hospital_name FROM mra1_encounter AS e
INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=e.patient_id
WHERE e.proc_type_nr=1 AND year(e.enc_disch_date)>=mpp4 AND t2.mdd_2=mpp1;

INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='m01Call',mdd_3=CONCAT('c2-',mpp1);

SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
START TRANSACTION;

SET @mg1vv=0; SET @mg2vv=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
  FETCH mrw INTO qArg00,qFacilityNr,qEncProcType,qEncNr,qPatientID,qEncDischDate,qEncAdmitDate,qProcTypeNr,qHospNr,qIsErVisit,qEncPos,qIsSnfRec,qEncRefAdmitDate,qEncSnfAdmitDate,qIsEncTransfer;
 IF bmc = 0 THEN

  IF qProcTypeNr=1 THEN

   IF qIsEncTransfer=0 AND qEncProcType IN ('Acute Hospital','Observation') THEN
    SET mEntryNr = (SELECT entry_nr FROM mra1_tm_encounter WHERE pt_facility_nr=qFacilityNr AND proc_type_nr=1 AND is_enc_transfer=0 AND enc_pos=qEncPos AND patient_id=qPatientID AND is_enc_ref_admitdate < qEncRefAdmitDate AND enc_disch_date <> qEncDischDate AND enc_proc_type=qEncProcType AND DATEDIFF(qEncRefAdmitDate,enc_disch_date) BETWEEN 0 AND 30 ORDER BY is_enc_ref_admitdate DESC LIMIT 1);
    IF mEntryNr IS NOT NULL THEN
     UPDATE mra1_encounter t1 LEFT JOIN adt_hosp_centers t2 ON t2.nr=qHospNr SET t1.is_c2_readmit=1,t1.pre_enc_nr=qEncNr,t1.pre_admit_date=qEncRefAdmitDate,t1.pre_discharge_date=qEncDischDate, t1.pre_hospital_nr=qHospNr, t1.pre_hosp_name=t2.`mname` WHERE t1.entry_nr=mEntryNr AND t1.pt_facility_nr=qFacilityNr;
    END IF;

    SET @mTmp= (SELECT CONCAT(e.enc_disch_date,';;',IF(e.hospital_name IS NULL,'NA',e.hospital_name)) AS mcc FROM mra1_tm_encounter e WHERE e.proc_type_nr=1 AND e.pt_facility_nr=qFacilityNr AND e.is_er_visit=1 AND e.patient_id=qPatientID AND e.enc_admit_date < qEncAdmitDate AND e.enc_disch_date <> qEncDischDate AND DATEDIFF(qEncAdmitDate,e.enc_disch_date) BETWEEN 0 AND 30 ORDER BY e.enc_admit_date DESC LIMIT 1);
    IF @mTmp IS NOT NULL THEN
     UPDATE mra1_encounter SET pre_emr_discharge_date=SUBSTRING_INDEX(@mTmp,';;',1), pre_emr_hospital_name=SUBSTRING_INDEX(@mTmp,';;',-1) WHERE entry_nr=qArg00 AND pt_facility_nr=qFacilityNr;
    END IF;
   ELSEIF qIsSnfRec=1 THEN
    SET mEntryNr = (SELECT entry_nr FROM mra1_tm_encounter WHERE pt_facility_nr=qFacilityNr AND proc_type_nr=1 AND is_snf_rec=1 AND enc_pos=qEncPos AND patient_id=qPatientID AND is_snf_admitdate_ref < qEncSnfAdmitDate AND enc_disch_date <> qEncDischDate AND DATEDIFF(qEncSnfAdmitDate,enc_disch_date) BETWEEN 0 AND 30 ORDER BY patient_id, is_snf_admitdate_ref DESC LIMIT 1);
    IF mEntryNr IS NOT NULL THEN
     UPDATE mra1_encounter t1 LEFT JOIN adt_hosp_centers t2 ON t2.nr=qHospNr SET t1.is_c2_readmit=1,t1.pre_enc_nr=qEncNr,t1.pre_admit_date=qEncSnfAdmitDate,t1.pre_discharge_date=qEncDischDate, t1.pre_hospital_nr=qHospNr, t1.pre_hosp_name=t2.`mname` WHERE t1.entry_nr=mEntryNr AND t1.pt_facility_nr=qFacilityNr;
    END IF;
   ELSEIF qIsErVisit=1 THEN
    SET @mTmp = (SELECT CONCAT(enc_disch_date,';;',IF(`mhos_cent_nr` IS NULL,0,`mhos_cent_nr`),';;',IF(`hospital_name` IS NULL,'NA',`hospital_name`)) as mcc FROM mra1_tm_encounter WHERE pt_facility_nr=qFacilityNr AND proc_type_nr=1 AND is_er_visit=1 AND patient_id=qPatientID AND enc_admit_date < qEncAdmitDate AND enc_disch_date <> qEncDischDate AND DATEDIFF(qEncAdmitDate,enc_disch_date) BETWEEN 0 AND 30 ORDER BY enc_admit_date DESC LIMIT 1);
    IF @mTmp IS NOT NULL THEN
     set @m2Tmp=SUBSTRING_INDEX(@mTmp,';;',2);set @m2Tmp=SUBSTRING_INDEX(@m2Tmp,';;',-1);
     UPDATE mra1_encounter t1 SET t1.is_er_readmit=1,t1.pre_discharge_date=SUBSTRING_INDEX(@mTmp,';;',1),t1.pre_hospital_nr=@m2Tmp,t1.pre_hosp_name=SUBSTRING_INDEX(@mTmp,';;',-1) WHERE t1.entry_nr=qArg00 AND t1.pt_facility_nr=qFacilityNr;
    END IF;
   END IF;
  END IF;

  SET @mg2vv=qArg00; IF m1i=0 THEN SET @mg1vv=qArg00; END IF;
  INSERT INTO mra1_331_m1 SET mdd_1=mpp3,mdd_2='m02Call',mdd_5=mpp1,mdd_6=qArg00,mdd_7=m1i;
  SET m1i=m1i+1;

 END IF;
END LOOP;
CLOSE mrw;

COMMIT;

INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='END',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00;
IF `_rollback` THEN
 INSERT INTO mra1_316_m1 SET mdd_1=mpp3,mdd_2='ERROR',mdd_3=mpp1,mdd_6=@mg1vv,mdd_7=@mg2vv,mdd_8=mpp1,m_rec_lastid=qArg00,mdd_4=msgVR01,mdd_5=msgVR02;
END IF;

END */$$
