SELECT e.entry_nr,e.pt_facility_nr,e.patient_id,e.enc_proc_type,e.enc_admit_date,e.enc_disch_date,e.proc_type_nr,e.enc_pos,e.is_er_visit,e.is_enc_transfer,e.is_enc_ref_admitdate,e.is_snf_rec,e.is_snf_admitdate_ref,e.hospital_nr,e.hospital_name FROM mra1_encounter AS e
