/* Procedure structure for procedure `MRA_IMP1_M03ENC31_m11_START_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_M03ENC31_m11_START_m3`(m1pp SMALLINT)
BEGIN
 DECLARE mmi INT; DECLARE mjobId INT; DECLARE m2Cnt INT; DECLARE m1sval SMALLINT;DECLARE m2sval SMALLINT;
 DECLARE mYear SMALLINT DEFAULT 2023; DECLARE mOrder SMALLINT;
 
 SET mOrder=1; SET @m1Chk=0;
 INSERT INTO mra_01_tmp SET mdd_1='mra_01_tmp',mdd_2='MRAM03ENC31_m11_START_m3',mdd_3='START';

 CALL mradb_prod.MRA_IMP1_M11ENC_m3(20,mYear);
 IF m1pp=1 THEN SET m1sval=1001; SET m2sval=1050;
 ELSEIF m1pp=3 THEN SET @m1Chk=3; END IF;

 SET @mTmp=(SELECT mdd_2 FROM mra_06_tmp WHERE mdd_1='Mra6Check' AND mdd_3='START' ORDER BY nr DESC LIMIT 1);
 IF @mTmp='m1002z' THEN SET @m1Chk=2;
 ELSEIF @mTmp='m1005z' THEN SET @m1Chk=3;
 ELSEIF @mTmp='m1006z' THEN SET @m1Chk=4; END IF;

 IF @mTmp='mmENDzz' THEN 
  SET m1sval=0; SET m2sval=0; SET mOrder=0;
 ELSE 
  
  IF @m1Chk=2 THEN SET m1sval=1002; SET m2sval=1050; SET mOrder=2;
  ELSEIF @m1Chk=3 THEN SET m1sval=1005; SET m2sval=1006; SET mOrder=3;
  ELSEIF @m1Chk=4 THEN SET m1sval=1006; SET m2sval=1006; SET mOrder=4; END IF;

  SET @m1Cnt=(SELECT COUNT(DISTINCT torder) AS mcc FROM mra1_61_tmp WHERE mjob_id BETWEEN m1sval AND m2sval);
 
  SET mmi=1;
 LOOP_M01: LOOP
  IF mmi > @m1Cnt THEN LEAVE LOOP_M01; END IF;

  SET @m1tmp=(SELECT CONCAT(mdd_1,'!@#',mjob_id) AS mcc FROM mra1_61_tmp WHERE is_active=1 AND mjob_id BETWEEN m1sval AND m2sval AND torder=mOrder LIMIT 1);

  IF @m1tmp IS NULL THEN
   SET mmi=mmi+1; ITERATE LOOP_M01;
  ELSE  
   SET @mdd_1=SUBSTRING_INDEX(@m1tmp,'!@#',1); SET mjobId=SUBSTRING_INDEX(@m1tmp,'!@#',-1);

   INSERT INTO mra_01_tmp SET mdd_1='mra_01_tmp',mdd_2=@mdd_1,mdd_3='START';
   CALL MRA_IMP1_M03ENC31_m31_m3(mjobId); CALL MRA_IMP1_M03ENC31_m12_ToCheck_m3();
   IF mjobId=1001 THEN
    INSERT INTO mra_06_tmp SET mdd_1='Mra6Check',mdd_2='m1002z',mdd_3='START';
   ELSEIF mjobId=1002 THEN
    UPDATE mra1_encounter SET m1_map3status=1 WHERE m1_map3status=2;
    SET m2Cnt=(SELECT COUNT(entry_nr) AS mcc FROM mra1_encounter WHERE YEAR(enc_disch_date)>=mYear AND m1_map3status=0);
    IF m2Cnt >= 3 THEN SET mmi=mmi-1; SET mOrder=mOrder-1;
    ELSE INSERT INTO mra_06_tmp SET mdd_1='Mra6Check',mdd_2='m1005z',mdd_3='START';
    END IF;
   ELSEIF mjobId=1005 THEN 
    INSERT INTO mra_06_tmp SET mdd_1='Mra6Check',mdd_2='m1006z',mdd_3='START';
   ELSEIF mjobId=1006 THEN 
    INSERT INTO mra_06_tmp SET mdd_1='Mra6Check',mdd_2='mmENDzz',mdd_3='START'; 
   END IF;

   SET mmi=mmi+1; SET mOrder=mOrder+1; ITERATE LOOP_M01;
  END IF; 
 END LOOP;

 END IF;

 INSERT INTO mra_06_tmp SET mdd_1='Mra6Check',mdd_2='mmENDzz',mdd_3='START';
 INSERT INTO mra_01_tmp SET mdd_1='mra_01_tmp',mdd_2='MRAM03ENC31_m11_START_m3',mdd_3='END';
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_M03ENC31_m12_ToCheck_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_M03ENC31_m12_ToCheck_m3`()
BEGIN

 DECLARE mmi INT; SET mmi=1;

 LOOP_M01:  LOOP
  IF mmi >= 300 THEN LEAVE LOOP_M01; END IF;
  IF mmi%10=0 THEN INSERT INTO mra1_100_tmp SET mdd_1='M03ENC31',mdd_2='ToCheck',mdd_3=mmi; END IF;

  SET @m1cc=(SELECT SLEEP(60) AS mcc);
  INSERT INTO mra_00_tmp SET mdd_1='mra_tmp',mdd_2='sleep',mdd_3='# 60 sec';
  SET @mcc=(SELECT mjob_id FROM mra1_61_tmp WHERE mj_start=1 LIMIT 1);
  IF @mcc IS NULL THEN
   SET mmi = 1000; LEAVE LOOP_M01;
  END IF;

  SET  mmi=mmi+1;
  ITERATE LOOP_M01;
 END LOOP;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_M03ENC31_m17_ToStop_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_M03ENC31_m17_ToStop_m3`(m1pp int)
BEGIN

 UPDATE mra1_61_tmp SET mj_start=2;
 ALTER EVENT M11_MRA1_ENC_SP11_m3 ON SCHEDULE EVERY 300 HOUR;
 ALTER EVENT M11_MRA1_ENC_SP12_m3 ON SCHEDULE EVERY 300 HOUR; 
 ALTER EVENT M11_MRA1_ENC_SP13_m3 ON SCHEDULE EVERY 300 HOUR;
 INSERT INTO mra1_100_tmp SET mdd_1=m1pp,mdd_2='END_END_END';

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_M03ENC31_m31_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_M03ENC31_m31_m3`(m1pp INT)
BEGIN

 UPDATE mra1_61_tmp SET mj_start=2;

 TRUNCATE mra1_100_tmp; TRUNCATE mra1_316_m1; TRUNCATE mra1_331_m1;
 UPDATE mradb_prod.mra1_61_tmp SET mdd_2=1,mj_start=1 WHERE mjob_id=m1pp;
 ALTER EVENT M11_MRA1_ENC_SP11_m3 ON SCHEDULE EVERY 10 SECOND; 

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_M03ENC31_n31_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_M03ENC31_n31_m3`()
BEGIN

DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 INT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 int;DECLARE qArg03 INT;DECLARE qArg04 tinyINT;

DECLARE mrw CURSOR FOR SELECT mjob_id,mdd_1,mdd_2,mdd_3,mj_type FROM mradb_prod.mra1_61_tmp WHERE mj_start=1 limit 1;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04;
 IF bmc = 0 THEN
 
  SET @m1tmp=1;
  IF qArg04=1 and qArg02>1 THEN 
   SET @m1tmp=(SELECT mdd_8 FROM mra1_316_m1 WHERE mdd_1=qArg01 AND mdd_2='START' AND mdd_8=1 LIMIT 1);
  end if;

  IF @m1tmp=1 and qArg02 <= qArg03 THEN 
   UPDATE mradb_prod.mra1_61_tmp SET mdd_2=mdd_2+1 WHERE mjob_id=qArg00;
   IF qArg02 = qArg03 THEN     
     ALTER EVENT M11_MRA1_ENC_SP12_m3 ON SCHEDULE EVERY 1 minute;
   END IF;
   INSERT INTO mra1_100_tmp SET mdd_1=qArg01,mdd_2='START',mdd_3=qArg02;
   CALL MRA_IMP1_M03ENC31_n32_m3(qArg01,qArg02,0,0,qArg03);
  elseIF @m1tmp=1 THEN
   ALTER EVENT M11_MRA1_ENC_SP11_m3 ON SCHEDULE EVERY 300 HOUR; 
   INSERT INTO mra1_100_tmp SET mdd_1=qArg01,mdd_2='ENC_SP11_m3',mdd_3='END';
  END IF;

 END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_M03ENC31_n32_11_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_M03ENC31_n32_11_m3`(mYear SMALLINT,mpp1 VARCHAR(100),mpp2 SMALLINT,mpp3 TINYINT, mpp4 BIGINT,mpp5 INT)
BEGIN

 IF mpp3=0 THEN
  INSERT INTO mra1_100_tmp SET mdd_1=mpp1,mdd_2='callNum',mdd_3=1;
  INSERT INTO mra1_316_m1 SET mdd_1=mpp1,mdd_2='START',mdd_3=mpp2,mdd_6=0,mdd_7=0,mdd_8=mpp2;
 END IF;
 INSERT INTO mra1_100_tmp SET mdd_1=mpp1,mdd_2='call02Num',mdd_3=CONCAT('mpp2: ',mpp2,' mpp4: ',mpp4);

 CASE mpp1
 WHEN 'MRAIMP1_C21CLF_P1_m3' THEN CALL mradb_prod.MRA_IMP1_C21CLF_P1_m3(mpp2,mpp4,mpp1,mYear);
 WHEN 'MRAIMP1_C21CLF_P2_m3' THEN CALL mradb_prod.MRA_IMP1_C21CLF_P2_m3(mpp2,mpp4,mpp1,mYear);
 WHEN 'MRAIMP1_C21CLF_P3_m3' THEN CALL mradb_prod.MRA_IMP1_C21CLF_P3_m3(mpp2,mpp4,mpp1,mYear);
 WHEN 'MRAIMP1_C21CLF_P4_m3' THEN CALL mradb_prod.MRA_IMP1_C21CLF_P4_m3(mpp2,mpp4,mpp1,mYear);
 WHEN 'MRAIMP1_C22_m5ENC_C11_m3' THEN CALL mradb_prod.MRA_IMP1_C22_m5ENC_C11_m3(mpp2,mpp4,mpp1,mYear);
 WHEN 'MRAIMP1_C23_m5ENC_ColMapping_m3' THEN CALL mradb_prod.MRA_IMP1_C23_m5ENC_ColMapping_m3(mpp2,mpp4,mpp1,mYear);
 WHEN 'MRAIMP1_B221_m5Roster_K15_m3' THEN CALL mradb_prod.MRA_IMP1_B211_m5Roster_K15_m3(mpp2,mpp4,mpp1,mYear);
 WHEN 'MRAIMP14_C21ENC01m1' THEN CALL mradb_prod.MRA_IMP14_C21ENC01_m3(mpp2,mpp4,mpp1,mYear); 
 WHEN 'MRAIMP14_C31ENC01m1' THEN CALL mradb_prod.MRA_IMP14_C31ENC01_m3(mpp2,mpp4,mpp1,mYear);
 WHEN 'MRAIMP14_C32ENC01m1' THEN CALL mradb_prod.MRA_IMP14_C32ENC01_m3(mpp2,mpp4,mpp1,mYear);
 END CASE;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_M03ENC31_n32_21_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_M03ENC31_n32_21_m3`(mYear SMALLINT,mpp1 VARCHAR(100), mpp2 SMALLINT, mpp3 TINYINT, mpp4 BIGINT, mpp5 INT)
BEGIN

 IF mpp3=0 THEN
  INSERT INTO mra1_100_tmp SET mdd_1=mpp1,mdd_2='callNum',mdd_3=1;
  SET @mtmp = (SELECT CONCAT(MIN(e.entry_nr),'!@#',MAX(e.entry_nr)) AS mcc FROM mra1_encounter e INNER JOIN mra1_311_m1 t2 ON t2.mdd_1=e.patient_id WHERE year(e.enc_disch_date)>=mYear AND t2.mdd_2=mpp2);
  SET @m3vv=SUBSTRING_INDEX(@mtmp,'!@#',1); SET @m4vv=SUBSTRING_INDEX(@mtmp,'!@#',-1);
  INSERT INTO mra1_316_m1 SET mdd_1=mpp1,mdd_2='START',mdd_3=mpp2,mdd_6=@m3vv,mdd_7=@m4vv,mdd_8=mpp2;
  SET mpp4=CONVERT(@m3vv,SIGNED);
 END IF;
 INSERT INTO mra1_100_tmp SET mdd_1=mpp1,mdd_2='call02Num',mdd_3=CONCAT('mpp2: ',mpp2,' mpp4: ',mpp4);
 IF mpp1='MRAIMP1_C31ENC05m1' THEN CALL mradb_prod.MRA_IMP1_C31ENC_05_11(mpp2, mpp4, mpp1, mYear);
 ELSEIF mpp1='MRAIMP1_C31ENC05m2' THEN CALL mradb_prod.MRA_IMP1_C31ENC_05_21(mpp2, mpp4, mpp1, mYear); END IF;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_M03ENC31_n32_31_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_M03ENC31_n32_31_m3`(mYear SMALLINT,mpp1 VARCHAR(100),mpp2 SMALLINT,mpp3 TINYINT,mpp4 BIGINT,mpp5 INT)
BEGIN

 SET @m01val=0; SET @m03val=0;
 IF mpp2=mpp5 THEN 
  SET @m02val = (SELECT mdd_9 FROM mra1_316_m1 WHERE mdd_1=mpp1 AND mdd_2='START' AND mdd_8=1 LIMIT 1);
 END IF;
 IF mpp3=0 THEN SET @m5tmp=0;
  IF mpp2=1 THEN
   IF mpp1 IN ('MRAIMP1_C31ENC03m1','MRAIMP1_X31TEST_03') THEN
    SET @m03val = (SELECT COUNT(entry_nr) AS mcc FROM mra1_encounter WHERE year(enc_disch_date)>=mYear);
   ELSEIF mpp1 = 'MRAIMP1_C31ENC04m1' THEN
    SET @m03val = (SELECT COUNT(entry_nr) AS mcc FROM mra1_encounter WHERE year(enc_disch_date)>=mYear and m1_map3status=0);
   END IF;
   SET @m3tmp = (@m03val)/mpp5; SET @m3tmp = FLOOR(@m3tmp);
   SET @m4tmp = @m3tmp * mpp5; SET @m5tmp = @m03val - @m4tmp;
  ELSE
   SET @m3tmp = (SELECT (mdd_7+1) AS mcc FROM mra1_316_m1 WHERE mdd_1=mpp1 AND mdd_2='START' AND mdd_8=1 LIMIT 1);
  END IF;
  SET @m2tmp = (mpp2-1) * @m3tmp; SET @m7tmp = (@m3tmp-1);
  IF mpp2=mpp5 THEN SET @m7tmp = (@m7tmp+@m02val); END IF;
  INSERT INTO mra1_316_m1 SET mdd_1=mpp1,mdd_2='START',mdd_3=mpp2,mdd_6=@m2tmp,mdd_7=@m7tmp,mdd_8=mpp2,mdd_9=@m5tmp;
 ELSEIF mpp3=1 THEN
  SET @m3tmp = (SELECT (mdd_7+1) AS mcc FROM mra1_316_m1 WHERE mdd_1=mpp1 AND mdd_2='START' AND mdd_8=1 LIMIT 1);
  SET @m2tmp = (mpp2-1) * @m3tmp; SET @m01val=mpp4;
  SET @m2tmp = @m2tmp + mpp4; SET @m3tmp = @m3tmp - mpp4;   
 END IF;
 IF mpp2=mpp5 THEN SET @m3tmp = (@m3tmp+@m02val); END IF;

 INSERT INTO mra1_100_tmp SET mdd_1=mpp1,mdd_2=mpp2,mdd_3=@m2tmp,mdd_4=@m3tmp,mdd_5=@m01val;
 IF mpp1='MRAIMP1_C31ENC03m1' THEN CALL mradb_prod.MRA_IMP1_C31ENC_03(mpp1,mpp2,@m2tmp,@m3tmp,@m01val,mYear);
 ELSEIF mpp1='MRAIMP1_C31ENC04m1' THEN CALL mradb_prod.MRA_IMP1_C31ENC_04_11(mpp1,mpp2,@m2tmp,@m3tmp,@m01val,mYear);
 ELSEIF mpp1='MRAIMP1_X31TEST_03' THEN CALL mradb_prod.MRA_IMP1_X31TEST_03(mpp1,mpp2,@m2tmp,@m3tmp,@m01val,mYear); END IF;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_M03ENC31_n32_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_M03ENC31_n32_m3`(mpp1 VARCHAR(100), mpp2 SMALLINT, mpp3 TINYINT, mpp4 BIGINT, mpp5 INT)
BEGIN

 DECLARE mYear smallINT DEFAULT 2023;

 SET @mjType=(SELECT mj_type FROM mra1_61_tmp WHERE mdd_1=mpp1 LIMIT 1);

 IF @mjType=0 THEN
  call MRA_IMP1_M03ENC31_n32_21_m3(mYear,mpp1,mpp2,mpp3,mpp4,mpp5);
 ELSEIF @mjType=1 THEN
  call MRA_IMP1_M03ENC31_n32_31_m3(mYear,mpp1,mpp2,mpp3,mpp4,mpp5);
 ELSEIF @mjType=3 THEN
  CALL MRA_IMP1_M03ENC31_n32_11_m3(mYear,mpp1,mpp2,mpp3,mpp4,mpp5); 
 END IF;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_M03ENC31_n41_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_M03ENC31_n41_m3`()
BEGIN

DECLARE bmc INT DEFAULT 0; DECLARE mmi INT; DECLARE mc1v INT;
DECLARE qArg00 INT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 INT;DECLARE qArg03 INT;DECLARE qMjType tinyINT;

DECLARE mrw CURSOR FOR SELECT mjob_id,mdd_1,mdd_2,mdd_3,mj_type FROM mradb_prod.mra1_61_tmp WHERE mj_start=1;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qMjType;
 IF bmc = 0 THEN

  SET mc1v= 1; 
  SET @m2vv=(SELECT nr FROM mra1_316_m1 WHERE mdd_1=qArg01 AND mdd_2='START' AND m_status=0 LIMIT 1);
  SET @m3vv=(SELECT nr FROM mra1_316_m1 WHERE mdd_1=qArg01 AND mdd_2='START' AND m_status=1 LIMIT 1);
  IF @m2vv IS NULL and @m3vv IS not NULL THEN
   cALL MRA_IMP1_M03ENC31_m17_ToStop_m3(qArg00); SET qArg02=2;
  ELSE 
   SET mc1v=(SELECT COUNT(nr) AS mcc FROM mra1_316_m1 WHERE mdd_1=qArg01 AND mdd_2='END');
   SET qArg02 = qArg02-1;   
  END IF;
  
  INSERT INTO mra1_100_tmp SET mdd_1=qArg01,mdd_2='END_COUNT',mdd_3=mc1v,mdd_4=qArg02;

 IF mc1v= qArg02 THEN 
  IF qMjType= 3 THEN
   UPDATE mra1_316_m1 SET m_status=1,m_rec_lastid=0 WHERE mdd_1=qArg01 AND mdd_2='START';
  else
  SET mmi = 1;
  LOOP_M01:  LOOP
   IF mmi > mc1v THEN LEAVE LOOP_M01; END IF;
   SET @m21v=(SELECT mdd_7 FROM mra1_316_m1 WHERE mdd_1=qArg01 AND mdd_2='START' AND mdd_8=mmi AND m_status=0 and m2_rscount<5 LIMIT 1);
   INSERT INTO mra1_100_tmp SET mdd_1=qArg01,mdd_2='mc_310',mdd_3=mmi,mdd_4=@m21v;
   IF @m21v IS NOT NULL THEN
    SET @m21v=CONVERT(@m21v,SIGNED);
    #SET @m22v=(SELECT mdd_6 FROM mra1_331_m1 WHERE mdd_1=qArg01 AND mdd_5=mmi ORDER BY nr DESC LIMIT 1);
    SET @m22v=(SELECT m_rec_lastid FROM mra1_316_m1 WHERE mdd_1=qArg01 AND mdd_2='END' AND mdd_8=mmi LIMIT 1);
    if @m22v is null then set @m22v=0; end if;
    SET @m22v=CONVERT(@m22v,SIGNED);
    IF @m22v>=@m21v THEN
     UPDATE mra1_316_m1 SET m_status=1,m_rec_lastid=@m22v WHERE mdd_1=qArg01 AND mdd_2='START' AND mdd_8=mmi;
     INSERT INTO mra1_100_tmp SET mdd_1=qArg01,mdd_2='mc_end_m3',mdd_3=mmi,mdd_4=@m22v,mdd_5=@m21v;
    ELSE
     UPDATE mra1_316_m1 SET m2status=1,m_status=0,m2_rscount=(m2_rscount+1),m_rec_lastid=@m22v WHERE mdd_1=qArg01 AND mdd_2='START' AND mdd_8=mmi;
     ALTER EVENT M11_MRA1_ENC_SP13_m3 ON SCHEDULE EVERY 10 second;
     INSERT INTO mra1_100_tmp SET mdd_1=qArg01,mdd_2='mc_restart_m3',mdd_3=mmi,mdd_4=@m22v,mdd_5=@m21v;
    END IF;
   END IF;
   SET mmi = mmi + 1; ITERATE LOOP_M01;
  END LOOP;    
  END IF;  
 END IF;

  SET @m2vv=(SELECT nr FROM mra1_316_m1 WHERE mdd_1=qArg01 AND mdd_2='START' AND m_status=0 LIMIT 1);
  SET @m3vv=(SELECT nr FROM mra1_316_m1 WHERE mdd_1=qArg01 AND mdd_2='START' AND m_status=1 LIMIT 1);
  IF @m2vv IS NULL AND @m3vv IS NOT NULL THEN
   call MRA_IMP1_M03ENC31_m17_ToStop_m3(qArg00);
  END IF;

 END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_M03ENC31_n42_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_M03ENC31_n42_m3`()
BEGIN

DECLARE bmc INT DEFAULT 0; DECLARE mmi INT;
DECLARE qArg00 INT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 INT;DECLARE qArg03 BIGINT;

DECLARE mrw CURSOR FOR SELECT nr,mdd_1,mdd_8,m_rec_lastid FROM mradb_prod.mra1_316_m1 WHERE m2status=1 LIMIT 1;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03;
 IF bmc = 0 THEN

  SET @m1tmp=(SELECT mdd_3 FROM mra1_61_tmp WHERE mdd_1=qArg01 LIMIT 1);
  UPDATE mra1_316_m1 SET m2status=2 WHERE nr=qArg00;
  DELETE FROM mra1_316_m1 WHERE mdd_1=qArg01 AND mdd_2='END' AND mdd_8=qArg02;
  INSERT INTO mra1_100_tmp SET mdd_1=qArg01,mdd_2='mc_n42_m3',mdd_3=qArg02,mdd_4=qArg03;
  CALL MRA_IMP1_M03ENC31_n32_m3(qArg01,qArg02,1,qArg03,@m1tmp);

 END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_M10AA_MainCall` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_M10AA_MainCall`()
BEGIN

 INSERT INTO mra_01_tmp SET mdd_1='mra_start',mdd_2='MRAIMP1_M10AA_MainCall',mdd_3='START';
 call MRA_IMP1_M03ENC31_m11_START_m3(1);

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_M10AC_MainCall` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_M10AC_MainCall`()
BEGIN

 call MRA_IMP1_B210_m3Roster_START_m3(3);

 INSERT INTO mra_01_tmp SET mdd_1='mrai',mdd_2='EXTRA_SCRPT',mdd_3='START';
 UPDATE `alert_draft_queue` t1 INNER JOIN `mra1_encounter_icd_codes` t2 ON t1.encounter_nr=t2.encounter_nr SET t1.code_nr=t2.`entry_nr` WHERE t1.code=t2.diagnosis_code AND t1.type='icd' AND t1.code_nr!=t2.`entry_nr`;

 INSERT INTO mra_01_tmp SET mdd_1='mra_end',mdd_2='MRAIMP1_M10AA_MainCall',mdd_3='END';

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_M11ENC_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_M11ENC_m3`(m1pp tinyINT,m2pp smallINT)
BEGIN

DECLARE mmi INT; DECLARE m2mi INT; DECLARE m3mi INT;
DECLARE vtmp VARCHAR(100); 

TRUNCATE mra1_311_m1; TRUNCATE mra_00_tmp;
insert into mra_00_tmp set mdd_1='START',mdd_2=0;

INSERT INTO mra1_311_m1 (mdd_1,mdd_2)
SELECT DISTINCT t1.origid,1 FROM cclf_encounter t1 WHERE year(t1.discharge_date)>=m2pp AND t1.mra_proc_type_nr between 1 and 4;

SET m3mi = (SELECT COUNT(mdd_1) FROM mra1_311_m1);
SET m3mi = CEIL(m3mi/m1pp);

SET mmi = 1;

LOOP_M01:  LOOP

 SET m2mi= ((mmi-1)*m3mi ) +1;
 UPDATE mra1_311_m1 SET mdd_2=mmi WHERE nr BETWEEN m2mi AND (m2mi+(m3mi-1)); 
 IF  mmi > m1pp THEN LEAVE  LOOP_M01;  END  IF;
 SET  mmi = mmi + 1;
 insert into mra_00_tmp set mdd_1='m1cc',mdd_2=mmi;

 ITERATE  LOOP_M01;
END LOOP;

UPDATE mra1_311_m1 SET mdd_1='a123z' WHERE mdd_1='' OR mdd_1 IS NULL;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_X03ENC31_m11_START_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_X03ENC31_m11_START_m3`()
BEGIN
 DECLARE mmi INT;

 INSERT INTO mra_01_tmp SET mdd_1='mra_01_tmp',mdd_2=1,mdd_3='START';
 CALL MRA_IMP1_M03ENC31_m31_m3(1001); CALL MRA_IMP1_M03ENC31_m12_ToCheck_m3();
 INSERT INTO mra_01_tmp SET mdd_1='mra_01_tmp',mdd_2=1,mdd_3='START';
 CALL MRA_IMP1_M03ENC31_m31_m3(1006); CALL MRA_IMP1_M03ENC31_m12_ToCheck_m3();


END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_X31TEST_03` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_X31TEST_03`(m1pp VARCHAR(100),m2pp INT,m3pp BIGINT,m4pp BIGINT,m5pp INT,m6pp SMALLINT)
BEGIN

DECLARE bmc INT DEFAULT 0;DECLARE _rollback TINYINT DEFAULT 0;DECLARE m1i INT;DECLARE m2i INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg02 INT;DECLARE qArg03 INT;DECLARE qEncounterNr BIGINT;DECLARE qDischDate DATE;DECLARE qProcTypeNr SMALLINT;DECLARE qIsErVisit TINYINT;DECLARE qEncPos VARCHAR(10);DECLARE qHosTaxonomy01 VARCHAR(50);DECLARE qIsSnfRec TINYINT;DECLARE qMproviderMr INT;DECLARE qPatientID VARCHAR(100);DECLARE qAdmitDate DATE;DECLARE qEdischargeType VARCHAR(5);DECLARE qMproviderNr INT;DECLARE qMraClmReferNum BIGINT;

DECLARE mEncProcType VARCHAR(50);DECLARE msgVR01 VARCHAR(100);DECLARE msgVR02 VARCHAR(200);

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t1.pt_facility_nr,t1.pt_facility_sub_nr,t1.encounter_nr,t1.enc_disch_date,t1.proc_type_nr,t1.is_er_visit,t1.enc_pos,t1.hos_taxonomy01,t1.is_snf_rec,t1.m_provider_nr,t1.patient_id,t1.enc_admit_date,t1.e_discharge_type,t1.m_provider_nr,t1.mra_clm_refer_num FROM mra1_encounter t1 WHERE YEAR(t1.enc_disch_date)>=m6pp ORDER BY t1.entry_nr LIMIT m3pp,m4pp;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc=1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
BEGIN
 SET _rollback = 1;
 GET DIAGNOSTICS CONDITION 1
 msgVR01 = RETURNED_SQLSTATE, msgVR02 = MESSAGE_TEXT;
END;

SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
START TRANSACTION;

SET m1i=m5pp; SET @m1vval=0; SET @m2vval=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg02,qArg03,qEncounterNr,qDischDate,qProcTypeNr,qIsErVisit,qEncPos,qHosTaxonomy01,qIsSnfRec,qMproviderMr,qPatientID,qAdmitDate,qEdischargeType,qMproviderNr,qMraClmReferNum;

 IF bmc = 0 THEN
  SET @mIsVisitPcp=0;

  SET @mIsVisitPcp= (SELECT 1 from personell_hosp_assocs where hospital_nr=qArg02 AND user_nr=qMproviderMr LIMIT 1);
  IF @mIsVisitPcp is null THEN SET @mIsVisitPcp=0; END IF;  


  UPDATE mra1_encounter SET mm_test_val='a_h01_z',is_visit_pcp=@mIsVisitPcp,is_offvisit_rec=NULL WHERE entry_nr=qArg00 AND pt_facility_nr=qArg02;

  IF qProcTypeNr in (1,2) THEN
   IF @mIsVisitPcp=1 THEN
    UPDATE mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr INNER JOIN personell t4 ON t1.m_provider_nr=t4.nr SET t1.is_offvisit_rec=1 WHERE ( (t2.bb_Code IN ('98000','98001','98002','98003','98004','98005','98006','98007','98008','98009','98010','98011','98012','98013','98014','98015','98016','90957','90958','90959','90960','90961','90962','90965','90966','90969','90970','92002','92004','92012','92014','93750','93797','93798','94004','94625','94626','94664','96160','96164','96165','96167','96168','97129','97130','97151','97152','97161','97162','97163','97164','97530','97535','97750','97755','97761','97763','97802','97803','97804','98960','98961','98962','98966','98967','98968','98970','98971','98972','99091','99201','99202','99203','99204','99205','99211','99212','99213','99214','99215','99241','99242','99243','99244','99245','99341','99342','99343','99344','99345','99347','99348','99349','99350','99381','99382','99383','99384','99385','99386','99387','99391','99392','99393','99394','99395','99396','99397','99401','99402','99403','99404','99411','99412','99421','99422','99423','99429','99441','99442','99443','99453','99454','99455','99456','99457','99458','99473','99474','99487','99489','99490','99491','99495','99496','99497','99498','0591T','0592T','0593T','G0071','G0108','G0109','G0270','G0296','G0402','G0406','G0407','G0408','G0420','G0421','G0422','G0423','G0425','G0426','G0427','G0438','G0439','G0446','G0459','G0463','G0506','G0508','G0509','G0511','G0512','G0513','G0514','G2010','G2012','G2025','G2061','G2062','G2063','G2211','G2212','G2250','G2251','G2252','G3002','G3003','G9481','G9482','G9483','G9484','G9485','G9486','G9487','G9488','G9489','T1015','G2001','G2002','G2003','G2004','G2005','G2006','G2007','G2008','G2009','G2013','G2014','G2015') AND (t1.proc_type_nr=2 OR (t1.proc_type_nr=1 AND t1.enc_pos="40")) ) OR (t1.proc_type_nr=2 AND t1.enc_pos IN ('02','10')) ) AND t4.is_dce=1 AND t4.dce_type='DCE' AND t1.entry_nr=qArg00 AND t1.pt_facility_nr=qArg02;
   END IF;
  END IF;


  SET @m2vval=qArg00; IF m2i=0 THEN SET @m1vval=qArg00; END IF;
  INSERT INTO mra1_331_m1 SET mdd_1=m1pp,mdd_2='m02Call',mdd_5=m2pp,mdd_6=m1i,mdd_7=qArg00;
  SET m1i=m1i+1; SET m2i=m2i+1;

 END IF;
END LOOP;
CLOSE mrw;

COMMIT;

INSERT INTO mra1_316_m1 SET mdd_1=m1pp,mdd_2='END',mdd_3=m2pp,mdd_6=@m1vval,mdd_7=@m2vval,mdd_8=m2pp,m_rec_lastid=m1i;
IF `_rollback` THEN
 INSERT INTO mra1_316_m1 SET mdd_1=m1pp,mdd_2='ERROR',mdd_3=m2pp,mdd_6=@m1vval,mdd_7=@m2vval,mdd_8=m2pp,m_rec_lastid=m1i,mdd_4=msgVR01,mdd_5=msgVR02;
END IF;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP1_Z31_m5_tmp_k3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP1_Z31_m5_tmp_k3`(m1pp TINYINT)
BEGIN

DECLARE mmi INT; DECLARE m2mi INT; DECLARE m3mi INT;
DECLARE vtmp VARCHAR(100); 

TRUNCATE mra1_311_m1; TRUNCATE mra_00_tmp;
INSERT INTO mra_00_tmp SET mdd_1='START',mdd_2=0;

INSERT INTO mra1_311_m1 (mdd_1,mdd_2,mdd_3)
SELECT DISTINCT t1.patient_id,1,'m5ENC_tmp_k3' FROM mra1_encounter t1 WHERE t1.m1_map_status=5 AND t1.proc_type_nr BETWEEN 1 AND 4;

SET m3mi = (SELECT COUNT(mdd_1) FROM mra1_311_m1);
SET m3mi = CEIL(m3mi/m1pp);

SET mmi = 1;

LOOP_M01:  LOOP

 SET m2mi= ((mmi-1)*m3mi ) +1;
 UPDATE mra1_311_m1 SET mdd_2=mmi WHERE nr BETWEEN m2mi AND (m2mi+(m3mi-1)); 
 IF  mmi > m1pp THEN LEAVE  LOOP_M01;  END  IF;
 SET  mmi = mmi + 1;
 INSERT INTO mra_00_tmp SET mdd_1='m1cc',mdd_2=mmi;

 ITERATE  LOOP_M01;
END LOOP;

UPDATE mra1_311_m1 SET mdd_1='a123z' WHERE mdd_1='' OR mdd_1 IS NULL;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP2_CR_M11_CStart_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP2_CR_M11_CStart_m3`()
BEGIN

 CALL MRA_IMP2_CR_M31_Part_A_m3();
 CALL MRA_IMP2_CR_M31_Part_B_m3();
 CALL MRA_IMP2_CR_M32_Roster_m3();

/*
SELECT id,CLMH_MEDICARE_PART FROM mra_file_static.mra_clm1_claims 
WHERE  CLMH_FROM_DT>='2024-01-01' AND map_data_status=0 AND map_process_status=1

SELECT nr,CLMH_MBI,CLMH_FROM_DT,CLMH_PVDR_CCN,CLMH_DCN,CLMH_FROM_DT,CLMH_PVDR_NPI,CLMH_THRU_DT 
FROM mra_cr_m3_part_a WHERE map_data_status=0 
*/

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP2_CR_M31_Part_A_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP2_CR_M31_Part_A_m3`()
BEGIN

DECLARE mi INT DEFAULT 0; DECLARE bmc INT DEFAULT 0;

DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(100);DECLARE qArg06 VARCHAR(20);DECLARE qADJSMT_Type VARCHAR(5);DECLARE qArg08 VARCHAR(30);DECLARE qArg09 VARCHAR(30);DECLARE qArg10 VARCHAR(30);DECLARE qArg11 VARCHAR(30);
DECLARE mClmReimbAmt decimal(11,2);DECLARE mClmCoInsAmt decimal(11,2);DECLARE mClmDdcPayAmt decimal(11,2);
DECLARE mClmTccRedAmt DECIMAL(11,2);DECLARE mClmSeqAmt DECIMAL(11,2);DECLARE mClmAllowAmt DECIMAL(11,2);
DECLARE qArg12 VARCHAR(300);DECLARE qArg13 VARCHAR(50);DECLARE qArg14 text;

DECLARE mrw CURSOR FOR SELECT id,CLMH_MBI,CLMH_FROM_DT,CLMH_PVDR_CCN,CLMH_PVDR_NPI,CLMH_DCN,file_date,CLMH_ADJSMT_TYPE_CD,CLMH_BILL_FACILITY,CLMH_BILL_CATEGORY,CLMH_PVDR_NPI,CLMH_THRU_DT,CLMH_REIMB_AMT,CLMH_BENE_PMT_COINSRNC_AMT,CLMH_RCPNT_PMT_DDCTBL_PD_AMT,CLMH_TCC_RED_AMT,CLMH_SEQ_AMT,filename,file_line_no,CONCAT(IF(CLMH_DIAG_CODE_1 IS NULL OR CLMH_DIAG_CODE_1='','-',CLMH_DIAG_CODE_1),', ',IF(CLMH_DIAG_CODE_2 IS NULL OR CLMH_DIAG_CODE_2='','-',CLMH_DIAG_CODE_2),', ',IF(CLMH_DIAG_CODE_3 IS NULL OR CLMH_DIAG_CODE_3='','-',CLMH_DIAG_CODE_3),', ',IF(CLMH_DIAG_CODE_4 IS NULL OR CLMH_DIAG_CODE_4='','-',CLMH_DIAG_CODE_4),', ',IF(CLMH_DIAG_CODE_5 IS NULL OR CLMH_DIAG_CODE_5='','-',CLMH_DIAG_CODE_5),', ',IF(CLMH_DIAG_CODE_6 IS NULL OR CLMH_DIAG_CODE_6='','-',CLMH_DIAG_CODE_6),', ',IF(CLMH_DIAG_CODE_7 IS NULL OR CLMH_DIAG_CODE_7='','-',CLMH_DIAG_CODE_7),', ',IF(CLMH_DIAG_CODE_8 IS NULL OR CLMH_DIAG_CODE_8='','-',CLMH_DIAG_CODE_8),', ',IF(CLMH_DIAG_CODE_9 IS NULL OR CLMH_DIAG_CODE_9='','-',CLMH_DIAG_CODE_9),', ',IF(CLMH_DIAG_CODE_10 IS NULL OR CLMH_DIAG_CODE_10='','-',CLMH_DIAG_CODE_10)) FROM mra_file_static.mra_clm1_claims WHERE CLMH_MEDICARE_PART !='HUBC' AND CLMH_FROM_DT>='2024-01-01' AND map_data_status=0 AND map_process_status=1 order by CLMH_MBI,CLMH_FROM_DT,CLMH_PVDR_CCN;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

INSERT INTO mra_01_tmp SET mdd_1="CR_IMP2_Part_A",mdd_2='START',mdd_3='-';

SET @mRosterV2024n=(SELECT MAX(cc_version) FROM dc_bene_alignment_rostr_m01 WHERE mm_year=2024);
SET @mRosterV2025n=(SELECT MAX(cc_version) FROM dc_bene_alignment_rostr_m01 WHERE mm_year=2025);

DROP TABLE IF EXISTS mra6_dc_bene_m01; DROP TABLE IF EXISTS mra6_dc_bene_m02;

CREATE TEMPORARY TABLE `mra6_dc_bene_m01`(
  `cc_version` INT,`prov_npi_nr` VARCHAR(20),mm_date DATE,`ALIGN_STATUS_CODE` VARCHAR(20), `mm_curr_mbi_id` VARCHAR(100),  
  KEY `mkey01` (`cc_version`),KEY `mkey02` (`prov_npi_nr`),KEY `mkey03` (`mm_curr_mbi_id`),KEY `mkey04` (`mm_date`)
) ENGINE=INNODB DEFAULT CHARSET=latin1;

INSERT INTO mra6_dc_bene_m01 (cc_version,mm_curr_mbi_id,prov_npi_nr,mm_date,ALIGN_STATUS_CODE)
SELECT cc_version,mm_curr_mbi_id,prov_npi_nr,mm_date,ALIGN_STATUS_CODE 
FROM dc_bene_alignment_rostr_m01 WHERE cc_version IN (@mRosterV2024n,@mRosterV2025n);

CREATE TEMPORARY TABLE `mra6_dc_bene_m02`(
  `cc_version` INT,`prov_npi_nr` VARCHAR(20),  
  KEY `mkey01` (`cc_version`),KEY `mkey02` (`prov_npi_nr`)
) ENGINE=INNODB DEFAULT CHARSET=latin1;

INSERT INTO mra6_dc_bene_m02 (cc_version,prov_npi_nr)
SELECT DISTINCT cc_version,prov_npi_nr FROM dc_bene_alignment_rostr_m01 
WHERE cc_version IN (@mRosterV2024n,@mRosterV2025n);

SET @mFormulaType=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05,qArg06,qADJSMT_Type,qArg08,qArg09,qArg10,qArg11,mClmReimbAmt,mClmCoInsAmt,mClmDdcPayAmt,mClmTccRedAmt,mClmSeqAmt,qArg12,qArg13,qArg14;
 
 IF bmc = 0 THEN

  IF mClmReimbAmt IS NULL THEN SET mClmReimbAmt=0; END IF; IF mClmCoInsAmt IS NULL THEN SET mClmCoInsAmt=0; END IF;
  IF mClmDdcPayAmt IS NULL THEN SET mClmDdcPayAmt=0; END IF; IF mClmTccRedAmt IS NULL THEN SET mClmTccRedAmt=0; END IF;
  IF mClmSeqAmt IS NULL THEN SET mClmSeqAmt=0; END IF;

  if qArg06 >= '2025-02-07' then
   SET @mFormulaType=1; 
  elseif qArg06 between '2025-01-01' and '2025-02-06' and year(qArg02)>=2025 then
   SET @mFormulaType=1;
  end if;
 
  SET @ttmp= (SELECT nr FROM bt_static.mra_clmred_pcp_m1_cm WHERE Performance_Year = YEAR(qArg06) AND Organization_NPI=qArg04 AND CCN=qArg03 AND Provider_Class IS NOT NULL AND Provider_Class<>'' AND qArg06 BETWEEN Effective_Start_Date AND Effective_End_Date ORDER BY cc_version,nr DESC LIMIT 1);
  IF @ttmp IS NULL THEN
   SET @ttmp= (SELECT nr FROM bt_static.mra_clmred_pcp_m1_cm WHERE Performance_Year = YEAR(qArg06) AND Organization_NPI=qArg04 AND CCN=qArg03 AND Provider_Class IS NOT NULL AND Provider_Class<>'' ORDER BY cc_version,nr DESC LIMIT 1);
  end if;

  SET @mcVal = (SELECT CONCAT(IF(Provider_Class IS NULL,'',Provider_Class),'!@#',IF(Capped_or_FFS IS NULL,'',Capped_or_FFS),'!@#',IF(FFS_Carveout_Rate_per IS NULL,'',FFS_Carveout_Rate_per),'!@#',IF(PCP_Services_Rate_per IS NULL,'',PCP_Services_Rate_per),'!@#',IF(Individual_NPI IS NULL,'',Individual_NPI),'!@#',IF(Base_Provider_TIN IS NULL,'',Base_Provider_TIN),'!@#',IF(Organization_NPI IS NULL,'',Organization_NPI),'!@#',IF(CCN IS NULL,'',CCN),'!@#az') as mcc FROM bt_static.mra_clmred_pcp_m1_cm WHERE nr=@ttmp);

  SET @m1val= SUBSTRING_INDEX(@mcVal,'!@#',1);
  SET @ttmp= SUBSTRING_INDEX(@mcVal,'!@#',2); SET @m2val= SUBSTRING_INDEX(@ttmp,'!@#',-1);
  SET @ttmp= SUBSTRING_INDEX(@mcVal,'!@#',3); SET @m3val= SUBSTRING_INDEX(@ttmp,'!@#',-1);
  SET @ttmp= SUBSTRING_INDEX(@mcVal,'!@#',4); SET @m4val= SUBSTRING_INDEX(@ttmp,'!@#',-1);
  SET @ttmp= SUBSTRING_INDEX(@mcVal,'!@#',5); SET @m5val= SUBSTRING_INDEX(@ttmp,'!@#',-1);
  SET @ttmp= SUBSTRING_INDEX(@mcVal,'!@#',6); SET @m6val= SUBSTRING_INDEX(@ttmp,'!@#',-1);
  SET @ttmp= SUBSTRING_INDEX(@mcVal,'!@#',7); SET @m7val= SUBSTRING_INDEX(@ttmp,'!@#',-1);
  SET @ttmp= SUBSTRING_INDEX(@mcVal,'!@#',8); SET @m8val= SUBSTRING_INDEX(@ttmp,'!@#',-1);
  IF @m3val IS NULL THEN SET @m3val=0; END IF; IF @m4val IS NULL THEN SET @m4val=0; END IF;

  SET @m81val= (SELECT 1 FROM bt_static.mra_clmred_pcp_m2_cap_services WHERE qArg06 BETWEEN fl_startdate AND fl_enddate and qArg02 between py_startdate and py_enddate AND pcp_cap_service in (SELECT distinct CLML_HCPC_CD FROM mra_file_static.mra_clm1_claim_details WHERE claim_id=qArg00) LIMIT 1);

  SET mClmAllowAmt= mClmReimbAmt + mClmCoInsAmt + mClmDdcPayAmt + mClmTccRedAmt + mClmSeqAmt;

  SET @m_logs='Provider_Rate_Missing'; SET @mForCMS_Amt=0;
  IF @m1val='Participant Provider' AND UPPER(@m2val) IN ('CAP','FFS','BOTH') THEN
   IF UPPER(@m2val)='CAP' or @mFormulaType=0 then
    SET @m_logs = CONCAT('(Allowed * FFS_Carveout_Rate_Calc) - CLMH_Sequest_Amt'); SET @mRatePer = @m3val/100;
    IF @m81val IS NOT NULL then 
     SET @m_logs=CONCAT('(Allowed * PCP_Services_Rate_Calc) - CLMH_Sequest_Amt'); SET @mRatePer = @m4val/100;
    end if;
   else
    SET @mRatePer = @m3val/100;
    IF @m81val IS NOT NULL THEN 
     SET @m_logs=CONCAT('(Allowed * FFS_Carveout_Rate_Calc) - CLMH_Sequest_Amt');
    else
     SET @m_logs=CONCAT('(Allowed * FFS_Carveout_Rate_Calc) - CLMH_Sequest_Amt, Copay and CoIns removed');
     SET mClmAllowAmt = mClmReimbAmt + mClmSeqAmt + mClmTccRedAmt;
    END IF;  
   end if; 

   SET @mClmAllowed = mClmAllowAmt*@mRatePer;
   SET @mForCMS_Amt = @mClmAllowed-mClmSeqAmt;

   IF UPPER(@m2val)='CAP' AND @m81val IS NOT NULL THEN
    SET @m_logs='CAP_Zero_Amount'; SET @mForCMS_Amt=0;
   END IF;
  ELSEIF @m1val='Preferred Provider' THEN 
   SET @m_logs = CONCAT('CLMH_TCC_RED_AMT * FFS_Carveout_Rate_Calc'); SET @mRatePer = @m3val / 100;
   SET @mClmAllowed = mClmAllowAmt*@mRatePer;
   SET @mForCMS_Amt = mClmTccRedAmt*@mRatePer;
  END IF;

  SET @mRosterVersion=@mRosterV2025n;
  if YEAR(qArg11)=2024 then SET @mRosterVersion=@mRosterV2024n; end if;
  if @m_logs='Provider_Rate_Missing' then
   SET @mtmp=(SELECT prov_npi_nr FROM mra6_dc_bene_m02 WHERE cc_version=@mRosterVersion and prov_npi_nr=@m5val limit 1);
   if @mtmp is null then set @m_logs='Provider_Roster_Missing'; END IF;
  END IF;

  SET @mDischargeDate=CONCAT(YEAR(qArg11),'-',MONTH(qArg11),'-01');
  SET @ptAlign2status=(SELECT ALIGN_STATUS_CODE FROM mra6_dc_bene_m01 WHERE cc_version=@mRosterVersion AND mm_curr_mbi_id=qArg01 AND mm_date=@mDischargeDate LIMIT 1);
  if UPPER(@ptAlign2status)='AL' then set @ptAlign2status=1; else set @ptAlign2status=0; end if;

  SET @mCpt_CODES= (SELECT GROUP_CONCAT(CLML_HCPC_CD) FROM mra_file_static.mra_clm1_claim_details WHERE claim_id=qArg00);

  INSERT ignore INTO mra_cr_m3_part_a SET map_data_status=0,map_process_status=0,pt_aligned2status=@ptAlign2status,m_ref_num=qArg00,mfile_name=qArg12,mfile_line_no=qArg13,CLMH_ADJSMT_TYPE_CD=qADJSMT_Type,CLMH_MBI=qArg01,CLMH_FROM_DT=qArg02,CLMH_PVDR_CCN=qArg03,CLMH_DCN=qArg05,BT_Amount=@mForCMS_Amt,CLMH_TCC_RED_AMT=mClmTccRedAmt,CLMH_REIMB_AMT=mClmReimbAmt,CLMH_BENE_PMT_COINSRNC_AMT=mClmCoInsAmt,CLMH_RCPNT_PMT_DDCTBL_PD_AMT=mClmDdcPayAmt,CLMH_SEQ_AMT=mClmSeqAmt,Provider_Class=@m1val,Capped_or_FFS=@m2val,FFS_Carveout_Rate_per=@m3val,PCP_Services_Rate_per=@m4val,Individual_NPI=@m5val,Base_Provider_TIN=@m6val,Organization_NPI=@m7val,CCN=@m8val,CLML_PCP_Service=@m81val,CLMH_Allowed=@mClmAllowed,mdd_8=@m_logs,CLM_CPT_CODES=@mCpt_CODES,CLM_ICT_CODES=qArg14,CLMH_BILL_FACILITY=qArg08,CLMH_BILL_CATEGORY=qArg09,CLMH_PVDR_NPI=qArg10,CLMH_THRU_DT=qArg11;

  update mra_file_static.mra_clm1_claims set map_data_status=1 where id=qArg00;
  INSERT INTO mra_00_tmp SET mdd_1="CR_IMP2_Part_A",mdd_2='LOOP',mdd_3=mi;

  SET mi=mi+1;  
 END IF;

END LOOP;
CLOSE mrw;

update mra_file_static.mra_clm1_claims set map_data_status=4 where CLMH_MEDICARE_PART !='HUBC' AND map_data_status=0;
INSERT INTO mra_01_tmp SET mdd_1="CR_IMP2_Part_A",mdd_2='END',mdd_3='-';

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP2_CR_M31_Part_B_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP2_CR_M31_Part_B_m3`()
BEGIN

DECLARE mi INT DEFAULT 0; DECLARE bmc INT DEFAULT 0;

DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(20);DECLARE qArg06 VARCHAR(200);DECLARE qArg07 INT;DECLARE qArg08 VARCHAR(20);DECLARE qArg09 VARCHAR(20);DECLARE qArg10 BIGINT;DECLARE mALOWD_AMT DECIMAL(15,2);DECLARE mCPD_AMT DECIMAL(15,2);DECLARE mCOINS_AMT DECIMAL(15,2);DECLARE mDDCT_AMT DECIMAL(15,2);DECLARE mMIPOS_AMT DECIMAL(15,2);DECLARE mMIPNG_AMT DECIMAL(15,2);DECLARE mSEQ_AMT DECIMAL(15,2);DECLARE mTCC_AMT DECIMAL(15,2);DECLARE qArg11 text;

DECLARE mrw CURSOR FOR SELECT t1.id,t1.CLMH_MBI,t1.CLMH_FROM_DT,t1.CLMH_DCN,t2.CLML_HCPC_CD,t1.file_date,t1.filename,t1.file_line_no,t1.CLMH_THRU_DT,t2.CLML_POS_CD,t2.id,t2.CLML_ALOWD_CHRG_AMT,t2.CLML_CVRD_PD_AMT,t2.CLML_BENE_PMT_COINSRNC_AMT,t2.CLML_RCPNT_PMT_DDCTBL_PD_AMT,t2.CLML_MIPS_POS_AMT,t2.CLML_MIPS_NEG_AMT,t2.CLML_SEQ_PMT_AMT,t2.CLML_TCC_RED_AMT,CONCAT(IF(t1.CLMH_DIAG_CODE_1 IS NULL OR t1.CLMH_DIAG_CODE_1='','-',t1.CLMH_DIAG_CODE_1),', ',IF(t1.CLMH_DIAG_CODE_2 IS NULL OR t1.CLMH_DIAG_CODE_2='','-',t1.CLMH_DIAG_CODE_2),', ',IF(t1.CLMH_DIAG_CODE_3 IS NULL OR t1.CLMH_DIAG_CODE_3='','-',t1.CLMH_DIAG_CODE_3),', ',IF(t1.CLMH_DIAG_CODE_4 IS NULL OR t1.CLMH_DIAG_CODE_4='','-',t1.CLMH_DIAG_CODE_4),', ',IF(t1.CLMH_DIAG_CODE_5 IS NULL OR t1.CLMH_DIAG_CODE_5='','-',t1.CLMH_DIAG_CODE_5),', ',IF(t1.CLMH_DIAG_CODE_6 IS NULL OR t1.CLMH_DIAG_CODE_6='','-',t1.CLMH_DIAG_CODE_6),', ',IF(t1.CLMH_DIAG_CODE_7 IS NULL OR t1.CLMH_DIAG_CODE_7='','-',t1.CLMH_DIAG_CODE_7),', ',IF(t1.CLMH_DIAG_CODE_8 IS NULL OR t1.CLMH_DIAG_CODE_8='','-',t1.CLMH_DIAG_CODE_8),', ',IF(t1.CLMH_DIAG_CODE_9 IS NULL OR t1.CLMH_DIAG_CODE_9='','-',t1.CLMH_DIAG_CODE_9),', ',IF(t1.CLMH_DIAG_CODE_10 IS NULL OR t1.CLMH_DIAG_CODE_10='','-',t1.CLMH_DIAG_CODE_10)) FROM mra_file_static.mra_clm1_claims AS t1 INNER JOIN mra_file_static.mra_clm1_claim_details AS t2 ON t2.claim_id=t1.id WHERE t1.CLMH_MEDICARE_PART ='HUBC' AND t1.CLMH_FROM_DT>='2024-01-01' AND map_data_status=0 AND map_process_status=1;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

INSERT INTO mra_01_tmp SET mdd_1="CR_IMP2_Part_B",mdd_2='START',mdd_3='-';

SET @mRosterV2024n=(SELECT MAX(cc_version) FROM dc_bene_alignment_rostr_m01 WHERE mm_year=2024);
SET @mRosterV2025n=(SELECT MAX(cc_version) FROM dc_bene_alignment_rostr_m01 WHERE mm_year=2025);

DROP TABLE IF EXISTS mra6_dc_bene_m01; DROP TABLE IF EXISTS mra6_dc_bene_m02;

CREATE TEMPORARY TABLE `mra6_dc_bene_m01`(
  `cc_version` INT,`prov_npi_nr` VARCHAR(20),mm_date DATE,`ALIGN_STATUS_CODE` VARCHAR(20), `mm_curr_mbi_id` VARCHAR(100),  
  KEY `mkey01` (`cc_version`),KEY `mkey02` (`prov_npi_nr`),KEY `mkey03` (`mm_curr_mbi_id`),KEY `mkey04` (`mm_date`)
) ENGINE=INNODB DEFAULT CHARSET=latin1;

INSERT INTO mra6_dc_bene_m01 (cc_version,mm_curr_mbi_id,prov_npi_nr,mm_date,ALIGN_STATUS_CODE)
SELECT cc_version,mm_curr_mbi_id,prov_npi_nr,mm_date,ALIGN_STATUS_CODE 
FROM dc_bene_alignment_rostr_m01 WHERE cc_version IN (@mRosterV2024n,@mRosterV2025n);

CREATE TEMPORARY TABLE `mra6_dc_bene_m02`(
  `cc_version` INT,`prov_npi_nr` VARCHAR(20),  
  KEY `mkey01` (`cc_version`),KEY `mkey02` (`prov_npi_nr`)
) ENGINE=INNODB DEFAULT CHARSET=latin1;

INSERT INTO mra6_dc_bene_m02 (cc_version,prov_npi_nr)
SELECT distinct cc_version,prov_npi_nr FROM dc_bene_alignment_rostr_m01 
WHERE cc_version IN (@mRosterV2024n,@mRosterV2025n);

SET @mFormulaType=0;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05,qArg06,qArg07,qArg08,qArg09,qArg10,mALOWD_AMT,mCPD_AMT,mCOINS_AMT,mDDCT_AMT,mMIPOS_AMT,mMIPNG_AMT,mSEQ_AMT,mTCC_AMT,qArg11;
 IF bmc = 0 THEN
 
  if qArg04 is null then set qArg04=''; end if;

  IF mALOWD_AMT IS NULL THEN SET mALOWD_AMT=0; END IF; IF mCPD_AMT IS NULL THEN SET mCPD_AMT=0; END IF;
  IF mCOINS_AMT IS NULL THEN SET mCOINS_AMT=0; END IF; IF mDDCT_AMT IS NULL THEN SET mDDCT_AMT=0; END IF;
  IF mMIPOS_AMT IS NULL THEN SET mMIPOS_AMT=0; END IF; IF mMIPNG_AMT IS NULL THEN SET mMIPNG_AMT=0; END IF;
  IF mSEQ_AMT IS NULL THEN SET mSEQ_AMT=0; END IF; IF mTCC_AMT IS NULL THEN SET mTCC_AMT=0; END IF;
  
  IF qArg05 >= '2025-02-07' THEN
   SET @mFormulaType=1; 
  ELSEIF qArg05 BETWEEN '2025-01-01' AND '2025-02-06' AND YEAR(qArg02)>=2025 THEN
   SET @mFormulaType=1;
  END IF;

  SET @mcVal= (SELECT CONCAT(CLML_RNDRG_PRVDR_TAX_NUM,'!@#',CLML_RNDRG_PRVDR_NPI_NUM) FROM mra_file_static.mra_clm1_claim_details WHERE claim_id=qArg00 LIMIT 1);
  SET @mPRVDR_TAXNUM = SUBSTRING_INDEX(@mcVal,'!@#',1); SET @mPRVDR_TAXNPI = SUBSTRING_INDEX(@mcVal,'!@#',-1);
    
  SET @ttmp= (SELECT nr FROM bt_static.mra_clmred_pcp_m1_cm WHERE Performance_Year = year(qArg05) and Individual_NPI=@mPRVDR_TAXNPI and Base_Provider_TIN=@mPRVDR_TAXNUM AND Provider_Class IS NOT NULL AND Provider_Class<>'' and qArg05 between Effective_Start_Date and Effective_End_Date ORDER BY cc_version,nr DESC LIMIT 1);
  if @ttmp is null then SET @ttmp= (SELECT nr FROM bt_static.mra_clmred_pcp_m1_cm WHERE Performance_Year = YEAR(qArg05) AND Individual_NPI=@mPRVDR_TAXNPI AND Base_Provider_TIN=@mPRVDR_TAXNUM AND Provider_Class IS NOT NULL AND Provider_Class<>'' ORDER BY cc_version,nr DESC LIMIT 1); end if;
  IF @ttmp IS NULL THEN SET @ttmp= (SELECT nr FROM bt_static.mra_clmred_pcp_m1_cm WHERE Performance_Year = YEAR(qArg05) AND Organization_NPI=@mPRVDR_TAXNPI AND Base_Provider_TIN=@mPRVDR_TAXNUM AND Provider_Class IS NOT NULL AND Provider_Class<>'' AND qArg05 BETWEEN Effective_Start_Date AND Effective_End_Date ORDER BY cc_version,nr DESC LIMIT 1); END IF;
  IF @ttmp IS NULL THEN SET @ttmp= (SELECT nr FROM bt_static.mra_clmred_pcp_m1_cm WHERE Performance_Year = YEAR(qArg05) AND Organization_NPI=@mPRVDR_TAXNPI AND Base_Provider_TIN=@mPRVDR_TAXNUM AND Provider_Class IS NOT NULL AND Provider_Class<>'' ORDER BY cc_version,nr DESC LIMIT 1); END IF;
  
  SET @mcVal = (SELECT CONCAT(IF(Provider_Class IS NULL,'',Provider_Class),'!@#',IF(Capped_or_FFS IS NULL,'',Capped_or_FFS),'!@#',IF(FFS_Carveout_Rate_per IS NULL,'',FFS_Carveout_Rate_per),'!@#',IF(PCP_Services_Rate_per IS NULL,'',PCP_Services_Rate_per),'!@#',IF(Individual_NPI IS NULL,'',Individual_NPI),'!@#',IF(Base_Provider_TIN IS NULL,'',Base_Provider_TIN),'!@#',IF(Organization_NPI IS NULL,'',Organization_NPI),'!@#',IF(CCN IS NULL,'',CCN),'!@#az') AS mcc FROM bt_static.mra_clmred_pcp_m1_cm WHERE nr=@ttmp);  
  
  SET @m1val = SUBSTRING_INDEX(@mcVal,'!@#',1);
  SET @ttmp= SUBSTRING_INDEX(@mcVal,'!@#',2); SET @m2val= SUBSTRING_INDEX(@ttmp,'!@#',-1);
  SET @ttmp= SUBSTRING_INDEX(@mcVal,'!@#',3); SET @m3val= SUBSTRING_INDEX(@ttmp,'!@#',-1);
  SET @ttmp= SUBSTRING_INDEX(@mcVal,'!@#',4); SET @m4val= SUBSTRING_INDEX(@ttmp,'!@#',-1);
  SET @ttmp= SUBSTRING_INDEX(@mcVal,'!@#',5); SET @m5val= SUBSTRING_INDEX(@ttmp,'!@#',-1);
  SET @ttmp= SUBSTRING_INDEX(@mcVal,'!@#',6); SET @m6val= SUBSTRING_INDEX(@ttmp,'!@#',-1);
  SET @ttmp= SUBSTRING_INDEX(@mcVal,'!@#',7); SET @m7val= SUBSTRING_INDEX(@ttmp,'!@#',-1);
  SET @ttmp= SUBSTRING_INDEX(@mcVal,'!@#',8); SET @m8val= SUBSTRING_INDEX(@ttmp,'!@#',-1);

  SET @m81val = (SELECT 1 FROM bt_static.mra_clmred_pcp_m2_cap_services WHERE qArg05 BETWEEN fl_startdate AND fl_enddate and qArg02 between py_startdate and py_enddate AND pcp_cap_service=qArg04 LIMIT 1);

  SET @m_logs='Provider_Rate_Missing'; SET @mForCMS_Amt=0; SET @mForCMS2Amt=0;
  IF @m1val='Participant Provider' AND UPPER(@m2val) IN ('CAP','FFS','BOTH') THEN
   IF UPPER(@m2val)='CAP' OR @mFormulaType=0 THEN
    SET @m_logs=CONCAT('(Allowed * FFS_Carveout_Rate) - CMS_Covered_Paid + MIPS_POS_AMT - MIPS_NEG_AMT - SEQ_PMT_AMT'); SET @mRatePer = @m3val/100;
    IF @m81val IS NOT NULL then 
     SET @m_logs=CONCAT('(Allowed * PCP_Services_Rate) - CMS_Covered_Paid + MIPS_POS_AMT - MIPS_NEG_AMT - SEQ_PMT_AMT'); SET @mRatePer = @m4val/100;
    end if;
   ELSE
    SET @mRatePer = @m3val/100;
    IF @m81val IS NOT NULL THEN 
     SET @m_logs=CONCAT('( Allowed * FFS_Carveout_Rate) - CMS_Covered_Paid + MIPS_POS_AMT - MIPS_NEG_AMT - SEQ_PMT_AMT - Patient_Coins - Patient_Deductible');
     SET @mForCMS2Amt= mCOINS_AMT + mDDCT_AMT;
    ELSE
     SET @m_logs=CONCAT('( Allowed * FFS_Carveout_Rate) - CMS_Covered_Paid + MIPS_POS_AMT - MIPS_NEG_AMT - SEQ_PMT_AMT');
    END IF;
   END IF; 

   SET @mForCMS_Amt = (mALOWD_AMT*@mRatePer) - mCPD_AMT + mMIPOS_AMT - mMIPNG_AMT - mSEQ_AMT - @mForCMS2Amt;
   IF UPPER(@m2val)='CAP' AND @m81val IS NOT NULL THEN
    SET @m_logs='CAP_Zero_Amount'; SET @mForCMS_Amt=0;
   END IF;
  ELSEIF @m1val='Preferred Provider' THEN 
   SET @m_logs = CONCAT('CLML_Allowed * CLML_FFS_Carveout_Rate_Calc - CLML_CMS_Covered_Paid - CLML_Patient_Coins - CLML_Patient_Deductible + CLML_MIPS_POS_AMT - CLML_MIPS_NEG_AMT - CLML_SEQ_PMT_AMT'); SET @mRatePer = @m3val / 100;
   SET @mForCMS_Amt = (mALOWD_AMT*@mRatePer) - mCPD_AMT - mCOINS_AMT - mDDCT_AMT + mMIPOS_AMT - mMIPNG_AMT - mSEQ_AMT;
  END IF;

  SET @mRosterVersion=@mRosterV2025n;
  if YEAR(qArg08)=2024 then SET @mRosterVersion=@mRosterV2024n; end if;
  IF @m_logs='Provider_Rate_Missing' THEN
   SET @mtmp=(SELECT prov_npi_nr FROM mra6_dc_bene_m02 WHERE cc_version=@mRosterVersion AND prov_npi_nr=@m5val LIMIT 1);
   IF @mtmp IS NULL THEN SET @m_logs='Provider_Roster_Missing'; END IF;
  END IF;
  
  SET @mDischargeDate=CONCAT(YEAR(qArg08),'-',MONTH(qArg08),'-01');
  SET @ptAlign2status=(SELECT ALIGN_STATUS_CODE FROM mra6_dc_bene_m01 WHERE cc_version=@mRosterVersion AND mm_curr_mbi_id=qArg01 AND mm_date=@mDischargeDate LIMIT 1);
  IF UPPER(@ptAlign2status)='AL' THEN SET @ptAlign2status=1; ELSE SET @ptAlign2status=0; END IF;
  
 INSERT ignore INTO mra_cr_m3_part_b SET map_data_status=0,pt_aligned2status=@ptAlign2status,m_ref_num=qArg10,mfile_name=qArg06,mfile_line_no=qArg07,CLMH_MBI=qArg01,CLMH_FROM_DT=qArg02,CLMH_DCN=qArg03,CLML_RNDRG_PRVDR_TAX_NUM=@mPRVDR_TAXNUM,CLML_RNDRG_PRVDR_NPI_NUM=@mPRVDR_TAXNPI,CLML_HCPC_CD=qArg04,Provider_Class=@m1val,Capped_or_FFS=@m2val,FFS_Carveout_Rate_per=@m3val,PCP_Services_Rate_per=@m4val,Individual_NPI=@m5val,Base_Provider_TIN=@m6val,Organization_NPI=@m7val,CLML_PCP_Service=@m81val,mdd_8=@m_logs,BT_Amount=@mForCMS_Amt,CLML_ALOWD_CHRG_AMT=mALOWD_AMT,CLML_CVRD_PD_AMT=mCPD_AMT,CLML_BENE_PMT_COINSRNC_AMT=mCOINS_AMT,CLML_RCPNT_PMT_DDCTBL_PD_AMT=mDDCT_AMT,CLML_MIPS_POS_AMT=mMIPOS_AMT,CLML_MIPS_NEG_AMT=mMIPNG_AMT,CLML_SEQ_PMT_AMT=mSEQ_AMT,CLML_TCC_RED_AMT=mTCC_AMT,CLM_ICT_CODES=qArg11,CLMH_THRU_DT=qArg08,CLML_POS_CD=qArg09;

  update mra_file_static.mra_clm1_claims set map_data_status=1 where id=qArg00;
  INSERT INTO mra_00_tmp SET mdd_1="CR_IMP2_Part_B",mdd_2='LOOP',mdd_3=mi;
  SET mi=mi+1;  
 END IF;
END LOOP;
CLOSE mrw;

update mra_file_static.mra_clm1_claims set map_data_status=4 where CLMH_MEDICARE_PART='HUBC' AND map_data_status=0;
INSERT INTO mra_01_tmp SET mdd_1="CR_IMP2_Part_B",mdd_2='END',mdd_3='-';

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP2_CR_M32_Roster_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP2_CR_M32_Roster_m3`()
BEGIN

 DECLARE mmi INT;

 SET mmi = 2024;
 LOOP_M01:  LOOP
  IF mmi >= 2026 THEN LEAVE LOOP_M01; END IF;
  SET @m1cv = (SELECT MAX(cc_version) FROM dc_bene_alignment_rostr_m01 WHERE mm_year=mmi LIMIT 1);
  
  INSERT INTO mra_01_tmp SET mdd_1='CR_IMP2_Part_A',mdd_2='MRA_ROSTER_z',mdd_3=mmi;
  UPDATE mra_cr_m3_part_a t1 INNER JOIN dc_bene_alignment_rostr_m01 t2 ON t1.CLMH_MBI=t2.mm_curr_mbi_id
 SET t1.market_id=t2.market_id, t1.dce_group_nr=t2.dce_group_nr, t1.prov_npi_nr=t2.prov_npi_nr,
 t1.dce_sub_group_nr=t2.dce_sub_group_nr, t1.market_names=t2.market_names, t1.dce_group_name=t2.dce_group_name,
 t1.dce_provider_name=t2.dce_provider_name, t1.dce_sub_group_name=t2.dce_sub_group_name
WHERE t2.cc_version=@m1cv AND t1.CLMH_MBI=t2.mm_curr_mbi_id;

  INSERT INTO mra_01_tmp SET mdd_1='CR_IMP2_Part_B',mdd_2='MRA_ROSTER_z',mdd_3=mmi;
  UPDATE mra_cr_m3_part_b t1 INNER JOIN dc_bene_alignment_rostr_m01 t2 ON t1.CLMH_MBI=t2.mm_curr_mbi_id
 SET t1.market_id=t2.market_id, t1.dce_group_nr=t2.dce_group_nr, t1.prov_npi_nr=t2.prov_npi_nr,
 t1.dce_sub_group_nr=t2.dce_sub_group_nr, t1.market_names=t2.market_names, t1.dce_group_name=t2.dce_group_name,
 t1.dce_provider_name=t2.dce_provider_name, t1.dce_sub_group_name=t2.dce_sub_group_name
WHERE t2.cc_version=@m1cv AND t1.CLMH_MBI=t2.mm_curr_mbi_id;

  SET mmi = mmi + 1; ITERATE LOOP_M01;
 END LOOP;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP2_CR_M35_PA_02_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP2_CR_M35_PA_02_m3`()
BEGIN

DECLARE vtmp VARCHAR(100); DECLARE v1Check TINYINT DEFAULT 0; DECLARE bmc INT DEFAULT 0; 
DECLARE mv_proc_type_nr SMALLINT DEFAULT 1; DECLARE mv_imp_job_nr INT DEFAULT 3000;
DECLARE m_hosp_nr BIGINT DEFAULT 0;

DECLARE vm_enc_nr BIGINT; DECLARE mv_bill_id BIGINT; DECLARE mMBI_IDNEW VARCHAR(100);
DECLARE qArg00 BIGINT;DECLARE qArg01 BIGINT;DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(100);DECLARE qArg06 VARCHAR(100);DECLARE qArg07 VARCHAR(100);DECLARE qArg08 VARCHAR(100);DECLARE qArg09 VARCHAR(100);DECLARE qArg10 VARCHAR(30);

DECLARE mrw CURSOR FOR SELECT nr,m_ref_num,CLMH_MBI,CLMH_FROM_DT,CLMH_PVDR_CCN,CLMH_DCN,CONCAT(SUBSTR(`CLMH_FROM_DT`,1,4),SUBSTR(`CLMH_FROM_DT`,6,2),SUBSTR(`CLMH_FROM_DT`,9,2)) AS encounter_date,CLMH_BILL_FACILITY,CLMH_BILL_CATEGORY,CLMH_PVDR_NPI,CLMH_THRU_DT FROM mra_cr_m3_part_a WHERE map_data_status=0 group by CLMH_MBI,CLMH_FROM_DT,CLMH_PVDR_CCN;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05,qArg06,qArg07,qArg08,qArg09,qArg10;
 IF bmc = 0 THEN

  SET mMBI_IDNEW=MRA_FN01_GetPatientIDLastCCLF(qArg02);
  set @mPOSz='';

 IF ((@mPOSz IS NULL OR @mPOSz='') AND qArg07='3' ) THEN
  SET @mPOSz='10';
 ELSEIF ((@mPOSz IS NULL OR @mPOSz='') AND qArg07='8' AND qArg08 IN ('1','2') ) THEN
  SET @mPOSz='50';
 ELSEIF ((@mPOSz IS NULL OR @mPOSz='') AND qArg07 IN ('1','4','5','6','9') AND qArg08 IN ('1','2','7') ) THEN
  SET @mPOSz='60';
 ELSEIF ((@mPOSz IS NULL OR @mPOSz='') AND qArg07 IN ('1','4','5','6','9') AND qArg08='3' ) THEN
  SET @mPOSz='40';
 ELSEIF ((@mPOSz IS NULL OR @mPOSz='') AND qArg07='2' AND qArg08='8' ) THEN
  SET @mPOSz='30';
 ELSEIF ((@mPOSz IS NULL OR @mPOSz='') AND qArg07='2' ) THEN
  SET @mPOSz='20'; 
 ELSEIF (@mPOSz IS NULL OR @mPOSz='') THEN
  SET @mPOSz='00';
 END IF;  

 SET vm_enc_nr = (SELECT encounter_nr FROM cclf_encounter WHERE origid IN (mMBI_IDNEW,qArg02) AND DATE_FORMAT(encounter_date,'%Y-%m-%d')=qArg03 AND CLM_BLG_PRVDR_OSCAR_NUM=qArg04 AND mra_proc_type_nr=mv_proc_type_nr LIMIT 1);
 IF vm_enc_nr IS NULL THEN
   SET vm_enc_nr = (SELECT encounter_nr FROM cclf_encounter WHERE origid IN (mMBI_IDNEW,qArg02) AND CLM_CNTL_NUM=qArg05 AND mra_proc_type_nr=mv_proc_type_nr LIMIT 1);
 END IF;

 IF vm_enc_nr IS NULL THEN  
  	UPDATE sequence_table_data SET sequence_id=sequence_id+1 WHERE sequence_name='encount_cr';
	SET vtmp = (SELECT sequence_id FROM sequence_table_data WHERE sequence_name='encount_cr'); 
	SET vm_enc_nr= CONCAT(qArg06,'61',vtmp);

	CALL MRA_IMP_FUNC_Hospital(qArg09);
	SET m_hosp_nr = (SELECT nr FROM adt_hosp_centers WHERE npi_id=qArg09 LIMIT 1);

	INSERT INTO cclf_encounter SET mra_clm_refer_num=qArg00,mra_clm_refer_m01='mm_claim_reduct',mra_cur_clm_uniq_id=0,create_id='mra_sch_import_claim',encounter_status='admitted',mra_proc_type_nr=mv_proc_type_nr,encounter_class_nr='9',is_discharged='0',report_status='1',mm_curr_mbi_id=qArg02,origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,mhos_cent_nr=m_hosp_nr,encounter_date=qArg03,discharge_date=qArg10,discharge_time="",encounter_type='',ATNDG_PRVDR_NPI_NUM='',CLM_BLG_PRVDR_OSCAR_NUM=qArg04,CUR_CLM_UNIQ_ID=0,CLM_EFCTV_DT='',CLM_CNTL_NUM=qArg05,CLM_ADJSMT_TYPE_CD=0,mm_imp_job_nr=mv_imp_job_nr,place_of_service=@mPOSz,pos=@mPOSz,CLM_BILL_FAC_TYPE_CD=qArg07,CLM_BILL_CLSFCTN_CD=qArg08,FAC_PRVDR_NPI_NUM=qArg09;
	INSERT INTO cclf_study_report_billing SET mra_clm_refer_num=qArg00,mra_clm_refer_m01='mm_claim_reduct',created_date=NOW(),created_by='mra_sch_import_claim',Patient_Id=mMBI_IDNEW,encounter_nr=vm_enc_nr,Procedure_Type='',CLM_ADJSMT_TYPE_CD=0,CLM_BILL_FAC_TYPE_CD=qArg07,CLM_TYPE_CD=0,CLM_OP_SRVC_TYPE_CD=0,CLM_ADMSN_TYPE_CD=0,CLM_ADMSN_SRC_CD=0,CLM_AMT_PD=0;
	SET mv_bill_id=LAST_INSERT_ID(); sET v1Check=1;
  ELSE
	UPDATE cclf_encounter SET mra_is_clf_redunct=1,map_data_status=0 WHERE encounter_nr=vm_enc_nr;
	CALL MRA_IMP3_M01ENC_99_01(vm_enc_nr);

	SET mv_bill_id = (SELECT Billing_ID FROM cclf_study_report_billing WHERE encounter_nr=vm_enc_nr LIMIT 1);
  END IF; 

  IF mv_bill_id != 0 THEN
	CALL MRA_IMP2_CR_M35_PA_31_m3(mv_bill_id,qArg02,qArg03,qArg04,vm_enc_nr);
  END IF;

  IF v1Check=1 THEN
   CALL MRA_IMP2_CR_M35_PA_32_m11(vm_enc_nr,qArg02,qArg03,mMBI_IDNEW,qArg01);
  END IF; 

  CALL MRA_01_Cal_EncHccScore_11(vm_enc_nr);
  INSERT INTO mra1_encounter_logs SET mcreate_id='system',map_data_src=5,encounter_nr=vm_enc_nr,patient_id=qArg02,proc_type_nr=mv_proc_type_nr,m_notes='',mSrcInserted_Type='mra_clm1_claims__a',mSrcInserted_ID=qArg00,mm_imp_job_nr=mv_imp_job_nr;

  UPDATE mra_cr_m3_part_a SET map_data_status=1 WHERE nr=qArg00;

