/* Procedure structure for procedure `MRA_IMP2_CR_M35_PA_31_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP2_CR_M35_PA_31_m3`(mpp1 BIGINT,mpp2 VARCHAR(50),mpp3 VARCHAR(50),mpp4 VARCHAR(50),mpp5 BIGINT)
BEGIN

 SET @qArg14 = (SELECT sum(if(CLMH_ADJSMT_TYPE_CD=1,-BT_Amount,BT_Amount)) FROM mra_cr_m3_part_a WHERE CLMH_MBI=mpp2 and CLMH_FROM_DT=mpp3 and CLMH_PVDR_CCN=mpp4);
 IF @qArg14 IS NULL then set @qArg14=0; END IF;

 SET @vtmp = (SELECT ID FROM cclf_study_report_billing_codes WHERE encounter_nr=mpp5 and Billing_Code='DRG01' LIMIT 1);
 iF @vtmp IS NOT NULL THEN
  UPDATE cclf_study_report_billing_codes SET mra_is2clf_redunct=1, cal2amount = @qArg14 WHERE ID=@vtmp LIMIT 1;
 ELSE 
  insert ignore into cclf_study_report_billing_codes SET encounter_nr=mpp5,Billing_ID=mpp1,mra_is2clf_redunct=1,cal2amount=@qArg14,Billing_Code='DRG01',CLM_LINE_PROD_REV_CTR_CD='',COUNT='1',`modifier`='',Billing_Type='P',cpt_code_order_num=1;
 END IF;

END */$$
DELIMITER ;

