DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP2_CR_M35_PA_32_m11`(mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp5 VARCHAR(100),mpp6 BIGINT)
BEGIN

DECLARE vtmp VARCHAR(100); DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 VARCHAR(100); DECLARE qArg01 VARCHAR(30);DECLARE qArg02 VARCHAR(30);DECLARE qArg03 VARCHAR(30);DECLARE qArg04 VARCHAR(30);DECLARE qArg05 VARCHAR(30); DECLARE qArg06 VARCHAR(30);DECLARE qArg07 VARCHAR(30);DECLARE qArg08 VARCHAR(30);DECLARE qArg09 VARCHAR(30);DECLARE qArg10 VARCHAR(30); DECLARE qArg11 VARCHAR(30);DECLARE qArg12 VARCHAR(30);DECLARE qArg13 VARCHAR(30);DECLARE qArg14 VARCHAR(30);DECLARE qArg15 VARCHAR(30); DECLARE qArg16 VARCHAR(90);DECLARE qArg17 VARCHAR(90);DECLARE qArg18 VARCHAR(90);DECLARE qArg19 VARCHAR(90);DECLARE qArg20 VARCHAR(90);

DECLARE mrw CURSOR FOR SELECT CLMH_DIAG_CODE_1,CLMH_DIAG_CODE_2,CLMH_DIAG_CODE_3,CLMH_DIAG_CODE_4,CLMH_DIAG_CODE_5,CLMH_DIAG_CODE_6,CLMH_DIAG_CODE_7,CLMH_DIAG_CODE_8,CLMH_DIAG_CODE_9,CLMH_DIAG_CODE_10,CLMH_DIAG_CODE_11,CLMH_DIAG_CODE_12,CLMH_DIAG_CODE_13 FROM mra_file_static.mra_clm1_claims WHERE id=mpp6;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01,qArg02,qArg03,qArg04,qArg05,qArg06,qArg07,qArg08,qArg09,qArg10,qArg11,qArg12,qArg13;
 IF bmc = 0 THEN 
  CALL MRA_IMP2_CR_M35_PA_32_m12(mpp1,mpp2,mpp3,qArg01,mpp5,mpp6); 
  CALL MRA_IMP2_CR_M35_PA_32_m12(mpp1,mpp2,mpp3,qArg02,mpp5,mpp6);
  CALL MRA_IMP2_CR_M35_PA_32_m12(mpp1,mpp2,mpp3,qArg03,mpp5,mpp6);
  CALL MRA_IMP2_CR_M35_PA_32_m12(mpp1,mpp2,mpp3,qArg04,mpp5,mpp6);
  CALL MRA_IMP2_CR_M35_PA_32_m12(mpp1,mpp2,mpp3,qArg05,mpp5,mpp6); 
  CALL MRA_IMP2_CR_M35_PA_32_m12(mpp1,mpp2,mpp3,qArg06,mpp5,mpp6); 
  CALL MRA_IMP2_CR_M35_PA_32_m12(mpp1,mpp2,mpp3,qArg07,mpp5,mpp6);
  CALL MRA_IMP2_CR_M35_PA_32_m12(mpp1,mpp2,mpp3,qArg08,mpp5,mpp6);   
  CALL MRA_IMP2_CR_M35_PA_32_m12(mpp1,mpp2,mpp3,qArg09,mpp5,mpp6);   
  CALL MRA_IMP2_CR_M35_PA_32_m12(mpp1,mpp2,mpp3,qArg10,mpp5,mpp6);
  CALL MRA_IMP2_CR_M35_PA_32_m12(mpp1,mpp2,mpp3,qArg11,mpp5,mpp6);  
  CALL MRA_IMP2_CR_M35_PA_32_m12(mpp1,mpp2,mpp3,qArg12,mpp5,mpp6);  
  CALL MRA_IMP2_CR_M35_PA_32_m12(mpp1,mpp2,mpp3,qArg13,mpp5,mpp6);
 END IF;
 END LOOP;
CLOSE mrw;

END */$$
