DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP2_CR_M35_PA_32_m12`(mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100),mpp6 BIGINT)
BEGIN
 DECLARE vm_probdesc VARCHAR(500); 
 IF mpp4 <> '' THEN
  if LENGTH(mpp4)>3 and mpp4 NOT LIKE '%.%' then
   SET mpp4=CONCAT(SUBSTR(mpp4,1,3),'.',SUBSTR(mpp4,4));
  end if;
  sET vm_probdesc = MRA_FN21_GetIcdDescription(mpp4);
  INSERT IGNORE INTO cclf_encounter_icd_codes SET mra_clm_refer_num=mpp6, mra_clm_refer_m01='CRM35_PA_32_m12', encounter_nr=mpp1, patient_id=mpp5,`onset_date`=mpp3, diagnosis_code=mpp4, `diagnosis_desc`=vm_probdesc, SNOMED_CID='',SNOMED_FSN='',`status`='Active',problem_type='Problems',diagnosis_type='Problems', `created_by`='mra_sch_import_claim',`created_date`=NOW();
 END IF;
END */$$
