DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100); DECLARE qArg05 VARCHAR(100);DECLARE qArg06 BIGINT;DECLARE qArg07 VARCHAR(30);DECLARE qArg08 VARCHAR(30);DECLARE qArg09 VARCHAR(30);

DECLARE mrw CURSOR FOR SELECT nr,CLMH_MBI,CLMH_FROM_DT,CLML_RNDRG_PRVDR_NPI_NUM,CLMH_DCN,CLMH_ADJSMT_TYPE_CD,m_ref_num,CONCAT(SUBSTR(`CLMH_FROM_DT`,1,4),SUBSTR(`CLMH_FROM_DT`,6,2),SUBSTR(`CLMH_FROM_DT`,9,2)) AS encounter_date,CLML_POS_CD,CLMH_THRU_DT FROM mra_cr_m3_part_b WHERE map_data_status=0 GROUP BY `CLMH_MBI`,CLMH_FROM_DT,CLMH_DCN;
