 IF bmc = 0 THEN

 SET mMBI_IDNEW=MRA_FN01_GetPatientIDLastCCLF(qArg01);

 SET vm_enc_nr = (SELECT encounter_nr FROM cclf_encounter WHERE origid IN (mMBI_IDNEW,qArg01) AND DATE_FORMAT(encounter_date,'%Y-%m-%d')=qArg02 AND CLM_CNTL_NUM=qArg04 AND mra_proc_type_nr=mv_proc_type_nr LIMIT 1);

 IF vm_enc_nr IS NULL THEN  
  UPDATE sequence_table_data SET sequence_id=sequence_id+1 WHERE sequence_name='encount_cr';
  SET vtmp = (SELECT sequence_id FROM sequence_table_data WHERE sequence_name='encount_cr'); 
  SET vm_enc_nr= CONCAT(qArg07,'62',vtmp);

  IF LENGTH(qArg03)>4 THEN CALL MRA_IMP_FUNC_Personell(qArg03); END IF;

  SET @mc_topersonellnr=0; SET @mc_topersonellname=qArg03;
  SET @mc_tmp = (SELECT nr FROM personell WHERE npr_id=qArg03 LIMIT 1);
  IF @mc_tmp IS NOT NULL THEN
   SET @mc_topersonellnr=@mc_tmp; SET @mc_topersonellname = (SELECT `name` FROM personell WHERE nr=@mc_tmp LIMIT 1);
  END IF;
  
  INSERT INTO cclf_encounter SET mra_clm_refer_num=qArg00,mra_clm_refer_m01='mm_claim_reduct',mra_cur_clm_uniq_id=0,create_id='mra_sch_import_claim',encounter_status='admitted',mra_proc_type_nr=mv_proc_type_nr,encounter_class_nr='10',is_discharged='0',report_status='1',mm_curr_mbi_id=qArg01,origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,mhos_cent_nr=0,encounter_date=qArg02,discharge_date=qArg09,discharge_time="",encounter_type='',ATNDG_PRVDR_NPI_NUM=qArg03,CLM_BLG_PRVDR_OSCAR_NUM='',CUR_CLM_UNIQ_ID=0,CLM_CNTL_NUM=qArg04,CLM_ADJSMT_TYPE_CD=qArg05,mm_imp_job_nr=mv_imp_job_nr,place_of_service=qArg08,pos=qArg08,CLM_PRVDR_SPCLTY_CD='88',CLM_BILL_FAC_TYPE_CD=0,CLM_BILL_CLSFCTN_CD=0,FAC_PRVDR_NPI_NUM='',CLM_EFCTV_DT='';
  INSERT INTO cclf_study_report_billing SET mra_clm_refer_num=qArg00,mra_clm_refer_m01='mm_claim_reduct',created_date=NOW(),created_by='mra_sch_import_claim',Patient_Id=mMBI_IDNEW,encounter_nr=vm_enc_nr,Procedure_Type='',CLM_ADJSMT_TYPE_CD=qArg05,CLM_BILL_FAC_TYPE_CD=0,CLM_TYPE_CD=0,CLM_OP_SRVC_TYPE_CD=0,CLM_ADMSN_TYPE_CD=qArg05,CLM_ADMSN_SRC_CD=qArg05,CLM_AMT_PD=0;

   SET mv_bill_id=LAST_INSERT_ID(); SET v1Check=1;
  ELSE
   UPDATE cclf_encounter SET mra_is_clf_redunct=1,map_data_status=0 WHERE encounter_nr=vm_enc_nr;
   CALL MRA_IMP3_M01ENC_99_01(vm_enc_nr);
   SET mv_bill_id = (SELECT Billing_ID FROM cclf_study_report_billing WHERE encounter_nr=vm_enc_nr LIMIT 1);
  END IF; 

  IF mv_bill_id != 0 THEN
   CALL MRA_IMP2_CR_M35_PB_31_m3(mv_bill_id,qArg01,qArg02,qArg04,vm_enc_nr);
  END IF;

  IF v1Check=1 THEN
   SET qArg06 = (SELECT claim_id FROM mra_file_static.mra_clm1_claim_details WHERE id=qArg06 LIMIT 1);
   CALL MRA_IMP2_CR_M35_PA_32_m11(vm_enc_nr,qArg01,qArg02,mMBI_IDNEW,qArg06);
  END IF; 

  CALL MRA_01_Cal_EncHccScore_11(vm_enc_nr);
  INSERT INTO mra1_encounter_logs SET mcreate_id='system',map_data_src=5,encounter_nr=vm_enc_nr,patient_id=qArg01,proc_type_nr=mv_proc_type_nr,m_notes='',mSrcInserted_Type='mra_clm1_claims__b',mSrcInserted_ID=qArg00,mm_imp_job_nr=mv_imp_job_nr;

  UPDATE mra_cr_m3_part_b SET map_data_status=1 WHERE nr=qArg00;

  INSERT INTO mra_00_tmp SET mdd_1='mraclm1_claims__b',mdd_2=qArg00,mdd_3=qArg01,mdd_4=vm_enc_nr;

 END IF;
END LOOP;

UPDATE mra_cr_m3_part_b SET map_data_status=4 WHERE map_data_status=0;
INSERT INTO mra_01_tmp SET mdd_1="mraclm1_claims__b",mdd_2='END',mdd_3='-';

CLOSE mrw;
END */$$
