/* Procedure structure for procedure `MRA_IMP2_CR_M35_PB_31_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP2_CR_M35_PB_31_m3`(mpp1 BIGINT,mpp2 VARCHAR(50),mpp3 VARCHAR(50),mpp4 VARCHAR(50),mpp5 BIGINT)
BEGIN

 DECLARE bmc INT DEFAULT 0; DECLARE qArg00 bigINT;
 DECLARE qArg01 DECIMAL(11,2); DECLARE qArg02 VARCHAR(50);
 DECLARE mrw CURSOR FOR SELECT t1.nr,sum(IF(t1.CLMH_ADJSMT_TYPE_CD=1,-t1.BT_Amount,t1.BT_Amount)),t1.CLML_HCPC_CD FROM mra_cr_m3_part_b AS t1 WHERE t1.CLMH_MBI=mpp2 and t1.CLMH_FROM_DT=mpp3 AND t1.CLMH_DCN=mpp4 group by t1.CLML_HCPC_CD;
 DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1; 
 
 OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02;
 IF bmc = 0 THEN

 IF qArg02 IS NULL OR qArg02='' THEN SET qArg02='DRG01'; END IF;
 SET @vtmp = (SELECT ID FROM cclf_study_report_billing_codes WHERE encounter_nr=mpp5 AND Billing_Code=qArg02 LIMIT 1);
 IF @vtmp IS NOT NULL THEN
  UPDATE cclf_study_report_billing_codes SET mra_is2clf_redunct=1, cal2amount = qArg01 WHERE ID=@vtmp LIMIT 1;
 ELSE 
  INSERT IGNORE INTO cclf_study_report_billing_codes SET encounter_nr=mpp5,Billing_ID=mpp1,mra_is2clf_redunct=1,cal2amount=qArg01,Billing_Code=qArg02,CLM_LINE_PROD_REV_CTR_CD='',COUNT='1',`modifier`='',Billing_Type='P',cpt_code_order_num=1,mra_clm_refer_m01='mm_claim_reduct',mra_clm_refer_num=qArg00;
 END IF;

 END IF;
END LOOP;
CLOSE mrw;
END */$$
