/* Procedure structure for procedure `MRA_IMP3_E11_isBCDA_RecMatch_11` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP3_E11_isBCDA_RecMatch_11`(mpp1 VARCHAR(10))
BEGIN

 DECLARE vtmp VARCHAR(1000); 

DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(10);DECLARE qArg06 VARCHAR(30);

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t1.patient_id,t1.enc_admit_date,t1.enc_disch_date,t1.enc_pos,t1.proc_type_nr,t1.m_provider_npi FROM mra1_encounter t1 WHERE t1.is_bcda_match IS NULL AND t1.enc_disch_date>=mpp1 ORDER BY t1.entry_nr;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05,qArg06;
 IF bmc = 0 THEN

  IF qArg05='1' THEN
   SET vtmp=(SELECT entry_nr FROM mra4_encounter WHERE proc_type_nr=1 AND patient_id=qArg01 AND enc_admit_date=qArg02 AND enc_disch_date=qArg03 AND enc_pos=qArg04 LIMIT 1);
   IF vtmp IS NOT NULL THEN 
    UPDATE mra1_encounter SET is_bcda_match=1 WHERE entry_nr=qArg00;
   END IF;
  ELSEIF qArg05='2' THEN 
   SET vtmp=(SELECT entry_nr FROM mra4_encounter WHERE proc_type_nr=2 AND patient_id=qArg01 AND enc_admit_date=qArg02 AND enc_disch_date=qArg03 AND m_provider_npi=qArg06 LIMIT 1);
   IF vtmp IS NOT NULL THEN 
    UPDATE mra1_encounter SET is_bcda_match=1 WHERE entry_nr=qArg00;
   END IF;
  END IF; 
 
  INSERT INTO mra_00_tmp SET mdd_1='MRAIMP3_E11_isBCDA_RecMatch_11',mdd_2=qArg00,mdd_3=qArg01;

 END IF;
END LOOP;
CLOSE mrw;


END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP3_E31_RosterMapping_11` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP3_E31_RosterMapping_11`(m1pp INT, m2pp INT)
BEGIN

DECLARE vtmp VARCHAR(900); 
DECLARE mi INT DEFAULT 0; DECLARE bmc INT DEFAULT 0;

DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(100);DECLARE qArg06 VARCHAR(100);DECLARE qArg07 VARCHAR(100);DECLARE qArg08 VARCHAR(100);DECLARE qArg09 VARCHAR(100);

DECLARE mrw CURSOR FOR SELECT mm_curr_mbi_id,market_id,market_names,dce_group_nr,dce_sub_group_nr,prov_npi_nr,dce_group_name,dce_sub_group_name,dce_provider_name FROM mradb_prod.dc_bene_alignment_roster t1 WHERE t1.cc_version=m2pp;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01,qArg02,qArg03,qArg04,qArg05,qArg06,qArg07,qArg08,qArg09;
 IF bmc = 0 THEN

  UPDATE mra1_encounter SET market_nr=qArg02,market_name=qArg03,pt_facility_nr=qArg04, pt_facility_sub_nr=qArg05, pt_provider_num=qArg06, pt_facility_name=qArg07, pt_facility_sub_name=qArg08, pt_sp_dr_1=qArg09 WHERE patient_id=qArg01 AND YEAR(enc_admit_date)=m1pp;
  INSERT INTO mra_00_tmp SET mdd_1="MA_E31_Roster",mdd_2=CONCAT(m2pp,'-',mi),mdd_3=qArg01;
  SET mi=mi+1;

 END IF;
END LOOP;
CLOSE mrw;
END */$$
