/* Procedure structure for procedure `MRA_IMP3_E31_Roster_02_Mapping_11` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP3_E31_Roster_02_Mapping_11`(mpp1 INT)
BEGIN

DECLARE vtmp VARCHAR(1000); DECLARE m_year INT; DECLARE m_month INT; DECLARE m2year INT;
DECLARE ptFacilityNr VARCHAR(100); DECLARE ptFacilitySubNr VARCHAR(100); DECLARE ptProviderNum VARCHAR(100); DECLARE ptProviderName VARCHAR(100); DECLARE m1MarketNr INT;
DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg1 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);
DECLARE mrw CURSOR FOR SELECT entry_nr,patient_id,enc_admit_date,enc_disch_date FROM mra1_encounter WHERE year(enc_disch_date)>=mpp1;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg1,qArg2,qArg3;
 IF bmc = 0 THEN
  
  SET ptFacilityNr='0';SET ptFacilitySubNr='0';SET ptProviderNum='';SET ptProviderName='';
  set m_year=YEAR(qArg2); SET m_month=month(qArg2); SET m2year=YEAR(qArg3);

  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_bene_alignment_rostr_m01 WHERE mm_curr_mbi_id=qArg1 AND mm_year=m_year ORDER BY cc_version DESC LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET ptFacilitySubNr=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(ptFacilitySubNr,'!@#',-1);
  END IF;  
 
IF ptFacilityNr='' OR ptFacilityNr='0' THEN 
  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_bene_alignment_rostr_m01 WHERE mm_curr_mbi_id=qArg1 AND mm_year<=m2year order by cc_version desc LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET ptFacilitySubNr=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(ptFacilitySubNr,'!@#',-1);
  END IF;
END IF;
IF ptFacilityNr='' OR ptFacilityNr='0' THEN 
  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_bene_alignment_rostr_m01 WHERE mm_curr_mbi_id=qArg1 ORDER BY cc_version DESC LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET ptFacilitySubNr=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(ptFacilitySubNr,'!@#',-1);
  END IF;
END IF;
IF ptFacilityNr='' OR ptFacilityNr='0' THEN 
 SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_quater_alignment WHERE mm_curr_mbi_id=qArg1 AND qArg2 BETWEEN m_start_date AND m_end_date LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET ptFacilitySubNr=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(ptFacilitySubNr,'!@#',-1);
 END IF;
END IF;
IF ptFacilityNr='' OR ptFacilityNr='0' THEN 
  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_quater_alignment WHERE mm_curr_mbi_id=qArg1 ORDER BY cc_version DESC LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET ptFacilitySubNr=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(ptFacilitySubNr,'!@#',-1);
  END IF;
END IF;

 SET vtmp=(SELECT `name` FROM personell WHERE is_dce=1 and npr_id=ptProviderNum LIMIT 1);
 IF vtmp IS NOT NULL THEN SET ptProviderName=vtmp; END IF;	
 SET m1MarketNr = (SELECT market_id FROM hospital_market_assocs WHERE hosp_id=ptFacilityNr LIMIT 1);

 update mra1_encounter SET market_nr=m1MarketNr,pt_facility_nr=ptFacilityNr,pt_facility_sub_nr=ptFacilitySubNr,pt_provider_num=ptProviderNum,pt_sp_dr_1=ptProviderName where entry_nr=qArg00;

 INSERT INTO mra_00_tmp SET mdd_1='M01ENC_03_R01',mdd_2=mpp1,mdd_3=concat(qArg00,'-',qArg1);

 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP3_M01ENC_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP3_M01ENC_01`()
BEGIN

DECLARE mmi INT; DECLARE m2mi INT;
SET mmi = 1;

INSERT INTO mra_01_tmp SET mdd_1='mra_01_tmp',mdd_2='imp_mra1_encounter',mdd_3='START';

SET m2mi = (SELECT COUNT(t1.entry_nr) FROM encounter t1 INNER JOIN appointment t2 ON t2.encounter_nr=t1.encounter_nr WHERE t1.map_data_status=0 AND t1.mra_proc_type_nr IN (1,2,3,4)); SET m2mi = CEIL(m2mi/10000);

LOOP_M01:  LOOP
 CALL MRA_IMP3_M01ENC_03(mmi);
 IF  mmi >= m2mi THEN LEAVE  LOOP_M01;  END  IF;
 SET  mmi = mmi + 1;
 ITERATE  LOOP_M01;
END LOOP;

CALL MRA_IMP3_M03ENC_CleanDup_m1(1);
	
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP3_M01ENC_03` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP3_M01ENC_03`(mpp1 INT)
BEGIN

DECLARE vtmp VARCHAR(1000); DECLARE mra_enc_nr BIGINT; DECLARE m_year INT; DECLARE m_month INT;
DECLARE ptFacilityNr VARCHAR(100); DECLARE ptFacilitySubNr VARCHAR(100); DECLARE ptProviderNum VARCHAR(100); 
DECLARE m1MarketNr INT;
DECLARE mc1data VARCHAR(30); DECLARE mc2data VARCHAR(30); DECLARE mc3data VARCHAR(30);

DECLARE bmc INT DEFAULT 0;
DECLARE qArg0 BIGINT;DECLARE qArg1 BIGINT;DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);DECLARE qArg7 VARCHAR(100);DECLARE qArg8 VARCHAR(100);DECLARE qArg9 VARCHAR(100);DECLARE qArg10 VARCHAR(100);DECLARE qArg11 VARCHAR(100);DECLARE qArg12 VARCHAR(100);DECLARE qArg13 VARCHAR(100);DECLARE qArg14 VARCHAR(100);DECLARE qArg15 VARCHAR(100);DECLARE qArg16 smallint;DECLARE qArg17 VARCHAR(2);DECLARE qArg18 VARCHAR(100);DECLARE qArg19 VARCHAR(50);DECLARE qArg20 VARCHAR(10);DECLARE qHccScore DOUBLE(20,4);DECLARE qArg22 VARCHAR(10);DECLARE qArg23 VARCHAR(10);DECLARE qArg24 VARCHAR(30);DECLARE qArg25 VARCHAR(50);DECLARE qArg26 VARCHAR(30);DECLARE qArg27 VARCHAR(100);DECLARE qArg28 VARCHAR(100);DECLARE qArg29 VARCHAR(100);DECLARE qClmBLG_PRVDR_NPI_NUM VARCHAR(100);DECLARE qArg31 VARCHAR(100);DECLARE qArg32 VARCHAR(100);DECLARE qArg33 VARCHAR(100);DECLARE qArg34 VARCHAR(200);DECLARE m_CLM_ADMSN_SRC_CD VARCHAR(50);DECLARE mClmAmtPD double(20,4);

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t1.encounter_nr,t1.origid,t1.encounter_class_nr,t1.encounter_status,t1.discharge_date,t1.discharge_time,t1.create_id,t1.place_of_service,t1.encounter_type,t2.`date`,t2.`time`,t1.hospital_nr, t2.to_dept_nr, t2.to_personell_nr,t1.CLM_PRVDR_SPCLTY_CD,t1.mra_proc_type_nr,t1.mra_is_clf_redunct,t1.mm_curr_mbi_id,t1.mra_clm_refer_num,t1.mm_imp_job_nr,t1.hcc_score,t2.CLM_ADMSN_TYPE_CD,t3.discharge_type,t4.npr_id,t5.taxonomy_1,t5.nrp_id,t1.CLM_BILL_FAC_TYPE_CD,t1.CLM_BILL_CLSFCTN_CD,t1.CLM_BLG_PRVDR_OSCAR_NUM,t1.CLM_BLG_PRVDR_NPI_NUM,t1.RNDRG_PRVDR_TYPE_CD,t1.CLM_RNDRG_PRVDR_TAX_NUM,t1.CLM_RNDRG_PRVDR_NPI_NUM,t5.name,t2.CLM_ADMSN_SRC_CD,t1.CLM_AMT_PD FROM encounter t1 INNER JOIN appointment t2 ON t2.encounter_nr=t1.encounter_nr LEFT JOIN procedure_discharge t3 ON t3.encounter_nr=t1.encounter_nr LEFT JOIN personell t4 ON t4.nr=t2.to_personell_nr LEFT JOIN hospital_centers t5 ON t5.nr=t1.hospital_nr WHERE t1.map_data_status=0 AND t1.mra_proc_type_nr IN (1,2,3,4) LIMIT 10000;
 
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg0,qArg1,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8,qArg9,qArg10,qArg11,qArg12,qArg13,qArg14,qArg15,qArg16,qArg17,qArg18,qArg19,qArg20,qHccScore,qArg22,qArg23,qArg24,qArg25,qArg26,qArg27,qArg28,qArg29,qClmBLG_PRVDR_NPI_NUM,qArg31,qArg32,qArg33,qArg34,m_CLM_ADMSN_SRC_CD,mClmAmtPD;
 IF bmc = 0 THEN

  #call `MRA_IMP3_M01ENC_99_01`(qArg1);

  SET ptFacilityNr='0';SET ptFacilitySubNr='0';SET ptProviderNum='';

  SET m_year=YEAR(qArg5); SET m_month=MONTH(qArg5);
  set @mDischargeDate=concat(m_year,'-',m_month,'-01');

  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_bene_alignment_rostr_m01 WHERE mm_curr_mbi_id=qArg2 AND mm_date=@mDischargeDate ORDER BY cc_version DESC LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET ptFacilitySubNr=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(ptFacilitySubNr,'!@#',-1);
  END IF;  
 
IF ptFacilityNr='' OR ptFacilityNr='0' THEN 
  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_bene_alignment_rostr_m01 WHERE mm_curr_mbi_id=qArg2 ORDER BY cc_version DESC LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET ptFacilitySubNr=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(ptFacilitySubNr,'!@#',-1);
  END IF;
END IF;

IF ptFacilityNr='' OR ptFacilityNr='0' THEN 
  SET vtmp=(SELECT CONCAT(dce_group_nr,'!@#',dce_sub_group_nr,'!@#',prov_npi_nr) FROM dc_quater_alignment WHERE mm_curr_mbi_id=qArg2 ORDER BY cc_version DESC LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   SET ptFacilityNr=SUBSTRING_INDEX(vtmp,'!@#',1); SET ptProviderNum=SUBSTRING_INDEX(vtmp,'!@#',-1);
   SET ptFacilitySubNr=SUBSTRING_INDEX(vtmp,'!@#',2); SET ptFacilitySubNr=SUBSTRING_INDEX(ptFacilitySubNr,'!@#',-1);
  END IF;
END IF;

 SET mc1data=qArg8; SET mc2data=qArg10; SET mc3data=qArg11;
 IF qArg3="10" THEN SET mc1data=qArg15; END IF;
 IF qArg3="9" THEN SET mc2data=qArg5; SET mc3data=qArg6; END IF;

 set @mEncChk1Pos=qArg8; if qArg16=2 then SET @mEncChk1Pos=qArg15; end if;

 SET m1MarketNr = (SELECT market_id FROM hospital_market_assocs WHERE hosp_id=ptFacilityNr LIMIT 1);

 # SET mra_enc_nr = (SELECT entry_nr FROM mra1_encounter WHERE encounter_nr=qArg1 LIMIT 1);
 INSERT INTO mra1_encounter SET m1_map_status=5,market_nr=m1MarketNr,mra_score_val=0,mmodify_datetime=NOW(),mh1_cal_amount=mClmAmtPD,patient_id=qArg2,enc_class_nr=qArg3,enc_status=qArg4,enc_disch_date=qArg5,enc_disch_time=qArg6,mcreate_id=qArg7,enc_pos=qArg8,proc_type_nr=qArg16,enc_admit_date=qArg10,enc_admit_time=qArg11,hospital_nr=qArg12,dept_nr=qArg13,m_provider_nr=qArg14,CLM_PRVDR_SPCLTY_CD=qArg15,pt_facility_nr=ptFacilityNr,pt_facility_sub_nr=ptFacilitySubNr,pt_provider_num=ptProviderNum,enc_chk1_pos=@mEncChk1Pos,enc_chk1_date=mc2data,enc_chk1_time=mc3data,pt_sp_dr_1='',mra_is_clf_redunct=qArg17,mm_curr_mbi_id=qArg18,mra_clm_refer_num=qArg19,mm_imp_job_nr=qArg20,hcc_score=qHccScore,CLM_ADMSN_TYPE_CD=qArg22,e_discharge_type=qArg23,m_provider_npi=qArg24,hospital_name=qArg34,hos_taxonomy01=qArg25,hc_npi_nr=qArg26,CLM_BILL_FAC_TYPE_CD=qArg27,CLM_BILL_CLSFCTN_CD=qArg28,CLM_BLG_PRVDR_OSCAR_NUM=qArg29,CLM_BLG_PRVDR_NPI_NUM=qClmBLG_PRVDR_NPI_NUM,RNDRG_PRVDR_TYPE_CD=qArg31,CLM_RNDRG_PRVDR_TAX_NUM=qArg32,CLM_RNDRG_PRVDR_NPI_NUM=qArg33,CLM_ADMSN_SRC_CD=m_CLM_ADMSN_SRC_CD,mcreate_datetime=NOW(),encounter_nr=qArg1;
 SET mra_enc_nr=LAST_INSERT_ID();

 CALL MRA_IMP3_M01ENC_30_01(mra_enc_nr,qArg1,qArg2);
 CALL MRA_IMP3_M01ENC_30_02(mra_enc_nr,qArg1,qArg2);
 
 UPDATE encounter SET map_data_status=1 WHERE map_data_status=0 AND entry_nr=qArg0;
 INSERT INTO mra_00_tmp SET mdd_1=mpp1,mdd_2=qArg0,mdd_3=qArg1;

 END IF;
END LOOP;
CLOSE mrw;


END */$$
