/* Procedure structure for procedure `MRA_IMP3_M01ENC_30_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP3_M01ENC_30_01`(mpp1 BIGINT, mpp2 BIGINT, mpp3 VARCHAR(100))
BEGIN

DECLARE vtmp VARCHAR(100);
DECLARE bmc INT DEFAULT 0;
DECLARE qArg0 BIGINT;DECLARE qArg1 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);DECLARE qArg7 VARCHAR(100);DECLARE qArg8 VARCHAR(100);DECLARE qArg9 VARCHAR(100);
DECLARE mrw CURSOR FOR SELECT t1.ID,t1.Billing_Code,t1.Billing_Type,t1.modifier,t1.count,t1.cpt_code_order_num,t1.cal_amount,t1.CLM_LINE_PROD_REV_CTR_CD,t1.cal2amount,t1.cal3amount FROM study_report_billing_codes t1 INNER JOIN study_report_billing t2 ON t2.Billing_ID=t1.Billing_ID WHERE t2.encounter_nr=mpp2;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg0,qArg1,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8,qArg9;
 IF bmc = 0 THEN
  INSERT IGNORE INTO mra1_encounter_bill_cpts SET mm_imp_ref_num=qArg0,mcreate_datetime=NOW(),mra_enc_nr=mpp1,encounter_nr=mpp2,patient_id=mpp3,bb_Code=qArg1,bb_Type=qArg2,bb_modifier=qArg3,bb_count=qArg4,bb_order_num=qArg5,CLM_LINE_PROD_REV_CTR_CD=qArg7,cal_amount=qArg6,cal2amount=qArg8,cal3amount=qArg9;
 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

