/* Procedure structure for procedure `MRA_IMP3_M03ENC_CleanDupEnc_m1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP3_M03ENC_CleanDupEnc_m1`()
BEGIN

DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(100);DECLARE qArg06 VARCHAR(100);DECLARE qArg07 VARCHAR(100);

DECLARE mrw CURSOR FOR 
SELECT encounter_nr, COUNT(*) AS mcnt  FROM mra1_encounter  WHERE 1=1 GROUP BY encounter_nr HAVING mcnt>1;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;

OPEN mrw;
read_loop: LOOP
IF bmc = 1 THEN LEAVE read_loop; END IF;
FETCH mrw INTO qArg00,qArg01;
IF bmc = 0 THEN

 INSERT INTO mra_00_tmp SET mdd_1="MRAA03_32ReAdmit_Flag_z",mdd_2=qArg00,mdd_3=qArg01;
 DELETE FROM mra1_encounter WHERE encounter_nr=qArg00 LIMIT 1;

END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP3_M03ENC_CleanDup_m1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP3_M03ENC_CleanDup_m1`(mpp1 INT)
BEGIN

DECLARE vtmp VARCHAR(100); DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT; DECLARE qArg01 VARCHAR(100); DECLARE qArg02 VARCHAR(20); DECLARE qArg03 VARCHAR(100); DECLARE qArg04 VARCHAR(20);

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t2.encounter_nr,t2.bb_Code,t2.mm_imp_ref_num, COUNT(*) AS mcnt FROM mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr WHERE t1.enc_disch_date>='2023-01-01' GROUP BY t2.encounter_nr,t2.bb_Code,t2.mm_imp_ref_num HAVING mcnt>1 order by t1.proc_type_nr;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;
INSERT INTO mra_00_tmp SET mdd_1="MRA_IMP3_M03ENC_CleanDup_m1",mdd_2='##START##',mdd_3=1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04;
 IF bmc = 0 THEN

  delete from mra1_encounter_bill_cpts where encounter_nr=qArg01 and bb_Code='-9999';
  DELETE FROM mra1_encounter_bill_cpts WHERE encounter_nr=qArg01 AND bb_Code=qArg02 AND mm_imp_ref_num=qArg03 limit 1;
  UPDATE mra1_encounter SET mc1_cal_amount = -123, m1_map_status=5 WHERE entry_nr=qArg00;
  INSERT INTO mra_00_tmp SET mdd_1="MRA_IMP3_M03ENC_CleanDup_m1",mdd_2=qArg00,mdd_3=mpp1;

 END IF;
END LOOP;
CLOSE mrw;


END */$$
DELIMITER ;

