 INSERT INTO mra_00_tmp SET mdd_1='mra_tmp',mdd_2='mra1_enc_tmp',mdd_3='START';
 DROP TABLE IF EXISTS mra1_encounter_tmp; CREATE TABLE mra1_encounter_tmp LIKE mra1_encounter;
 INSERT INTO mra1_encounter_tmp SELECT * FROM mra1_encounter WHERE enc_disch_date>='2023-01-01';

 INSERT INTO mra_01_tmp SET mdd_1='mra_tmp',mdd_2='EXTRA_SCRPT',mdd_3='START';
 INSERT INTO mra_00_tmp SET mdd_1='mra_tmp',mdd_2='EXTRA_SCRPT',mdd_3='START';
 UPDATE `alert_draft_queue` t1 INNER JOIN `mra1_encounter_icd_codes` t2 ON t1.encounter_nr=t2.encounter_nr SET t1.code_nr=t2.`entry_nr` WHERE t1.code=t2.diagnosis_code AND t1.type='icd' AND t1.code_nr!=t2.`entry_nr`;

END */$$
