/* Procedure structure for procedure `MRA_IMP3_M11CalEncounterHeader` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP3_M11CalEncounterHeader`()
BEGIN

DECLARE vtmp VARCHAR(100); 

DECLARE bmc INT DEFAULT 0; DECLARE qArg01 INT;
DECLARE mrw CURSOR FOR SELECT DISTINCT t1.pt_facility_nr FROM mra1_encounter t1 WHERE t1.enc_disch_date>='2023-01-01' AND (t1.mc1_cal_amount IS NULL OR t1.mc1_cal_amount= -123);

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01;
 IF bmc = 0 THEN

  mBLOCK_01: BEGIN
DECLARE b21mc INT DEFAULT 0;
DECLARE vtmp VARCHAR(999);  DECLARE mc1tmp VARCHAR(999); DECLARE mc2tmp VARCHAR(999); 
DECLARE q2Arg00 BIGINT;DECLARE q2Arg01 BIGINT;DECLARE q2Arg02 VARCHAR(100);DECLARE q2Arg03 VARCHAR(100);DECLARE q2Arg04 VARCHAR(100);
DECLARE m21rw CURSOR FOR SELECT t1.entry_nr,t1.encounter_nr,t2.lastname,t2.firstname,t2.birthdate FROM mra1_encounter t1 left JOIN patient t2 ON t2.origid=t1.patient_id WHERE t1.enc_disch_date>='2023-01-01' AND t1.pt_facility_nr=qArg01 AND (t1.mc1_cal_amount IS NULL OR t1.mc1_cal_amount= -123);
DECLARE CONTINUE HANDLER FOR NOT FOUND SET b21mc = 1;
OPEN m21rw; 
read21loop: LOOP
IF b21mc = 1 THEN LEAVE read21loop; END IF;
FETCH FROM m21rw INTO q2Arg00,q2Arg01,q2Arg02,q2Arg03,q2Arg04;
IF b21mc = 0 THEN
 
 SET mc1tmp='';SET mc2tmp='';
 SET vtmp = (SELECT CONCAT(SUM(cal_amount),'##',SUM(cal2amount)) FROM mra1_encounter_bill_cpts WHERE encounter_nr=q2Arg01);
 IF vtmp IS NOT NULL THEN
  SET mc1tmp=SUBSTRING_INDEX(vtmp,'##',1); SET mc2tmp=SUBSTRING_INDEX(vtmp,'##',-1);
 END IF;

 UPDATE mra1_encounter SET pt_lastname=q2Arg02, pt_firstname=q2Arg03, pt_birthdate=q2Arg04,
mc1_bb_Code='-123', mc1_diagnosis_code='-123', mc1_CLM_LINE_PROD_REV_CTR_CD='-123',mc1_cal_amount=mc1tmp, mc1_cal2amount=mc2tmp WHERE pt_facility_nr=qArg01 AND entry_nr=q2Arg00;

 INSERT INTO mra_00_tmp SET mdd_1='cal02_mm_encounter',mdd_2=q2Arg00,mdd_3=qArg01,mdd_4=vtmp;
 
END IF;
END LOOP read21loop;
END mBLOCK_01;

 END IF;
END LOOP;
CLOSE mrw;

  
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP3_M12CalEncounterHeader` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP3_M12CalEncounterHeader`()
BEGIN

DECLARE vtmp VARCHAR(100); 

DECLARE bmc INT DEFAULT 0; DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);

DECLARE mrw CURSOR FOR SELECT entry_nr,encounter_nr,patient_id,(mh1_cal_amount-mc1_cal_amount) AS mdiff FROM mra1_encounter t1 WHERE proc_type_nr=1 AND enc_disch_date>='2022-01-01' AND (mc1_cal_amount IS NOT NULL AND mc1_cal_amount <> -123) AND mh1_cal_amount IS NOT NULL HAVING mdiff>0.01 OR mdiff < -0.01;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03;
 IF bmc = 0 THEN

  INSERT IGNORE INTO mra1_encounter_bill_cpts SET mm_imp_ref_num= -1000,mcreate_datetime=NOW(),mra_enc_nr=qArg00,encounter_nr=qArg01,patient_id=qArg02,bb_Code='-9999',bb_Type='',bb_modifier='',bb_count=1,bb_order_num=0,CLM_LINE_PROD_REV_CTR_CD='XXXX',cal_amount=qArg03,cal2amount=0,cal3amount=0;

  UPDATE mra1_encounter SET mc1_cal_amount = -123, m1_map_status=5 WHERE entry_nr=qArg00;

  INSERT INTO mra_00_tmp SET mdd_1='cal02_m12_encounter',mdd_2=qArg00,mdd_3=qArg01;

 END IF;
END LOOP;
CLOSE mrw;

  
END */$$
DELIMITER ;

