   UPDATE mra1_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-09-01') AND CONCAT(qArg02,'-09-30') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Sep IN ('AL','D1Y'));
   
