   UPDATE mra1_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-11-01') AND CONCAT(qArg02,'-11-30') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Nov IN ('AL','D1Y'));
   UPDATE mra1_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-12-01') AND CONCAT(qArg02,'-12-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND `Dec` IN ('AL','D1Y'));

 END IF;
