/* Procedure structure for procedure `MRA_IMP3_S20_EncProcType_m1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP3_S20_EncProcType_m1`(m1pp INT)
BEGIN

INSERT INTO mra_01_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='SET_NULL';
INSERT INTO mra_00_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='SET_NULL';
UPDATE mra1_encounter SET enc_proc_type='',is_er_readmit=0,is_c2_readmit=0,pre_hospital_nr=0,pre_discharge_date=NULL,is_enc_transfer=1,is_enc_ref_admitdate=enc_admit_date,is_snf_rec=0,is_snf_admitdate_ref=NULL,pre_emr_hospital_name=NULL,pre_emr_discharge_date=NULL WHERE YEAR(enc_disch_date)>=m1pp;

INSERT INTO mra_00_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='Observation';
UPDATE mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr SET t1.enc_proc_type='Observation' WHERE YEAR(t1.enc_disch_date)>=m1pp AND t1.proc_type_nr=1 AND t1.enc_pos IN (60,61) AND (t2.CLM_LINE_PROD_REV_CTR_CD IN ('0760','0762') OR t2.bb_Code IN ('99217','99218','99219','99220','99221','99222','99223','99224','99225','99226','99231','99232','99233','99234','99235','99236','99252','99253','99254'));

INSERT INTO mra_00_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='Acute Hospital';
UPDATE mra1_encounter SET enc_proc_type='Acute Hospital' WHERE YEAR(enc_disch_date)>=m1pp AND proc_type_nr=1 AND enc_pos IN (60,61) AND hos_taxonomy01 IN ('282N00000X','282NC0060X','282NR1301X','282NC2000X','284300000X');
INSERT INTO mra_00_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='Hospice';
UPDATE mra1_encounter SET enc_proc_type='Hospice' WHERE YEAR(enc_disch_date)>=m1pp AND proc_type_nr=1 AND enc_pos IN (50);

INSERT INTO mra_01_tmp SET mdd_1="MRAA03_31Transfer_Flag_Marked_z",mdd_2='## Observation ##';
CALL mradb_prod.MRA_IMP_A03_31Transfer_Flag_z(m1pp,'Observation');
INSERT INTO mra_01_tmp SET mdd_1="MRAA03_31Transfer_Flag_Marked_z",mdd_2='## Acute Hospital ##';
CALL mradb_prod.MRA_IMP_A03_31Transfer_Flag_z(m1pp,'Acute Hospital');
INSERT INTO mra_01_tmp SET mdd_1="MRAA03_31Transfer_Flag_Marked_z",mdd_2='## Hospice ##';
CALL mradb_prod.MRA_IMP_A03_31Transfer_Flag_z(m1pp,'Hospice');

INSERT INTO mra_01_tmp SET mdd_1='mra_tmp',mdd_2='MRA_A03_SnfMarked_z',mdd_3='START';
INSERT INTO mra_00_tmp SET mdd_1='mra_tmp',mdd_2='MRA_A03_SnfMarked_z',mdd_3='START';
CALL MRA_IMP_A03_SNF_Marked_z(@m1vc);

INSERT INTO mra_01_tmp SET mdd_1="MRAA03_32ReAdmit_Flag21_z1",mdd_2='## Observation ##';
CALL mradb_prod.MRA_IMP_A03_32ReAdmit_Flag21_z1(m1pp,'Observation');
INSERT INTO mra_01_tmp SET mdd_1="MRAA03_32ReAdmit_Flag21_z1",mdd_2='## Acute Hospital ##';
CALL mradb_prod.MRA_IMP_A03_32ReAdmit_Flag21_z1(m1pp,'Acute Hospital');
INSERT INTO mra_01_tmp SET mdd_1="MRAA03_32ReAdmit_Flag22_z1",mdd_2='## SNF ##';
CALL mradb_prod.MRA_IMP_A03_32ReAdmit_Flag22_SNF_z1(m1pp);
INSERT INTO mra_01_tmp SET mdd_1="MRAA03_32ReAdmit_Flag23_z1",mdd_2='## ER ##';
CALL mradb_prod.MRA_IMP_A03_32ReAdmit_Flag23_ER_z1(m1pp);

INSERT INTO mra_00_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='SNF';
UPDATE mra1_encounter SET enc_proc_type='SNF' WHERE YEAR(enc_disch_date)>=m1pp AND proc_type_nr=1 AND enc_pos IN (20,30) AND is_snf_rec=1;

END */$$
