/* Procedure structure for procedure `MRA_IMP3_Z10_ENC_ColMapping_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP3_Z10_ENC_ColMapping_01`()
BEGIN

DECLARE mi BIGINT DEFAULT 0; DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 BIGINT;DECLARE qArg02 INT;DECLARE qFacilityNr INT;
DECLARE mrw CURSOR FOR SELECT entry_nr,encounter_nr,proc_type_nr,pt_facility_nr FROM mra1_encounter WHERE m1_map_status=5 AND YEAR(enc_disch_date)>=2023 ORDER BY enc_disch_date DESC, entry_nr;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
TRUNCATE mra_00_tmp;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qFacilityNr;
 
 IF bmc = 0 THEN
  SET mi=mi+1;
  SET @mv2Val="update mra1_encounter SET m1_map_status=1,mmodify_datetime=NOW()";
  SET @mEncCptTxt=''; SET @mEncIcdTxt='';SET @mEncIcd1Txt='';SET @mEncIcd2Txt='';SET @mEncIcd3Txt='';
  SET @mIcdAdmit=''; SET @mIcdPrinc='';
IF qArg02 = 1 THEN
mBLOCK_11: BEGIN
 DECLARE b2mc INT DEFAULT 0; DECLARE m2i INT;
 DECLARE q2Arg01 VARCHAR(100);DECLARE q2Arg02 VARCHAR(100);DECLARE q2Arg03 VARCHAR(30);
 DECLARE m2rw CURSOR FOR SELECT bb_Code,SUM(cal_amount+cal2amount) AS mtotal,CLM_LINE_PROD_REV_CTR_CD FROM mra1_encounter_bill_cpts WHERE encounter_nr=qArg01 GROUP BY bb_Code ORDER BY mtotal DESC LIMIT 20;
 DECLARE CONTINUE HANDLER FOR NOT FOUND SET b2mc = 1;
 SET m2i=0;
 OPEN m2rw; 
 read2loop: LOOP
  IF b2mc = 1 THEN LEAVE read2loop; END IF;
  FETCH FROM m2rw INTO q2Arg01,q2Arg02,q2Arg03;
  IF b2mc = 0 THEN
   SET m2i=m2i+1;
   IF q2Arg01 IS NULL THEN SET q2Arg01=''; END IF; IF q2Arg02 IS NULL THEN SET q2Arg02='0'; END IF;
   IF q2Arg03 IS NULL THEN SET q2Arg03=''; END IF;
   SET @mv2Val=CONCAT(@mv2Val,",m1_cpt",m2i,"_bb_code='",q2Arg01,"',m1_cpt",m2i,"_cal_amount='",q2Arg02,"',m1_cpt",m2i,"_revenue_code='",q2Arg03,"'");
   SET @mtmp=(SELECT cpt_name FROM cpt_codes WHERE cpt_code=q2Arg01 LIMIT 1);
   IF @mtmp IS NULL THEN SET @mtmp=''; END IF;
   IF q2Arg01 IS NULL THEN SET q2Arg01=''; END IF;
   SET @mEncCptTxt=CONCAT(@mEncCptTxt,' # ',m2i,' ) ',q2Arg01,' : ',@mtmp,', Amount : $ ',FORMAT(q2Arg02,2));
  END IF;
 END LOOP read2loop;
 mLOOP_01: LOOP
  IF  m2i >= 20 THEN LEAVE mLOOP_01; END IF;
  SET m2i = m2i + 1;
  SET @mv2Val=CONCAT(@mv2Val,",m1_cpt",m2i,"_bb_code='',m1_cpt",m2i,"_cal_amount='0',m1_cpt",m2i,"_revenue_code=''");
  ITERATE  mLOOP_01;
 END LOOP;
END mBLOCK_11;
ELSE
mBLOCK_12: BEGIN
 DECLARE b2mc INT DEFAULT 0; DECLARE m2i INT;
 DECLARE q2Arg01 VARCHAR(100);DECLARE q2Arg02 VARCHAR(100);DECLARE q2Arg03 VARCHAR(30);
 DECLARE m2rw CURSOR FOR SELECT bb_Code,SUM(cal_amount+cal2amount) AS mtotal,CLM_LINE_PROD_REV_CTR_CD FROM mra1_encounter_bill_cpts WHERE encounter_nr=qArg01 GROUP BY bb_Code ORDER BY mtotal DESC LIMIT 20;
 DECLARE CONTINUE HANDLER FOR NOT FOUND SET b2mc = 1;
 SET m2i=0;
 OPEN m2rw; 
 read2loop: LOOP
  IF b2mc = 1 THEN LEAVE read2loop; END IF;
  FETCH FROM m2rw INTO q2Arg01,q2Arg02,q2Arg03;
  IF b2mc = 0 THEN
   SET m2i=m2i+1;
   IF q2Arg01 IS NULL THEN SET q2Arg01=''; END IF; IF q2Arg02 IS NULL THEN SET q2Arg02='0'; END IF;
   IF q2Arg03 IS NULL THEN SET q2Arg03=''; END IF;
   SET @mv2Val=CONCAT(@mv2Val,",m1_cpt",m2i,"_bb_code='",q2Arg01,"',m1_cpt",m2i,"_cal_amount='",q2Arg02,"',m1_cpt",m2i,"_revenue_code='",q2Arg03,"'");
   SET @mtmp=(SELECT cpt_name FROM cpt_codes WHERE cpt_code=q2Arg01 LIMIT 1);
   IF @mtmp IS NULL THEN SET @mtmp=''; END IF;
   IF q2Arg01 IS NULL THEN SET q2Arg01=''; END IF;
   SET @mEncCptTxt=CONCAT(@mEncCptTxt,' # ',m2i,' ) ',q2Arg01,' : ',@mtmp,', Amount : $ ',FORMAT(q2Arg02,2));
  END IF;
 END LOOP read2loop;
 mLOOP_01: LOOP
  IF  m2i >= 20 THEN LEAVE mLOOP_01; END IF;
  SET m2i = m2i + 1;
  SET @mv2Val=CONCAT(@mv2Val,",m1_cpt",m2i,"_bb_code='',m1_cpt",m2i,"_cal_amount='0',m1_cpt",m2i,"_revenue_code=''");
  ITERATE  mLOOP_01;
 END LOOP;
END mBLOCK_12;
END IF;
mBLOCK_21: BEGIN
 DECLARE b2mc INT DEFAULT 0; DECLARE m2i INT; DECLARE m3i INT;
 DECLARE q2Arg01 VARCHAR(100); DECLARE q2Arg02 VARCHAR(30); DECLARE q2Arg03 VARCHAR(300);
 DECLARE m2rw CURSOR FOR SELECT diagnosis_code,problem_type,diagnosis_desc FROM encounter_icd_codes WHERE encounter_nr=qArg01 GROUP BY diagnosis_code,problem_type;
 DECLARE CONTINUE HANDLER FOR NOT FOUND SET b2mc = 1;

 SET m2i=0;
 OPEN m2rw; 
 read2loop: LOOP
  IF b2mc = 1 THEN LEAVE read2loop; END IF;
  FETCH FROM m2rw INTO q2Arg01,q2Arg02,q2Arg03;
  IF b2mc = 0 THEN
   SET m2i=m2i+1;
   IF q2Arg01 IS NULL THEN SET q2Arg01=''; END IF;

   IF q2Arg02='Admitting' THEN SET @mIcdAdmit=q2Arg01;
   ELSEIF q2Arg02='Principal' THEN SET @mIcdPrinc=q2Arg01; END IF;

   IF m2i <= 10 THEN SET @mv2Val=CONCAT(@mv2Val,",m1_icd",m2i,"_code='",q2Arg01,"'"); END IF;

   IF q2Arg02='Admitting' THEN 
    SET @mEncIcd1Txt=CONCAT(@mEncIcd1Txt,'
  # ',q2Arg01,' - ',q2Arg03);
   ELSEIF q2Arg02='Principal' THEN 
    SET @mEncIcd2Txt=CONCAT(@mEncIcd2Txt,'
  # ',q2Arg01,' - ',q2Arg03);
   ELSE 
    SET @mEncIcd3Txt=CONCAT(@mEncIcd3Txt,'
  # ',q2Arg01,' - ',q2Arg03);
   END IF;
  END IF;
 END LOOP read2loop;

 SET @mEncIcdTxt=CONCAT('[Admitting]',@mEncIcd1Txt,'
 
[Principal]',@mEncIcd2Txt,'
 
[Misc.]',@mEncIcd3Txt);


 mLOOP_01: LOOP
  IF  m2i >= 10 THEN LEAVE mLOOP_01; END IF;
  SET m2i = m2i + 1;
  SET @mv2Val=CONCAT(@mv2Val,",m1_icd",m2i,"_code=''");
  ITERATE  mLOOP_01;
 END LOOP;
END mBLOCK_21;
  SET @mEncCptTxt=REPLACE(@mEncCptTxt,"'","\\'"); SET @mEncIcdTxt=REPLACE(@mEncIcdTxt,"'","\\'");

  SET @mv2Val=CONCAT(@mv2Val,",m2_icd_admit='",@mIcdAdmit,"', m2_icd_princ='",@mIcdPrinc,"'"); 
  SET @mv2Val=CONCAT(@mv2Val,",m1_cpt_cpt_text='",@mEncCptTxt,"',m1_icd_code='",@mEncIcdTxt,"' WHERE entry_nr=",qArg00," AND pt_facility_nr=",qFacilityNr);
  PREPARE stmt FROM @mv2Val; EXECUTE stmt; DEALLOCATE PREPARE stmt;
  INSERT INTO mra_00_tmp SET mdd_1='MRA_Z10_ENC_ColMapping_01',mdd_2=qArg00,mdd_3=mi;
 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP3_Z30_SET_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP3_Z30_SET_01`()
BEGIN

SET @m1vc=2023;

INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='MRA_M12CalEncounterHeader',mdd_3='-';
CALL MRA_IMP3_M12CalEncounterHeader();
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='MRA-RE_M11CalEncounterHeader',mdd_3='-';
CALL MRA_IMP3_M11CalEncounterHeader();
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='MRA_Z10_ENC_ColMapping_01',mdd_3='-';
CALL MRA_IMP3_Z10_ENC_ColMapping_01();

INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='Emergency';
UPDATE mra1_encounter SET enc_proc_type='Emergency' WHERE YEAR(enc_disch_date)>=@m1vc AND is_er_visit=1;
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='Long Term Care Hospital';
UPDATE mra1_encounter SET enc_proc_type='Long Term Care Hospital' WHERE YEAR(enc_disch_date)>=@m1vc AND proc_type_nr=1 AND enc_pos IN (60,61) AND hos_taxonomy01 IN ('282E00000X');
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='Rehabilitation';
UPDATE mra1_encounter SET enc_proc_type='Rehabilitation' WHERE YEAR(enc_disch_date)>=@m1vc AND proc_type_nr=1 AND enc_pos IN (60,61) AND hos_taxonomy01 IN ('261QR0400X','283X00000X','261QR0401X','273Y00000X','2081P2900X','208100000X','283XC2000X','261QR0404X','111NR0400X','225400000X');
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='HHA';
UPDATE mra1_encounter SET enc_proc_type='HHA' WHERE YEAR(enc_disch_date)>=@m1vc AND proc_type_nr=1 AND enc_pos IN (60,61) AND hos_taxonomy01 IN ('251E00000X','253Z00000X','374U00000X','251F00000X');
UPDATE mra1_encounter SET enc_proc_type='Psychiatric' WHERE YEAR(enc_disch_date)>=@m1vc AND proc_type_nr=1 AND enc_pos IN (60,61) AND hos_taxonomy01 IN ('273R00000X','283Q00000X');
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='UNK';
UPDATE mra1_encounter SET enc_proc_type='UNK' WHERE YEAR(enc_disch_date)>=@m1vc AND proc_type_nr=1 AND enc_pos IN (60,61) AND enc_proc_type='';

#################################################################
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='Part B';
UPDATE mra1_encounter SET enc_proc_type='Part B' WHERE YEAR(enc_disch_date)>=@m1vc AND proc_type_nr=2;
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='Part DME';
UPDATE mra1_encounter SET enc_proc_type='Part DME' WHERE YEAR(enc_disch_date)>=@m1vc AND proc_type_nr=3;
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='m_cal_bed_days',mdd_3='';
UPDATE mra1_encounter SET m_cal_bed_days=DATEDIFF(enc_disch_date,is_enc_ref_admitdate) WHERE YEAR(enc_disch_date)>=@m1vc;
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='m_snf_cal_bed_days',mdd_3='';
UPDATE mra1_encounter SET m_cal_bed_days=DATEDIFF(enc_disch_date,is_snf_admitdate_ref) WHERE YEAR(enc_disch_date)>=@m1vc AND proc_type_nr=1 AND enc_pos IN (20,30) AND is_snf_rec=1;

#################################################################
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='market_nr',mdd_3='';
UPDATE mra1_encounter t1 SET t1.market_nr = (SELECT t2.market_id FROM hospital_market_assocs t2 WHERE t2.hosp_id=t1.pt_facility_nr) WHERE YEAR(t1.enc_disch_date)>=@m1vc;
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='market_name',mdd_3='';
UPDATE mra1_encounter t1 INNER JOIN hospital_market t2 ON t2.market_id=t1.market_nr SET t1.market_name=t2.`market_name` WHERE YEAR(t1.enc_disch_date)>=@m1vc;
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='pt_facility_name',mdd_3='';
UPDATE mra1_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.pt_facility_nr SET t1.pt_facility_name=t2.`name` WHERE YEAR(t1.enc_disch_date)>=@m1vc;
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='pt_facility_sub_name',mdd_3='';
UPDATE mra1_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.pt_facility_sub_nr SET t1.pt_facility_sub_name=t2.`name` WHERE YEAR(t1.enc_disch_date)>=@m1vc;
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='pt_sp_dr_1',mdd_3='';
UPDATE mra1_encounter t1 INNER JOIN personell t2 ON t2.npr_id=t1.pt_provider_num AND t2.is_dce=1 SET t1.pt_sp_dr_1=t2.`name` WHERE t2.is_dce=1 AND YEAR(t1.enc_disch_date)>=@m1vc;
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='m_provider_name',mdd_3='';
UPDATE mra1_encounter t1 INNER JOIN personell t2 ON t2.nr=t1.m_provider_nr SET t1.m_provider_name=t2.`name` WHERE YEAR(t1.enc_disch_date)>=@m1vc;
UPDATE mra1_encounter SET m_provider_nr=1,m_provider_npi='xxxx',m_provider_name='UNK' WHERE m_provider_nr IN (0,1,2) AND YEAR(enc_disch_date)>=@m1vc;


INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='No Sub Group',mdd_3='pt_facility_sub_name';
UPDATE mra1_encounter SET pt_facility_sub_name='No Sub Group' WHERE (pt_facility_sub_nr='' OR pt_facility_sub_nr IS NULL) AND YEAR(enc_disch_date)>=@m1vc;


#################################################################
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='m_pos_txt',mdd_3='';
UPDATE mra1_encounter t1 SET t1.m_pos_txt=(SELECT t2.`option_label` FROM option_code_values t2 WHERE t2.column_order IN ('1119','1120') AND t2.option_value=t1.enc_pos LIMIT 1) WHERE YEAR(t1.enc_disch_date)>=@m1vc;
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='m_prov_spclty_txt',mdd_3='';
UPDATE mra1_encounter t1 SET t1.m_prov_spclty_txt=(SELECT t2.`option_label` FROM option_code_values t2 WHERE t2.column_order='1118' AND t2.option_value=t1.CLM_PRVDR_SPCLTY_CD LIMIT 1) WHERE YEAR(t1.enc_disch_date)>=@m1vc;
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='m_patient_txt',mdd_3='';
UPDATE mra1_encounter t1 INNER JOIN patient t2 ON t1.patient_id=t2.origid SET t1.pt_lastname=t2.lastname,t1.pt_firstname=t2.firstname,t1.pt_birthdate=t2.birthdate WHERE YEAR(t1.enc_disch_date)>=@m1vc;

INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='e_discharge_text',mdd_3='';
UPDATE mradb_prod.mra1_encounter t1 INNER JOIN procedure_discharge t2 ON t2.encounter_nr=t1.encounter_nr SET t1.e_discharge_text=t2.discharge_loc WHERE YEAR(t1.enc_disch_date)>=@m1vc;
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='pre_hosp_name',mdd_3='';
UPDATE mra1_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.pre_hospital_nr SET t1.pre_hosp_name=t2.`name` WHERE YEAR(t1.enc_disch_date)>=@m1vc;

/*
INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='e_discharge_type',mdd_3='';
UPDATE mradb_prod.mra1_encounter t1 INNER JOIN procedure_discharge t2 ON t2.encounter_nr=t1.encounter_nr SET t1.e_discharge_type=t2.discharge_type WHERE YEAR(t1.enc_disch_date)>=@m1vc;
*/

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP4_A03_31Transfer_Flag_z` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_A03_31Transfer_Flag_z`(mpp1 INT, mpp2 VARCHAR(30))
BEGIN
DECLARE vtmp VARCHAR(900); 
DECLARE mv1tmp VARCHAR(20); DECLARE mv2tmp VARCHAR(30);
DECLARE mv3tmp TEXT;

DECLARE bmc INT DEFAULT 0;

DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);

DECLARE mrw CURSOR FOR 
SELECT entry_nr,pt_facility_nr,patient_id,enc_admit_date,enc_disch_date FROM mra4_encounter WHERE proc_type_nr=1 AND enc_proc_type=mpp2 AND YEAR(enc_disch_date)>=mpp1 ORDER BY entry_nr;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg2,qArg3,qArg4;
 IF bmc = 0 THEN

 INSERT INTO mra_00_tmp SET mdd_1="MRAA03_31Transfer_Flag_Marked_z",mdd_2=qArg00,mdd_3=qArg01,mdd_4=qArg2;

 SET vtmp=(SELECT encounter_nr FROM mra4_encounter WHERE proc_type_nr=1 AND pt_facility_nr=qArg01 AND patient_id=qArg2 AND enc_proc_type=mpp2 AND enc_admit_date=qArg4 AND entry_nr<>qArg00 LIMIT 1);
 IF vtmp IS NULL THEN
 
  SET mv1tmp=qArg3;SET mv2tmp=qArg00; SET mv3tmp='0;;';
  LOOP_M01: LOOP
   SET vtmp=(SELECT CONCAT(enc_admit_date,';;',entry_nr) FROM mra4_encounter WHERE proc_type_nr=1 AND pt_facility_nr=qArg01 AND patient_id=qArg2 AND enc_proc_type=mpp2 AND entry_nr<>mv2tmp AND mv1tmp=enc_disch_date LIMIT 1);
   IF vtmp IS NULL THEN
    LEAVE LOOP_M01;
   ELSEIF vtmp IS NOT NULL THEN
    SET mv1tmp=SUBSTRING_INDEX(vtmp,';;',1);SET mv2tmp=SUBSTRING_INDEX(vtmp,';;',-1);
    IF LOCATE(CONCAT(';;',mv2tmp,';;'),mv3tmp)>0 THEN
     LEAVE LOOP_M01;
    END IF;
    SET mv3tmp=CONCAT(mv3tmp,mv2tmp,';;');
   END IF;
   
  ITERATE LOOP_M01;
  END LOOP;
  
  UPDATE mra4_encounter SET is_enc_transfer=0,is_enc_ref_admitdate=mv1tmp WHERE pt_facility_nr=qArg01 AND entry_nr=qArg00;

 END IF; 

 END IF;
END LOOP;
CLOSE mrw;


END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP4_A03_32ReAdmit_Flag21_z1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_A03_32ReAdmit_Flag21_z1`(mpp1 INT,mpp2 varchar(30))
BEGIN

DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(100);DECLARE qArg06 VARCHAR(100);DECLARE qArg07 VARCHAR(100);

DECLARE mrw CURSOR FOR 
SELECT entry_nr,pt_facility_nr,pt_facility_sub_nr,pt_provider_num,YEAR(is_enc_ref_admitdate) AS `year`,MONTH(`is_enc_ref_admitdate`) AS `month`,enc_pos,is_enc_ref_admitdate AS mdate FROM mra4_encounter WHERE proc_type_nr=1 AND is_enc_transfer=0 and enc_proc_type=mpp2 AND YEAR(is_enc_ref_admitdate)>=mpp1 GROUP BY pt_facility_nr,pt_provider_num,`year`,`month`,enc_pos ORDER BY pt_facility_nr,pt_facility_sub_nr,pt_provider_num,`year`,`month`,enc_pos;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
IF bmc = 1 THEN LEAVE read_loop; END IF;
FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05,qArg06,qArg07;
IF bmc = 0 THEN

 INSERT INTO mra_00_tmp SET mdd_1="MRAA03_32ReAdmit_Flag_z",mdd_2=qArg00,mdd_3=qArg01;
 
 mBLOCK_01: BEGIN
 
  DECLARE v2tmp VARCHAR(300);
  
  DECLARE b2mc INT DEFAULT 0;
  DECLARE q2Arg00 BIGINT;DECLARE q2Arg01 VARCHAR(100);DECLARE q2Arg02 VARCHAR(100);DECLARE q2Arg03 VARCHAR(100);

  DECLARE m2rw CURSOR FOR 
  SELECT e.entry_nr, e.patient_id, e.is_enc_ref_admitdate, e.enc_disch_date FROM mra4_encounter e WHERE e.proc_type_nr=1 AND is_enc_transfer=0 AND e.pt_facility_nr=qArg01 AND e.pt_facility_sub_nr=qArg02 AND e.pt_provider_num=qArg03 AND e.is_enc_ref_admitdate BETWEEN concat(qArg04,'-',qArg05,'-01') AND concat(qArg04,'-',qArg05,'-31') AND e.enc_proc_type=mpp2 ORDER BY e.patient_id, e.is_enc_ref_admitdate;

  DECLARE CONTINUE HANDLER FOR NOT FOUND SET b2mc = 1;

  OPEN m2rw;
  read2loop: LOOP
  IF b2mc = 1 THEN LEAVE read2loop; END IF;
  FETCH m2rw INTO q2Arg00,q2Arg01,q2Arg02,q2Arg03;
  IF b2mc = 0 THEN
  
   SET v2tmp = (SELECT concat(e.enc_disch_date,';;', e.hospital_nr) FROM mra4_encounter e WHERE e.proc_type_nr=1 AND e.is_enc_transfer=0 AND e.pt_facility_nr=qArg01 AND e.pt_facility_sub_nr=qArg02 AND e.pt_provider_num=qArg03 AND e.enc_pos=qArg06 AND e.patient_id=q2Arg01 AND e.is_enc_ref_admitdate < q2Arg02 AND e.enc_disch_date <> q2Arg03 AND e.enc_proc_type=mpp2 and DATEDIFF(q2Arg02,e.enc_disch_date) between 0 and 30 ORDER BY e.patient_id, e.is_enc_ref_admitdate DESC LIMIT 1);
   IF v2tmp IS not NULL THEN
      UPDATE mra4_encounter SET is_c2_readmit=1,pre_discharge_date=SUBSTRING_INDEX(v2tmp,';;',1), pre_hospital_nr=SUBSTRING_INDEX(v2tmp,';;',-1) WHERE entry_nr=q2Arg00;
   END IF;

   SET v2tmp = (SELECT CONCAT(e.enc_disch_date,';;', t2.`name`) FROM mra4_encounter e INNER JOIN hospital_centers t2 ON t2.nr=e.hospital_nr WHERE e.proc_type_nr=1 AND e.pt_facility_nr=qArg01 AND e.pt_provider_num=qArg03 AND e.is_er_visit=1 AND e.patient_id=q2Arg01 AND e.enc_admit_date < q2Arg02 AND e.enc_disch_date <> q2Arg03 AND DATEDIFF(q2Arg02,e.enc_disch_date) BETWEEN 0 AND 30 ORDER BY e.patient_id, e.enc_admit_date DESC LIMIT 1);
   IF v2tmp IS NOT NULL THEN
      UPDATE mra4_encounter SET pre_emr_discharge_date=SUBSTRING_INDEX(v2tmp,';;',1), pre_emr_hospital_name=SUBSTRING_INDEX(v2tmp,';;',-1) WHERE entry_nr=q2Arg00;
   END IF;

  END IF;
  END LOOP;
  CLOSE m2rw;

 END mBLOCK_01; 

END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP4_A03_32ReAdmit_Flag22_SNF_z1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_A03_32ReAdmit_Flag22_SNF_z1`(mpp1 INT)
BEGIN

DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(100);DECLARE qArg06 VARCHAR(100);DECLARE qArg07 VARCHAR(100);

DECLARE mrw CURSOR FOR 
SELECT entry_nr,pt_facility_nr,pt_facility_sub_nr,pt_provider_num,YEAR(is_snf_admitdate_ref) AS `year`,MONTH(`is_snf_admitdate_ref`) AS `month`,enc_pos,is_snf_admitdate_ref AS mdate FROM mra4_encounter WHERE proc_type_nr=1 AND is_snf_rec=1 AND enc_pos IN (20,30) AND YEAR(is_snf_admitdate_ref)>=mpp1 GROUP BY pt_facility_nr,pt_provider_num,`year`,`month`,enc_pos ORDER BY pt_facility_nr,pt_facility_sub_nr,pt_provider_num,`year`,`month`,enc_pos;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
IF bmc = 1 THEN LEAVE read_loop; END IF;
FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05,qArg06,qArg07;
IF bmc = 0 THEN

 INSERT INTO mra_00_tmp SET mdd_1="MRAA03_32ReAdmit_Flag_SNF_z",mdd_2=qArg00,mdd_3=qArg01;
 
 mBLOCK_01: BEGIN
 
  DECLARE v2tmp VARCHAR(300);
  
  DECLARE b2mc INT DEFAULT 0;
  DECLARE q2Arg00 BIGINT;DECLARE q2Arg01 VARCHAR(100);DECLARE q2Arg02 VARCHAR(100);DECLARE q2Arg03 VARCHAR(100);

  DECLARE m2rw CURSOR FOR 
  SELECT e.entry_nr, e.patient_id, e.is_snf_admitdate_ref, e.enc_disch_date FROM mra4_encounter e WHERE e.proc_type_nr=1 AND is_snf_rec=1 AND e.pt_facility_nr=qArg01 AND e.pt_facility_sub_nr=qArg02 AND e.pt_provider_num=qArg03 AND e.enc_pos=qArg06 AND e.is_snf_admitdate_ref BETWEEN CONCAT(qArg04,'-',qArg05,'-01') AND CONCAT(qArg04,'-',qArg05,'-31') ORDER BY e.patient_id, e.is_snf_admitdate_ref;

  DECLARE CONTINUE HANDLER FOR NOT FOUND SET b2mc = 1;

  OPEN m2rw;
  read2loop: LOOP
  IF b2mc = 1 THEN LEAVE read2loop; END IF;
  FETCH m2rw INTO q2Arg00,q2Arg01,q2Arg02,q2Arg03;
  IF b2mc = 0 THEN
  
   SET v2tmp = (SELECT CONCAT(e.enc_disch_date,';;', e.hospital_nr) FROM mra4_encounter e WHERE e.proc_type_nr=1 AND e.is_snf_rec=1 AND e.pt_facility_nr=qArg01 AND e.pt_facility_sub_nr=qArg02 AND e.pt_provider_num=qArg03 AND e.enc_pos=qArg06 AND e.patient_id=q2Arg01 AND e.is_snf_admitdate_ref < q2Arg02 AND e.enc_disch_date <> q2Arg03 AND DATEDIFF(q2Arg02,e.enc_disch_date) between 0 and 30 ORDER BY e.patient_id, e.is_snf_admitdate_ref DESC LIMIT 1);
   IF v2tmp IS NOT NULL THEN
      UPDATE mra4_encounter SET is_c2_readmit=1,pre_discharge_date=SUBSTRING_INDEX(v2tmp,';;',1), pre_hospital_nr=SUBSTRING_INDEX(v2tmp,';;',-1) WHERE entry_nr=q2Arg00;
   END IF;

  END IF;
  END LOOP;
  CLOSE m2rw;

 END mBLOCK_01; 

END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP4_A03_32ReAdmit_Flag23_ER_z1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_A03_32ReAdmit_Flag23_ER_z1`(mpp1 INT)
BEGIN

DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(100);

DECLARE mrw CURSOR FOR 
SELECT entry_nr,pt_facility_nr,pt_facility_sub_nr,pt_provider_num,YEAR(enc_admit_date) AS `year`,MONTH(`enc_admit_date`) AS `month` FROM mra4_encounter WHERE proc_type_nr=1 AND is_er_visit=1 AND YEAR(enc_admit_date)>=mpp1 GROUP BY pt_facility_nr,pt_provider_num,`year`,`month` ORDER BY pt_facility_nr,pt_facility_sub_nr,pt_provider_num,`year`,`month`;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
IF bmc = 1 THEN LEAVE read_loop; END IF;
FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05;
IF bmc = 0 THEN

 INSERT INTO mra_00_tmp SET mdd_1="MRAA03_32ReAdmit_Flag_z",mdd_2=qArg00,mdd_3=qArg01;
 
 mBLOCK_01: BEGIN
 
  DECLARE v2tmp VARCHAR(300);
  
  DECLARE b2mc INT DEFAULT 0;
  DECLARE q2Arg00 BIGINT;DECLARE q2Arg01 VARCHAR(100);DECLARE q2Arg02 VARCHAR(100);DECLARE q2Arg03 VARCHAR(100);

  DECLARE m2rw CURSOR FOR 
  SELECT e.entry_nr, e.patient_id, e.enc_admit_date, e.enc_disch_date FROM mra4_encounter e WHERE e.proc_type_nr=1 AND e.pt_facility_nr=qArg01 AND e.pt_provider_num=qArg03 AND e.is_er_visit=1 AND e.enc_admit_date BETWEEN concat(qArg04,'-',qArg05,'-01') AND concat(qArg04,'-',qArg05,'-31') ORDER BY e.patient_id, e.enc_admit_date;

  DECLARE CONTINUE HANDLER FOR NOT FOUND SET b2mc = 1;

  OPEN m2rw;
  read2loop: LOOP
  IF b2mc = 1 THEN LEAVE read2loop; END IF;
  FETCH m2rw INTO q2Arg00,q2Arg01,q2Arg02,q2Arg03;
  IF b2mc = 0 THEN
  
   SET v2tmp = (SELECT concat(e.enc_disch_date,';;', e.hospital_nr) FROM mra4_encounter e WHERE e.proc_type_nr=1 AND e.pt_facility_nr=qArg01 AND e.pt_provider_num=qArg03 AND e.is_er_visit=1 AND e.patient_id=q2Arg01 AND e.enc_admit_date < q2Arg02 AND e.enc_disch_date <> q2Arg03 and DATEDIFF(q2Arg02,e.enc_disch_date) between 0 and 30 ORDER BY e.patient_id, e.enc_admit_date DESC LIMIT 1);
   IF v2tmp IS not NULL THEN
      UPDATE mra4_encounter SET is_er_readmit=1,pre_discharge_date=SUBSTRING_INDEX(v2tmp,';;',1), pre_hospital_nr=SUBSTRING_INDEX(v2tmp,';;',-1) WHERE entry_nr=q2Arg00;
   END IF;

  END IF;
  END LOOP;
  CLOSE m2rw;

 END mBLOCK_01; 

END IF;
END LOOP;
CLOSE mrw;

END */$$
