/* Procedure structure for procedure `MRA_IMP4_A03_72HrFlowUp_Set_z` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_A03_72HrFlowUp_Set_z`(mpp1 INT)
BEGIN

DECLARE m1vc tinyINT; DECLARE cv1flag tinyINT;DECLARE cv2flag tinyINT;DECLARE cv3flag tinyINT;DECLARE cv4flag tinyINT;

DECLARE vtmp VARCHAR(100); DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT; DECLARE qArg01 VARCHAR(100); DECLARE qArg02 VARCHAR(20);

DECLARE mrw CURSOR FOR SELECT e.entry_nr,e.patient_id,e.enc_disch_date FROM mra4_encounter e WHERE e.proc_type_nr=1 AND e.m_flwup_flag=1 AND YEAR(e.enc_disch_date)>=mpp1 ORDER BY e.entry_nr;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02;
 IF bmc = 0 THEN

  INSERT INTO mra_00_tmp SET mdd_1="MRA_A03_72HrFlowUp_Set_z",mdd_2=qArg00,mdd_3=1; 

  SET vtmp = (SELECT e.enc_admit_date FROM mra4_encounter e WHERE e.proc_type_nr IN (1,2) AND e.is_offvisit_rec=1 AND e.patient_id=qArg01 AND e.enc_admit_date>=qArg02 order by e.enc_admit_date LIMIT 1);
  IF vtmp IS NOT NULL THEN
   SET cv1flag=0;SET cv2flag=0;SET cv3flag=0;SET cv4flag=0;
   SET m1vc=MRA_A31_Get72HrFlowUpDays_m1(vtmp,qArg02);

   if m1vc between 0 and 3 then  SET cv1flag=1; SET cv2flag=1; SET cv3flag=1; 
   elseif m1vc between 4 and 7 then  SET cv2flag=1; SET cv3flag=1;
   elseif m1vc between 8 and 14 then  SET cv3flag=1; END IF;

   if m1vc >= 0 then SET cv4flag=1; END IF;

   UPDATE mra4_encounter SET is_72_hr_flwup=cv1flag,is_flwup_7_days=cv2flag,is_flwup_14_days=cv3flag,is_gflwup_14_days=cv4flag,m72hr_flwup_date=vtmp WHERE entry_nr=qArg00;
  END IF;

 END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP4_A03_ErVisit_Set_z` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_A03_ErVisit_Set_z`(mpp1 INT)
BEGIN

DECLARE bmc INT DEFAULT 0;
DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);

DECLARE mrw CURSOR FOR SELECT DISTINCT e.pt_facility_nr,e.encounter_nr FROM mra4_encounter e INNER JOIN mra4_encounter_bill_cpts t2 ON t2.encounter_nr=e.encounter_nr WHERE e.proc_type_nr=1 AND (CLM_LINE_PROD_REV_CTR_CD IN ('0450','0451','0452','0453','0454','0455','0456','0457','0458','0459','0981') AND DATEDIFF(e.enc_disch_date,e.enc_admit_date) <= 2) AND YEAR(e.enc_disch_date)>=mpp1;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;
INSERT INTO mra_00_tmp SET mdd_1="MRA_A03_ErVisit_Set_z",mdd_2='##START##',mdd_3=1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01,qArg02;
 IF bmc = 0 THEN
  UPDATE mra4_encounter SET is_er_visit=1 WHERE pt_facility_nr=qArg01 AND encounter_nr=qArg02;
  INSERT INTO mra_00_tmp SET mdd_1="MRA_A03_ErVisit_Set_z",mdd_2=qArg02,mdd_3=1;
 END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP4_A03_SNF_Marked_z` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_A03_SNF_Marked_z`(mpp1 INT)
BEGIN
DECLARE vtmp VARCHAR(900); 
DECLARE mv1tmp VARCHAR(20); DECLARE mv2tmp VARCHAR(30);
DECLARE mv3tmp TEXT;

DECLARE bmc INT DEFAULT 0;

DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);

DECLARE mrw CURSOR FOR 
SELECT entry_nr,pt_facility_nr,patient_id,enc_admit_date,enc_disch_date FROM mra4_encounter WHERE proc_type_nr=1 AND is_snf_rec=0 AND YEAR(enc_disch_date)>=mpp1 AND enc_pos IN (20,30) ORDER BY entry_nr; 

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg2,qArg3,qArg4;
 IF bmc = 0 THEN

 INSERT INTO mra_00_tmp SET mdd_1="MRA_A03_SNF_Marked_z",mdd_2=qArg00,mdd_3=qArg01,mdd_4=qArg2;

 SET vtmp=(SELECT encounter_nr FROM mra4_encounter WHERE proc_type_nr=1 AND pt_facility_nr=qArg01 AND patient_id=qArg2 AND enc_pos IN (20,30) AND DATEDIFF(enc_admit_date,qArg4) IN (0,1) LIMIT 1);
 IF vtmp IS NULL THEN

  SET mv1tmp=qArg3;SET mv2tmp=qArg00; SET mv3tmp='0;;';
  LOOP_M01: LOOP
   SET vtmp=(SELECT CONCAT(enc_admit_date,';;',entry_nr) FROM mra4_encounter WHERE proc_type_nr=1 AND pt_facility_nr=qArg01 AND patient_id=qArg2 AND enc_pos IN (20,30) AND entry_nr<>mv2tmp AND DATEDIFF(mv1tmp,enc_disch_date) IN (0,1) LIMIT 1);
   IF vtmp IS NULL THEN
    LEAVE LOOP_M01;
   ELSEIF vtmp IS NOT NULL THEN
    SET mv1tmp=SUBSTRING_INDEX(vtmp,';;',1);SET mv2tmp=SUBSTRING_INDEX(vtmp,';;',-1);
    IF LOCATE(CONCAT(';;',mv2tmp,';;'),mv3tmp)>0 THEN
     LEAVE LOOP_M01;
    END IF;
    SET mv3tmp=CONCAT(mv3tmp,mv2tmp,';;');
   END IF;
   
  ITERATE LOOP_M01;
  END LOOP;
  
  UPDATE mra4_encounter SET is_snf_rec=1,is_snf_admitdate_ref=mv1tmp WHERE pt_facility_nr=qArg01 AND entry_nr=qArg00;
 END IF; 

 END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

