DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_M02ENC_ACO_Map`(mpp1 INT,mpp2 INT)
BEGIN

DECLARE vtmp VARCHAR(900); 
DECLARE mi INT DEFAULT 0; DECLARE bmc INT DEFAULT 0;

DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(100);DECLARE qArg06 VARCHAR(100);DECLARE qArg07 VARCHAR(100);DECLARE qArg08 VARCHAR(100);DECLARE qArg09 VARCHAR(100);

DECLARE mrw CURSOR FOR SELECT mm_curr_mbi_id,market_id,market_names,dce_group_nr,dce_sub_group_nr,prov_npi_nr,dce_group_name,dce_sub_group_name,dce_provider_name FROM mradb_prod.dc_bene_alignment_roster t1 WHERE t1.cc_version=mpp2;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01,qArg02,qArg03,qArg04,qArg05,qArg06,qArg07,qArg08,qArg09;
 IF bmc = 0 THEN

  UPDATE mra4_encounter SET market_nr=qArg02,pt_fac_name=qArg07,pt_facility_nr=qArg04,pt_facility_sub_nr=qArg05,pt_provider_num=qArg06,pt_sp_dr_1=qArg09,pt_fac_sub_name=qArg08 WHERE patient_id=qArg01 AND YEAR(enc_admit_date)=mpp1;
  INSERT INTO mra_00_tmp SET mdd_1="MADT_02_Roster",mdd_2=CONCAT(mpp1,'-',mi),mdd_3=qArg01;

  SET mi=mi+1;
 END IF;
END LOOP;
CLOSE mrw;
END */$$
