/* Procedure structure for procedure `MRA_IMP4_M10AA_MainCall` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_M10AA_MainCall`(mpp1 SMALLINT)
BEGIN


INSERT INTO mra_06_tmp SET mdd_1='upt',mdd_2='m_ReSet_Flag',mdd_3='START';
# enc_proc_type='',
UPDATE mra4_encounter SET is_enc_transfer=1,is_enc_ref_admitdate=enc_admit_date,is_er_visit=0,is_visit_pcp=NULL,is_offvisit_rec=NULL,is_offvisit2rec=NULL,m_flwup_flag=0,is_72_hr_flwup=0,is_flwup_7_days=0,is_flwup_14_days=NULL,is_gflwup_14_days=NULL,modify_datetime=NOW() WHERE YEAR(enc_disch_date)>=mpp1;

INSERT INTO mra_06_tmp SET mdd_1='mra_tmp',mdd_2='ErVisit',mdd_3=1;
CALL MRA_IMP4_A03_ErVisit_Set_z(mpp1);


INSERT INTO mra_06_tmp SET mdd_1='mra_tmp',mdd_2='is_visit_pcp',mdd_3='START';
INSERT INTO mra_00_tmp SET mdd_1='mra_tmp',mdd_2='is_visit_pcp',mdd_3='START';
UPDATE mra4_encounter t1 
INNER JOIN personell_hosp_assocs t2 ON t2.hospital_nr=t1.pt_facility_nr AND t2.user_nr=t1.m_provider_nr 
 SET t1.is_visit_pcp=1 
WHERE YEAR(t1.enc_disch_date)>=mpp1 AND t1.is_visit_pcp IS NULL;

INSERT INTO mra_06_tmp SET mdd_1='mra_tmp',mdd_2='is_offvisit_rec',mdd_3='START';
INSERT INTO mra_00_tmp SET mdd_1='mra_tmp',mdd_2='is_offvisit_rec',mdd_3='START';
UPDATE mra4_encounter t1 
INNER JOIN mra4_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr 
 SET t1.is_offvisit_rec=1
WHERE ( (t2.bb_Code IN ('99201','99202','99203','99204','99205','99211','99212','99213','99214','99215','G2211','G2212','99241','99242','99243','99244','99245','99304','99305','99306','99307','99308','99309','99310','99341','99342','99343','99344','99345','99347','99348','99349','99350','99381','99382','99383','99384','99385','99386','99387','99391','99392','99393','99394','99395','99396','99397','99401','99402','99403','99404','99411','99412','99417','99429','99455','99456','99487','99489','99490','99495','99496','99497','99498','99499','99441','99442','99443','G0438','G0439','G0402','G0463','G0466','G0467','G0468','G0469','G0511','G0512','T1015') 
AND (t1.proc_type_nr=2 OR (t1.proc_type_nr=1 AND t1.CLM_TYPE_CD="40")) ) OR (t1.proc_type_nr=2 AND t1.CLM_TYPE_CD IN ('02','10')) ) AND YEAR(t1.enc_disch_date)>=mpp1; #  AND t1.is_visit_pcp=1

INSERT INTO mra_06_tmp SET mdd_1='mra_tmp',mdd_2='is_offvisit2rec',mdd_3='START';
INSERT INTO mra_00_tmp SET mdd_1='mra_tmp',mdd_2='is_offvisit2rec',mdd_3='START';
UPDATE mra4_encounter t1 
INNER JOIN mra4_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr 
 SET t1.is_offvisit2rec=1
WHERE ( (t2.bb_Code IN ('99201','99202','99203','99204','99205','99211','99212','99213','99214','99215','G2211','G2212','99241','99242','99243','99244','99245','99304','99305','99306','99307','99308','99309','99310','99341','99342','99343','99344','99345','99347','99348','99349','99350','99381','99382','99383','99384','99385','99386','99387','99391','99392','99393','99394','99395','99396','99397','99401','99402','99403','99404','99411','99412','99417','99429','99455','99456','99487','99489','99490','99495','99496','99497','99498','99499','99441','99442','99443','G0438','G0439','G0402','G0463','G0466','G0467','G0468','G0469','G0511','G0512','T1015') 
AND (t1.proc_type_nr=2 OR (t1.proc_type_nr=1 AND t1.CLM_TYPE_CD="40")) ) 
OR (t1.proc_type_nr=2 AND t1.CLM_TYPE_CD IN ('02','10')) ) AND YEAR(t1.enc_disch_date)>=mpp1 ;


INSERT INTO mra_06_tmp SET mdd_1='mra_tmp',mdd_2='m_flwup_flag',mdd_3='START';
INSERT INTO mra_00_tmp SET mdd_1="mra_tmp",mdd_2='m_flwup_flag',mdd_3='START';
UPDATE mra4_encounter e SET e.m_flwup_flag=1 WHERE e.proc_type_nr=1 AND (e.is_er_visit=1 OR (CLM_TYPE_CD IN ('60','61') AND hos_taxonomy01 IN ('282N00000X','282NC0060X','282NR1301X','282NC2000X','284300000X'))) AND YEAR(e.enc_disch_date)>=mpp1;
 #AND (e.e_discharge_type IN ('1','6','7','30','50','81','86') OR e.e_discharge_type IS NULL )

INSERT INTO mra_06_tmp SET mdd_1="mra_tmp",mdd_2='MRA_A03_72HrFlowUp_Set_z',mdd_3='START';
CALL MRA_IMP4_A03_72HrFlowUp_Set_z(mpp1);

CALL MRA_IMP4_S20_EncProcType_m1(mpp1);

INSERT INTO mra_06_tmp SET mdd_1='mra_06_tmp',mdd_2='MRAIMP4_M10AA_MainCall',mdd_3='END';

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP4_S10_SET_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_S10_SET_01`()
BEGIN
 DECLARE vtmp VARCHAR(100); DECLARE m1pp INT DEFAULT 0;
 DECLARE bmc INT DEFAULT 0; DECLARE mmi INT DEFAULT 0;
 DECLARE qArg01 INT; DECLARE qArg02 VARCHAR(100);
 DECLARE mrw CURSOR FOR SELECT DISTINCT MAX(cc_version),mm_year FROM dc_bene_alignment_roster WHERE mm_year>=2024 GROUP BY mm_year LIMIT 10;
 DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
 
 OPEN mrw;
 read_loop: LOOP
  IF bmc = 1 THEN LEAVE read_loop; END IF;
  FETCH mrw INTO qArg01,qArg02;
  IF bmc = 0 THEN
   SET  mmi = mmi + 1;
   INSERT INTO mra_00_tmp SET mdd_1="MRA_IMP4_Z10_SET_01",mdd_2=0,mdd_3=mmi,mdd_4=qArg02;
   SET m1pp=qArg01;
   UPDATE mra4_encounter SET pt_aligned_status=0 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-01-01') AND CONCAT(qArg02,'-12-31');
   INSERT INTO mra_00_tmp SET mdd_1="MRA_IMP4_Z10_SET_01",mdd_2=1,mdd_3=mmi,mdd_4=qArg02;
   UPDATE mra4_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-01-01') AND CONCAT(qArg02,'-01-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Jan='AL');
   UPDATE mra4_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-02-01') AND CONCAT(qArg02,'-02-28') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Feb='AL');
   UPDATE mra4_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-03-01') AND CONCAT(qArg02,'-03-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Mar='AL');
   INSERT INTO mra_00_tmp SET mdd_1="MRA_IMP4_Z10_SET_01",mdd_2=2,mdd_3=mmi,mdd_4=qArg02;
   UPDATE mra4_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-04-01') AND CONCAT(qArg02,'-04-30') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Apr='AL');
   UPDATE mra4_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-05-01') AND CONCAT(qArg02,'-05-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND May='AL');
   UPDATE mra4_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-06-01') AND CONCAT(qArg02,'-06-30') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Jun='AL');
   
   INSERT INTO mra_00_tmp SET mdd_1="MRA_IMP4_Z10_SET_01",mdd_2=3,mdd_3=mmi,mdd_4=qArg02;
   UPDATE mra4_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-07-01') AND CONCAT(qArg02,'-07-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Jul='AL');
   UPDATE mra4_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-08-01') AND CONCAT(qArg02,'-08-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Aug='AL');
   UPDATE mra4_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-09-01') AND CONCAT(qArg02,'-09-30') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Sep='AL');
   
   INSERT INTO mra_00_tmp SET mdd_1="MRA_IMP4_Z10_SET_01",mdd_2=4,mdd_3=mmi,mdd_4=qArg02;
   UPDATE mra4_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-10-01') AND CONCAT(qArg02,'-10-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND `Oct`='AL');
   UPDATE mra4_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-11-01') AND CONCAT(qArg02,'-11-30') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Nov='AL');
   UPDATE mra4_encounter SET pt_aligned_status=1 WHERE enc_disch_date BETWEEN CONCAT(qArg02,'-12-01') AND CONCAT(qArg02,'-12-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND `Dec`='AL');
 END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP4_S10_SET_02` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_S10_SET_02`()
BEGIN

 DECLARE vtmp VARCHAR(100); DECLARE m1pp INT DEFAULT 0;
 DECLARE bmc INT DEFAULT 0; DECLARE mmi INT DEFAULT 0;
 DECLARE qArg01 INT; DECLARE qArg02 VARCHAR(100);

 DECLARE mrw CURSOR FOR SELECT DISTINCT MAX(cc_version),mm_year FROM dc_bene_alignment_roster WHERE mm_year>=2024 GROUP BY mm_year LIMIT 10;
 DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

 OPEN mrw;
 read_loop: LOOP
  IF bmc = 1 THEN LEAVE read_loop; END IF;
  FETCH mrw INTO qArg01,qArg02;
  IF bmc = 0 THEN

   SET mmi = mmi+1; SET m1pp=qArg01;


   INSERT INTO mra_00_tmp SET mdd_1="MRA_IMP4_S10_SET_01",mdd_2=10,mdd_3=mmi,mdd_4=qArg02;
   UPDATE mra4_encounter SET pt_aligned2status=0 WHERE is_enc_ref_admitdate BETWEEN CONCAT(qArg02,'-01-01') AND CONCAT(qArg02,'-12-31');

   INSERT INTO mra_00_tmp SET mdd_1="MRA_IMP4_S10_SET_01",mdd_2=11,mdd_3=mmi,mdd_4=qArg02;
   UPDATE mra4_encounter SET pt_aligned2status=1 WHERE is_enc_ref_admitdate BETWEEN CONCAT(qArg02,'-01-01') AND CONCAT(qArg02,'-01-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Jan='AL');
   UPDATE mra4_encounter SET pt_aligned2status=1 WHERE is_enc_ref_admitdate BETWEEN CONCAT(qArg02,'-02-01') AND CONCAT(qArg02,'-02-29') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Feb='AL');
   UPDATE mra4_encounter SET pt_aligned2status=1 WHERE is_enc_ref_admitdate BETWEEN CONCAT(qArg02,'-03-01') AND CONCAT(qArg02,'-03-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Mar='AL');

   INSERT INTO mra_00_tmp SET mdd_1="MRA_IMP4_S10_SET_01",mdd_2=12,mdd_3=mmi,mdd_4=qArg02;
   UPDATE mra4_encounter SET pt_aligned2status=1 WHERE is_enc_ref_admitdate BETWEEN CONCAT(qArg02,'-04-01') AND CONCAT(qArg02,'-04-30') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Apr='AL');
   UPDATE mra4_encounter SET pt_aligned2status=1 WHERE is_enc_ref_admitdate BETWEEN CONCAT(qArg02,'-05-01') AND CONCAT(qArg02,'-05-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND May='AL');
   UPDATE mra4_encounter SET pt_aligned2status=1 WHERE is_enc_ref_admitdate BETWEEN CONCAT(qArg02,'-06-01') AND CONCAT(qArg02,'-06-30') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Jun='AL');
   
   INSERT INTO mra_00_tmp SET mdd_1="MRA_IMP4_S10_SET_01",mdd_2=13,mdd_3=mmi,mdd_4=qArg02;
   UPDATE mra4_encounter SET pt_aligned2status=1 WHERE is_enc_ref_admitdate BETWEEN CONCAT(qArg02,'-07-01') AND CONCAT(qArg02,'-07-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Jul='AL');
   UPDATE mra4_encounter SET pt_aligned2status=1 WHERE is_enc_ref_admitdate BETWEEN CONCAT(qArg02,'-08-01') AND CONCAT(qArg02,'-08-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Aug='AL');
   UPDATE mra4_encounter SET pt_aligned2status=1 WHERE is_enc_ref_admitdate BETWEEN CONCAT(qArg02,'-09-01') AND CONCAT(qArg02,'-09-30') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Sep='AL');

   INSERT INTO mra_00_tmp SET mdd_1="MRA_IMP4_S10_SET_01",mdd_2=14,mdd_3=mmi,mdd_4=qArg02;
   UPDATE mra4_encounter SET pt_aligned2status=1 WHERE is_enc_ref_admitdate BETWEEN CONCAT(qArg02,'-10-01') AND CONCAT(qArg02,'-10-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND `Oct`='AL');
   UPDATE mra4_encounter SET pt_aligned2status=1 WHERE is_enc_ref_admitdate BETWEEN CONCAT(qArg02,'-11-01') AND CONCAT(qArg02,'-11-30') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND Nov='AL');
   UPDATE mra4_encounter SET pt_aligned2status=1 WHERE is_enc_ref_admitdate BETWEEN CONCAT(qArg02,'-12-01') AND CONCAT(qArg02,'-12-31') AND patient_id IN (SELECT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE cc_version=m1pp AND `Dec`='AL');

 END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP4_S20_EncProcType_m1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_S20_EncProcType_m1`(m1pp INT)
BEGIN

INSERT INTO mra_06_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='SET_NULL';
INSERT INTO mra_00_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='SET_NULL';
UPDATE mra4_encounter SET enc_proc_type='',is_er_readmit=0,is_c2_readmit=0,pre_hospital_nr=0,pre_discharge_date=NULL,is_enc_transfer=1,is_enc_ref_admitdate=enc_admit_date,is_snf_rec=0,is_snf_admitdate_ref=NULL,pre_emr_hospital_name=NULL,pre_emr_discharge_date=NULL WHERE YEAR(enc_disch_date)>=m1pp;

INSERT INTO mra_00_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='Observation';
UPDATE mra4_encounter t1 INNER JOIN mra4_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr SET t1.enc_proc_type='Observation' WHERE YEAR(t1.enc_disch_date)>=m1pp AND t1.proc_type_nr=1 AND t1.CLM_TYPE_CD IN ('60','61') AND (t2.CLM_LINE_PROD_REV_CTR_CD IN ('0760','0762') OR t2.bb_Code IN ('99217','99218','99219','99220','99221','99222','99223','99224','99225','99226','99234','99235','99236'));
INSERT INTO mra_00_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='Acute Hospital';
UPDATE mra4_encounter SET enc_proc_type='Acute Hospital' WHERE YEAR(enc_disch_date)>=m1pp AND proc_type_nr=1 AND CLM_TYPE_CD IN ('60','61') AND hos_taxonomy01 IN ('282N00000X','282NC0060X','282NR1301X','282NC2000X','284300000X');
INSERT INTO mra_00_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='Hospice';
UPDATE mra4_encounter SET enc_proc_type='Hospice' WHERE YEAR(enc_disch_date)>=m1pp AND proc_type_nr=1 AND CLM_TYPE_CD IN ('50');

INSERT INTO mra_06_tmp SET mdd_1="MRAA03_31Transfer_Flag_Marked_z",mdd_2='## Observation ##';
CALL mradb_prod.MRA_IMP4_A03_31Transfer_Flag_z(m1pp,'Observation');
INSERT INTO mra_06_tmp SET mdd_1="MRAA03_31Transfer_Flag_Marked_z",mdd_2='## Acute Hospital ##';
CALL mradb_prod.MRA_IMP4_A03_31Transfer_Flag_z(m1pp,'Acute Hospital');
INSERT INTO mra_06_tmp SET mdd_1="MRAA03_31Transfer_Flag_Marked_z",mdd_2='## Hospice ##';
CALL mradb_prod.MRA_IMP4_A03_31Transfer_Flag_z(m1pp,'Hospice');

INSERT INTO mra_06_tmp SET mdd_1='mra_tmp',mdd_2='MRA_A03_SnfMarked_z',mdd_3='START';
INSERT INTO mra_00_tmp SET mdd_1='mra_tmp',mdd_2='MRA_A03_SnfMarked_z',mdd_3='START';
CALL MRA_IMP4_A03_SNF_Marked_z(@m1vc);

INSERT INTO mra_06_tmp SET mdd_1="MRAA03_32ReAdmit_Flag21_z1",mdd_2='## Observation ##';
call mradb_prod.MRA_IMP4_A03_32ReAdmit_Flag21_z1(m1pp,'Observation');
INSERT INTO mra_06_tmp SET mdd_1="MRAA03_32ReAdmit_Flag21_z1",mdd_2='## Acute Hospital ##';
call mradb_prod.MRA_IMP4_A03_32ReAdmit_Flag21_z1(m1pp,'Acute Hospital');
INSERT INTO mra_06_tmp SET mdd_1="MRAA03_32ReAdmit_Flag22_z1",mdd_2='## SNF ##';
CALL mradb_prod.MRA_IMP4_A03_32ReAdmit_Flag22_SNF_z1(m1pp);
INSERT INTO mra_06_tmp SET mdd_1="MRAA03_32ReAdmit_Flag23_z1",mdd_2='## ER ##';
CALL mradb_prod.MRA_IMP4_A03_32ReAdmit_Flag23_ER_z1(m1pp);

INSERT INTO mra_00_tmp SET mdd_1='mra1_enc_zz',mdd_2='enc_proc_type',mdd_3='SNF';
UPDATE mra4_encounter SET enc_proc_type='SNF' WHERE YEAR(enc_disch_date)>=m1pp AND proc_type_nr=1 AND CLM_TYPE_CD IN ('20','30') AND is_snf_rec=1;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP4_Z10_ENC_ColMapping_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_Z10_ENC_ColMapping_01`()
BEGIN

DECLARE vtmp VARCHAR(1000); DECLARE mi BIGINT DEFAULT 0;
DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 BIGINT;
DECLARE mrw CURSOR FOR SELECT entry_nr,encounter_nr FROM mra4_encounter WHERE m4_map_status=0 AND enc_admit_date>='2025-01-01';

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
TRUNCATE mra4_00_tmp;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01;
 
 IF bmc = 0 THEN
  SET mi=mi+1;
  SET @mv2Val="update mra4_encounter SET m4_map_status=1";
mBLOCK_01: BEGIN
 DECLARE b2mc INT DEFAULT 0; DECLARE m2i INT;
 DECLARE q2Arg01 VARCHAR(100);DECLARE q2Arg02 VARCHAR(100);
 DECLARE m2rw CURSOR FOR SELECT bb_Code,cal_amount FROM mra4_encounter_bill_cpts WHERE encounter_nr=qArg01 ORDER BY cal_amount DESC LIMIT 10;
 DECLARE CONTINUE HANDLER FOR NOT FOUND SET b2mc = 1;
 SET m2i=0;
 OPEN m2rw; 
 read2loop: LOOP
  IF b2mc = 1 THEN LEAVE read2loop; END IF;
  FETCH FROM m2rw INTO q2Arg01,q2Arg02;
  IF b2mc = 0 THEN
   SET m2i=m2i+1;
   SET @mv2Val=CONCAT(@mv2Val,",m4_cpt",m2i,"_bb_code='",q2Arg01,"',m4_cpt",m2i,"_cal_amount='",q2Arg02,"'");
  END IF;
 END LOOP read2loop;
 mLOOP_01: LOOP
  IF  m2i >= 10 THEN LEAVE mLOOP_01; END IF;
  SET m2i = m2i + 1;
  SET @mv2Val=CONCAT(@mv2Val,",m4_cpt",m2i,"_bb_code='',m4_cpt",m2i,"_cal_amount='0'");
  ITERATE  mLOOP_01;
 END LOOP;
END mBLOCK_01;

mBLOCK_02: BEGIN
 DECLARE b2mc INT DEFAULT 0; DECLARE m2i INT; DECLARE m3i INT;
 DECLARE q2Arg01 VARCHAR(100); DECLARE q2Arg02 VARCHAR(50);
 DECLARE m2rw CURSOR FOR SELECT DISTINCT diagnosis_code,problem_type FROM mra4_encounter_icd_codes WHERE encounter_nr=qArg01 LIMIT 10;
 DECLARE CONTINUE HANDLER FOR NOT FOUND SET b2mc=1;

 SET m2i=0; SET @mv41Val=''; SET @mv42Val='';
 OPEN m2rw; 
 read2loop: LOOP
  IF b2mc = 1 THEN LEAVE read2loop; END IF;
  FETCH FROM m2rw INTO q2Arg01,q2Arg02;
  IF b2mc = 0 THEN
   IF q2Arg02='admitting' THEN SET @mv41Val=q2Arg01;
   ELSEIF q2Arg02='principal' THEN SET @mv42Val=q2Arg01;    
   ELSEIF m2i <= 10 THEN
    SET m2i=m2i+1; SET @mv2Val=CONCAT(@mv2Val,",m4_icd",m2i,"_code='",q2Arg01,"'");
   END IF;
  END IF;
 END LOOP read2loop;

 SET @mv2Val=CONCAT(@mv2Val,",m4_icd_admit='",@mv41Val,"'");
 SET @mv2Val=CONCAT(@mv2Val,",m4_icd_princ='",@mv42Val,"'");

 mLOOP_01: LOOP
  IF  m2i >= 10 THEN LEAVE mLOOP_01; END IF;
  SET m2i = m2i + 1;
  SET @mv2Val=CONCAT(@mv2Val,",m4_icd",m2i,"_code=''");
  ITERATE  mLOOP_01;
 END LOOP;
END mBLOCK_02;
  SET @mv2Val=CONCAT(@mv2Val," WHERE entry_nr=",qArg00);
  PREPARE stmt FROM @mv2Val; EXECUTE stmt; DEALLOCATE PREPARE stmt;
  INSERT INTO mra4_00_tmp SET mdd_1='MRA_IMP4_Z01ENC_ColMap01',mdd_2=qArg00,mdd_3=mi,mdd_6=@mv2Val;
 END IF;
END LOOP;

CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP4_Z20_SET_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_Z20_SET_01`()
BEGIN

 INSERT INTO mra_00_tmp SET mdd_1='mra_00_tmp',mdd_2='pt_facility_nr',mdd_3=1;
 UPDATE mra4_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.pt_facility_nr SET t1.pt_fac_name=t2.`name`;
 INSERT INTO mra_00_tmp SET mdd_1='mra_00_tmp',mdd_2='pt_facility_sub_nr',mdd_3=1;
 UPDATE mra4_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.pt_facility_sub_nr SET t1.pt_fac_sub_name=t2.`name`;
 INSERT INTO mra_00_tmp SET mdd_1='mra_00_tmp',mdd_2='m_provider_name',mdd_3=1;
 UPDATE mra4_encounter t1 INNER JOIN personell t2 ON t2.nr=t1.m_provider_nr SET t1.m_provider_name=t2.`name`;
 INSERT INTO mra_00_tmp SET mdd_1='mra_00_tmp',mdd_2='hospital_name',mdd_3=1;
 UPDATE mra4_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.hospital_nr SET t1.hospital_name=t2.`name`;
 INSERT INTO mra_00_tmp SET mdd_1='mra_00_tmp',mdd_2='market_name',mdd_3=1;
 UPDATE mra4_encounter t1 INNER JOIN hospital_market t2 ON t2.market_id=t1.market_nr SET t1.market_name=t2.`market_name`;

 INSERT INTO mra_00_tmp SET mdd_1='mra_00_tmp',mdd_2='m_pos_txt',mdd_3=1;
 UPDATE mra4_encounter t1 SET t1.m_pos_txt=(SELECT t2.`option_label` FROM option_code_values t2 WHERE t2.column_order IN ('1119','1120') AND t2.option_value=t1.enc_pos LIMIT 1);
 INSERT INTO mra_00_tmp SET mdd_1='mra_00_tmp',mdd_2='m_prov_spclty_txt',mdd_3=1;
 UPDATE mra4_encounter t1 SET t1.m_prov_spclty_txt=(SELECT t2.`option_label` FROM option_code_values t2 WHERE t2.column_order='1118' AND t2.option_value=t1.CLM_PRVDR_SPCLTY_CD LIMIT 1);

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP4_Z30_SET_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP4_Z30_SET_01`()
BEGIN

SET @m1vc=2024;

TRUNCATE mra_06_tmp;

INSERT INTO mra_06_tmp SET mdd_1='mra_tmp',mdd_2='MRAIMP4_Z10_ENC_ColMapping_01',mdd_3=1;
CALL MRA_IMP4_Z10_ENC_ColMapping_01();

INSERT INTO mra_06_tmp SET mdd_1='mra_tmp',mdd_2='MRAIMP4_S10_SET01',mdd_3=1;
CALL MRA_IMP4_S10_SET_01();
INSERT INTO mra_06_tmp SET mdd_1='mra_tmp',mdd_2='MRAIMP4_S10_SET02',mdd_3=1;
CALL MRA_IMP4_S10_SET_02();


set @mmi=2024;
LOOP_M01:  LOOP
 INSERT INTO mra_06_tmp SET mdd_1='IMP81_GroupMap_m1',mdd_2=@mmi,mdd_3=1;
 SET @mRosterVersion=(SELECT MAX(cc_version) FROM dc_bene_alignment_rostr_m01 WHERE YEAR(mm_date)=@mmi);
 UPDATE mra4_encounter t1 INNER JOIN dc_bene_alignment_roster t2 ON t2.mm_curr_mbi_id=t1.patient_id
  SET t1.market_nr=t2.market_id,t1.market_name=t2.market_names,t1.pt_fac_name=t2.dce_group_name,t1.pt_facility_nr=t2.dce_group_nr,t1.pt_facility_sub_nr=t2.dce_sub_group_nr,t1.pt_provider_num=t2.prov_npi_nr,t1.pt_sp_dr_1=t2.dce_provider_name,t1.pt_fac_sub_name=t2.dce_sub_group_name WHERE t2.cc_version=@mRosterVersion AND YEAR(t1.enc_disch_date)=@mmi; 

 IF  @mmi >= 2024 THEN LEAVE LOOP_M01; END IF;
 SET  @mmi = @mmi + 1;
 ITERATE  LOOP_M01;
END LOOP;



INSERT INTO mra_06_tmp SET mdd_1='A03_ErVisit_Set_z',mdd_2='--',mdd_3=1;
CALL MRA_IMP4_A03_ErVisit_Set_z(@m1vc);

INSERT INTO mra_06_tmp SET mdd_1='m_cal_bed_days',mdd_2='3',mdd_3=1;
UPDATE mra4_encounter SET m_cal_bed_days=DATEDIFF(enc_disch_date,enc_admit_date) WHERE YEAR(enc_disch_date)>=@m1vc;

INSERT INTO mra_06_tmp SET mdd_1='mra4',mdd_2='pt_fac_name',mdd_3=1;
UPDATE mra4_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.pt_facility_nr SET t1.pt_fac_name=t2.`name` WHERE YEAR(t1.enc_disch_date)>=@m1vc;
INSERT INTO mra_06_tmp SET mdd_1='mra4',mdd_2='pt_fac_sub_name',mdd_3=1;
UPDATE mra4_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.pt_facility_sub_nr SET t1.pt_fac_sub_name=t2.`name` WHERE YEAR(t1.enc_disch_date)>=@m1vc;
INSERT INTO mra_06_tmp SET mdd_1='mra4',mdd_2='pt_sp_dr_1',mdd_3=1;
UPDATE mra4_encounter t1 INNER JOIN personell t2 ON t2.npr_id=t1.pt_provider_num AND t2.is_dce=1 SET t1.pt_sp_dr_1=t2.`name` WHERE t2.is_dce=1 AND YEAR(t1.enc_disch_date)>=@m1vc;


INSERT INTO mra_06_tmp SET mdd_1='mra4',mdd_2='patient',mdd_3=1;
UPDATE mra4_encounter t1 INNER JOIN patient t2 ON t1.patient_id=t2.origid SET t1.pt_lastname=t2.lastname,t1.pt_firstname=t2.firstname,t1.pt_birthdate=t2.birthdate WHERE YEAR(t1.enc_disch_date)>=@m1vc;


INSERT INTO mra_06_tmp SET mdd_1='hospital_centers',mdd_2='Reset',mdd_3=1;
UPDATE mra4_encounter t1 INNER JOIN hospital_centers t2 ON t2.nrp_id=t1.hc_npi_nr 
SET t1.hos_taxonomy01=t2.`taxonomy_1`,t1.hospital_nr=t2.`nr` WHERE YEAR(t1.enc_disch_date)>=@m1vc;

CALL MRA_IMP4_M10AA_MainCall(@m1vc);

INSERT INTO mra_06_tmp SET mdd_1='mra4_z30_01',mdd_2='## END ##',mdd_3=0;


/*
INSERT INTO mra_06_tmp SET mdd_1='enc_proc_type',mdd_2='Reset',mdd_3=1;
UPDATE mra4_encounter SET enc_proc_type='' WHERE YEAR(enc_disch_date)>=@m1vc;

INSERT INTO mra_06_tmp SET mdd_1='enc_proc_type',mdd_2='Acute Hospital',mdd_3=1;
UPDATE mra4_encounter SET enc_proc_type='Acute Hospital' WHERE proc_type_nr=1 AND CLM_TYPE_CD IN ('60','61') AND hos_taxonomy01 IN ('282N00000X','282NC0060X','282NR1301X','282NC2000X','284300000X') AND YEAR(enc_disch_date)>=@m1vc;

INSERT INTO mra_06_tmp SET mdd_1='enc_proc_type',mdd_2='Emergency',mdd_3=1;
UPDATE mra4_encounter SET enc_proc_type='Emergency' WHERE proc_type_nr=1 AND is_er_visit=1 AND YEAR(enc_disch_date)>=@m1vc;
*/

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP5_Z10_ENC_ColMapping_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP5_Z10_ENC_ColMapping_01`()
BEGIN

DECLARE vtmp VARCHAR(1000); DECLARE mi BIGINT DEFAULT 0; DECLARE bmc INT DEFAULT 0;
DECLARE mc1val INT;

DECLARE mRedmitFlag TINYINT DEFAULT 0;

DECLARE qArg00 BIGINT;DECLARE qArg01 BIGINT;DECLARE qArg02 VARCHAR(20);
DECLARE mrw CURSOR FOR SELECT entry_nr,encounter_nr,encounter_date FROM adt_encounter WHERE m1_map_status=0 AND YEAR(encounter_date)>=2024 ORDER BY entry_nr;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02;

 IF bmc = 0 THEN
  SET mi=mi+1;

  /* set mc1val=(SELECT COUNT(e.origid) as mcnt  FROM encounter e WHERE e.origid=qArg02 AND e.encounter_date BETWEEN qArg02 AND qArg02); if mc1val>1 then  set mRedmitFlag=1; end if; */

  SET @mv2Val=CONCAT("update adt_encounter SET m1_map_status=1,m_redmit_flag=",mRedmitFlag,",m_discharge_to=''");
  SET @mEncCptTxt=''; SET @mEncIcdTxt='';SET @mEncIcd1Txt='';SET @mEncIcd2Txt='';SET @mEncIcd3Txt='';

mBLOCK_21: BEGIN
 DECLARE b2mc INT DEFAULT 0; DECLARE m2i INT;
 DECLARE q2Arg01 VARCHAR(100); DECLARE q2Arg02 VARCHAR(30); DECLARE q2Arg03 VARCHAR(300);
 DECLARE m2rw CURSOR FOR SELECT diagnosis_code,problem_type,diagnosis_desc FROM adt_encounter_icd_codes  WHERE encounter_nr=qArg01;
 DECLARE CONTINUE HANDLER FOR NOT FOUND SET b2mc = 1;
 SET m2i=0;
 OPEN m2rw; 
 read2loop: LOOP
  IF b2mc = 1 THEN LEAVE read2loop; END IF;
  FETCH FROM m2rw INTO q2Arg01,q2Arg02,q2Arg03;
  IF b2mc = 0 THEN
   SET m2i=m2i+1;

   IF @mtmp IS NULL THEN SET @mtmp=''; END IF;
   IF q2Arg01 IS NULL THEN SET q2Arg01=''; END IF;

   IF q2Arg02='Admitting' THEN 
    SET @mEncIcd1Txt=CONCAT(@mEncIcd1Txt,'
  # ',q2Arg01,' - ',q2Arg03);
   ELSEIF q2Arg02='Principal' THEN 
    SET @mEncIcd2Txt=CONCAT(@mEncIcd2Txt,'
  # ',q2Arg01,' - ',q2Arg03);
   ELSE 
    SET @mEncIcd3Txt=CONCAT(@mEncIcd3Txt,'
  # ',q2Arg01,' - ',q2Arg03);
   END IF;
  END IF;
 END LOOP read2loop;


 SET @mEncIcdTxt=CONCAT('[Admitting]',@mEncIcd1Txt,'
 
[Principal]',@mEncIcd2Txt,'
 
[Misc.]',@mEncIcd3Txt);

END mBLOCK_21;

  SET @mEncIcdTxt=REPLACE(@mEncIcdTxt,"'","\\'");
  SET @mv2Val=CONCAT(@mv2Val,",m1_icd_code='",@mEncIcdTxt,"' WHERE entry_nr=",qArg00);
  PREPARE stmt FROM @mv2Val; EXECUTE stmt; DEALLOCATE PREPARE stmt;
  INSERT INTO mra_52_tmp SET mdd_1='MRAIMP5_Z10_ENC_ColMapping_01',mdd_2=qArg00,mdd_3=mi;

 END IF;
END LOOP;
CLOSE mrw;

END */$$
