DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP5_Z30_SET_01`()
BEGIN

 SET @m1vc=2023;

 INSERT INTO mra_00_tmp SET mdd_1='adt_z30_enc',mdd_2='IMP5_Z30',mdd_3='START';

 call MRA_IMP5_Z10_ENC_ColMapping_01();

