INSERT INTO mra_00_tmp SET mdd_1='mra_tmp',mdd_2='enc_proc_type',mdd_3='Acute Hospital';
UPDATE adt_encounter e SET enc_proc_type='Acute Hospital' WHERE e.encounter_class_nr=4 AND e.encounter_status NOT IN ('cancelled','duplicate','delete', 'inactive') and e.align_status_code IN ('AL') and e.pos_curr IN (21,60,61) AND e.taxonomy IN ('282N00000X','282NC0060X','282NR1301X','282NC2000X','284300000X');
UPDATE adt_encounter e SET enc_proc_type='Rehabilitation' WHERE e.encounter_class_nr=4 AND e.encounter_status NOT IN ('cancelled','duplicate','delete', 'inactive') AND e.align_status_code IN ('AL') AND e.pos_curr IN (21,60,61) AND e.taxonomy IN ('261QR0400X','283X00000X','261QR0401X','273Y00000X','2081P2900X','208100000X','283XC2000X','261QR0404X','111NR0400X','225400000X');
UPDATE adt_encounter e SET enc_proc_type='HHA' WHERE e.encounter_class_nr=4 AND e.encounter_status NOT IN ('cancelled','duplicate','delete', 'inactive') AND e.align_status_code IN ('AL') AND e.pos_curr IN (21,60,61) AND e.taxonomy IN ('251E00000X','253Z00000X','374U00000X','251F00000X');
UPDATE adt_encounter e SET enc_proc_type='Hospice' WHERE e.encounter_class_nr=4 AND e.encounter_status NOT IN ('cancelled','duplicate','delete', 'inactive') AND e.align_status_code IN ('AL') AND e.pos_curr IN (21,60,61) AND e.taxonomy IN ('251G00000X');
UPDATE adt_encounter e SET enc_proc_type='SNF' WHERE e.encounter_class_nr=4 AND e.encounter_status NOT IN ('cancelled','duplicate','delete', 'inactive') AND e.align_status_code IN ('AL') AND e.pos_curr IN (21,60,61)  AND e.taxonomy IN ('314000000X');

INSERT INTO mra_00_tmp SET mdd_1='mra_tmp',mdd_2='OutPatient',mdd_3=1;
UPDATE adt_encounter e SET enc_proc_type='OutPatient' WHERE e.encounter_class_nr=4 AND e.encounter_status NOT IN ('cancelled','duplicate','delete', 'inactive') AND e.align_status_code IN ('AL') AND e.pos_curr IN (22);
UPDATE adt_encounter e SET enc_proc_type='Emergency' WHERE e.encounter_class_nr=4 AND e.encounter_status NOT IN ('cancelled','duplicate','delete', 'inactive') AND e.align_status_code IN ('AL') AND e.pos_curr IN (23); 
UPDATE adt_encounter e SET enc_proc_type='Observation' WHERE e.encounter_class_nr=4 AND e.encounter_status NOT IN ('cancelled','duplicate','delete', 'inactive') AND e.align_status_code IN ('AL') AND e.pos_curr IN (24);
UPDATE adt_encounter e SET enc_proc_type='IP-PREADMIT' WHERE e.encounter_class_nr=4 AND e.encounter_status NOT IN ('cancelled','duplicate','delete', 'inactive') AND e.align_status_code IN ('AL') AND e.pos_curr="-99";

INSERT INTO mra_00_tmp SET mdd_1='mra_tmp',mdd_2='m_cal_bed_days',mdd_3=1;
UPDATE adt_encounter SET m_cal_bed_days=DATEDIFF(DATE_ADD(discharge_date, INTERVAL 1 DAY),encounter_date);

#################################################################################################
INSERT INTO mra_00_tmp SET mdd_1='adt_z30_enc',mdd_2='is_visit_pcp',mdd_3='001';
UPDATE adt_encounter SET is_visit_pcp=NULL;
UPDATE adt_encounter t1 
INNER JOIN adt_appointment t2 ON t2.encounter_nr=t1.encounter_nr
INNER JOIN personell_hosp_assocs t3 ON t3.hospital_nr=t1.dce_group_nr AND t3.user_nr=t2.to_personell_nr 
 SET t1.is_visit_pcp=1
WHERE t1.align_status_code IN ('AL') AND YEAR(t1.encounter_date)>=@m1vc AND t1.is_visit_pcp IS NULL;


#################################################################################################
INSERT INTO mra_00_tmp SET mdd_1='adt_z30_enc',mdd_2='hospital_name',mdd_3='';
UPDATE adt_encounter t1 INNER JOIN adt_hosp_mhie t2 ON t2.nr=t1.mhos_mhie_nr SET t1.hospital_name=t2.`mname`,t1.hospital_npi=t2.`npi_id`;


INSERT INTO mra_00_tmp SET mdd_1='adt_z30_enc',mdd_2='market_id',mdd_3='';
UPDATE adt_encounter t1 SET t1.market_id = (SELECT t2.market_id FROM hospital_market_assocs t2 WHERE t2.hosp_id=t1.dce_group_nr);
UPDATE adt_encounter t1 INNER JOIN hospital_market t2 ON t2.market_id=t1.market_id SET t1.market_name=t2.`market_name`;
INSERT INTO mra_00_tmp SET mdd_1='adt_z30_enc',mdd_2='dce_group_name',mdd_3='';
UPDATE adt_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.dce_group_nr SET t1.dce_group_name=t2.`name`;
INSERT INTO mra_00_tmp SET mdd_1='adt_z30_enc',mdd_2='dce_group_sub_name',mdd_3='';
UPDATE adt_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.dce_group_sub_nr SET t1.dce_group_sub_name=t2.`name`; 
INSERT INTO mra_00_tmp SET mdd_1='adt_z30_enc',mdd_2='dce_provider_name',mdd_3='';
UPDATE adt_encounter t1 INNER JOIN personell t2 ON t2.npr_id=t1.dce_prov_npi_nr AND t2.is_dce=1 SET t1.dce_provider_name=t2.`name` WHERE t2.is_dce=1;


INSERT INTO mra_00_tmp SET mdd_1='adt_z30_enc',mdd_2='MRA_ADT_E02_EncMaping_01',mdd_3='';
call MRA_ADT_E02_EncMapping_01(@m1vc);


 INSERT INTO mra_00_tmp SET mdd_1='adt_z30_enc',mdd_2='##END##',mdd_3=0;
 
END */$$
