/* Procedure structure for procedure `MRA_IMP6_C01_Columns_m1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP6_C01_Columns_m1`(m1pp int)
BEGIN

DECLARE vtmp text; DECLARE v2tmp VARCHAR(1000); DECLARE bmc INT DEFAULT 0;

DECLARE m1Months VARCHAR(100);

DECLARE qArg00 BIGINT; DECLARE qArg01 VARCHAR(50); DECLARE qArg02 VARCHAR(50); DECLARE qArg03 SMALLINT; DECLARE qArg04 smallint; DECLARE qArg05 VARCHAR(20);

DECLARE mrw CURSOR FOR SELECT nr,dce_group_nr,mm_curr_mbi_id,mm_year,mm_month,mm_date FROM dc_bene_alignment_rostr_m01 WHERE cc_version=m1pp ORDER BY nr ASC;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;
INSERT INTO mra5_01_tmp SET job_id=m1pp, mdd_1="MRAIMP6_C01_Columns_m1",mdd_2='##START##',mdd_3=1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05;
 IF bmc = 0 THEN

  set m1Months = "1,2,3";
  if (MONTH(qArg05)=4 or MONTH(qArg05)=5 or MONTH(qArg05)=6) then set m1Months = "4,5,6";
  elseif (MONTH(qArg05)=7 or MONTH(qArg05)=8 or MONTH(qArg05)=9) THEN set m1Months = "7,8,9"; 
  elseif (MONTH(qArg05)=10 or MONTH(qArg05)=11 or MONTH(qArg05)=12) THEN set m1Months = "10,11,12"; 
  end if;

  SET v2tmp = (SELECT percentile FROM refactor_ai WHERE report_type_id=1 AND origid=qArg02 AND YEAR(index_date)=qArg03 AND MONTH(index_date)=MONTH(qArg05) ORDER BY mnr DESC LIMIT 1);
  IF v2tmp IS NULL THEN
    SET v2tmp = (SELECT percentile FROM refactor_ai WHERE report_type_id=1 AND origid=qArg02 AND FIND_IN_SET(MONTH(index_date),m1Months) ORDER BY mnr DESC LIMIT 1);
  END IF;
  IF v2tmp IS NULL THEN set v2tmp=0; end if;
  SET @mv1Val=CONCAT("UHA_percentile='",v2tmp,"'");

  SET v2tmp=(SELECT percentile FROM refactor_ai WHERE report_type_id=2 AND origid=qArg02 AND YEAR(index_date)=qArg03 AND MONTH(index_date)=MONTH(qArg05) ORDER BY mnr DESC LIMIT 1);
  IF v2tmp IS NULL THEN
    SET v2tmp=(SELECT percentile FROM refactor_ai WHERE report_type_id=2 AND origid=qArg02 AND FIND_IN_SET(MONTH(index_date),m1Months) ORDER BY mnr DESC LIMIT 1);
  END IF;
  IF v2tmp IS NULL THEN set v2tmp=0; end if;
  SET @mv1Val=CONCAT(@mv1Val,",UHA2percentile='",v2tmp,"'");

  SET @mvVal=CONCAT("UPDATE dc_bene_alignment_rostr_m01 SET ",@mv1Val," WHERE nr=",qArg00,"");  
  PREPARE stmt FROM @mvVal; EXECUTE stmt; DEALLOCATE PREPARE stmt;
  SET @mvVal=CONCAT("UPDATE dc_bene_alignment_roster SET ",@mv1Val," WHERE cc_version=",m1pp," AND mm_curr_mbi_id='",qArg02,"'");
  PREPARE stmt FROM @mvVal; EXECUTE stmt; DEALLOCATE PREPARE stmt; 

  SET vtmp = (SELECT CONCAT(IF(norm_risk_score IS NULL,'',norm_risk_score),'!@#',IF(clndr_yr IS NULL,'',clndr_yr),'!@#',IF(clndr_mo IS NULL,'',clndr_mo),'!@#',IF(bnmrk IS NULL,'',bnmrk),'!@#',IF(adi_natrank IS NULL,'',adi_natrank),'!@#',IF(adi_staterank IS NULL,'',adi_staterank),'!@#',IF(de_bmp IS NULL,'',de_bmp),'!@#',IF(lis_bmp IS NULL,'',lis_bmp),'!@#',IF(heba_bmp IS NULL,'',heba_bmp),'!@#',IF(cdi_natrank IS NULL,'',cdi_natrank),'!@#',IF(pa_bmp IS NULL,'',pa_bmp),'!@#',IF(pa_score IS NULL,'',pa_score),'!@#',IF(eqty_score IS NULL,'',eqty_score)) as mcc FROM mra_risk_score_report WHERE bene_mbi=qArg02 AND clndr_yr=qArg03 AND clndr_mo<=MONTH(NOW()) ORDER BY nr DESC LIMIT 1);
  IF vtmp IS not NULL THEN

   SET @mv1Val=concat("m_mra_score='",SUBSTRING_INDEX(vtmp,'!@#',1),"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',2);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=concat(@mv1Val,",mrisk_clndr_yr='",v2tmp,"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',3);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=concat(@mv1Val,",mrisk_clndr_mo='",v2tmp,"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',4);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=concat(@mv1Val,",mrisk_bnmrk='",v2tmp,"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',5);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=concat(@mv1Val,",mrisk_adi_natrank='",v2tmp,"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',6);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=concat(@mv1Val,",mrisk_adi_staterank='",v2tmp,"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',7);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=concat(@mv1Val,",mrisk_de_bmp='",v2tmp,"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',8);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=concat(@mv1Val,",mrisk_lis_bmp='",v2tmp,"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',9);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=concat(@mv1Val,",mrisk_heba_bmp='",v2tmp,"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',10);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=concat(@mv1Val,",mrisk_cdi_natrank='",v2tmp,"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',11);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=concat(@mv1Val,",mrisk_pa_bmp='",v2tmp,"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',12);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=concat(@mv1Val,",mrisk_pa_score='",v2tmp,"'");

   SET @mv1Val=CONCAT(@mv1Val,",mrisk_eqty_score='",SUBSTRING_INDEX(vtmp,'!@#',-1),"'");

   SET @mvVal=CONCAT("UPDATE dc_bene_alignment_rostr_m01 SET ",@mv1Val," WHERE nr=",qArg00,"");  
   PREPARE stmt FROM @mvVal; EXECUTE stmt; DEALLOCATE PREPARE stmt;
   SET @mvVal=CONCAT("UPDATE dc_bene_alignment_roster SET ",@mv1Val," WHERE cc_version=",m1pp," AND mm_curr_mbi_id='",qArg02,"'");
   PREPARE stmt FROM @mvVal; EXECUTE stmt; DEALLOCATE PREPARE stmt; 

  END IF;  

  INSERT INTO mra_00_tmp SET mdd_1="MRAIMP6_C01_Columns_m1",mdd_2=qArg00,mdd_3=m1pp;

 END IF;
END LOOP;
CLOSE mrw;

INSERT INTO mra5_01_tmp SET job_id=m1pp, mdd_1="MRAIMP6_C01_Columns_m1",mdd_2='##END##',mdd_3=1;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP6_C02_Columns_m1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP6_C02_Columns_m1`(m1pp int)
BEGIN

DECLARE vtmp text; DECLARE v2tmp VARCHAR(1000); DECLARE bmc INT DEFAULT 0;

DECLARE qArg00 BIGINT; DECLARE qArg01 VARCHAR(50); DECLARE qArg02 VARCHAR(50); DECLARE qArg03 SMALLINT; DECLARE qArg04 smallint; DECLARE qArg05 VARCHAR(20);

DECLARE mrw CURSOR FOR SELECT nr,dce_group_nr,mm_curr_mbi_id,mm_year,mm_month,mm_date FROM dc_bene_alignment_rostr_m01 WHERE cc_version=m1pp ORDER BY nr ASC;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;
INSERT INTO mra_01_tmp SET mdd_1="MRAIMP6_C02_Columns_m1",mdd_2='##START##',mdd_3=1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05;
 IF bmc = 0 THEN

  SET vtmp = (SELECT CONCAT(IF(BENE_DUAL_STUS_CD IS NULL,'',BENE_DUAL_STUS_CD),'!@#',IF(BENE_MDCR_STUS_CD IS NULL,'',BENE_MDCR_STUS_CD),'!@#',IF(BENE_PART_A_ENRLMT_BGN_DT IS NULL,'',BENE_PART_A_ENRLMT_BGN_DT),'!@#',IF(BENE_PART_B_ENRLMT_BGN_DT IS NULL,'',BENE_PART_B_ENRLMT_BGN_DT),'!@#',IF(BENE_RNG_BGN_DT IS NULL,'',BENE_RNG_BGN_DT),'!@#',IF(BENE_RNG_END_DT IS NULL,'',BENE_RNG_END_DT)) as mcc FROM mra_file_static.mra_cclf8 WHERE BENE_MBI_ID=qArg02 AND YEAR(create_date)=YEAR(qArg05) ORDER BY nr DESC LIMIT 1);
  IF vtmp IS not NULL THEN

   SET @mv1Val=concat("BENE_DUAL_STUS_CD='",SUBSTRING_INDEX(vtmp,'!@#',1),"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',2);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=concat(@mv1Val,",BENE_MDCR_STUS_CD='",v2tmp,"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',3);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=concat(@mv1Val,",BENE_PART_A_ENRLMT_BGN_DT='",v2tmp,"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',4);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=CONCAT(@mv1Val,",BENE_PART_B_ENRLMT_BGN_DT='",v2tmp,"'");
   SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',5);SET v2tmp=SUBSTRING_INDEX(v2tmp,'!@#',-1);
   SET @mv1Val=CONCAT(@mv1Val,",BENE_RNG_BGN_DT='",v2tmp,"'");
   SET @mv1Val=CONCAT(@mv1Val,",BENE_RNG_END_DT='",SUBSTRING_INDEX(vtmp,'!@#',-1),"'");

   SET @mvVal=CONCAT("UPDATE dc_bene_alignment_rostr_m01 SET ",@mv1Val," WHERE nr=",qArg00,"");  
   PREPARE stmt FROM @mvVal; EXECUTE stmt; DEALLOCATE PREPARE stmt;

  END IF;  

  INSERT INTO mra_00_tmp SET mdd_1="MRAIMP6_C02_Columns_m1",mdd_2=qArg00,mdd_3=m1pp;

 END IF;
END LOOP;
CLOSE mrw;

INSERT INTO mra_01_tmp SET mdd_1="MRAIMP6_C02_Columns_m1",mdd_2='##END##',mdd_3=1;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP6_C31_Columns_m1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP6_C31_Columns_m1`(m1pp INT)
BEGIN

 DECLARE vtmp TEXT;
 
 INSERT INTO mra_01_tmp SET mdd_1="MRAIMP6_C31_Columns_m1",mdd_2='##START##',mdd_3=1;

 SET vtmp = (SELECT CONCAT(mm_year,'!@#',mm_month) FROM dc_bene_alignment_rostr_m01 WHERE cc_version=m1pp LIMIT 1);
 SET @mm_year=SUBSTRING_INDEX(vtmp,'!@#',1);SET @mm_month=SUBSTRING_INDEX(vtmp,'!@#',-1);
 SET @mPreMonth = @mm_month - 1;

 SET @mPreVersion = (SELECT MAX(cc_version) FROM dc_bene_alignment_rostr_m01 WHERE mm_year=@mm_year AND mm_month=@mPreMonth); 

 INSERT INTO mra_01_tmp SET mdd_1="MRAIMP6_C31_Columns_m1",mdd_2=CONCAT('Y: ',@mm_year,' M: ',@mm_month,' -- PreVersion: ',@mPreVersion,' mPreMonth: ',@mPreMonth,' ;;');

 UPDATE dc_bene_alignment_rostr_m01 t1 
  INNER JOIN  dc_bene_alignment_rostr_m01 t2 ON t1.BENE_MBI_ID=t2.BENE_MBI_ID AND t1.mm_date=t2.mm_date SET 
    t1.m_pmra_score=t2.m_pmra_score,t1.m_prma_score=t2.m_prma_score,t1.hcc_count=t2.hcc_count,
    t1.hcc_diag=t2.hcc_diag,t1.stratification_level=t2.stratification_level,t1.stratification_reason=t2.stratification_reason
  WHERE  t1.cc_version=m1pp  AND t2.cc_version=@mPreVersion;

  UPDATE dc_bene_alignment_rostr_m01 t1 
  INNER JOIN  dc_bene_alignment_rostr_m01 t2 ON t1.BENE_MBI_ID=t2.BENE_MBI_ID SET 
    t1.m_pmra_score=t2.m_pmra_score,t1.m_prma_score=t2.m_prma_score,t1.hcc_count=t2.hcc_count,
    t1.hcc_diag=t2.hcc_diag,t1.stratification_level=t2.stratification_level,t1.stratification_reason=t2.stratification_reason
  WHERE  t1.cc_version=m1pp  AND t2.cc_version=@mPreVersion AND t1.mm_date=CONCAT(@mm_year,'-',@mm_month,'-01') AND t2.mm_date=CONCAT(@mm_year,'-',@mPreMonth,'-01');

 INSERT INTO mra_01_tmp SET mdd_1="MRAIMP6_C31_Columns_m1",mdd_2='##END##';

 CALL MRA_IMP6_C31_Columns_m2(m1pp);

/*
t1.market_id=t2.market_id,t1.market_names=t2.market_names,t1.dce_group_nr=t2.dce_group_nr,t1.dce_group_name=t2.dce_group_name,t1.dce_sub_group_nr=t2.dce_sub_group_nr,t1.dce_sub_group_name=t2.dce_sub_group_name, */


END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP6_C31_Columns_m2` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP6_C31_Columns_m2`(m1pp INT)
BEGIN

DECLARE m1val BIGINT; DECLARE bmc INT DEFAULT 0;

DECLARE qArg01 VARCHAR(50);
DECLARE mrw CURSOR FOR SELECT DISTINCT mm_curr_mbi_id FROM dc_bene_alignment_rostr_m01 WHERE cc_version=m1pp AND dce_group_nr=0;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;
INSERT INTO mra_01_tmp SET mdd_1="MRAIMP6_C31_Columns_m2",mdd_2='##START##',mdd_3=1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01;
 IF bmc = 0 THEN

  SET m1val = (SELECT nr FROM dc_bene_alignment_rostr_m01 WHERE cc_version=m1pp AND dce_group_nr<>0 AND mm_curr_mbi_id=qArg01 ORDER BY mm_date DESC LIMIT 1);
  IF m1val IS NOT NULL THEN

UPDATE dc_bene_alignment_rostr_m01 t1
INNER JOIN  dc_bene_alignment_rostr_m01 t2 ON t2.mm_curr_mbi_id=t1.mm_curr_mbi_id 
SET t1.market_id=t2.market_id, t1.dce_group_nr=t2.dce_group_nr,
 t1.prov_npi_nr=t2.prov_npi_nr, t1.dce_sub_group_nr=t2.dce_sub_group_nr,
 t1.market_names=t2.market_names, t1.dce_group_name=t2.dce_group_name,
 t1.dce_provider_name=t2.dce_provider_name, t1.dce_sub_group_name=t2.dce_sub_group_name
WHERE t1.cc_version=m1pp AND t2.nr=m1val AND t1.mm_curr_mbi_id=qArg01;

  END IF;  

  INSERT INTO mra_00_tmp SET mdd_1="MRAIMP6_C31_Columns_m2",mdd_2=qArg01,mdd_3=m1val;

 END IF;
END LOOP;
CLOSE mrw;

INSERT INTO mra_01_tmp SET mdd_1="MRAIMP6_C31_Columns_m2",mdd_2='##END##',mdd_3=1;

# CALL MRA_IMP6_C31_Columns_m3(m1pp);

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP6_C31_Columns_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP6_C31_Columns_m3`(m1pp INT)
BEGIN

DECLARE m1val BIGINT; DECLARE bmc INT DEFAULT 0;

DECLARE qArg01 VARCHAR(50);
DECLARE mrw CURSOR FOR SELECT DISTINCT mm_curr_mbi_id FROM dc_bene_alignment_rostr_m01 WHERE cc_version=m1pp;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;
INSERT INTO mra_01_tmp SET mdd_1="MRAIMP6_C31_Columns_m3",mdd_2='##START##',mdd_3=1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01;
 IF bmc = 0 THEN

  SET m1val = (SELECT nr FROM dc_bene_alignment_rostr_m01 WHERE cc_version=m1pp AND dce_group_nr<>0 AND mm_curr_mbi_id=qArg01 ORDER BY mm_date DESC LIMIT 1);
  IF m1val IS NOT NULL THEN

UPDATE dc_bene_alignment_rostr_m01 t1
INNER JOIN  dc_bene_alignment_rostr_m01 t2 ON t2.mm_curr_mbi_id=t1.mm_curr_mbi_id 
SET t1.market_id=t2.market_id, t1.dce_group_nr=t2.dce_group_nr,
 t1.prov_npi_nr=t2.prov_npi_nr, t1.dce_sub_group_nr=t2.dce_sub_group_nr,
 t1.market_names=t2.market_names, t1.dce_group_name=t2.dce_group_name,
 t1.dce_provider_name=t2.dce_provider_name, t1.dce_sub_group_name=t2.dce_sub_group_name
WHERE t1.cc_version=m1pp AND t2.nr=m1val AND t1.mm_curr_mbi_id=qArg01;

  END IF;  

  INSERT INTO mra_00_tmp SET mdd_1="MRAIMP6_C31_Columns_m3",mdd_2=qArg01,mdd_3=m1val;

 END IF;
END LOOP;
