/* Procedure structure for procedure `MRA_IMP6_C33_CHAPS_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP6_C33_CHAPS_m3`(m1pp int, m2pp date)
BEGIN

DECLARE bmc INT DEFAULT 0;DECLARE qArg00 bigint;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 date;
DECLARE isChapsFlag tinyINT;DECLARE isExlDeceased TINYINT;DECLARE isExlInstitutional tinyINT;DECLARE isPcvHcps TINYINT;
DECLARE m01Date date;

DECLARE mrw CURSOR FOR SELECT nr,mm_curr_mbi_id,BENE_DATE_OF_DEATH FROM dc_bene_alignment_rostr_m01 WHERE cc_version=m1pp and mm_date=m2pp ORDER BY nr ASC;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;
INSERT INTO mra_01_tmp SET mdd_1="MRAIMP6_C33_CHAPS_m3",mdd_2='##START##',mdd_3=1;

delete from mra_logs_chaps_m3 where roster_version=m1pp;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02;
 IF bmc = 0 THEN
 
  set m01Date=DATE_SUB(current_date(), INTERVAL 365 DAY);

  set isChapsFlag=0;SET isExlDeceased=0;SET isExlInstitutional=0;SET isPcvHcps=0;

  IF qArg02 IS not NULL and qArg02<>'0000-00-00' THEN SET isExlDeceased=1; END IF;
  
  SET @mtmp=(SELECT t2.nr FROM mra_file_static.mra_cclf2 t1 iNNER JOIN mra_file_static.mra_cclf1 t2 ON t2.CUR_CLM_UNIQ_ID=t1.CUR_CLM_UNIQ_ID WHERE t2.`BENE_MBI_ID`=qArg01 AND t2.`CLM_FROM_DT` BETWEEN m01Date AND m2pp AND t1.CLM_TYPE_CD IN ('40','50','60','20','30') LIMIT 1);
  IF @mtmp IS NULL THEN  SET isExlInstitutional=1; END IF;

  SET @mtmp=(SELECT t1.entry_nr FROM mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t1.encounter_nr=t2.encounter_nr WHERE t1.proc_type_nr=2 and t1.is_visit_pcp=1 AND t1.patient_id=qArg01 AND t1.enc_admit_date BETWEEN m01Date AND m2pp AND t2.bb_Code IN ('99201','99202','99203','99204','99205','99211','99212','99213','99214','99215','99381','99382','99383','99384','99385','99386','99387','99391','99392','99393','99394','99395','99396','99397','G0402','G0438','G0439') LIMIT 1);
  IF @mtmp is null THEN  SET isPcvHcps=1; END IF;
  
  IF isExlDeceased=1 or isExlInstitutional=1 OR isPcvHcps=1 THEN
    SET isChapsFlag=1;
  END IF;

  INSERT INTO mra_logs_chaps_m3 SET created_date=now(),roster_version=m1pp,roster_date=m2pp,mm_curr_mbi_id=qArg01,is_chaps_flag=isChapsFlag,exl_is_deceased=isExlDeceased,exl_is_institutional=isExlInstitutional,pcv_is_hcps=isPcvHcps;  
  
  # UPDATE dc_bene_alignment_rostr_m01 SET is_chaps_flag WHERE nr=qArg00;

  INSERT INTO mra_00_tmp SET mdd_1="MRAIMP6_C33_CHAPS_m3",mdd_2=m1pp,mdd_3=qArg01;

 END IF;
END LOOP;
CLOSE mrw;

INSERT INTO mra_01_tmp SET mdd_1="MRAIMP6_C33_CHAPS_m3",mdd_2='##END##',mdd_3=1;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP6_Z30_SET_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP6_Z30_SET_01`(m1pp INT)
BEGIN

SET @m1vc=2024;

UPDATE feed_status SET date_received=DATE_SUB(NOW(), INTERVAL 1 DAY),time_received=NOW(),updated_as_of=NOW(),date_in_uat=NOW(),date_in_prod=NOW() WHERE `type`='Roster' ORDER BY `year` DESC LIMIT 1;


INSERT INTO mra_00_tmp SET mdd_1='MRA_RosterMonthlyAlign_zz',mdd_2='MRAIMP6_C01_Columns_m1',mdd_3='--',mdd_4='# START #';
CALL MRA_IMP6_C01_Columns_m1(m1pp);
INSERT INTO mra_00_tmp SET mdd_1='MRA_RosterMonthlyAlign_zz',mdd_2='MRAIMP6_C01_Columns_m1',mdd_3='--',mdd_4='# END #';

INSERT INTO mra_00_tmp SET mdd_1='MRA_RosterMonthlyAlign_zz',mdd_2='MRAIMP6_C01_Columns_m1',mdd_3='--',mdd_4='# START #';
CALL MRA_IMP6_C02_Columns_m1(m1pp);
INSERT INTO mra_00_tmp SET mdd_1='MRA_RosterMonthlyAlign_zz',mdd_2='MRAIMP6_C01_Columns_m1',mdd_3='--',mdd_4='# END #';


INSERT INTO mra_00_tmp SET mdd_1='dc_bene_align_roster',mdd_2='patient_login',mdd_3='';

INSERT IGNORE INTO `patient_login` (`origid`,`username`,`password`,`pt_email`,`type`,`status`) 
SELECT origid,origid,SHA1('abc123'),email,'patient','true' FROM patient p 
INNER JOIN `dc_bene_alignment_rostr_m01` d ON p.origid=d.mm_curr_mbi_id 
WHERE d.cc_version=(SELECT MAX(cc_version) FROM dc_bene_alignment_rostr_m01 ) AND d.align_status_code='AL';

INSERT INTO mra_00_tmp SET mdd_1='dc_bene_align_roster',mdd_2='market_id',mdd_3='';
UPDATE dc_bene_alignment_roster t1 SET t1.market_id = (SELECT t2.market_id FROM hospital_market_assocs t2 WHERE t2.hosp_id=t1.dce_group_nr) WHERE mm_year>=@m1vc;
INSERT INTO mra_00_tmp SET mdd_1='dc_bene_align_roster',mdd_2='market_name',mdd_3='';
UPDATE dc_bene_alignment_roster t1 INNER JOIN hospital_market t2 ON t2.market_id=t1.market_id SET t1.market_names=t2.`market_name` WHERE mm_year>=@m1vc;

INSERT INTO mra_00_tmp SET mdd_1='dc_bene_alignment_roster',mdd_2='dce_group_name',mdd_3='';
UPDATE dc_bene_alignment_roster t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.dce_group_nr SET t1.dce_group_name=t2.`name` WHERE mm_year>=@m1vc;
INSERT INTO mra_00_tmp SET mdd_1='dc_bene_alignment_roster',mdd_2='dce_sub_group_name',mdd_3='';
UPDATE dc_bene_alignment_roster t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.dce_sub_group_nr SET t1.dce_sub_group_name=t2.`name` WHERE mm_year>=@m1vc;
INSERT INTO mra_00_tmp SET mdd_1='dc_bene_alignment_roster',mdd_2='dce_provider_name',mdd_3='';
UPDATE dc_bene_alignment_roster t1 INNER JOIN personell t2 ON t2.npr_id=t1.prov_npi_nr AND t2.is_dce=1 SET t1.dce_provider_name=t2.`name` WHERE t2.is_dce=1 AND mm_year>=@m1vc;

/*######################################################################################*/

INSERT INTO mra_00_tmp SET mdd_1='dc_bene_align_m01_roster',mdd_2='market_id',mdd_3='';
UPDATE dc_bene_alignment_rostr_m01 t1 SET t1.market_id = (SELECT t2.market_id FROM hospital_market_assocs t2 WHERE t2.hosp_id=t1.dce_group_nr) WHERE YEAR(mm_date)>=@m1vc;
INSERT INTO mra_00_tmp SET mdd_1='dc_bene_align_m01_roster',mdd_2='market_name',mdd_3='';
UPDATE dc_bene_alignment_rostr_m01 t1 INNER JOIN hospital_market t2 ON t2.market_id=t1.market_id SET t1.market_names=t2.`market_name` WHERE YEAR(mm_date)>=@m1vc;

INSERT INTO mra_00_tmp SET mdd_1='dc_bene_align_m01_roster',mdd_2='dce_group_name',mdd_3='';
UPDATE dc_bene_alignment_rostr_m01 t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.dce_group_nr SET t1.dce_group_name=t2.`name`,t1.dce_group_type=t2.dce_type WHERE YEAR(mm_date)>=@m1vc;
INSERT INTO mra_00_tmp SET mdd_1='dc_bene_align_m01_roster',mdd_2='dce_sub_group_name',mdd_3='';
UPDATE dc_bene_alignment_rostr_m01 t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.dce_sub_group_nr SET t1.dce_sub_group_name=t2.`name`,t1.dce_sub_group_type=t2.dce_type WHERE YEAR(mm_date)>=@m1vc;
INSERT INTO mra_00_tmp SET mdd_1='dc_bene_align_m01_roster',mdd_2='dce_provider_name',mdd_3='';
UPDATE dc_bene_alignment_rostr_m01 t1 INNER JOIN personell t2 ON t2.npr_id=t1.prov_npi_nr AND t2.is_dce=1 SET t1.dce_provider_name=t2.`name` WHERE t2.is_dce=1 AND YEAR(t1.mm_date)>=@m1vc;

/*
####################################################################################################
SELECT DISTINCT cc_version FROM dc_bene_alignment_rostr_m01
----------------------------------------------------------------------------------------------------
INSERT INTO dc_bene_alignment_rostr_m01_history SELECT * FROM dc_bene_alignment_rostr_m01 
WHERE cc_version=20241001;
D3ELETE FROM dc_bene_alignment_rostr_m01 WHERE cc_version=20241001;
####################################################################################################
UPDATE dc_quater_alignment t1 INNER JOIN personell t2 ON t2.npr_id=t1.prov_npi_nr AND t2.is_dce=1  SET t1.dce_provider_name=t2.`name`  WHERE t2.is_dce=1;
UPDATE mra3_bene_roster_summary t1 INNER JOIN personell t2 ON t2.npr_id=t1.prov_npi_nr AND t2.is_dce=1 SET t1.dce_provider_name=t2.`name` WHERE t2.is_dce=1;
UPDATE mra3_bene_no_visit_x_month t1 INNER JOIN personell t2 ON t2.npr_id=t1.prov_npi_nr AND t2.is_dce=1 SET t1.dce_provider_name=t2.`name` WHERE t2.is_dce=1;
*/

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP6_Z40_SET_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP6_Z40_SET_01`(m1pp int,m2pp varchar(100))
BEGIN

### COPY ROSTER Version to History #########################################################################################

if m1pp = 11 then
  SELECT DISTINCT cc_version FROM dc_bene_alignment_rostr_m01;

  INSERT INTO dc_bene_alignment_rostr_m01_history SELECT * FROM dc_bene_alignment_rostr_m01 WHERE cc_version=20250701;
  DELETE FROM dc_bene_alignment_rostr_m01 WHERE cc_version=20250701;

  UPDATE dc_quater_alignment t1 INNER JOIN personell t2 ON t2.npr_id=t1.prov_npi_nr AND t2.is_dce=1  SET t1.dce_provider_name=t2.`name`  WHERE t2.is_dce=1;

  UPDATE mra3_bene_roster_summary t1 INNER JOIN personell t2 ON t2.npr_id=t1.prov_npi_nr AND t2.is_dce=1 SET t1.dce_provider_name=t2.`name` WHERE t2.is_dce=1;
  UPDATE mra3_bene_no_visit_x_month t1 INNER JOIN personell t2 ON t2.npr_id=t1.prov_npi_nr AND t2.is_dce=1 SET t1.dce_provider_name=t2.`name` WHERE t2.is_dce=1;
end if;


### ADDING Current Month #########################################################################################
if m1pp = 12 then

  DELETE FROM dc_bene_alignment_rostr_m01 WHERE cc_version=20250101 AND mm_date='2025-02-01';

  INSERT INTO dc_bene_alignment_rostr_m01 ( map_process_status,mrisk_cdi_natrank, m_pmra_score,m_prma_score,hcc_count,hcc_diag, map_data_status,   map_mod_status,   map_mod_stats_desc,   cc_version,   mm_year,   mm_month,   mm_date,   ALIGN_STATUS_TXT,   ALIGN_STATUS_CODE,   mm_curr_mbi_id,   BENE_MBI_ID,   BENE_ALN_EFF_START_DATE,   BENE_ALN_EFF_TER_DATE,   BENE_F_NAME,   BENE_L_NAME,   BENE_L1_ADDR,   BENE_L2_ADDR,   BENE_L3_ADDR,   BENE_L4_ADDR,   BENE_L5_ADDR,   BENE_L6_ADDR,  BENE_CITY,   BENE_USPS_STATE_CODE,   BENE_ZIP_5,   BENE_ZIP_4,   BENE_STATE_CR_SSA,   BENE_STATE_CR_FIPS,   BENE_GENDER,   RACE_ETHNICITY,   BENE_BIRTH_DATE,   BENE_AGE,   BENE_DATE_OF_DEATH,   BENE_ELIGIBILITY_ALIGN_Y1,   BENE_ELIGIBILITY_ALIGN_Y2,   BENE_PART_D_CVRG_ALIGN_Y1,   BENE_PART_D_CVRG_ALIGN_Y2,   NEWLY_ALIGN_BENE_FLAG,   PRPETVE_PLUS_ALIGNT, 
  CLAIM_BASED_ALIGNT_INDTR,   VOLANTRY_ALIGNT_TYPE,   MOB_IMP_INDICATOR,   FRAILTY_INDICATOR,   M_RISK_W_UNP_ADMSN_INDICATOR,   H_RISK_SCR_INDICATOR,   m_mra_score,   mrisk_clndr_yr, 
  mrisk_clndr_mo,   mrisk_bnmrk,   mrisk_adi_natrank,   mrisk_adi_staterank,   mrisk_de_bmp,   mrisk_lis_bmp,   mrisk_heba_bmp,   mrisk_eqty_score,   mcnt_inpatient,   mcnt_er_visit, 
  mcnt_off_visit,   UHA_percentile,   UHA2percentile,   mra_adi_score,   Last_PCP_Visit_Date,   Last_PCP_Visit_Pc,   Last_Visit_Date,   Last_Visit_Pc,   stratification_level,   stratification_reason, 
  BENE_DUAL_STUS_CD,   BENE_MDCR_STUS_CD,   BENE_PART_A_ENRLMT_BGN_DT,   BENE_PART_B_ENRLMT_BGN_DT,   BENE_RNG_BGN_DT,   BENE_RNG_END_DT,   market_id,   dce_group_nr,   prov_npi_nr, 
  dce_sub_group_nr,   market_names,   dce_group_name,   dce_provider_name,   dce_sub_group_name,   created_date )

SELECT  
  2, mrisk_cdi_natrank, m_pmra_score,m_prma_score,hcc_count,hcc_diag, map_data_status,   map_mod_status,   map_mod_stats_desc,   cc_version,   mm_year,   mm_month,   '2025-08-01',   ALIGN_STATUS_TXT,   ALIGN_STATUS_CODE,   mm_curr_mbi_id,   BENE_MBI_ID,   BENE_ALN_EFF_START_DATE,   BENE_ALN_EFF_TER_DATE,   BENE_F_NAME,   BENE_L_NAME,   BENE_L1_ADDR,   BENE_L2_ADDR,   BENE_L3_ADDR,   BENE_L4_ADDR,   BENE_L5_ADDR,   BENE_L6_ADDR, 
  BENE_CITY,   BENE_USPS_STATE_CODE,   BENE_ZIP_5,   BENE_ZIP_4,   BENE_STATE_CR_SSA,   BENE_STATE_CR_FIPS,   BENE_GENDER,   RACE_ETHNICITY,   BENE_BIRTH_DATE,   BENE_AGE, 
  BENE_DATE_OF_DEATH,   BENE_ELIGIBILITY_ALIGN_Y1,   BENE_ELIGIBILITY_ALIGN_Y2,   BENE_PART_D_CVRG_ALIGN_Y1,   BENE_PART_D_CVRG_ALIGN_Y2,   NEWLY_ALIGN_BENE_FLAG,   PRPETVE_PLUS_ALIGNT, 
  CLAIM_BASED_ALIGNT_INDTR,   VOLANTRY_ALIGNT_TYPE,   MOB_IMP_INDICATOR,   FRAILTY_INDICATOR,   M_RISK_W_UNP_ADMSN_INDICATOR,   H_RISK_SCR_INDICATOR,   m_mra_score,   mrisk_clndr_yr, 
  mrisk_clndr_mo,   mrisk_bnmrk,   mrisk_adi_natrank,   mrisk_adi_staterank,   mrisk_de_bmp,   mrisk_lis_bmp,   mrisk_heba_bmp,   mrisk_eqty_score,   mcnt_inpatient,   mcnt_er_visit, 
  mcnt_off_visit,   UHA_percentile,   UHA2percentile,   mra_adi_score,   Last_PCP_Visit_Date,   Last_PCP_Visit_Pc,   Last_Visit_Date,   Last_Visit_Pc,   stratification_level,   stratification_reason, 
  BENE_DUAL_STUS_CD,   BENE_MDCR_STUS_CD,   BENE_PART_A_ENRLMT_BGN_DT,   BENE_PART_B_ENRLMT_BGN_DT,   BENE_RNG_BGN_DT,   BENE_RNG_END_DT,   market_id,   dce_group_nr,   prov_npi_nr, 
  dce_sub_group_nr,   market_names,   dce_group_name,   dce_provider_name,   dce_sub_group_name,   NOW() 
FROM dc_bene_alignment_rostr_m01 WHERE cc_version = '20250701' AND mm_date='2025-07-01';

end if;


#############################################################################################################
IF m1pp = 13 THEN
  INSERT IGNORE INTO patient (origid,facility_nr,sp_dr_1_npi,primary_start_date,primary_end_date,firstname,lastname,addr_str,addr_citytown_name,addr_zip,addr_state,sex,race,birthdate,inactive_date,age,create_time,create_id,external_id,mra_clm_refer_num,mra_clm_refer_m01,date_reg,otherid)

  SELECT t1.BENE_MBI_ID,t1.dce_group_nr,t1.prov_npi_nr,t1.BENE_ALN_EFF_START_DATE,t1.BENE_ALN_EFF_TER_DATE,
   t1.BENE_F_NAME,t1.BENE_L_NAME,t1.BENE_L1_ADDR,t1.BENE_CITY,t1.BENE_ZIP_5,t1.BENE_STATE_CR_SSA,t1.
   BENE_GENDER,t1.RACE_ETHNICITY,t1.BENE_BIRTH_DATE,t1.BENE_DATE_OF_DEATH,t1.BENE_AGE,NOW(),'dc_bene_alignment_roster',t1.nr,t1.nr,'dc_bene_alignment_roster', NOW(), '' 
  FROM dc_bene_alignment_roster t1
  WHERE t1.cc_version='20250701' AND mm_curr_mbi_id NOT IN (SELECT DISTINCT origid FROM patient);

end if;

### ROSTER Sanity checks ###################################################
/* 
SELECT  COUNT(*) AS mcnt, mm_curr_mbi_id,dce_group_name,prov_npi_nr,dce_provider_name
FROM dc_bene_alignment_rostr_m01
WHERE cc_version=20241101
GROUP BY mm_curr_mbi_id,prov_npi_nr,dce_group_name
 # HAVING mcnt<11
ORDER BY mcnt DESC
LIMIT 1000000
*/


### Copy Roster Version Data checks ###################################################
/*
UPDATE dc_bene_alignment_rostr_m01 t1
INNER JOIN dc_bene_alignment_rostr_m01 t2 ON t2.mm_curr_mbi_id=t1.mm_curr_mbi_id 
SET t1.hcc_diag=t2.hcc_diag,t1.m_pmra_score=t2.m_pmra_score,t1.m_prma_score=t2.m_prma_score,t1.hcc_count=t2.hcc_count,
t1.m_mra_score=t2.m_mra_score,t1.mrisk_clndr_yr=t2.mrisk_clndr_yr,t1.mrisk_clndr_mo=t2.mrisk_clndr_mo,
t1.mrisk_bnmrk=t2.mrisk_bnmrk,t1.mrisk_adi_natrank=t2.mrisk_adi_natrank,t1.mrisk_adi_staterank=t2.mrisk_adi_staterank,
t1.mrisk_de_bmp=t2.mrisk_de_bmp,t1.mrisk_lis_bmp=t2.mrisk_lis_bmp,t1.mrisk_heba_bmp=t2.mrisk_heba_bmp,
t1.mrisk_eqty_score=t2.mrisk_eqty_score,t1.UHA_percentile=t2.UHA_percentile,t1.UHA2percentile=t2.UHA2percentile,
t1.stratification_level=t2.stratification_level,t1.stratification_reason=t2.stratification_reason,
t1.mra_adi_score=t2.mra_adi_score,t1.BENE_DUAL_STUS_CD=t2.BENE_DUAL_STUS_CD,t1.BENE_MDCR_STUS_CD=t2.BENE_MDCR_STUS_CD,
t1.BENE_PART_A_ENRLMT_BGN_DT=t2.BENE_PART_A_ENRLMT_BGN_DT,t1.BENE_PART_B_ENRLMT_BGN_DT=t2.BENE_PART_B_ENRLMT_BGN_DT,
t1.BENE_RNG_BGN_DT=t2.BENE_RNG_BGN_DT,t1.BENE_RNG_END_DT=t2.BENE_RNG_END_DT
WHERE t1.cc_version=20250101 AND t2.cc_version=20241201 AND t2.mm_curr_mbi_id=t1.mm_curr_mbi_id;
*/


END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP81_GroupMap_m1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP81_GroupMap_m1`(mpp1 SMALLINT,mpp2 INT)
BEGIN
DECLARE vtmp VARCHAR(900); 
DECLARE mi INT DEFAULT 0; DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(100);DECLARE qArg06 VARCHAR(100);DECLARE qArg07 VARCHAR(100);DECLARE qArg08 VARCHAR(100);DECLARE qArg09 VARCHAR(100);DECLARE qArg10 VARCHAR(20);DECLARE qArg11 VARCHAR(64);DECLARE qArg12 VARCHAR(64);DECLARE qArg13 VARCHAR(6);DECLARE qArg14 VARCHAR(6);
DECLARE mrw CURSOR FOR SELECT DISTINCT mm_curr_mbi_id,market_id,market_names,dce_group_nr,dce_sub_group_nr,prov_npi_nr,dce_group_name,dce_sub_group_name,dce_provider_name,YEAR(mm_date),BENE_F_NAME,BENE_L_NAME,BENE_GENDER,`ALIGN_STATUS_CODE` FROM mradb_prod.dc_bene_alignment_rostr_m01 t1 WHERE t1.cc_version=mpp2;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01,qArg02,qArg03,qArg04,qArg05,qArg06,qArg07,qArg08,qArg09,qArg10,qArg11,qArg12,qArg13,qArg14;
 IF bmc = 0 THEN
  SET @mStartDate = CONCAT(qArg10,'-01-01'); SET @mEndDate = CONCAT(qArg10,'-12-31');
  IF mpp1=1 THEN   /* enc_disch_date */
    UPDATE mra1_encounter SET market_nr=qArg02,market_name=qArg03,pt_facility_name=qArg07,pt_facility_nr=qArg04,pt_facility_sub_nr=qArg05,pt_provider_num=qArg06,pt_sp_dr_1=qArg09,pt_facility_sub_name=qArg08 WHERE patient_id=qArg01 AND enc_disch_date BETWEEN @mStartDate AND @mEndDate;
  ELSEIF mpp1=4 THEN
    UPDATE mra4_encounter SET market_nr=qArg02,market_name=qArg03,pt_fac_name=qArg07,pt_facility_nr=qArg04,pt_facility_sub_nr=qArg05,pt_provider_num=qArg06,pt_sp_dr_1=qArg09,pt_fac_sub_name=qArg08 WHERE patient_id=qArg01 AND enc_disch_date BETWEEN @mStartDate AND @mEndDate;
  ELSEIF mpp1=5 THEN
   UPDATE adt_encounter SET market_id=qArg02,market_name=qArg03,dce_group_name=qArg07,dce_group_nr=qArg04,dce_group_sub_nr=qArg05,dce_prov_npi_nr=qArg06,dce_provider_name=qArg09,dce_group_sub_name=qArg08,lastname=qArg12,firstname=qArg11,sex=qArg13,align_status_code=qArg14 WHERE origid=qArg01  AND (
    (discharge_date IS NOT NULL AND discharge_date NOT IN ('0000-00-00', '1969-12-31') 
     AND discharge_date BETWEEN @mStartDate AND @mEndDate)
    OR 
    (discharge_date IS NULL OR discharge_date IN ('0000-00-00', '1969-12-31') 
     AND encounter_date BETWEEN @mStartDate AND @mEndDate)
);
/*
update adt_encounter set align_status_code='UAL' where (
    (discharge_date IS NOT NULL AND discharge_date NOT IN ('0000-00-00', '1969-12-31') 
     AND discharge_date BETWEEN @mStartDate AND @mEndDate)
    OR 
    (discharge_date IS NULL OR discharge_date IN ('0000-00-00', '1969-12-31') 
     AND encounter_date BETWEEN @mStartDate AND @mEndDate)
) and origid NOT IN (SELECT DISTINCT mm_curr_mbi_id FROM mradb_prod.dc_bene_alignment_rostr_m01 t1 WHERE t1.cc_version=mpp2 AND ALIGN_STATUS_CODE IN ('AL','D1Y')) AND align_status_code='AL';*/
  END IF;
  
  INSERT INTO mra_00_tmp SET mdd_1="MADT_02_Roster",mdd_2=CONCAT(mpp1,'-',mi),mdd_3=qArg01;
  SET mi=mi+1;
 END IF;
END LOOP;
CLOSE mrw;
 
 UPDATE adt_encounter SET encounter_status='admitted' WHERE (discharge_date IS NULL OR discharge_date IN ('0000-00-00', '1969-12-31') ) AND encounter_status NOT IN('cancelled','duplicate','delete', 'inactive')  AND (
    (discharge_date IS NOT NULL AND discharge_date NOT IN ('0000-00-00', '1969-12-31') 
     AND discharge_date BETWEEN @mStartDate AND @mEndDate)
    OR 
    (discharge_date IS NULL OR discharge_date IN ('0000-00-00', '1969-12-31') 
     AND encounter_date BETWEEN @mStartDate AND @mEndDate)
);
UPDATE adt_encounter SET encounter_status='discharge' WHERE (discharge_date IS NOT NULL OR discharge_date NOT IN ('0000-00-00', '1969-12-31') ) AND encounter_status NOT IN('cancelled','duplicate','delete', 'inactive')  AND (
    (discharge_date IS NOT NULL AND discharge_date NOT IN ('0000-00-00', '1969-12-31') 
     AND discharge_date BETWEEN @mStartDate AND @mEndDate)
    OR 
    (discharge_date IS NULL OR discharge_date IN ('0000-00-00', '1969-12-31') 
     AND encounter_date BETWEEN @mStartDate AND @mEndDate)
);
UPDATE adt_encounter e INNER JOIN adt_hosp_mhie h ON e.mhos_mhie_nr=h.nr SET
 e.hospital_name=h.`mname` WHERE  
      e.encounter_date BETWEEN @mStartDate AND @mEndDate
 AND e.hospital_name='UNK';
UPDATE adt_encounter SET align_status_code='UAL' WHERE origid NOT IN (SELECT DISTINCT mm_curr_mbi_id FROM mradb_prod.dc_bene_alignment_rostr_m01 t1 WHERE t1.cc_version=mpp2)  AND discharge_date BETWEEN @mStartDate AND @mEndDate;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_A01_PERF_PROV_00_z` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_A01_PERF_PROV_00_z`()
BEGIN

 DECLARE mmi INT;

 TRUNCATE mra3_performance_provider_rpt;
 UPDATE bt_static.mra_config_a1_perf_prov_01 SET map_data_status=0;

 SET mmi = 2024;
 LOOP_M01:  LOOP
  IF mmi <= 2022 THEN LEAVE LOOP_M01; END IF;
  INSERT INTO mra_01_tmp SET mdd_1='mra_01_tmp',mdd_2='MRA_A01_GroupPerformance_01_z',mdd_3=mmi;
  SET @m1cv = (SELECT cc_version FROM dc_bene_alignment_roster WHERE mm_year=mmi ORDER BY cc_version DESC LIMIT 1);
  # DELETE FROM mra3_performance_provider_rpt WHERE YEAR(m_mos)=mmi;
  CALL `MRA_IMP_A01_PERF_PROV_01_z`(@m1cv);
  SET mmi = mmi - 1; ITERATE LOOP_M01;
 END LOOP;


END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_A01_PERF_PROV_01_z` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_A01_PERF_PROV_01_z`(m1pp INT)
BEGIN

DECLARE vtmp TEXT; DECLARE v2tmp TEXT; DECLARE v3tmp INT; DECLARE m1Amt DOUBLE(20,4);
DECLARE m1DceSubGroupNr VARCHAR(30); DECLARE m1chk TINYINT;
DECLARE mvDecProvName VARCHAR(100); DECLARE mvDecProvNpi VARCHAR(20);
DECLARE mvStartdate VARCHAR(100); DECLARE mvEnddate VARCHAR(100);
DECLARE m1MemberCnt INT; DECLARE m1MarketNr INT;

DECLARE m1BchmrkAmt DOUBLE(20,4); DECLARE m1TotPaidExpAmt DOUBLE(20,4); DECLARE m1TotClaimExpAmt DOUBLE(20,4);
DECLARE m1IbnrAmt DOUBLE(20,4); DECLARE m1CapAmt DOUBLE(20,4); DECLARE m1MLR DOUBLE(20,4);
DECLARE m1NetstoplossAmt DOUBLE(20,4); DECLARE m1QualityAmt DOUBLE(20,4);
DECLARE m1TrnsptexpAmt DOUBLE(20,4); DECLARE m1CapPmPmAmt DOUBLE(20,4);
DECLARE m1MarginAmt DOUBLE(20,4); DECLARE m1MarginPmPmAmt DOUBLE(20,4);

DECLARE m1PartA_Amt DOUBLE(20,4); DECLARE m1PartB_Amt DOUBLE(20,4); DECLARE m1PartC_Amt DOUBLE(20,4); 

DECLARE bmc INT DEFAULT 0; DECLARE mmi INT DEFAULT 0; DECLARE m2mi INT;
DECLARE qArg01 VARCHAR(100); DECLARE qArg02 VARCHAR(100); DECLARE qArg03 VARCHAR(100);

DECLARE mrw CURSOR FOR SELECT dce_group_nr,prov_npi_nr,mm_year FROM dc_bene_alignment_roster
WHERE cc_version=m1pp AND dce_group_nr NOT IN (0,10014313) GROUP BY dce_group_nr,prov_npi_nr ORDER BY dce_group_nr; 
#   AND dce_group_nr IN (10003373)

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01,qArg02,qArg03;
 IF bmc = 0 THEN
  SET  mmi = mmi + 1;

  SET mvDecProvName = (SELECT `name` FROM personell WHERE is_dce=1 AND `npr_id`=qArg02 LIMIT 1);
  SET mvDecProvNpi = (SELECT `npr_id` FROM personell WHERE is_dce=1 AND `npr_id`=qArg02 LIMIT 1);
  SET m1MarketNr = (SELECT market_id FROM hospital_market_assocs WHERE hosp_id=qArg01 LIMIT 1);
  SET m1DceSubGroupNr = (SELECT dce_sub_group_nr FROM dc_bene_alignment_roster WHERE cc_version<=m1pp AND prov_npi_nr=mvDecProvNpi ORDER BY nr DESC LIMIT 1);

  SET v3tmp = (SELECT COUNT(DISTINCT MOS) FROM bt_static.mra_config_a1_perf_prov_01 WHERE YEAR(MOS)=qArg03);

  SET m2mi = 1;
  LOOP_M01:  LOOP
  IF  m2mi > v3tmp THEN LEAVE LOOP_M01; END IF;

  SET mvStartdate=CONCAT(qArg03,'-',m2mi,'-01'); SET mvEnddate=(SELECT LAST_DAY(mvStartdate));
  SET m1MemberCnt=MRA_FN01_DcMememberCount(m1pp,qArg01,mvDecProvNpi,mvStartdate);

  SET vtmp = (SELECT CONCAT(SUM(IBNR_PER),'!@#',SUM(TrnsptExp),'!@#',SUM(Bchmrk),'!@#',CapPMPM,'!@#',NetStoploss,'!@#',SUM(IBNR_A),'!@#',SUM(IBNR_B),'!@#',SUM(IBNR_C),'!@#',Quality) mccc FROM bt_static.mra_config_a1_perf_prov_01 WHERE Provider_NPI=qArg02 AND MOS=mvStartdate LIMIT 1); # dce_group_nr=qArg01 AND 

  SET m1IbnrAmt=SUBSTRING_INDEX(vtmp,'!@#',1); SET m1QualityAmt=SUBSTRING_INDEX(vtmp,'!@#',-1);
  SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',2); SET m1TrnsptexpAmt=SUBSTRING_INDEX(v2tmp,'!@#',-1);
  SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',3); SET m1BchmrkAmt=SUBSTRING_INDEX(v2tmp,'!@#',-1);
  SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',4); SET m1CapPmPmAmt=SUBSTRING_INDEX(v2tmp,'!@#',-1);
  SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',5); SET m1NetstoplossAmt=SUBSTRING_INDEX(v2tmp,'!@#',-1);
  SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',6); SET @m1Ibnr1Amt=SUBSTRING_INDEX(v2tmp,'!@#',-1);
  SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',7); SET @m1Ibnr2Amt=SUBSTRING_INDEX(v2tmp,'!@#',-1);
  SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',8); SET @m1Ibnr3Amt=SUBSTRING_INDEX(v2tmp,'!@#',-1);

  SET m1PartA_Amt=0; SET m1Amt = (SELECT SUM(t1.mh1_cal_amount+t1.mc1_cal2amount) AS mAMT FROM mra1_encounter t1 WHERE t1.proc_type_nr=1 AND t1.enc_class_nr=9 AND t1.pt_facility_nr=qArg01 AND t1.pt_provider_num=mvDecProvNpi AND t1.enc_disch_date BETWEEN mvStartdate AND mvEnddate AND t1.pt_aligned_status='1');
  IF m1Amt IS NOT NULL THEN SET m1PartA_Amt=m1Amt; END IF;

  SET m1PartB_Amt=0; SET m1Amt = (SELECT SUM(t2.cal_amount+t2.cal2amount) AS mAMT FROM mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr
WHERE t1.proc_type_nr=2 AND t1.enc_class_nr=10 AND t1.pt_facility_nr=qArg01 AND t1.pt_provider_num=mvDecProvNpi AND t1.enc_disch_date BETWEEN mvStartdate AND mvEnddate AND t1.pt_aligned_status='1');
  IF m1Amt IS NOT NULL THEN SET m1PartB_Amt=m1Amt; END IF;

  SET m1PartC_Amt=0; SET m1Amt = (SELECT SUM(t2.cal_amount+t2.cal2amount) AS mAMT FROM mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr
WHERE t1.proc_type_nr=3 AND t1.pt_facility_nr=qArg01 AND t1.pt_provider_num=mvDecProvNpi AND t1.enc_disch_date BETWEEN mvStartdate AND mvEnddate AND t1.pt_aligned_status='1');
  IF m1Amt IS NOT NULL THEN SET m1PartC_Amt=m1Amt; END IF;

 SET @m2PartA_Amt = m1PartA_Amt + CAST(@m1Ibnr1Amt AS DECIMAL(20,2));
 SET @m2PartB_Amt = m1PartB_Amt + CAST(@m1Ibnr2Amt AS DECIMAL(20,2));
 SET @m2PartC_Amt = m1PartC_Amt + CAST(@m1Ibnr3Amt AS DECIMAL(20,2));

 SET m1TotPaidExpAmt = m1PartA_Amt + m1PartB_Amt + m1PartC_Amt;
 SET m1TotClaimExpAmt = m1TotPaidExpAmt + m1IbnrAmt;
 
 SET m1NetstoplossAmt = m1MemberCnt * m1NetstoplossAmt;
 SET m1QualityAmt = m1MemberCnt * m1QualityAmt;
 SET m1CapAmt = m1MemberCnt * m1CapPmPmAmt;

 SET m1MarginAmt = m1BchmrkAmt - m1TotClaimExpAmt - m1CapAmt - m1NetstoplossAmt - m1QualityAmt - m1TrnsptexpAmt;
 SET m1MarginPmPmAmt=0;  IF m1MemberCnt != 0 THEN SET m1MarginPmPmAmt = m1MarginAmt / m1MemberCnt; END IF;

 SET m1MLR = m1TotClaimExpAmt + m1CapAmt + m1NetstoplossAmt + m1QualityAmt + m1TrnsptexpAmt;
 IF m1MLR != 0 THEN SET m1MLR = m1MLR / m1BchmrkAmt; END IF;

 SET m1chk=0;
 IF m1MemberCnt <= 0 THEN
  SET m1chk=1;
  SET vtmp = (SELECT 1 FROM bt_static.mra_config_a1_perf_prov_01 WHERE dce_group_nr=qArg01 AND Provider_NPI=qArg02 AND MOS=mvStartdate LIMIT 1);
  IF vtmp = 1 THEN
   SET m1chk=0;
  END IF;  
 END IF;

 IF m1chk = 1 THEN 
  SET m1BchmrkAmt = 0; SET m1NetstoplossAmt = 0; SET m1QualityAmt = 0; SET m1TrnsptexpAmt = 0; SET m1CapAmt = 0;
  SET m1MarginAmt = 0; SET m1MarginPmPmAmt = 0; SET m1MLR = 0;
 END IF;

 INSERT IGNORE INTO mra3_performance_provider_rpt SET m_market_nr=m1MarketNr, m_facility_nr=qArg01,m_facility_sub_nr=m1DceSubGroupNr, m_provider_num=qArg02, m_mos=mvStartdate, m_mbrs=m1MemberCnt, m_part_A_amt=@m2PartA_Amt, m_part_B_amt=@m2PartB_Amt, m_part_C_amt=@m2PartC_Amt, m_bchmrk_amt=m1BchmrkAmt, m_IBNR_amt=m1IbnrAmt, m_cap_amt=m1CapAmt,m_total_paid_expense=m1TotPaidExpAmt,m_total_claim_exp=m1TotClaimExpAmt, m_netstoploss_amt=m1NetstoplossAmt, m_quality_amt=m1QualityAmt, m_trnspt_exp_amt=m1TrnsptexpAmt, m_Cap_PMPM=m1CapPmPmAmt, m_margin_v=m1MarginAmt, m_margin_pmpm=m1MarginPmPmAmt, m_mlr=m1MLR, mcreate_id='admin', mcreate_datetime=NOW();

  UPDATE bt_static.mra_config_a1_perf_prov_01 SET map_data_status=1 WHERE dce_group_nr=qArg01 AND Provider_NPI=qArg02 AND MOS=mvStartdate;
  INSERT INTO mra_00_tmp SET mdd_1="mra3_performance_provider_rpt",mdd_2=CONCAT(m1pp,'--',mmi),mdd_3=qArg01,mdd_4=qArg02;
  
  SET  m2mi = m2mi + 1;
  ITERATE  LOOP_M01;
 END LOOP;

 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_A01_PERF_PROV_RANK_01_z` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_A01_PERF_PROV_RANK_01_z`()
BEGIN

DECLARE vtmp LONGTEXT; DECLARE m1Amt DOUBLE(20,4);
DECLARE mvStartdate VARCHAR(100); DECLARE mvEnddate VARCHAR(100);
DECLARE m1MemberCnt INT; DECLARE m1MarketNr INT; DECLARE m_roster_version INT;

DECLARE m1PartA_Amt DOUBLE(20,4); DECLARE m1PartA2Amt DOUBLE(20,4); DECLARE m1PartC_Amt DOUBLE(20,4);
DECLARE m1PartB_Amt DOUBLE(20,4); DECLARE m1PartB2Amt DOUBLE(20,4); DECLARE m1TotPaidExpAmt DOUBLE(20,4);

DECLARE mRiskScore VARCHAR(100); DECLARE m90DayNotSeen INT(11); DECLARE mDischargeCnt INT(11); DECLARE mLos BIGINT(20);
DECLARE mReAdmit INT(11); DECLARE mER_per1000 BIGINT(20);
DECLARE mCaseMngmnt VARCHAR(100); DECLARE mHeiCompleted VARCHAR(100);

DECLARE mAvgVisitPerYear BIGINT; DECLARE mAvgVisitHccPerYear VARCHAR(100);DECLARE mTotalAvgVisitHccPerYear INT;
DECLARE m72HourFollowUp VARCHAR(100); DECLARE m72HourFlwUpDem INT;
DECLARE mAdmitPer1000 DOUBLE(20,4); DECLARE mAlertAll VARCHAR(100); DECLARE mAlertCleared VARCHAR(100);
DECLARE mCcVersion VARCHAR(100);

DECLARE bmc INT DEFAULT 0; DECLARE mmi INT DEFAULT 0;
DECLARE qArg01 VARCHAR(100); DECLARE qArg02 VARCHAR(100); DECLARE qArg03 VARCHAR(100); DECLARE qArg04 VARCHAR(100); DECLARE qArg05 VARCHAR(20);

DECLARE mrw CURSOR FOR SELECT pt_facility_nr,pt_provider_num,YEAR(enc_admit_date) AS m_year,MONTH(enc_admit_date) AS m_month,pt_facility_sub_nr FROM mra1_encounter WHERE pt_facility_nr>0 AND enc_admit_date>="2023-01-01" AND enc_admit_date<=NOW()
GROUP BY pt_facility_nr,pt_provider_num,m_year,m_month
ORDER BY m_year DESC,m_month ASC,pt_facility_nr; # AND pt_facility_nr IN (3,10003373)  ==== AND enc_disch_date<="2023-03-01" 

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE `mra_00_tmp`; TRUNCATE mra3_performance_provider_ranking_rpt;

SET SESSION group_concat_max_len = 1000000;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01,qArg02,qArg03,qArg04,qArg05;
 IF bmc = 0 THEN
  SET  mmi = mmi + 1;
  
  SET m_roster_version = (SELECT MAX(cc_version) FROM dc_bene_alignment_rostr_m01 WHERE mm_year=qArg03);
  SET mvStartdate=CONCAT(qArg03,'-',qArg04,'-01'); SET mvEnddate=(SELECT LAST_DAY(mvStartdate));
  SET m1MarketNr = (SELECT market_id FROM hospital_market_assocs WHERE hosp_id=qArg01 LIMIT 1);
  SET m1MemberCnt=MRA_FN01_DcMememberCount(m_roster_version,qArg01,qArg02,mvStartdate);

  SET m1PartA_Amt=0; SET m1Amt = (SELECT SUM(t1.mh1_cal_amount+t1.mc1_cal2amount) AS mAMT FROM mra1_encounter t1 WHERE t1.proc_type_nr=1 AND t1.enc_class_nr=9 AND t1.pt_facility_nr=qArg01 AND t1.pt_provider_num=qArg02 AND t1.enc_disch_date BETWEEN mvStartdate AND mvEnddate AND t1.pt_aligned_status=1);
  IF m1Amt IS NOT NULL THEN SET m1PartA_Amt=m1Amt; END IF;

  SET m1PartB_Amt=0; SET m1Amt = (SELECT SUM(t2.cal_amount+t2.cal2amount) AS mAMT FROM mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr
WHERE t1.proc_type_nr=2 AND t1.enc_class_nr=10 AND t1.pt_facility_nr=qArg01 AND t1.pt_provider_num=qArg02 AND t1.enc_disch_date BETWEEN mvStartdate AND mvEnddate AND t1.pt_aligned_status=1);
  IF m1Amt IS NOT NULL THEN SET m1PartB_Amt=m1Amt; END IF;

  SET m1PartC_Amt=0; SET m1Amt = (SELECT SUM(t2.cal_amount+t2.cal2amount) AS mAMT FROM mra1_encounter t1 INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=t1.encounter_nr
WHERE t1.proc_type_nr=3 AND t1.pt_facility_nr=qArg01 AND t1.pt_provider_num=qArg02 AND t1.enc_disch_date BETWEEN mvStartdate AND mvEnddate AND t1.pt_aligned_status=1);
  IF m1Amt IS NOT NULL THEN SET m1PartC_Amt=m1Amt; END IF;

 SET m1TotPaidExpAmt = m1PartA_Amt + m1PartB_Amt + m1PartC_Amt;

 SET mReAdmit=0; SET m1Amt = (SELECT COUNT(t1.encounter_nr) AS mAMT FROM mra1_encounter t1 WHERE  t1.pt_aligned_status=1 AND t1.proc_type_nr=1 AND t1.enc_pos IN (60,61) AND t1.is_readmit=1 AND t1.pt_facility_nr=qArg01 AND t1.pt_provider_num=qArg02 AND t1.enc_disch_date BETWEEN mvStartdate AND mvEnddate);
 IF m1Amt IS NOT NULL THEN SET mReAdmit=m1Amt; END IF;
 
 SET mLos=0; SET m1Amt = (SELECT SUM(d_count) AS d_count FROM (SELECT DATEDIFF(e.enc_disch_date,e.enc_admit_date) AS d_count FROM mra1_encounter e WHERE e.pt_aligned_status=1 AND e.proc_type_nr=1 AND e.enc_pos IN (60,61) AND e.pt_facility_nr=qArg01 AND e.pt_provider_num=qArg02 AND e.enc_disch_date BETWEEN mvStartdate AND mvEnddate) tb1);
 IF m1Amt IS NOT NULL THEN SET mLos=m1Amt; END IF;

 SET mDischargeCnt=0; SET m1Amt = (SELECT COUNT(t1.encounter_nr) AS mAMT FROM mra1_encounter t1 WHERE  t1.pt_aligned_status=1 AND t1.proc_type_nr=1 AND t1.enc_pos IN (60,61) AND t1.pt_facility_nr=qArg01 AND t1.pt_provider_num=qArg02 AND t1.enc_disch_date BETWEEN mvStartdate AND mvEnddate);
 IF m1Amt IS NOT NULL THEN SET mDischargeCnt=m1Amt; END IF;

 SET mER_per1000=(SELECT COUNT(cnt) AS d_count FROM (SELECT COUNT(DISTINCT e.entry_nr) AS cnt, DATEDIFF(e.enc_disch_date,e.enc_admit_date) AS mdays FROM mra1_encounter e INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=e.encounter_nr WHERE e.proc_type_nr=1 AND e.enc_pos IN (40) AND e.enc_class_nr=9 AND e.enc_status!='cancelled' AND e.pt_aligned_status=1 AND e.pt_facility_nr=qArg01 AND e.pt_provider_num=qArg02 AND e.enc_admit_date BETWEEN mvStartdate AND mvEnddate AND CLM_LINE_PROD_REV_CTR_CD IN ('0450','0451','0452','0453','0454','0455','0456','0457','0458','0459','0981') GROUP BY e.entry_nr HAVING mdays <=2) AS tbl);

 SET mAdmitPer1000 = (SELECT COUNT(DISTINCT e.entry_nr) AS cnt FROM mra1_encounter e WHERE e.proc_type_nr=1 AND e.pt_aligned_status=1 AND e.enc_pos IN (60,61) AND e.pt_facility_nr=qArg01 AND e.pt_provider_num=qArg02 AND e.enc_admit_date BETWEEN mvStartdate AND mvEnddate);

 SET mCaseMngmnt = (SELECT COUNT(t1.entry_nr) AS mAMT FROM adt_encounter t1 INNER JOIN ccm_history t2 ON t2.encounter_nr=t1.encounter_nr WHERE t1.dce_group_nr=qArg01 AND t1.dce_prov_npi_nr=qArg02 AND t1.encounter_date BETWEEN mvStartdate AND mvEnddate AND t2.`TYPE` IN ('ST_CM','LT_CM'));

 SET mHeiCompleted=(SELECT COUNT(DISTINCT t2.origid) AS mAMT FROM mra_member_history_data t2 WHERE t2.created_date BETWEEN mvStartdate AND mvEnddate AND t2.history_nr=150665 AND t2.history_value='Completed' AND t2.origid IN ( SELECT DISTINCT t1.mm_curr_mbi_id FROM dc_bene_alignment_rostr_m01 t1 WHERE t1.cc_version=m_roster_version AND t1.dce_group_nr=qArg01 AND t1.prov_npi_nr=qArg02 AND t1.ALIGN_STATUS_CODE IN ('AL','D1Y') AND t1.mm_date=mvStartdate));

 SET mRiskScore=(SELECT SUM(norm_risk_score) FROM mra_risk_score_report WHERE clndr_yr=qArg03 AND clndr_mo=qArg04 AND bene_mbi IN (SELECT DISTINCT t1.mm_curr_mbi_id FROM dc_bene_alignment_rostr_m01 t1 WHERE t1.cc_version=m_roster_version AND t1.dce_group_nr=qArg01 AND t1.prov_npi_nr=qArg02 AND t1.ALIGN_STATUS_CODE IN ('AL','D1Y') AND t1.mm_date=mvStartdate) ORDER BY clndr_mo DESC);  
 IF mRiskScore IS NULL THEN  SET mRiskScore= 0; END IF;

 SET m72HourFollowUp=(SELECT COUNT(e.entry_nr) FROM mra1_encounter e WHERE e.proc_type_nr IN (1,2) AND e.pt_aligned_status=1 AND e.enc_class_nr=9 AND e.is_72_hr_flwup=1 AND e.pt_facility_nr=qArg01 AND e.pt_provider_num=qArg02 AND e.enc_disch_date BETWEEN mvStartdate AND mvEnddate);
 SET m72HourFlwUpDem=(SELECT COUNT(e.entry_nr) FROM mra1_encounter e INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=e.encounter_nr WHERE e.proc_type_nr=1 AND e.pt_aligned_status=1 AND ((CLM_LINE_PROD_REV_CTR_CD IN ('0450','0451','0452','0453','0454','0455','0456','0457','0458','0459','0981') AND DATEDIFF(e.enc_disch_date,e.enc_admit_date) <= 2) OR e.enc_pos IN (60,61)) AND e.pt_facility_nr=qArg01 AND e.pt_provider_num=qArg02 AND e.enc_disch_date BETWEEN mvStartdate AND mvEnddate);

 SET mAvgVisitPerYear=(SELECT COUNT(e.entry_nr) FROM mra1_encounter e WHERE e.proc_type_nr IN (1,2) AND e.is_offvisit_rec=1 AND e.pt_facility_nr=qArg01 AND e.pt_provider_num=qArg02 AND e.enc_disch_date BETWEEN mvStartdate AND mvEnddate);

 SET mAlertAll=(SELECT COUNT(t1.origid) AS mAMT FROM mra_qpi_result t1  WHERE t1.group_id=qArg01 AND t1.provider_npi=qArg02 AND t1.year=qArg03 AND t1.month=qArg04 AND measure_id=1002 AND is_denom=1);

 SET mAlertCleared=(SELECT COUNT(t1.origid) AS mAMT FROM mra_qpi_result t1  WHERE t1.group_id=qArg01 AND t1.provider_npi=qArg02 AND t1.year=qArg03 AND t1.month=qArg04 AND measure_id=1002 AND is_numerator=1);

 SET vtmp=(SELECT GROUP_CONCAT(DISTINCT t1.patient_id) FROM mra1_encounter t1 WHERE t1.proc_type_nr=2 AND t1.is_offvisit_rec=1 AND t1.enc_disch_date BETWEEN mvStartdate - INTERVAL 90 DAY AND mvStartdate AND t1.pt_facility_nr=qArg01 AND t1.pt_provider_num=qArg02);
 SET vtmp=(SELECT GROUP_CONCAT(DISTINCT dc.mm_curr_mbi_id) FROM dc_bene_alignment_rostr_m01 dc WHERE dc.cc_version=m_roster_version AND dc.ALIGN_STATUS_CODE IN ('AL','D1Y') AND dc.dce_group_nr=qArg01 AND dc.prov_npi_nr=qArg02 AND dc.mm_date=mvStartdate AND NOT FIND_IN_SET(dc.mm_curr_mbi_id,vtmp));
 SET m90DayNotSeen=(SELECT COUNT(DISTINCT pt.origid) FROM patient AS pt INNER JOIN dc_bene_alignment_rostr_m01 dc ON pt.origid=dc.mm_curr_mbi_id WHERE dc.cc_version=m_roster_version AND dc.ALIGN_STATUS_CODE IN ('AL','D1Y') AND dc.dce_group_nr=qArg01 AND dc.prov_npi_nr=qArg02 AND dc.mm_date=mvStartdate AND FIND_IN_SET(pt.origid,vtmp));

 SET mTotalAvgVisitHccPerYear=(SELECT COUNT(e.entry_nr) FROM mra1_encounter e WHERE e.proc_type_nr IN (1,2) AND e.pt_aligned_status=1 AND e.hcc_score>0 AND e.pt_facility_nr=qArg01 AND e.pt_provider_num=qArg02 AND e.enc_disch_date BETWEEN mvStartdate AND mvEnddate);
 SET mAvgVisitHccPerYear=(SELECT SUM(e.hcc_score) FROM mra1_encounter e WHERE e.proc_type_nr IN (1,2) AND e.pt_aligned_status=1 AND e.hcc_score>0 AND e.pt_facility_nr=qArg01 AND e.pt_provider_num=qArg02 AND e.enc_disch_date BETWEEN mvStartdate AND mvEnddate);

 SET mCcVersion=(SELECT MAX(mm_imp_job_nr) FROM mra_file_static.mra_cclf8 LIMIT 1);
 SET mCcVersion=CONCAT(DATE_FORMAT(NOW(),"%Y%m"),'_',m_roster_version,'_',mCcVersion);

 SET vtmp=(SELECT t2.`name` FROM personell t2 WHERE t2.npr_id=qArg02 AND t2.is_dce=1 LIMIT 1);

 INSERT IGNORE INTO mra3_performance_provider_ranking_rpt SET cc_version=mCcVersion,m_provider_name=vtmp, m_market_nr=m1MarketNr, m_facility_nr=qArg01,m_facility_sub_nr=qArg05, m_provider_num=qArg02, m_mos=mvStartdate, m_mbrs=m1MemberCnt, m_part_A_amt=m1PartA_Amt, m_part_B_amt=m1PartB_Amt, m_part_C_amt=m1PartC_Amt, m_total_paid_expense=m1TotPaidExpAmt
,m_risk_score=mRiskScore,m_90_day_not_seen=m90DayNotSeen,m_los=mLos,m_discharge_cnt=mDischargeCnt,m_readmit=mReAdmit,m_ER_per_1000=mER_per1000,m_case_management=mCaseMngmnt,m_hei_completed=mHeiCompleted,m_average_visit_per_year=mAvgVisitPerYear,m_average_hcc_per_score=mAvgVisitHccPerYear,m_average_hcc_per_mtotal=mTotalAvgVisitHccPerYear,m_72_hour_followup=m72HourFollowUp,m_72_hour_flwup_dem=m72HourFlwUpDem,m_apt=mAdmitPer1000,m_alert_all=mAlertAll,m_alert_cleared=mAlertCleared,mcreate_id='admin',mcreate_datetime=NOW();

  INSERT INTO mra_00_tmp SET mdd_1="mra3_performance_provider_ranking_rpt",mdd_2=qArg03,mdd_3=qArg04;

 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_A02_No_X_Visit_11_z` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_A02_No_X_Visit_11_z`()
BEGIN

 DECLARE mmi INT; DECLARE mv01 VARCHAR(30); DECLARE mv02 VARCHAR(30);
 DECLARE mv03 VARCHAR(30); 

 TRUNCATE mra_00_tmp; TRUNCATE mra3_bene_no_visit_x_month;
 SET SESSION group_concat_max_len = 1000000;

 set mv01=(SELECT MAX(cc_version) AS cc_version FROM dc_bene_alignment_roster);
 SET mv02=DATE_FORMAT(NOW(),'%Y-%m-01');
 CALL MRA_IMP_A02_No_X_Visit_12_z(mv01,mv02);
 CALL MRA_IMP_A02_No_X_Visit_12_z(mv01,'2024-01-01');

 SET mv03=(SELECT MAX(cc_version) AS cc_version FROM dc_bene_alignment_roster WHERE mm_year=2023);
 SET mv02='2023-10-01'; SET mmi = 1;
 LOOP_M01:  LOOP
  IF mmi >4 THEN LEAVE LOOP_M01; END IF;
  IF mmi >1 THEN set mv02= mv02 + INTERVAL -3 month; END IF;

  CALL MRA_IMP_A02_No_X_Visit_12_z(mv03,mv02);
  CALL MRA_IMP_A02_No_X_Visit_12_z(mv01,mv02);
  SET mmi = mmi + 1; ITERATE LOOP_M01;
 END LOOP;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_A02_No_X_Visit_12_z` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_A02_No_X_Visit_12_z`(mpp1 INT,mpp2 VARCHAR(30))
BEGIN

DECLARE bmc INT DEFAULT 0; DECLARE mmi INT;
DECLARE v1tmp VARCHAR(10); DECLARE v2tmp INT; DECLARE v3tmp LONGTEXT;
DECLARE v1_01_tmp INT;DECLARE v1_02_tmp INT;DECLARE v1_03_tmp INT;
DECLARE v1_04_tmp INT;DECLARE v1_05_tmp INT;DECLARE v1_06_tmp INT;

DECLARE vRosterDate VARCHAR(50);
DECLARE vDceGroupNr VARCHAR(50); DECLARE vCurrentDate VARCHAR(50); DECLARE vm_days INT;

DECLARE qArg00 BIGINT; DECLARE qArg01 VARCHAR(100); DECLARE qArg02 VARCHAR(100); DECLARE qArg03 VARCHAR(100); DECLARE qArg06 VARCHAR(30);DECLARE qArg07 VARCHAR(30);DECLARE qArg08 VARCHAR(30);DECLARE qArg09 VARCHAR(100);DECLARE qArg10 VARCHAR(100);DECLARE qArg11 VARCHAR(100);

DECLARE mrw CURSOR FOR SELECT nr,cc_version,dce_group_nr,`market_id`,`prov_npi_nr`,`dce_sub_group_nr`,`dce_group_name`,`dce_provider_name`,`dce_sub_group_name` FROM dc_bene_alignment_rostr_m01 WHERE cc_version=mpp1 AND dce_group_nr>0 GROUP BY dce_group_nr,prov_npi_nr ORDER BY dce_group_nr,prov_npi_nr;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_31_tmp;TRUNCATE mra_32_tmp;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,vDceGroupNr,qArg06,qArg07,qArg08,qArg09,qArg10,qArg11;
 IF bmc = 0 THEN

 SET vCurrentDate=mpp2; SET qArg02=YEAR(mpp2); SET qArg03=MONTH(mpp2);
 SET vRosterDate=(SELECT MAX(mm_date) AS mm_date FROM dc_bene_alignment_rostr_m01 WHERE cc_version=mpp1);

 SET v1tmp = (SELECT 1 FROM mra_32_tmp e WHERE mdd_1='01_02' AND mdd_2=vDceGroupNr LIMIT 1);
 IF v1tmp IS NULL THEN
  INSERT INTO mra_31_tmp (mdd_1,mdd_2,mdd_3) SELECT 'cql_01_mm',vDceGroupNr,t1.patient_id FROM mra1_encounter t1 WHERE t1.proc_type_nr IN (1,2) AND t1.is_offvisit_rec=1 AND t1.pt_facility_nr=vDceGroupNr GROUP BY t1.patient_id;
  INSERT INTO mra_32_tmp SET create_datetime=NOW(),mdd_1='01_01',mdd_2=vDceGroupNr;
  SET v3tmp=(SELECT GROUP_CONCAT(mdd_3) FROM mra_31_tmp WHERE mdd_1='cql_01_mm' AND mdd_2=vDceGroupNr);
  INSERT INTO mra_31_tmp (mdd_1,mdd_2,mdd_3) SELECT 'cql_02_mm',vDceGroupNr,dc.mm_curr_mbi_id FROM dc_bene_alignment_rostr_m01 dc WHERE dc.cc_version=qArg01 AND mm_date=vRosterDate AND dc.ALIGN_STATUS_CODE IN ('AL','D1Y') AND dc.dce_group_nr=vDceGroupNr AND NOT FIND_IN_SET(dc.mm_curr_mbi_id,v3tmp) GROUP BY dc.mm_curr_mbi_id;
  INSERT INTO mra_32_tmp SET create_datetime=NOW(),mdd_1='01_02',mdd_2=vDceGroupNr;
 END IF;

 SET v1_01_tmp=(SELECT COUNT(DISTINCT pt.origid) FROM patient AS pt INNER JOIN dc_bene_alignment_rostr_m01 dc ON pt.origid=dc.mm_curr_mbi_id INNER JOIN mra_31_tmp t3 ON t3.mdd_1='cql_02_mm' AND t3.mdd_2=vDceGroupNr AND t3.mdd_3=pt.origid WHERE dc.cc_version=qArg01 AND mm_date=vRosterDate AND dc.ALIGN_STATUS_CODE IN ('AL','D1Y') AND dc.dce_group_nr=vDceGroupNr AND dc.prov_npi_nr=qArg07);
 INSERT INTO mra_32_tmp SET create_datetime=NOW(),mdd_1='01_03',mdd_2=vDceGroupNr;

 SET mmi = 2; SET vm_days=30;
 LOOP_M01:  LOOP

  IF  mmi > 6 THEN LEAVE LOOP_M01; END IF;

  SET v1tmp = (SELECT 1 FROM mra_32_tmp e WHERE mdd_1='02_02' AND mdd_2=vDceGroupNr AND mdd_3=vm_days LIMIT 1);
  IF v1tmp IS NULL THEN
   INSERT INTO mra_31_tmp (mdd_1,mdd_2,mdd_3,mdd_4) SELECT 'cql_11_mm',vDceGroupNr,t1.patient_id,vm_days FROM mra1_encounter t1 WHERE t1.proc_type_nr IN (1,2) AND t1.is_offvisit_rec=1 AND t1.enc_admit_date BETWEEN vCurrentDate - INTERVAL vm_days DAY AND vCurrentDate AND t1.pt_facility_nr=vDceGroupNr GROUP BY t1.patient_id;
   INSERT INTO mra_32_tmp SET create_datetime=NOW(),mdd_1='02_01',mdd_2=vDceGroupNr,mdd_3=vm_days;

   SET v3tmp=(SELECT GROUP_CONCAT(mdd_3) FROM mra_31_tmp WHERE mdd_1='cql_11_mm' AND mdd_2=vDceGroupNr AND mdd_4=vm_days);
   INSERT INTO mra_31_tmp (mdd_1,mdd_2,mdd_3,mdd_4) SELECT 'cql_12_mm',vDceGroupNr,dc.mm_curr_mbi_id,vm_days FROM dc_bene_alignment_rostr_m01 dc WHERE dc.cc_version=qArg01 AND mm_date=vRosterDate AND dc.ALIGN_STATUS_CODE IN ('AL','D1Y') AND dc.dce_group_nr=vDceGroupNr AND NOT FIND_IN_SET(dc.mm_curr_mbi_id,v3tmp) GROUP BY dc.mm_curr_mbi_id;
   INSERT INTO mra_32_tmp SET create_datetime=NOW(),mdd_1='02_02',mdd_2=vDceGroupNr,mdd_3=vm_days;
  END IF;

  SET v2tmp=(SELECT COUNT(DISTINCT pt.origid) FROM patient AS pt INNER JOIN dc_bene_alignment_rostr_m01 dc ON pt.origid=dc.mm_curr_mbi_id INNER JOIN mra_31_tmp t3 ON t3.mdd_1='cql_12_mm' AND t3.mdd_2=vDceGroupNr AND t3.mdd_4=vm_days AND t3.mdd_3=pt.origid WHERE dc.cc_version=qArg01 AND mm_date=vRosterDate AND dc.ALIGN_STATUS_CODE IN ('AL','D1Y') AND dc.dce_group_nr=vDceGroupNr AND dc.prov_npi_nr=qArg07);
  INSERT INTO mra_32_tmp SET create_datetime=NOW(),mdd_1='02_03',mdd_2=vDceGroupNr,mdd_3=vm_days,mdd_4=qArg07;

  IF mmi=2 THEN SET v1_02_tmp=v2tmp; SET vm_days=60;
  ELSEIF mmi=3 THEN SET v1_03_tmp=v2tmp; SET vm_days=90; ELSEIF mmi=4 THEN SET v1_04_tmp=v2tmp; SET vm_days=180;
  ELSEIF mmi=5 THEN SET v1_05_tmp=v2tmp; SET vm_days=360; ELSEIF mmi=6 THEN SET v1_06_tmp=v2tmp;
  END IF;

  SET  mmi = mmi + 1;
  ITERATE  LOOP_M01;
 END LOOP;


 INSERT IGNORE INTO mra3_bene_no_visit_x_month SET created_date=NOW(),cc_version=qArg01,mm_year=qArg02,mm_month=qArg03,
cc_as_of_date=mpp2,
Last_01_PCP_Visit_Count=v1_01_tmp,Last_04_PCP_Visit_Count=v1_04_tmp,
Last_02_PCP_Visit_Count=v1_02_tmp,Last_05_PCP_Visit_Count=v1_05_tmp,
Last_03_PCP_Visit_Count=v1_03_tmp,Last_06_PCP_Visit_Count=v1_06_tmp,
`dce_group_nr`=vDceGroupNr,`market_id`=qArg06,`prov_npi_nr`=qArg07,`dce_sub_group_nr`=qArg08,`dce_group_name`=qArg09,`dce_provider_name`=qArg10,`dce_sub_group_name`=qArg11;

 INSERT INTO mra_00_tmp SET mdd_1="MRA_A02_No_X_Visit_12_z",mdd_2=mpp2,mdd_3=vDceGroupNr,mdd_4=qArg07;

 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_A03_31Transfer_Flag_z` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_A03_31Transfer_Flag_z`(mpp1 INT, mpp2 varchar(30))
BEGIN
DECLARE vtmp VARCHAR(900); 
DECLARE mv1tmp VARCHAR(20); DECLARE mv2tmp VARCHAR(30);
DECLARE mv3tmp TEXT;

DECLARE bmc INT DEFAULT 0;

DECLARE qArg00 BIGINT;DECLARE qArg01 BIGINT;DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);

DECLARE mrw CURSOR FOR 
SELECT entry_nr,pt_facility_nr,patient_id,enc_admit_date,enc_disch_date FROM mra1_encounter WHERE proc_type_nr=1 and enc_proc_type=mpp2 AND YEAR(enc_disch_date)>=mpp1 ORDER BY entry_nr;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg2,qArg3,qArg4;
 IF bmc = 0 THEN

 INSERT INTO mra_00_tmp SET mdd_1="MRAA03_31Transfer_Flag_Marked_z",mdd_2=qArg00,mdd_3=qArg01,mdd_4=qArg2;

 SET vtmp=(SELECT encounter_nr FROM mra1_encounter WHERE proc_type_nr=1 AND pt_facility_nr=qArg01 AND patient_id=qArg2 AND enc_proc_type=mpp2 AND enc_admit_date=qArg4 AND entry_nr<>qArg00 LIMIT 1);
 IF vtmp IS NULL THEN
 
  SET mv1tmp=qArg3;SET mv2tmp=qArg00; SET mv3tmp='0;;';
  LOOP_M01: LOOP
   SET vtmp=(SELECT CONCAT(enc_admit_date,';;',entry_nr) FROM mra1_encounter WHERE proc_type_nr=1 AND pt_facility_nr=qArg01 AND patient_id=qArg2 AND enc_proc_type=mpp2 AND entry_nr<>mv2tmp AND mv1tmp=enc_disch_date LIMIT 1);
   IF vtmp IS NULL THEN
    LEAVE LOOP_M01;
   ELSEIF vtmp IS NOT NULL THEN
    SET mv1tmp=SUBSTRING_INDEX(vtmp,';;',1);SET mv2tmp=SUBSTRING_INDEX(vtmp,';;',-1);
    IF LOCATE(CONCAT(';;',mv2tmp,';;'),mv3tmp)>0 THEN
     LEAVE LOOP_M01;
    END IF;
    SET mv3tmp=CONCAT(mv3tmp,mv2tmp,';;');
   END IF;
   
  ITERATE LOOP_M01;
  END LOOP;
  
  UPDATE mra1_encounter SET is_enc_transfer=0,is_enc_ref_admitdate=mv1tmp WHERE pt_facility_nr=qArg01 AND entry_nr=qArg00;

 END IF; 

 END IF;
END LOOP;
CLOSE mrw;


END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_A03_32ReAdmit_Flag21_z1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_A03_32ReAdmit_Flag21_z1`(mpp1 INT,mpp2 VARCHAR(30))
BEGIN

DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 BIGINT;DECLARE qArg02 BIGINT;DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(100);DECLARE qArg06 VARCHAR(100);DECLARE qArg07 VARCHAR(100);DECLARE qArg08 VARCHAR(20);

DECLARE mrw CURSOR FOR 
SELECT entry_nr,pt_facility_nr,pt_facility_sub_nr,pt_provider_num,YEAR(is_enc_ref_admitdate) AS `year`,MONTH(`is_enc_ref_admitdate`) AS `month`,enc_pos,is_enc_ref_admitdate AS mdate,LAST_DAY(is_enc_ref_admitdate) as m2date FROM mra1_encounter WHERE proc_type_nr=1 AND is_enc_transfer=0 AND enc_proc_type=mpp2 AND YEAR(is_enc_ref_admitdate)>=mpp1 GROUP BY pt_facility_nr,pt_provider_num,`year`,`month`,enc_pos ORDER BY pt_facility_nr,pt_facility_sub_nr,pt_provider_num,`year`,`month`,enc_pos;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
IF bmc = 1 THEN LEAVE read_loop; END IF;
FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05,qArg06,qArg07,qArg08;
IF bmc = 0 THEN

 INSERT INTO mra_00_tmp SET mdd_1="MRAA03_32ReAdmit_Flag_z",mdd_2=qArg00,mdd_3=qArg01;
 
