/* Procedure structure for procedure `MRA_IMP_A03_72HrFlowUp_Set_z` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_A03_72HrFlowUp_Set_z`(mpp1 INT)
BEGIN

DECLARE m1vc TINYINT;DECLARE cv1flag TINYINT;DECLARE cv2flag TINYINT;DECLARE cv3flag TINYINT;DECLARE cv4flag TINYINT;

DECLARE vtmp VARCHAR(100); DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT; DECLARE qArg01 VARCHAR(100); DECLARE qArg02 VARCHAR(20); DECLARE qArg03 INT;

DECLARE mrw CURSOR FOR SELECT e.entry_nr,e.patient_id,e.enc_disch_date,e.pt_facility_nr FROM mra1_encounter e WHERE e.proc_type_nr=1 AND e.m_flwup_flag=1 AND YEAR(e.enc_disch_date)>=mpp1 ORDER BY e.entry_nr;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03;
 IF bmc = 0 THEN

  INSERT INTO mra_00_tmp SET mdd_1="MRA_A03_72HrFlowUp_Set_z",mdd_2=qArg00,mdd_3=1; 

  SET vtmp = (SELECT e.enc_admit_date FROM mra1_encounter e WHERE e.proc_type_nr IN (1,2) AND e.is_offvisit_rec=1 AND e.patient_id=qArg01 AND e.enc_admit_date>=qArg02 ORDER BY e.enc_admit_date LIMIT 1);
  IF vtmp IS NOT NULL THEN
   SET cv1flag=0;SET cv2flag=0;SET cv3flag=0;SET cv4flag=0;
   SET m1vc=MRA_A31_Get72HrFlowUpDays_m1(vtmp,qArg02);

   IF m1vc BETWEEN 0 AND 3 THEN  SET cv1flag=1; SET cv2flag=1; SET cv3flag=1; 
   ELSEIF m1vc BETWEEN 4 AND 7 THEN  SET cv2flag=1; SET cv3flag=1;
   ELSEIF m1vc BETWEEN 8 AND 14 THEN  SET cv3flag=1; END IF;

   IF m1vc >= 0 THEN SET cv4flag=1; END IF;

   UPDATE mra1_encounter SET is_72_hr_flwup=cv1flag,is_flwup_7_days=cv2flag,is_flwup_14_days=cv3flag,is_gflwup_14_days=cv4flag,m72hr_flwup_date=vtmp WHERE pt_facility_nr=qArg03 AND entry_nr=qArg00;
  END IF;

 END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

