  SET vtmp = (SELECT e.enc_admit_date FROM mra1_encounter e WHERE e.proc_type_nr IN (1,2) AND (e.is_offvisit_rec=1 OR e.is_offvisit2rec=1) AND e.patient_id=qArg01 AND e.enc_admit_date>=qArg02 ORDER BY e.enc_admit_date LIMIT 1);
