/*!50003 CREATE PROCEDURE `MRA_IMP_A03_ErVisit_Set_z`(mpp1 INT)
BEGIN

DECLARE bmc INT DEFAULT 0;
DECLARE qArg01 VARCHAR(100);DECLARE qArg02 bigint;

DECLARE mrw CURSOR FOR SELECT e.pt_facility_nr,e.encounter_nr FROM mra1_encounter e INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=e.encounter_nr WHERE e.proc_type_nr=1 AND enc_chk1_pos IN ('00','10','40','50') AND ( (CLM_LINE_PROD_REV_CTR_CD IN ('0450','0451','0452','0453','0454','0455','0456','0457','0458','0459','0981') or t2.bb_Code IN ('99281','99282','99283','99284','99285') ) AND DATEDIFF(e.enc_disch_date,e.enc_admit_date) <= 2) AND YEAR(e.enc_disch_date)>=mpp1;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;
INSERT INTO mra_00_tmp SET mdd_1="MRA_A03_ErVisit_Set_z",mdd_2='##START##',mdd_3=1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01,qArg02;
 IF bmc = 0 THEN
  UPDATE mra1_encounter SET is_er_visit=1,enc_proc_type='Emergency' WHERE pt_facility_nr=qArg01 AND encounter_nr=qArg02;
  INSERT INTO mra_00_tmp SET mdd_1="MRA_A03_ErVisit_Set_z",mdd_2=qArg02,mdd_3=1;
 END IF;
END LOOP;
CLOSE mrw;

END */$$
