/* Procedure structure for procedure `MRA_IMP_A03_SNF_Marked_z` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_A03_SNF_Marked_z`(mpp1 INT)
BEGIN
DECLARE vtmp VARCHAR(900); 
DECLARE mv1tmp VARCHAR(20); DECLARE mv2tmp VARCHAR(30);
DECLARE mv3tmp text;

DECLARE bmc INT DEFAULT 0;

DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);

DECLARE mrw CURSOR FOR 
SELECT entry_nr,pt_facility_nr,patient_id,enc_admit_date,enc_disch_date FROM mra1_encounter WHERE proc_type_nr=1 AND is_snf_rec=0 AND YEAR(enc_disch_date)>=mpp1 AND enc_pos IN (20,30) ORDER BY entry_nr; 

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

truncate mra_00_tmp;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg2,qArg3,qArg4;
 IF bmc = 0 THEN

 INSERT INTO mra_00_tmp SET mdd_1="MRA_A03_SNF_Marked_z",mdd_2=qArg00,mdd_3=qArg01,mdd_4=qArg2;

 SET vtmp=(SELECT encounter_nr FROM mra1_encounter WHERE proc_type_nr=1 AND pt_facility_nr=qArg01 AND patient_id=qArg2 AND enc_pos IN (20,30) AND DATEDIFF(enc_admit_date,qArg4) IN (0,1) LIMIT 1);
 IF vtmp IS NULL THEN

  SET mv1tmp=qArg3;SET mv2tmp=qArg00; set mv3tmp='0;;';
  LOOP_M01: LOOP
   SET vtmp=(SELECT CONCAT(enc_admit_date,';;',entry_nr) FROM mra1_encounter WHERE proc_type_nr=1 AND pt_facility_nr=qArg01 AND patient_id=qArg2 AND enc_pos IN (20,30) AND entry_nr<>mv2tmp AND DATEDIFF(mv1tmp,enc_disch_date) IN (0,1) LIMIT 1);
   IF vtmp IS NULL THEN
    LEAVE LOOP_M01;
   ELSEIF vtmp IS NOT NULL THEN
    SET mv1tmp=SUBSTRING_INDEX(vtmp,';;',1);SET mv2tmp=SUBSTRING_INDEX(vtmp,';;',-1);
    if LOCATE(CONCAT(';;',mv2tmp,';;'),mv3tmp)>0 then
     LEAVE LOOP_M01;
    end if;
    set mv3tmp=concat(mv3tmp,mv2tmp,';;');
   END IF;
   
  ITERATE LOOP_M01;
  END LOOP;
  
  UPDATE mra1_encounter SET is_snf_rec=1,is_snf_admitdate_ref=mv1tmp WHERE pt_facility_nr=qArg01 AND entry_nr=qArg00;
 END IF; 

 END IF;
END LOOP;
CLOSE mrw;

END */$$
