DECLARE mrw CURSOR FOR SELECT t1.encounter_nr,t2.FAC_PRVDR_NPI_NUM FROM encounter t1 INNER JOIN mra_file_static.mra_cclf1 t2 ON t1.mra_clm_refer_num=t2.nr WHERE YEAR(t1.discharge_date)>=mpp1 AND t1.mra_proc_type_nr=1 AND t1.hospital_nr=32767;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
