 SET vtmp = (SELECT nr FROM hospital_centers WHERE nrp_id=qArg02 LIMIT 1);
 IF vtmp IS not NULL THEN
  update encounter SET hospital_nr=vtmp where encounter_nr=qArg01;
  SET m2i=m2i+1;
 END IF;
 INSERT INTO mra_00_tmp SET mdd_1="MRA_TT_C01_QueryToTempp",mdd_2=qArg02,mdd_3=CONCAT(m2i,'--',mi),mdd_4=0;
 set mi=mi+1;
 END IF;
