UPDATE encounter t1 INNER JOIN mra_file_static.mra_cclf1 t2 ON t1.mra_clm_refer_num=t2.nr 
 SET t1.FAC_PRVDR_NPI_NUM=t2.FAC_PRVDR_NPI_NUM
WHERE t1.mra_proc_type_nr=1 AND YEAR(t1.discharge_date)>=2023; 
UPDATE encounter t1 SET t1.hospital_nr= ( SELECT t3.nr FROM hospital_centers t3 WHERE t3.nrp_id=t1.FAC_PRVDR_NPI_NUM LIMIT 1)
WHERE t1.mra_proc_type_nr=1 AND YEAR(t1.discharge_date)>=2023;

UPDATE encounter_procedure t1 INNER JOIN encounter t2 ON t1.encounter_nr=t2.encounter_nr INNER JOIN hospital_centers t3 ON t3.nr=t2.hospital_nr SET t1.procedure_center=t3.name WHERE YEAR(t2.discharge_date)>=2023;
UPDATE mra1_encounter t2 INNER JOIN encounter t1 ON t1.encounter_nr=t2.encounter_nr SET t2.hospital_nr=t1.hospital_nr 
WHERE YEAR(t1.discharge_date)>=2023;


UPDATE mra1_encounter t1 INNER JOIN hospital_centers t2 ON t2.nr=t1.hospital_nr SET t1.hos_taxonomy01=t2.taxonomy_1,t1.hospital_name=t2.`name`,t1.hc_npi_nr=t2.nrp_id WHERE YEAR(t1.enc_disch_date)>=2023;
UPDATE mra1_encounter SET enc_proc_type='Acute Hospital' WHERE YEAR(enc_disch_date)>=2023 AND proc_type_nr=1 AND enc_pos IN (60,61) AND hos_taxonomy01 IN ('282N00000X','282NC0060X','282NR1301X','282NC2000X','284300000X');
*/

