/* Procedure structure for procedure `MRA_IMP_TDC_CA_m31` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CA_m31`()
BEGIN

 SET @m3tmp=1;
 
 ## cclf 1,2,3
 SET @mcvlf=(SELECT nr FROM `mra_file2static`.tmp_cclf1_lambda LIMIT 1);
 IF @mcvlf IS NOT NULL THEN 
  SET @m1tmp=(SELECT (MAX(nr)+1) AS cc FROM mra_file_static.mra_cclf1);
  SET @m2tmp=(SELECT MIN(nr) AS cc FROM `mra_file2static`.tmp_cclf1_lambda);
  IF @m1tmp<>@m2tmp THEN SET @m3tmp=4;
  ELSE 
   INSERT INTO `mra_file_static`.mra_cclf1 SELECT * FROM `mra_file2static`.tmp_cclf1_lambda;
   DELETE FROM `mra_file2static`.tmp_cclf1_lambda;
  END IF;
 END IF;
 SET @mcvlf=(SELECT nr FROM `mra_file2static`.tmp_cclf2_lambda LIMIT 1);
