/* Procedure structure for procedure `MRA_IMP_TDC_CLF_PA_C1_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CLF_PA_C1_01`(mpp1 INT)
BEGIN
DECLARE mmi INT; DECLARE MV1_1 INT;

SET mmi = 1;
SET MV1_1=(SELECT COUNT(nr) FROM mra_file_static.mra_cclf1 WHERE map_data_status=1 AND map_process_status=1);
SET MV1_1= CEIL(MV1_1/10000);

LOOP_M01:  LOOP
 CALL MRA_IMP_TDC_CLF_PA_C1_02(mmi,mpp1);
 IF  mmi >= MV1_1 THEN LEAVE  LOOP_M01;  END  IF;
 SET  mmi = mmi + 1;
 ITERATE  LOOP_M01;
END LOOP;
	
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_TDC_CLF_PA_C1_02` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CLF_PA_C1_02`(mpp1 INT,mpp2 INT)
BEGIN

DECLARE vtmp VARCHAR(999); DECLARE v1tmp INT; DECLARE mMBI_IDNEW VARCHAR(100);
DECLARE mv_proc_type_nr SMALLINT DEFAULT 1; DECLARE ms01vv VARCHAR(20); 
DECLARE procedure_type VARCHAR(50); DECLARE to_personell_name VARCHAR(100); DECLARE mproc_center VARCHAR(100); DECLARE vm_enc_nr BIGINT;
DECLARE mv_bill_id BIGINT; DECLARE to_personell_nr INT; DECLARE mHospNr INT;
DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);DECLARE qArg7 VARCHAR(100);DECLARE qArg8 VARCHAR(100);DECLARE qArg9 VARCHAR(100);DECLARE qArg10 VARCHAR(100);DECLARE qArg11 VARCHAR(100);DECLARE qArg12 VARCHAR(100);DECLARE qArg13 VARCHAR(100);DECLARE qArg14 VARCHAR(100);DECLARE qArg15 VARCHAR(999);DECLARE qArg16 VARCHAR(10);
DECLARE qArg17 VARCHAR(100);DECLARE qArg18 VARCHAR(100);DECLARE qArg19 VARCHAR(100);DECLARE qArg20 VARCHAR(100);DECLARE qArg21 VARCHAR(100); DECLARE qArg22 VARCHAR(30);DECLARE qArg23 VARCHAR(50);DECLARE qArg24 INT; DECLARE qMapDatSrc INT;DECLARE qArg26 VARCHAR(50);DECLARE qArg27 VARCHAR(100);DECLARE qArg28 VARCHAR(10);

DECLARE mrw CURSOR FOR SELECT nr,`CUR_CLM_UNIQ_ID`,`ATNDG_PRVDR_NPI_NUM`,`OPRTG_PRVDR_NPI_NUM`,`CLM_FROM_DT`,CONCAT(SUBSTR(`CLM_FROM_DT`,1,4),SUBSTR(`CLM_FROM_DT`,6,2),SUBSTR(`CLM_FROM_DT`,9,2)) AS encounter_date,`BENE_MBI_ID`,`FAC_PRVDR_NPI_NUM`,`CLM_THRU_DT`,`PRVDR_OSCAR_NUM`,`CLM_BILL_FAC_TYPE_CD`,`CLM_TYPE_CD`,`CLM_OP_SRVC_TYPE_CD`,`CLM_ADMSN_TYPE_CD`,`CLM_ADMSN_SRC_CD`,BENE_PTNT_STUS_CD,CLM_ADJSMT_TYPE_CD,CLM_BLG_PRVDR_OSCAR_NUM,CLM_BLG_PRVDR_NPI_NUM,CLM_OPRTG_PRVDR_NPI_NUM,CLM_ATNDG_PRVDR_NPI_NUM,CLM_OTHR_PRVDR_NPI_NUM,CLM_EFCTV_DT,CLM_PMT_AMT,mm_imp_job_nr,map_data_src,CLM_CNTL_NUM,CLM_BILL_CLSFCTN_CD,CLM_MDCR_NPMT_RSN_CD FROM mra_file_static.mra_cclf1 WHERE map_data_status=1 AND map_process_status=1 ORDER BY CLM_EFCTV_DT, CUR_CLM_UNIQ_ID LIMIT 10000;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8,qArg9,qArg10,qArg11,qArg12,qArg13,qArg14,qArg15,qArg16,qArg17,qArg18,qArg19,qArg20,qArg21,qArg22,qArg23,qArg24,qMapDatSrc,qArg26,qArg27,qArg28;
 IF bmc = 0 THEN

  SET ms01vv = "mclf1_a";
  SET mMBI_IDNEW=MRA_FN01_GetPatientIDLastCCLF(qArg6);

  CALL MRA_IMP_FUNC_Hospital(qArg7);
  IF qArg2<>'~' THEN CALL MRA_IMP_FUNC_Personell(qArg2); END IF; 

  SET mHospNr=0; SET mproc_center=qArg7;
  SET vtmp = (SELECT nr FROM hospital_centers WHERE nrp_id=mproc_center LIMIT 1);
  IF vtmp IS NOT NULL THEN
   SET mHospNr=vtmp; SET mproc_center = (SELECT `name` FROM hospital_centers WHERE nr=mHospNr LIMIT 1);
  END IF;

  SET to_personell_nr=1; SET to_personell_name=''; IF qArg2<>'~' THEN SET to_personell_name=qArg2; END IF;
  SET vtmp = (SELECT nr FROM personell WHERE npr_id=to_personell_name LIMIT 1);
  IF vtmp IS NOT NULL THEN
   SET to_personell_nr=vtmp; SET to_personell_name = (SELECT `name` FROM personell WHERE nr=to_personell_nr LIMIT 1);
  END IF;

 SET @mfamount = (SELECT SUM(mm_famount) FROM mra_file_static.mra_cclf1 WHERE BENE_MBI_ID=qArg6 AND CLM_FROM_DT=qArg4 AND CLM_BLG_PRVDR_OSCAR_NUM=qArg17 AND CLM_TYPE_CD=qArg11 AND map_process2status=1);  

 SET vm_enc_nr = (SELECT encounter_nr FROM encounter WHERE origid=mMBI_IDNEW AND DATE_FORMAT(encounter_date,'%Y-%m-%d')=qArg4 AND CLM_BLG_PRVDR_OSCAR_NUM=qArg17 AND place_of_service=qArg11 AND mra_proc_type_nr=mv_proc_type_nr LIMIT 1); 
 IF vm_enc_nr IS NULL THEN
  UPDATE sequence_table_data SET sequence_id=sequence_id+1 WHERE sequence_name='encounter';
  SET vtmp = (SELECT sequence_id FROM sequence_table_data WHERE sequence_name='encounter'); 
  SET vm_enc_nr= CONCAT(qArg5,DATE_FORMAT(NOW(),'%s'),vtmp);
		
  SET procedure_type=qArg11;
  SET vtmp = (SELECT Option_Label FROM option_code_values WHERE Column_Order=1119 AND Option_Value=procedure_type LIMIT 1);
  IF vtmp IS NOT NULL THEN SET procedure_type=vtmp; END IF;
  IF qArg12<>"~" AND qArg12<>"" THEN
	IF qArg12=1 THEN SET procedure_type="Outpatient Emergent"; 
	ELSEIF qArg12=2 THEN SET procedure_type="Outpatient Urgent"; 
	ELSEIF qArg12=3 THEN SET procedure_type="Outpatient Elective";
	END IF;
  END IF;

  SET v1tmp=0; IF qArg16="1" THEN SET v1tmp=1; END IF;

  INSERT INTO encounter SET map_data_status=v1tmp,mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,create_id='mra_sch_import_claim',encounter_status='admitted',mra_proc_type_nr=mv_proc_type_nr,encounter_class_nr='9',is_discharged='0',report_status='1',mm_curr_mbi_id=qArg6,origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,hospital_nr=mHospNr,encounter_date=qArg5,discharge_date=qArg8,discharge_time="",encounter_type=procedure_type,place_of_service=qArg11,pos=qArg11,ATNDG_PRVDR_NPI_NUM=qArg2,PRVDR_OSCAR_NUM=qArg9,FAC_PRVDR_NPI_NUM=qArg7,CUR_CLM_UNIQ_ID=qArg01,CLM_EFCTV_DT=qArg22,CLM_CNTL_NUM=qArg26,CLM_ADJSMT_TYPE_CD=qArg16,mm_imp_job_nr=qArg24,CLM_BLG_PRVDR_OSCAR_NUM=qArg17,CLM_BLG_PRVDR_NPI_NUM=qArg18,CLM_BILL_FAC_TYPE_CD=qArg10,CLM_BILL_CLSFCTN_CD=qArg27,CLM_MDCR_NPMT_RSN_CD=qArg28,CLM_AMT_PD=@mfamount;
  INSERT INTO appointment SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,create_id='mra_sch_import_claim',origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,hospital_nr=mHospNr,`date`=qArg4,`language`='English Speaking',is_pre_schedule='0',`status`='closed',encounter_class_nr='9',appt_status='closed',to_dept_nr=14,TIME='08:00:00',to_personell_nr=to_personell_nr,to_personell_name=to_personell_name,`admitting_department`='Outpatient',CLM_TYPE_CD=qArg11,PRVDR_OSCAR_NUM=qArg9,CLM_BILL_FAC_TYPE_CD=qArg10,CLM_OP_SRVC_TYPE_CD=qArg12,CLM_ADMSN_TYPE_CD=qArg13,CLM_ADMSN_SRC_CD=qArg14;

  SET vtmp = (SELECT Option_Label FROM option_code_values WHERE Column_Order=86 AND Option_Value=qArg15 LIMIT 1);
  IF vtmp IS NULL THEN SET vtmp=qArg15; END IF;
  INSERT IGNORE INTO procedure_discharge SET encounter_nr=vm_enc_nr,discharge_type=qArg15,discharge_date=qArg8,discharge_to=vtmp,discharge_loc=vtmp,discharge_comments=vtmp,created_by='mra_sch_import_claim',create_date=NOW();
  INSERT INTO encounter_procedure SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,comments='mra_sch_import_claim',encounter_nr=vm_enc_nr,procedure_type=procedure_type,procedure_date=qArg4,procedure_center=mproc_center,interventionalist=to_personell_name,prcedure_op_type=1;
  
  INSERT INTO study_report_billing SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,created_date=NOW(),created_by='mra_sch_import_claim',Patient_Id=mMBI_IDNEW,encounter_nr=vm_enc_nr,Procedure_Type=procedure_type,CLM_ADJSMT_TYPE_CD=qArg16,CLM_BILL_FAC_TYPE_CD=qArg10,CLM_TYPE_CD=qArg11,CLM_OP_SRVC_TYPE_CD=qArg12,CLM_ADMSN_TYPE_CD=qArg13,CLM_ADMSN_SRC_CD=qArg14,CLM_AMT_PD=@mfamount;
  SET mv_bill_id=LAST_INSERT_ID();
 ELSE
  SET mv_bill_id = (SELECT Billing_ID FROM study_report_billing WHERE encounter_nr=vm_enc_nr LIMIT 1);

  UPDATE study_report_billing_codes SET cal_amount=0 WHERE Billing_Id=mv_bill_id;
  CALL MRA_IMP3_M01ENC_99_01(vm_enc_nr);

  SET v1tmp=0; IF qArg16="1" THEN SET v1tmp=1; END IF;

  UPDATE encounter SET map_data_status=v1tmp,mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,CUR_CLM_UNIQ_ID=qArg01,PRVDR_OSCAR_NUM=qArg9,FAC_PRVDR_NPI_NUM=qArg7,hospital_nr=mHospNr,discharge_date=qArg8,place_of_service=qArg11,pos=qArg11,ATNDG_PRVDR_NPI_NUM=qArg2,CLM_EFCTV_DT=qArg22,CLM_ADJSMT_TYPE_CD=qArg16,CLM_CNTL_NUM=qArg26,CLM_BLG_PRVDR_OSCAR_NUM=qArg17,CLM_BLG_PRVDR_NPI_NUM=qArg18,CLM_BILL_FAC_TYPE_CD=qArg10,CLM_BILL_CLSFCTN_CD=qArg27,CLM_MDCR_NPMT_RSN_CD=qArg28,CLM_AMT_PD=@mfamount,mm_imp_job_nr=qArg24 WHERE encounter_nr=vm_enc_nr;
 UPDATE appointment SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,create_id='mra_sch_import_claim',hospital_nr=mHospNr,to_personell_nr=to_personell_nr,to_personell_name=to_personell_name WHERE encounter_nr=vm_enc_nr;

 END IF; 
 
 IF (qArg11="60" OR qArg11="61" OR qArg11="20" OR qArg11="30") THEN
  SET vtmp = (SELECT t1.nr FROM mra_file_static.mra_cclf2 t1 INNER JOIN mra_file_static.mra_cclf1 t2 ON t2.CUR_CLM_UNIQ_ID=t1.CUR_CLM_UNIQ_ID WHERE t2.map_data_status=1 AND t2.map_process_status=1 AND t2.`BENE_MBI_ID`=qArg6 AND t2.`CLM_FROM_DT`=qArg4 AND t2.`CLM_BLG_PRVDR_OSCAR_NUM`=qArg17 AND t2.CUR_CLM_UNIQ_ID=qArg01 LIMIT 1);
  IF vtmp IS NULL THEN
   CALL MRA_IMP_TDC_CLF_PA_C1_31_5(ms01vv,mv_bill_id,qArg6,qArg4,qArg17,qArg00);
  ELSE
   CALL MRA_IMP_TDC_CLF_PA_C1_31_1(ms01vv,mv_bill_id,qArg6,qArg4,qArg17,qArg01);
  END IF; 
 ELSE 
  CALL MRA_IMP_TDC_CLF_PA_C1_31_1(ms01vv,mv_bill_id,qArg6,qArg4,qArg17,qArg01);
 END IF;
 
 CALL MRA_IMP_TDC_CLF_PA_C1_03(ms01vv,vm_enc_nr,qArg6,qArg4,qArg17,qArg01,mMBI_IDNEW); 

 CALL MRA_01_Cal_EncHccScore_11(vm_enc_nr);

 INSERT INTO mra1_encounter_logs SET mcreate_id='system',map_data_src=qMapDatSrc,encounter_nr=vm_enc_nr,patient_id=qArg6,proc_type_nr=mv_proc_type_nr,m_notes='',mSrcInserted_Type='mra_cclf1',mSrcInserted_ID=qArg00,mm_imp_job_nr=mpp2;

