 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg11,qArg12,qArg13,qArg14,qArg15,qArg16,qArg17,qArg18,qArg19,qArg20;
 IF bmc = 0 THEN 

 SET modifiers=REPLACE(qArg18,"~",","); SET modifiers=REPLACE(modifiers,",,",","); SET modifiers=REPLACE(modifiers,",,",","); SET modifiers=REPLACE(modifiers,",,",","); SET modifiers=REPLACE(modifiers,",,",","); SET modifiers=REPLACE(modifiers,",,",",");

 IF qArg19 <> "1" THEN
 
