   UPDATE study_report_billing_codes SET mra_clm_refer_num=qArg11,mra_clm_refer_m01=ms01vv,`modifier`=modifiers,cal_amount=qArg16,Billing_Code=qArg15,CLM_ADJSMT_TYPE_CD=qArg19,CLM_LINE_PROD_REV_CTR_CD=qArg20 WHERE ID=mvID;
  ELSE 
   INSERT IGNORE INTO study_report_billing_codes SET mra_clm_refer_num=qArg11,mra_clm_refer_m01=ms01vv,Billing_Id=mpp1,`count`='1',`modifier`=modifiers,Billing_Type='P',cpt_code_order_num=qArg14,cal_amount=qArg16,Billing_Code=qArg15,CLM_ADJSMT_TYPE_CD=qArg19,CLM_LINE_PROD_REV_CTR_CD=qArg20, CUR_CLM_UNIQ_ID=qArg13, CLM_LINE_NUM=qArg14;
