DECLARE mrw CURSOR FOR SELECT nr,`BENE_MBI_ID`,`CLM_FROM_DT`,IF (LENGTH(`PRNCPL_DGNS_CD`)>3,CONCAT(SUBSTR(`PRNCPL_DGNS_CD`,1,3),'.',SUBSTR(`PRNCPL_DGNS_CD`,4)),`PRNCPL_DGNS_CD`) AS `PRNCPL_DGNS_CD`,
IF (LENGTH(`ADMTG_DGNS_CD`)>3,CONCAT(SUBSTR(`ADMTG_DGNS_CD`,1,3),'.',SUBSTR(`ADMTG_DGNS_CD`,4)),`ADMTG_DGNS_CD`) AS `ADMTG_DGNS_CD`,CUR_CLM_UNIQ_ID FROM mra_file_static.mra_cclf1 WHERE `BENE_MBI_ID`=mpp2 AND `CLM_FROM_DT`=mpp3 AND CLM_BLG_PRVDR_OSCAR_NUM=mpp4 and CUR_CLM_UNIQ_ID=mpp5 AND map_data_status=1 AND map_process_status=1;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
