read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg0,qArg1,qArg2,qArg3,qArg4,qArg5; 
/* Principal -- Problems */
IF bmc = 0 AND qArg3<>"~" AND qArg3<>"" THEN
 SET prob_type="Principal";
 SET vm_probdesc = MRA_FN21_GetIcdDescription(qArg3);

 INSERT IGNORE INTO encounter_icd_codes SET mra_clm_refer_num=qArg0,mra_clm_refer_m01=ms01vv,patient_id=mpp6,`onset_date`=qArg2,diagnosis_type='Diagnosis',encounter_nr=mpp1, diagnosis_code=qArg3,`diagnosis_desc`=vm_probdesc,SNOMED_CID='',SNOMED_FSN='',`status`='Active',problem_type=prob_type,`created_by`='mra_sch_import_claim',`created_date`=NOW();
 END IF;
 
 /* Admitting -- Problems */
IF bmc = 0 AND qArg4<>"~" AND qArg4<>"" THEN
 SET prob_type="Admitting";
 SET vm_probdesc = MRA_FN21_GetIcdDescription(qArg4);

 INSERT IGNORE INTO encounter_icd_codes SET mra_clm_refer_num=qArg0,mra_clm_refer_m01=ms01vv,patient_id=mpp6,`onset_date`=qArg2,diagnosis_type='Diagnosis',encounter_nr=mpp1, diagnosis_code=qArg4,`diagnosis_desc`=vm_probdesc,SNOMED_CID='',SNOMED_FSN='',`status`='Active',problem_type=prob_type,`created_by`='mra_sch_import_claim',`created_date`=NOW();

 END IF;

 SET mm1=mm1+1;
 
END LOOP;
CLOSE mrw;
END */$$
