DECLARE mrw CURSOR FOR SELECT nr,`CUR_CLM_UNIQ_ID`,`BENE_MBI_ID`,`CLM_TYPE_CD`,`CLM_VAL_SQNC_NUM`,`CLM_PRCDR_CD`,`CLM_PRCDR_PRFRM_DT`,`CLM_FROM_DT`,`CLM_THRU_DT`,`DGNS_PRCDR_ICD_IND` FROM mra_file_static.mra_cclf3 WHERE `BENE_MBI_ID`=mpp2 AND `CLM_FROM_DT`=mpp3 AND CUR_CLM_UNIQ_ID=mpp5 and map_data_status=0;
