 END IF;

 SET vm_probdesc = MRA_FN21_GetIcdDescription(qArg5);

 INSERT IGNORE INTO encounter_icd_codes SET mra_clm_refer_num=qArg0,mra_clm_refer_m01=ms01vv,icd_order=qArg4,patient_id=mpp6,`onset_date`=qArg6,diagnosis_type='Diagnosis',encounter_nr=mpp1, diagnosis_code=qArg5,`diagnosis_desc`=vm_probdesc,SNOMED_CID='',SNOMED_FSN='',`status`='Active',problem_type="",`created_by`='mra_sch_import_claim',`created_date`=NOW();
 
 END IF;
 SET mm1=mm1+1;
 
