  SET  mmi = mmi + 1;
  CALL MRA_IMP_TDC_CLF_PA_C1_91(mmi,qArg00);
  UPDATE mra_file_static.mra_cclf1 SET map_data_status=1 WHERE map_data_status=0 AND BENE_MBI_ID=qArg00 COLLATE latin1_swedish_ci;
  
 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

