DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100) CHARACTER SET latin1;
DECLARE qArg04 VARCHAR(100) CHARACTER SET latin1;
DECLARE m01Val INT;
