 IF bmc = 1 THEN LEAVE read_loop; END IF;
 
 FETCH mrw INTO qArg01,qArg02;
 IF bmc = 0 THEN
 
  SET mi=mi+1;
  UPDATE mra_file_static.mra_cclf1 SET map_process2status=0 WHERE CUR_CLM_UNIQ_ID=qArg01;
  UPDATE mra_file_static.mra_cclf1 SET map_process2status=1,map_process_status=1 WHERE CUR_CLM_UNIQ_ID=qArg01 COLLATE latin1_swedish_ci ORDER BY mm_imp_job_nr DESC LIMIT 1; # ,map_data_status=0
  INSERT INTO mra_00_tmp SET mdd_1="MCLF_A1_92_1",mdd_2=qArg01,mdd_3=mi;

 END IF;
