/* Procedure structure for procedure `MRA_IMP_TDC_CLF_PB_C5_02` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CLF_PB_C5_02`(mpp1 INT,mpp2 INT,mpp3 VARCHAR(100))
BEGIN

DECLARE vtmp VARCHAR(100); DECLARE v1tmp INT; DECLARE mMBI_IDNEW VARCHAR(100) CHARACTER SET latin1;
DECLARE mv_proc_type_nr SMALLINT DEFAULT 2; DECLARE ms01vv VARCHAR(20); 
DECLARE procedure_type VARCHAR(50); DECLARE m_personell_name VARCHAR(100) CHARACTER SET latin1; DECLARE vm_enc_nr BIGINT;
DECLARE mv_bill_id BIGINT; DECLARE to_personell_nr INT; DECLARE mHospNr BIGINT;
DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg2 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);DECLARE qArg7 VARCHAR(100);DECLARE qArg8 VARCHAR(100);DECLARE qArg9 VARCHAR(100);DECLARE qArg10 VARCHAR(100);DECLARE qArg11 VARCHAR(100);DECLARE qArg12 VARCHAR(100);DECLARE qArg13 VARCHAR(100);DECLARE qArg14 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg15 VARCHAR(100);DECLARE qArg16 VARCHAR(100); DECLARE qArg17 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg18 VARCHAR(100);DECLARE qArg19 VARCHAR(20);DECLARE qArg20 VARCHAR(100) CHARACTER SET latin1; DECLARE qArg21 INT;

DECLARE mrw CURSOR FOR SELECT `nr`,`CUR_CLM_UNIQ_ID`,`BENE_MBI_ID`,CLM_FED_TYPE_SRVC_CD,`CLM_TYPE_CD`,`CLM_FROM_DT`,`CLM_THRU_DT`,CONCAT(SUBSTR(`CLM_FROM_DT`,1,4),SUBSTR(`CLM_FROM_DT`,6,2),SUBSTR(`CLM_FROM_DT`,9,2)) AS encounter_date,`RNDRG_PRVDR_TYPE_CD`,`RNDRG_PRVDR_FIPS_ST_CD`,`CLM_PRVDR_SPCLTY_CD`,`CLM_POS_CD`,`CLM_LINE_PRMRY_PYR_CD`,`CLM_RNDRG_PRVDR_TAX_NUM`,`RNDRG_PRVDR_NPI_NUM`,CLM_ADJSMT_TYPE_CD,CLM_PRVDR_SPCLTY_CD,CLM_RNDRG_PRVDR_NPI_NUM,CLM_RFRG_PRVDR_NPI_NUM,CLM_EFCTV_DT,CLM_CNTL_NUM,mm_imp_job_nr FROM mra_file_static.mra_cclf5 WHERE map_data_status=1 AND map_process_status=1 AND CLM_CARR_PMT_DNL_CD != "0" AND BENE_MBI_ID=mpp3 GROUP BY CLM_FROM_DT,RNDRG_PRVDR_NPI_NUM,CLM_CNTL_NUM,CUR_CLM_UNIQ_ID ORDER BY CLM_EFCTV_DT,CUR_CLM_UNIQ_ID;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8,qArg9,qArg10,qArg11,qArg12,qArg13,qArg14,qArg15,qArg16,qArg17,qArg18,qArg19,qArg20,qArg21;
 IF bmc = 0 THEN
 
 SET mMBI_IDNEW=MRA_FN01_GetPatientIDLastCCLF(qArg2);

 SET ms01vv = "mclf5_b";
 IF qArg14<>'~' THEN CALL MRA_IMP_FUNC_Personell(qArg14); END IF;
 IF qArg17<>'~' THEN CALL MRA_IMP_FUNC_Personell(qArg17); END IF;

 SET mHospNr= -3;

 SET to_personell_nr=1; SET m_personell_name=qArg14;
 SET vtmp = (SELECT nr FROM personell WHERE npr_id=m_personell_name COLLATE latin1_swedish_ci LIMIT 1);
 IF vtmp IS NOT NULL THEN
  SET to_personell_nr=vtmp; SET m_personell_name = (SELECT `name` FROM personell WHERE nr=to_personell_nr LIMIT 1);
 END IF;

 SET vm_enc_nr = (SELECT encounter_nr FROM encounter WHERE origid=mMBI_IDNEW COLLATE latin1_swedish_ci AND DATE_FORMAT(encounter_date,'%Y-%m-%d')=qArg5 AND ATNDG_PRVDR_NPI_NUM=qArg14 COLLATE latin1_swedish_ci AND CLM_CNTL_NUM=qArg20 COLLATE latin1_swedish_ci AND mra_proc_type_nr=mv_proc_type_nr LIMIT 1); 

 IF vm_enc_nr IS NULL THEN
 UPDATE sequence_table_data SET sequence_id = sequence_id +1 WHERE sequence_name='encounter';
 SET vtmp = (SELECT sequence_id FROM sequence_table_data WHERE sequence_name='encounter'); 
 SET vm_enc_nr= CONCAT(qArg7,DATE_FORMAT(NOW(),'%s'),vtmp);  
 
 SET procedure_type=qArg11;
 SET vtmp = (SELECT Option_Label FROM option_code_values WHERE Column_Order=1120 AND Option_Value=procedure_type LIMIT 1);
 IF vtmp IS NOT NULL THEN SET procedure_type=vtmp; END IF;

 SET v1tmp=0; IF qArg15="1" THEN SET v1tmp=1; END IF; 

 INSERT INTO encounter SET map_data_status=v1tmp,mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,create_id='mra_sch_import_claim',encounter_status='admitted',mra_proc_type_nr=mv_proc_type_nr,encounter_class_nr='10',is_discharged='0',report_status='1',mm_curr_mbi_id=qArg2,origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,hospital_nr=mHospNr,encounter_date=qArg5,discharge_date=qArg6,discharge_time="",encounter_type=procedure_type,place_of_service=qArg11,pos=qArg11,CLM_PRVDR_SPCLTY_CD=qArg16,ATNDG_PRVDR_NPI_NUM=qArg14,CUR_CLM_UNIQ_ID=qArg01,CLM_EFCTV_DT=qArg19,CLM_ADJSMT_TYPE_CD=qArg15,CLM_CNTL_NUM=qArg20,RNDRG_PRVDR_TYPE_CD=qArg8,CLM_RNDRG_PRVDR_TAX_NUM=qArg13,CLM_RNDRG_PRVDR_NPI_NUM=qArg17,mm_imp_job_nr=qArg21;
  INSERT INTO appointment SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,create_id='mra_sch_import_claim',origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,hospital_nr=mHospNr,`date`=qArg5,`language`='English Speaking',is_pre_schedule='0',`status`='closed',encounter_class_nr='10',appt_status='closed',to_dept_nr=14,TIME='08:00:00',to_personell_nr=to_personell_nr,to_personell_name=m_personell_name,`admitting_department`='physician',CLM_TYPE_CD=qArg4,CLM_FED_TYPE_SRVC_CD=qArg3,CLM_POS_CD=qArg11,RNDRG_PRVDR_TYPE_CD=qArg8;
 INSERT INTO encounter_details SET origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,CLM_RNDRG_PRVDR_NPI_NUM=qArg17,CLM_RFRG_PRVDR_NPI_NUM=qArg18; 
 INSERT INTO encounter_procedure SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,comments='mra_sch_import_claim',encounter_nr=vm_enc_nr,procedure_type=procedure_type,procedure_date=qArg5,procedure_center="NA",interventionalist=m_personell_name,prcedure_op_type=1;
 INSERT INTO study_report_billing SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,created_date=NOW(),created_by='mra_sch_import_claim',Patient_Id=mMBI_IDNEW,encounter_nr=vm_enc_nr,Procedure_Type=procedure_type,CLM_ADJSMT_TYPE_CD=qArg15;
 SET mv_bill_id=LAST_INSERT_ID();
ELSE
  SET mv_bill_id = (SELECT Billing_ID FROM study_report_billing WHERE encounter_nr=vm_enc_nr LIMIT 1); 

  UPDATE study_report_billing_codes SET cal_amount=0 WHERE Billing_Id=mv_bill_id;
  DELETE FROM encounter_icd_codes WHERE encounter_nr=vm_enc_nr;
  CALL MRA_IMP3_M01ENC_99_01(vm_enc_nr);

  SET v1tmp=0; IF qArg15="1" THEN SET v1tmp=1; END IF;  

  UPDATE encounter SET map_data_status=v1tmp,mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,hospital_nr=mHospNr,discharge_date=qArg6,place_of_service=qArg11,pos=qArg11,CLM_PRVDR_SPCLTY_CD=qArg16,ATNDG_PRVDR_NPI_NUM=qArg14,CUR_CLM_UNIQ_ID=qArg01,CLM_EFCTV_DT=qArg19,CLM_ADJSMT_TYPE_CD=qArg15,CLM_CNTL_NUM=qArg20,RNDRG_PRVDR_TYPE_CD=qArg8,CLM_RNDRG_PRVDR_TAX_NUM=qArg13,CLM_RNDRG_PRVDR_NPI_NUM=qArg17,mm_imp_job_nr=qArg21 WHERE encounter_nr=vm_enc_nr;
  UPDATE appointment SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,hospital_nr=mHospNr,to_personell_nr=to_personell_nr,to_personell_name=m_personell_name,CLM_TYPE_CD=qArg4,CLM_FED_TYPE_SRVC_CD=qArg3,CLM_POS_CD=qArg11,RNDRG_PRVDR_TYPE_CD=qArg8 WHERE encounter_nr=vm_enc_nr;
END IF; 

 CALL MRA_IMP_TDC_CLF_PB_C5_31(ms01vv,mv_bill_id,qArg2,qArg5,qArg14,qArg20,qArg01);
 CALL MRA_IMP_TDC_CLF_PB_C5_32(ms01vv,vm_enc_nr,qArg2,qArg5,qArg14,qArg20,qArg01,mMBI_IDNEW);

 CALL MRA_01_Cal_EncHccScore_11(vm_enc_nr);

 UPDATE mra_file_static.mra_cclf5 SET map_data_status=2 WHERE map_data_status=1 AND BENE_MBI_ID=qArg2 COLLATE latin1_swedish_ci AND CLM_FROM_DT=qArg5 AND RNDRG_PRVDR_NPI_NUM=qArg14 COLLATE latin1_swedish_ci AND `CLM_CNTL_NUM`=qArg20 COLLATE latin1_swedish_ci AND CUR_CLM_UNIQ_ID=qArg01 COLLATE latin1_swedish_ci;

 INSERT INTO mra_00_tmp SET mdd_1="MCLF_5_Part_B",mdd_2=mpp1,mdd_3=qArg00;

 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_TDC_CLF_PB_C5_31` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CLF_PB_C5_31`(ms01vv VARCHAR(30), mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100), mpp6 VARCHAR(100))
BEGIN

DECLARE mvID BIGINT; DECLARE mm1 INT DEFAULT 1; DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg1 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(10);DECLARE qArg6 VARCHAR(100);DECLARE qArg7 VARCHAR(30);DECLARE qArg8 VARCHAR(30);

DECLARE mrw CURSOR FOR SELECT `nr`,`CLM_LINE_HCPCS_CD`,`CLM_FROM_DT`,`CLM_LINE_ALOWD_CHRG_AMT`,SUM(`CLM_LINE_CVRD_PD_AMT`),`CLM_ADJSMT_TYPE_CD`,CONCAT(`HCPCS_1_MDFR_CD`,',',`HCPCS_2_MDFR_CD`,',',`HCPCS_3_MDFR_CD`,',',`HCPCS_4_MDFR_CD`,',',`HCPCS_5_MDFR_CD`) AS modifiers,CLM_PRCSG_IND_CD,CLM_CARR_PMT_DNL_CD FROM mra_file_static.mra_cclf5 WHERE `BENE_MBI_ID`=mpp2 COLLATE latin1_swedish_ci AND `CLM_FROM_DT`=mpp3 AND `RNDRG_PRVDR_NPI_NUM`=mpp4 COLLATE latin1_swedish_ci AND `CLM_CNTL_NUM`=mpp5 COLLATE latin1_swedish_ci AND `CUR_CLM_UNIQ_ID`=mpp6 COLLATE latin1_swedish_ci AND map_data_status=1 AND map_process_status=1 GROUP BY CLM_LINE_HCPCS_CD;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg1,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8; 
 IF bmc = 0 THEN

  SET qArg6=REPLACE(qArg6,"~",",");SET qArg6=REPLACE(qArg6,",,",",");SET qArg6=REPLACE(qArg6,",,",",");
  SET qArg6=REPLACE(qArg6,",,",",");SET qArg6=REPLACE(qArg6,",,",",");

  SET mvID = (SELECT ID FROM study_report_billing_codes WHERE Billing_ID=mpp1 AND Billing_Code=qArg1 COLLATE latin1_swedish_ci LIMIT 1);
  IF mvID IS NOT NULL THEN
   UPDATE study_report_billing_codes SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,`MODIFIER`=qArg6,cpt_code_order_num=mm1,cal_amount=qArg4,CLM_ADJSMT_TYPE_CD=qArg5,CLM_PRCSG_IND_CD=qArg7,CLM_MDCR_NPMT_RSN_CD=qArg8 WHERE ID=mvID;
  ELSE
   INSERT IGNORE INTO study_report_billing_codes SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,Billing_Id=mpp1,COUNT='1',`MODIFIER`=qArg6,Billing_Type='P',cpt_code_order_num=mm1,cal_amount=qArg4,cal2amount=0,Billing_Code=qArg1,CLM_ADJSMT_TYPE_CD=qArg5,CLM_PRCSG_IND_CD=qArg7,CLM_MDCR_NPMT_RSN_CD=qArg8;
  END IF;

  SET mm1=mm1+1;

 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_TDC_CLF_PB_C5_32` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CLF_PB_C5_32`(ms01vv VARCHAR(30), mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100), mpp6 VARCHAR(100), mpp7 VARCHAR(100))
BEGIN

DECLARE vtmp VARCHAR(100); DECLARE modifiers VARCHAR(100);
DECLARE mm1 INT DEFAULT 1; DECLARE bmc INT DEFAULT 0;

DECLARE qArg0 BIGINT; DECLARE qArg1 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg2 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg3 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg4 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg5 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg6 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg7 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg8 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg9 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg10 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg11 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg12 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg13 VARCHAR(100) CHARACTER SET latin1;

DECLARE mrw CURSOR FOR SELECT nr,IF (LENGTH(`CLM_LINE_DGNS_CD`)>3,CONCAT(SUBSTR(`CLM_LINE_DGNS_CD`,1,3),'.',SUBSTR(`CLM_LINE_DGNS_CD`,4)),`CLM_LINE_DGNS_CD`) AS diag_code,IF (LENGTH(`CLM_DGNS_1_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_1_CD`,1,3),'.',SUBSTR(`CLM_DGNS_1_CD`,4)),`CLM_DGNS_1_CD`) AS diag_code1,IF (LENGTH(`CLM_DGNS_2_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_2_CD`,1,3),'.',SUBSTR(`CLM_DGNS_2_CD`,4)),`CLM_DGNS_2_CD`) AS diag_code2,IF (LENGTH(`CLM_DGNS_3_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_3_CD`,1,3),'.',SUBSTR(`CLM_DGNS_3_CD`,4)),`CLM_DGNS_3_CD`) AS diag_code3,IF (LENGTH(`CLM_DGNS_4_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_4_CD`,1,3),'.',SUBSTR(`CLM_DGNS_4_CD`,4)),`CLM_DGNS_4_CD`) AS diag_code4,IF (LENGTH(`CLM_DGNS_5_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_5_CD`,1,3),'.',SUBSTR(`CLM_DGNS_5_CD`,4)),`CLM_DGNS_5_CD`) AS diag_code5,IF (LENGTH(`CLM_DGNS_6_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_6_CD`,1,3),'.',SUBSTR(`CLM_DGNS_6_CD`,4)),`CLM_DGNS_6_CD`) AS diag_code6,IF (LENGTH(`CLM_DGNS_7_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_7_CD`,1,3),'.',SUBSTR(`CLM_DGNS_7_CD`,4)),`CLM_DGNS_7_CD`) AS diag_code7,IF (LENGTH(`CLM_DGNS_8_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_8_CD`,1,3),'.',SUBSTR(`CLM_DGNS_8_CD`,4)),`CLM_DGNS_8_CD`) AS diag_code8,IF (LENGTH(`CLM_DGNS_9_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_9_CD`,1,3),'.',SUBSTR(`CLM_DGNS_9_CD`,4)),`CLM_DGNS_9_CD`) AS diag_code9,IF (LENGTH(`CLM_DGNS_10_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_10_CD`,1,3),'.',SUBSTR(`CLM_DGNS_10_CD`,4)),`CLM_DGNS_10_CD`) AS diag_code10,IF (LENGTH(`CLM_DGNS_11_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_11_CD`,1,3),'.',SUBSTR(`CLM_DGNS_11_CD`,4)),`CLM_DGNS_11_CD`) AS diag_code11,IF (LENGTH(`CLM_DGNS_12_CD`)>3,CONCAT(SUBSTR(`CLM_DGNS_12_CD`,1,3),'.',SUBSTR(`CLM_DGNS_12_CD`,4)),`CLM_DGNS_12_CD`) AS diag_code12 FROM mra_file_static.mra_cclf5 WHERE `BENE_MBI_ID`=mpp2 COLLATE latin1_swedish_ci AND `RNDRG_PRVDR_NPI_NUM`=mpp4 COLLATE latin1_swedish_ci AND `CLM_CNTL_NUM`=mpp5 COLLATE latin1_swedish_ci AND `CUR_CLM_UNIQ_ID`=mpp6 COLLATE latin1_swedish_ci AND `CLM_FROM_DT`=mpp3 AND map_data_status=1 AND map_process_status=1 GROUP BY CLM_LINE_HCPCS_CD ORDER BY nr DESC LIMIT 1;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg0,qArg1,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8,qArg9,qArg10,qArg11,qArg12,qArg13; 
 IF bmc = 0 THEN

 CALL MRA_IMP_TDC_CLF_PB_C5_32_2(1,ms01vv,mpp1,qArg0,qArg1,mpp2,mpp7);
 CALL MRA_IMP_TDC_CLF_PB_C5_32_2(5,ms01vv,mpp1,qArg0,qArg2,mpp2,mpp7);
 CALL MRA_IMP_TDC_CLF_PB_C5_32_2(5,ms01vv,mpp1,qArg0,qArg3,mpp2,mpp7);
 CALL MRA_IMP_TDC_CLF_PB_C5_32_2(5,ms01vv,mpp1,qArg0,qArg4,mpp2,mpp7);
 CALL MRA_IMP_TDC_CLF_PB_C5_32_2(5,ms01vv,mpp1,qArg0,qArg5,mpp2,mpp7);
 CALL MRA_IMP_TDC_CLF_PB_C5_32_2(5,ms01vv,mpp1,qArg0,qArg6,mpp2,mpp7);
 CALL MRA_IMP_TDC_CLF_PB_C5_32_2(5,ms01vv,mpp1,qArg0,qArg7,mpp2,mpp7);
 CALL MRA_IMP_TDC_CLF_PB_C5_32_2(5,ms01vv,mpp1,qArg0,qArg8,mpp2,mpp7);
 CALL MRA_IMP_TDC_CLF_PB_C5_32_2(5,ms01vv,mpp1,qArg0,qArg9,mpp2,mpp7); 
 CALL MRA_IMP_TDC_CLF_PB_C5_32_2(5,ms01vv,mpp1,qArg0,qArg10,mpp2,mpp7);
 CALL MRA_IMP_TDC_CLF_PB_C5_32_2(5,ms01vv,mpp1,qArg0,qArg11,mpp2,mpp7); 
 CALL MRA_IMP_TDC_CLF_PB_C5_32_2(5,ms01vv,mpp1,qArg0,qArg12,mpp2,mpp7);
 CALL MRA_IMP_TDC_CLF_PB_C5_32_2(5,ms01vv,mpp1,qArg0,qArg13,mpp2,mpp7);
 SET mm1=mm1+1; 

 END IF;

END LOOP;
