/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CLF_PB_C5_32_2`(m1pp tinyint,ms01vv VARCHAR(30),mpp1 BIGINT,mpp2 BIGINT,mpp3 VARCHAR(100),mpp4 VARCHAR(100),mpp5 VARCHAR(100))
BEGIN

DECLARE vm_probdesc VARCHAR(100);
DECLARE mm1 INT DEFAULT 1; DECLARE bmc INT DEFAULT 0;
DECLARE qArg0 BIGINT;DECLARE qArg1 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);
DECLARE mrw CURSOR FOR SELECT nr,`BENE_MBI_ID`,`CLM_FROM_DT`,`DGNS_PRCDR_ICD_IND` FROM mra_file_static.mra_cclf5 WHERE BENE_MBI_ID=mpp4 COLLATE latin1_swedish_ci AND nr=mpp2;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg0,qArg1,qArg2,qArg3;
 IF bmc = 0 AND mpp3<>"~" AND mpp3<>"0" THEN

 SET @probType="Problems"; if m1pp=1 then set @probType="Principal"; end if;

 SET vm_probdesc = MRA_FN21_GetIcdDescription(mpp3);
 INSERT IGNORE INTO encounter_icd_codes SET mra_clm_refer_num=qArg0,mra_clm_refer_m01=ms01vv,patient_id=mpp5,`onset_date`=qArg2,diagnosis_type=qArg3,encounter_nr=mpp1, diagnosis_code=mpp3,`diagnosis_desc`=vm_probdesc,SNOMED_CID='',SNOMED_FSN='',`status`='Active',problem_type=@probType,`created_by`='mra_sch_import_claim',`created_date`=NOW();

 SET mm1=mm1+1;
 
 END IF;
END LOOP;
CLOSE mrw;
END */$$
