DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CLF_PB_C5_91`(mpp1 INT, mpp2 VARCHAR(100))
BEGIN

DECLARE vtmp VARCHAR(100); DECLARE bmc INT DEFAULT 0; DECLARE m01Val INT;
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);
DECLARE mrw CURSOR FOR SELECT `nr`,`BENE_MBI_ID`,`CLM_FROM_DT`,RNDRG_PRVDR_NPI_NUM,CLM_CNTL_NUM FROM mra_file_static.mra_cclf5 WHERE map_data_status=0 AND BENE_MBI_ID=mpp2 GROUP BY BENE_MBI_ID,CLM_FROM_DT,RNDRG_PRVDR_NPI_NUM,CLM_CNTL_NUM;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04; 
 IF bmc = 0 THEN
 
 SET m01Val = (SELECT COUNT(tt1.nr) FROM (SELECT nr FROM mra_file_static.mra_cclf5 WHERE map_data_status=0 AND BENE_MBI_ID=qArg01 AND CLM_FROM_DT=qArg02 AND RNDRG_PRVDR_NPI_NUM=qArg03 GROUP BY CLM_CNTL_NUM) tt1);  

 IF m01Val=1 THEN
  UPDATE mra_file_static.mra_cclf5 SET map_process_status=1 WHERE map_data_status=0 AND `BENE_MBI_ID`=qArg01 AND CLM_FROM_DT=qArg02 AND RNDRG_PRVDR_NPI_NUM=qArg03 AND CLM_CNTL_NUM=qArg04;
 ELSEIF m01Val>1 THEN
  SET vtmp = (SELECT CUR_CLM_UNIQ_ID FROM mra_file_static.mra_cclf5 WHERE map_data_status=0 AND BENE_MBI_ID=qArg01 AND CLM_FROM_DT=qArg02 AND RNDRG_PRVDR_NPI_NUM=qArg03 AND CLM_CNTL_NUM=qArg04 ORDER BY CLM_EFCTV_DT DESC, CUR_CLM_UNIQ_ID DESC LIMIT 1);
  IF vtmp IS NOT NULL THEN 
   UPDATE mra_file_static.mra_cclf5 SET map_process_status=1 WHERE map_data_status=0 AND `BENE_MBI_ID`=qArg01 AND CLM_FROM_DT=qArg02 AND RNDRG_PRVDR_NPI_NUM=qArg03 AND CLM_CNTL_NUM=qArg04 AND CUR_CLM_UNIQ_ID=vtmp;
  END IF;
 END IF;
  
 END IF;
END LOOP;
CLOSE mrw;

END */$$
