/* Procedure structure for procedure `MRA_IMP_TDC_CLF_PB_C6_02` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CLF_PB_C6_02`(mpp1 INT, mpp2 INT,mpp3 VARCHAR(100))
BEGIN

DECLARE vtmp VARCHAR(100); DECLARE v1tmp INT; DECLARE mMBI_IDNEW VARCHAR(100) CHARACTER SET latin1;
DECLARE vm_enc_nr BIGINT; DECLARE mv_proc_type_nr SMALLINT DEFAULT 3; DECLARE ms01vv VARCHAR(20);
DECLARE procedure_type VARCHAR(50);DECLARE order_id VARCHAR(100); DECLARE to_personell_name VARCHAR(100) CHARACTER SET latin1;
DECLARE mv_bill_id BIGINT; DECLARE to_personell_nr INT; DECLARE mHospNr INT;
DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg2 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);DECLARE qArg7 VARCHAR(100);DECLARE qArg8 VARCHAR(100);DECLARE qArg9 VARCHAR(100);DECLARE qArg10 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg11 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg12 VARCHAR(100);
DECLARE qArg13 VARCHAR(100);DECLARE qArg14 VARCHAR(100);DECLARE qArg15 VARCHAR(100);DECLARE qArg16 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg17 INT;

DECLARE mrw CURSOR FOR SELECT `nr`,`CUR_CLM_UNIQ_ID`,`BENE_MBI_ID`,`CLM_TYPE_CD`,`CLM_FROM_DT`,`CLM_THRU_DT`,CONCAT(SUBSTR(`CLM_FROM_DT`,1,4),SUBSTR(`CLM_FROM_DT`,6,2),SUBSTR(`CLM_FROM_DT`,9,2)) AS encounter_date,`CLM_FED_TYPE_SRVC_CD`,`CLM_POS_CD`,`CLM_PRMRY_PYR_CD`,`PAYTO_PRVDR_NPI_NUM`,`ORDRG_PRVDR_NPI_NUM`,CLM_ADJSMT_TYPE_CD,CLM_BLG_PRVDR_NPI_NUM,CLM_RFRG_PRVDR_NPI_NUM,CLM_EFCTV_DT,CLM_CNTL_NUM,mm_imp_job_nr FROM mra_file_static.mra_cclf6 WHERE map_data_status=1 AND map_process_status=1 AND BENE_MBI_ID=mpp3 COLLATE latin1_swedish_ci GROUP BY BENE_MBI_ID,CLM_FROM_DT,ORDRG_PRVDR_NPI_NUM,CLM_CNTL_NUM,CUR_CLM_UNIQ_ID ORDER BY CLM_EFCTV_DT, CUR_CLM_UNIQ_ID;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8,qArg9,qArg10,qArg11,qArg12,qArg13,qArg14,qArg15,qArg16,qArg17;
 IF bmc = 0 THEN
 SET ms01vv = "mclf6_c";
 SET mMBI_IDNEW=MRA_FN01_GetPatientIDLastCCLF(qArg2);

 SET mHospNr= -3;
 
 IF qArg11<>'~' THEN CALL MRA_IMP_FUNC_Personell(qArg11); END IF;
 

SET vm_enc_nr = (SELECT encounter_nr FROM encounter WHERE origid=mMBI_IDNEW COLLATE latin1_swedish_ci AND DATE_FORMAT(encounter_date,'%Y-%m-%d')=qArg4 AND ATNDG_PRVDR_NPI_NUM=qArg11 COLLATE latin1_swedish_ci AND CLM_CNTL_NUM=qArg16 COLLATE latin1_swedish_ci AND mra_proc_type_nr=mv_proc_type_nr LIMIT 1);
 IF vm_enc_nr IS NULL THEN
 UPDATE sequence_table_data SET sequence_id = sequence_id +1 WHERE sequence_name='encounter';
 SET vtmp = (SELECT sequence_id FROM sequence_table_data WHERE sequence_name='encounter'); 
 SET vm_enc_nr= CONCAT(qArg6,DATE_FORMAT(NOW(),'%s'),vtmp); 
 
 SET to_personell_nr=1; SET to_personell_name=qArg11;
 SET vtmp = (SELECT nr FROM personell WHERE npr_id=to_personell_name COLLATE latin1_swedish_ci LIMIT 1);
 IF vtmp IS NOT NULL THEN
  SET to_personell_nr=vtmp; SET to_personell_name = (SELECT `name` FROM personell WHERE nr=to_personell_nr LIMIT 1);
 END IF;
 SET procedure_type=qArg8;
 SET vtmp = (SELECT Option_Label FROM option_code_values WHERE Column_Order=1120 AND Option_Value=procedure_type LIMIT 1);
 IF vtmp IS NOT NULL THEN SET procedure_type=vtmp; END IF;
 
 INSERT INTO appointment SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,create_id='mra_sch_import_claim',origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,hospital_nr=mHospNr,`date`=qArg4,`language`='English Speaking',is_pre_schedule='0',`status`='closed',encounter_class_nr='12',appt_status='closed',to_dept_nr=14,TIME='08:00:00',to_personell_nr=to_personell_nr,to_personell_name=to_personell_name,`admitting_department`='physician',CLM_TYPE_CD=qArg3,CLM_FED_TYPE_SRVC_CD=qArg7,CLM_POS_CD=qArg8,RNDRG_PRVDR_TYPE_CD=qArg9;
 INSERT INTO encounter SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,create_id='mra_sch_import_claim',mra_proc_type_nr=mv_proc_type_nr,encounter_class_nr='12',encounter_status='admitted',is_discharged='0',report_status='1',mm_curr_mbi_id=qArg2,origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,hospital_nr=mHospNr,encounter_date=qArg4,discharge_date=qArg5,discharge_time="",encounter_type=procedure_type,pos=qArg8,place_of_service=qArg8,ATNDG_PRVDR_NPI_NUM=qArg11,CLM_EFCTV_DT=qArg15,CLM_ADJSMT_TYPE_CD=qArg12,CLM_CNTL_NUM=qArg16,mm_imp_job_nr=qArg17;
 INSERT INTO encounter_details SET origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,CLM_BLG_PRVDR_NPI_NUM=qArg13,CLM_RFRG_PRVDR_NPI_NUM=qArg14;  
 INSERT INTO encounter_procedure SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,comments='mra_sch_import_claim',encounter_nr=vm_enc_nr,procedure_type=procedure_type,procedure_date=qArg4,procedure_center='NA',interventionalist=to_personell_name,prcedure_op_type=1;
 SET order_id= CONCAT("OE-mra_encounter-AP-",DATE_FORMAT(NOW(),'%Y%m%d'));
 INSERT INTO cpoe_orders SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,order_type='MRA_import',created_by='mra_sch_import_claim',created_date=NOW(),patient_id=mMBI_IDNEW,order_id=order_id,encounter_nr=vm_enc_nr,order_date=qArg4,category="36",sub_category="449",`item`="MRA Physician",referral_id="",doctor=to_personell_name,order_status="scheduled",notes="",parent_encounter_nr=vm_enc_nr;
 INSERT INTO study_report_billing SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,created_date=NOW(),created_by='mra_sch_import_claim',Patient_Id=mMBI_IDNEW,encounter_nr=vm_enc_nr,Procedure_Type=procedure_type,CLM_ADJSMT_TYPE_CD=qArg12;
 SET mv_bill_id=LAST_INSERT_ID();
 ELSE
  SET mv_bill_id = (SELECT Billing_ID FROM study_report_billing WHERE encounter_nr=vm_enc_nr LIMIT 1);
  SET v1tmp=0; IF qArg12="1" THEN SET v1tmp=1; END IF;
  UPDATE study_report_billing_codes SET cal_amount=0 WHERE Billing_Id=mv_bill_id;
  CALL MRA_IMP3_M01ENC_99_01(vm_enc_nr);

  UPDATE encounter SET map_data_status=v1tmp,mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,CUR_CLM_UNIQ_ID=qArg01,hospital_nr=mHospNr,discharge_date=qArg5,place_of_service=qArg8,pos=qArg8,ATNDG_PRVDR_NPI_NUM=qArg11,CLM_EFCTV_DT=qArg15,CLM_ADJSMT_TYPE_CD=qArg12,CLM_CNTL_NUM=qArg16 WHERE encounter_nr=vm_enc_nr;
  UPDATE appointment SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,create_id='mra_sch_import_claim',hospital_nr=mHospNr,to_personell_nr=to_personell_nr,to_personell_name=to_personell_name WHERE encounter_nr=vm_enc_nr;
 END IF; 
 CALL MRA_IMP_TDC_CLF_PB_C6_31(ms01vv,mv_bill_id,qArg2,qArg4,qArg11,qArg01);
 
 UPDATE mra_file_static.mra_cclf6 SET map_data_status=2 WHERE map_data_status=1 AND BENE_MBI_ID=qArg2 AND CLM_FROM_DT=qArg4 AND ORDRG_PRVDR_NPI_NUM=qArg11 COLLATE latin1_swedish_ci AND CLM_CNTL_NUM=qArg16 COLLATE latin1_swedish_ci AND CUR_CLM_UNIQ_ID=qArg01 COLLATE latin1_swedish_ci;
 INSERT INTO mra_00_tmp SET mdd_1="MCF_PB_DME_C6",mdd_2=mpp1,mdd_3=qArg00;

 END IF;
END LOOP;

CLOSE mrw;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_TDC_CLF_PB_C6_31` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CLF_PB_C6_31`(ms01vv VARCHAR(20), mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100))
BEGIN

DECLARE mvID BIGINT; DECLARE mm1 INT DEFAULT 1;
DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg1 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);
DECLARE mrw CURSOR FOR SELECT `nr`,`CLM_LINE_HCPCS_CD`,`CLM_LINE_ALOWD_CHRG_AMT`,SUM(CLM_LINE_CVRD_PD_AMT),CLM_ADJSMT_TYPE_CD FROM mra_file_static.mra_cclf6 WHERE map_data_status=1 AND map_process_status=1 AND `BENE_MBI_ID`=mpp2 COLLATE latin1_swedish_ci AND `CLM_FROM_DT`=mpp3 AND `ORDRG_PRVDR_NPI_NUM`=mpp4 COLLATE latin1_swedish_ci AND CUR_CLM_UNIQ_ID=mpp5 COLLATE latin1_swedish_ci GROUP BY CLM_LINE_HCPCS_CD;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
OPEN mrw;

read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg1,qArg2,qArg3,qArg4; 
 IF bmc = 0 THEN

  SET mvID = (SELECT ID FROM study_report_billing_codes WHERE Billing_ID=mpp1 AND Billing_Code=qArg1 COLLATE latin1_swedish_ci LIMIT 1);
  IF mvID IS NOT NULL THEN
   UPDATE study_report_billing_codes SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,cpt_code_order_num=mm1,Billing_Code=qArg1,cal_amount=qArg3,CLM_ADJSMT_TYPE_CD=qArg4 WHERE ID=mvID;
  ELSE
   INSERT IGNORE INTO study_report_billing_codes SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,Billing_Id=mpp1,`count`='1',`modifier`='',Billing_Type='P',cpt_code_order_num=mm1,Billing_Code=qArg1,cal_amount=qArg3,cal2amount=0,CLM_ADJSMT_TYPE_CD=qArg4;
  END IF;
  SET mm1=mm1+1;

 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

