DECLARE m01Val INT;
DECLARE mrw CURSOR FOR SELECT nr,`BENE_MBI_ID`,`CLM_FROM_DT`,ORDRG_PRVDR_NPI_NUM,CLM_CNTL_NUM FROM mra_file_static.mra_cclf6 WHERE map_data_status=0 AND BENE_MBI_ID=mpp2 COLLATE latin1_swedish_ci GROUP BY BENE_MBI_ID,CLM_FROM_DT,ORDRG_PRVDR_NPI_NUM,CLM_CNTL_NUM;
