 IF bmc = 0 THEN
 SET m01Val = (SELECT COUNT(tt1.nr) FROM (SELECT nr FROM mra_file_static.mra_cclf6 WHERE map_data_status=0 AND BENE_MBI_ID=qArg01 COLLATE latin1_swedish_ci AND CLM_FROM_DT=qArg02 AND ORDRG_PRVDR_NPI_NUM=qArg03 COLLATE latin1_swedish_ci GROUP BY CLM_CNTL_NUM) tt1);  
 IF m01Val=1 THEN
  UPDATE mra_file_static.mra_cclf6 SET map_process_status=1 WHERE map_data_status=0 AND `BENE_MBI_ID`=qArg01 COLLATE latin1_swedish_ci AND CLM_FROM_DT=qArg02 AND ORDRG_PRVDR_NPI_NUM=qArg03 COLLATE latin1_swedish_ci AND CLM_CNTL_NUM=qArg04 COLLATE latin1_swedish_ci;
 ELSEIF m01Val>1 THEN
	SET vtmp = (SELECT CUR_CLM_UNIQ_ID FROM mra_file_static.mra_cclf6 WHERE map_data_status=0 AND BENE_MBI_ID=qArg01 COLLATE latin1_swedish_ci AND CLM_FROM_DT=qArg02 AND ORDRG_PRVDR_NPI_NUM=qArg03 COLLATE latin1_swedish_ci AND CLM_CNTL_NUM=qArg04 COLLATE latin1_swedish_ci ORDER BY CLM_EFCTV_DT DESC, CUR_CLM_UNIQ_ID DESC LIMIT 1);
