 	 UPDATE mra_file_static.mra_cclf6 SET map_process_status=1 WHERE map_data_status=0 AND `BENE_MBI_ID`=qArg01 COLLATE latin1_swedish_ci AND CLM_FROM_DT=qArg02 AND ORDRG_PRVDR_NPI_NUM=qArg03 COLLATE latin1_swedish_ci AND CLM_CNTL_NUM=qArg04 COLLATE latin1_swedish_ci AND CUR_CLM_UNIQ_ID=vtmp COLLATE latin1_swedish_ci;
