/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CLF_PD_C7_20`(mpp1 INT,mpp2 INT,mpp3 VARCHAR(100))
BEGIN

DECLARE vtmp VARCHAR(100); DECLARE v1tmp INT; DECLARE ms01vv VARCHAR(20); DECLARE mMBI_IDNEW VARCHAR(100) CHARACTER SET latin1;
DECLARE mv_proc_type_nr SMALLINT DEFAULT 4; DECLARE procedure_type VARCHAR(20) DEFAULT "Pharmacy Visit";
DECLARE order_id VARCHAR(100); DECLARE to_personell_name VARCHAR(100) CHARACTER SET latin1; DECLARE vm_enc_nr BIGINT;
DECLARE mv_bill_id BIGINT; DECLARE to_personell_nr INT; DECLARE mHospNr INT;
DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg2 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);DECLARE qArg7 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg8 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg9 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg10 VARCHAR(100);DECLARE qArg11 VARCHAR(100); DECLARE qArg12 INT;

DECLARE mrw CURSOR FOR SELECT `nr`,`CUR_CLM_UNIQ_ID`,`BENE_MBI_ID`,`CLM_TYPE_CD`,`CLM_LINE_FROM_DT`,CONCAT(SUBSTR(`CLM_LINE_FROM_DT`,1,4),SUBSTR(`CLM_LINE_FROM_DT`,6,2),SUBSTR(`CLM_LINE_FROM_DT`,9,2)) AS encounter_date,`PRVDR_SRVC_ID_QLFYR_CD`,`CLM_SRVC_PRVDR_GNRC_ID_NUM`,`PRVDR_PRSBNG_ID_QLFYR_CD`,`CLM_PRSBNG_PRVDR_GNRC_ID_NUM`,CLM_ADJSMT_TYPE_CD,CLM_EFCTV_DT,mm_imp_job_nr FROM mra_file_static.mra_cclf7 WHERE map_data_status=1 AND map_process_status=1 AND BENE_MBI_ID=mpp3 COLLATE latin1_swedish_ci GROUP BY BENE_MBI_ID,CLM_LINE_FROM_DT,CLM_PRSBNG_PRVDR_GNRC_ID_NUM,CUR_CLM_UNIQ_ID ORDER BY CLM_EFCTV_DT, CUR_CLM_UNIQ_ID;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg2,qArg3,qArg4,qArg5,qArg6,qArg7,qArg8,qArg9,qArg10,qArg11,qArg12;
 IF bmc = 0 THEN

 SET ms01vv = "mclf7_d";
 SET mMBI_IDNEW=MRA_FN01_GetPatientIDLastCCLF(qArg2);
 IF qArg9<>'~' THEN CALL MRA_IMP_FUNC_Personell(qArg9); END IF; 
 SET mHospNr= -3;

SET vm_enc_nr = (SELECT encounter_nr FROM encounter WHERE origid=mMBI_IDNEW COLLATE latin1_swedish_ci AND DATE_FORMAT(encounter_date,'%Y-%m-%d')=qArg4 AND ATNDG_PRVDR_NPI_NUM=qArg9 COLLATE latin1_swedish_ci AND mra_proc_type_nr=mv_proc_type_nr LIMIT 1); 
 IF vm_enc_nr IS NULL THEN
 UPDATE sequence_table_data SET sequence_id = sequence_id +1 WHERE sequence_name='encounter';
 SET vtmp = (SELECT sequence_id FROM sequence_table_data WHERE sequence_name='encounter'); 
 SET vm_enc_nr= CONCAT(qArg5,DATE_FORMAT(NOW(),'%s'),vtmp); 
 
 SET to_personell_nr=1; SET to_personell_name=qArg9;
 SET vtmp = (SELECT nr FROM personell WHERE npr_id=to_personell_name COLLATE latin1_swedish_ci LIMIT 1);
 IF vtmp IS NOT NULL THEN
  SET to_personell_nr=vtmp; SET to_personell_name = (SELECT `name` FROM personell WHERE nr=to_personell_nr LIMIT 1);
 END IF;
 INSERT INTO appointment SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,create_id='mra_sch_import_claim',origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,hospital_nr=mHospNr,`date`=qArg4,`language`='English Speaking',is_pre_schedule='0',`status`='closed',encounter_class_nr='11',appt_status='closed',to_dept_nr=14,TIME='08:00:00',to_personell_nr=to_personell_nr,to_personell_name=to_personell_name,`admitting_department`='pharmacy',CLM_TYPE_CD=qArg3;
 INSERT INTO encounter SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,create_id='mra_sch_import_claim',encounter_status='admitted',mra_proc_type_nr=mv_proc_type_nr,encounter_class_nr='11',is_discharged='0',report_status='1',mm_curr_mbi_id=qArg2,origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,hospital_nr=mHospNr,encounter_date=qArg4,discharge_date=qArg4,discharge_time="",encounter_type=procedure_type,place_of_service='01',pos='01',ATNDG_PRVDR_NPI_NUM=qArg9,CLM_ADJSMT_TYPE_CD=qArg10,CLM_EFCTV_DT=qArg11,mm_imp_job_nr=qArg12;
 INSERT INTO encounter_procedure SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,comments='mra_sch_import_claim',encounter_nr=vm_enc_nr,procedure_type=procedure_type,procedure_date=qArg4,procedure_center='',interventionalist=to_personell_name,prcedure_op_type=1;
 SET order_id= CONCAT("OE-mra_encounter-AP-",DATE_FORMAT(NOW(),'%Y%m%d'));
 INSERT INTO cpoe_orders SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,order_type='MRA_import',created_by='mra_sch_import_claim',created_date=NOW(),patient_id=mMBI_IDNEW,order_id=order_id,encounter_nr=vm_enc_nr,order_date=qArg4,category="36",sub_category="449",`item`="MRA Pharmacy",referral_id="",doctor=to_personell_name,order_status="scheduled",notes="",parent_encounter_nr=vm_enc_nr;
 INSERT INTO study_report_billing SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,created_date=NOW(),created_by='mra_sch_import_claim',Patient_Id=mMBI_IDNEW,encounter_nr=vm_enc_nr,Procedure_Type=procedure_type;
 SET mv_bill_id=LAST_INSERT_ID();
 ELSE
  SET mv_bill_id = (SELECT Billing_ID FROM study_report_billing WHERE encounter_nr=vm_enc_nr LIMIT 1);
  SET v1tmp=0; IF qArg10="1" THEN SET v1tmp=1; END IF;
  DELETE FROM study_report_billing_codes WHERE Billing_Id=mv_bill_id;
  CALL MRA_IMP3_M01ENC_99_01(vm_enc_nr);
  UPDATE encounter SET map_data_status=v1tmp,mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,mra_cur_clm_uniq_id=qArg01,CUR_CLM_UNIQ_ID=qArg01,hospital_nr=mHospNr,discharge_date=qArg4,ATNDG_PRVDR_NPI_NUM=qArg9,CLM_ADJSMT_TYPE_CD=qArg10,CLM_EFCTV_DT=qArg11 WHERE encounter_nr=vm_enc_nr;
  UPDATE appointment SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,create_id='mra_sch_import_claim',hospital_nr=mHospNr,to_personell_nr=to_personell_nr,to_personell_name=to_personell_name WHERE encounter_nr=vm_enc_nr;
 END IF; 

 CALL MRA_IMP_TDC_CLF_PD_C7_31(ms01vv,mv_bill_id,qArg2,qArg4,qArg9,qArg01);
 CALL MRA_IMP_TDC_CLF_PD_C7_32(ms01vv,vm_enc_nr,qArg2,qArg4,qArg9,qArg01,mMBI_IDNEW);
 UPDATE mra_file_static.mra_cclf7 SET map_data_status=2 WHERE map_data_status=1 AND BENE_MBI_ID=qArg2 COLLATE latin1_swedish_ci AND CLM_LINE_FROM_DT=qArg4 AND CLM_PRSBNG_PRVDR_GNRC_ID_NUM=qArg9 COLLATE latin1_swedish_ci AND CUR_CLM_UNIQ_ID=qArg01 COLLATE latin1_swedish_ci;
 INSERT INTO mra_00_tmp SET mdd_1="MCLF_7_Part_D",mdd_2=mpp1,mdd_3=qArg00;

 END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_TDC_CLF_PD_C7_31` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CLF_PD_C7_31`(ms01vv VARCHAR(20), mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100))
BEGIN
DECLARE vtmp VARCHAR(100); DECLARE v2tmp TINYINT DEFAULT 0;
DECLARE vm_cptcode VARCHAR(100); DECLARE mm1 INT DEFAULT 1;
DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT; DECLARE qArg1 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);
DECLARE mrw CURSOR FOR SELECT `nr`,`CLM_LINE_NDC_CD`,`CLM_LINE_BENE_PMT_AMT`,`CLM_ADJSMT_TYPE_CD` FROM mra_file_static.mra_cclf7 WHERE map_data_status=1 AND map_process_status=1 AND CLM_LINE_NDC_CD!='~' AND `BENE_MBI_ID`=mpp2 AND `CLM_LINE_FROM_DT`=mpp3 AND CLM_PRSBNG_PRVDR_GNRC_ID_NUM=mpp4 AND `CUR_CLM_UNIQ_ID`=mpp5;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg1,qArg2,qArg3; 
 IF bmc = 0 THEN

  SET vm_cptcode = CONCAT(SUBSTRING(qArg1,1,5),'-',SUBSTRING(qArg1,6,4),'-',SUBSTRING(qArg1,10,2));
  SET vtmp = (SELECT cpt_code FROM cpt_codes WHERE cpt_ndc_code=vm_cptcode LIMIT 1); 
  IF vtmp IS NOT NULL THEN SET vm_cptcode=vtmp; END IF;
  IF vm_cptcode IS NULL THEN  SET vm_cptcode=qArg1; END IF;
  INSERT IGNORE INTO study_report_billing_codes SET mra_clm_refer_num=qArg00,mra_clm_refer_m01=ms01vv,Billing_Id=mpp1,`count`="1",`modifier`="",Billing_Type='P',cpt_code_order_num=mm1,cal_amount=qArg2,Billing_Code=vm_cptcode,CLM_ADJSMT_TYPE_CD=qArg3;
  SET mm1=mm1+1; 

 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_TDC_CLF_PD_C7_32` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CLF_PD_C7_32`(ms01vv VARCHAR(20), mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100), mpp6 VARCHAR(100))
BEGIN
DECLARE vtmp VARCHAR(100); DECLARE mm1 INT DEFAULT 1; DECLARE bmc INT DEFAULT 0; 
DECLARE vm_s0v BIGINT; DECLARE vm_s1v VARCHAR(80);DECLARE vm_s2v VARCHAR(100); DECLARE vm_presdocname VARCHAR(100) DEFAULT '';
DECLARE qArg0 BIGINT;DECLARE qArg1 VARCHAR(100);DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100);DECLARE qArg4 VARCHAR(100);DECLARE qArg5 VARCHAR(100);DECLARE qArg6 VARCHAR(100);

DECLARE mrw CURSOR FOR SELECT `nr`,CLM_LINE_NDC_CD,CLM_LINE_FROM_DT,CLM_PRSBNG_PRVDR_GNRC_ID_NUM,CLM_LINE_DAYS_SUPLY_QTY,CLM_LINE_RX_FILL_NUM,CLM_LINE_SRVC_UNIT_QTY FROM mra_file_static.mra_cclf7 WHERE map_data_status=1 AND map_process_status=1 AND CLM_LINE_NDC_CD!='~' AND `BENE_MBI_ID`=mpp2 AND `CLM_LINE_FROM_DT`=mpp3 AND CLM_PRSBNG_PRVDR_GNRC_ID_NUM=mpp4 AND `CUR_CLM_UNIQ_ID`=mpp5;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg0,qArg1,qArg2,qArg3,qArg4,qArg5,qArg6;
 IF bmc = 0 THEN
 SET vm_s0v=0;SET vm_s1v='';SET vm_s2v='';
 SET vtmp = (SELECT `rxnconso2_id` FROM bt_static.`rxnconso2_ndcid_map` WHERE `NDCID`=qArg1 LIMIT 1); 
 IF vtmp IS NOT NULL THEN SET vm_s0v=vtmp; END IF;
 IF vm_s0v != 0 THEN  
  SET vtmp = (SELECT CONCAT(RXAUI,'!@#',STR) AS vtmp FROM bt_static.rxnconso2 WHERE nr=vm_s0v LIMIT 1); 
  IF vtmp IS NOT NULL THEN  
    SET vm_s1v=SUBSTRING_INDEX(vtmp,'!@#',1);SET vm_s2v=SUBSTRING_INDEX(vtmp,'!@#',-1);
  END IF;  
 END IF;
 SET vm_presdocname="";
 SET vtmp = (SELECT `name` FROM personell WHERE npr_id=qArg3 LIMIT 1); 
 IF vtmp IS NOT NULL THEN SET vm_presdocname=vtmp; END IF; 
 INSERT IGNORE INTO encounter_patient_medication SET mra_clm_refer_num=qArg0,mra_clm_refer_m01=ms01vv,`created_by`='mra_sch_import_claim',`created_date`=NOW(),`quantity_unit`=qArg6,`fill_date`='',`type`='Order',`source`='MRA',`med_units`=qArg6,`patientid`=mpp6,`encounter_nr`=mpp1,`medications`=vm_s2v,`RxnormID`=vm_s1v,`NDCID`=qArg1,`quantity`=qArg4,`refills`=qArg5,`start_date`=qArg2,`prescribed_doctor`=vm_presdocname;
 
 INSERT IGNORE INTO drfirst_patient_medications SET mra_clm_refer_num=qArg0,mra_clm_refer_m01=ms01vv,`patientid`=mpp6,`medications`=vm_s2v,`generic_name`=vm_s2v,`NDCID`=qArg1,`RxnormID`=vm_s1v,`dose`='',`dose_unit`='',`start_date`=qArg2,`refills`=qArg5,`quantity`=qArg4,`quantity_unit`=qArg6,`type`='Order',`prescribed_doctor`=vm_presdocname,`source`='MRA',`created_by`='mra_sch_import_claim',`created_date`=NOW();
  
 SET mm1=mm1+1;
 
 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_TDC_CLF_PD_C7_90` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CLF_PD_C7_90`()
BEGIN

DECLARE vtmp VARCHAR(100); DECLARE bmc INT DEFAULT 0;
DECLARE mmi INT DEFAULT 0;
DECLARE qArg00 VARCHAR(100) CHARACTER SET latin1;
DECLARE mrw CURSOR FOR SELECT distinct `BENE_MBI_ID` FROM mra_file_static.mra_cclf7 WHERE map_data_status=0;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00;
 IF bmc = 0 THEN
  INSERT INTO mra_00_tmp SET mdd_1="CF_7_90",mdd_2=mmi,mdd_3=qArg00;
  SET  mmi = mmi + 1;
  CALL MRA_IMP_TDC_CLF_PD_C7_91(mmi,qArg00);
  UPDATE mra_file_static.mra_cclf7 SET map_data_status=1 WHERE map_data_status=0 AND BENE_MBI_ID=qArg00 COLLATE latin1_swedish_ci;  
 END IF;
END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_TDC_CLF_PD_C7_91` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDC_CLF_PD_C7_91`(mpp1 INT, mpp2 VARCHAR(100))
BEGIN

DECLARE vtmp VARCHAR(100) CHARACTER SET latin1; DECLARE bmc INT DEFAULT 0;DECLARE m01Val INT;
DECLARE qArg01 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100) CHARACTER SET latin1;

DECLARE mrw CURSOR FOR SELECT DISTINCT `BENE_MBI_ID`,`CLM_LINE_FROM_DT`,CLM_PRSBNG_PRVDR_GNRC_ID_NUM FROM mra_file_static.mra_cclf7 WHERE map_data_status=0 AND BENE_MBI_ID=mpp2 COLLATE latin1_swedish_ci;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01,qArg02,qArg03; 
 IF bmc = 0 THEN
 SET m01Val = (SELECT COUNT(tt1.mnr) FROM (SELECT COUNT(nr) AS mnr FROM mra_file_static.mra_cclf7 WHERE map_data_status=0 AND BENE_MBI_ID=qArg01 COLLATE latin1_swedish_ci AND CLM_LINE_FROM_DT=qArg02 AND CLM_PRSBNG_PRVDR_GNRC_ID_NUM=qArg03 COLLATE latin1_swedish_ci GROUP BY CUR_CLM_UNIQ_ID) tt1);  
 IF m01Val=1 THEN
  UPDATE mra_file_static.mra_cclf7 SET map_process_status=1 WHERE map_data_status=0 AND `BENE_MBI_ID`=qArg01 COLLATE latin1_swedish_ci AND CLM_LINE_FROM_DT=qArg02 AND CLM_PRSBNG_PRVDR_GNRC_ID_NUM=qArg03 COLLATE latin1_swedish_ci;
 ELSEIF m01Val>1 THEN
	SET vtmp = (SELECT CUR_CLM_UNIQ_ID FROM mra_file_static.mra_cclf7 WHERE map_data_status=0 AND BENE_MBI_ID=qArg01 COLLATE latin1_swedish_ci AND CLM_LINE_FROM_DT=qArg02 AND CLM_PRSBNG_PRVDR_GNRC_ID_NUM=qArg03 COLLATE latin1_swedish_ci ORDER BY CLM_EFCTV_DT DESC, CUR_CLM_UNIQ_ID DESC LIMIT 1);
	IF vtmp IS NOT NULL THEN 
 	 UPDATE mra_file_static.mra_cclf7 SET map_process_status=1 WHERE map_data_status=0 AND `BENE_MBI_ID`=qArg01 COLLATE latin1_swedish_ci AND CLM_LINE_FROM_DT=qArg02 AND CLM_PRSBNG_PRVDR_GNRC_ID_NUM=qArg03 COLLATE latin1_swedish_ci AND CUR_CLM_UNIQ_ID=vtmp COLLATE latin1_swedish_ci;
	END IF;
 END IF;
 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_TDE_CLF_PA_C1_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDE_CLF_PA_C1_01`(mpp1 INT)
BEGIN
DECLARE mmi  INT;
SET mmi = 1;
LOOP_M01:  LOOP
 CALL MRA_IMP_TDE_CLF_PA_C1_02(mmi);
 IF  mmi >= mpp1 THEN LEAVE  LOOP_M01;  END  IF;
 SET  mmi = mmi + 1;
 ITERATE  LOOP_M01;
END LOOP;
	
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_TDE_CLF_PA_C1_02` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDE_CLF_PA_C1_02`(mpp1 INT)
BEGIN

DECLARE vtmp VARCHAR(100); DECLARE v1Check TINYINT DEFAULT 0; DECLARE bmc INT DEFAULT 0; 
DECLARE mv_proc_type_nr SMALLINT DEFAULT 1; DECLARE hospital_nr BIGINT DEFAULT 0;

DECLARE vm_enc_nr BIGINT;DECLARE mv_bill_id BIGINT; DECLARE mMBI_IDNEW VARCHAR(100) CHARACTER SET latin1;
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg2 VARCHAR(100);DECLARE qArg3 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg4 VARCHAR(100) CHARACTER SET latin1; DECLARE qArg05 VARCHAR(100);DECLARE qArg06 VARCHAR(100);DECLARE qArg07 VARCHAR(100);DECLARE qArg08 VARCHAR(100) CHARACTER SET latin1;DECLARE qArg09 VARCHAR(30);DECLARE qArg10 VARCHAR(50);DECLARE qArg11 VARCHAR(30);DECLARE qArg12 VARCHAR(30);DECLARE qArg13 VARCHAR(30);

DECLARE mrw CURSOR FOR SELECT nr,`CLMH_MBI`,CLMH_FROM_DT,CLMH_PVDR_CCN,CLMH_DCN,CLMH_ADJSMT_TYPE_CD,map_version,CLMH_THRU_DT,CLMH_PVDR_NPI,CONCAT(SUBSTR(`CLMH_FROM_DT`,1,4),SUBSTR(`CLMH_FROM_DT`,6,2),SUBSTR(`CLMH_FROM_DT`,9,2)) AS encounter_date,FAC_PRVDR_NPI_NUM,clm_pos_code,CLMH_BILL_FACILITY,CLMH_BILL_CATEGORY FROM mra_file_static.mra_clm_redunction_part_a WHERE map_data_status=1 AND map_process_status=1 GROUP BY `CLMH_MBI`,CLMH_FROM_DT,CLMH_PVDR_CCN  LIMIT 10000;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg2,qArg3,qArg4,qArg05,qArg06,qArg07,qArg08,qArg09,qArg10,qArg11,qArg12,qArg13;
 IF bmc = 0 THEN

  SET mMBI_IDNEW=MRA_FN01_GetPatientIDLastCCLF(qArg01);

 IF ((qArg11 IS NULL OR qArg11='') AND qArg12='3' ) THEN
  SET qArg11='10';
 ELSEIF ((qArg11 IS NULL OR qArg11='') AND qArg12='8' AND qArg13 IN ('1','2') ) THEN
  SET qArg11='50';
 ELSEIF ((qArg11 IS NULL OR qArg11='') AND qArg12 IN ('1','4','5','6','9') AND qArg13 IN ('1','2','7') ) THEN
  SET qArg11='60';
 ELSEIF ((qArg11 IS NULL OR qArg11='') AND qArg12 IN ('1','4','5','6','9') AND qArg13='3' ) THEN
  SET qArg11='40';
 ELSEIF ((qArg11 IS NULL OR qArg11='') AND qArg12='2' AND qArg13='8' ) THEN
  SET qArg11='30';
 ELSEIF ((qArg11 IS NULL OR qArg11='') AND qArg12='2' ) THEN
  SET qArg11='20'; 
 ELSEIF (qArg11 IS NULL OR qArg11='') THEN
  SET qArg11='00';
 END IF;  

 SET vm_enc_nr = (SELECT encounter_nr FROM encounter WHERE origid IN (mMBI_IDNEW COLLATE latin1_swedish_ci,qArg01 COLLATE latin1_swedish_ci) AND DATE_FORMAT(encounter_date,'%Y-%m-%d')=qArg2 AND CLM_BLG_PRVDR_OSCAR_NUM=qArg3 COLLATE latin1_swedish_ci AND mra_proc_type_nr=mv_proc_type_nr LIMIT 1);
 IF vm_enc_nr IS NULL THEN
   SET vm_enc_nr = (SELECT encounter_nr FROM encounter WHERE origid IN (mMBI_IDNEW COLLATE latin1_swedish_ci,qArg01 COLLATE latin1_swedish_ci) AND CLM_CNTL_NUM=qArg4 COLLATE latin1_swedish_ci AND mra_proc_type_nr=mv_proc_type_nr LIMIT 1);
 END IF;

 IF vm_enc_nr IS NULL THEN  
  	UPDATE sequence_table_data SET sequence_id=sequence_id+1 WHERE sequence_name='encounter';
	SET vtmp = (SELECT sequence_id FROM sequence_table_data WHERE sequence_name='encounter'); 
	SET vm_enc_nr= CONCAT(qArg09,DATE_FORMAT(NOW(),'%s'),vtmp);

	CALL MRA_IMP_FUNC_Hospital(qArg08);
	SET hospital_nr = (SELECT nr FROM hospital_centers WHERE nrp_id=qArg08 COLLATE latin1_swedish_ci LIMIT 1);

