	INSERT INTO encounter SET mra_clm_refer_num=qArg00,mra_clm_refer_m01='mm_claim_reduct',mra_cur_clm_uniq_id=0,create_id='mra_sch_import_claim',encounter_status='admitted',mra_proc_type_nr=mv_proc_type_nr,encounter_class_nr='9',is_discharged='0',report_status='1',mm_curr_mbi_id=qArg01,origid=mMBI_IDNEW,encounter_nr=vm_enc_nr,hospital_nr=hospital_nr,encounter_date=qArg2,discharge_date=qArg07,discharge_time="",encounter_type='',ATNDG_PRVDR_NPI_NUM=qArg10,CLM_BLG_PRVDR_OSCAR_NUM=qArg3,CUR_CLM_UNIQ_ID=0,CLM_EFCTV_DT='',CLM_CNTL_NUM=qArg4,CLM_ADJSMT_TYPE_CD=qArg05,mm_imp_job_nr=qArg06,place_of_service=qArg11,pos=qArg11,CLM_BILL_FAC_TYPE_CD=qArg12,CLM_BILL_CLSFCTN_CD=qArg13,FAC_PRVDR_NPI_NUM=qArg08;

