	INSERT INTO study_report_billing SET mra_clm_refer_num=qArg00,mra_clm_refer_m01='mm_claim_reduct',created_date=NOW(),created_by='mra_sch_import_claim',Patient_Id=mMBI_IDNEW,encounter_nr=vm_enc_nr,Procedure_Type='',CLM_ADJSMT_TYPE_CD=qArg05,CLM_BILL_FAC_TYPE_CD=0,CLM_TYPE_CD=0,CLM_OP_SRVC_TYPE_CD=0,CLM_ADMSN_TYPE_CD=qArg05,CLM_ADMSN_SRC_CD=qArg05,CLM_AMT_PD=0;
	SET mv_bill_id=LAST_INSERT_ID();
	SET v1Check=1;
  ELSE
	UPDATE mra_file_static.mra_clm_redunction_part_b SET is_btree_enc_match=1 WHERE MBI=qArg01 AND DOS_From=qArg2 AND Rend_Prov_NPI=qArg3 AND `Claim_no_2`=qArg4;
	UPDATE encounter SET mra_is_clf_redunct=1,map_data_status=0 WHERE encounter_nr=vm_enc_nr;
	DELETE FROM mra1_encounter WHERE encounter_nr=vm_enc_nr;
	DELETE FROM mra1_encounter_bill_cpts WHERE encounter_nr=vm_enc_nr;
	DELETE FROM mra1_encounter_icd_codes WHERE encounter_nr=vm_enc_nr;
	SET mv_bill_id = (SELECT Billing_ID FROM study_report_billing WHERE encounter_nr=vm_enc_nr LIMIT 1);
  END IF; 
 
  IF mv_bill_id != 0 THEN
