  END IF; */
  
  # CALL MRA_01_Cal_EncHccScore_11(vm_enc_nr);

  INSERT INTO mra1_encounter_logs SET mcreate_id='system',map_data_src=5,encounter_nr=vm_enc_nr,patient_id=qArg01,proc_type_nr=mv_proc_type_nr,m_notes='',mSrcInserted_Type='mra_clm_redunct_part_b',mSrcInserted_ID=qArg00,mm_imp_job_nr=qArg06;
  UPDATE mra_file_static.mra_clm_redunction_part_b SET map_data_status=2 WHERE map_data_status=1 AND MBI=qArg01 AND DOS_From=qArg2 AND Rend_Prov_NPI=qArg3 AND `Claim_no_2`=qArg4;
  INSERT INTO mra_00_tmp SET mdd_1='mra_clm_redunction_part_b',mdd_2=mpp1,mdd_3=qArg00,mdd_4=qArg01;
