	 INSERT IGNORE INTO study_report_billing_codes SET Billing_ID=mpp1, mra_is2clf_redunct=1, cal2amount=qArg14, Billing_Code=qArg15, COUNT='1',`modifier`='',Billing_Type='P',cpt_code_order_num=1;
	END IF;
 END IF;
 END LOOP;
CLOSE mrw;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_IMP_TDE_CLF_PB_C5_32_1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_IMP_TDE_CLF_PB_C5_32_1`(mpp1 BIGINT, mpp2 VARCHAR(100), mpp3 VARCHAR(100), mpp4 VARCHAR(100), mpp5 VARCHAR(100), mpp6 VARCHAR(100))
BEGIN
DECLARE vtmp VARCHAR(100); DECLARE bmc INT DEFAULT 0;

DECLARE qArg00 VARCHAR(100); DECLARE qArg01 VARCHAR(90);DECLARE qArg02 VARCHAR(90);DECLARE qArg03 VARCHAR(90);DECLARE qArg04 VARCHAR(90);DECLARE qArg05 VARCHAR(90); DECLARE qArg06 VARCHAR(90);DECLARE qArg07 VARCHAR(90);DECLARE qArg08 VARCHAR(90);DECLARE qArg09 VARCHAR(90);DECLARE qArg10 VARCHAR(90); DECLARE qArg11 VARCHAR(90);DECLARE qArg12 VARCHAR(90);DECLARE qArg13 VARCHAR(90);DECLARE qArg14 VARCHAR(90);DECLARE qArg15 VARCHAR(90); DECLARE qArg16 VARCHAR(90);DECLARE qArg17 VARCHAR(90);DECLARE qArg18 VARCHAR(90);DECLARE qArg19 VARCHAR(90);DECLARE qArg20 VARCHAR(90);

DECLARE mrw CURSOR FOR SELECT nr,Diag_Code,CLML_DGNSCD_2,CLML_DGNSCD_3,CLML_DGNSCD_4 FROM mra_file_static.mra_clm_redunction_part_b WHERE map_data_status=1 AND map_process_status=1 AND Clm_Type_Adj_Code IN (0,2) and `MBI`=mpp2 AND `DOS_From`=mpp3 AND `Rend_Prov_NPI`=mpp4  AND `Claim_no_2`=mpp5 limit 1;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04;

 IF bmc = 0 THEN 

  CALL MRA_IMP_TDE_CLF_PA_C1_32_2(mpp1,mpp2,mpp3,qArg01,mpp6); CALL MRA_IMP_TDE_CLF_PA_C1_32_2(mpp1,mpp2,mpp3,qArg02,mpp6);
  CALL MRA_IMP_TDE_CLF_PA_C1_32_2(mpp1,mpp2,mpp3,qArg03,mpp6); CALL MRA_IMP_TDE_CLF_PA_C1_32_2(mpp1,mpp2,mpp3,qArg04,mpp6);

 END IF;
 END LOOP;
CLOSE mrw;
END */$$
