/* Procedure structure for procedure `MRA_Load_Journal_Data` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_Load_Journal_Data`()
BEGIN
      
 DROP TABLE IF EXISTS mjournal;

CREATE TEMPORARY TABLE mjournal
(INDEX my_index_786 (id))
SELECT * FROM journal  WHERE TIMESTAMP >= DATE_SUB(CURRENT_TIMESTAMP(), INTERVAL 365 DAY) AND id > (SELECT max_id FROM journal_max_id) AND
AES_DECRYPT(username,'75c835848db7c19f72de108d274dbc5110a97599') NOT IN ('Andrew Martin','user, Administrator ','','UNK');

TRUNCATE TABLE m_journal_decrypted;

INSERT INTO m_journal_decrypted(id,`TIMESTAMP`,username,did,what,`uuid`,details,main_page,sub_page,start_time,end_time,total_time,session_id,user_id)
SELECT  j.id AS id,j.timestamp AS TIMESTAMP ,AES_DECRYPT(j.username,'75c835848db7c19f72de108d274dbc5110a97599') AS `username`,AES_DECRYPT(j.did,'75c835848db7c19f72de108d274dbc5110a97599') AS `did`,AES_DECRYPT(j.what,'75c835848db7c19f72de108d274dbc5110a97599')AS `what`,AES_DECRYPT(j.uuid,'75c835848db7c19f72de108d274dbc5110a97599')AS `uuid`,AES_DECRYPT(j.details,'75c835848db7c19f72de108d274dbc5110a97599') AS `details`, main_page,sub_page,start_time,end_time,total_time,session_id,user_id FROM mjournal j; 
 
/*SELECT * FROM m_journal_decrypted;*/


DROP TABLE IF EXISTS journal_decrypted;

CREATE TABLE journal_decrypted
(INDEX my_index_787 (UUID) ) 
SELECT jd.*,po.o_name AS main_pg, poi.o_name AS sub_pg  FROM m_journal_decrypted jd
LEFT JOIN page_options_list po ON jd.main_page=po.o_nr LEFT JOIN page_options_list poi ON jd.sub_page=poi.o_nr; 

/*
SELECT j.timestamp,DATE_SUB(CURRENT_TIMESTAMP(), INTERVAL 365 DAY) FROM journal_records j WHERE j.timestamp < DATE_SUB(CURRENT_TIMESTAMP(), INTERVAL 365 DAY);
*/

DELETE FROM journal_records_prod  WHERE TIMESTAMP < DATE_SUB(CURRENT_TIMESTAMP(), INTERVAL 365 DAY);

Delete From `journal_decrypted` where id  in 
(
select remove_id 
from
(
SELECT jd.TIMESTAMP,jd.uuid,jd.username,UPPER(jd.did),UPPER(jd.what),
COUNT( DISTINCT id) AS dupli_count, MIN(id) remove_id , Max(id) max_id
FROM journal_decrypted jd 
group by jd.TIMESTAMP,jd.uuid,jd.username,upper(jd.did),upper(jd.what)
Having COUNT( DISTINCT id) > 1
) as rem_list
);

INSERT INTO `journal_records_prod` (
  `Id` ,
  `TIMESTAMP` ,
  `User Name` ,
  `Did` ,
  `What` ,
  `User Id` ,
  `Details` ,
  `Main Page Id` ,
  `Sub Page Id` ,
  `Main Page` ,
  `Sub Page` ,
  `Last Name` ,
  `First Name` ,
  `DOB` ,
  `Sex` ,
  `Market_id`,
  `Group Name` ,
  `Group Id` ,
  `Age` ,
  `Provider Name` ,
  `Provider NPI` ,
  `Sub Group Id` ,
  `Align Status Code` ,
  `Sub Group Name` ,
  `Market Name`,
  `Start`,
  `End`,
  `grp`,
  `session_id`,
  `total_time`,
  `IdxDate`
  
   )
  
 SELECT jd.id,jd.TIMESTAMP,jd.username,jd.did,jd.what,jd.uuid,jd.details,jd.main_page,jd.sub_page,
 jd.main_pg,jd.sub_pg,
 pt.lastname, pt.firstname,pt.birthdate,pt.sex,hma.market_id,pt.facility_name,pt.facility_nr,pt.age,
pt.sp_dr_1 AS provider, pt.sp_dr_1_npi AS provider_npi, pt.facility_sub_nr AS facility_sub_nr,pt. ALIG_STATUS_CODE, hc.name AS sub_group_name, hm.market_name AS market_name,
jd.start_time,jd.end_time, IFNULL(ga.group_id,-786) AS grp ,session_id,total_time, CAST(TIMESTAMP AS DATE)

 FROM journal_decrypted jd LEFT JOIN patient pt ON jd.uuid=pt.origid LEFT JOIN hospital_market_assocs hma ON hma.hosp_id=pt.facility_nr
 
LEFT JOIN `hospital_market` hm ON hma.market_id=hm.market_id

LEFT JOIN `hospital_centers` hc ON pt.facility_sub_nr=hc.nr

LEFT JOIN users u ON u.id=jd.user_id
/*
(
SELECT MAX(LOWER(TRIM(login_id))) AS login_id  FROM users  
WHERE  CONCAT(LOWER(TRIM(lastname)),LOWER(TRIM(firstname))) = REPLACE(REPLACE(REPLACE(TRIM(jd.username),', ' , '') ,' ','') ,',','')
OR CONCAT(LOWER(TRIM(firstname)),LOWER(TRIM(lastname))) = REPLACE(REPLACE(REPLACE(TRIM(jd.username),', ' , '')  ,' ','')  ,',','')
)
*/
/*jd.uuid*/
LEFT JOIN `group_user_assocs` ga ON ga.user_id = u.id AND ga.group_id =531;
 
 /*SELECT * FROM journal_records LIMIT 10;*/ 


UPDATE journal_max_id SET max_id=(SELECT IFNULL(MAX(id),0) AS max_id FROM journal_records_prod);

/*SELECT * FROM journal_max_id;*/

UPDATE journal_records_prod  SET what = REPLACE(what ,'Ananlatic', 'Analytic') WHERE what LIKE '%Ananlatic%' ;

UPDATE journal_records_prod  SET what = 'Census Worklist' WHERE what LIKE 'Census Worklistt';

UPDATE journal_records_prod  SET what = 'Options Data Edit' WHERE what IN ('Option Data Edit') ;

UPDATE journal_records_prod  SET what = 'Polices Document' WHERE what IN ('Policy Document') ;


UPDATE  `journal_records_prod` SET grp=531 WHERE `User Name` LIKE '%Taylor%Aaron%' ;
UPDATE  `journal_records_prod` SET grp=531 WHERE `User Name` LIKE '%Araceli%Ayon%' ;
UPDATE  `journal_records_prod` SET grp=531 WHERE `User Name` LIKE '%internal%test%' ;

UPDATE journal_records_prod SET `user name` = 'Martinez, Carmen ' WHERE (`user id`='cmartinez' OR `user name` ='Carmen Martinez' ) AND IdxDate > '2025-08-06';
UPDATE journal_records_prod SET `user name` = 'Martinez, Carmen ' WHERE 
IdxDate > '2025-08-06' AND
id IN (

SELECT id FROM journal  WHERE 
AES_DECRYPT(username,'75c835848db7c19f72de108d274dbc5110a97599')  IN ('Carmen Martinez')
ORDER BY TIMESTAMP DESC
);


/*
Delete From `journal_records_prod` where id  in 

(
select remove_id 
from
(

SELECT `TIMESTAMP`,IFNULL(`Provider NPI`,0),IFNULL(`USER Id`,'UNK'),IFNULL(`USER NAME`, 'UNK') , IFNULL(did,'UNK'), IFNULL(what,'UNK'), COUNT( DISTINCT id) AS dupli_count, MIN(id) remove_id , Max(id) max_id FROM `journal_records_prod`
GROUP BY `TIMESTAMP`,IFNULL(`Provider NPI`,0),IFNULL(`USER Id`,'UNK'),IFNULL(`USER NAME`, 'UNK') , IFNULL(did,'UNK'), IFNULL(what,'UNK')
Having COUNT( DISTINCT id) > 1

) as Rem_list
);
  */  
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_SET01_Patient_Columns` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_SET01_Patient_Columns`(mpp1 INT)
BEGIN
DECLARE bmc INT DEFAULT 0; DECLARE vtmp VARCHAR(500); 
DECLARE v1tmp VARCHAR(500); DECLARE v2tmp VARCHAR(500); DECLARE v3tmp VARCHAR(500); DECLARE v4tmp VARCHAR(500);
DECLARE v5tmp VARCHAR(50);

DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);
DECLARE mrw CURSOR FOR SELECT id,origid,sp_dr_1,facility_nr FROM patient;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03; 
 IF bmc = 0 THEN

 SET v1tmp=''; SET v2tmp=''; SET v3tmp=''; SET v4tmp=''; SET v5tmp="0";

 SET vtmp = (SELECT CONCAT(t1.enc_admit_date,'!@#',ep.interventionalist) FROM mra1_encounter t1 INNER JOIN encounter_procedure ep ON t1.encounter_nr=ep.encounter_nr WHERE t1.patient_id=qArg01 AND t1.enc_status!='cancelled' AND ep.interventionalist IN ( SELECT DISTINCT t22.`name` FROM personell t22 INNER JOIN personell_hosp_assocs t21 ON t22.nr=t21.user_nr WHERE t21.hospital_nr=qArg03 ) ORDER BY t1.enc_admit_date DESC LIMIT 1);
 IF vtmp IS NOT NULL THEN
  SET v1tmp=SUBSTRING_INDEX(vtmp,'!@#',1); SET v2tmp=SUBSTRING_INDEX(vtmp,'!@#',-1);
 END IF;

 SET vtmp = (SELECT concat(t1.enc_admit_date,'!@#',t4.`name`) FROM mra1_encounter t1 INNER JOIN appointment t3 ON t1.encounter_nr=t3.encounter_nr INNER JOIN personell t4 ON t3.to_personell_nr=t4.nr WHERE t1.patient_id = qArg01 AND t1.enc_status!='cancelled' AND t4.ctype=1 ORDER BY t1.enc_admit_date DESC LIMIT 1);
 IF vtmp IS NOT NULL THEN
  SET v3tmp=SUBSTRING_INDEX(vtmp,'!@#',1); SET v4tmp=SUBSTRING_INDEX(vtmp,'!@#',-1);
 END IF;

 SET vtmp = (SELECT COUNT(*) AS mcnt FROM `mra_scorecard_alerts` WHERE origid=qArg01 AND current_status=1);
 IF vtmp IS NOT NULL THEN
  SET v5tmp=vtmp; 
 END IF; 

 UPDATE patient SET Last_PCP_Visit_Date=v1tmp,Last_PCP_Visit_Pc=v2tmp,Last_Visit_Date=v3tmp,Last_Visit_Pc=v4tmp,Clinical_Alerts_Count=v5tmp WHERE origid=qArg01;

 INSERT INTO mra_00_tmp SET mdd_1=mpp1,mdd_2=qArg00,mdd_3=qArg01;

 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_SET01_Patient_HCC_Alerts_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_SET01_Patient_HCC_Alerts_01`(m1pp INT, m2pp INT)
BEGIN

DECLARE v1tmp TEXT; DECLARE vResolvedDate VARCHAR(100);
DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(300);

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t1.patient_id,t1.onset_date,t1.hcc_level,t1.diagnosis_code,t2.hcc_description FROM mra1_encounter_icd_codes t1 LEFT JOIN bt_static.`mra_hcc_hierarchy_desc` t2 ON t2.hcc=CONCAT('HCC',t1.hcc_level) WHERE t1.hcc_inc=1 AND t1.hcc_level>0 AND YEAR(t1.onset_date)=m1pp GROUP BY t1.patient_id,t1.hcc_level,t1.diagnosis_code ORDER BY t1.onset_date DESC;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04,qArg05;
 IF bmc = 0 THEN

 SET vResolvedDate = (SELECT onset_date FROM mra1_encounter_icd_codes WHERE hcc_inc=1 AND YEAR(onset_date)=m2pp AND patient_id=qArg01 AND hcc_level=qArg03 ORDER BY onset_date DESC LIMIT 1);
 IF vResolvedDate IS NULL THEN
  SET v1tmp = (SELECT nr FROM mra_scorecard_alerts WHERE `TYPE`='HCC' AND origid=qArg01 AND ref_detail LIKE CONCAT('HCC',qArg03,'-%') AND YEAR(ref_date)=m1pp LIMIT 1);
  IF v1tmp IS NULL THEN
   INSERT INTO mra_scorecard_alerts SET `TYPE`='HCC',origid=qArg01,ref_description=CONCAT('HCC',qArg03,'-',qArg05),ref_detail=CONCAT('HCC',qArg03,'-',qArg05),original_status=1,current_status=1,ref_id= -3,ref_date=qArg02,added_date=NOW();
  END IF;
  UPDATE mra1_encounter_icd_codes SET hcc_alert_status=1 WHERE entry_nr=qArg00;
 ELSE
  SET v1tmp = (SELECT nr FROM mra_scorecard_alerts WHERE `TYPE`='HCC' AND origid=qArg01 AND ref_detail LIKE CONCAT('HCC',qArg03,'-%') AND YEAR(ref_date)=m1pp AND resolved_by IS NULL LIMIT 1);
  IF v1tmp IS NOT NULL THEN
   UPDATE mra_scorecard_alerts SET current_status=4,ref_id= -2,resolved_date=vResolvedDate,resolved_by='system' WHERE nr=v1tmp;
   UPDATE mra1_encounter_icd_codes SET hcc_alert_status=2 WHERE entry_nr=qArg00;
  END IF;
 END IF; 

 INSERT INTO mra_00_tmp SET mdd_1='MRA_SET01_Patient_HCC_Alerts_01',mdd_2=qArg00,mdd_3=qArg01;

 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_SET01_Patient_HCC_Alerts_new_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_SET01_Patient_HCC_Alerts_new_01`(m1pp INT, m2pp INT)
BEGIN
    DECLARE v1tmp TEXT; 
    DECLARE vResolvedDate VARCHAR(100);
    DECLARE bmc INT DEFAULT 0;
    DECLARE qArg00 BIGINT;
    DECLARE qArg01 VARCHAR(100);
    DECLARE qArg02 VARCHAR(100);
    DECLARE qArg03 VARCHAR(100);
    DECLARE qArg04 VARCHAR(100);


    DECLARE mrw CURSOR FOR 
        SELECT pd.entry_nr, pd.patient_id, pd.onset_date, pd.hcc_level, pd.diagnosis_code 
        FROM mra1_encounter_icd_codes pd             
        
        WHERE pd.hcc_inc = 1 
            AND pd.hcc_level > 0 
            AND YEAR(pd.onset_date) = m1pp 
        GROUP BY pd.patient_id, pd.hcc_level, pd.diagnosis_code 
        ORDER BY pd.onset_date DESC;

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

    TRUNCATE mra_00_tmp;
    
DROP TABLE IF EXISTS Patients_for_Alert; 
DROP TABLE IF EXISTS Patients_for_Resolved;

/*
DROP TABLE IF EXISTS log_hcc_resolved;
DROP TABLE IF EXISTS log_hcc_unresolved;
*/

DROP TABLE IF EXISTS mra_hcc_tbl_base_hierarchy;  
/*
DROP TABLE IF EXISTS mra1_encounter_icd_codes_m2pp; 

CREATE TEMPORARY TABLE mra1_encounter_icd_codes_m2pp
(INDEX my_index_1 (patient_id,nc))
SELECT DISTINCT patient_id , hcc_level nc
        FROM mra1_encounter_icd_codes 
        WHERE hcc_inc = 1 AND hcc_level > 0 AND YEAR(onset_date) = m2pp;
        */

CREATE TEMPORARY TABLE mra_hcc_tbl_base_hierarchy
(INDEX my_index_2 (HCC_Code))
SELECT hcc_sub_nr HCC_Code ,IF (hcc_sub_nr=hcc_header_nr,GROUP_CONCAT(DISTINCT hcc_header_nr),CONCAT(hcc_sub_nr,',',GROUP_CONCAT(DISTINCT hcc_header_nr))) Relevent_Codes
,'Relevent Codes' AS relation
FROM 
(
SELECT hcc_header_nr, hcc_sub_nr ,'Parents at left' AS relation FROM 
mra_hcc_hierarchy_assocs
UNION 
SELECT DISTINCT hcc_header_nr, hcc_header_nr self_parent ,'Parents at left' AS relation FROM 
mra_hcc_hierarchy_assocs WHERE hcc_header_nr != ALL (SELECT DISTINCT hcc_sub_nr FROM 
mra_hcc_hierarchy_assocs)
UNION 
SELECT hcc_sub_nr AS hcc_sub_nr_  , hcc_header_nr AS hcc_header_nr_ ,'Childs on left' AS relation FROM 
mra_hcc_hierarchy_assocs
/*
UNION 
SELECT  DISTINCT hcc_sub_nr hcc_header_nr_, hcc_sub_nr self_child ,'Childs on left' AS relation FROM 
mra_hcc_hierarchy_assocs WHERE hcc_sub_nr != ALL (SELECT DISTINCT hcc_header_nr FROM 
mra_hcc_hierarchy_assocs)
*/
) AS Base_Hierarchy_Table

GROUP BY hcc_sub_nr;
   
CREATE TEMPORARY TABLE Patients_for_Alert  
(PRIMARY KEY my_pk_1 (entry_nr),INDEX my_index_3 (patient_id,hcc_level))
SELECT past_data.* FROM
(
SELECT DISTINCT current_year_data.entry_nr, current_year_data.patient_id , current_year_data.onset_date, current_year_data.hcc_level , current_year_data.diagnosis_code 
        FROM mra1_encounter_icd_codes AS current_year_data
        
        WHERE current_year_data.hcc_inc = 1 AND current_year_data.hcc_level > 0 
        AND YEAR(current_year_data.onset_date) = m1pp
        
        /*GROUP BY patient_id, hcc_level, diagnosis_code */ 
) AS past_data


WHERE  NOT FIND_IN_SET(past_data.hcc_level , (


SELECT GROUP_CONCAT(DISTINCT hcc_hierarchy.Relevent_Codes) Relevent_Codes FROM 

(
SELECT DISTINCT patient_id , hcc_level nc
        FROM mra1_encounter_icd_codes 
        WHERE hcc_inc = 1 AND hcc_level > 0 AND YEAR(onset_date) = m2pp
) AS current_data INNER JOIN mra_hcc_tbl_base_hierarchy AS hcc_hierarchy



ON current_data.nc=hcc_hierarchy.HCC_Code
WHERE current_data.patient_id = past_data.patient_id
GROUP BY current_data.patient_id

)
);



CREATE TEMPORARY TABLE Patients_for_Resolved 
(PRIMARY KEY my_pk_2 (entry_nr),INDEX my_index_4 (patient_id,hcc_level))
SELECT past_data.*   FROM
(
SELECT DISTINCT current_year_data.entry_nr, current_year_data.patient_id , current_year_data.onset_date, current_year_data.hcc_level , current_year_data.diagnosis_code 
        FROM mra1_encounter_icd_codes AS current_year_data
        
        WHERE current_year_data.hcc_inc = 1 AND current_year_data.hcc_level > 0 
        AND YEAR(current_year_data.onset_date) = m1pp
        
        /*GROUP BY patient_id, hcc_level, diagnosis_code */ 
) AS past_data

WHERE  FIND_IN_SET(past_data.hcc_level , (


SELECT GROUP_CONCAT(DISTINCT hcc_hierarchy.Relevent_Codes) Relevent_Codes FROM 

(
SELECT DISTINCT patient_id , hcc_level nc
        FROM mra1_encounter_icd_codes 
        WHERE hcc_inc = 1 AND hcc_level > 0 AND YEAR(onset_date) = m2pp
) AS current_data INNER JOIN mra_hcc_tbl_base_hierarchy AS hcc_hierarchy



ON current_data.nc=hcc_hierarchy.HCC_Code
WHERE current_data.patient_id = past_data.patient_id
GROUP BY current_data.patient_id

)
);

    
    OPEN mrw;
    read_loop: LOOP
        IF bmc = 1 THEN LEAVE read_loop; END IF;
        
        FETCH mrw INTO qArg00, qArg01, qArg02, qArg03, qArg04;
        
        IF bmc = 0 THEN
            SET vResolvedDate = (
                SELECT pfa.onset_date FROM Patients_for_Alert pfa 
                /*INNER JOIN mra1_encounter_icd_codes_m2pp mra_codes
                ON pfa.patient_id = mra_codes.patient_id*/
                
                WHERE 
                /*
                    hcc_inc = 1 
                    AND YEAR(onset_date) = m2pp 
                    */
                    pfa.patient_id = qArg01 
                    AND pfa.hcc_level = qArg03 
                    AND pfa.entry_nr = qArg00                     
                    
                ORDER BY pfa.onset_date DESC LIMIT 1
            );

            IF vResolvedDate IS NOT NULL THEN
                SET v1tmp = (
                    SELECT nr 
                    FROM mra_scorecard_alerts 
                    WHERE `TYPE` = 'HCC' 
                        AND origid = qArg01 
                        AND ref_detail LIKE CONCAT('HCC', qArg03, '-%') 
                        AND YEAR(ref_date) = m1pp 
                    LIMIT 1
                );

                IF v1tmp IS NULL THEN
                    INSERT INTO mra_scorecard_alerts 
                    SET `TYPE` = 'HCC', origid = qArg01, ref_detail = CONCAT('HCC', qArg03, '-', qArg04), 
                       
                     ref_description = (SELECT CONCAT('HCC', mhhd.hcc_id, '-',mhhd.hcc_description) FROM mra_hcc_hierarchy_desc  mhhd 
                        WHERE mhhd.hcc_id = qArg03),
                       
                         original_status = 1, current_status = 1, ref_id = -3, ref_date = qArg02, added_date = NOW();
                         
                 ELSE
                 
                  UPDATE mra_scorecard_alerts 
               SET original_status = 1,current_status = 1, ref_id = -3,ref_date = qArg02, added_date = NOW(), resolved_date = NULL, resolved_by = NULL
                /*ack_date = NULL, ack_by = NULL, ack_notes = NULL*/
                    WHERE nr = v1tmp ;/*and current_status != 1;*/
                    
                         
                END IF;

                UPDATE mra1_encounter_icd_codes 
                SET hcc_alert_status = 1 
                WHERE entry_nr = qArg00;
            ELSE
                SET v1tmp = (
                    SELECT nr 
                    FROM mra_scorecard_alerts 
                    WHERE `TYPE` = 'HCC' 
                        AND origid = qArg01 
                        AND ref_detail LIKE CONCAT('HCC', qArg03, '-%') 
                        AND YEAR(ref_date) = m1pp 
                        AND resolved_by IS NULL 
                    LIMIT 1
                );

                IF v1tmp IS NOT NULL THEN
                    UPDATE mra_scorecard_alerts 
                    SET current_status = 4, ref_id = -2, resolved_date = vResolvedDate, resolved_by = 'system' 
                    WHERE nr = v1tmp;

                    UPDATE mra1_encounter_icd_codes 
                    SET hcc_alert_status = 2 
                    WHERE entry_nr = qArg00;
                END IF;
            END IF; 

            INSERT INTO mra_00_tmp 
            SET mdd_1 = 'MRA_SET01_Patient_HCC_Alerts_01', mdd_2 = qArg00, mdd_3 = qArg01;
        END IF;
    END LOOP;
    CLOSE mrw;
    
INSERT INTO  log_hcc_resolved( entry_nr,patient_id,onset_date,hcc_level,diagnosis_code,Actual_Codes_Found,State,Due_To_Relevent_Codes,Log_Time_Stamp)  
SELECT pfr.entry_nr, pfr.patient_id , pfr.onset_date, pfr.hcc_level , pfr.diagnosis_code,codes_with_hierarchy.nc AS Actual_Codes_Found,
'Resolved' AS State ,Relevent_Codes Due_To_Relevent_Codes,NOW() AS Log_Time_Stamp
FROM Patients_for_Resolved pfr

LEFT JOIN

(


SELECT current_data.patient_id,GROUP_CONCAT(current_data.nc) AS nc,GROUP_CONCAT(DISTINCT hcc_hierarchy.Relevent_Codes) Relevent_Codes FROM 

(
SELECT DISTINCT patient_id , hcc_level nc
        FROM mra1_encounter_icd_codes 
        WHERE hcc_inc = 1 AND hcc_level > 0 AND YEAR(onset_date) = m2pp
) AS current_data INNER JOIN mra_hcc_tbl_base_hierarchy AS hcc_hierarchy



ON current_data.nc=hcc_hierarchy.HCC_Code

GROUP BY current_data.patient_id

) AS codes_with_hierarchy

ON pfr.patient_id=codes_with_hierarchy.patient_id;


INSERT INTO log_hcc_unresolved (entry_nr,patient_id,onset_date,hcc_level,diagnosis_code,Actual_Codes_Found,State,Due_To_Relevent_Codes,Log_Time_Stamp) 

SELECT pfa.entry_nr, pfa.patient_id , pfa.onset_date, pfa.hcc_level , pfa.diagnosis_code,codes_with_hierarchy.nc AS Actual_Codes_Found,
'Un Resolved' AS State ,Relevent_Codes Due_To_Relevent_Codes, NOW() AS Log_Time_Stamp
FROM Patients_for_Alert pfa

LEFT JOIN

(


SELECT current_data.patient_id,GROUP_CONCAT(current_data.nc) AS nc,GROUP_CONCAT(DISTINCT hcc_hierarchy_.Relevent_Codes) Relevent_Codes FROM 

(
SELECT DISTINCT patient_id , hcc_level nc
        FROM mra1_encounter_icd_codes 
        WHERE hcc_inc = 1 AND hcc_level > 0 AND YEAR(onset_date) = m2pp
) AS current_data INNER JOIN mra_hcc_tbl_base_hierarchy AS hcc_hierarchy_



ON current_data.nc=hcc_hierarchy_.HCC_Code

GROUP BY current_data.patient_id

) AS codes_with_hierarchy

ON pfa.patient_id=codes_with_hierarchy.patient_id;    
    
    
END */$$
DELIMITER ;

