        */

CREATE TEMPORARY TABLE mra_hcc_tbl_base_hierarchy
(INDEX my_index_2 (HCC_Code))
SELECT hcc_sub_nr HCC_Code ,IF (hcc_sub_nr=hcc_header_nr,GROUP_CONCAT(DISTINCT hcc_header_nr),CONCAT(hcc_sub_nr,',',GROUP_CONCAT(DISTINCT hcc_header_nr))) Relevent_Codes
,'Relevent Codes' AS relation,  ver AS vesion_no
FROM 
(
SELECT hcc_header_nr, hcc_sub_nr ,'Parents at left' AS relation FROM 
bt_static.mra_hcc_hierarchy_assocs
WHERE `version`= ver
UNION 
SELECT DISTINCT hcc_header_nr, hcc_header_nr self_parent ,'Parents at left' AS relation FROM 
bt_static.mra_hcc_hierarchy_assocs WHERE hcc_header_nr != ALL (SELECT DISTINCT hcc_sub_nr FROM 
bt_static.mra_hcc_hierarchy_assocs) and `version`= ver
UNION 
SELECT hcc_sub_nr AS hcc_sub_nr_  , hcc_header_nr AS hcc_header_nr_ ,'Childs on left' AS relation FROM 
bt_static.mra_hcc_hierarchy_assocs WHERE `version`= ver
/*
UNION 
SELECT  DISTINCT hcc_sub_nr hcc_header_nr_, hcc_sub_nr self_child ,'Childs on left' AS relation FROM 
bt_static.mra_hcc_hierarchy_assocs WHERE hcc_sub_nr != ALL (SELECT DISTINCT hcc_header_nr FROM 
bt_static.mra_hcc_hierarchy_assocs) and  `version`= ver
*/
) AS Base_Hierarchy_Table

GROUP BY hcc_sub_nr;
   
CREATE TEMPORARY TABLE Patients_for_Alert  
(PRIMARY KEY my_pk_1 (entry_nr),INDEX my_index_3 (patient_id,hcc_level))
