/* Procedure structure for procedure `MRA_SET02_Patient_HCC_Alerts_new_03` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_SET02_Patient_HCC_Alerts_new_03`(
    IN m1pp INT,
    IN m2pp INT,
    IN ver INT,
    IN optional_patient_id VARCHAR(100)
)
BEGIN
    DECLARE v1tmp TEXT; 
    DECLARE vResolvedDate VARCHAR(100);
    DECLARE bmc INT DEFAULT 0;
    DECLARE qArg00 BIGINT;
    DECLARE qArg01 VARCHAR(100);
    DECLARE qArg02 VARCHAR(100);
    DECLARE qArg03 VARCHAR(100);
    DECLARE qArg04 VARCHAR(100);
    DECLARE mrw CURSOR FOR 
        SELECT pd.entry_nr, pd.patient_id, pd.onset_date, pd.hcc_level, pd.diagnosis_code 
        FROM mra1_encounter_icd_codes pd
        WHERE pd.hcc_inc = 1 
            AND pd.hcc_level > 0 
            AND YEAR(pd.onset_date) = m1pp
            AND (optional_patient_id IS NULL OR pd.patient_id = optional_patient_id)
        GROUP BY pd.patient_id, pd.hcc_level, pd.diagnosis_code 
        ORDER BY pd.onset_date DESC;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
    TRUNCATE mra_00_tmp;
    DROP TEMPORARY TABLE IF EXISTS Patients_for_Alert; 
    DROP TEMPORARY TABLE IF EXISTS Patients_for_Resolved;
    DROP TEMPORARY TABLE IF EXISTS mra_hcc_tbl_base_hierarchy;
    CREATE TEMPORARY TABLE mra_hcc_tbl_base_hierarchy
    (INDEX my_index_2 (HCC_Code))
    SELECT hcc_sub_nr AS HCC_Code,
           GROUP_CONCAT(DISTINCT hcc_header_nr) AS Relevent_Codes,
           'Relevent Codes' AS relation,
           ver AS vesion_no
    FROM (
        SELECT hcc_header_nr, hcc_sub_nr FROM bt_static.mra_hcc_hierarchy_assocs WHERE `version` = ver
        UNION
        SELECT hcc_header_nr, hcc_header_nr FROM bt_static.mra_hcc_hierarchy_assocs WHERE hcc_header_nr NOT IN (
            SELECT DISTINCT hcc_sub_nr FROM bt_static.mra_hcc_hierarchy_assocs WHERE `version` = ver
        ) AND `version` = ver
    ) AS Base_Hierarchy_Table
    GROUP BY hcc_sub_nr;
    -- Create Patient-for-Resolved based on join (not FIND_IN_SET)
    CREATE TEMPORARY TABLE Patients_for_Resolved 
    (PRIMARY KEY (entry_nr), INDEX (patient_id, hcc_level))
    SELECT DISTINCT cur.entry_nr, cur.patient_id, cur.onset_date, cur.hcc_level, cur.diagnosis_code
    FROM mra1_encounter_icd_codes cur
    JOIN (
        SELECT DISTINCT patient_id, hcc_level AS nc
        FROM mra1_encounter_icd_codes
        WHERE hcc_inc = 1 AND hcc_level > 0 AND YEAR(onset_date) = m2pp
        AND (optional_patient_id IS NULL OR patient_id = optional_patient_id)
    ) m2
    ON cur.patient_id = m2.patient_id
    JOIN mra_hcc_tbl_base_hierarchy hcc_h ON hcc_h.HCC_Code = m2.nc
    WHERE cur.hcc_inc = 1 AND cur.hcc_level > 0
        AND YEAR(cur.onset_date) = m1pp
        AND FIND_IN_SET(cur.hcc_level, hcc_h.Relevent_Codes);
    -- Patients for Alert: Not in Resolved
    CREATE TEMPORARY TABLE Patients_for_Alert 
    (PRIMARY KEY (entry_nr), INDEX (patient_id, hcc_level))
    SELECT DISTINCT cur.entry_nr, cur.patient_id, cur.onset_date, cur.hcc_level, cur.diagnosis_code
    FROM mra1_encounter_icd_codes cur
    WHERE cur.hcc_inc = 1 AND cur.hcc_level > 0 
        AND YEAR(cur.onset_date) = m1pp
        AND (optional_patient_id IS NULL OR cur.patient_id = optional_patient_id)
        AND NOT EXISTS (
            SELECT 1 FROM Patients_for_Resolved pfr
            WHERE pfr.entry_nr = cur.entry_nr
        );
    -- Process Alerts
    OPEN mrw;
    read_loop: LOOP
        FETCH mrw INTO qArg00, qArg01, qArg02, qArg03, qArg04;
        IF bmc THEN LEAVE read_loop; END IF;
        -- Check if itâs an alert
        SELECT onset_date INTO vResolvedDate
        FROM Patients_for_Alert
        WHERE entry_nr = qArg00 LIMIT 1;
        IF vResolvedDate IS NOT NULL THEN
            SELECT nr INTO v1tmp FROM mra_scorecard_alerts 
            WHERE `TYPE` = 'HCC' AND version_no = ver AND origid = qArg01 
                AND ref_detail LIKE CONCAT('HCC', qArg03, '-%') 
                AND YEAR(ref_date) = m1pp LIMIT 1;
            IF v1tmp IS NULL THEN
                INSERT INTO mra_scorecard_alerts 
                SET `TYPE` = 'HCC', version_no = ver, origid = qArg01, 
                    ref_detail = CONCAT('HCC', qArg03, '-', qArg04), 
                    ref_description = (
                        SELECT CONCAT('HCC', mhhd.hcc_id, '-', mhhd.hcc_description) 
                        FROM mra_hcc_hierarchy_desc mhhd 
                        WHERE mhhd.hcc_id = qArg03
                    ),
                    original_status = 1, current_status = 1, 
                    ref_id = -3, ref_date = qArg02, added_date = NOW();
            ELSE
                UPDATE mra_scorecard_alerts 
                SET original_status = 1, current_status = 1, 
                    ref_id = -3, ref_date = qArg02, 
                    added_date = NOW(), resolved_date = NULL, resolved_by = NULL
                WHERE nr = v1tmp AND version_no = ver;
            END IF;
            UPDATE mra1_encounter_icd_codes SET hcc_alert_status = 1 WHERE entry_nr = qArg00;
        ELSE -- resolved
            SELECT nr INTO v1tmp FROM mra_scorecard_alerts 
            WHERE `TYPE` = 'HCC' AND version_no = ver AND origid = qArg01 
                AND ref_detail LIKE CONCAT('HCC', qArg03, '-%') 
                AND YEAR(ref_date) = m1pp AND resolved_by IS NULL 
                LIMIT 1;
            IF v1tmp IS NOT NULL THEN
                UPDATE mra_scorecard_alerts 
                SET current_status = 4, ref_id = -2, 
                    resolved_date = NOW(), resolved_by = 'system'
                WHERE nr = v1tmp AND version_no = ver;
                UPDATE mra1_encounter_icd_codes SET hcc_alert_status = 2 WHERE entry_nr = qArg00;
            END IF;
        END IF;
        INSERT INTO mra_00_tmp 
        SET mdd_1 = 'MRA_SET02_Patient_HCC_Alerts_new_03', 
            mdd_2 = qArg00, mdd_3 = qArg01, version_no = ver;
    END LOOP;
    CLOSE mrw;
    -- Logging
    INSERT INTO log_hcc_resolved(entry_nr, patient_id, onset_date, hcc_level, diagnosis_code,
        Actual_Codes_Found, State, Due_To_Relevent_Codes, Log_Time_Stamp, for_version)
    SELECT pfr.entry_nr, pfr.patient_id, pfr.onset_date, pfr.hcc_level, pfr.diagnosis_code,
           hcc_data.nc, 'Resolved', hcc_data.Relevent_Codes, NOW(), ver
    FROM Patients_for_Resolved pfr
    LEFT JOIN (
        SELECT m2.patient_id, GROUP_CONCAT(DISTINCT m2.nc) AS nc,
               GROUP_CONCAT(DISTINCT hcc_h.Relevent_Codes) AS Relevent_Codes
        FROM (
            SELECT DISTINCT patient_id, hcc_level AS nc
            FROM mra1_encounter_icd_codes
            WHERE hcc_inc = 1 AND hcc_level > 0 AND YEAR(onset_date) = m2pp
            AND (optional_patient_id IS NULL OR patient_id = optional_patient_id)
        ) m2
        JOIN mra_hcc_tbl_base_hierarchy hcc_h ON hcc_h.HCC_Code = m2.nc
        GROUP BY m2.patient_id
    ) hcc_data ON hcc_data.patient_id = pfr.patient_id;
    INSERT INTO log_hcc_unresolved(entry_nr, patient_id, onset_date, hcc_level, diagnosis_code,
        Actual_Codes_Found, State, Due_To_Relevent_Codes, Log_Time_Stamp, for_version)
    SELECT pfa.entry_nr, pfa.patient_id, pfa.onset_date, pfa.hcc_level, pfa.diagnosis_code,
           hcc_data.nc, 'Un Resolved', hcc_data.Relevent_Codes, NOW(), ver
    FROM Patients_for_Alert pfa
    LEFT JOIN (
        SELECT m2.patient_id, GROUP_CONCAT(DISTINCT m2.nc) AS nc,
               GROUP_CONCAT(DISTINCT hcc_h.Relevent_Codes) AS Relevent_Codes
        FROM (
            SELECT DISTINCT patient_id, hcc_level AS nc
            FROM mra1_encounter_icd_codes
            WHERE hcc_inc = 1 AND hcc_level > 0 AND YEAR(onset_date) = m2pp
            AND (optional_patient_id IS NULL OR patient_id = optional_patient_id)
        ) m2
        JOIN mra_hcc_tbl_base_hierarchy hcc_h ON hcc_h.HCC_Code = m2.nc
        GROUP BY m2.patient_id
    ) hcc_data ON hcc_data.patient_id = pfa.patient_id;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_SET05_Cm_MoveToHistory_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_SET05_Cm_MoveToHistory_01`()
BEGIN

DECLARE vtmp VARCHAR(100); 

SET vtmp = (SELECT nr FROM ccm_active WHERE expiration_date<DATE_SUB(NOW(), INTERVAL 1 DAY) LIMIT 1);
IF vtmp IS NOT NULL THEN
 INSERT IGNORE INTO ccm_history (origid,encounter_nr,`type`,`status`,onset_date,expiration_date,completed_date,active_period,source,created_by,created_date,assigned_cm,m_ref_nr, m_moved_date,m_source)
 SELECT origid,encounter_nr,`TYPE`,'inactive',onset_date,expiration_date,completed_date,active_period,source,created_by,created_date, assigned_cm,nr,NOW(),'auto_sp_script' FROM ccm_active WHERE expiration_date<DATE_SUB(NOW(), INTERVAL 1 DAY);

 DELETE FROM ccm_active WHERE expiration_date<DATE_SUB(NOW(), INTERVAL 1 DAY) AND encounter_nr IN (SELECT DISTINCT encounter_nr FROM ccm_history);
END IF;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_SET05_TransportationBenefitUsed_01` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_SET05_TransportationBenefitUsed_01`(IN default_argument INT)
BEGIN
DECLARE done INT DEFAULT 0;
DECLARE tt_nr BIGINT; DECLARE origid_val VARCHAR(100);
DECLARE lastname_val, firstname_val, facility_nr_val, facility_name_val, facility_sub_nr_val, facility_sub_name_val, birthdate_val, phone_1_code_val, phone_1_nr_val, dce_provider_name_val, addr_str_val, dce_prov_npi_nr_val VARCHAR(100);
DECLARE facility_sub_name_temp VARCHAR(100);
DECLARE member_type_temp VARCHAR(25);
DECLARE mrw CURSOR FOR
    SELECT
    t.nr,
        t.orig_id,
        p.lastname,
        p.firstname,
        p.facility_nr,
        p.facility_name,
        p.facility_sub_nr,
        p.birthdate,
        p.phone_1_code,
        p.phone_1_nr,
        p.sp_dr_1 AS dce_provider_name,
        p.addr_str,
        p.sp_dr_1_npi AS dce_prov_npi_nr
    FROM
        transportation_benefit t
    INNER JOIN
        patient p ON t.orig_id = p.origid
    WHERE
        t.map_data_status = 0;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;
OPEN mrw;
read_loop: LOOP
    IF done = 1 THEN
        LEAVE read_loop;
    END IF;
    FETCH mrw INTO
    tt_nr,
        origid_val,
        lastname_val,
        firstname_val,
        facility_nr_val,
        facility_name_val,
        facility_sub_nr_val,
        birthdate_val,
        phone_1_code_val,
        phone_1_nr_val,
        dce_provider_name_val,
        addr_str_val,
        dce_prov_npi_nr_val;
 IF done = 0 THEN
  SET facility_sub_name_temp=(SELECT `NAME` FROM hospital_centers WHERE nr = facility_sub_nr_val LIMIT 1);
   SET member_type_temp = (
    SELECT pd.`member_type`
    FROM patient_details pd
    INNER JOIN transportation_benefit t ON pd.origid = t.orig_id
    WHERE t.nr = tt_nr
    LIMIT 1
);

    UPDATE transportation_benefit
    SET
        lastname = lastname_val,
        firstname = firstname_val,
        facility_nr = facility_nr_val,
        facility_name = facility_name_val,
        facility_sub_nr = facility_sub_nr_val,
        facility_sub_name = facility_sub_name_temp,
        birthdate = birthdate_val,
        phone_1_code = phone_1_code_val,
        phone_1_nr = phone_1_nr_val,
        dce_provider_name = dce_provider_name_val,
        addr_str = addr_str_val,
        dce_prov_npi_nr = dce_prov_npi_nr_val,
        member_type=member_type_temp,
        map_data_status = 1
    WHERE
        nr = tt_nr;
END IF;        
        
END LOOP read_loop;
CLOSE mrw;
END */$$
DELIMITER ;

