/* Procedure structure for procedure `MRA_TT_C01_QueryToTempp` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_TT_C01_QueryToTempp`(mpp1 INT)
BEGIN

DECLARE vtmp VARCHAR(100); DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT; DECLARE qArg01 VARCHAR(100); DECLARE qArg02 VARCHAR(20);
DECLARE mrw CURSOR FOR SELECT DISTINCT e.entry_nr,e.patient_id,e.enc_disch_date FROM mra1_encounter e INNER JOIN mra1_encounter_bill_cpts t2 ON t2.encounter_nr=e.encounter_nr WHERE e.proc_type_nr=1 AND (e.is_er_visit=1 OR (enc_pos IN (60,61) AND hos_taxonomy01 IN ('282N00000X','282NC0060X','282NR1301X','282NC2000X','284300000X'))) AND YEAR(e.enc_disch_date)>=mpp1;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp;
INSERT INTO mra_00_tmp SET mdd_1="MRA_A03_72HrFlowUp_Set_z",mdd_2='##START##',mdd_3=1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02;
 IF bmc = 0 THEN

  SET vtmp = (SELECT e.entry_nr FROM mra1_encounter e WHERE e.proc_type_nr IN (1,2) AND e.is_offvisit_rec=1 AND e.patient_id=qArg01 AND DATEDIFF(e.enc_admit_date,qArg02) BETWEEN 0 AND 14 LIMIT 1);
  IF vtmp IS NOT NULL THEN
   UPDATE mra1_encounter SET is_flwup_14_days=1 WHERE entry_nr=qArg00;
  ELSE
   SET vtmp = (SELECT e.entry_nr FROM mra1_encounter e WHERE e.proc_type_nr IN (1,2) AND e.is_offvisit_rec=1 AND e.patient_id=qArg01 AND DATEDIFF(e.enc_admit_date,qArg02) BETWEEN 0 AND 7 LIMIT 1);
   IF vtmp IS NOT NULL THEN
    set vtmp=1;
   ELSE
    SET vtmp = (SELECT e.entry_nr FROM mra1_encounter e WHERE e.proc_type_nr IN (1,2) AND e.is_offvisit_rec=1 AND e.patient_id=qArg01 AND DATEDIFF(e.enc_admit_date,qArg02) BETWEEN 0 AND 3 LIMIT 1);
    IF vtmp IS NOT NULL THEN
     set vtmp=1;
    ELSE
     SET vtmp = (SELECT e.entry_nr FROM mra1_encounter e WHERE e.proc_type_nr IN (1,2) AND e.is_offvisit_rec=1 AND e.patient_id=qArg01 AND DATEDIFF(e.enc_admit_date,qArg02) >14 LIMIT 1);
     IF vtmp IS NOT NULL THEN
      UPDATE mra1_encounter SET is_gflwup_14_days=1 WHERE entry_nr=qArg00;
     END IF;
    END IF;    
   END IF;   
  END IF;

  INSERT INTO mra_00_tmp SET mdd_1="MRA_A03_72HrFlowUp_Set_z",mdd_2=qArg00,mdd_3=1;

 END IF;
END LOOP;
CLOSE mrw;


END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_TT_C02_QueryToTempp` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_TT_C02_QueryToTempp`()
BEGIN

DECLARE vtmp VARCHAR(900); DECLARE v11tmp VARCHAR(900);
DECLARE v21tmp INT DEFAULT 0;

DECLARE mi INT DEFAULT 0;DECLARE m2i INT DEFAULT 0;
DECLARE bmc INT DEFAULT 0;

DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);DECLARE qArg04 VARCHAR(100);DECLARE qArg05 VARCHAR(100);DECLARE qArg06 VARCHAR(100);

DECLARE mrw CURSOR FOR SELECT DISTINCT mm_curr_mbi_id FROM dc_bene_alignment_roster WHERE mm_year=2023;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

TRUNCATE mra_00_tmp; TRUNCATE mra_01_tmp;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01;
 IF bmc = 0 THEN

 SET vtmp = (SELECT adi_score FROM mra_adi_score  WHERE origid=qArg01 AND m_year='2023' ORDER BY `version` DESC LIMIT 1);
 IF vtmp IS NOT NULL THEN
  UPDATE dc_bene_alignment_roster SET mra_adi_score=vtmp WHERE mm_year='2023' AND mm_curr_mbi_id=qArg01;
  UPDATE dc_bene_alignment_rostr_m01 SET mra_adi_score=vtmp WHERE mm_year='2023' AND mm_curr_mbi_id=qArg01;
  SET m2i=m2i+1;
 END IF;

 INSERT INTO mra_00_tmp SET mdd_1="MRA_TT_C01_QueryToTempp",mdd_2=mi,mdd_3=m2i,mdd_4=qArg01;
 SET mi=mi+1;

 END IF;
END LOOP;
CLOSE mrw;
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_TT_C99_QueryToTempp` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_TT_C99_QueryToTempp`()
BEGIN
DECLARE bmc INT DEFAULT 0; DECLARE vtmp VARCHAR(500); 
DECLARE v1tmp VARCHAR(500); DECLARE v2tmp VARCHAR(500); DECLARE v3tmp VARCHAR(500); DECLARE v4tmp VARCHAR(500);
DECLARE v5tmp VARCHAR(50);

DECLARE qArg00 BIGINT;DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);DECLARE qArg03 VARCHAR(100);
DECLARE qArg04 VARCHAR(100);

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t1.encounter_nr,t1.origid,t1.encounter_date,COUNT(*) AS 'cnt' FROM encounter t1
WHERE t1.mra_clm_refer_m01='hl7_hie_data' AND t1.mra_clm_refer_m02 IN ('mc_taxes','NJ','mc_ky')
GROUP BY t1.origid,t1.encounter_date, t1.hospital_nr
HAVING cnt > 1;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02,qArg03,qArg04; 
 IF bmc = 0 THEN

 INSERT INTO mra_00_tmp SET mdd_1="MRA_TT_C01_QueryToTempp",mdd_2=qArg01,mdd_3=1;

 SET vtmp = (SELECT t1.encounter_nr FROM encounter t1 WHERE t1.mra_clm_refer_m01='hl7_hie_data' AND t1.mra_clm_refer_m02 IN ('mc_taxes','NJ','mc_ky') AND t1.origid=qArg02 and t1.encounter_date=qArg03 and entry_nr not in (qArg00) limit 1);
 IF vtmp IS NOT NULL THEN  
    INSERT INTO mra_00_tmp SET mdd_1="MRA_TT_C01_QueryToTempp",mdd_2=vtmp,mdd_3=2;
 END IF;
 
 SET v1tmp = (SELECT t1.encounter_nr FROM encounter t1 WHERE t1.mra_clm_refer_m01='hl7_hie_data' AND t1.mra_clm_refer_m02 IN ('mc_taxes','NJ','mc_ky') AND t1.origid=qArg02 AND t1.encounter_date=qArg03 AND entry_nr NOT IN (qArg00, vtmp) LIMIT 1);
 IF v1tmp IS NOT NULL THEN  
    INSERT INTO mra_00_tmp SET mdd_1="MRA_TT_C01_QueryToTempp",mdd_2=v1tmp,mdd_3=2;
 END IF;
 
 SET v2tmp = (SELECT t1.encounter_nr FROM encounter t1 WHERE t1.mra_clm_refer_m01='hl7_hie_data' AND t1.mra_clm_refer_m02 IN ('mc_taxes','NJ','mc_ky') AND t1.origid=qArg02 AND t1.encounter_date=qArg03 AND entry_nr NOT IN (qArg00, vtmp, v1tmp) LIMIT 1);
 IF v2tmp IS NOT NULL THEN  
    INSERT INTO mra_00_tmp SET mdd_1="MRA_TT_C01_QueryToTempp",mdd_2=v2tmp,mdd_3=2;
 END IF;

 END IF;
END LOOP;
CLOSE mrw;

/*

SELECT t1.entry_nr,t1.encounter_nr,t1.origid,t1.encounter_date
,t1.pos,t1.place_of_service,t1.hospital_nr
,t3.facility_nr, t4.name
,t1.appt_confirmed_mra ,t1.care_status ,t1.care_status_notes
 ,t1.follow_up_appt_within
,t1.care_status_personnel , t2.reminder_notes
FROM encounter t1
INNER JOIN patient t3 ON t3.origid=t1.origid
INNER JOIN hospital_centers t4 ON t4.nr=t3.facility_nr
LEFT JOIN reminder_events t2 ON t2.encounter_nr=t1.encounter_nr
WHERE t1.mra_clm_refer_m01='hl7_hie_data' AND t1.mra_clm_refer_m02 IN ('mc_taxes','NJ','mc_ky')
AND t1.encounter_nr IN (SELECT mdd_2 FROM mra_00_tmp WHERE mdd_1="MRA_TT_C01_QueryToTempp")
ORDER BY t1.origid,t1.encounter_date, hospital_nr

*/

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_UFL_BTS_imp11_blq_all_Roster_m3` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_UFL_BTS_imp11_blq_all_Roster_m3`()
BEGIN

 SET @m1cv=(SELECT MAX(cc_version) FROM dc_bene_alignment_rostr_m01 LIMIT 1);

 INSERT INTO mra_00_tmp SET mdd_1='btstatic',mdd_2='imp11blq_acr_roster_z',mdd_3=0;
 UPDATE bt_static.imp11_blq_acr t1 INNER JOIN dc_bene_alignment_rostr_m01 t2 ON t1.MBI=t2.mm_curr_mbi_id
 SET t1.market_id=t2.market_id, t1.dce_group_nr=t2.dce_group_nr, t1.prov_npi_nr=t2.prov_npi_nr,
