 WHERE t2.cc_version=@m1cv AND t1.dce_group_nr IS NULL;
 
 INSERT INTO mra_00_tmp SET mdd_1='btstatic',mdd_2='imp11blq_tfu_roster_z',mdd_3=0;
 UPDATE bt_static.imp11_blq_tfu t1 INNER JOIN dc_bene_alignment_rostr_m01 t2 ON t1.MBI=t2.mm_curr_mbi_id
 SET t1.market_id=t2.market_id, t1.dce_group_nr=t2.dce_group_nr, t1.prov_npi_nr=t2.prov_npi_nr,
  t1.dce_sub_group_nr=t2.dce_sub_group_nr, t1.market_names=t2.market_names, t1.dce_group_name=t2.dce_group_name,
  t1.dce_provider_name=t2.dce_provider_name, t1.dce_sub_group_name=t2.dce_sub_group_name
 WHERE t2.cc_version=@m1cv AND t1.dce_group_nr IS NULL;
 
 INSERT INTO mra_00_tmp SET mdd_1='btstatic',mdd_2='imp11blq_uamcc_roster_z',mdd_3=0;
 UPDATE bt_static.imp11_blq_uamcc t1 INNER JOIN dc_bene_alignment_rostr_m01 t2 ON t1.MBI=t2.mm_curr_mbi_id
 SET t1.market_id=t2.market_id, t1.dce_group_nr=t2.dce_group_nr, t1.prov_npi_nr=t2.prov_npi_nr,
  t1.dce_sub_group_nr=t2.dce_sub_group_nr, t1.market_names=t2.market_names, t1.dce_group_name=t2.dce_group_name,
  t1.dce_provider_name=t2.dce_provider_name, t1.dce_sub_group_name=t2.dce_sub_group_name
 WHERE t2.cc_version=@m1cv AND t1.dce_group_nr IS NULL;

 INSERT INTO mra_00_tmp SET mdd_1='btstatic',mdd_2='imp11_END_ROSTER_z',mdd_3='END';

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_UpdateAlignStatus` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_UpdateAlignStatus`(
    IN mStartDate DATE,
    IN mEndDate DATE,
    IN cc_version VARCHAR(10),
    IN mm_date DATE
)
BEGIN
    -- Validate Inputs
    IF mStartDate IS NULL OR mEndDate IS NULL OR cc_version IS NULL OR mm_date IS NULL THEN
        SIGNAL SQLSTATE '45000' 
        SET MESSAGE_TEXT = 'Error: All parameters (mStartDate, mEndDate, cc_version, mm_date) must be provided.';
    END IF;
    -- Perform the Update
    UPDATE adt_encounter 
    SET align_status_code = 'UAL' 
    WHERE (
        (discharge_date IS NOT NULL AND discharge_date NOT IN ('0000-00-00', '1969-12-31') 
         AND discharge_date BETWEEN mStartDate AND mEndDate)
        OR 
        (discharge_date IS NULL OR discharge_date IN ('0000-00-00', '1969-12-31') 
         AND encounter_date BETWEEN mStartDate AND mEndDate)
    ) 
    AND origid NOT IN (
        SELECT DISTINCT mm_curr_mbi_id 
        FROM mradb_prod.dc_bene_alignment_rostr_m01 t1 
        WHERE t1.cc_version = cc_version 
          AND t1.ALIGN_STATUS_CODE IN ('AL', 'D1Y') 
          AND t1.mm_date = mm_date
    ) 
    AND align_status_code = 'AL';
    
END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_Update_MBI` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_Update_MBI`()
BEGIN

DECLARE _rollback BOOL DEFAULT 0;
DECLARE vtmp VARCHAR(100); DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT; DECLARE qArg01 VARCHAR(100);DECLARE qArg02 VARCHAR(100);

DECLARE mrw CURSOR FOR SELECT DISTINCT t1.origid FROM mradb_prod.sva_data  t1 WHERE ( 
t1.origid IN ( SELECT DISTINCT PRVS_NUM FROM mra_file_static.mra_cclf9 WHERE PRVS_NUM!=mm_curr_mbi_id )  OR 
t1.origid IN ( SELECT DISTINCT CRNT_NUM FROM mra_file_static.mra_cclf9 WHERE CRNT_NUM!=mm_curr_mbi_id ) ) and cc_version=20240701 ;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION SET _rollback = 1;

TRUNCATE mra_00_tmp;
INSERT INTO mra_00_tmp SET mdd_1='MRAIMP4_M03ENC_02_O1',mdd_2='Start',mdd_3=''; 

OPEN mrw;

read_loop: LOOP

 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg01;
 IF bmc = 0 THEN

  INSERT INTO mra_00_tmp SET mdd_1='MRAIMP4_M03ENC_02_O1',mdd_2=qArg01,mdd_3=mpp1;
  SET vtmp=MRA_FN01_GetPatientIDLastCCLF(qArg01);
  IF vtmp IS NULL THEN SET vtmp=qArg01; END IF;
  UPDATE mradb_prod.sva_data SET origid=vtmp WHERE origid=qArg01   AND cc_version=20240701 and origid is not null ;

 END IF;

END LOOP;
CLOSE mrw;

IF `_rollback` THEN
 INSERT INTO mra_01_tmp SET mdd_1='MRAIMP4_M03ENC_02_O1',mdd_2=0,mdd_3='Error',mdd_4=RETURNED_SQLSTATE,mdd_5=MESSAGE_TEXT;
END IF;

END */$$
DELIMITER ;

