/* Procedure structure for procedure `MRA_VV_F11_Mra1Encounter_21` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_VV_F11_Mra1Encounter_21`(mp11 INT,mpp1 INT,mpp2 TINYINT,mpp3 TINYINT)
BEGIN

 DECLARE MV03C VARCHAR(2);

 SET mpp3=mpp2+mpp3; SET MV03C='31';
 IF mpp3=2 THEN SET MV03C='28'; IF mpp1=2024 THEN SET MV03C='29'; END IF;
 ELSEIF mpp3=3 THEN SET MV03C='31'; ELSEIF mpp3=4 THEN SET MV03C='30';
 ELSEIF mpp3=5 THEN SET MV03C='31'; ELSEIF mpp3=6 THEN SET MV03C='30';
 ELSEIF mpp3=7 THEN SET MV03C='31'; ELSEIF mpp3=8 THEN SET MV03C='31';
 ELSEIF mpp3=9 THEN SET MV03C='30'; ELSEIF mpp3=10 THEN SET MV03C='31';
 ELSEIF mpp3=11 THEN SET MV03C='30'; ELSEIF mpp3=12 THEN SET MV03C='31';
 END IF;

 IF mp11=2 THEN
  SELECT * FROM mra4_encounter WHERE enc_disch_date BETWEEN CONCAT(mpp1,'-',mpp2,'-01') AND CONCAT(mpp1,'-',mpp3,'-',MV03C);
 ELSE
  SELECT * FROM mra1_encounter WHERE enc_disch_date BETWEEN CONCAT(mpp1,'-',mpp2,'-01') AND CONCAT(mpp1,'-',mpp3,'-',MV03C);
 END IF;

END */$$
DELIMITER ;

/* Procedure structure for procedure `MRA_VV_F11_Mra1Encounter_31` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_VV_F11_Mra1Encounter_31`(mpp1 INT,mpp2 INT)
BEGIN

 DECLARE mpp3 INT;

 if mpp1<= 0 then set mpp1=1000000; end if;
 SET mpp3=mpp2*mpp1;
 
 SELECT * FROM mra1_encounter ORDER BY entry_nr DESC LIMIT mpp3,mpp1;

END */$$
DELIMITER ;

