/* Procedure structure for procedure `MRA_X2_C02_Q01_m1` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_X2_C02_Q01_m1`()
BEGIN

DECLARE m1pp INT;

DECLARE mmi INT; DECLARE m2mi INT;

SET mmi = 1; SET m2mi = 300;
TRUNCATE mra_00_tmp;

LOOP_M01:  LOOP
 if mmi=1 then
  set m1pp=70114423; /* 70114423 */
 else
  SET m1pp=(select mdd_3 from mra_00_tmp where mdd_1="MRA_X2_C02_QueryToTempp" order by nr desc limit 1);  
 end if;
 CALL MRA_X2_C02_QueryToTempp(m1pp,mmi);
 IF mmi >= m2mi THEN LEAVE  LOOP_M01; END IF;
 SET mmi = mmi + 1;
 ITERATE  LOOP_M01;
END LOOP;
	
END */$$
