/* Procedure structure for procedure `MRA_X2_C02_QueryToTempp` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `MRA_X2_C02_QueryToTempp`(mpp1 BIGINT)
BEGIN

DECLARE bmc INT DEFAULT 0;
DECLARE qArg00 BIGINT; DECLARE qArg01 BIGINT; DECLARE qArg02 VARCHAR(20);

DECLARE mrw CURSOR FOR SELECT t1.entry_nr,t1.encounter_nr,t2.CLM_LINE_DGNS_CD FROM encounter t1 
INNER JOIN mra_file_static.mra_cclf5 t2 ON t2.nr=t1.mra_clm_refer_num
WHERE t1.mra_proc_type_nr=2 AND t1.discharge_date between '2023-10-01' and '2023-12-31' AND t1.entry_nr>=mpp1
ORDER BY t1.entry_nr LIMIT 100000;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;

truncate mra_31_tmp;

OPEN mrw;
read_loop: LOOP
 IF bmc = 1 THEN LEAVE read_loop; END IF;
 FETCH mrw INTO qArg00,qArg01,qArg02;
 IF bmc = 0 THEN
 
  IF LENGTH(`qArg02`)>3 THEN SET qArg02=CONCAT(SUBSTR(`qArg02`,1,3),'.',SUBSTR(`qArg02`,4)); END IF;

  UPDATE mra1_encounter SET m2_icd_princ=qArg02 WHERE encounter_nr=qArg01;
  INSERT INTO mra_31_tmp SET mdd_1="MC01_T21",mdd_2=qArg01,mdd_3=qArg00;

 END IF;
END LOOP;
CLOSE mrw;


END */$$
DELIMITER ;

