DECLARE mrw CURSOR FOR SELECT DISTINCT t1.Id_received FROM mradb_prod.dc_flat_provider_paper_align_rpt_cpy  t1 WHERE ( 
t1.Id_received IN ( SELECT DISTINCT PRVS_NUM FROM mra_file_static.mra_cclf9 WHERE PRVS_NUM!=mm_curr_mbi_id )  OR 
t1.Id_received IN ( SELECT DISTINCT CRNT_NUM FROM mra_file_static.mra_cclf9 WHERE CRNT_NUM!=mm_curr_mbi_id ) )  ;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET bmc = 1;
DECLARE CONTINUE HANDLER FOR SQLEXCEPTION SET _rollback = 1;

TRUNCATE mra_00_tmp;
