/* Procedure structure for procedure `UpdateDeptReceivingForPatients` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `UpdateDeptReceivingForPatients`()
BEGIN
    DECLARE done INT DEFAULT FALSE;
    DECLARE distinct_AssOrigid VARCHAR(255);
    DECLARE msg_id INT;
    DECLARE decrypted_message_to VARCHAR(255);

    -- Cursor to fetch distinct AssOrigid values from message_system
    DECLARE assorigid_cursor CURSOR FOR
        SELECT DISTINCT AssOrigid 
        FROM message_system 
        WHERE AssOrigid IS NOT NULL AND AssOrigid != '' AND AssOrigid != '0';

    -- Cursor to fetch message IDs for the current AssOrigid
    DECLARE msg_cursor CURSOR FOR
        SELECT id 
        FROM message_system 
        WHERE AssOrigid = distinct_AssOrigid;

    -- Cursor to fetch decrypted message_to for each message_id
    DECLARE recepient_cursor CURSOR FOR
        SELECT AES_DECRYPT(message_to, 'Braintree') 
        FROM message_recepient 
        WHERE message_id = msg_id AND msg_to_id = '0';

    -- Declare a single handler for NOT FOUND
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    -- Open the AssOrigid cursor
    OPEN assorigid_cursor;

    assorigid_loop: LOOP
        -- Reset done flag
        SET done = FALSE;

        -- Fetch distinct AssOrigid values
        FETCH assorigid_cursor INTO distinct_AssOrigid;
        IF done THEN
            LEAVE assorigid_loop;
        END IF;

        -- Open the msg_cursor
        OPEN msg_cursor;

        msg_loop: LOOP
            -- Reset done flag
            SET done = FALSE;

            FETCH msg_cursor INTO msg_id;
            IF done THEN
                LEAVE msg_loop;
            END IF;

            -- Open the recepient_cursor
            OPEN recepient_cursor;

            recepient_loop: LOOP
                -- Reset done flag
                SET done = FALSE;

                FETCH recepient_cursor INTO decrypted_message_to;
                IF done THEN
                    LEAVE recepient_loop;
                END IF;

                -- Update department_receiving based on decrypted_message_to
                IF decrypted_message_to IS NOT NULL AND decrypted_message_to != '' THEN
                    IF decrypted_message_to = 'casemanagement@ilumed.com' THEN
                        UPDATE message_system
                        SET department_receiving = 'Short term Case Management'
                        WHERE id = msg_id;
                    ELSEIF decrypted_message_to = 'socialwork@ilumed.com' THEN
                        UPDATE message_system
                        SET department_receiving = 'Social Work'
                        WHERE id = msg_id;
                    ELSEIF decrypted_message_to = 'memberservices@ilumed.com' THEN
                        UPDATE message_system
                        SET department_receiving = 'Member Outreach Services'
                        WHERE id = msg_id;
                    ELSEIF decrypted_message_to = 'coding@ilumed.com' THEN
                        UPDATE message_system
                        SET department_receiving = 'Coding'
                        WHERE id = msg_id;
                    END IF;
                END IF;

            END LOOP;

            -- Close the recepient_cursor after processing
            CLOSE recepient_cursor;

        END LOOP;

        -- Close the msg_cursor after processing all messages for the current AssOrigid
        CLOSE msg_cursor;

    END LOOP;

    -- Close the AssOrigid cursor after processing all AssOrigid values
    CLOSE assorigid_cursor;

END */$$
DELIMITER ;

/* Procedure structure for procedure `update_hospital_name` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `update_hospital_name`(in_old_name VARCHAR(200), in_new_name VARCHAR(200))
BEGIN
	UPDATE encounter_procedure SET procedure_center = in_new_name WHERE  procedure_center =in_old_name;
	UPDATE patient_access_history SET hospital = in_new_name WHERE  hospital =in_old_name;
	UPDATE hospital_centers SET NAME = in_new_name WHERE  NAME =in_old_name;
    END */$$
DELIMITER ;

/* Procedure structure for procedure `update_personell_name` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `update_personell_name`(in_old_name VARCHAR(200), in_new_name VARCHAR(200))
BEGIN
	UPDATE encounter_procedure SET primary_surgen = in_new_name  WHERE primary_surgen = in_old_name;
	UPDATE encounter_procedure SET interventionalist = in_new_name  WHERE interventionalist = in_old_name;	
	UPDATE encounter_procedure SET sign_full_name = in_new_name  WHERE sign_full_name = in_old_name;	
	UPDATE encounter_procedure SET secondary_surgen = in_new_name  WHERE secondary_surgen = in_old_name;
	UPDATE encounter_procedure SET referrer_dr = in_new_name  WHERE referrer_dr = in_old_name;
	UPDATE encounter_procedure SET nephrologist = in_new_name  WHERE nephrologist = in_old_name;
	UPDATE encounter SET referrer_dr = in_new_name  WHERE referrer_dr = in_old_name;
	UPDATE appointment SET to_personell_name = in_new_name WHERE to_personell_name = in_old_name;
	UPDATE patient_access_history SET placed_doctor_name = in_new_name  WHERE placed_doctor_name = in_old_name;
	UPDATE patient_access_history SET placed_other_name = in_new_name  WHERE placed_other_name = in_old_name;
	UPDATE study SET readingphysician = in_new_name  WHERE readingphysician = in_old_name;
	UPDATE study SET referringphysician = in_new_name  WHERE referringphysician = in_old_name;
	UPDATE personell SET NAME = in_new_name  WHERE NAME = in_old_name;
    END */$$
DELIMITER ;

/* Procedure structure for procedure `ZOHO_care_Plan` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `ZOHO_care_Plan`()
BEGIN

SELECT  p.origid AS 'Member Id',
	CONCAT(TRIM(p.lastname),' ',TRIM(p.firstname)) AS 'Member Name',
	market_name AS 'ACO Market',
	cp.careplan_name AS 'Care Plan Name',
	dba.dce_provider_name AS 'ACO Provider',
	dba.dce_group_name AS 'ACO Group',
	dba.dce_sub_group_name AS 'ACO SUB Group',
	DATE_FORMAT(p.birthdate,'%m/%d/%Y') AS 'Date of Birth' ,
	plan_riskfactor AS 'Plan Risk Factor',
	plan_barriers AS 'Plan Barriers',
	plan_goals AS 'Plan Goals',
	plan_treatment AS 'Plan Treatment',
	cpp.plan_created_by AS 'Plan Created By',
	DATE_FORMAT(cpp.plan_start_date,'%m/%d/%Y') AS 'Plan Start Date',
	DATE_FORMAT(cpp.plan_inactive_datetime,'%m/%d/%Y') AS 'Plan Inactive Datetime',
	cpp.mra_provider_status AS 'Provider Status',
	
	dba.market_id As "ACO Market ID",
	dba.dce_group_nr "ACO Group ID",
	dba.dce_sub_group_nr "ACO Sub Group ID",
	dba.prov_npi_nr "ACO Provider ID"
	FROM care_plan_patient cpp
	INNER JOIN patient p ON cpp.origid=p.origid 
	INNER JOIN care_plan AS cp ON cp.careplan_id=cpp.cp_id 
	INNER JOIN dc_bene_alignment_rostr_m01 dba ON dba.mm_curr_mbi_id=cpp.origid 
	INNER JOIN `hospital_market_assocs` hms ON hms.hosp_id=p.facility_nr 
	INNER JOIN `hospital_market` hm ON hm.market_id=hms.market_id 
	WHERE dba.ALIGN_STATUS_CODE IN ('AL','D1Y') 
	AND dba.cc_version  IN
	(
 	SELECT MAX(cc_version)
	FROM  dc_bene_alignment_rostr_m01 
	)
	AND dba.mm_date  IN
	(
 	SELECT MAX(mm_date)
	FROM  dc_bene_alignment_rostr_m01 
	)
      ;



END */$$
DELIMITER ;

/* Procedure structure for procedure `ZOHO_CM_Summary` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `ZOHO_CM_Summary`()
BEGIN

TRUNCATE TABLE cm_summary_new;

INSERT INTO cm_summary_new (

`CM Label`,
`Reminder`,
`ACO Market`,
`ACO Group`,
`ACO Sub Group`,
`ACO Provider`,
`Member Name`,
`Member ID`,
`DOB`,
`State Code`,
`City`,
`Phone Number`,
`Cell Phone`,
`Call Status`,
`Role Type`,
`Reminder Type`,
`Category`,
`Continuation Note`,
`Action Item`,
`CM type`,
`Date`,
`Case Manager`,
`User Id`,
`ACO Market ID`,
`ACO Group ID`,
`ACO Sub Group ID`,
`ACO Provider ID`,
`Encounter ID`,
`Alignment Status`,
last_access_time,
rncc_action_item
)

SELECT 
`CM Label`,
 `Reminder`,
`ACO Market`,
`ACO Group`,
`ACO Sub Group`,
`ACO Provider`,
`Member Name`,
`Member ID`,
 DOB,
`State Code`,
`City`,
`Phone Number`,
`Cell Phone`,       
`Call Status`,
`Role Type`,
`Reminder Type`,
`Category`,
`Continuation Note`,
`Action Item`,
`CM type`,
 `Date`,
`Case Manager`,
`User Id` ,
`ACO Market ID`,
`ACO Group ID`,
`ACO Sub Group ID`,
`ACO Provider ID`,
`Encounter ID`,
`Alignment Status`,
last_access_time,
rncc_action_item 
FROM 
(       
SELECT 
'All' AS 'CM Label',
r.reminder_id  AS 'Reminder',
market_name  AS 'ACO Market',
dce_group_name AS `ACO GROUP`,
IF(dce_sub_group_name  = 'NULL', '', dce_sub_group_name) AS `ACO Sub Group`,
dce_provider_name AS `ACO Provider`,
CONCAT(dba.BENE_F_NAME, ' ', dba.BENE_L_NAME) AS `Member NAME`,
dba.mm_curr_mbi_id AS `Member ID`,
dba.BENE_BIRTH_DATE AS DOB,
dba.BENE_USPS_STATE_CODE AS `State Code`,
dba.BENE_CITY AS `City`,
CONCAT(p.phone_1_code, ' ', p.phone_1_nr) AS `Phone Number`,
p.cellphone_2_nr AS "Cell Phone",       
r.reminder_name  AS 'Call Status',
pr.job_type_nr AS `Role Type`,
r.reminder_type AS `Reminder Type`,
r.category  AS 'Category',
r.reminder_des AS 'Continuation Note',
r.census_item as rncc_action_item,
CASE
WHEN r.`declined_cm` = '' THEN 'Empty'
ELSE r.`declined_cm`
END AS 'Action Item',
'Unknown' AS 'CM type',
r.created_date AS "Date",
r.signature AS `Case Manager`,
IF(r.created_by='migration_script',r.signature,r.created_by) AS `User Id` ,
dba.market_id AS "ACO Market ID",
dce_group_nr AS "ACO Group ID",
dce_sub_group_nr AS "ACO Sub Group ID",
prov_npi_nr AS "ACO Provider ID",
r.encounter_nr AS "Encounter ID",
dba.`ALIGN_STATUS_CODE` AS "Alignment Status",
r.last_access_time
FROM reminder_events r 
INNER JOIN dc_bene_alignment_rostr_m01 dba ON r.origid=dba.BENE_MBI_ID 
INNER JOIN patient p ON r.origid=p.origid 
INNER JOIN personell per ON per.name=r.signature
INNER JOIN hospital_market_assocs hm ON p.facility_nr=hm.hosp_id
INNER JOIN `hospital_market` m ON m.market_id=hm.market_id 
INNER JOIN personell_roles pr ON pr.personell_nr = per.nr
INNER JOIN personnel_dept_assocs  pda ON  pda.personnel_nr= per.nr
WHERE r.signature NOT IN  ('admin','') 


AND dba.cc_version IN
    (
    SELECT MAX(cc_version)
    FROM  dc_bene_alignment_rostr_m01 
    )
AND dba.mm_date   IN
    (
    SELECT MAX(mm_date)
    FROM  dc_bene_alignment_rostr_m01 
    where cc_version in (SELECT MAX(cc_version)
    FROM  dc_bene_alignment_rostr_m01)
    )
AND pr.job_type_nr IN (116,121,123,124,125)
GROUP BY r.reminder_id
) r

;



END */$$
DELIMITER ;

