/* Procedure structure for procedure `ZOHO_Continuous_Notes` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `ZOHO_Continuous_Notes`()
BEGIN

SELECT

    hm.market_name AS 'ACO Market',   
    p.facility_name AS `ACO Group`,
    (SELECT IF( NAME  = NULL, '', NAME) FROM hospital_centers WHERE nr=p.facility_sub_nr) AS 'ACO Sub Group',
    
    p.sp_dr_1 AS `ACO Provider`,
    CONCAT(p.lastname,' ',p.firstname) AS `Member NAME`,
    p.origid AS `Member ID`,
    DATE_FORMAT(p.birthdate,'%m/%d/%Y')  AS DOB,

    hm.market_id AS "ACO Market ID",
    p.facility_nr "ACO Group ID",
    p.facility_sub_nr "ACO Sub Group ID",
    p.sp_dr_1_npi "ACO Provider ID",
    r.reminder_notes_auditor,
    r.reminder_id,
    r.signature AS 'Created By',
    r.category AS 'Category',
CASE
WHEN r.reminder_type  = 'External Office' THEN 'External Office'
WHEN r.reminder_type  = 'CMOS_NOTES' THEN 'CMOS_NOTES'
WHEN r.reminder_type  = 'CCM_NOTES' THEN 'CCM_NOTES'
WHEN r.reminder_type  = 'Census_Notes' THEN 'Census_Notes'
WHEN r.reminder_type  = 'Long Term' THEN 'Long Term'
WHEN r.reminder_type  = 'SW_MNGT' THEN 'SW_MNGT'
WHEN r.reminder_type  = 'PROPS_NOTES' THEN 'PROPS_NOTES'
WHEN r.reminder_type  = 'HCC_NOTES' THEN 'HCC_NOTES'
WHEN r.reminder_type  = 'OUTREACH_NOTES' THEN 'OUTREACH_NOTES'
WHEN r.reminder_type  = 'CCM_MNGT' THEN 'CCM_MNGT'
ELSE 'Unknown'
END AS 'Type',    
    
    r.various_reasons,
    DATE_FORMAT(r.created_date,'%m/%d/%Y') AS `Date`,
    r.reminder_des AS 'Continuation Notes',
    
    
CASE
WHEN r.declined_cm  = 'ADT follow up appt made' THEN 'ADT follow up appt made'
WHEN r.declined_cm  = 'Declined CM' THEN 'Declined CM'
WHEN r.declined_cm  = 'DNC' THEN 'DNC'
WHEN r.declined_cm  = 'Enrolled' THEN 'Enrolled'
WHEN r.declined_cm  = 'Enrolled- No Scheduled Call Time' THEN 'Enrolled- No Scheduled Call Time'
WHEN r.declined_cm  = 'Enrolled- Time Scheduled' THEN 'Enrolled- Time Scheduled'
WHEN r.declined_cm  = 'Not enrolled' THEN 'Not enrolled'
ELSE 'Unknown'
END AS 'Action Item'      
    
  FROM patient p 
  INNER  JOIN reminder_events r ON r.origid=p.origid
  JOIN `hospital_market_assocs` hms ON  hms.hosp_id=p.facility_nr
  JOIN `hospital_market` hm ON hm.market_id=hms.market_id 
  
    GROUP BY r.created_date,r.origid 
      ;
  
 


END */$$
DELIMITER ;

/* Procedure structure for procedure `ZOHO_Global_Alerts` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `ZOHO_Global_Alerts`()
BEGIN


SELECT DISTINCT
(p.origid) AS "Member ID",
CONCAT(p.lastname, ' ', p.firstname) AS "Member Name",
DATE_FORMAT(dba.BENE_BIRTH_DATE, '%m/%d/%Y') AS "DOB",
dba.market_names AS 'ACO Market',
dba.dce_group_name AS `ACO GROUP`,
IF(dba.dce_sub_group_name  = 'NULL', '', dba.dce_sub_group_name) AS `ACO Sub Group`,
dba.dce_provider_name AS `ACO Provider`,
'DO NOT CALL' AS TYPE,
IF(p.is_alert_research  = 1, 'Yes', 'No') AS VALUE,
p.alert_note_research AS 'NOTES',
DATE_FORMAT(p.global_alerts_date, '%m/%d/%Y') AS "Date",
dba.market_id AS 'ACO Market ID',
dba.dce_group_nr AS 'ACO Group ID',
dba.dce_sub_group_nr AS 'ACO Sub Group ID',
dba.prov_npi_nr "ACO Provider ID"
FROM  patient p
INNER JOIN dc_bene_alignment_rostr_m01 dba ON dba.mm_curr_mbi_id  = p.origid  
WHERE    dba.ALIGN_STATUS_CODE  IN ( 'AL'  , 'D1Y'  )
AND     dba.mm_date  IN
(
SELECT MAX(mm_date)
FROM  dc_bene_alignment_rostr_m01 
)
AND     dba.CC_version  IN
(
SELECT MAX(cc_version)
FROM  dc_bene_alignment_rostr_m01 
)

UNION

SELECT DISTINCT
(p.origid) AS "Member ID",
CONCAT(p.lastname, ' ', p.firstname) AS "Member Name",
DATE_FORMAT(dba.BENE_BIRTH_DATE, '%m/%d/%Y') AS "DOB",
dba.market_names AS 'ACO Market',
dba.dce_group_name AS `ACO GROUP`,
IF(dba.dce_sub_group_name  = 'NULL', '', dba.dce_sub_group_name) AS `ACO Sub Group`,
dba.dce_provider_name AS `ACO Provider`,
'DO NOT MAIL' AS TYPE,
IF(p.is_alert_global  = 1, 'Yes', 'No') AS VALUE,
p.alert_note_global AS 'NOTES',
DATE_FORMAT(p.global_alerts_date, '%m/%d/%Y') AS "Date",
dba.market_id AS 'ACO Market ID',
dba.dce_group_nr AS 'ACO Group ID',
dba.dce_sub_group_nr AS 'ACO Sub Group ID',
dba.prov_npi_nr "ACO Provider ID"
FROM  patient p
INNER JOIN dc_bene_alignment_rostr_m01 dba ON dba.mm_curr_mbi_id  = p.origid  
WHERE dba.ALIGN_STATUS_CODE  IN ( 'AL'  , 'D1Y'  )
AND dba.mm_date  IN
(
SELECT MAX(mm_date)
FROM  dc_bene_alignment_rostr_m01 
)
AND dba.CC_version  IN
(
SELECT MAX(cc_version)
FROM  dc_bene_alignment_rostr_m01 
)

UNION

SELECT DISTINCT
(p.origid) AS "Member ID",
CONCAT(p.lastname, ' ', p.firstname) AS "Member Name",
DATE_FORMAT(dba.BENE_BIRTH_DATE, '%m/%d/%Y') AS "DOB",
dba.market_names AS 'ACO Market',
dba.dce_group_name AS `ACO GROUP`,
IF(dba.dce_sub_group_name  = 'NULL', '', dba.dce_sub_group_name) AS `ACO Sub Group`,
dba.dce_provider_name AS `ACO Provider`,
'OPT-OUT MAIL AND CALL' AS TYPE,
IF(p.is_alert_dpatient  = 1, 'Yes', 'No') AS VALUE,
p.alert_note_dpatient AS 'NOTES',
DATE_FORMAT(p.global_alerts_date, '%m/%d/%Y') AS "Date",
dba.market_id AS 'ACO Market ID',
dba.dce_group_nr AS 'ACO Group ID',
dba.dce_sub_group_nr AS 'ACO Sub Group ID',
dba.prov_npi_nr "ACO Provider ID"
FROM  patient p
INNER JOIN dc_bene_alignment_rostr_m01 dba ON dba.mm_curr_mbi_id  = p.origid  
WHERE dba.ALIGN_STATUS_CODE  IN ( 'AL'  , 'D1Y'  )
AND dba.mm_date  IN
(
SELECT MAX(mm_date)
FROM  dc_bene_alignment_rostr_m01 
)
AND dba.CC_version  IN
(
SELECT MAX(cc_version)
FROM  dc_bene_alignment_rostr_m01 
)

UNION

SELECT DISTINCT
(p.origid) AS "Member ID",
CONCAT(p.lastname, ' ', p.firstname) AS "Member Name",
DATE_FORMAT(dba.BENE_BIRTH_DATE, '%m/%d/%Y') AS "DOB",
dba.market_names AS 'ACO Market',
dba.dce_group_name AS `ACO GROUP`,
IF(dba.dce_sub_group_name  = 'NULL', '', dba.dce_sub_group_name) AS `ACO Sub Group`,
dba.dce_provider_name AS `ACO Provider`,
'DECEASED' AS TYPE,
IF(p.is_alert_inc_alerts  = 1, 'Yes', 'No') AS VALUE,
p.alert_note_inc_alerts AS 'NOTES',
DATE_FORMAT(p.global_alerts_date, '%m/%d/%Y') AS "Date",
dba.market_id AS 'ACO Market ID',
dba.dce_group_nr AS 'ACO Group ID',
dba.dce_sub_group_nr AS 'ACO Sub Group ID',
dba.prov_npi_nr "ACO Provider ID"
FROM  patient p
INNER JOIN dc_bene_alignment_rostr_m01 dba ON dba.mm_curr_mbi_id  = p.origid  
WHERE dba.ALIGN_STATUS_CODE  IN ( 'AL'  , 'D1Y'  )
AND dba.mm_date  IN
(
SELECT MAX(mm_date)
FROM  dc_bene_alignment_rostr_m01 
)
AND dba.CC_version  IN
(
SELECT MAX(cc_version)
FROM  dc_bene_alignment_rostr_m01 
)

UNION

SELECT DISTINCT
(p.origid) AS "Member ID",
CONCAT(p.lastname, ' ', p.firstname) AS "Member Name",
DATE_FORMAT(dba.BENE_BIRTH_DATE, '%m/%d/%Y') AS "DOB",
dba.market_names AS 'ACO Market',
dba.dce_group_name AS `ACO GROUP`,
IF(dba.dce_sub_group_name  = 'NULL', '', dba.dce_sub_group_name) AS `ACO Sub Group`,
dba.dce_provider_name AS `ACO Provider`,
'NOT PCP' AS TYPE,
IF(p.is_alert_transportation  = 1, 'Yes', 'No') AS VALUE,
p.alert_note_transportation AS 'NOTES',
DATE_FORMAT(p.global_alerts_date, '%m/%d/%Y') AS "Date",
dba.market_id AS 'ACO Market ID',
dba.dce_group_nr AS 'ACO Group ID',
dba.dce_sub_group_nr AS 'ACO Sub Group ID',
dba.prov_npi_nr "ACO Provider ID"
FROM  patient p
INNER JOIN dc_bene_alignment_rostr_m01 dba ON dba.mm_curr_mbi_id  = p.origid  
WHERE dba.ALIGN_STATUS_CODE  IN ( 'AL'  , 'D1Y'  )
AND dba.mm_date  IN
(
SELECT MAX(mm_date)
FROM  dc_bene_alignment_rostr_m01 
)
AND dba.CC_version  IN
(
SELECT MAX(cc_version)
FROM  dc_bene_alignment_rostr_m01 
)

UNION

SELECT DISTINCT
(p.origid) AS "Member ID",
CONCAT(p.lastname, ' ', p.firstname) AS "Member Name",
DATE_FORMAT(dba.BENE_BIRTH_DATE, '%m/%d/%Y') AS "DOB",
dba.market_names AS 'ACO Market',
dba.dce_group_name AS `ACO GROUP`,
IF(dba.dce_sub_group_name  = 'NULL', '', dba.dce_sub_group_name) AS `ACO Sub Group`,
dba.dce_provider_name AS `ACO Provider`,
'OTHER' AS TYPE,
IF(p.nursing_home_alert  = 1, 'Yes', 'No') AS VALUE,
p.nursing_home_a_notes AS 'NOTES',
DATE_FORMAT(p.global_alerts_date, '%m/%d/%Y') AS "Date",
dba.market_id AS 'ACO Market ID',
dba.dce_group_nr AS 'ACO Group ID',
dba.dce_sub_group_nr AS 'ACO Sub Group ID',
dba.prov_npi_nr "ACO Provider ID"
FROM  patient p
INNER JOIN dc_bene_alignment_rostr_m01 dba ON dba.mm_curr_mbi_id  = p.origid  
WHERE dba.ALIGN_STATUS_CODE  IN ( 'AL'  , 'D1Y'  )
AND dba.mm_date  IN
(
SELECT MAX(mm_date)
FROM  dc_bene_alignment_rostr_m01 
)
AND dba.CC_version  IN
(
SELECT MAX(cc_version)
FROM  dc_bene_alignment_rostr_m01 
)

;


END */$$
DELIMITER ;

/* Procedure structure for procedure `ZOHO_temp_Plan` */

DELIMITER $$

/*!50003 CREATE PROCEDURE `ZOHO_temp_Plan`()
BEGIN

SELECT 
r.reminder_id  AS 'Reminder',
market_name  AS 'ACO Market',
dce_group_name AS `ACO GROUP`,
IF(dce_sub_group_name  = 'NULL', '', dce_sub_group_name) AS `ACO Sub Group`,
dce_provider_name AS `ACO Provider`,
CONCAT(dba.BENE_F_NAME, ' ', dba.BENE_L_NAME) AS `Member NAME`,
dba.mm_curr_mbi_id AS `Member ID`,
DATE_FORMAT(dba.BENE_BIRTH_DATE, '%m/%d/%Y') AS DOB,
dba.BENE_USPS_STATE_CODE AS `State Code`,
dba.BENE_CITY AS `City`,
CONCAT(p.phone_1_code, ' ', p.phone_1_nr) AS `Phone Number`,
p.cellphone_2_nr AS "Cell Phone",       
r.reminder_name AS `Reminder Name`,
pr.job_type_nr AS `Role Type`,
r.reminder_type AS `Reminder Type`,
r.category AS 'Category',
r.reminder_des AS 'Reminder Description',
r.`declined_cm` AS 'Action Item',
ccm.type AS 'CM type',
DATE_FORMAT(r.created_date, '%m/%d/%Y') AS "Date",
r.signature AS `Case Manager`,
IF(r.created_by='migration_script',r.signature,r.created_by) AS `User Id` ,
dba.market_id AS "ACO Market ID",
dce_group_nr "ACO Group ID",
dce_sub_group_nr "ACO Sub Group ID",
prov_npi_nr "ACO Provider ID"
FROM reminder_events r 
INNER JOIN dc_bene_alignment_rostr_m01 dba ON r.origid=dba.BENE_MBI_ID 
INNER JOIN patient p ON r.origid=p.origid 
INNER JOIN personell per ON per.name=r.signature
LEFT JOIN ccm_active ccm ON ccm.origid=p.origid 
INNER JOIN hospital_market_assocs hm ON p.facility_nr=hm.hosp_id
INNER JOIN `hospital_market` m ON m.market_id=hm.market_id 
INNER JOIN personell_roles pr ON pr.personell_nr = per.nr
INNER JOIN personnel_dept_assocs  pda ON  pda.personnel_nr= per.nr
WHERE r.signature NOT IN  ('admin','') 
AND p.firstname NOT LIKE '%test%' 
AND p.lastname NOT LIKE '%test%' 
AND p.origid!='987654321'  
AND dba.cc_version=(20231101) 
AND dba.mm_date  LIKE '%2023-11-01%'
AND dba.`ALIGN_STATUS_CODE` IN ('D1Y','AL') AND pr.job_type_nr NOT IN (0,2,111,113,119,120)
AND r.created_date BETWEEN "2023-12-01" AND "2023-12-31"
ORDER BY r.reminder_id DESC;



END */$$
DELIMITER ;

