/*View structure for view hei_live */

/*!50001 DROP TABLE IF EXISTS `hei_live` */;
/*!50001 CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `hei_live` AS select `main`.`origid` AS `origid`,`main`.`market` AS `market`,`main`.`DCE_Group` AS `DCE_Group`,`main`.`dce_group_nr` AS `dce_group_nr`,`main`.`DCE_Provider` AS `DCE_Provider`,`main`.`months` AS `months`,`main`.`YEAR` AS `YEAR`,`main`.`dce_sub_group` AS `dce_sub_group`,`main`.`dob` AS `dob`,`main`.`userid` AS `userid`,`main`.`history_value` AS `history_value`,`main`.`market_id` AS `market_id`,`main`.`ALIGN_STATUS_CODE` AS `ALIGN_STATUS_CODE`,`main`.`encounter_class_nr` AS `encounter_class_nr`,`main`.`history_nr` AS `history_nr`,`main`.`enc_mbi` AS `enc_mbi`,`main`.`history_date` AS `history_date`,`main`.`history_dt` AS `history_dt`,`main`.`concat_encounter` AS `concat_encounter`,`main`.`Patient_name` AS `Patient_name`,`main`.`is_completed_by_office` AS `is_completed_by_office`,`deps`.`nr` AS `nr`,`deps`.`rep_name` AS `rep_name`,`deps`.`full_name` AS `full_name`,`deps`.`Department` AS `Department`,`dupli`.`duplicated_nr` AS `duplicated_nr` from (((select distinct `p`.`origid` AS `origid`,`m`.`market_name` AS `market`,`dba`.`dce_group_name` AS `DCE_Group`,`dba`.`dce_group_nr` AS `dce_group_nr`,`dba`.`dce_provider_name` AS `DCE_Provider`,month(`e`.`encounter_date`) AS `months`,year(`e`.`encounter_date`) AS `YEAR`,`dba`.`dce_sub_group_name` AS `dce_sub_group`,date_format(`p`.`birthdate`,'%m/%d/%Y') AS `dob`,`r`.`created_by` AS `userid`,`r`.`history_value` AS `history_value`,`hm`.`market_id` AS `market_id`,`dba`.`ALIGN_STATUS_CODE` AS `ALIGN_STATUS_CODE`,`e`.`encounter_class_nr` AS `encounter_class_nr`,`r`.`history_nr` AS `history_nr`,`e`.`origid` AS `enc_mbi`,(select date_format(`mra_member_history_data`.`history_value`,'%m/%d/%Y') from `mra_member_history_data` where ((`mra_member_history_data`.`encounter_nr` = `r`.`encounter_nr`) and (`mra_member_history_data`.`history_nr` = 150661)) limit 1) AS `history_date`,(select date_format(`mra_member_history_data`.`history_value`,'%m/%d/%Y') from `mra_member_history_data` where ((`mra_member_history_data`.`encounter_nr` = `r`.`encounter_nr`) and (`mra_member_history_data`.`history_nr` = 150661)) limit 1) AS `history_dt`,`r`.`encounter_nr` AS `concat_encounter`,concat(`p`.`lastname`,' ',`p`.`firstname`) AS `Patient_name`,if((`office_check`.`enc` is null),'No','Yes') AS `is_completed_by_office` from ((((((`mra_member_history_data` `r` join `encounter` `e` on((`r`.`encounter_nr` = `e`.`encounter_nr`))) join `patient` `p` on((`e`.`origid` = `p`.`origid`))) join `dc_bene_alignment_rostr_m01` `dba` on((`dba`.`mm_curr_mbi_id` = convert(`p`.`origid` using utf8mb3)))) join `hospital_market_assocs` `hm` on((`dba`.`dce_group_nr` = `hm`.`hosp_id`))) join `hospital_market` `m` on((`m`.`market_id` = `hm`.`market_id`))) left join (select distinct `mra_member_history_data`.`encounter_nr` AS `enc` from `mra_member_history_data` where ((`mra_member_history_data`.`history_nr` = 150686) and (`mra_member_history_data`.`history_value` = 'Y'))) `office_check` on((`r`.`encounter_nr` = `office_check`.`enc`))) where (((select date_format(`mra_member_history_data`.`history_value`,'%Y-%m-%d') from `mra_member_history_data` where ((`mra_member_history_data`.`encounter_nr` = `r`.`encounter_nr`) and (`mra_member_history_data`.`history_nr` = 150661)) limit 1) between '2024-10-01' and '2024-12-31') and (year(`e`.`encounter_date`) >= 2024) and (`r`.`history_nr` in (150665,150661)) and (`r`.`history_value` is not null) and (`r`.`history_value` not in (';../../','')) and (`dba`.`cc_version` = 20241001) and (`dba`.`mm_date` = '2024-11-01'))) `main` left join (select `m`.`nr` AS `nr`,max(`m`.`rep_name`) AS `rep_name`,max(`m`.`full_name`) AS `full_name`,min(`m`.`type`) AS `Department` from (select distinct `p`.`nr` AS `nr`,`t`.`type` AS `type`,`p`.`name` AS `rep_name`,concat(`p`.`last_name`,', ',`p`.`first_name`) AS `full_name`,`pr`.`is_default_role` AS `is_default_role`,`pr`.`active_date` AS `Active_date` from ((`personell` `p` join `personell_roles` `pr` on((`p`.`nr` = `pr`.`personell_nr`))) join `type_personel` `t` on((`pr`.`job_type_nr` = `t`.`nr`))) where ((`p`.`is_dce` = 1) and (`p`.`dce_type` = 'DCE') and (`pr`.`job_type_nr` in (116,117,121,122,123,124,125)) and (`pr`.`is_default_role` = 1)) union select distinct `p`.`nr` AS `nr`,`t`.`type` AS `type`,`p`.`name` AS `rep_name`,concat(`p`.`last_name`,', ',`p`.`first_name`) AS `full_name`,`pr`.`is_default_role` AS `is_default_role`,`pr`.`active_date` AS `Active_date` from (((`personell` `p` join `personell_roles` `pr` on((`p`.`nr` = `pr`.`personell_nr`))) join `type_personel` `t` on((`pr`.`job_type_nr` = `t`.`nr`))) join (select `personell_roles`.`personell_nr` AS `personell_nr`,max(`personell_roles`.`active_date`) AS `max_active` from `personell_roles` group by `personell_roles`.`personell_nr`) `max_tab` on(((`max_tab`.`max_active` = `pr`.`active_date`) and (`max_tab`.`personell_nr` = `p`.`nr`)))) where ((`p`.`is_dce` = 1) and (`p`.`dce_type` = 'DCE') and (`pr`.`job_type_nr` in (116,117,121,122,123,124,125)) and `p`.`nr` in (select distinct `p`.`nr` from ((`personell` `p` join `personell_roles` `pr` on((`p`.`nr` = `pr`.`personell_nr`))) join `type_personel` `t` on((`pr`.`job_type_nr` = `t`.`nr`))) where ((`p`.`is_dce` = 1) and (`p`.`dce_type` = 'DCE') and (`pr`.`job_type_nr` in (116,117,121,122,123,124,125)) and (`pr`.`is_default_role` = 1))) is false)) `m` group by `m`.`nr`) `deps` on(((convert(`deps`.`rep_name` using utf8mb3) = `main`.`userid`) or (convert(`deps`.`full_name` using utf8mb3) = `main`.`userid`)))) left join (select `m`.`nr` AS `duplicated_nr` from (select distinct `p`.`nr` AS `nr`,`t`.`type` AS `type`,concat(`p`.`last_name`,', ',`p`.`first_name`) AS `rep_name`,`pr`.`is_default_role` AS `is_default_role`,`pr`.`active_date` AS `Active_date` from ((`personell` `p` join `personell_roles` `pr` on((`p`.`nr` = `pr`.`personell_nr`))) join `type_personel` `t` on((`pr`.`job_type_nr` = `t`.`nr`))) where ((`p`.`is_dce` = 1) and (`p`.`dce_type` = 'DCE') and (`pr`.`job_type_nr` in (116,117,121,122,123,124,125)))) `m` group by `m`.`nr` having (count(`m`.`type`) > 1)) `dupli` on((`deps`.`nr` = `dupli`.`duplicated_nr`))) */;

