/*View structure for view mra_report_bed_days_census */

/*!50001 DROP TABLE IF EXISTS `mra_report_bed_days_census` */;
/*!50001 CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `mra_report_bed_days_census` AS select concat(`p`.`lastname`,', ',`p`.`firstname`,' ',`p`.`middlename`) AS `Member Name`,date_format(`e`.`encounter_date`,'%m/%d/%Y') AS `Admit`,date_format(`e`.`discharge_date`,'%m/%d/%Y') AS `Disch`,(to_days(`e`.`discharge_date`) - to_days(`e`.`encounter_date`)) AS `Days`,`ep`.`procedure_center` AS `Facility`,'' AS `Auth Num`,if(((select count(0) from `encounter` where (`encounter`.`origid` = `p`.`origid`)) > 1),'Y','N') AS `Readmit`,'' AS `ACP`,(select group_concat(`drfirst_problems`.`Problem_code` separator ',') from `drfirst_problems` where (`drfirst_problems`.`patient_id` = `p`.`origid`)) AS `Diag`,date_format(curdate(),'%m/%d/%Y') AS `Run Date`,'' AS `Lob`,`e`.`encounter_date` AS `encounter_date`,date_format(`p`.`birthdate`,'%m/%d/%Y') AS `birthdate`,`p`.`origid` AS `origid` from ((`patient` `p` join `encounter` `e` on((`e`.`origid` = `p`.`origid`))) join `encounter_procedure` `ep` on((`ep`.`encounter_nr` = `e`.`encounter_nr`))) */;

/*View structure for view mra_report_diagnosis_dropoff */

/*!50001 DROP TABLE IF EXISTS `mra_report_diagnosis_dropoff` */;
/*!50001 CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `mra_report_diagnosis_dropoff` AS select `p`.`sp_dr_1` AS `PCP`,`e`.`hospital_nr` AS `Center ID`,concat(`p`.`firstname`,' ',`p`.`lastname`) AS `Member Name`,if((`p`.`inactive_date` is null),'Active','Inactive') AS `Member Status`,date_format(`p`.`birthdate`,'%m/%d/%Y') AS `Member DOB`,`p`.`origid` AS `Member PID`,if((`dp`.`Problem_code` = -(99)),'',`dp`.`Problem_code`) AS `Diagnosis Code`,date_format(`dp`.`Problem_date`,'%m/%d/%Y') AS `Original Date Diagnosis Code was Coded`,`mhc`.`hcc` AS `HCC Category`,`ep`.`interventionalist` AS `Servicing Provider for Original Visit Date`,`pr`.`npr_id` AS `Servicing Provider ID for Original Visit Date`,`pr`.`speciality_code` AS `Servicing Provider Speciality Code for Original Visit Date`,`pr`.`speciality` AS `Servicing Provider Speciality for Original Visit Date`,if((`dp`.`Problem_code` = -(99)),'Yes','No') AS `Diagnosis Code Reconciled`,`pd`.`recent_pcp_date` AS `Most Recent PCP Visit`,`ep`.`procedure_date` AS `procedure_date`,`pr`.`nr` AS `personell_nr`,`hma`.`market_id` AS `market_id`,`p`.`birthdate` AS `birthdate`,`ep`.`referrer_dr` AS `referrer_dr` from (((((((`patient` `p` join `patient_details` `pd` on((convert(`p`.`origid` using utf8mb3) = convert(`pd`.`origid` using utf8mb3)))) join `drfirst_problems` `dp` on((`dp`.`patient_id` = `p`.`origid`))) join `encounter` `e` on((`e`.`origid` = `p`.`origid`))) join `encounter_procedure` `ep` on((`ep`.`encounter_nr` = `e`.`encounter_nr`))) join `personell` `pr` on((`pr`.`name` = `ep`.`interventionalist`))) left join `hospital_market_assocs` `hma` on((`hma`.`hosp_id` = `e`.`hospital_nr`))) join `bt_static`.`mra_hcc_coefficients` `mhc` on((`mhc`.`diagnosis_code` = convert(`dp`.`Problem_code` using utf8mb3)))) group by `ep`.`encounter_nr`,`dp`.`Problem_code` */;

/*View structure for view mra_report_membership_roster */

/*!50001 DROP TABLE IF EXISTS `mra_report_membership_roster` */;
/*!50001 CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `mra_report_membership_roster` AS select concat(`p`.`lastname`,', ',`p`.`firstname`,' ',`p`.`middlename`) AS `Member Name`,`p`.`origid` AS `Member ID`,`p_i`.`copay_amount` AS `Copay`,`p`.`addr_str` AS `Address`,concat(`p`.`addr_citytown_name`,', ',`p`.`addr_state`,' ',`p`.`addr_zip`) AS `City, ST ZIP`,concat(`p`.`phone_1_code`,' ',`p`.`phone_1_nr`) AS `Phone`,date_format(`p`.`birthdate`,'%m/%d/%Y') AS `Birthday`,timestampdiff(YEAR,`p`.`birthdate`,curdate()) AS `Age`,`p`.`sex` AS `Sex`,`e`.`encounter_date` AS `Begin Date`,date_format(`e`.`discharge_date`,'%m/%d/%Y') AS `End Date`,`p_i`.`insurance_category_code` AS `Medicare`,'' AS `LOB`,'MED' AS `Prod`,`p`.`status` AS `Status`,`p`.`date_reg` AS `Reg Date` from ((`patient` `p` join `encounter` `e` on((`e`.`origid` = `p`.`origid`))) left join `patient_insurance` `p_i` on((`p_i`.`origid` = `p`.`origid`))) */;

/*View structure for view mra_report_membership_roster_detail */

/*!50001 DROP TABLE IF EXISTS `mra_report_membership_roster_detail` */;
/*!50001 CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `mra_report_membership_roster_detail` AS select if((`p`.`inactive_date` is null),'Active','Inactive') AS `Status`,`p`.`facility_nr` AS `Center ID`,`p`.`facility_name` AS `CENTER NAME`,`hm`.`market_name` AS `REGION`,`hma`.`market_id` AS `market_id`,concat(`p`.`firstname`,' ',`p`.`lastname`) AS `MBR NM`,`p`.`origid` AS `MBR PID`,`p`.`addr_str` AS `MBR ADDR1`,`p`.`addr_str2` AS `MBR ADDR2`,`p`.`addr_citytown_name` AS `MBR CITY`,`p`.`addr_state` AS `MBR STATE`,`p`.`addr_zip` AS `MBR ZIP`,`p`.`addr_country` AS `MBR CNTYNM`,concat(`p`.`phone_2_code`,'',`p`.`phone_2_nr`) AS `MBR PHONE`,date_format(`p`.`birthdate`,'%m/%d/%Y') AS `MBR BTH`,`p`.`age` AS `MBR AGE`,`p`.`sex` AS `MBR SEX`,`pd`.`member_type` AS `MEMBER TYPE`,(select date_format(`patient_insurance`.`plan_effective_date`,'%Y-%m-%d') from `patient_insurance` where ((`patient_insurance`.`origid` = `p`.`origid`) and (`patient_insurance`.`insurance_type` = 'Primary') and (`patient_insurance`.`status` = 'active')) limit 1) AS `ENROLL DATE`,(select `patient_insurance`.`copay_amount` from `patient_insurance` where ((`patient_insurance`.`origid` = `p`.`origid`) and (`patient_insurance`.`insurance_type` = 'Primary') and (`patient_insurance`.`status` = 'active')) limit 1) AS `Copay ID`,date_format(`p`.`inactive_date`,'%Y-%m-%d') AS `INACTIVE DATE`,`p`.`inactive_reason` AS `INACTIVE REASON`,`p`.`sp_dr_1` AS `provider_name`,`pd`.`member_type` AS `member_type`,`pd`.`mra_score` AS `MRA SCORE`,date_format(`p`.`birthdate`,'%m/%d/%Y') AS `birthdate` from ((((`patient` `p` left join `patient_details` `pd` on((convert(`p`.`origid` using utf8mb3) = convert(`pd`.`origid` using utf8mb3)))) left join `hospital_centers` `hc` on((`hc`.`nr` = `p`.`facility_nr`))) left join `hospital_market_assocs` `hma` on((`hma`.`hosp_id` = `hc`.`nr`))) left join `hospital_market` `hm` on((`hm`.`market_id` = `hma`.`market_id`))) group by `p`.`origid` order by `p`.`create_time` desc */;

