/*!50001 CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `mra_tab_table_data` AS select `mjs`.`job_id` AS `job_id`,`mjs`.`job_file1_status` AS `job_file1_status`,date_format(`mjs`.`process_date`,'%m/%d/%Y') AS `processed_date`,`mip`.`import_record_nr` AS `import_record_nr`,`mjs`.`map_data_status` AS `map_data_status`,`mip`.`origid` AS `origid`,(select `mhd`.`history_value` from `mra_member_history_data` `mhd` where ((`mhd`.`history_nr` = '90003') and (`mhd`.`member_file_id` = `mjs`.`job_id`) and (`mhd`.`origid` = convert(`mip`.`origid` using utf8mb3)) and (`mhd`.`member_file_type` = 'MRA') and (`mhd`.`member_record_id` = `mip`.`import_record_nr`))) AS `contract_no`,(select date_format(`mhd`.`history_value`,'%m/%d/%Y %H:%i:%s') from `mra_member_history_data` `mhd` where ((`mhd`.`history_nr` = '90004') and (`mhd`.`member_file_id` = `mjs`.`job_id`) and (`mhd`.`origid` = convert(`mip`.`origid` using utf8mb3)) and (`mhd`.`member_file_type` = 'MRA') and (`mhd`.`member_record_id` = `mip`.`import_record_nr`))) AS `run_date`,(select date_format(`mhd`.`history_value`,'%m/%d/%Y %H:%i:%s') from `mra_member_history_data` `mhd` where ((`mhd`.`history_nr` = '90006') and (`mhd`.`member_file_id` = `mjs`.`job_id`) and (`mhd`.`origid` = convert(`mip`.`origid` using utf8mb3)) and (`mhd`.`member_file_type` = 'MRA') and (`mhd`.`member_record_id` = `mip`.`import_record_nr`))) AS `payment_date`,(select `mhd`.`history_value` from `mra_member_history_data` `mhd` where ((`mhd`.`history_nr` = '90007') and (`mhd`.`member_file_id` = `mjs`.`job_id`) and (`mhd`.`origid` = convert(`mip`.`origid` using utf8mb3)) and (`mhd`.`member_file_type` = 'MRA') and (`mhd`.`member_record_id` = `mip`.`import_record_nr`))) AS `beneficial_id` from (`mra_job_schedules` `mjs` join `mra_import_patient_files` `mip` on((`mjs`.`job_id` = `mip`.`job_id`))) where ((`mjs`.`job_file1_status` = 1) and (`mjs`.`map_data_status` = 1)) */;

