/*!50001 CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `patient_infections_vw` AS select `patient`.`origid` AS `origid`,`patient`.`lastname` AS `lastname`,`patient`.`firstname` AS `firstname`,concat_ws(_utf8mb3', ',convert(if((`patient`.`lastname` = _latin1''),NULL,`patient`.`lastname`) using utf8mb3),convert(if((`patient`.`firstname` = _latin1''),NULL,`patient`.`firstname`) using utf8mb3),convert(if((`patient`.`middlename` = _latin1''),NULL,`patient`.`middlename`) using utf8mb3)) AS `Patient_Name`,`patient`.`birthdate` AS `birthdate`,`patient`.`sex` AS `sex`,`patient`.`dialysis_clinic` AS `dialysis_clinic`,`patient_infections`.`inf_date` AS `inf_date`,`patient_infections`.`inf_time` AS `inf_time`,`patient_infections`.`inf_organism` AS `inf_organism`,`patient_infections`.`inf_treatment` AS `inf_treatment`,`patient_infections`.`inf_dose` AS `inf_dose`,`patient_infections`.`inf_route` AS `inf_route`,`patient_infections`.`inf_duration` AS `inf_duration`,`patient_infections`.`inf_location` AS `inf_location`,`patient_infections`.`inf_comments` AS `inf_comments` from (`patient_infections` join `patient` on((`patient`.`origid` = `patient_infections`.`inf_origid`))) union all select `patient`.`origid` AS `origid`,`patient`.`lastname` AS `lastname`,`patient`.`firstname` AS `firstname`,concat_ws(_utf8mb3', ',convert(if((`patient`.`lastname` = _latin1''),NULL,`patient`.`lastname`) using utf8mb3),convert(if((`patient`.`firstname` = _latin1''),NULL,`patient`.`firstname`) using utf8mb3),convert(if((`patient`.`middlename` = _latin1''),NULL,`patient`.`middlename`) using utf8mb3)) AS `Patient_Name`,`patient`.`birthdate` AS `birthdate`,`patient`.`sex` AS `sex`,`patient`.`dialysis_clinic` AS `dialysis_clinic`,`encounter`.`encounter_date` AS `inf_date`,_utf8mb3'' AS `inf_time`,_utf8mb3'' AS `inf_organism`,_utf8mb3'' AS `inf_treatment`,_utf8mb3'' AS `inf_dose`,_utf8mb3'' AS `inf_route`,_utf8mb3'' AS `inf_duration`,_utf8mb3'' AS `inf_location`,`procedure_history_data`.`comments` AS `inf_comments` from (((`procedure_history_data` join `encounter` on((`encounter`.`encounter_nr` = `procedure_history_data`.`encounter_nr`))) join `encounter_procedure` on((`encounter_procedure`.`encounter_nr` = `encounter`.`encounter_nr`))) join `patient` on((`patient`.`origid` = `encounter`.`origid`))) where ((`procedure_history_data`.`history_nr` = 461) and (`procedure_history_data`.`history_value` = _latin1'Yes')) */;

