/*!50001 CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `studynotes_search_vw` AS select distinct `encounter`.`encounter_nr` AS `encounter_nr`,unix_timestamp(`ep`.`procedure_date`) AS `procedure_date`,`patient`.`origid` AS `origid`,concat_ws(_utf8mb3', ',convert(if((`patient`.`lastname` = _latin1''),NULL,`patient`.`lastname`) using utf8mb3),convert(if((`patient`.`firstname` = _latin1''),NULL,`patient`.`firstname`) using utf8mb3),convert(if((`patient`.`middlename` = _latin1''),NULL,`patient`.`middlename`) using utf8mb3)) AS `patient_name`,`ep`.`procedure_type` AS `procedure_type`,`ep`.`interventionalist` AS `interventionalist`,`ep`.`dialysis_clinic` AS `dialysis_clinic`,`studynotes`.`id` AS `id`,`studynotes`.`notes` AS `notes`,`encounter`.`hospital_nr` AS `hospital_nr`,`option_code_values`.`ID` AS `proc_id`,`clinic_centers`.`nr` AS `clinic_id` from (((((`encounter_procedure` `ep` join `encounter` on((`encounter`.`encounter_nr` = `ep`.`encounter_nr`))) join `patient` on((`patient`.`origid` = `encounter`.`origid`))) join `studynotes` on((`studynotes`.`encounter_nr` = `encounter`.`encounter_nr`))) left join `option_code_values` on(((`option_code_values`.`Column_Order` = 5) and (`option_code_values`.`Option_Value` = `ep`.`procedure_type`)))) left join `clinic_centers` on((`clinic_centers`.`name` = `ep`.`dialysis_clinic`))) where (`encounter`.`encounter_status` <> _latin1'cancelled') */;

