/*!50001 CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `cm_departments` AS select `deps`.`nr` AS `nr`,`deps`.`rep_name` AS `rep_name`,`deps`.`full_name` AS `full_name`,`deps`.`Department` AS `Department`,`dupli`.`duplicated_nr` AS `duplicated_nr` from ((select `m`.`nr` AS `nr`,max(`m`.`rep_name`) AS `rep_name`,max(`m`.`full_name`) AS `full_name`,min(`m`.`type`) AS `Department` from (select distinct `p`.`nr` AS `nr`,`t`.`type` AS `type`,`p`.`name` AS `rep_name`,concat(`p`.`last_name`,', ',`p`.`first_name`) AS `full_name`,`pr`.`is_default_role` AS `is_default_role`,`pr`.`active_date` AS `Active_date` from ((`personell` `p` join `personell_roles` `pr` on((`p`.`nr` = `pr`.`personell_nr`))) join `type_personel` `t` on((`pr`.`job_type_nr` = `t`.`nr`))) where ((`p`.`is_dce` = 1) and (`p`.`dce_type` = 'DCE') and (`pr`.`job_type_nr` in (116,117,121,122,123,124,125)) and (`pr`.`is_default_role` = 1)) union select distinct `p`.`nr` AS `nr`,`t`.`type` AS `type`,`p`.`name` AS `rep_name`,concat(`p`.`last_name`,', ',`p`.`first_name`) AS `full_name`,`pr`.`is_default_role` AS `is_default_role`,`pr`.`active_date` AS `Active_date` from (((`personell` `p` join `personell_roles` `pr` on((`p`.`nr` = `pr`.`personell_nr`))) join `type_personel` `t` on((`pr`.`job_type_nr` = `t`.`nr`))) join (select `personell_roles`.`personell_nr` AS `personell_nr`,max(`personell_roles`.`active_date`) AS `max_active` from `personell_roles` group by `personell_roles`.`personell_nr`) `max_tab` on(((`max_tab`.`max_active` = `pr`.`active_date`) and (`max_tab`.`personell_nr` = `p`.`nr`)))) where ((`p`.`is_dce` = 1) and (`p`.`dce_type` = 'DCE') and (`pr`.`job_type_nr` in (116,117,121,122,123,124,125)) and `p`.`nr` in (select distinct `p`.`nr` from ((`personell` `p` join `personell_roles` `pr` on((`p`.`nr` = `pr`.`personell_nr`))) join `type_personel` `t` on((`pr`.`job_type_nr` = `t`.`nr`))) where ((`p`.`is_dce` = 1) and (`p`.`dce_type` = 'DCE') and (`pr`.`job_type_nr` in (116,117,121,122,123,124,125)) and (`pr`.`is_default_role` = 1))) is false)) `m` group by `m`.`nr`) `deps` left join (select `m`.`nr` AS `duplicated_nr` from (select distinct `p`.`nr` AS `nr`,`t`.`type` AS `type`,concat(`p`.`last_name`,', ',`p`.`first_name`) AS `rep_name`,`pr`.`is_default_role` AS `is_default_role`,`pr`.`active_date` AS `Active_date` from ((`personell` `p` join `personell_roles` `pr` on((`p`.`nr` = `pr`.`personell_nr`))) join `type_personel` `t` on((`pr`.`job_type_nr` = `t`.`nr`))) where ((`p`.`is_dce` = 1) and (`p`.`dce_type` = 'DCE') and (`pr`.`job_type_nr` in (116,117,121,122,123,124,125)))) `m` group by `m`.`nr` having (count(`m`.`type`) > 1)) `dupli` on((`deps`.`nr` = `dupli`.`duplicated_nr`))) */;

/*View structure for view view_peer_review */

/*!50001 DROP TABLE IF EXISTS `view_peer_review` */;
/*!50001 CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `view_peer_review` AS select `ppr`.`nr` AS `nr`,`d`.`dept_nr` AS `dept_nr`,date_format(`ppr`.`date_of_cn_notes`,'%m/%d/%Y') AS `date_of_cn_notes`,`ppr`.`origid` AS `origid`,`ppr`.`peer_reviewer` AS `peer_reviewer`,`ppr`.`assigned_cm` AS `assigned_cm`,`ppr`.`status` AS `status`,`ppr`.`notes` AS `notes`,date_format(`ppr`.`reviewed_date`,'%Y-%m-%d') AS `reviewed_date`,`ppr`.`follow_up` AS `follow_up`,`ppr`.`comments` AS `comments`,`ppr`.`score` AS `score`,`ppr`.`rationale` AS `rationale`,date_format(`ppr`.`created_date`,'%m/%d/%Y') AS `createdDate`,`t`.`type` AS `type`,`rr`.`reminder_type` AS `reminder_type`,`cmd`.`Department` AS `department`,`cmd`.`duplicated_nr` AS `duplicated_nr` from ((((((`mra_patient_peer_review` `ppr` join `personell` `p` on((`p`.`name` = `ppr`.`assigned_cm`))) join `personell_roles` `r` on((`r`.`personell_nr` = `p`.`nr`))) join `type_personel` `t` on((`r`.`job_type_nr` = `t`.`nr`))) join `personnel_dept_assocs` `d` on((`d`.`personnel_nr` = `p`.`nr`))) join `reminder_events` `rr` on((`rr`.`reminder_id` = `ppr`.`reiminder_id`))) left join `cm_departments` `cmd` on(((`cmd`.`rep_name` = `ppr`.`assigned_cm`) or (`cmd`.`full_name` = `ppr`.`assigned_cm`)))) where ((`p`.`is_dce` = 1) and (`p`.`dce_type` = 'DCE')) */;

