/*View structure for view view_sva_records */

/*!50001 DROP TABLE IF EXISTS `view_sva_records` */;
/*!50001 CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `view_sva_records` AS select upper(ifnull(`mra_sva_records`.`origid`,'UNK')) AS `MBI`,upper(ifnull(`mra_sva_records`.`benef_first_name`,'UNK')) AS `First Name`,upper(ifnull(`mra_sva_records`.`benef_last_name`,'UNK')) AS `Last Name`,upper(ifnull(`mra_sva_records`.`benef_street_addr`,'UNK')) AS `Address`,upper(ifnull(`mra_sva_records`.`city`,'UNK')) AS `City`,upper(ifnull(`mra_sva_records`.`state`,'UNK')) AS `State`,upper(ifnull(`mra_sva_records`.`zip_code`,'UNK')) AS `Zip Code`,upper(ifnull(`mra_sva_records`.`dce_group`,'No Group')) AS `ACO Group`,`mra_sva_records`.`group_nr` AS `group_nr`,`mra_sva_records`.`signature_date` AS `sva_sig_date`,NULL AS `Response Code`,upper(ifnull(`mra_sva_records`.`source`,'Unknown Source')) AS `Source Description`,`mra_sva_records`.`npr_id` AS `npr_id`,`mra_sva_records`.`todays_date` AS `Source Todays Date`,`mra_sva_records`.`is_delete` AS `is_delete`,upper(ifnull(`mra_sva_records`.`sp_dr_1`,'No Provider')) AS `ACO Provider`,upper(ifnull(`mra_sva_records`.`market_name`,'No Market Name')) AS `Market`,upper(ifnull(`mra_sva_records`.`sub_group_name`,'No Sub Group')) AS `ACO Sub Group`,`mra_sva_records`.`created_date` AS `Created Date` from `mra_sva_records` where ((`mra_sva_records`.`is_delete` = 0) and (upper(ifnull(`mra_sva_records`.`origid`,'UNK')) <> 'UNK') and `mra_sva_records`.`npr_id` in (select `p`.`npr_id` from ((`personell` `p` join `personell_hosp_assocs` `pha` on((`p`.`npr_id` = `pha`.`user_npi`))) join `hospital_centers` `hc` on((`pha`.`hospital_nr` = `hc`.`nr`))) where ((`p`.`npr_id` is not null) and (`p`.`npr_id` <> '') and ((not((`p`.`npr_id` like '%xx%'))) or (`p`.`name` like '%UNK%')) and (year(`pha`.`start_date`) <= '2024') and (year(`pha`.`end_date`) >= '2024') and (`p`.`is_dce` = 1) and (`p`.`dce_type` = 'DCE')) group by `p`.`npr_id`)) */;

