ew`.`user npi` AS `user npi`,`admin_sub_view`.`Sub_GroupName` AS `Sub_GroupName`,`admin_sub_view`.`provider_npi` AS `provider_npi`,`admin_sub_view`.`subg` AS `subg` from `admin_sub_view`) `hierarchy` on((`rbac`.`usrid` = `hierarchy`.`user_id`))) */;

/*View structure for view admin_sub_view */

/*!50001 DROP TABLE IF EXISTS `admin_sub_view` */;
/*!50001 CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `admin_sub_view` AS select distinct `uha`.`user_nr` AS `user_id`,`hm`.`market_id` AS `market_id`,`hm`.`market_name` AS `Market_Name`,`grps`.`nr` AS `GroupID`,`grps`.`name` AS `GroupName`,`subgrps`.`nr` AS `Sub_GroupID`,`pha`.`user_npi` AS `user npi`,if((`pha`.`user_npi` is null),'UNK',`subgrps`.`name`) AS `Sub_GroupName`,if((cast(`pha`.`end_date` as date) >= curdate()),ifnull(`upro`.`provider_npi`,0),-(786)) AS `provider_npi`,(select `user_hosp_assoc`.`hospital_nr` from `user_hosp_assoc` where ((`user_hosp_assoc`.`user_nr` = `uha`.`user_nr`) and `user_hosp_assoc`.`hospital_nr` in (select `hospital_centers`.`nr` from `hospital_centers` where (`hospital_centers`.`main_hospital_nr` = `grps`.`nr`)) and (`user_hosp_assoc`.`hospital_nr` = `subgrps`.`nr`))) AS `subg` from ((((((`user_hosp_assoc` `uha` join (select `hospital_centers`.`nr` AS `nr`,`hospital_centers`.`name` AS `name` from `hospital_centers` where ((`hospital_centers`.`is_dce` = 1) and (`hospital_centers`.`dce_type` = 'DCE') and (`hospital_centers`.`main_hospital_nr` is null))) `grps` on((`uha`.`hospital_nr` = `grps`.`nr`))) left join (select `hospital_centers`.`nr` AS `nr`,`hospital_centers`.`main_hospital_nr` AS `main_hospital_nr`,`hospital_centers`.`name` AS `name` from `hospital_centers` where ((`hospital_centers`.`main_hospital_nr` is not null) and (`hospital_centers`.`is_dce` = 1) and (`hospital_centers`.`dce_type` = 'DCE'))) `subgrps` on((`grps`.`nr` = `subgrps`.`main_hospital_nr`))) join `hospital_market_assocs` `hma` on((`hma`.`hosp_id` = `grps`.`nr`))) join `hospital_market` `hm` on((`hma`.`market_id` = `hm`.`market_id`))) join `user_dce_provider_assoc` `upro` on((`upro`.`user_id` = `uha`.`user_nr`))) left join (select distinct `personell_hosp_assocs`.`user_npi` AS `user_npi`,`personell_hosp_assocs`.`hospital_nr` AS `hospital_nr`,`personell_hosp_assocs`.`end_date` AS `end_date` from `personell_hosp_assocs`) `pha` on(((`pha`.`hospital_nr` = ifnull(`subgrps`.`nr`,`grps`.`nr`)) and (`pha`.`user_npi` = ifnull(`upro`.`provider_npi`,0))))) */;

/*View structure for view v_journal_sms */

/*!50001 DROP TABLE IF EXISTS `v_journal_sms` */;
/*!50001 CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `v_journal_sms` AS select `sms`.`nr` AS `nr`,`sms`.`description` AS `description`,`sms`.`message_id` AS `message_id`,`sms`.`phone_number` AS `phone_number`,`sms`.`created_date` AS `created_date`,`sms`.`message_sent_date` AS `message_sent_date`,`sms`.`message_status` AS `message_status`,`sms`.`encounter_nr` AS `encounter_nr`,`sms`.`origid` AS `origid`,`sms`.`source` AS `source`,`sms`.`user_id` AS `user_id`,`rc`.`msg_body` AS `msg_body`,`rc`.`received_at` AS `received_at`,ifnull(max(`r`.`reminder_id`),0) AS `reminder_id` from ((`journal_sms` `sms` left join `rem_priority` `r` on((`r`.`msg_sent_id` = `sms`.`nr`))) left join `braintree_central_db`.`journal_sms_replies_central` `rc` on((`sms`.`nr` = `rc`.`center_reply_of`))) where (`sms`.`source` = 'ccm_active') group by `sms`.`nr`,`sms`.`description`,`sms`.`message_id`,`sms`.`phone_number`,`sms`.`created_date`,`sms`.`message_sent_date`,`sms`.`message_status`,`sms`.`encounter_nr`,`sms`.`origid`,`sms`.`source`,`sms`.`user_id` */;

/*View structure for view rem_priority */

/*!50001 DROP TABLE IF EXISTS `rem_priority` */;
/*!50001 CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `rem_priority` AS select `ranked`.`msg_sent_id` AS `msg_sent_id`,`ranked`.`reminder_id` AS `reminder_id`,`ranked`.`reminder_name` AS `reminder_name` from (select `reminder_events`.`msg_sent_id` AS `msg_sent_id`,`reminder_events`.`reminder_id` AS `reminder_id`,`reminder_events`.`reminder_name` AS `reminder_name`,dense_rank() OVER (PARTITION BY `reminder_events`.`msg_sent_id` ORDER BY field(`reminder_events`.`reminder_name`,'Called Patient/Family - Spoke With','TOC Called Patient Family Spoke With','Called Facility - Spoke With','Left message','Unable to Contact') )  AS `rn` from `reminder_events` where ((ifnull(`reminder_events`.`msg_sent_id`,0) <> 0) and (ifnull(`reminder_events`.`reminder_name`,'UNK') in ('Called Patient/Family - Spoke With','Called Facility - Spoke With','TOC Called Patient Family Spoke With','Left message','Unable to Contact')))) `ranked` where (`ranked`.`rn` = 1) */;

